    public function currentUserId(): int
    {
        if (session_status() !== PHP_SESSION_ACTIVE) {
            return 1;
        }

        if (!isset($_SESSION['user_id'])) {
            $_SESSION['user_id'] = 1;
        }

        return (int) $_SESSION['user_id'];
    }

    public function currentUser(): array
    {
        $userId = $this->currentUserId();
        foreach ($this->store->load()['users'] as $user) {
            if ((int) $user['id'] === $userId) {
                return $user;
            }
        }

        return [
            'id' => 1,
            'nickname' => '游客A',
            'phone' => '',
            'role' => 'guest',
            'membership' => false,
            'membership_expires_at' => null,
            'coin_balance' => 0,
            'bonus_coin_balance' => 0,
            'bonus_expires_at' => null,
            'auto_unlock_next' => false,
        ];
    }

    public function bindCurrentUser(string $nickname, string $phone): array
    {
        $data = $this->store->load();
        $userId = $this->currentUserId();

        foreach ($data['users'] as &$user) {
            if ((int) $user['id'] === $userId) {
                $user['nickname'] = $nickname;
                $user['phone'] = $phone;
                $user['role'] = 'user';
                $user['created_at'] = (string) (($user['created_at'] ?? '') ?: date('Y-m-d H:i:s'));
                break;
            }
        }

        $this->store->save($data);
        return $this->currentUser();
    }

