    public function saveFilterPreset(array $payload): string
    {
        $data = $this->store->load();
        $admin = $this->currentAdmin();
        $scope = $this->normalizeFilterPresetScope((string) ($payload['preset_scope'] ?? $payload['scope'] ?? 'orders'));
        $name = $this->limitText(trim((string) ($payload['preset_name'] ?? $payload['name'] ?? '')), 60);
        if ($name === '') {
            return '筛选方案名称不能为空。';
        }

        $filters = $this->filterPresetPayload($scope, $payload);
        if (empty($filters)) {
            return '筛选条件不能为空，请先设置至少一个筛选条件后再保存。';
        }

        $adminId = (int) ($admin['id'] ?? ($_SESSION['admin_id'] ?? 0));
        $now = date('Y-m-d H:i:s');
        $presets = array_values((array) ($data['filter_presets'] ?? []));
        $targetIndex = null;
        $payloadId = max(0, (int) ($payload['preset_id'] ?? 0));
        foreach ($presets as $index => $preset) {
            if ((int) ($preset['admin_id'] ?? 0) !== $adminId) {
                continue;
            }
            if ($payloadId > 0 && (int) ($preset['id'] ?? 0) === $payloadId) {
                $targetIndex = $index;
                break;
            }
            if ($payloadId <= 0 && (string) ($preset['scope'] ?? '') === $scope && (string) ($preset['name'] ?? '') === $name) {
                $targetIndex = $index;
                break;
            }
        }

        $item = [
            'id' => $targetIndex === null ? $this->nextFilterPresetId($presets) : (int) ($presets[$targetIndex]['id'] ?? $this->nextFilterPresetId($presets)),
            'scope' => $scope,
            'name' => $name,
            'filters' => $filters,
            'admin_id' => $adminId,
            'admin_name' => $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? ($_SESSION['admin_name'] ?? '管理员')))), 60),
            'role' => (string) ($admin['role'] ?? ($_SESSION['admin_role'] ?? 'super_admin')),
            'is_shared' => !empty($payload['preset_shared']),
            'created_at' => $targetIndex === null ? $now : (string) ($presets[$targetIndex]['created_at'] ?? $now),
            'updated_at' => $now,
        ];

        if ($targetIndex === null) {
            $presets[] = $item;
        } else {
            $presets[$targetIndex] = $item;
        }
        $data['filter_presets'] = $presets;
        $this->store->save($data);

        return $targetIndex === null ? '筛选方案已保存。' : '筛选方案已更新。';
    }

    public function deleteFilterPreset(array $payload): string
    {
        $data = $this->store->load();
        $admin = $this->currentAdmin();
        $scope = $this->normalizeFilterPresetScope((string) ($payload['preset_scope'] ?? $payload['scope'] ?? 'orders'));
        $id = max(0, (int) ($payload['preset_id'] ?? 0));
        if ($id <= 0) {
            return '请选择要删除的筛选方案。';
        }

        $adminId = (int) ($admin['id'] ?? ($_SESSION['admin_id'] ?? 0));
        $role = (string) ($admin['role'] ?? ($_SESSION['admin_role'] ?? 'super_admin'));
        $deleted = false;
        $blocked = false;
        $data['filter_presets'] = array_values(array_filter((array) ($data['filter_presets'] ?? []), static function (array $preset) use ($id, $scope, $adminId, $role, &$deleted, &$blocked): bool {
            if ((int) ($preset['id'] ?? 0) !== $id || (string) ($preset['scope'] ?? '') !== $scope) {
                return true;
            }
            if ((int) ($preset['admin_id'] ?? 0) === $adminId || $role === 'super_admin') {
                $deleted = true;
                return false;
            }
            $blocked = true;
            return true;
        }));

        if ($blocked) {
            return '只能删除自己创建的筛选方案。';
        }
        if (!$deleted) {
            return '筛选方案不存在。';
        }

        $this->store->save($data);

        return '筛选方案已删除。';
    }

    public function csrfToken(): string
    {
        if (session_status() !== PHP_SESSION_ACTIVE) {
            return '';
        }

        if (empty($_SESSION['csrf_token']) || !is_string($_SESSION['csrf_token'])) {
            $_SESSION['csrf_token'] = bin2hex(random_bytes(32));
        }

        return (string) $_SESSION['csrf_token'];
    }

    public function verifyCsrfToken(?string $token): bool
    {
        if (session_status() !== PHP_SESSION_ACTIVE) {
            return false;
        }

        $stored = (string) ($_SESSION['csrf_token'] ?? '');
        $token = (string) ($token ?? '');

        return $stored !== '' && $token !== '' && hash_equals($stored, $token);
    }

    public function currentAdminScope(?array $data = null): array
    {
        $data ??= $this->store->load();
        $admin = $this->currentAdmin();
        $role = (string) ($admin['role'] ?? 'super_admin');
        $role = in_array($role, ['super_admin', 'business', 'leader', 'agent', 'editor'], true) ? $role : 'super_admin';
        $agentId = max(0, (int) ($admin['agent_id'] ?? 0));
        $agentIds = $this->agentScopeIds((array) ($data['agents'] ?? []), $role, $agentId);
        $restricted = !in_array($role, ['super_admin', 'editor'], true);

        return [
            'role' => $role,
            'role_label' => $this->adminRoleLabels()[$role] ?? '管理员',
            'agent_id' => $agentId,
            'agent_ids' => $agentIds,
            'restricted' => $restricted,
            'can_manage_system' => $role === 'super_admin',
            'can_manage_content' => in_array($role, ['super_admin', 'editor'], true),
            'can_manage_promotion' => in_array($role, ['super_admin', 'business', 'leader', 'agent'], true),
        ];
    }

    public function adminRoleLabels(): array
    {
        return [
            'super_admin' => '管理员',
            'business' => '商务',
            'leader' => '代理组长',
            'agent' => '代理',
            'editor' => '编辑',
        ];
    }

    public function adminCanAccessAgentId(int $agentId, ?array $data = null): bool
    {
        $scope = $this->currentAdminScope($data);
        if (empty($scope['restricted'])) {
            return true;
        }
        if ($agentId <= 0) {
            return false;
        }

        return in_array($agentId, array_map('intval', (array) ($scope['agent_ids'] ?? [])), true);
    }

    public function adminCanAccessPromotionLink(array $link, ?array $data = null): bool
    {
        return $this->adminCanAccessAgentId((int) ($link['agent_id'] ?? 0), $data);
    }

    public function adminCanAccessPromotionStopTask(array $item, ?array $data = null): bool
    {
        $data ??= $this->store->load();
        $scope = $this->currentAdminScope($data);
        if (empty($scope['restricted'])) {
            return true;
        }

        $agentIds = array_fill_keys(array_map('intval', (array) ($scope['agent_ids'] ?? [])), true);
        if (empty($agentIds)) {
            return false;
        }
        $agentId = (int) ($item['agent_id'] ?? 0);
        if ($agentId > 0 && isset($agentIds[$agentId])) {
            return true;
        }

        $promotionLinkId = (int) ($item['promotion_link_id'] ?? 0);
        if ($promotionLinkId > 0) {
            foreach ((array) ($data['promotion_links'] ?? []) as $link) {
                if ((int) ($link['id'] ?? 0) === $promotionLinkId) {
                    return isset($agentIds[(int) ($link['agent_id'] ?? 0)]);
                }
            }
        }

        return false;
    }

    public function adminCanAccessFeedbackItem(array $item, ?array $data = null): bool
    {
        $data ??= $this->store->load();
        $scope = $this->currentAdminScope($data);
        if (empty($scope['restricted'])) {
            return true;
        }

        $agentIds = array_fill_keys(array_map('intval', (array) ($scope['agent_ids'] ?? [])), true);
        if (empty($agentIds)) {
            return false;
        }
        $agentId = (int) ($item['agent_id'] ?? 0);
        if ($agentId > 0 && isset($agentIds[$agentId])) {
            return true;
        }

        $promotionLinkId = (int) ($item['promotion_link_id'] ?? 0);
        if ($promotionLinkId > 0) {
            foreach ((array) ($data['promotion_links'] ?? []) as $link) {
                if ((int) ($link['id'] ?? 0) === $promotionLinkId) {
                    return isset($agentIds[(int) ($link['agent_id'] ?? 0)]);
                }
            }
        }

        $orderNo = trim((string) ($item['order_no'] ?? ''));
        if ($orderNo !== '') {
            foreach ((array) ($data['orders'] ?? []) as $order) {
                if ((string) ($order['order_no'] ?? '') !== $orderNo) {
                    continue;
                }
                return isset($agentIds[(int) ($order['agent_id'] ?? 0)])
                    || isset($agentIds[(int) ($this->promotionLinkAgentId((int) ($order['promotion_link_id'] ?? 0), $data))]);
            }
        }

        return false;
    }

