    public function adminCanAccessOrder(array $order, ?array $data = null): bool
    {
        $data ??= $this->store->load();
        $scope = $this->currentAdminScope($data);
        if (empty($scope['restricted'])) {
            return true;
        }

        $agentIds = array_fill_keys(array_map('intval', (array) ($scope['agent_ids'] ?? [])), true);
        if (empty($agentIds)) {
            return false;
        }

        $agentId = (int) ($order['agent_id'] ?? 0);
        if ($agentId > 0 && isset($agentIds[$agentId])) {
            return true;
        }

        $promotionLinkId = (int) ($order['promotion_link_id'] ?? 0);
        if ($promotionLinkId <= 0) {
            return false;
        }

        return isset($agentIds[(int) $this->promotionLinkAgentId($promotionLinkId, $data)]);
    }

    public function throttle(string $key, int $limit, int $windowSeconds): array
    {
        $windowSeconds = max(1, $windowSeconds);
        $limit = max(1, $limit);
        $now = time();
        $bucketKey = preg_replace('/[^a-zA-Z0-9_.:-]+/', '_', $key) ?: 'global';

        if (session_status() !== PHP_SESSION_ACTIVE) {
            return ['allowed' => true, 'remaining' => $limit - 1, 'retry_after' => 0];
        }

        $bucket = $_SESSION['rate_limits'][$bucketKey] ?? ['started_at' => $now, 'count' => 0];
        if (!is_array($bucket) || ($now - (int) ($bucket['started_at'] ?? 0)) >= $windowSeconds) {
            $bucket = ['started_at' => $now, 'count' => 0];
        }

        $bucket['count'] = (int) ($bucket['count'] ?? 0) + 1;
        $_SESSION['rate_limits'][$bucketKey] = $bucket;
        $retryAfter = max(0, $windowSeconds - ($now - (int) $bucket['started_at']));

        return [
            'allowed' => $bucket['count'] <= $limit,
            'remaining' => max(0, $limit - (int) $bucket['count']),
            'retry_after' => $retryAfter,
        ];
    }

