    public function currentAdmin(): ?array
    {
        $adminId = (int) ($_SESSION['admin_id'] ?? 0);
        if ($adminId === 0) {
            return null;
        }

        foreach ($this->store->load()['admins'] as $admin) {
            if ((int) $admin['id'] === $adminId) {
                return $admin;
            }
        }

        return null;
    }

    public function adminLogin(string $username, string $password): bool
    {
        foreach ($this->store->load()['admins'] as $admin) {
            if ($admin['username'] === $username && (string) ($admin['status'] ?? 'active') === 'active' && password_verify($password, $admin['password_hash'])) {
                if (session_status() === PHP_SESSION_ACTIVE) {
                    session_regenerate_id(true);
                    unset($_SESSION['csrf_token'], $_SESSION['rate_limits']);
                }
                $_SESSION['admin_id'] = $admin['id'];
                $_SESSION['admin_name'] = $admin['nickname'] ?: $admin['username'];
                $_SESSION['admin_role'] = (string) ($admin['role'] ?? 'super_admin');
                return true;
            }
        }

        return false;
    }

    public function adminLoginChallenge(bool $forceNew = false): array
    {
        if (session_status() !== PHP_SESSION_ACTIVE) {
            return $this->buildAdminLoginChallenge();
        }

        $challenge = $_SESSION['admin_login_challenge'] ?? null;
        if (
            $forceNew
            || !is_array($challenge)
            || (int) ($challenge['expires_at'] ?? 0) < time()
        ) {
            $challenge = $this->buildAdminLoginChallenge();
            $_SESSION['admin_login_challenge'] = $challenge;
        }

        return $challenge;
    }

    public function verifyAdminLoginChallenge(array $payload): bool
    {
        if (session_status() !== PHP_SESSION_ACTIVE) {
            return false;
        }

        $challenge = $_SESSION['admin_login_challenge'] ?? null;
        unset($_SESSION['admin_login_challenge']);

        if (!is_array($challenge) || (int) ($challenge['expires_at'] ?? 0) < time()) {
            return false;
        }

        $challengeId = (string) ($payload['login_challenge_id'] ?? '');
        $passed = (string) ($payload['login_slider_passed'] ?? '') === '1';
        $position = (float) ($payload['login_slider_percent'] ?? -1);
        $elapsed = (int) ($payload['login_slider_elapsed'] ?? 0);
        $target = (float) ($challenge['target'] ?? -100);

        if (!$passed || $challengeId === '' || !hash_equals((string) ($challenge['id'] ?? ''), $challengeId)) {
            return false;
        }

        if ($elapsed < 350 || $elapsed > 600000) {
            return false;
        }

        return abs($position - $target) <= 4;
    }

    public function adminLogout(): void
    {
        unset($_SESSION['admin_id'], $_SESSION['admin_name'], $_SESSION['csrf_token'], $_SESSION['rate_limits']);
    }

    public function adminLoggedIn(): bool
    {
        return !empty($_SESSION['admin_id']);
    }

    private function buildAdminLoginChallenge(): array
    {
        return [
            'id' => bin2hex(random_bytes(16)),
            'target' => random_int(58, 84),
            'issued_at' => time(),
            'expires_at' => time() + 600,
        ];
    }

