    public function appConfig(?string $appKey = null): ?array
    {
        $targetKey = $this->normalizeAppKey((string) ($appKey ?? ''));
        if ($targetKey === '') {
            $targetKey = 'default';
        }
        $defaultApp = null;
        foreach ($this->apps() as $app) {
            $key = $this->normalizeAppKey((string) ($app['app_key'] ?? ''));
            if ($key === 'default') {
                $defaultApp = $app;
            }
            if ($key === $targetKey) {
                return $app;
            }
        }

        return $defaultApp;
    }

    public function clientAppConfig(array $filters = []): array
    {
        $data = $this->store->load(false);
        $appKey = $this->clientAppKeyFromData($filters, $data);
        $app = $this->appConfigFromData($appKey, $data) ?? [];
        $userId = max(0, (int) ($filters['user_id'] ?? $this->currentUserId()));
        $tier = $this->resolveAppUserTier($app, $userId, $data);
        $operationConfig = $this->clientOperationConfigFromData($data, array_merge($filters, ['app_key' => (string) ($app['app_key'] ?? $appKey)]), $app, $tier);
        $clientConfig = (array) ($app['client_config'] ?? []);
        $gray = $this->appConfigGrayResult((string) ($app['app_key'] ?? $appKey), $userId, $clientConfig, $filters);

        $response = [
            'app_key' => (string) ($app['app_key'] ?? 'default'),
            'name' => (string) ($app['name'] ?? '默认应用'),
            'type' => (string) ($app['type'] ?? 'h5'),
            'status' => (string) ($app['status'] ?? 'active'),
            'homepage_template' => (string) ($app['homepage_template'] ?? 'mini'),
            'privacy_url' => (string) ($app['privacy_url'] ?? ''),
            'agreement_url' => (string) ($app['agreement_url'] ?? ''),
            'client_config' => array_merge($clientConfig, [
                'gray_hit' => (bool) ($gray['hit'] ?? true),
                'gray_bucket' => (int) ($gray['bucket'] ?? 0),
            ]),
            'current_user_tier' => $tier,
            'user_tiers' => array_values((array) ($app['user_tiers'] ?? [])),
            'recommend_slots' => (array) ($app['recommend_slots'] ?? []),
            'task_config' => (array) ($app['task_config'] ?? []),
            'operation_config' => $operationConfig,
        ];
        $this->recordAppConfigDeliveryLog($data, $app, $userId, $tier, $clientConfig, $gray);

        return $response;
    }

    private function clientAppKeyFromData(array $filters, array $data): string
    {
        $attribution = $this->currentPromotionAttribution();
        $candidates = [
            $filters['app_key'] ?? '',
            $filters['media_app_id'] ?? '',
            $filters['app_id'] ?? '',
            $_POST['app_key'] ?? '',
            $_GET['app_key'] ?? '',
            $_POST['media_app_id'] ?? '',
            $_GET['media_app_id'] ?? '',
            $_POST['app_id'] ?? '',
            $_GET['app_id'] ?? '',
            $attribution['app_key'] ?? '',
            $attribution['media_app_id'] ?? '',
        ];

        foreach ($candidates as $candidate) {
            $appKey = $this->normalizeAppKey((string) $candidate);
            if ($appKey === '') {
                continue;
            }
            $app = $this->appConfigFromData($appKey, $data);
            return (string) ($app['app_key'] ?? $appKey);
        }

        return 'default';
    }

    private function appConfigFromData(?string $appKey, array $data): ?array
    {
        $targetKey = $this->normalizeAppKey((string) ($appKey ?? '')) ?: 'default';
        $apps = array_values((array) ($data['apps'] ?? []));
        usort($apps, static fn (array $a, array $b): int => [(int) ($a['sort'] ?? 0), (int) ($a['id'] ?? 0)] <=> [(int) ($b['sort'] ?? 0), (int) ($b['id'] ?? 0)]);
        $defaultApp = null;
        foreach ($apps as $app) {
            $key = $this->normalizeAppKey((string) ($app['app_key'] ?? ''));
            if ($key === 'default') {
                $defaultApp = $app;
            }
            if ($key === $targetKey) {
                return $app;
            }
        }

        return $defaultApp;
    }

    private function appConfigGrayResult(string $appKey, int $userId, array $clientConfig, array $filters): array
    {
        $percent = max(0, min(100, (int) ($clientConfig['gray_release_percent'] ?? 100)));
        $clientId = trim((string) ($filters['client_id'] ?? $filters['device_id'] ?? $filters['openid'] ?? ''));
        $seed = $appKey . ':' . $userId . ':' . $clientId;
        $bucket = (int) (hexdec(substr(sha1($seed), 0, 8)) % 100);

        return [
            'percent' => $percent,
            'bucket' => $bucket,
            'hit' => $percent >= 100 || ($percent > 0 && $bucket < $percent),
            'client_id' => $clientId,
        ];
    }

    private function recordAppConfigDeliveryLog(array $data, array $app, int $userId, array $tier, array $clientConfig, array $gray): void
    {
        $logs = array_values((array) ($data['app_config_delivery_logs'] ?? []));
        $appKey = (string) ($app['app_key'] ?? 'default');
        $reviewMode = (string) ($clientConfig['review_mode'] ?? 'normal');
        $version = (string) ($clientConfig['version'] ?? '');
        $clientId = (string) ($gray['client_id'] ?? '');
        $hour = date('YmdH');
        $fingerprint = 'app_config:' . $appKey . ':' . $userId . ':' . sha1($clientId) . ':' . $version . ':' . $reviewMode . ':' . $hour;
        $now = date('Y-m-d H:i:s');
        $targetIndex = null;
        foreach ($logs as $index => $log) {
            if ((string) ($log['fingerprint'] ?? '') === $fingerprint) {
                $targetIndex = $index;
                break;
            }
        }
        $record = [
            'id' => empty($logs) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $logs)) + 1),
            'fingerprint' => $fingerprint,
            'app_key' => $appKey,
            'app_name' => (string) ($app['name'] ?? '默认应用'),
            'user_id' => $userId,
            'client_id' => $clientId,
            'user_tier' => (string) ($tier['key'] ?? ''),
            'app_status' => (string) ($app['status'] ?? 'active'),
            'review_mode' => $reviewMode,
            'version' => $version,
            'min_version' => (string) ($clientConfig['min_version'] ?? ''),
            'gray_percent' => (int) ($gray['percent'] ?? 100),
            'gray_bucket' => (int) ($gray['bucket'] ?? 0),
            'gray_hit' => !empty($gray['hit']),
            'force_update' => !empty($clientConfig['force_update']),
            'show_ads' => array_key_exists('show_ads', $clientConfig) ? !empty($clientConfig['show_ads']) : true,
            'show_rewards' => array_key_exists('show_rewards', $clientConfig) ? !empty($clientConfig['show_rewards']) : true,
            'show_vip' => array_key_exists('show_vip', $clientConfig) ? !empty($clientConfig['show_vip']) : true,
            'hit_count' => 1,
            'first_seen_at' => $now,
            'last_seen_at' => $now,
        ];
        if ($targetIndex !== null) {
            $record['id'] = (int) ($logs[$targetIndex]['id'] ?? $record['id']);
            $record['hit_count'] = max(1, (int) ($logs[$targetIndex]['hit_count'] ?? 1)) + 1;
            $record['first_seen_at'] = (string) ($logs[$targetIndex]['first_seen_at'] ?? $now);
            $logs[$targetIndex] = $record;
        } else {
            $logs[] = $record;
        }
        usort($logs, static fn (array $a, array $b): int => strcmp((string) ($b['last_seen_at'] ?? ''), (string) ($a['last_seen_at'] ?? '')));
        $data['app_config_delivery_logs'] = array_slice(array_values($logs), 0, 2000);
        $this->store->save($data, false);
    }

    public function clientOperationConfig(array $filters = []): array
    {
        $data = $this->store->load();
        $appKey = $this->currentAppKey($filters);
        $app = $this->appConfig($appKey) ?? [];
        $userId = max(0, (int) ($filters['user_id'] ?? $this->currentUserId()));
        $userTier = $this->resolveAppUserTier($app, $userId);
        return $this->clientOperationConfigFromData($data, $filters, $app, $userTier);
    }

    private function clientOperationConfigFromData(array $data, array $filters, array $app, array $userTier): array
    {
        $appKey = (string) ($app['app_key'] ?? $this->clientAppKeyFromData($filters, $data));
        $userId = max(0, (int) ($filters['user_id'] ?? $this->currentUserId()));
        $trigger = trim((string) ($filters['trigger'] ?? ''));
        $slot = trim((string) ($filters['slot'] ?? ''));
        $now = date('Y-m-d H:i:s');

        $homeRecommendations = array_values(array_filter((array) ($data['home_recommendations'] ?? []), function (array $item) use ($appKey, $slot, $now): bool {
            if (!$this->operationItemActiveForApp($item, $appKey, $now)) {
                return false;
            }
            return $slot === '' || (string) ($item['slot'] ?? '') === $slot;
        }));
        usort($homeRecommendations, static fn (array $a, array $b): int => [(int) ($a['sort'] ?? 0), (int) ($a['id'] ?? 0)] <=> [(int) ($b['sort'] ?? 0), (int) ($b['id'] ?? 0)]);

        $popupNotices = array_values(array_filter((array) ($data['popup_notices'] ?? []), function (array $item) use ($appKey, $trigger, $now): bool {
            if (!$this->operationItemActiveForApp($item, $appKey, $now)) {
                return false;
            }
            return $trigger === '' || (string) ($item['trigger'] ?? '') === $trigger;
        }));
        usort($popupNotices, static fn (array $a, array $b): int => [(int) ($a['priority'] ?? 100), (int) ($a['id'] ?? 0)] <=> [(int) ($b['priority'] ?? 100), (int) ($b['id'] ?? 0)]);

        $activities = array_values(array_filter((array) ($data['activity_configs'] ?? []), fn (array $item): bool => $this->operationItemActiveForApp($item, $appKey, $now) && $this->activityMatchesUserTier($item, $userTier)));
        $activities = $this->filterActivitiesForExperiment($activities, $appKey, $userId);
        usort($activities, static fn (array $a, array $b): int => [(int) ($a['sort'] ?? 0), (int) ($a['id'] ?? 0)] <=> [(int) ($b['sort'] ?? 0), (int) ($b['id'] ?? 0)]);
        $hotRanks = array_values(array_filter((array) ($data['hot_rank_configs'] ?? []), fn (array $item): bool => $this->operationItemActiveForApp($item, $appKey, $now)));
        usort($hotRanks, static fn (array $a, array $b): int => [(int) ($a['sort'] ?? 0), (int) ($a['id'] ?? 0)] <=> [(int) ($b['sort'] ?? 0), (int) ($b['id'] ?? 0)]);

        return [
            'app_key' => $appKey,
            'current_user_tier' => $userTier,
            'home_recommendations' => array_map([$this, 'publicHomeRecommendation'], $homeRecommendations),
            'popup_notices' => array_map([$this, 'publicPopupNotice'], $popupNotices),
            'activities' => array_map([$this, 'publicActivityConfig'], $activities),
            'hot_ranks' => array_map(fn (array $config): array => $this->publicHotRank($config, $data), $hotRanks),
            'generated_at' => $now,
        ];
    }

