    public function saveApp(array $payload): array
    {
        $data = $this->store->load();
        $snapshot = $this->buildAppConfigSnapshot($payload, $data);
        if (empty($snapshot['ok'])) {
            return ['ok' => false, 'message' => (string) ($snapshot['message'] ?? '应用配置内容无效。')];
        }
        if ($this->configApprovalPolicyEnabled($data, 'app_config') && empty($payload['skip_config_approval'])) {
            return $this->createConfigChangeRequestFromSnapshot('app_config', $snapshot, [
                'title' => $this->limitText(trim((string) ($payload['change_title'] ?? '')) ?: (string) ($snapshot['title'] ?? '应用配置变更'), 120),
                'reason' => $this->limitText(trim((string) ($payload['change_reason'] ?? '直接保存应用配置触发强制审批')), 240),
            ]);
        }

        $apply = $this->applyConfigSnapshot($data, ['config_type' => 'app_config', 'target_key' => (string) ($snapshot['target_key'] ?? '')], (array) ($snapshot['after_snapshot'] ?? []), false);
        if (empty($apply['ok'])) {
            return ['ok' => false, 'message' => (string) ($apply['message'] ?? '应用配置保存失败。')];
        }
        $this->store->save($data);

        return ['ok' => true, 'app' => (array) ($snapshot['after_snapshot'] ?? []), 'message' => '应用配置已保存。'];
    }

    private function buildAppConfigSnapshot(array $payload, array $data): array
    {
        $apps = array_values((array) ($data['apps'] ?? []));
        $appId = max(0, (int) ($payload['id'] ?? $payload['app_row_id'] ?? 0));
        $appKey = $this->normalizeAppKey((string) ($payload['app_key'] ?? ''));
        if ($appKey === '') {
            return ['ok' => false, 'message' => '应用标识不能为空。'];
        }

        $templateKeys = array_map(static fn (array $template): string => (string) ($template['app_key'] ?? ''), (array) ($data['recharge_config']['app_product_templates'] ?? []));
        $templateKey = $this->normalizeAppKey((string) ($payload['product_template_key'] ?? $appKey));
        if (!in_array($templateKey, $templateKeys, true)) {
            $templateKey = in_array($appKey, $templateKeys, true) ? $appKey : 'default';
        }

        $paymentRouteIds = array_map(static fn (array $route): string => (string) ($route['id'] ?? ''), (array) ($data['payment_config']['routes'] ?? []));
        $paymentRouteId = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['payment_route_id'] ?? '')));
        if (!in_array($paymentRouteId, $paymentRouteIds, true)) {
            $paymentRouteId = (string) ($data['payment_config']['default_route_id'] ?? ($paymentRouteIds[0] ?? ''));
        }

        foreach ($apps as $item) {
            if ((int) ($item['id'] ?? 0) === $appId) {
                continue;
            }
            if ($this->normalizeAppKey((string) ($item['app_key'] ?? '')) === $appKey) {
                return ['ok' => false, 'message' => '同一个应用标识只能配置一个应用。'];
            }
        }

        $now = date('Y-m-d H:i:s');
        $homepageTemplate = (string) ($payload['homepage_template'] ?? 'mini');
        $homepageTemplate = in_array($homepageTemplate, ['mini', 'marketing', 'diy'], true) ? $homepageTemplate : 'mini';
        $baseApp = [];
        foreach ($apps as $item) {
            if ((int) ($item['id'] ?? 0) === $appId) {
                $baseApp = $item;
                break;
            }
        }
        $app = [
            'id' => $appId > 0 ? $appId : (empty($apps) ? 1 : ((int) max(array_column($apps, 'id')) + 1)),
            'app_key' => $appKey,
            'name' => $this->limitText(trim((string) ($payload['name'] ?? '')) ?: ($appKey === 'default' ? '默认应用' : $appKey), 60),
            'type' => in_array((string) ($payload['type'] ?? 'h5'), ['h5', 'wechat_mp', 'wechat_official', 'quick_app', 'douyin', 'kuaishou', 'native'], true) ? (string) $payload['type'] : 'h5',
            'status' => in_array((string) ($payload['status'] ?? 'active'), ['active', 'review', 'paused'], true) ? (string) $payload['status'] : 'active',
            'app_id' => $this->limitText(trim((string) ($payload['app_id'] ?? '')), 80),
            'app_secret' => $this->limitText(trim((string) ($payload['app_secret'] ?? '')), 120),
            'original_id' => $this->limitText(trim((string) ($payload['original_id'] ?? '')), 80),
            'product_template_key' => $templateKey,
            'payment_route_id' => $paymentRouteId,
            'homepage_template' => $homepageTemplate,
            'privacy_url' => trim((string) ($payload['privacy_url'] ?? '')),
            'agreement_url' => trim((string) ($payload['agreement_url'] ?? '')),
            'callback_url' => trim((string) ($payload['callback_url'] ?? '')),
            'recommend_slots' => $this->appRecommendSlotsFromPayload($payload, (array) ($baseApp['recommend_slots'] ?? [])),
            'task_config' => $this->appTaskConfigFromPayload($payload, (array) ($baseApp['task_config'] ?? [])),
            'user_tiers' => $this->appUserTiersFromPayload($payload, (array) ($baseApp['user_tiers'] ?? [])),
            'client_config' => $this->appClientConfigFromPayload($payload, (array) ($baseApp['client_config'] ?? [])),
            'callback_policy' => $this->appCallbackPolicyFromPayload($payload, (array) ($baseApp['callback_policy'] ?? [])),
            'remark' => $this->limitText(trim((string) ($payload['remark'] ?? '')), 120),
            'sort' => (int) ($payload['sort'] ?? 100),
            'updated_at' => $now,
        ];
        $app['created_at'] = (string) (($baseApp['created_at'] ?? '') ?: $now);

        return [
            'ok' => true,
            'title' => ($baseApp ? '应用配置变更：' : '新增应用配置：') . (string) ($app['name'] ?? $appKey),
            'target_key' => $appKey,
            'before_snapshot' => $baseApp,
            'after_snapshot' => $app,
        ];
    }

    public function saveMiniProgramConfig(array $payload): array
    {
        $data = $this->store->load();
        if ((string) ($this->currentAdminScope($data)['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以配置小程序。'];
        }

        $configs = array_values((array) ($data['mini_program_configs'] ?? []));
        $configId = max(0, (int) ($payload['mini_program_config_id'] ?? $payload['config_id'] ?? $payload['id'] ?? 0));
        $appKey = $this->normalizeAppKey((string) ($payload['app_key'] ?? ''));
        if ($appKey === '') {
            $appKey = 'default';
        }
        $app = $this->appConfig($appKey);
        if (is_array($app)) {
            $appKey = (string) ($app['app_key'] ?? $appKey);
        }
        foreach ($configs as $item) {
            if ((int) ($item['id'] ?? 0) !== $configId && (string) ($item['app_key'] ?? '') === $appKey) {
                return ['ok' => false, 'message' => '同一个应用只能配置一个小程序账号。'];
            }
        }

        $name = $this->limitText(trim((string) ($payload['name'] ?? '')), 80);
        if ($name === '') {
            $name = (string) (($app['name'] ?? '') ?: '小程序配置');
        }
        $status = (string) ($payload['status'] ?? 'draft');
        $status = in_array($status, ['draft', 'active', 'paused'], true) ? $status : 'draft';
        $uploadMode = (string) ($payload['upload_mode'] ?? 'manual');
        $uploadMode = in_array($uploadMode, ['manual', 'api', 'ci'], true) ? $uploadMode : 'manual';
        $contentScope = (string) ($payload['content_scope'] ?? 'all');
        $contentScope = in_array($contentScope, ['all', 'drama', 'novel'], true) ? $contentScope : 'all';
        $now = date('Y-m-d H:i:s');
        $baseConfig = [];
        foreach ($configs as $item) {
            if ((int) ($item['id'] ?? 0) === $configId) {
                $baseConfig = $item;
                break;
            }
        }
        $config = [
            'id' => $configId > 0 ? $configId : (empty($configs) ? 1 : ((int) max(array_column($configs, 'id')) + 1)),
            'app_key' => $appKey,
            'name' => $name,
            'status' => $status,
            'mp_app_id' => $this->limitText(trim((string) ($payload['mp_app_id'] ?? $payload['appid'] ?? '')), 80),
            'mp_app_secret' => $this->limitText(trim((string) ($payload['mp_app_secret'] ?? $payload['app_secret'] ?? '')), 120),
            'original_id' => $this->limitText(trim((string) ($payload['original_id'] ?? '')), 80),
            'mch_id' => $this->limitText(trim((string) ($payload['mch_id'] ?? '')), 80),
            'server_domain' => trim((string) ($payload['server_domain'] ?? '')),
            'upload_token' => $this->limitText(trim((string) ($payload['upload_token'] ?? '')), 120),
            'upload_mode' => $uploadMode,
            'api_base_url' => trim((string) ($payload['api_base_url'] ?? ($baseConfig['api_base_url'] ?? ''))) ?: 'https://api.weixin.qq.com',
            'access_token' => (string) ($baseConfig['access_token'] ?? ''),
            'access_token_expires_at' => (string) ($baseConfig['access_token_expires_at'] ?? ''),
            'access_token_last_refresh_at' => (string) ($baseConfig['access_token_last_refresh_at'] ?? ''),
            'access_token_status' => (string) ($baseConfig['access_token_status'] ?? ''),
            'access_token_message' => (string) ($baseConfig['access_token_message'] ?? ''),
            'access_token_response' => is_array($baseConfig['access_token_response'] ?? null) ? (array) $baseConfig['access_token_response'] : [],
            'content_scope' => $contentScope,
            'default_drama_category' => $this->limitText(trim((string) ($payload['default_drama_category'] ?? '短剧')), 40),
            'default_novel_category' => $this->limitText(trim((string) ($payload['default_novel_category'] ?? '小说')), 40),
            'privacy_url' => trim((string) ($payload['privacy_url'] ?? ($app['privacy_url'] ?? ''))),
            'agreement_url' => trim((string) ($payload['agreement_url'] ?? ($app['agreement_url'] ?? ''))),
            'config_json' => $this->miniProgramConfigJsonFromPayload($payload, $baseConfig),
            'last_sync_at' => (string) ($baseConfig['last_sync_at'] ?? ''),
            'last_sync_status' => (string) ($baseConfig['last_sync_status'] ?? ''),
            'remark' => $this->limitText(trim((string) ($payload['remark'] ?? '')), 160),
            'updated_at' => $now,
        ];

        $replaced = false;
        foreach ($configs as &$item) {
            if ((int) ($item['id'] ?? 0) !== $config['id']) {
                continue;
            }
            $config['created_at'] = (string) ($item['created_at'] ?? $now);
            $item = $config;
            $replaced = true;
            break;
        }
        unset($item);
        if (!$replaced) {
            $config['created_at'] = $now;
            $configs[] = $config;
        }

        $data['mini_program_configs'] = $configs;
        $this->store->save($data);

        return ['ok' => true, 'config' => $config];
    }

    public function createMiniProgramSyncTask(array $payload): array
    {
        $data = $this->store->load();
        if ((string) ($this->currentAdminScope($data)['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以生成小程序同步任务。'];
        }

        $configId = max(0, (int) ($payload['mini_program_config_id'] ?? $payload['config_id'] ?? 0));
        $config = null;
        foreach ((array) ($data['mini_program_configs'] ?? []) as $item) {
            if ((int) ($item['id'] ?? 0) === $configId) {
                $config = $item;
                break;
            }
        }
        if (!$config) {
            return ['ok' => false, 'message' => '请选择有效的小程序配置。'];
        }

        $contentType = (string) ($payload['content_type'] ?? 'mixed');
        $contentType = in_array($contentType, ['drama', 'novel', 'mixed'], true) ? $contentType : 'mixed';
        $contentIds = $this->idsFromPayload($payload['content_ids'] ?? $payload['content_id'] ?? []);
        $manifest = $this->miniProgramManifest($data, $config, $contentType, $contentIds);
        if (empty($manifest['items'])) {
            return ['ok' => false, 'message' => '没有可同步的短剧或小说内容。'];
        }

        $tasks = array_values((array) ($data['mini_program_sync_tasks'] ?? []));
        $admin = $this->currentAdmin();
        $now = date('Y-m-d H:i:s');
        $task = [
            'id' => empty($tasks) ? 1 : ((int) max(array_column($tasks, 'id')) + 1),
            'config_id' => (int) ($config['id'] ?? 0),
            'app_key' => (string) ($config['app_key'] ?? 'default'),
            'content_type' => $contentType,
            'content_ids' => $contentIds,
            'status' => 'generated',
            'item_count' => count((array) ($manifest['items'] ?? [])),
            'version' => date('Y.m.d.Hi'),
            'upload_mode' => (string) ($config['upload_mode'] ?? 'manual'),
            'retry_count' => 0,
            'error_category' => '',
            'next_retry_at' => '',
            'retry_blocked_reason' => '',
            'platform_code' => '',
            'platform_message' => '',
            'last_error_at' => '',
            'last_error' => '',
            'last_action' => 'generate',
            'last_action_at' => $now,
            'action_logs' => [[
                'action' => 'generate',
                'status' => 'success',
                'message' => '已生成上传清单。',
                'created_at' => $now,
                'admin_name' => $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60),
            ]],
            'manifest' => $manifest,
            'message' => '已生成小程序上传清单，可用于后续 API/CI 上传。',
            'created_by_admin_id' => max(0, (int) ($admin['id'] ?? 0)),
            'created_by_admin_name' => $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60),
            'created_at' => $now,
            'updated_at' => $now,
        ];
        $tasks[] = $task;
        $data['mini_program_sync_tasks'] = array_slice(array_values($tasks), -1000);
        foreach ($data['mini_program_configs'] as &$item) {
            if ((int) ($item['id'] ?? 0) !== (int) ($config['id'] ?? 0)) {
                continue;
            }
            $item['last_sync_at'] = $now;
            $item['last_sync_status'] = 'generated';
            $item['updated_at'] = $now;
            break;
        }
        unset($item);
        $this->store->save($data);

        return ['ok' => true, 'task' => $task];
    }

    public function runMiniProgramTaskAction(array $payload): array
    {
        $data = $this->store->load();
        if ((string) ($this->currentAdminScope($data)['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以操作小程序发布任务。'];
        }

        $taskId = max(0, (int) ($payload['mini_program_task_id'] ?? $payload['task_id'] ?? 0));
        $action = (string) ($payload['mini_program_action'] ?? $payload['task_action'] ?? 'upload');
        $allowedActions = ['upload', 'submit_review', 'query_review', 'release', 'retry'];
        if (!in_array($action, $allowedActions, true)) {
            return ['ok' => false, 'message' => '小程序任务动作不支持。'];
        }
        $tasks = array_values((array) ($data['mini_program_sync_tasks'] ?? []));
        $taskIndex = null;
        foreach ($tasks as $index => $task) {
            if ((int) ($task['id'] ?? 0) === $taskId) {
                $taskIndex = $index;
                break;
            }
        }
        if ($taskIndex === null) {
            return ['ok' => false, 'message' => '小程序同步任务不存在。'];
        }
        $task = (array) ($tasks[$taskIndex] ?? []);
        $config = $this->miniProgramConfigById($data, (int) ($task['config_id'] ?? 0));
        if ($config === null) {
            return ['ok' => false, 'message' => '小程序配置不存在，无法继续发布。'];
        }

        if ($action === 'retry') {
            $retryBlockMessage = $this->miniProgramRetryBlockMessage($task);
            if ($retryBlockMessage !== '' && empty($payload['force_retry'])) {
                $now = date('Y-m-d H:i:s');
                $task['retry_blocked_reason'] = $retryBlockMessage;
                $task['updated_at'] = $now;
                $tasks[$taskIndex] = $task;
                $data['mini_program_sync_tasks'] = $tasks;
                $this->store->save($data);

                return ['ok' => false, 'task' => $task, 'message' => $retryBlockMessage];
            }
            $action = (string) (($task['last_failed_action'] ?? '') ?: $this->nextMiniProgramActionForRetry((string) ($task['status'] ?? 'generated')));
            $task['retry_count'] = max(0, (int) ($task['retry_count'] ?? 0)) + 1;
            $task['status'] = match ($action) {
                'submit_review' => 'uploaded',
                'query_review' => 'review_submitted',
                'release' => 'review_passed',
                default => 'generated',
            };
        }

        $result = $this->miniProgramActionResult($action, $task, $config, $payload, $data);
        $now = date('Y-m-d H:i:s');
        $admin = $this->currentAdmin();
        $adminName = $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60);
        $task['last_action'] = $action;
        $task['last_action_at'] = $now;
        $task['request_snapshot'] = (array) ($result['request'] ?? []);
        $task['response_snapshot'] = (array) ($result['response'] ?? []);
        $task['action_logs'] = array_values((array) ($task['action_logs'] ?? []));
        $task['action_logs'][] = [
            'action' => $action,
            'status' => !empty($result['ok']) ? 'success' : 'failed',
            'message' => (string) ($result['message'] ?? ''),
            'created_at' => $now,
            'admin_id' => max(0, (int) ($admin['id'] ?? 0)),
            'admin_name' => $adminName,
        ];
        $task['action_logs'] = array_slice($task['action_logs'], -30);

        if (empty($result['ok'])) {
            $task['status'] = 'failed';
            $task['last_failed_action'] = $action;
            $task['last_error'] = (string) ($result['message'] ?? '小程序任务执行失败。');
            $task['message'] = $task['last_error'];
            $meta = $this->miniProgramFailureMeta($result, $action, $task, $now);
            $this->miniProgramApplyFailureMeta($task, $meta, $now);
        } else {
            $task['status'] = (string) ($result['next_status'] ?? $task['status'] ?? 'generated');
            $task['last_error'] = '';
            $task['message'] = (string) ($result['message'] ?? '小程序任务已更新。');
            foreach ((array) ($result['patch'] ?? []) as $key => $value) {
                $task[$key] = $value;
            }
            if ((string) ($task['status'] ?? '') === 'review_rejected') {
                $meta = $this->miniProgramBuildFailureMeta('review_rejected', (string) (($task['last_error'] ?? '') ?: '小程序审核驳回。'), $task, $action, $now, (int) ($result['response']['errcode'] ?? 0));
                $this->miniProgramApplyFailureMeta($task, $meta, $now);
            } else {
                $this->miniProgramClearFailureMeta($task);
            }
        }
        $task['updated_at'] = $now;
        $tasks[$taskIndex] = $task;
        $data['mini_program_sync_tasks'] = $tasks;
        foreach ($data['mini_program_configs'] as &$configItem) {
            if ((int) ($configItem['id'] ?? 0) !== (int) ($config['id'] ?? 0)) {
                continue;
            }
            $configItem['last_sync_at'] = $now;
            $configItem['last_sync_status'] = (string) ($task['status'] ?? '');
            $configItem['updated_at'] = $now;
            break;
        }
        unset($configItem);
        $this->store->save($data);

        return ['ok' => !empty($result['ok']), 'task' => $task, 'message' => (string) ($task['message'] ?? '')];
    }

    public function refreshMiniProgramAccessToken(array $payload): array
    {
        $data = $this->store->load();
        if ((string) ($this->currentAdminScope($data)['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以刷新小程序 access_token。'];
        }

        $configId = max(0, (int) ($payload['mini_program_config_id'] ?? $payload['config_id'] ?? $payload['id'] ?? 0));
        if ($configId <= 0) {
            return ['ok' => false, 'message' => '请选择小程序配置。'];
        }
        $config = $this->miniProgramConfigById($data, $configId);
        if ($config === null) {
            return ['ok' => false, 'message' => '小程序配置不存在。'];
        }

        $result = $this->refreshMiniProgramAccessTokenForUse($data, $config, true);
        $this->store->save($data);

        return [
            'ok' => !empty($result['ok']),
            'status' => (string) ($result['status'] ?? ''),
            'config' => (array) ($result['config'] ?? $config),
            'message' => !empty($result['ok']) ? '小程序 access_token 已刷新。' : (string) ($result['message'] ?? '小程序 access_token 刷新失败。'),
        ];
    }

    public function saveAdSlot(array $payload): array
    {
        $data = $this->store->load();
        if ((string) ($this->currentAdminScope($data)['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以配置广告位。'];
        }

        $slots = array_values((array) ($data['ad_slots'] ?? []));
        $slotId = max(0, (int) ($payload['ad_slot_id'] ?? $payload['id'] ?? 0));
        $code = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['code'] ?? '')));
        if ($code === '') {
            $code = 'ad' . base_convert((string) (time() + ($slotId > 0 ? $slotId : count($slots) + 1)), 10, 36);
        }
        foreach ($slots as $item) {
            if ((int) ($item['id'] ?? 0) !== $slotId && (string) ($item['code'] ?? '') === $code) {
                return ['ok' => false, 'message' => '广告位编码已存在。'];
            }
        }

        $name = $this->limitText(trim((string) ($payload['name'] ?? '')), 60);
        if ($name === '') {
            return ['ok' => false, 'message' => '广告位名称不能为空。'];
        }

        $adType = (string) ($payload['ad_type'] ?? 'banner');
        $adType = in_array($adType, ['reward_video', 'interstitial', 'banner', 'floating', 'native'], true) ? $adType : 'banner';
        $position = (string) ($payload['position'] ?? 'home_banner');
        $position = in_array($position, ['home_banner', 'player_pause', 'player_pre_unlock', 'reader_bottom', 'center_top', 'landing_page'], true) ? $position : 'home_banner';
        $status = (string) ($payload['status'] ?? 'active');
        $status = in_array($status, ['active', 'review', 'paused'], true) ? $status : 'active';
        $appKey = $this->normalizeAppKey((string) ($payload['app_key'] ?? ''));
        if ($appKey === '') {
            $appKey = 'default';
        }
        $app = $this->appConfig($appKey);
        if (is_array($app)) {
            $appKey = (string) ($app['app_key'] ?? $appKey);
        }

        $now = date('Y-m-d H:i:s');
        $slot = [
            'id' => $slotId > 0 ? $slotId : (empty($slots) ? 1 : ((int) max(array_column($slots, 'id')) + 1)),
            'code' => $this->limitText($code, 80),
            'name' => $name,
            'ad_type' => $adType,
            'position' => $position,
            'app_key' => $appKey,
            'status' => $status,
            'provider' => $this->limitText(trim((string) ($payload['provider'] ?? '')), 40),
            'unit_id' => $this->limitText(trim((string) ($payload['unit_id'] ?? $payload['ad_unit_id'] ?? '')), 100),
            'estimate_ecpm' => round(max(0, (float) ($payload['estimate_ecpm'] ?? $payload['ecpm'] ?? 0)), 2),
            'revenue_share_rate' => min(100, max(0, round((float) ($payload['revenue_share_rate'] ?? 100), 2))),
            'title' => $this->limitText(trim((string) ($payload['title'] ?? '')), 80),
            'image' => trim((string) ($payload['image'] ?? '')),
            'link' => trim((string) ($payload['link'] ?? '')),
            'reward_coins' => max(0, (int) ($payload['reward_coins'] ?? 0)),
            'daily_limit' => max(0, (int) ($payload['daily_limit'] ?? 0)),
            'frequency_seconds' => max(0, (int) ($payload['frequency_seconds'] ?? 0)),
            'sort' => (int) ($payload['sort'] ?? 100),
            'remark' => $this->limitText(trim((string) ($payload['remark'] ?? '')), 120),
            'updated_at' => $now,
        ];

        $replaced = false;
        foreach ($slots as &$item) {
            if ((int) ($item['id'] ?? 0) !== $slot['id']) {
                continue;
            }
            $slot['created_at'] = (string) ($item['created_at'] ?? $now);
            $item = $slot;
            $replaced = true;
            break;
        }
        unset($item);
        if (!$replaced) {
            $slot['created_at'] = $now;
            $slots[] = $slot;
        }

        $data['ad_slots'] = $slots;
        $this->store->save($data);

        return ['ok' => true, 'ad_slot' => $slot];
    }

    public function saveAdPlatformConfig(array $payload): array
    {
        $data = $this->store->load();
        if ((string) ($this->currentAdminScope($data)['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以配置广告平台。'];
        }

        $items = array_values((array) ($data['ad_platform_configs'] ?? []));
        $configId = max(0, (int) ($payload['ad_platform_config_id'] ?? $payload['id'] ?? 0));
        $appKey = $this->normalizeAppKey((string) ($payload['app_key'] ?? ''));
        if ($appKey === '') {
            $appKey = 'default';
        }
        $provider = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['provider'] ?? '')));
        if ($provider === '') {
            return ['ok' => false, 'message' => '广告平台编码不能为空。'];
        }
        foreach ($items as $item) {
            if ((int) ($item['id'] ?? 0) !== $configId && (string) ($item['app_key'] ?? 'default') === $appKey && (string) ($item['provider'] ?? '') === $provider) {
                return ['ok' => false, 'message' => '该应用下广告平台配置已存在。'];
