            $decoded = json_decode($rawInitParams, true);
            if (is_array($decoded)) {
                $initParams = $decoded;
            }
        }
        $status = (string) ($payload['status'] ?? 'active');
        $config = [
            'id' => $configId > 0 ? $configId : (empty($items) ? 1 : ((int) max(array_column($items, 'id')) + 1)),
            'app_key' => $appKey,
            'provider' => $this->limitText($provider, 40),
