            'media_id' => $this->limitText(trim((string) ($payload['media_id'] ?? '')), 100),
            'currency' => $this->limitText(trim((string) ($payload['currency'] ?? 'CNY')) ?: 'CNY', 12),
            'default_ecpm' => round(max(0, (float) ($payload['default_ecpm'] ?? $payload['estimate_ecpm'] ?? 0)), 2),
            'revenue_share_rate' => min(100, max(0, round((float) ($payload['revenue_share_rate'] ?? 100), 2))),
            'test_mode' => !empty($payload['test_mode']),
            'init_params' => $initParams,
            'privacy_note' => $this->limitText(trim((string) ($payload['privacy_note'] ?? '')), 160),
            'remark' => $this->limitText(trim((string) ($payload['remark'] ?? '')), 160),
            'updated_at' => $now,
        ];

        $replaced = false;
        foreach ($items as &$item) {
            if ((int) ($item['id'] ?? 0) !== (int) $config['id']) {
                continue;
            }
            $config['created_at'] = (string) ($item['created_at'] ?? $now);
            $item = $config;
            $replaced = true;
            break;
        }
        unset($item);
        if (!$replaced) {
            $config['created_at'] = $now;
            $items[] = $config;
        }

        $data['ad_platform_configs'] = $items;
        $this->store->save($data);

        return ['ok' => true, 'config' => $config];
    }

