    public function updateAdWaterfallConfig(array $payload): array
    {
        $data = $this->store->load();
        if ((string) ($this->currentAdminScope($data)['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以配置广告瀑布流。'];
        }

        $mode = (string) ($payload['mode'] ?? 'auto');
        $config = [
            'enabled' => !empty($payload['enabled']),
            'mode' => in_array($mode, ['manual', 'auto'], true) ? $mode : 'auto',
            'score_window_days' => max(1, min(90, (int) ($payload['score_window_days'] ?? 7))),
            'min_requests' => max(0, min(10000, (int) ($payload['min_requests'] ?? 20))),
            'max_slots' => max(0, min(100, (int) ($payload['max_slots'] ?? 0))),
            'ecpm_weight' => max(0, min(100, (float) ($payload['ecpm_weight'] ?? 45))),
            'fill_rate_weight' => max(0, min(100, (float) ($payload['fill_rate_weight'] ?? 25))),
            'ctr_weight' => max(0, min(100, (float) ($payload['ctr_weight'] ?? 10))),
            'reward_rate_weight' => max(0, min(100, (float) ($payload['reward_rate_weight'] ?? 10))),
            'failure_penalty_weight' => max(0, min(100, (float) ($payload['failure_penalty_weight'] ?? 25))),
            'manual_sort_weight' => max(0, min(100, (float) ($payload['manual_sort_weight'] ?? 10))),
            'remark' => $this->limitText(trim((string) ($payload['remark'] ?? '')), 160),
            'updated_at' => date('Y-m-d H:i:s'),
        ];
        $data['ad_waterfall_config'] = $config;
        $this->store->save($data);

        return ['ok' => true, 'config' => $config];
    }

    public function activeAdPlatformConfigs(array $filters = []): array
    {
        $data = $this->store->load();
        $appKey = $this->normalizeAppKey((string) ($filters['app_key'] ?? $filters['media_app_id'] ?? $filters['app_id'] ?? ''));
        if ($appKey === '') {
            $appKey = $this->currentAppKey($filters);
        }
        $provider = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($filters['provider'] ?? '')));
        $configs = array_values(array_filter((array) ($data['ad_platform_configs'] ?? []), static function (array $config) use ($appKey, $provider): bool {
            if (!in_array((string) ($config['status'] ?? 'active'), ['active', 'test'], true)) {
                return false;
            }
            $configAppKey = (string) ($config['app_key'] ?? 'default');
            if ($appKey !== '' && $configAppKey !== $appKey && $configAppKey !== 'default') {
                return false;
            }
            if ($provider !== '' && (string) ($config['provider'] ?? '') !== $provider) {
                return false;
            }

            return true;
        }));
        usort($configs, static fn (array $a, array $b): int => [(string) ($a['app_key'] ?? ''), (string) ($a['provider'] ?? '')] <=> [(string) ($b['app_key'] ?? ''), (string) ($b['provider'] ?? '')]);

        return array_map([$this, 'publicAdPlatformConfig'], $configs);
    }

    public function activeAdDeliveryRules(array $filters = []): array
    {
        $data = $this->store->load();
        $appKey = $this->normalizeAppKey((string) ($filters['app_key'] ?? $filters['media_app_id'] ?? $filters['app_id'] ?? ''));
        if ($appKey === '') {
            $appKey = $this->currentAppKey($filters);
        }
        $rules = array_values(array_filter((array) ($data['ad_delivery_rules'] ?? []), function (array $rule) use ($appKey): bool {
            if ((string) ($rule['status'] ?? 'active') !== 'active') {
                return false;
            }
            $appKeys = array_map('strval', (array) ($rule['app_keys'] ?? []));
            return empty($appKeys) || in_array('default', $appKeys, true) || $appKey === '' || in_array($appKey, $appKeys, true);
        }));
        usort($rules, static fn (array $a, array $b): int => [(int) ($a['priority'] ?? 100), (int) ($a['id'] ?? 0)] <=> [(int) ($b['priority'] ?? 100), (int) ($b['id'] ?? 0)]);

        return array_map([$this, 'publicAdDeliveryRule'], $rules);
    }

    public function activeAdSlots(array $filters = []): array
    {
        $data = $this->store->load();
        $appKey = $this->normalizeAppKey((string) ($filters['app_key'] ?? $filters['media_app_id'] ?? $filters['app_id'] ?? ''));
        if ($appKey === '') {
            $appKey = $this->currentAppKey($filters);
        }
        $position = (string) ($filters['position'] ?? '');
        $adType = (string) ($filters['ad_type'] ?? $filters['type'] ?? '');
        $slots = array_values(array_filter((array) ($data['ad_slots'] ?? []), static function (array $slot) use ($appKey, $position, $adType): bool {
            if ((string) ($slot['status'] ?? 'active') !== 'active') {
                return false;
            }
            $slotAppKey = (string) ($slot['app_key'] ?? 'default');
            if ($appKey !== '' && $slotAppKey !== $appKey && $slotAppKey !== 'default') {
                return false;
            }
            if ($position !== '' && (string) ($slot['position'] ?? '') !== $position) {
                return false;
            }
            if ($adType !== '' && (string) ($slot['ad_type'] ?? '') !== $adType) {
                return false;
            }

            return true;
        }));
        $rules = array_values((array) ($data['ad_delivery_rules'] ?? []));
        $hasActiveRules = !empty(array_filter($rules, static fn (array $rule): bool => (string) ($rule['status'] ?? 'active') === 'active'));
        if ($hasActiveRules) {
            $slots = array_values(array_filter(array_map(function (array $slot) use ($data, $filters, $appKey): ?array {
                $rule = $this->matchingAdDeliveryRule($slot, $data, $filters, $appKey);
                if (!$rule) {
                    return empty($this->activeSlotScopedDeliveryRules($slot, $data, $appKey)) ? $slot : null;
                }

                return $this->applyAdDeliveryRuleToSlot($slot, $rule);
            }, $slots)));
        }
        $slots = $this->applyAdWaterfallOrdering($slots, $data);

        return array_map([$this, 'publicAdSlot'], $slots);
    }

    public function recordAdEvent(array $payload): array
    {
        $data = $this->store->load();
        $slot = $this->resolveAdSlot($payload, $data);
        if (!$slot) {
            return ['ok' => false, 'message' => '广告位不存在或已停用。'];
        }
        $payloadAppKey = $this->normalizeAppKey((string) ($payload['app_key'] ?? $payload['media_app_id'] ?? $payload['app_id'] ?? ''));
        if ($payloadAppKey === '') {
            $payloadAppKey = $this->currentAppKey($payload);
        }
        $ruleAppKey = (string) (($payloadAppKey !== '' ? $payloadAppKey : ($slot['app_key'] ?? 'default')));
        $rule = $this->matchingAdDeliveryRule($slot, $data, $payload, $ruleAppKey);
        if ($rule) {
            $slot = $this->applyAdDeliveryRuleToSlot($slot, $rule);
        } elseif (!empty($this->activeSlotScopedDeliveryRules($slot, $data, $ruleAppKey))) {
            return ['ok' => false, 'message' => '广告位未命中当前分层策略。'];
        }

        $eventType = (string) ($payload['event'] ?? $payload['event_type'] ?? 'impression');
        $eventType = in_array($eventType, ['request', 'fill', 'impression', 'click', 'reward', 'fail'], true) ? $eventType : 'impression';
        $userId = max(0, (int) ($payload['user_id'] ?? $this->currentUserId()));
        $now = date('Y-m-d H:i:s');
        $events = array_values((array) ($data['ad_events'] ?? []));
        $eventId = empty($events) ? 1 : ((int) max(array_column($events, 'id')) + 1);
        $reward = [
            'granted' => false,
            'coins' => 0,
            'message' => '',
            'limit_reached' => false,
            'frequency_limited' => false,
        ];

        if ($eventType === 'reward') {
            $reward = $this->grantAdRewardIfAllowed($data, $slot, $userId, $now, $eventId);
        }

        $ecpm = round(max(0, (float) ($payload['ecpm'] ?? $payload['ad_ecpm'] ?? $slot['estimate_ecpm'] ?? 0)), 2);
        $reportedRevenue = round(max(0, (float) ($payload['revenue'] ?? $payload['amount'] ?? 0)), 4);
        $shareRate = min(100, max(0, (float) ($slot['revenue_share_rate'] ?? 100))) / 100;
        $estimatedRevenue = $eventType === 'impression' && $reportedRevenue <= 0 && $ecpm > 0 ? round(($ecpm / 1000) * $shareRate, 4) : 0.0;

        $event = [
            'id' => $eventId,
            'ad_slot_id' => (int) ($slot['id'] ?? 0),
            'code' => (string) ($slot['code'] ?? ''),
            'event' => $eventType,
            'user_id' => $userId,
            'app_key' => (string) ($slot['app_key'] ?? 'default'),
            'position' => (string) ($slot['position'] ?? ''),
            'ad_type' => (string) ($slot['ad_type'] ?? ''),
            'provider' => (string) ($slot['provider'] ?? ''),
            'unit_id' => (string) ($slot['unit_id'] ?? ''),
            'reward_coins' => $reward['granted'] ? (int) ($reward['coins'] ?? 0) : 0,
            'revenue' => $reportedRevenue > 0 ? $reportedRevenue : $estimatedRevenue,
            'ecpm' => $ecpm,
            'currency' => $this->limitText(trim((string) ($payload['currency'] ?? 'CNY')) ?: 'CNY', 12),
            'error_code' => $this->limitText(trim((string) ($payload['error_code'] ?? '')), 60),
            'error_message' => $this->limitText(trim((string) ($payload['error_message'] ?? $payload['message'] ?? '')), 160),
            'delivery_rule_id' => (int) ($slot['delivery_rule']['id'] ?? 0),
            'delivery_rule_code' => (string) ($slot['delivery_rule']['code'] ?? ''),
            'delivery_rule_name' => (string) ($slot['delivery_rule']['name'] ?? ''),
            'path' => $this->limitText(trim((string) ($payload['path'] ?? ($_SERVER['HTTP_REFERER'] ?? ''))), 220),
            'created_at' => $now,
        ];
        $data['ad_events'][] = $event;
        $data['ad_events'] = array_slice(array_values((array) ($data['ad_events'] ?? [])), -10000);
        $this->store->save($data);

        return [
            'ok' => true,
            'event' => $event,
            'reward' => $reward,
            'user' => $eventType === 'reward' && $reward['granted'] ? $this->currentUser() : null,
        ];
    }

    public function enabledPaymentRoutes(): array
    {
        $routes = array_values(array_filter($this->paymentRoutes(), static fn (array $route): bool => !empty($route['enabled'])));

        return empty($routes) ? [$this->defaultPaymentRoute()] : $routes;
    }

    public function paymentRoute(string $routeId): ?array
    {
        $routeId = trim($routeId);
        if ($routeId === '') {
            return null;
        }

        foreach ($this->paymentRoutes() as $route) {
            if ((string) ($route['id'] ?? '') === $routeId) {
                return $route;
            }
        }

        return null;
    }

    public function defaultPaymentRoute(?string $preferredRouteId = null): array
    {
        if ($preferredRouteId !== null && $preferredRouteId !== '') {
            $preferred = $this->paymentRoute($preferredRouteId);
            if ($preferred !== null) {
                return $preferred;
            }
        }

        foreach ($this->paymentRoutes() as $route) {
            if (!empty($route['is_default'])) {
                return $route;
            }
        }

        return $this->paymentRoutes()[0] ?? $this->paymentConfig();
    }

    public function paymentRouteForOrder(array $order): array
    {
        $route = $this->paymentRoute((string) ($order['payment_route_id'] ?? '')) ?? null;
        if ($route === null) {
            foreach ($this->paymentRoutes() as $item) {
                $providerMatches = (string) ($item['provider'] ?? '') === (string) ($order['payment_provider'] ?? '');
                $methodMatches = (string) ($item['payment_method'] ?? '') === (string) ($order['payment_method'] ?? '');
                if ($providerMatches && $methodMatches) {
                    $route = $item;
                    break;
                }
            }
        }

        return $route ?? $this->defaultPaymentRoute();
    }

    public function paymentDisplayForOrder(array $order): array
    {
        $route = $this->paymentRouteForOrder($order);
        $methodCode = (string) (($order['payment_method'] ?? '') ?: ($route['payment_method'] ?? 'alipay'));
        $methodName = trim((string) ($order['payment_method_name'] ?? ''));
        if ($methodName === '') {
            $methodName = $methodCode === 'jingxiu' ? (string) ($route['payment_method_name'] ?? '支付宝') : match ($methodCode) {
                'alipay' => '支付宝',
                'wechat', 'wxpay' => '微信支付',
                'qqpay' => 'QQ 钱包',
                'bank' => '网银支付',
                'jdpay' => '京东钱包',
                'unionpay' => '云闪付',
                'paypal' => 'PayPal',
                'douyinpay' => '抖音支付',
                default => strtoupper($methodCode),
            };
        }

        return [
            'route_id' => (string) (($order['payment_route_id'] ?? '') ?: ($route['id'] ?? '')),
            'provider' => (string) (($order['payment_provider'] ?? '') ?: ($route['provider'] ?? 'jingxiu')),
            'provider_name' => (string) (($order['payment_provider_name'] ?? '') ?: ($route['provider_name'] ?? '精秀聚合支付')),
            'channel_name' => (string) (($order['payment_channel_name'] ?? '') ?: ($route['channel_name'] ?? '精秀主通道')),
            'method' => $methodCode === 'jingxiu' ? (string) ($route['payment_method'] ?? 'alipay') : $methodCode,
            'method_name' => $methodName,
            'trade_type' => (string) (($order['gateway_trade_type'] ?? '') ?: ($route['trade_type'] ?? $route['pay_type'] ?? 'alipayWap')),
        ];
    }

    private function selectPaymentRouteForPayload(array $data, array $payload): array
    {
        $amount = round((float) ($payload['amount'] ?? 0), 2);
        $userId = max(0, (int) ($payload['user_id'] ?? 0));
        $preferredRouteId = trim((string) ($payload['payment_route_id'] ?? ''));
        $forceRoute = !empty($payload['force_route']) && $preferredRouteId !== '';
        $preferredRoute = $this->findRouteInList((array) ($data['payment_config']['routes'] ?? []), $preferredRouteId)
            ?? $this->defaultPaymentRoute($preferredRouteId);
        $routes = array_values((array) ($data['payment_config']['routes'] ?? []));
        $candidateRoutes = array_values(array_filter($routes, fn (array $route): bool => $this->paymentRouteAvailableForPayload($route, $data, $amount, $userId)));
        if (empty($candidateRoutes)) {
            return $preferredRoute;
        }

        if ($forceRoute) {
            foreach ($candidateRoutes as $route) {
                if ((string) ($route['id'] ?? '') === $preferredRouteId) {
                    return $route;
                }
            }
        }

        $policy = (array) ($data['payment_config']['route_policy'] ?? []);
        $mode = (string) ($policy['mode'] ?? 'default');
        $mode = in_array($mode, ['default', 'success_rate', 'round_robin'], true) ? $mode : 'default';
        if ($mode === 'success_rate') {
            return $this->selectPaymentRouteBySuccessRate($candidateRoutes, $data, $policy, $preferredRoute);
        }
        if ($mode === 'round_robin') {
            return $this->selectPaymentRouteByRoundRobin($candidateRoutes, $data, $preferredRoute);
        }

        foreach ($candidateRoutes as $route) {
            if (!empty($route['is_default'])) {
                return $route;
            }
        }

        return $candidateRoutes[0] ?? $preferredRoute;
    }

    private function paymentRouteAvailableForPayload(array $route, array $data, float $amount, int $userId): bool
    {
        if (empty($route['enabled'])) {
            return false;
        }
        $minAmount = max(0.0, (float) ($route['min_amount'] ?? 0));
        $maxAmount = max(0.0, (float) ($route['max_amount'] ?? 0));
        if ($minAmount > 0 && $amount < $minAmount) {
            return false;
        }
        if ($maxAmount > 0 && $amount > $maxAmount) {
            return false;
        }
        $hour = (int) date('G');
        $startHour = min(23, max(0, (int) ($route['open_start_hour'] ?? 0)));
        $endHour = min(23, max(0, (int) ($route['open_end_hour'] ?? 23)));
        $inOpenHours = $startHour <= $endHour
            ? ($hour >= $startHour && $hour <= $endHour)
            : ($hour >= $startHour || $hour <= $endHour);
        if (!$inOpenHours) {
            return false;
        }

        $routeId = (string) ($route['id'] ?? '');
        $today = date('Y-m-d');
        $dailyAmount = 0.0;
        $dailyOrders = 0;
        $frequencyOrders = 0;
        $frequencyWindow = max(0, (int) ($route['frequency_window'] ?? 0));
        $frequencyCount = max(0, (int) ($route['frequency_count'] ?? 0));
        $windowStart = $frequencyWindow > 0 ? (time() - ($frequencyWindow * 60)) : 0;
        foreach ((array) ($data['orders'] ?? []) as $order) {
            if ((string) ($order['payment_route_id'] ?? '') !== $routeId || !empty($order['is_test'])) {
                continue;
            }
            $createdAt = strtotime((string) ($order['created_at'] ?? '')) ?: 0;
            if ($createdAt > 0 && date('Y-m-d', $createdAt) === $today) {
                $dailyOrders++;
                if (in_array((string) ($order['status'] ?? 'pending'), ['paid', 'partial_refunded', 'refunded'], true)) {
                    $dailyAmount += max(0.0, (float) ($order['amount'] ?? 0) - (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0));
                }
            }
            if ($userId > 0 && $frequencyWindow > 0 && (int) ($order['user_id'] ?? 0) === $userId && $createdAt >= $windowStart) {
                $frequencyOrders++;
            }
        }

        $dailyAmountLimit = max(0.0, (float) ($route['daily_amount_limit'] ?? 0));
        $dailyOrderLimit = max(0, (int) ($route['daily_order_limit'] ?? 0));
        if ($dailyAmountLimit > 0 && ($dailyAmount + $amount) > $dailyAmountLimit) {
            return false;
        }
        if ($dailyOrderLimit > 0 && ($dailyOrders + 1) > $dailyOrderLimit) {
            return false;
        }
        if ($frequencyWindow > 0 && $frequencyCount > 0 && ($frequencyOrders + 1) > $frequencyCount) {
            return false;
        }

        return true;
    }

    private function selectPaymentRouteBySuccessRate(array $routes, array $data, array $policy, array $fallback): array
    {
        $windowDays = max(1, min(90, (int) ($policy['success_window_days'] ?? 7)));
        $minSample = max(0, (int) ($policy['min_sample_orders'] ?? 3));
        $since = time() - ($windowDays * 86400);
        $metrics = [];
        foreach ($routes as $route) {
            $metrics[(string) ($route['id'] ?? '')] = ['orders' => 0, 'paid' => 0, 'amount' => 0.0];
        }
        foreach ((array) ($data['orders'] ?? []) as $order) {
            $routeId = (string) ($order['payment_route_id'] ?? '');
            if (!isset($metrics[$routeId]) || !empty($order['is_test'])) {
                continue;
            }
            $createdAt = strtotime((string) ($order['created_at'] ?? '')) ?: 0;
            if ($createdAt > 0 && $createdAt < $since) {
                continue;
            }
            $metrics[$routeId]['orders']++;
            if (in_array((string) ($order['status'] ?? 'pending'), ['paid', 'partial_refunded', 'refunded'], true)) {
                $metrics[$routeId]['paid']++;
                $metrics[$routeId]['amount'] += max(0.0, (float) ($order['amount'] ?? 0) - (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0));
            }
        }

        usort($routes, static function (array $a, array $b) use ($metrics, $minSample): int {
            $aId = (string) ($a['id'] ?? '');
            $bId = (string) ($b['id'] ?? '');
            $aMetrics = $metrics[$aId] ?? ['orders' => 0, 'paid' => 0, 'amount' => 0.0];
            $bMetrics = $metrics[$bId] ?? ['orders' => 0, 'paid' => 0, 'amount' => 0.0];
            $aRate = (int) $aMetrics['orders'] > 0 ? ((int) $aMetrics['paid'] / (int) $aMetrics['orders']) : 0.0;
            $bRate = (int) $bMetrics['orders'] > 0 ? ((int) $bMetrics['paid'] / (int) $bMetrics['orders']) : 0.0;
            $aReady = (int) $aMetrics['orders'] >= $minSample ? 1 : 0;
            $bReady = (int) $bMetrics['orders'] >= $minSample ? 1 : 0;

            return [$bReady, $bRate, (float) $bMetrics['amount'], !empty($b['is_default']) ? 1 : 0, (int) ($b['id'] ?? 0)]
                <=> [$aReady, $aRate, (float) $aMetrics['amount'], !empty($a['is_default']) ? 1 : 0, (int) ($a['id'] ?? 0)];
        });

        return $routes[0] ?? $fallback;
    }

    private function selectPaymentRouteByRoundRobin(array $routes, array $data, array $fallback): array
    {
        if (count($routes) <= 1) {
            return $routes[0] ?? $fallback;
        }
        $routeIds = array_values(array_map(static fn (array $route): string => (string) ($route['id'] ?? ''), $routes));
        $routeIds = array_values(array_filter($routeIds, static fn (string $routeId): bool => $routeId !== ''));
        if (empty($routeIds)) {
            return $routes[0] ?? $fallback;
        }
        $lastRouteId = '';
        foreach (array_reverse((array) ($data['orders'] ?? [])) as $order) {
            $routeId = (string) ($order['payment_route_id'] ?? '');
            if ($routeId !== '' && in_array($routeId, $routeIds, true) && empty($order['is_test'])) {
                $lastRouteId = $routeId;
                break;
            }
        }
        $nextIndex = 0;
        if ($lastRouteId !== '') {
            $lastIndex = array_search($lastRouteId, $routeIds, true);
            $nextIndex = $lastIndex === false ? 0 : (($lastIndex + 1) % count($routeIds));
        }
        $nextRouteId = $routeIds[$nextIndex] ?? '';
        foreach ($routes as $route) {
            if ((string) ($route['id'] ?? '') === $nextRouteId) {
                return $route;
            }
        }

        return $routes[0] ?? $fallback;
    }

