    public function saveAgent(array $payload): array
    {
        $data = $this->store->load();
        if (!empty($this->currentAdminScope($data)['restricted'])) {
            return ['ok' => false, 'message' => '当前后台角色不能维护投放组织。'];
        }
        $agents = array_values((array) ($data['agents'] ?? []));
        $agentId = max(0, (int) ($payload['agent_id'] ?? 0));
        $role = (string) ($payload['role'] ?? 'agent');
        $role = in_array($role, ['business', 'leader', 'agent'], true) ? $role : 'agent';
        $parentId = max(0, (int) ($payload['parent_id'] ?? 0));
        if ($role === 'business') {
            $parentId = 0;
        }

        $name = $this->limitText(trim((string) ($payload['name'] ?? '')), 60);
        if ($name === '') {
            return ['ok' => false, 'message' => '投放账号名称不能为空。'];
        }

        if ($parentId > 0) {
            $parent = null;
            foreach ($agents as $item) {
                if ((int) ($item['id'] ?? 0) === $parentId) {
                    $parent = $item;
                    break;
                }
            }
            $validParent = $role === 'leader'
                ? (string) ($parent['role'] ?? '') === 'business'
                : (string) ($parent['role'] ?? '') === 'leader';
            if (!$validParent) {
                return ['ok' => false, 'message' => '请选择正确的上级账号。'];
            }
        } elseif ($role !== 'business') {
            return ['ok' => false, 'message' => '组长和代理必须选择上级。'];
        }

        $now = date('Y-m-d H:i:s');
        $agent = [
            'id' => $agentId > 0 ? $agentId : (empty($agents) ? 1 : ((int) max(array_column($agents, 'id')) + 1)),
            'name' => $name,
            'role' => $role,
            'parent_id' => $parentId,
            'status' => in_array((string) ($payload['status'] ?? 'active'), ['active', 'paused'], true) ? (string) $payload['status'] : 'active',
            'remark' => $this->limitText(trim((string) ($payload['remark'] ?? '')), 120),
            'updated_at' => $now,
        ];

        $replaced = false;
        foreach ($agents as &$item) {
            if ((int) ($item['id'] ?? 0) !== $agent['id']) {
                continue;
            }
            $agent['created_at'] = (string) ($item['created_at'] ?? $now);
            $item = $agent;
            $replaced = true;
            break;
        }
        unset($item);
        if (!$replaced) {
            $agent['created_at'] = $now;
            $agents[] = $agent;
        }

        $data['agents'] = $agents;
        $this->store->save($data);

        return ['ok' => true, 'agent' => $agent];
    }

    public function generateAgentSettlements(array $payload): array
    {
        $data = $this->store->load();
        if (!empty($this->currentAdminScope($data)['restricted'])) {
            return ['ok' => false, 'message' => '当前后台角色不能生成代理结算。'];
        }

        $periodStart = $this->settlementDateFromPayload($payload, ['period_start', 'started_at', 'settlement_start'], date('Y-m-01'));
        $periodEnd = $this->settlementDateFromPayload($payload, ['period_end', 'ended_at', 'settlement_end'], date('Y-m-d'));
        if ($periodEnd < $periodStart) {
            [$periodStart, $periodEnd] = [$periodEnd, $periodStart];
        }
        $targetAgentId = max(0, (int) ($payload['agent_id'] ?? 0));
        $settlementMode = (string) ($payload['settlement_mode'] ?? 'revenue_share');
        $settlementMode = in_array($settlementMode, ['revenue_share', 'profit_share'], true) ? $settlementMode : 'revenue_share';
        $commissionRate = round(max(0.0, min(100.0, (float) ($payload['commission_rate'] ?? 10))), 2);
        $remark = $this->limitText(trim((string) ($payload['remark'] ?? '')), 240);
        $rows = $this->buildAgentSettlementRows($data, $periodStart, $periodEnd, $targetAgentId, $settlementMode, $commissionRate, $remark);
        if (empty($rows)) {
            return ['ok' => false, 'message' => '当前周期没有可结算的代理收入。'];
        }

        $admin = $this->currentAdmin();
        $adminName = $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60);
        $now = date('Y-m-d H:i:s');
        $items = array_values((array) ($data['agent_settlements'] ?? []));
        $maxId = empty($items) ? 0 : (int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $items));
        $byFingerprint = [];
        foreach ($items as $index => $item) {
            $fingerprint = (string) ($item['fingerprint'] ?? '');
            if ($fingerprint !== '') {
                $byFingerprint[$fingerprint] = $index;
            }
        }

        $created = 0;
        $updated = 0;
        foreach ($rows as $row) {
            $fingerprint = (string) ($row['fingerprint'] ?? '');
            $existingIndex = $byFingerprint[$fingerprint] ?? null;
            $record = $row + [
                'id' => ++$maxId,
                'status' => 'pending',
                'payout_method' => '',
                'payout_account' => '',
                'payout_name' => '',
                'payout_reference_no' => '',
                'payout_proof_url' => '',
                'invoice_no' => '',
                'paid_at' => '',
                'agent_confirm_status' => 'none',
                'agent_confirm_remark' => '',
                'agent_confirmed_by_admin_id' => 0,
                'agent_confirmed_by_admin_name' => '',
                'agent_confirmed_by_admin_role' => '',
                'agent_confirmed_at' => '',
                'dispute_status' => 'none',
                'dispute_resolution_type' => '',
                'dispute_adjustment_amount' => 0.0,
                'dispute_final_commission_amount' => (float) ($row['commission_amount'] ?? 0),
                'dispute_resolution_remark' => '',
                'dispute_handled_by_admin_id' => 0,
                'dispute_handled_by_admin_name' => '',
                'dispute_handled_at' => '',
                'generated_by_admin_id' => max(0, (int) ($admin['id'] ?? 0)),
                'generated_by_admin_name' => $adminName,
                'handled_by_admin_id' => 0,
                'handled_by_admin_name' => '',
                'handled_at' => '',
                'created_at' => $now,
                'updated_at' => $now,
            ];
            if ($existingIndex !== null) {
                $current = $items[$existingIndex];
                if (in_array((string) ($current['status'] ?? 'pending'), ['paid', 'confirmed'], true)) {
                    continue;
                }
                $record['id'] = (int) ($current['id'] ?? $record['id']);
                $record['created_at'] = (string) ($current['created_at'] ?? $now);
                $items[$existingIndex] = $record;
                $this->appendAgentSettlementNotificationLogs($data, $record, 'generated');
                $updated++;
            } else {
                $items[] = $record;
                $this->appendAgentSettlementNotificationLogs($data, $record, 'generated');
                $created++;
            }
        }

        $data['agent_settlements'] = $items;
        $this->store->save($data);

        return [
            'ok' => true,
            'message' => '代理结算已生成：新增 ' . $created . ' 条，更新 ' . $updated . ' 条。',
            'created' => $created,
            'updated' => $updated,
            'rows' => $rows,
        ];
    }

    public function updateAgentSettlement(array $payload): array
    {
        $data = $this->store->load();
        if (!empty($this->currentAdminScope($data)['restricted'])) {
            return ['ok' => false, 'message' => '当前后台角色不能处理代理结算。'];
        }
        $settlementId = max(0, (int) ($payload['settlement_id'] ?? $payload['id'] ?? 0));
        if ($settlementId <= 0) {
            return ['ok' => false, 'message' => '结算单不存在。'];
        }
        $status = (string) ($payload['status'] ?? 'pending');
        $status = in_array($status, ['pending', 'confirmed', 'paid', 'rejected'], true) ? $status : 'pending';
        $admin = $this->currentAdmin();
        $adminName = $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60);
        $now = date('Y-m-d H:i:s');
        $proofUpload = $this->storePayoutProofUpload($payload['payout_proof_file'] ?? $payload['proof_file'] ?? null, 'settlement-' . $settlementId);
        if (empty($proofUpload['ok'])) {
            return ['ok' => false, 'message' => (string) ($proofUpload['message'] ?? '打款凭证上传失败。')];
        }
        foreach ($data['agent_settlements'] as &$item) {
            if ((int) ($item['id'] ?? 0) !== $settlementId) {
                continue;
            }
            $item['status'] = $status;
            $item['payout_method'] = $this->limitText(trim((string) ($payload['payout_method'] ?? ($item['payout_method'] ?? ''))), 60);
            $item['payout_account'] = $this->limitText(trim((string) ($payload['payout_account'] ?? ($item['payout_account'] ?? ''))), 120);
            $item['payout_name'] = $this->limitText(trim((string) ($payload['payout_name'] ?? ($item['payout_name'] ?? ''))), 80);
            $item['payout_reference_no'] = $this->limitText(trim((string) ($payload['payout_reference_no'] ?? ($item['payout_reference_no'] ?? ''))), 120);
            $item['payout_proof_url'] = $this->limitText(trim((string) ($payload['payout_proof_url'] ?? ($item['payout_proof_url'] ?? ''))), 240);
            if ((string) ($proofUpload['url'] ?? '') !== '') {
                $item['payout_proof_url'] = (string) $proofUpload['url'];
                $item['payout_proof_file_name'] = (string) ($proofUpload['file_name'] ?? '');
                $item['payout_proof_file_size'] = (int) ($proofUpload['file_size'] ?? 0);
                $item['payout_proof_mime'] = (string) ($proofUpload['mime'] ?? '');
                $item['payout_proof_uploaded_at'] = $now;
            }
            $item['invoice_no'] = $this->limitText(trim((string) ($payload['invoice_no'] ?? ($item['invoice_no'] ?? ''))), 120);
            $item['remark'] = $this->limitText(trim((string) ($payload['remark'] ?? ($item['remark'] ?? ''))), 240);
            $item['handled_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
            $item['handled_by_admin_name'] = $adminName;
            $item['handled_at'] = $now;
            $item['paid_at'] = $status === 'paid' ? $this->normalizeDateTime((string) ($payload['paid_at'] ?? $now), $now) : (string) ($item['paid_at'] ?? '');
            $item['updated_at'] = $now;
            $this->appendAgentSettlementNotificationLogs($data, $item, 'status_' . $status);
            $this->store->save($data);

            return ['ok' => true, 'message' => '代理结算状态已保存。', 'settlement' => $item];
        }
        unset($item);

        return ['ok' => false, 'message' => '结算单不存在。'];
    }

    public function bulkUpdateAgentSettlements(array $payload): array
    {
        $data = $this->store->load();
        if (!empty($this->currentAdminScope($data)['restricted'])) {
            return ['ok' => false, 'message' => '当前后台角色不能批量处理代理结算。'];
        }

        $targetStatus = (string) ($payload['target_status'] ?? $payload['bulk_status'] ?? 'paid');
        $targetStatus = in_array($targetStatus, ['pending', 'confirmed', 'paid', 'rejected'], true) ? $targetStatus : '';
        if ($targetStatus === '') {
            return ['ok' => false, 'message' => '请选择要更新的结算状态。'];
        }

        $idValues = [];
        foreach (['settlement_ids', 'settlement_ids_text', 'ids'] as $key) {
            if (!array_key_exists($key, $payload)) {
                continue;
            }
            if (is_array($payload[$key])) {
                $idValues = array_merge($idValues, array_map('strval', $payload[$key]));
            } else {
                $idValues[] = (string) $payload[$key];
            }
        }
        $idText = trim(implode(',', $idValues));
        $targetIds = [];
        if ($idText !== '') {
            foreach (preg_split('/[^0-9]+/', $idText) ?: [] as $id) {
                $id = (int) $id;
                if ($id > 0) {
                    $targetIds[$id] = true;
                }
            }
        }

        $statusFilter = (string) ($payload['status_filter'] ?? 'confirmed');
        $statusFilter = in_array($statusFilter, ['all', 'pending', 'confirmed', 'paid', 'rejected'], true) ? $statusFilter : 'confirmed';
        $periodStart = $this->settlementDateString((string) ($payload['period_start'] ?? ''));
        $periodEnd = $this->settlementDateString((string) ($payload['period_end'] ?? ''));
        if ($periodStart !== '' && $periodEnd !== '' && $periodEnd < $periodStart) {
            [$periodStart, $periodEnd] = [$periodEnd, $periodStart];
        }
        $targetAgentId = max(0, (int) ($payload['agent_id'] ?? 0));
        $payoutMethod = $this->limitText(trim((string) ($payload['payout_method'] ?? '')), 60);
        $payoutReferenceNo = $this->limitText(trim((string) ($payload['payout_reference_no'] ?? '')), 120);
        $payoutProofUrl = $this->limitText(trim((string) ($payload['payout_proof_url'] ?? '')), 240);
        $invoiceNo = $this->limitText(trim((string) ($payload['invoice_no'] ?? '')), 120);
        $remark = $this->limitText(trim((string) ($payload['remark'] ?? '')), 240);
        $paidAt = $this->normalizeDateTime((string) ($payload['paid_at'] ?? ''), date('Y-m-d H:i:s'));
        $admin = $this->currentAdmin();
        $adminName = $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60);
        $now = date('Y-m-d H:i:s');
        $proofUpload = $this->storePayoutProofUpload($payload['payout_proof_file'] ?? $payload['proof_file'] ?? null, 'settlement-bulk');
        if (empty($proofUpload['ok'])) {
            return ['ok' => false, 'message' => (string) ($proofUpload['message'] ?? '打款凭证上传失败。')];
        }
        $updated = 0;
        $matched = 0;

        foreach ($data['agent_settlements'] as &$item) {
            $settlementId = (int) ($item['id'] ?? 0);
            if (!empty($targetIds) && !isset($targetIds[$settlementId])) {
                continue;
            }
            if (empty($targetIds) && $statusFilter !== 'all' && (string) ($item['status'] ?? 'pending') !== $statusFilter) {
                continue;
            }
            if ($targetAgentId > 0 && !in_array($targetAgentId, [
                (int) ($item['agent_id'] ?? 0),
                (int) ($item['leader_id'] ?? 0),
                (int) ($item['business_id'] ?? 0),
            ], true)) {
                continue;
            }
            $itemStart = $this->settlementDateString((string) ($item['period_start'] ?? ''));
            $itemEnd = $this->settlementDateString((string) ($item['period_end'] ?? ''));
            if ($periodStart !== '' && $itemEnd !== '' && $itemEnd < $periodStart) {
                continue;
            }
            if ($periodEnd !== '' && $itemStart !== '' && $itemStart > $periodEnd) {
                continue;
            }

            $matched++;
            $item['status'] = $targetStatus;
            if ($payoutMethod !== '') {
                $item['payout_method'] = $payoutMethod;
            }
            if ($payoutReferenceNo !== '') {
                $item['payout_reference_no'] = $payoutReferenceNo;
            }
            if ($payoutProofUrl !== '') {
                $item['payout_proof_url'] = $payoutProofUrl;
            }
            if ((string) ($proofUpload['url'] ?? '') !== '') {
                $item['payout_proof_url'] = (string) $proofUpload['url'];
                $item['payout_proof_file_name'] = (string) ($proofUpload['file_name'] ?? '');
                $item['payout_proof_file_size'] = (int) ($proofUpload['file_size'] ?? 0);
                $item['payout_proof_mime'] = (string) ($proofUpload['mime'] ?? '');
                $item['payout_proof_uploaded_at'] = $now;
            }
            if ($invoiceNo !== '') {
                $item['invoice_no'] = $invoiceNo;
            }
            if ($remark !== '') {
                $item['remark'] = $remark;
            }
            $item['handled_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
            $item['handled_by_admin_name'] = $adminName;
            $item['handled_at'] = $now;
            if ($targetStatus === 'paid') {
                $item['paid_at'] = $paidAt;
            }
            $item['updated_at'] = $now;
            $this->appendAgentSettlementNotificationLogs($data, $item, 'status_' . $targetStatus);
            $updated++;
        }
        unset($item);

        if ($updated <= 0) {
            return ['ok' => false, 'message' => '没有匹配到可批量处理的结算单。', 'matched' => $matched, 'updated' => 0];
        }

        $this->store->save($data);

        return [
            'ok' => true,
            'message' => '代理结算批量处理完成：更新 ' . $updated . ' 单。',
            'matched' => $matched,
            'updated' => $updated,
            'status' => $targetStatus,
        ];
    }

    public function acknowledgeAgentSettlement(array $payload): array
    {
        $data = $this->store->load();
        $settlementId = max(0, (int) ($payload['settlement_id'] ?? $payload['id'] ?? 0));
        if ($settlementId <= 0) {
            return ['ok' => false, 'message' => '结算单不存在。'];
        }

        $confirmStatus = (string) ($payload['agent_confirm_status'] ?? $payload['confirm_status'] ?? 'confirmed');
        $confirmStatus = in_array($confirmStatus, ['confirmed', 'disputed'], true) ? $confirmStatus : '';
        if ($confirmStatus === '') {
            return ['ok' => false, 'message' => '请选择确认到账或提出异议。'];
        }
        $remark = $this->limitText(trim((string) ($payload['agent_confirm_remark'] ?? $payload['remark'] ?? '')), 240);
        if ($confirmStatus === 'disputed' && $remark === '') {
            return ['ok' => false, 'message' => '提出异议时请填写原因。'];
        }

        $scope = $this->currentAdminScope($data);
        $allowedAgentIds = array_fill_keys(array_map('intval', (array) ($scope['agent_ids'] ?? [])), true);
        $admin = $this->currentAdmin();
        $role = (string) ($scope['role'] ?? ($admin['role'] ?? 'super_admin'));
        $adminName = $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60);
        $now = date('Y-m-d H:i:s');

        foreach ($data['agent_settlements'] as &$item) {
            if ((int) ($item['id'] ?? 0) !== $settlementId) {
                continue;
            }
            if (!empty($scope['restricted'])) {
                $visible = isset($allowedAgentIds[(int) ($item['agent_id'] ?? 0)])
                    || isset($allowedAgentIds[(int) ($item['leader_id'] ?? 0)])
                    || isset($allowedAgentIds[(int) ($item['business_id'] ?? 0)]);
                if (!$visible) {
                    return ['ok' => false, 'message' => '当前后台角色不能确认该结算单。'];
                }
            }
            if ((string) ($item['status'] ?? 'pending') !== 'paid') {
                return ['ok' => false, 'message' => '结算单未打款，暂不能做到账确认。'];
            }

            $item['agent_confirm_status'] = $confirmStatus;
            $item['agent_confirm_remark'] = $remark;
            $item['agent_confirmed_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
            $item['agent_confirmed_by_admin_name'] = $adminName;
            $item['agent_confirmed_by_admin_role'] = $this->limitText($role, 40);
            $item['agent_confirmed_at'] = $now;
            if ($confirmStatus === 'disputed') {
                $item['dispute_status'] = 'open';
                $item['dispute_resolution_type'] = '';
                $item['dispute_adjustment_amount'] = 0.0;
                $item['dispute_final_commission_amount'] = round(max(0.0, (float) ($item['commission_amount'] ?? 0)), 2);
                $item['dispute_resolution_remark'] = '';
                $item['dispute_handled_by_admin_id'] = 0;
                $item['dispute_handled_by_admin_name'] = '';
                $item['dispute_handled_at'] = '';
            } elseif (!in_array((string) ($item['dispute_status'] ?? 'none'), ['resolved', 'rejected'], true)) {
                $item['dispute_status'] = 'none';
            }
            $item['updated_at'] = $now;
            $this->appendAgentSettlementNotificationLogs($data, $item, $confirmStatus === 'disputed' ? 'agent_disputed' : 'agent_confirmed');
            $this->store->save($data);

            return [
                'ok' => true,
                'message' => $confirmStatus === 'confirmed' ? '结算已确认到账。' : '结算异议已提交。',
                'settlement' => $item,
            ];
        }
        unset($item);

        return ['ok' => false, 'message' => '结算单不存在。'];
    }

    public function resolveAgentSettlementDispute(array $payload): array
    {
        $data = $this->store->load();
        if (!empty($this->currentAdminScope($data)['restricted'])) {
            return ['ok' => false, 'message' => '当前后台角色不能处理代理结算异议。'];
        }

        $settlementId = max(0, (int) ($payload['settlement_id'] ?? $payload['id'] ?? 0));
        if ($settlementId <= 0) {
            return ['ok' => false, 'message' => '结算单不存在。'];
        }
        $disputeStatus = (string) ($payload['dispute_status'] ?? 'processing');
        $disputeStatus = in_array($disputeStatus, ['open', 'processing', 'resolved', 'rejected'], true) ? $disputeStatus : '';
        if ($disputeStatus === '') {
            return ['ok' => false, 'message' => '请选择异议处理状态。'];
        }
        $resolutionType = (string) ($payload['dispute_resolution_type'] ?? '');
        $resolutionType = in_array($resolutionType, ['keep_original', 'adjust_amount', 'supplement_payout', 'reject'], true) ? $resolutionType : '';
        if (in_array($disputeStatus, ['resolved', 'rejected'], true) && $resolutionType === '') {
            return ['ok' => false, 'message' => '请填写异议处理方式。'];
        }
        if ($disputeStatus === 'rejected') {
            $resolutionType = 'reject';
        }
        $remark = $this->limitText(trim((string) ($payload['dispute_resolution_remark'] ?? $payload['remark'] ?? '')), 300);
        if (in_array($disputeStatus, ['resolved', 'rejected'], true) && $remark === '') {
            return ['ok' => false, 'message' => '请填写异议处理结论。'];
        }
        $adjustmentAmount = round((float) ($payload['dispute_adjustment_amount'] ?? 0), 2);
        if (!in_array($resolutionType, ['adjust_amount', 'supplement_payout'], true)) {
            $adjustmentAmount = 0.0;
        }

        $admin = $this->currentAdmin();
        $adminName = $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60);
        $now = date('Y-m-d H:i:s');
        foreach ($data['agent_settlements'] as &$item) {
            if ((int) ($item['id'] ?? 0) !== $settlementId) {
                continue;
            }
            if ((string) ($item['agent_confirm_status'] ?? 'none') !== 'disputed') {
                return ['ok' => false, 'message' => '该结算单没有代理异议。'];
            }
            $commissionAmount = round(max(0.0, (float) ($item['commission_amount'] ?? 0)), 2);
            $finalCommissionAmount = round(max(0.0, $commissionAmount + $adjustmentAmount), 2);
            $item['dispute_status'] = $disputeStatus;
            $item['dispute_resolution_type'] = $resolutionType;
            $item['dispute_adjustment_amount'] = $adjustmentAmount;
            $item['dispute_final_commission_amount'] = $finalCommissionAmount;
            $item['dispute_resolution_remark'] = $remark;
            $item['dispute_handled_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
            $item['dispute_handled_by_admin_name'] = $adminName;
            $item['dispute_handled_at'] = $now;
            $item['updated_at'] = $now;
            $this->appendAgentSettlementNotificationLogs($data, $item, 'dispute_' . $disputeStatus);
            $this->store->save($data);

            return [
                'ok' => true,
                'message' => '代理结算异议已处理。',
                'settlement' => $item,
            ];
        }
        unset($item);

        return ['ok' => false, 'message' => '结算单不存在。'];
    }

    public function recordAgentPayoutBatch(array $payload): array
    {
        $data = $this->store->load();
        if (!empty($this->currentAdminScope($data)['restricted'])) {
            return ['ok' => false, 'message' => '当前后台角色不能生成代理打款批次。'];
        }

        $batchNo = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['batch_no'] ?? '')));
        if ($batchNo === '') {
            $batchNo = 'agent-pay-' . date('Ymd-His');
        }
        $batches = array_values((array) ($data['agent_payout_batches'] ?? []));
        $existingBatchNos = array_fill_keys(array_map(static fn (array $item): string => (string) ($item['batch_no'] ?? ''), $batches), true);
        $baseBatchNo = $batchNo;
        $suffix = 2;
        while (isset($existingBatchNos[$batchNo])) {
            $batchNo = $baseBatchNo . '-' . $suffix;
            $suffix++;
        }

        $settlementIds = array_values(array_unique(array_filter(array_map('intval', (array) ($payload['settlement_ids'] ?? [])), static fn (int $id): bool => $id > 0)));
        $agentIds = array_values(array_unique(array_filter(array_map('intval', (array) ($payload['agent_ids'] ?? [])), static fn (int $id): bool => $id > 0)));
        $admin = $this->currentAdmin();
        $adminName = $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60);
        $now = date('Y-m-d H:i:s');
        $fileName = trim((string) ($payload['file_name'] ?? ''));
        if ($fileName === '') {
            $fileName = 'jingxiu-agent-payout-' . $batchNo . '.csv';
        }
        $batch = [
            'id' => empty($batches) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $batches)) + 1),
            'batch_no' => $batchNo,
            'channel' => $this->limitText(trim((string) ($payload['channel'] ?? '通用打款')), 60),
            'status' => 'generated',
            'item_count' => max(0, (int) ($payload['item_count'] ?? count($settlementIds))),
            'total_amount' => round(max(0.0, (float) ($payload['total_amount'] ?? 0)), 2),
            'settlement_ids' => array_slice($settlementIds, 0, 1000),
            'agent_ids' => array_slice($agentIds, 0, 1000),
            'filters' => is_array($payload['filters'] ?? null) ? (array) $payload['filters'] : [],
            'file_name' => $this->limitText($fileName, 160),
            'proof_url' => '',
            'remark' => $this->limitText(trim((string) ($payload['remark'] ?? '')), 240),
            'generated_by_admin_id' => max(0, (int) ($admin['id'] ?? 0)),
            'generated_by_admin_name' => $adminName,
            'handled_by_admin_id' => 0,
            'handled_by_admin_name' => '',
            'handled_at' => '',
            'paid_at' => '',
            'created_at' => $now,
            'updated_at' => $now,
        ];
        $batches[] = $batch;
        $data['agent_payout_batches'] = array_slice(array_values($batches), -1000);
        $this->store->save($data);

        return ['ok' => true, 'batch' => $batch, 'message' => '代理打款批次已记录。'];
    }

    public function updateAgentPayoutBatch(array $payload): array
    {
        $data = $this->store->load();
        if (!empty($this->currentAdminScope($data)['restricted'])) {
            return ['ok' => false, 'message' => '当前后台角色不能维护代理打款批次。'];
        }

        $batchId = max(0, (int) ($payload['batch_id'] ?? $payload['id'] ?? 0));
        $batchNo = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['batch_no'] ?? '')));
        if ($batchId <= 0 && $batchNo === '') {
            return ['ok' => false, 'message' => '打款批次不存在。'];
        }
        $status = (string) ($payload['status'] ?? 'generated');
        $status = in_array($status, ['generated', 'paid', 'failed', 'cancelled'], true) ? $status : 'generated';
        $admin = $this->currentAdmin();
        $adminName = $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60);
        $now = date('Y-m-d H:i:s');
        $proofUpload = $this->storePayoutProofUpload($payload['proof_file'] ?? $payload['payout_proof_file'] ?? null, 'payout-batch-' . ($batchId > 0 ? (string) $batchId : ($batchNo !== '' ? $batchNo : 'manual')));
        if (empty($proofUpload['ok'])) {
            return ['ok' => false, 'message' => (string) ($proofUpload['message'] ?? '打款凭证上传失败。')];
        }
        foreach ($data['agent_payout_batches'] as &$batch) {
            if ($batchId > 0 && (int) ($batch['id'] ?? 0) !== $batchId) {
                continue;
            }
            if ($batchId <= 0 && (string) ($batch['batch_no'] ?? '') !== $batchNo) {
                continue;
            }
            $batch['status'] = $status;
            $batch['proof_url'] = $this->limitText(trim((string) ($payload['proof_url'] ?? ($batch['proof_url'] ?? ''))), 240);
            if ((string) ($proofUpload['url'] ?? '') !== '') {
                $batch['proof_url'] = (string) $proofUpload['url'];
                $batch['proof_file_name'] = (string) ($proofUpload['file_name'] ?? '');
                $batch['proof_file_size'] = (int) ($proofUpload['file_size'] ?? 0);
                $batch['proof_mime'] = (string) ($proofUpload['mime'] ?? '');
                $batch['proof_uploaded_at'] = $now;
            }
            $batch['remark'] = $this->limitText(trim((string) ($payload['remark'] ?? ($batch['remark'] ?? ''))), 240);
            $batch['paid_at'] = $status === 'paid' ? $this->normalizeDateTime((string) ($payload['paid_at'] ?? $now), $now) : (string) ($batch['paid_at'] ?? '');
            $batch['handled_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
            $batch['handled_by_admin_name'] = $adminName;
            $batch['handled_at'] = $now;
            $batch['updated_at'] = $now;
            $this->store->save($data);

            return ['ok' => true, 'batch' => $batch, 'message' => '代理打款批次已更新。'];
        }
        unset($batch);

        return ['ok' => false, 'message' => '打款批次不存在。'];
    }

    private function storePayoutProofUpload(mixed $file, string $prefix): array
    {
        if (!is_array($file) || (int) ($file['error'] ?? UPLOAD_ERR_NO_FILE) === UPLOAD_ERR_NO_FILE) {
            return ['ok' => true, 'url' => ''];
        }

        $error = (int) ($file['error'] ?? UPLOAD_ERR_OK);
        if ($error !== UPLOAD_ERR_OK) {
            return ['ok' => false, 'message' => '打款凭证上传失败，错误码：' . $error . '。'];
        }

        $tmpName = (string) ($file['tmp_name'] ?? '');
        if ($tmpName === '' || !is_file($tmpName)) {
            return ['ok' => false, 'message' => '打款凭证文件不存在。'];
        }

        $size = max(0, (int) ($file['size'] ?? filesize($tmpName) ?: 0));
        if ($size <= 0) {
            return ['ok' => false, 'message' => '打款凭证文件为空。'];
        }
        if ($size > 8 * 1024 * 1024) {
            return ['ok' => false, 'message' => '打款凭证不能超过 8MB。'];
        }

        $originalName = $this->limitText(trim(basename((string) ($file['name'] ?? 'proof'))), 160);
        $extension = strtolower(pathinfo($originalName, PATHINFO_EXTENSION));
        $allowedExtensions = ['jpg', 'jpeg', 'png', 'webp', 'pdf', 'csv'];
        if (!in_array($extension, $allowedExtensions, true)) {
            return ['ok' => false, 'message' => '打款凭证仅支持 JPG、PNG、WEBP、PDF 或 CSV。'];
        }

        $mime = '';
        if (function_exists('finfo_open')) {
            $finfo = finfo_open(FILEINFO_MIME_TYPE);
            if ($finfo !== false) {
                $detected = finfo_file($finfo, $tmpName);
                $mime = is_string($detected) ? $detected : '';
                if (PHP_VERSION_ID < 80500) {
                    finfo_close($finfo);
                }
            }
        }
        $allowedMimes = [
            'image/jpeg', 'image/png', 'image/webp', 'application/pdf', 'text/plain',
            'text/csv', 'application/csv', 'application/vnd.ms-excel', 'application/octet-stream',
        ];
        if ($mime !== '' && !in_array($mime, $allowedMimes, true)) {
            return ['ok' => false, 'message' => '打款凭证文件类型不支持。'];
        }

        $month = date('Ym');
        $relativeDir = '/uploads/agent-payout-proofs/' . $month;
        $targetDir = dirname(__DIR__, 2) . '/public' . $relativeDir;
        if (!is_dir($targetDir) && !mkdir($targetDir, 0775, true) && !is_dir($targetDir)) {
            return ['ok' => false, 'message' => '打款凭证目录创建失败。'];
        }

        $safePrefix = preg_replace('/[^a-zA-Z0-9_-]+/', '-', trim($prefix)) ?: 'proof';
        $targetName = $safePrefix . '-' . date('YmdHis') . '-' . bin2hex(random_bytes(4)) . '.' . $extension;
        $targetPath = $targetDir . '/' . $targetName;
        $stored = is_uploaded_file($tmpName)
            ? move_uploaded_file($tmpName, $targetPath)
            : (PHP_SAPI === 'cli' && copy($tmpName, $targetPath));
        if (!$stored) {
            return ['ok' => false, 'message' => '打款凭证保存失败。'];
        }
        @chmod($targetPath, 0664);

        return [
            'ok' => true,
            'url' => $relativeDir . '/' . $targetName,
            'file_name' => $originalName,
            'file_size' => $size,
            'mime' => $mime,
        ];
    }

    private function appendAgentSettlementNotificationLogs(array &$data, array $settlement, string $event): void
    {
        $receivers = $this->agentSettlementNotificationReceivers($data, $settlement, $event);
        if (empty($receivers)) {
            return;
        }

        $data['agent_settlement_notification_logs'] = array_values((array) ($data['agent_settlement_notification_logs'] ?? []));
        $nextId = empty($data['agent_settlement_notification_logs'])
            ? 1
            : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $data['agent_settlement_notification_logs'])) + 1);
        $now = date('Y-m-d H:i:s');
        [$title, $message] = $this->agentSettlementNotificationContent($settlement, $event);
        foreach ($receivers as $receiver) {
            $data['agent_settlement_notification_logs'][] = [
                'id' => $nextId++,
                'settlement_id' => (int) ($settlement['id'] ?? 0),
                'event' => $event,
                'channel' => 'in_app',
                'receiver_admin_id' => (int) ($receiver['id'] ?? 0),
                'receiver_name' => $this->limitText((string) (($receiver['nickname'] ?? '') ?: ($receiver['username'] ?? '管理员')), 80),
                'receiver_role' => $this->limitText((string) ($receiver['role'] ?? ''), 40),
                'receiver_contact' => $this->limitText((string) (($receiver['email'] ?? '') ?: ($receiver['phone'] ?? '')), 120),
                'agent_id' => (int) ($settlement['agent_id'] ?? 0),
                'leader_id' => (int) ($settlement['leader_id'] ?? 0),
                'business_id' => (int) ($settlement['business_id'] ?? 0),
                'title' => $title,
                'message' => $message,
                'status' => 'success',
                'created_at' => $now,
            ];
        }
        $data['agent_settlement_notification_logs'] = array_slice(array_values($data['agent_settlement_notification_logs']), -5000);
    }

    private function agentSettlementNotificationReceivers(array $data, array $settlement, string $event): array
    {
        $admins = array_values(array_filter((array) ($data['admins'] ?? []), static fn (array $admin): bool => (string) ($admin['status'] ?? 'active') === 'active'));
        $notifySuper = in_array($event, ['agent_confirmed', 'agent_disputed'], true);
        if (str_starts_with($event, 'dispute_')) {
            $notifySuper = false;
        }
        $ids = [];
        if ($notifySuper) {
            foreach ($admins as $admin) {
                if ((string) ($admin['role'] ?? '') === 'super_admin') {
                    $ids[(int) ($admin['id'] ?? 0)] = $admin;
                }
            }
            return array_values($ids);
        }

        $targetByRole = [
            'agent' => (int) ($settlement['agent_id'] ?? 0),
            'leader' => (int) ($settlement['leader_id'] ?? 0),
            'business' => (int) ($settlement['business_id'] ?? 0),
        ];
        foreach ($admins as $admin) {
            $role = (string) ($admin['role'] ?? '');
            if (!isset($targetByRole[$role])) {
                continue;
            }
            if ((int) ($admin['agent_id'] ?? 0) !== (int) $targetByRole[$role]) {
                continue;
            }
            $ids[(int) ($admin['id'] ?? 0)] = $admin;
        }
        if (empty($ids)) {
            foreach ($admins as $admin) {
                if ((string) ($admin['role'] ?? '') === 'super_admin') {
                    $ids[(int) ($admin['id'] ?? 0)] = $admin;
                }
            }
        }

        return array_values($ids);
    }

    private function agentSettlementNotificationContent(array $settlement, string $event): array
    {
        $agentName = (string) ($settlement['agent_name'] ?? '代理');
        $period = (string) ($settlement['period_start'] ?? '') . ' 至 ' . (string) ($settlement['period_end'] ?? '');
        $amount = number_format((float) ($settlement['commission_amount'] ?? 0), 2);
        $finalAmount = number_format((float) ($settlement['dispute_final_commission_amount'] ?? $settlement['commission_amount'] ?? 0), 2);
        $eventLabel = match ($event) {
            'generated' => '结算单已生成',
            'status_pending' => '结算状态改为待确认',
            'status_confirmed' => '结算已确认',
            'status_paid' => '结算已打款',
            'status_rejected' => '结算已驳回',
            'agent_confirmed' => '代理已确认到账',
            'agent_disputed' => '代理提交结算异议',
            'dispute_open' => '结算异议待处理',
            'dispute_processing' => '结算异议处理中',
            'dispute_resolved' => '结算异议已解决',
            'dispute_rejected' => '结算异议已驳回',
            default => '代理结算更新',
        };
        $message = match ($event) {
            'generated' => $agentName . ' ' . $period . ' 结算单已生成，佣金 ' . $amount . ' 元。',
            'status_paid' => $agentName . ' ' . $period . ' 结算已打款，佣金 ' . $amount . ' 元，请核对到账。',
            'agent_disputed' => $agentName . ' 对 ' . $period . ' 结算提出异议：' . (string) ($settlement['agent_confirm_remark'] ?? ''),
            'agent_confirmed' => $agentName . ' 已确认 ' . $period . ' 结算到账。',
            'dispute_resolved' => $agentName . ' ' . $period . ' 结算异议已解决，最终佣金 ' . $finalAmount . ' 元。',
            'dispute_rejected' => $agentName . ' ' . $period . ' 结算异议已驳回，处理结论：' . (string) ($settlement['dispute_resolution_remark'] ?? ''),
            default => $agentName . ' ' . $period . ' ' . $eventLabel . '，佣金 ' . $amount . ' 元。',
        };

        return [$eventLabel, $this->limitText($message, 600)];
    }

    public function promotionCosts(): array
    {
        $costs = array_values($this->store->load()['promotion_costs'] ?? []);
        usort($costs, static fn (array $a, array $b): int => strcmp((string) ($b['date'] ?? ''), (string) ($a['date'] ?? '')));

        return $costs;
    }

    public function landingPages(?array $data = null): array
    {
        $data ??= $this->store->load();
        $pages = array_values((array) ($data['landing_pages'] ?? []));
        usort($pages, static fn (array $a, array $b): int => [(int) ($a['sort'] ?? 0), (int) ($a['id'] ?? 0)] <=> [(int) ($b['sort'] ?? 0), (int) ($b['id'] ?? 0)]);

        return $pages;
    }

    public function landingPageEvents(?array $data = null): array
    {
        $data ??= $this->store->load();
        $events = array_values((array) ($data['landing_page_events'] ?? []));
        usort($events, static fn (array $a, array $b): int => strcmp((string) ($b['created_at'] ?? ''), (string) ($a['created_at'] ?? '')));

        return $events;
    }

    public function findLandingPage(string $slug, ?array $data = null): ?array
    {
        $slug = preg_replace('/[^a-zA-Z0-9_-]+/', '', $slug);
        if ($slug === '') {
            return null;
        }
        $data ??= $this->store->load();
        foreach ((array) ($data['landing_pages'] ?? []) as $page) {
            if ((string) ($page['slug'] ?? '') === $slug) {
                return $page;
            }
        }

        return null;
    }

    public function saveLandingPage(array $payload): array
    {
        $data = $this->store->load();
        $scope = $this->currentAdminScope($data);
        $pages = array_values((array) ($data['landing_pages'] ?? []));
        $pageId = max(0, (int) ($payload['landing_page_id'] ?? $payload['id'] ?? 0));
        $promotionLinkId = max(0, (int) ($payload['promotion_link_id'] ?? 0));
        $link = null;
        foreach ((array) ($data['promotion_links'] ?? []) as $item) {
            if ($promotionLinkId > 0 && (int) ($item['id'] ?? 0) === $promotionLinkId) {
                $link = $item;
                break;
            }
        }
        if ($promotionLinkId > 0 && (!$link || !$this->adminCanAccessPromotionLink($link, $data))) {
            return ['ok' => false, 'message' => '当前后台角色不能绑定该推广链接。'];
        }

        $agentId = max(0, (int) ($payload['agent_id'] ?? ($link['agent_id'] ?? 0)));
        if (!empty($scope['restricted'])) {
            $allowedAgentIds = array_values(array_map('intval', (array) ($scope['agent_ids'] ?? [])));
            if ($agentId <= 0) {
                $agentId = (int) ($scope['agent_id'] ?? 0);
            }
            if ($agentId <= 0 || !in_array($agentId, $allowedAgentIds, true)) {
                return ['ok' => false, 'message' => '当前后台角色不能为该投放账号创建落地页。'];
            }
        }

        $name = $this->limitText(trim((string) ($payload['name'] ?? '')), 60);
        if ($name === '') {
            return ['ok' => false, 'message' => '落地页名称不能为空。'];
        }
        $contentType = in_array((string) ($payload['content_type'] ?? ($link['content_type'] ?? '')), ['drama', 'novel'], true)
            ? (string) ($payload['content_type'] ?? ($link['content_type'] ?? ''))
            : 'drama';
        $dramaId = $contentType === 'drama' ? max(0, (int) ($payload['drama_id'] ?? ($link['drama_id'] ?? 0))) : 0;
        $episodeId = $contentType === 'drama' ? max(0, (int) ($payload['episode_id'] ?? ($link['episode_id'] ?? 0))) : 0;
        $novelId = $contentType === 'novel' ? max(0, (int) ($payload['novel_id'] ?? ($link['novel_id'] ?? 0))) : 0;
        $chapterId = $contentType === 'novel' ? max(0, (int) ($payload['chapter_id'] ?? ($link['chapter_id'] ?? 0))) : 0;
        $appKey = $this->normalizeAppKey((string) ($payload['app_key'] ?? ($link['media_app_id'] ?? '')));
        $app = $appKey !== '' ? $this->appConfig($appKey) : null;
        if (is_array($app)) {
            $appKey = (string) ($app['app_key'] ?? $appKey);
        }

        $slug = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['slug'] ?? '')));
        if ($slug === '') {
            $slug = 'lp' . base_convert((string) (time() + ($pageId > 0 ? $pageId : count($pages) + 1)), 10, 36);
        }
        $existingSlugs = [];
        foreach ($pages as $page) {
            if ((int) ($page['id'] ?? 0) !== $pageId) {
                $existingSlugs[] = (string) ($page['slug'] ?? '');
            }
        }
        $baseSlug = $slug;
        $suffix = 2;
        while (in_array($slug, $existingSlugs, true)) {
            $slug = $baseSlug . '-' . $suffix;
            $suffix++;
        }

        $title = $this->limitText(trim((string) ($payload['title'] ?? '')), 80);
        if ($title === '') {
            $title = $contentType === 'novel'
                ? (string) (($this->findNovel($novelId)['title'] ?? '') ?: $name)
                : (string) (($this->findDrama($dramaId)['title'] ?? '') ?: $name);
        }
        $template = (string) ($payload['template'] ?? $contentType);
        $template = in_array($template, ['drama', 'novel', 'mixed'], true) ? $template : $contentType;
        $status = (string) ($payload['status'] ?? 'active');
        $status = in_array($status, ['active', 'review', 'paused'], true) ? $status : 'active';
        $ctaMode = (string) ($payload['cta_mode'] ?? 'content');
        $ctaMode = in_array($ctaMode, ['content', 'promotion', 'custom'], true) ? $ctaMode : 'content';
        $now = date('Y-m-d H:i:s');
        $page = [
            'id' => $pageId > 0 ? $pageId : (empty($pages) ? 1 : ((int) max(array_column($pages, 'id')) + 1)),
            'slug' => $this->limitText($slug, 80),
            'name' => $name,
            'title' => $title,
            'subtitle' => $this->limitText(trim((string) ($payload['subtitle'] ?? '')), 140),
            'template' => $template,
            'status' => $status,
            'cta_text' => $this->limitText(trim((string) ($payload['cta_text'] ?? '')) ?: ($contentType === 'novel' ? '立即阅读' : '立即观看'), 24),
            'cta_mode' => $ctaMode,
            'cta_url' => trim((string) ($payload['cta_url'] ?? '')),
            'promotion_link_id' => $promotionLinkId,
            'promotion_code' => (string) ($link['code'] ?? preg_replace('/[^a-zA-Z0-9_-]+/', '', (string) ($payload['promotion_code'] ?? ''))),
            'agent_id' => $agentId,
            'content_type' => $contentType,
            'drama_id' => $dramaId,
            'episode_id' => $episodeId,
            'novel_id' => $novelId,
            'chapter_id' => $chapterId,
            'app_key' => $appKey,
            'cover' => trim((string) ($payload['cover'] ?? '')),
            'badge' => $this->limitText(trim((string) ($payload['badge'] ?? '')), 30),
            'selling_points' => $this->landingPagePointsFromPayload($payload['selling_points'] ?? $payload['selling_points_text'] ?? ''),
            'traffic_platform' => $this->limitText(trim((string) ($payload['traffic_platform'] ?? ($link['traffic_platform'] ?? ''))), 40),
            'channel_id' => $this->limitText(trim((string) ($payload['channel_id'] ?? ($link['channel_id'] ?? ''))), 60),
            'media_app_id' => $this->limitText($appKey !== '' ? $appKey : trim((string) ($payload['media_app_id'] ?? ($link['media_app_id'] ?? ''))), 60),
            'ad_id' => $this->limitText(trim((string) ($payload['ad_id'] ?? ($link['ad_id'] ?? ''))), 80),
            'creative_id' => $this->limitText(trim((string) ($payload['creative_id'] ?? ($link['creative_id'] ?? ''))), 80),
            'material_id' => $this->limitText(trim((string) ($payload['material_id'] ?? ($link['material_id'] ?? ''))), 80),
            'sort' => (int) ($payload['sort'] ?? 100),
            'updated_at' => $now,
        ];

        $replaced = false;
        foreach ($pages as &$item) {
            if ((int) ($item['id'] ?? 0) !== $page['id']) {
                continue;
            }
            $page['views'] = max(0, (int) ($item['views'] ?? 0));
            $page['clicks'] = max(0, (int) ($item['clicks'] ?? 0));
            $page['created_at'] = (string) ($item['created_at'] ?? $now);
            $item = $page;
            $replaced = true;
            break;
        }
        unset($item);
        if (!$replaced) {
            $page['views'] = 0;
            $page['clicks'] = 0;
            $page['created_at'] = $now;
            $pages[] = $page;
        }

        $data['landing_pages'] = $pages;
        $this->store->save($data);

        return ['ok' => true, 'landing_page' => $page];
    }

    public function landingPageForVisit(string $slug): ?array
    {
        $data = $this->store->load();
        $page = null;
        $pageIndex = null;
        foreach ((array) ($data['landing_pages'] ?? []) as $index => $item) {
            if ((string) ($item['slug'] ?? '') === preg_replace('/[^a-zA-Z0-9_-]+/', '', $slug)) {
                $page = $item;
                $pageIndex = $index;
                break;
            }
        }
        if (!$page || (string) ($page['status'] ?? 'active') === 'paused') {
            return null;
        }

        $link = null;
        if ((int) ($page['promotion_link_id'] ?? 0) > 0) {
            foreach ((array) ($data['promotion_links'] ?? []) as $item) {
                if ((int) ($item['id'] ?? 0) === (int) ($page['promotion_link_id'] ?? 0)) {
                    $link = $item;
                    break;
                }
            }
        }
        $this->setPromotionAttributionFromLandingPage($page, $link);
        $this->appendLandingPageEvent($data, $page, 'view', $this->landingPageTargetUrl($page, $link));
        if ($pageIndex !== null) {
            $data['landing_pages'][$pageIndex]['views'] = max(0, (int) ($data['landing_pages'][$pageIndex]['views'] ?? 0)) + 1;
            $data['landing_pages'][$pageIndex]['updated_at'] = date('Y-m-d H:i:s');
            $page = $data['landing_pages'][$pageIndex];
        }
        $this->store->save($data);

        return $this->landingPageViewModel($page, $link);
    }

    public function landingPageClickTarget(string $slug): ?string
    {
        $data = $this->store->load();
        $page = null;
        $pageIndex = null;
        foreach ((array) ($data['landing_pages'] ?? []) as $index => $item) {
            if ((string) ($item['slug'] ?? '') === preg_replace('/[^a-zA-Z0-9_-]+/', '', $slug)) {
                $page = $item;
                $pageIndex = $index;
                break;
            }
        }
        if (!$page || (string) ($page['status'] ?? 'active') === 'paused') {
            return null;
        }
        $link = null;
        if ((int) ($page['promotion_link_id'] ?? 0) > 0) {
            foreach ((array) ($data['promotion_links'] ?? []) as $item) {
                if ((int) ($item['id'] ?? 0) === (int) ($page['promotion_link_id'] ?? 0)) {
                    $link = $item;
                    break;
                }
            }
        }
        $target = $this->landingPageTargetUrl($page, $link);
        $this->setPromotionAttributionFromLandingPage($page, $link);
        $this->appendLandingPageEvent($data, $page, 'click', $target);
        if ($pageIndex !== null) {
            $data['landing_pages'][$pageIndex]['clicks'] = max(0, (int) ($data['landing_pages'][$pageIndex]['clicks'] ?? 0)) + 1;
            $data['landing_pages'][$pageIndex]['updated_at'] = date('Y-m-d H:i:s');
        }
        $this->store->save($data);

        return $target;
    }

    public function createPromotionLink(array $payload): array
    {
        $data = $this->store->load();
        $scope = $this->currentAdminScope($data);
        $agentId = max(0, (int) ($payload['agent_id'] ?? 0));
        if (!empty($scope['restricted'])) {
            $allowedAgentIds = array_values(array_map('intval', (array) ($scope['agent_ids'] ?? [])));
            if ($agentId <= 0) {
                $agentId = (int) ($scope['agent_id'] ?? 0);
            }
            if (!in_array($agentId, $allowedAgentIds, true)) {
                throw new \RuntimeException('当前后台角色不能为该投放账号创建推广链接。');
            }
        }
        $nextId = empty($data['promotion_links']) ? 1 : ((int) max(array_column($data['promotion_links'], 'id')) + 1);
        $code = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['code'] ?? '')));
        if ($code === '') {
            $code = 'p' . base_convert((string) (time() + $nextId), 10, 36);
        }

        $existingCodes = array_map(static fn (array $link): string => (string) ($link['code'] ?? ''), $data['promotion_links']);
        $baseCode = $code;
        $suffix = 2;
        while (in_array($code, $existingCodes, true)) {
            $code = $baseCode . '-' . $suffix;
            $suffix++;
        }

        $contentType = in_array((string) ($payload['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $payload['content_type'] : 'drama';
        $dramaId = max(0, (int) ($payload['drama_id'] ?? 0));
        $episodeId = max(0, (int) ($payload['episode_id'] ?? 0));
        $novelId = max(0, (int) ($payload['novel_id'] ?? 0));
        $chapterId = max(0, (int) ($payload['chapter_id'] ?? 0));
        if ($contentType === 'novel') {
            $dramaId = 0;
            $episodeId = 0;
        } else {
            $novelId = 0;
            $chapterId = 0;
        }
        $appKey = $this->normalizeAppKey((string) ($payload['app_key'] ?? $payload['media_app_id'] ?? $payload['app_id'] ?? ''));
        $app = $appKey !== '' ? $this->appConfig($appKey) : null;
        if (is_array($app)) {
            $appKey = (string) ($app['app_key'] ?? $appKey);
        }
        $targetUrl = trim((string) ($payload['target_url'] ?? ''));
        if ($targetUrl === '' && $contentType === 'novel' && $novelId > 0) {
            $targetUrl = $chapterId > 0
                ? '/?route=novel-read&novel_id=' . $novelId . '&chapter_id=' . $chapterId
                : '/?route=novel&id=' . $novelId;
        }
        if ($targetUrl === '' && $contentType === 'drama' && $dramaId > 0) {
            $targetUrl = '/?route=yulan&id=' . $dramaId . ($episodeId > 0 ? '&episode_id=' . $episodeId : '');
        }
        if ($targetUrl === '') {
            $targetUrl = $contentType === 'novel' ? '/?route=novels' : '/duanju';
        }
        if ($appKey !== '') {
            $targetUrl = $this->urlWithQueryParam($targetUrl, 'app_key', $appKey);
        }

        $now = date('Y-m-d H:i:s');
        $link = [
            'id' => $nextId,
            'code' => $code,
            'name' => $this->limitText(trim((string) ($payload['name'] ?? '')) ?: '推广链接' . $nextId, 60),
            'content_type' => $contentType,
            'drama_id' => $dramaId,
            'episode_id' => $episodeId,
            'novel_id' => $novelId,
            'chapter_id' => $chapterId,
            'agent_id' => $agentId,
            'source' => $this->limitText(trim((string) ($payload['source'] ?? '')), 40),
            'campaign' => $this->limitText(trim((string) ($payload['campaign'] ?? '')), 60),
            'traffic_platform' => $this->limitText(trim((string) ($payload['traffic_platform'] ?? $payload['platform'] ?? '')), 40),
            'channel_id' => $this->limitText(trim((string) ($payload['channel_id'] ?? '')), 60),
            'media_app_id' => $this->limitText($appKey !== '' ? $appKey : trim((string) ($payload['media_app_id'] ?? $payload['app_id'] ?? '')), 60),
            'app_name' => $this->limitText((string) ($app['name'] ?? ''), 60),
            'ad_id' => $this->limitText(trim((string) ($payload['ad_id'] ?? '')), 80),
            'creative_id' => $this->limitText(trim((string) ($payload['creative_id'] ?? '')), 80),
            'material_id' => $this->limitText(trim((string) ($payload['material_id'] ?? '')), 80),
            'cost_budget_limit' => round(max(0, (float) ($payload['cost_budget_limit'] ?? 0)), 2),
            'min_recovery_rate' => round(max(0, (float) ($payload['min_recovery_rate'] ?? 0)), 2),
            'auto_pause_on_cost' => !empty($payload['auto_pause_on_cost']),
            'auto_pause_min_cost' => round(max(0, (float) ($payload['auto_pause_min_cost'] ?? 0)), 2),
            'auto_paused_at' => '',
            'auto_paused_reason' => '',
            'status' => in_array((string) ($payload['status'] ?? ''), ['active', 'review', 'paused'], true) ? (string) $payload['status'] : 'active',
            'jump_mode' => in_array((string) ($payload['jump_mode'] ?? ''), ['auto', 'app', 'review'], true) ? (string) $payload['jump_mode'] : 'auto',
            'target_url' => $targetUrl,
            'review_url' => trim((string) ($payload['review_url'] ?? '')),
            'created_at' => $now,
            'updated_at' => $now,
        ];

        $data['promotion_links'][] = $link;
        $this->store->save($data);

        return $link;
    }

    public function savePromotionReplacementRule(array $payload): array
    {
        $data = $this->store->load();
        $linkId = max(0, (int) ($payload['promotion_link_id'] ?? 0));
        if ($linkId <= 0) {
            return ['ok' => false, 'message' => '请选择推广链接。'];
        }

        $linkIndex = null;
        foreach ($data['promotion_links'] as $index => $link) {
            if ((int) ($link['id'] ?? 0) === $linkId) {
                $linkIndex = $index;
                break;
            }
        }
        if ($linkIndex === null) {
            return ['ok' => false, 'message' => '推广链接不存在。'];
        }
        if (!$this->adminCanAccessPromotionLink((array) ($data['promotion_links'][$linkIndex] ?? []), $data)) {
            return ['ok' => false, 'message' => '当前后台角色不能维护该推广链接。'];
        }

        $contentType = in_array((string) ($payload['replacement_content_type'] ?? $payload['content_type'] ?? ''), ['drama', 'novel'], true)
            ? (string) ($payload['replacement_content_type'] ?? $payload['content_type'])
            : 'drama';
        $dramaId = $contentType === 'drama' ? max(0, (int) ($payload['replacement_drama_id'] ?? $payload['drama_id'] ?? 0)) : 0;
        $episodeId = $contentType === 'drama' ? max(0, (int) ($payload['replacement_episode_id'] ?? $payload['episode_id'] ?? 0)) : 0;
        $novelId = $contentType === 'novel' ? max(0, (int) ($payload['replacement_novel_id'] ?? $payload['novel_id'] ?? 0)) : 0;
        $chapterId = $contentType === 'novel' ? max(0, (int) ($payload['replacement_chapter_id'] ?? $payload['chapter_id'] ?? 0)) : 0;
        $targetUrl = trim((string) ($payload['replacement_target_url'] ?? $payload['target_url'] ?? ''));
        if ($targetUrl === '') {
            $targetUrl = $this->promotionContentTargetUrl($contentType, $dramaId, $episodeId, $novelId, $chapterId);
        }

        $startedAt = $this->normalizeDateTime((string) ($payload['started_at'] ?? ''), '');
        $endedAt = $this->normalizeDateTime((string) ($payload['ended_at'] ?? ''), '');
        if ($startedAt !== '' && $endedAt !== '' && strtotime($endedAt) < strtotime($startedAt)) {
            return ['ok' => false, 'message' => '结束时间不能早于开始时间。'];
        }

        $rules = array_values((array) ($data['promotion_links'][$linkIndex]['replacement_rules'] ?? []));
        $nextId = empty($rules) ? 1 : ((int) max(array_column($rules, 'id')) + 1);
        $now = date('Y-m-d H:i:s');
        $rule = [
            'id' => $nextId,
            'name' => $this->limitText(trim((string) ($payload['replacement_name'] ?? $payload['name'] ?? '')) ?: '替换规则' . $nextId, 60),
            'content_type' => $contentType,
            'drama_id' => $dramaId,
            'episode_id' => $episodeId,
            'novel_id' => $novelId,
            'chapter_id' => $chapterId,
            'target_url' => $targetUrl,
            'review_url' => trim((string) ($payload['replacement_review_url'] ?? $payload['review_url'] ?? '')),
            'started_at' => $startedAt,
            'ended_at' => $endedAt,
            'status' => in_array((string) ($payload['replacement_status'] ?? $payload['status'] ?? ''), ['active', 'paused'], true) ? (string) ($payload['replacement_status'] ?? $payload['status']) : 'active',
            'priority' => max(0, (int) ($payload['priority'] ?? 0)),
            'remark' => $this->limitText(trim((string) ($payload['remark'] ?? '')), 120),
            'created_at' => $now,
            'updated_at' => $now,
        ];

        $rules[] = $rule;
        $data['promotion_links'][$linkIndex]['replacement_rules'] = array_slice($this->normalizePromotionReplacementRules($rules), -30);
        $data['promotion_links'][$linkIndex]['updated_at'] = $now;
        $this->store->save($data);

        return ['ok' => true, 'rule' => $rule];
    }

    public function trackPromotionVisit(string $code): ?array
    {
        $code = preg_replace('/[^a-zA-Z0-9_-]+/', '', $code);
        if ($code === '') {
            return null;
        }

        $data = $this->store->load();
        $link = null;
        foreach ($data['promotion_links'] as $item) {
            if ((string) ($item['code'] ?? '') === $code) {
                $link = $item;
                break;
            }
        }
        if ($link === null) {
            return null;
        }

        if (session_status() === PHP_SESSION_ACTIVE) {
            $appKey = $this->normalizeAppKey((string) ($link['media_app_id'] ?? ''));
            $app = $appKey !== '' ? $this->appConfig($appKey) : null;
            $_SESSION['promotion_attribution'] = [
                'promotion_link_id' => (int) ($link['id'] ?? 0),
                'code' => (string) ($link['code'] ?? ''),
                'agent_id' => (int) ($link['agent_id'] ?? 0),
                'source' => (string) ($link['source'] ?? ''),
                'campaign' => (string) ($link['campaign'] ?? ''),
                'app_key' => (string) ($app['app_key'] ?? $appKey),
                'app_name' => (string) ($app['name'] ?? ($link['app_name'] ?? '')),
                'traffic_platform' => (string) ($link['traffic_platform'] ?? ''),
                'channel_id' => (string) ($link['channel_id'] ?? ''),
                'media_app_id' => (string) ($link['media_app_id'] ?? ''),
                'ad_id' => (string) ($link['ad_id'] ?? ''),
                'creative_id' => (string) ($link['creative_id'] ?? ''),
                'material_id' => (string) ($link['material_id'] ?? ''),
                'started_at' => date('Y-m-d H:i:s'),
            ];
        }

        $trafficMeta = $this->trafficMetaFromLink($link);
        $data['promotion_events'][] = [
            'id' => count($data['promotion_events'] ?? []) + 1,
            'promotion_link_id' => (int) ($link['id'] ?? 0),
            'code' => (string) ($link['code'] ?? ''),
            'event' => 'visit',
            'user_id' => $this->currentUserId(),
            'order_no' => '',
            'path' => (string) ($_SERVER['REQUEST_URI'] ?? ''),
            'user_agent' => substr((string) ($_SERVER['HTTP_USER_AGENT'] ?? ''), 0, 220),
            'ip' => (string) ($_SERVER['REMOTE_ADDR'] ?? ''),
            'created_at' => date('Y-m-d H:i:s'),
        ] + $trafficMeta;
        $data['promotion_events'] = array_slice(array_values($data['promotion_events']), -2000);
        $this->store->save($data);

        return $link;
    }

    public function promotionLandingTarget(array $link): string
    {
        $effectiveRule = $this->effectivePromotionReplacementRule($link);
        $mode = (string) ($link['jump_mode'] ?? 'auto');
        if ($effectiveRule !== null) {
            if ($mode === 'review' && trim((string) ($effectiveRule['review_url'] ?? '')) !== '') {
                return (string) $effectiveRule['review_url'];
            }

            return (string) (($effectiveRule['target_url'] ?? '') ?: ($link['target_url'] ?? '/duanju'));
        }

        if ($mode === 'review' && trim((string) ($link['review_url'] ?? '')) !== '') {
            return (string) $link['review_url'];
        }

        return (string) (($link['target_url'] ?? '') ?: '/duanju');
    }

    public function recordPromotionEvent(string $eventType, array $payload = []): array
    {
        $eventType = in_array($eventType, ['visit', 'register', 'add_desktop', 'activate'], true) ? $eventType : 'visit';
        $data = $this->store->load();
        $link = null;
        $code = preg_replace('/[^a-zA-Z0-9_-]+/', '', (string) ($payload['code'] ?? ''));
        $linkId = max(0, (int) ($payload['promotion_link_id'] ?? 0));
        foreach ($data['promotion_links'] ?? [] as $item) {
            if (($linkId > 0 && (int) ($item['id'] ?? 0) === $linkId) || ($code !== '' && (string) ($item['code'] ?? '') === $code)) {
                $link = $item;
                break;
            }
        }

        if ($link === null) {
            $attribution = $this->currentPromotionAttribution();
            if (!empty($attribution)) {
                $linkId = (int) ($attribution['promotion_link_id'] ?? 0);
                $code = (string) ($attribution['code'] ?? $code);
                foreach ($data['promotion_links'] ?? [] as $item) {
                    if ((int) ($item['id'] ?? 0) === $linkId) {
                        $link = $item;
                        break;
                    }
                }
            }
        }

        if ($link === null) {
            return ['ok' => false, 'message' => '推广链接不存在，事件未记录。'];
        }

        $userId = max(0, (int) ($payload['user_id'] ?? $this->currentUserId()));
        $trafficMeta = $this->trafficMetaFromPayload($payload, $link);
        $event = [
            'id' => count($data['promotion_events'] ?? []) + 1,
            'promotion_link_id' => (int) ($link['id'] ?? 0),
            'code' => (string) ($link['code'] ?? $code),
            'event' => $eventType,
            'user_id' => $userId,
            'order_no' => trim((string) ($payload['order_no'] ?? '')),
            'amount' => round(max(0, (float) ($payload['amount'] ?? 0)), 2),
            'path' => trim((string) ($payload['path'] ?? ($_SERVER['REQUEST_URI'] ?? ''))),
            'user_agent' => substr((string) ($_SERVER['HTTP_USER_AGENT'] ?? ''), 0, 220),
            'ip' => (string) ($_SERVER['REMOTE_ADDR'] ?? ''),
            'created_at' => date('Y-m-d H:i:s'),
        ] + $trafficMeta;

        foreach ($data['promotion_events'] ?? [] as $item) {
            $sameUserEvent = (int) ($item['promotion_link_id'] ?? 0) === (int) $event['promotion_link_id']
                && (string) ($item['event'] ?? '') === $eventType
                && (int) ($item['user_id'] ?? 0) === $userId
                && $userId > 0;
            if ($sameUserEvent && str_starts_with((string) ($item['created_at'] ?? ''), date('Y-m-d'))) {
                return ['ok' => true, 'duplicate' => true, 'event' => $item];
            }
        }

        $data['promotion_events'][] = $event;
        $this->queueCallbackLog($data, $event);
        $data['promotion_events'] = array_slice(array_values($data['promotion_events']), -5000);
        $this->store->save($data);

        return ['ok' => true, 'event' => $event];
    }

    public function savePromotionCost(array $payload): array
    {
        $data = $this->store->load();
        $linkId = max(0, (int) ($payload['promotion_link_id'] ?? 0));
        $link = null;
        foreach ($data['promotion_links'] ?? [] as $item) {
            if ((int) ($item['id'] ?? 0) === $linkId) {
                $link = $item;
                break;
            }
        }
        if (!is_array($link) || !$this->adminCanAccessPromotionLink($link, $data)) {
            return ['ok' => false, 'message' => '当前后台角色不能记录该推广链接的投放消耗。'];
        }

        $date = trim((string) ($payload['cost_date'] ?? $payload['date'] ?? ''));
        $timestamp = strtotime($date);
        $date = $timestamp === false ? date('Y-m-d') : date('Y-m-d', $timestamp);
        $amount = round(max(0, (float) ($payload['amount'] ?? 0)), 2);
        if ($amount <= 0) {
            return ['ok' => false, 'message' => '投放消耗必须大于 0。'];
        }

        $nextId = empty($data['promotion_costs']) ? 1 : ((int) max(array_column($data['promotion_costs'], 'id')) + 1);
        $now = date('Y-m-d H:i:s');
        $cost = [
            'id' => $nextId,
            'date' => $date,
            'promotion_link_id' => $linkId,
            'code' => (string) ($link['code'] ?? ''),
            'agent_id' => (int) ($link['agent_id'] ?? ($payload['agent_id'] ?? 0)),
            'amount' => $amount,
            'clicks' => max(0, (int) ($payload['clicks'] ?? 0)),
            'impressions' => max(0, (int) ($payload['impressions'] ?? 0)),
            'source' => $this->limitText(trim((string) ($payload['source'] ?? ($link['source'] ?? ''))), 40),
            'campaign' => $this->limitText(trim((string) ($payload['campaign'] ?? ($link['campaign'] ?? ''))), 60),
            'traffic_platform' => $this->limitText(trim((string) ($payload['traffic_platform'] ?? ($link['traffic_platform'] ?? ''))), 40),
            'channel_id' => $this->limitText(trim((string) ($payload['channel_id'] ?? ($link['channel_id'] ?? ''))), 60),
            'media_app_id' => $this->limitText(trim((string) ($payload['media_app_id'] ?? ($link['media_app_id'] ?? ''))), 60),
            'ad_id' => $this->limitText(trim((string) ($payload['ad_id'] ?? ($link['ad_id'] ?? ''))), 80),
            'creative_id' => $this->limitText(trim((string) ($payload['creative_id'] ?? ($link['creative_id'] ?? ''))), 80),
            'material_id' => $this->limitText(trim((string) ($payload['material_id'] ?? ($link['material_id'] ?? ''))), 80),
            'remark' => $this->limitText(trim((string) ($payload['remark'] ?? '')), 120),
            'created_at' => $now,
            'updated_at' => $now,
        ];

        $data['promotion_costs'][] = $cost;
        $data['promotion_costs'] = array_slice(array_values($data['promotion_costs']), -3000);
        $autoPause = $this->applyPromotionLinkAutoPause($data, $linkId, $now);
        $this->store->save($data);

        return ['ok' => true, 'cost' => $cost, 'auto_pause' => $autoPause];
    }

    public function updateCallbackConfig(array $payload): array
    {
        $data = $this->store->load();
        $splitEvents = static function (mixed $value, array $fallback): array {
            $items = is_array($value) ? $value : preg_split('/[\s,，|]+/u', (string) $value);
            $events = array_values(array_filter(array_map(static fn ($item): string => trim((string) $item), (array) $items), static fn (string $item): bool => $item !== ''));

            return empty($events) ? $fallback : array_slice(array_values(array_unique($events)), 0, 10);
        };

        $data['callback_config'] = [
            'enabled' => !empty($payload['enabled']),
            'endpoint' => trim((string) ($payload['endpoint'] ?? '')),
            'secret' => trim((string) ($payload['secret'] ?? '')),
            'platform' => $this->limitText(trim((string) ($payload['platform'] ?? '巨量引擎')) ?: '巨量引擎', 40),
            'template_key' => preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['template_key'] ?? $payload['callback_template_key'] ?? ($data['callback_config']['template_key'] ?? 'custom')))) ?: 'custom',
            'template_name' => $this->limitText(trim((string) ($payload['template_name'] ?? $payload['callback_template_name'] ?? ($data['callback_config']['template_name'] ?? '自定义模板'))) ?: '自定义模板', 60),
            'field_mapping' => $this->callbackFieldMappingFromPayload($payload, (array) ($data['callback_config']['field_mapping'] ?? [])),
            'auth_config' => $this->callbackAuthConfigFromPayload($payload, (array) ($data['callback_config']['auth_config'] ?? []), trim((string) ($payload['secret'] ?? $data['callback_config']['secret'] ?? ''))),
            'retry_policy' => $this->callbackRetryPolicyFromPayload($payload, (array) ($data['callback_config']['retry_policy'] ?? [])),
            'fallback_time_match' => !empty($payload['fallback_time_match']),
            'add_desktop_events' => $splitEvents($payload['add_desktop_events'] ?? '', ['active']),
            'paid_events' => $splitEvents($payload['paid_events'] ?? '', ['pay']),
            'updated_at' => date('Y-m-d H:i:s'),
        ];
        $this->store->save($data);

        return ['ok' => true, 'config' => $data['callback_config']];
    }

    public function callbackTemplates(): array
    {
        return $this->callbackTemplatePresets();
    }

    public function applyCallbackTemplate(array $payload): array
    {
        $data = $this->store->load();
        if ((string) ($this->currentAdminScope($data)['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以应用回传模板。'];
        }

        $templateKey = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['callback_template_key'] ?? $payload['template_key'] ?? ''))) ?: '';
        $templates = $this->callbackTemplatePresets();
        if ($templateKey === '' || !isset($templates[$templateKey])) {
            return ['ok' => false, 'message' => '请选择有效的平台回传模板。'];
        }

        $template = $templates[$templateKey];
        $current = (array) ($data['callback_config'] ?? []);
        $data['callback_config'] = array_merge($current, [
            'enabled' => !empty($payload['enable_after_apply']) || !empty($current['enabled']),
            'platform' => (string) ($template['platform'] ?? $template['name'] ?? '投放平台'),
            'template_key' => $templateKey,
            'template_name' => (string) ($template['name'] ?? $templateKey),
            'field_mapping' => (array) ($template['field_mapping'] ?? []),
            'auth_config' => $this->normalizeCallbackAuthConfig((array) ($template['auth_config'] ?? ($current['auth_config'] ?? [])), (string) ($current['secret'] ?? '')),
            'retry_policy' => $this->normalizeCallbackRetryPolicy((array) ($current['retry_policy'] ?? [])),
            'add_desktop_events' => array_values((array) ($template['add_desktop_events'] ?? ['active'])),
            'paid_events' => array_values((array) ($template['paid_events'] ?? ['pay'])),
            'fallback_time_match' => true,
            'updated_at' => date('Y-m-d H:i:s'),
        ]);
        if (!empty($payload['endpoint'])) {
            $data['callback_config']['endpoint'] = trim((string) $payload['endpoint']);
        } elseif (empty($data['callback_config']['endpoint']) && !empty($template['endpoint_placeholder'])) {
            $data['callback_config']['endpoint'] = (string) $template['endpoint_placeholder'];
        }
        if (array_key_exists('secret', $payload)) {
            $data['callback_config']['secret'] = trim((string) $payload['secret']);
            $data['callback_config']['auth_config'] = $this->normalizeCallbackAuthConfig((array) ($data['callback_config']['auth_config'] ?? []), (string) $data['callback_config']['secret']);
        }
        $this->store->save($data);

        return [
            'ok' => true,
            'config' => $data['callback_config'],
            'message' => '已应用平台回传模板：' . (string) ($template['name'] ?? $templateKey) . '。',
        ];
    }

    public function callbackLogs(): array
    {
        $logs = array_values((array) ($this->store->load()['callback_logs'] ?? []));
        usort($logs, static fn (array $a, array $b): int => strcmp((string) ($b['created_at'] ?? ''), (string) ($a['created_at'] ?? '')));

        return $logs;
    }

    public function feedbackItems(?array $data = null): array
    {
        $data ??= $this->store->load();
        $items = array_values((array) ($data['feedback_items'] ?? []));
        foreach ($items as &$item) {
            if (is_array($item)) {
                $item = $this->refreshFeedbackSlaState($item);
            }
        }
        unset($item);
        usort($items, static fn (array $a, array $b): int => strcmp((string) ($b['created_at'] ?? ''), (string) ($a['created_at'] ?? '')));

        return $items;
    }

    public function feedbackDashboard(?array $data = null): array
    {
        $data ??= $this->store->load();
        $items = $this->feedbackItems($data);
        $summary = [
            'total' => count($items),
            'pending' => 0,
            'processing' => 0,
            'resolved' => 0,
            'rejected' => 0,
            'open' => 0,
            'overdue' => 0,
            'due_soon' => 0,
            'payment' => 0,
            'with_order' => 0,
            'with_promotion' => 0,
            'suggest_refund' => 0,
            'suggest_rights_repair' => 0,
            'avg_handle_minutes' => 0,
            'sla_hit_rate' => 100.0,
        ];
        $handledMinutes = [];
        $handledTotal = 0;
        $handledOnTime = 0;
        $appRows = [];
        $actionRows = [];

        foreach ($items as $item) {
            $status = (string) ($item['status'] ?? 'pending');
            if (isset($summary[$status])) {
                $summary[$status]++;
            }
            if (in_array($status, ['pending', 'processing'], true)) {
                $summary['open']++;
            }
            if ((string) ($item['sla_status'] ?? '') === 'overdue') {
                $summary['overdue']++;
            } elseif ((string) ($item['sla_status'] ?? '') === 'due_soon') {
                $summary['due_soon']++;
            }
            if ((string) ($item['type'] ?? '') === 'payment') {
                $summary['payment']++;
            }
            if (trim((string) ($item['order_no'] ?? '')) !== '') {
                $summary['with_order']++;
            }
            if ((int) ($item['promotion_link_id'] ?? 0) > 0) {
                $summary['with_promotion']++;
            }
            if ((string) ($item['suggested_action'] ?? '') === 'refund') {
                $summary['suggest_refund']++;
            } elseif ((string) ($item['suggested_action'] ?? '') === 'rights_repair') {
                $summary['suggest_rights_repair']++;
            }
            if (in_array($status, ['resolved', 'rejected'], true) && !empty($item['handled_at'])) {
                $handledTotal++;
                if ((string) ($item['sla_status'] ?? '') !== 'handled_overdue') {
                    $handledOnTime++;
                }
                $minutes = max(0, (int) ($item['handled_minutes'] ?? 0));
                if ($minutes > 0) {
                    $handledMinutes[] = $minutes;
                }
            }

            $appKey = (string) (($item['app_key'] ?? '') ?: 'default');
            $appRows[$appKey] ??= [
                'app_key' => $appKey,
                'app_name' => (string) (($item['app_name'] ?? '') ?: $appKey),
                'total' => 0,
                'open' => 0,
                'overdue' => 0,
                'payment' => 0,
                'suggest_refund' => 0,
            ];
            $appRows[$appKey]['total']++;
            if (in_array($status, ['pending', 'processing'], true)) {
                $appRows[$appKey]['open']++;
            }
            if ((string) ($item['sla_status'] ?? '') === 'overdue') {
                $appRows[$appKey]['overdue']++;
            }
            if ((string) ($item['type'] ?? '') === 'payment') {
                $appRows[$appKey]['payment']++;
            }
            if ((string) ($item['suggested_action'] ?? '') === 'refund') {
                $appRows[$appKey]['suggest_refund']++;
            }

            $action = (string) (($item['suggested_action'] ?? '') ?: 'none');
            $actionRows[$action] ??= ['action' => $action, 'total' => 0, 'open' => 0, 'overdue' => 0];
            $actionRows[$action]['total']++;
            if (in_array($status, ['pending', 'processing'], true)) {
                $actionRows[$action]['open']++;
            }
            if ((string) ($item['sla_status'] ?? '') === 'overdue') {
                $actionRows[$action]['overdue']++;
            }
        }

        if (!empty($handledMinutes)) {
            $summary['avg_handle_minutes'] = (int) round(array_sum($handledMinutes) / count($handledMinutes));
        }
        if ($handledTotal > 0) {
            $summary['sla_hit_rate'] = round(($handledOnTime / $handledTotal) * 100, 2);
        }

        $appRows = array_values($appRows);
        usort($appRows, static fn (array $a, array $b): int => [(int) $b['open'], (int) $b['overdue'], (int) $b['total']] <=> [(int) $a['open'], (int) $a['overdue'], (int) $a['total']]);
        $actionRows = array_values($actionRows);
        usort($actionRows, static fn (array $a, array $b): int => [(int) $b['open'], (int) $b['overdue'], (int) $b['total']] <=> [(int) $a['open'], (int) $a['overdue'], (int) $a['total']]);

        return [
            'summary' => $summary,
            'app_rows' => $appRows,
            'action_rows' => $actionRows,
            'overdue_rows' => array_slice(array_values(array_filter($items, static fn (array $item): bool => (string) ($item['sla_status'] ?? '') === 'overdue')), 0, 10),
            'suggestion_rows' => array_slice(array_values(array_filter($items, static fn (array $item): bool => in_array((string) ($item['suggested_action'] ?? ''), ['refund', 'rights_repair', 'query_payment'], true))), 0, 12),
        ];
    }

    public function contentComments(?array $data = null): array
    {
        $data ??= $this->store->load();
        $items = array_values((array) ($data['content_comments'] ?? []));
        $contentIndex = $this->contentCommentContentIndex($data);
        foreach ($items as &$item) {
            if (!is_array($item)) {
                continue;
            }
            $key = (string) ($item['content_type'] ?? 'drama') . ':' . (int) ($item['content_id'] ?? 0);
            $content = $contentIndex[$key] ?? [];
            $item['content_title'] = (string) (($content['title'] ?? '') ?: (($item['content_type'] ?? 'drama') === 'novel' ? '小说' : '短剧') . ' #' . (int) ($item['content_id'] ?? 0));
            $item['content_cover'] = (string) ($content['cover'] ?? '');
        }
        unset($item);
        usort($items, static fn (array $a, array $b): int => [
            !empty($b['is_pinned']) ? 1 : 0,
            (string) ($b['created_at'] ?? ''),
            (int) ($b['id'] ?? 0),
        ] <=> [
            !empty($a['is_pinned']) ? 1 : 0,
            (string) ($a['created_at'] ?? ''),
            (int) ($a['id'] ?? 0),
        ]);

        return $items;
    }

    public function commentDashboard(?array $data = null): array
    {
        $data ??= $this->store->load();
        $items = $this->contentComments($data);
        $summary = [
            'total' => count($items),
            'pending' => 0,
            'approved' => 0,
            'rejected' => 0,
            'hidden' => 0,
            'featured' => 0,
            'pinned' => 0,
            'sensitive' => 0,
            'spam' => 0,
            'avg_rating' => 0.0,
            'negative' => 0,
        ];
        $ratingSum = 0;
        $contentRows = [];
        foreach ($items as $item) {
            $status = (string) ($item['status'] ?? 'pending');
            if (isset($summary[$status])) {
                $summary[$status]++;
            }
            if (!empty($item['is_featured'])) {
                $summary['featured']++;
            }
            if (!empty($item['is_pinned'])) {
                $summary['pinned']++;
            }
            if ((string) ($item['risk_level'] ?? 'normal') === 'sensitive') {
                $summary['sensitive']++;
            } elseif ((string) ($item['risk_level'] ?? 'normal') === 'spam') {
                $summary['spam']++;
            }
            if ((string) ($item['sentiment'] ?? 'neutral') === 'negative') {
                $summary['negative']++;
            }
            $ratingSum += max(1, min(5, (int) ($item['rating'] ?? 5)));
            $key = (string) ($item['content_type'] ?? 'drama') . ':' . (int) ($item['content_id'] ?? 0);
            $contentRows[$key] ??= [
                'key' => $key,
                'content_type' => (string) ($item['content_type'] ?? 'drama'),
                'content_id' => (int) ($item['content_id'] ?? 0),
                'title' => (string) ($item['content_title'] ?? '内容'),
                'total' => 0,
                'pending' => 0,
                'approved' => 0,
                'negative' => 0,
                'rating_sum' => 0,
                'avg_rating' => 0.0,
                'latest_at' => '',
            ];
            $contentRows[$key]['total']++;
            if (isset($contentRows[$key][$status])) {
                $contentRows[$key][$status]++;
            }
            if ((string) ($item['sentiment'] ?? 'neutral') === 'negative') {
                $contentRows[$key]['negative']++;
            }
            $contentRows[$key]['rating_sum'] += max(1, min(5, (int) ($item['rating'] ?? 5)));
            if (strcmp((string) ($item['created_at'] ?? ''), (string) ($contentRows[$key]['latest_at'] ?? '')) > 0) {
                $contentRows[$key]['latest_at'] = (string) ($item['created_at'] ?? '');
            }
        }
        if ($summary['total'] > 0) {
            $summary['avg_rating'] = round($ratingSum / $summary['total'], 2);
        }
        foreach ($contentRows as &$row) {
            $row['avg_rating'] = (int) ($row['total'] ?? 0) > 0 ? round((int) ($row['rating_sum'] ?? 0) / (int) $row['total'], 2) : 0.0;
            unset($row['rating_sum']);
        }
        unset($row);
        $contentRows = array_values($contentRows);
        usort($contentRows, static fn (array $a, array $b): int => [(int) $b['pending'], (int) $b['total'], (string) $b['latest_at']] <=> [(int) $a['pending'], (int) $a['total'], (string) $a['latest_at']]);

        return [
            'summary' => $summary,
            'content_rows' => array_slice($contentRows, 0, 30),
            'pending_rows' => array_slice(array_values(array_filter($items, static fn (array $item): bool => (string) ($item['status'] ?? '') === 'pending')), 0, 20),
            'risk_rows' => array_slice(array_values(array_filter($items, static fn (array $item): bool => in_array((string) ($item['risk_level'] ?? 'normal'), ['sensitive', 'spam'], true) || (string) ($item['sentiment'] ?? 'neutral') === 'negative')), 0, 20),
        ];
    }

    public function publicContentComments(array $filters = []): array
    {
        $data = $this->store->load();
        $appKey = $this->currentAppKey($filters);
        $contentType = (string) ($filters['content_type'] ?? 'drama') === 'novel' ? 'novel' : 'drama';
        $contentId = max(0, (int) ($filters['content_id'] ?? ($contentType === 'novel' ? ($filters['novel_id'] ?? 0) : ($filters['drama_id'] ?? 0))));
        $unitId = max(0, (int) ($filters['unit_id'] ?? ($contentType === 'novel' ? ($filters['chapter_id'] ?? 0) : ($filters['episode_id'] ?? 0))));
        $limit = max(1, min(100, (int) ($filters['limit'] ?? 30)));
        $rows = [];
        foreach ($this->contentComments($data) as $item) {
            if ((string) ($item['status'] ?? 'pending') !== 'approved') {
                continue;
            }
            if ((string) ($item['content_type'] ?? 'drama') !== $contentType) {
                continue;
            }
            if ($contentId > 0 && (int) ($item['content_id'] ?? 0) !== $contentId) {
                continue;
            }
            if ($unitId > 0 && (int) ($item['unit_id'] ?? 0) !== $unitId) {
                continue;
            }
            $itemAppKey = $this->normalizeAppKey((string) ($item['app_key'] ?? 'default'));
            if ($itemAppKey !== '' && $itemAppKey !== 'all' && $appKey !== '' && $itemAppKey !== $appKey) {
                continue;
            }
            $rows[] = [
                'id' => (int) ($item['id'] ?? 0),
                'content_type' => (string) ($item['content_type'] ?? 'drama'),
                'content_id' => (int) ($item['content_id'] ?? 0),
                'unit_id' => (int) ($item['unit_id'] ?? 0),
                'user_id' => (int) ($item['user_id'] ?? 0),
                'nickname' => (string) (($item['nickname'] ?? '') ?: '匿名用户'),
                'avatar' => (string) ($item['avatar'] ?? ''),
                'rating' => max(1, min(5, (int) ($item['rating'] ?? 5))),
                'content' => (string) ($item['content'] ?? ''),
                'reply' => (string) ($item['reply'] ?? ''),
                'likes' => max(0, (int) ($item['likes'] ?? 0)),
                'is_pinned' => !empty($item['is_pinned']),
                'is_featured' => !empty($item['is_featured']),
                'created_at' => (string) ($item['created_at'] ?? ''),
            ];
        }
        usort($rows, static fn (array $a, array $b): int => [
            !empty($b['is_pinned']) ? 1 : 0,
            !empty($b['is_featured']) ? 1 : 0,
            (string) ($b['created_at'] ?? ''),
        ] <=> [
            !empty($a['is_pinned']) ? 1 : 0,
            !empty($a['is_featured']) ? 1 : 0,
            (string) ($a['created_at'] ?? ''),
        ]);

        return array_slice($rows, 0, $limit);
    }

    public function submitContentComment(array $payload): array
    {
        $data = $this->store->load();
        $contentType = (string) ($payload['content_type'] ?? 'drama') === 'novel' ? 'novel' : 'drama';
        $contentId = max(0, (int) ($payload['content_id'] ?? ($contentType === 'novel' ? ($payload['novel_id'] ?? 0) : ($payload['drama_id'] ?? 0))));
        if ($contentId <= 0) {
            return ['ok' => false, 'message' => '请选择要评论的内容。'];
        }
        if (!$this->contentCommentTargetExists($data, $contentType, $contentId)) {
            return ['ok' => false, 'message' => '评论内容不存在或不可评论。'];
        }
        $content = $this->limitText(trim((string) ($payload['content'] ?? $payload['comment'] ?? '')), 600);
        if ($content === '') {
            return ['ok' => false, 'message' => '请填写评论内容。'];
        }
        $rating = max(1, min(5, (int) ($payload['rating'] ?? 5)));
        $unitId = max(0, (int) ($payload['unit_id'] ?? ($contentType === 'novel' ? ($payload['chapter_id'] ?? 0) : ($payload['episode_id'] ?? 0))));
        $user = $this->currentUser();
        $userId = max(0, (int) ($payload['user_id'] ?? ($user['id'] ?? $this->currentUserId())));
        $attribution = $this->currentPromotionAttribution();
        $linkId = max(0, (int) ($payload['promotion_link_id'] ?? ($attribution['promotion_link_id'] ?? 0)));
        $code = preg_replace('/[^a-zA-Z0-9_-]+/', '', (string) ($payload['promotion_code'] ?? $payload['code'] ?? ($attribution['code'] ?? '')));
        $link = [];
        foreach ((array) ($data['promotion_links'] ?? []) as $item) {
            if (($linkId > 0 && (int) ($item['id'] ?? 0) === $linkId) || ($code !== '' && (string) ($item['code'] ?? '') === $code)) {
                $link = $item;
                $linkId = (int) ($item['id'] ?? $linkId);
                $code = (string) ($item['code'] ?? $code);
                break;
            }
        }
        $fallbackMeta = $this->trafficMetaFromPayload($link);
        $fallbackMeta = $this->trafficMetaFromPayload((array) $attribution, $fallbackMeta);
        $trafficMeta = $this->trafficMetaFromPayload($payload, $fallbackMeta);
        $risk = $this->commentRiskProfile($content);
        $now = date('Y-m-d H:i:s');
        $comments = array_values((array) ($data['content_comments'] ?? []));
        $comment = [
            'id' => empty($comments) ? 1 : ((int) max(array_column($comments, 'id')) + 1),
            'content_type' => $contentType,
            'content_id' => $contentId,
            'drama_id' => $contentType === 'drama' ? $contentId : 0,
            'episode_id' => $contentType === 'drama' ? $unitId : 0,
            'novel_id' => $contentType === 'novel' ? $contentId : 0,
            'chapter_id' => $contentType === 'novel' ? $unitId : 0,
            'unit_id' => $unitId,
            'user_id' => $userId,
            'nickname' => $this->limitText(trim((string) ($payload['nickname'] ?? ($user['nickname'] ?? '匿名用户'))), 60),
            'avatar' => trim((string) ($payload['avatar'] ?? '')),
            'phone' => $this->limitText(trim((string) ($payload['phone'] ?? ($user['phone'] ?? ''))), 32),
            'app_key' => $this->currentAppKey($payload),
            'rating' => $rating,
            'content' => $content,
            'reply' => '',
            'status' => (string) ($risk['risk_level'] ?? 'normal') === 'normal' ? 'pending' : 'pending',
            'risk_level' => (string) ($risk['risk_level'] ?? 'normal'),
            'sentiment' => (string) ($risk['sentiment'] ?? 'neutral'),
            'source' => 'api',
            'likes' => 0,
            'reports' => 0,
            'is_pinned' => false,
            'is_featured' => false,
            'promotion_link_id' => $linkId,
            'promotion_code' => $code,
            'agent_id' => max(0, (int) ($payload['agent_id'] ?? ($link['agent_id'] ?? ($attribution['agent_id'] ?? 0)))),
            'reviewed_by_admin_id' => 0,
            'reviewed_by_admin_name' => '',
            'reviewed_at' => '',
            'ip' => $this->limitText(trim((string) ($_SERVER['REMOTE_ADDR'] ?? '')), 64),
            'user_agent' => $this->limitText(trim((string) ($_SERVER['HTTP_USER_AGENT'] ?? '')), 220),
            'created_at' => $now,
            'updated_at' => $now,
        ] + $trafficMeta;

        $data['content_comments'][] = $comment;
        $data['content_comments'] = array_slice(array_values((array) ($data['content_comments'] ?? [])), -10000);
        $this->store->save($data);

        return ['ok' => true, 'comment' => $comment, 'message' => '评论已提交，审核通过后展示。'];
    }

    public function updateContentComment(array $payload): array
    {
        $data = $this->store->load();
        $commentId = max(0, (int) ($payload['comment_id'] ?? $payload['id'] ?? 0));
        if ($commentId <= 0) {
            return ['ok' => false, 'message' => '评论记录不存在。'];
        }
        $status = (string) ($payload['status'] ?? 'approved');
        $status = in_array($status, ['pending', 'approved', 'rejected', 'hidden'], true) ? $status : 'approved';
        $riskLevel = (string) ($payload['risk_level'] ?? 'normal');
        $riskLevel = in_array($riskLevel, ['normal', 'sensitive', 'spam'], true) ? $riskLevel : 'normal';
        $sentiment = (string) ($payload['sentiment'] ?? 'neutral');
        $sentiment = in_array($sentiment, ['positive', 'neutral', 'negative'], true) ? $sentiment : 'neutral';
        $admin = $this->currentAdmin();
        $now = date('Y-m-d H:i:s');
        foreach ($data['content_comments'] as &$item) {
            if ((int) ($item['id'] ?? 0) !== $commentId) {
                continue;
            }
            $item['status'] = $status;
            $item['risk_level'] = $riskLevel;
            $item['sentiment'] = $sentiment;
            $item['rating'] = max(1, min(5, (int) ($payload['rating'] ?? ($item['rating'] ?? 5))));
            $item['content'] = $this->limitText(trim((string) ($payload['content'] ?? ($item['content'] ?? ''))), 600);
            $item['reply'] = $this->limitText(trim((string) ($payload['reply'] ?? '')), 500);
            $item['likes'] = max(0, (int) ($payload['likes'] ?? ($item['likes'] ?? 0)));
            $item['reports'] = max(0, (int) ($payload['reports'] ?? ($item['reports'] ?? 0)));
            $item['is_pinned'] = !empty($payload['is_pinned']);
            $item['is_featured'] = !empty($payload['is_featured']);
            $item['reviewed_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
            $item['reviewed_by_admin_name'] = $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60);
            $item['reviewed_at'] = $now;
            $item['updated_at'] = $now;
            $this->store->save($data);

            return ['ok' => true, 'comment' => $item, 'message' => '评论已更新。'];
        }
        unset($item);

        return ['ok' => false, 'message' => '评论记录不存在。'];
    }

    private function contentCommentContentIndex(array $data): array
    {
        $index = [];
        foreach ((array) ($data['dramas'] ?? []) as $drama) {
            $id = (int) ($drama['id'] ?? 0);
            if ($id > 0) {
                $index['drama:' . $id] = [
                    'title' => (string) ($drama['title'] ?? '未命名短剧'),
                    'cover' => (string) ($drama['cover'] ?? ''),
                    'status' => (string) ($drama['status'] ?? ''),
                ];
            }
        }
        foreach ((array) ($data['novels'] ?? []) as $novel) {
            $id = (int) ($novel['id'] ?? 0);
            if ($id > 0) {
                $index['novel:' . $id] = [
                    'title' => (string) ($novel['title'] ?? '未命名小说'),
                    'cover' => (string) ($novel['cover'] ?? ''),
                    'status' => (string) ($novel['status'] ?? ''),
                ];
            }
        }

        return $index;
    }

    private function contentCommentTargetExists(array $data, string $contentType, int $contentId): bool
    {
        $collection = $contentType === 'novel' ? 'novels' : 'dramas';
        foreach ((array) ($data[$collection] ?? []) as $item) {
            if ((int) ($item['id'] ?? 0) !== $contentId) {
                continue;
            }
            return !in_array((string) ($item['status'] ?? 'online'), ['offline', 'deleted'], true);
        }

        return false;
    }

    private function commentRiskProfile(string $content): array
    {
        $lower = strtolower($content);
        $spamWords = ['加微信', 'vx', 'qq', '返利', '代充', '刷单', '广告'];
        $sensitiveWords = ['骗子', '诈骗', '垃圾', '不到账', '乱扣', '退款', '投诉'];
        foreach ($spamWords as $word) {
            if (str_contains($lower, strtolower($word))) {
                return ['risk_level' => 'spam', 'sentiment' => 'negative'];
            }
        }
        foreach ($sensitiveWords as $word) {
            if (str_contains($lower, strtolower($word))) {
                return ['risk_level' => 'sensitive', 'sentiment' => 'negative'];
            }
        }
        $positiveWords = ['好看', '精彩', '喜欢', '推荐', '上头', '不错', '爽'];
        foreach ($positiveWords as $word) {
            if (str_contains($lower, strtolower($word))) {
                return ['risk_level' => 'normal', 'sentiment' => 'positive'];
            }
        }

        return ['risk_level' => 'normal', 'sentiment' => 'neutral'];
    }

    public function submitFeedback(array $payload): array
    {
        $data = $this->store->load();
        $user = $this->currentUser();
        $attribution = $this->currentPromotionAttribution();
        $orderNo = trim((string) ($payload['order_no'] ?? ''));
        $order = null;
        $payloadUserId = max(0, (int) ($payload['user_id'] ?? ($user['id'] ?? $this->currentUserId())));
        $payloadContentType = in_array((string) ($payload['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $payload['content_type'] : '';
        $payloadDramaId = max(0, (int) ($payload['drama_id'] ?? 0));
        $payloadEpisodeId = max(0, (int) ($payload['episode_id'] ?? 0));
        $payloadNovelId = max(0, (int) ($payload['novel_id'] ?? 0));
        $payloadChapterId = max(0, (int) ($payload['chapter_id'] ?? 0));
        foreach ((array) ($data['orders'] ?? []) as $item) {
            if ($orderNo !== '' && (string) ($item['order_no'] ?? '') === $orderNo) {
                $order = $this->normalizeOrderState($item);
                break;
            }
        }
        if ($order === null) {
            $order = $this->findRelatedFeedbackOrder($data, $payloadUserId, $payloadContentType, $payloadDramaId, $payloadEpisodeId, $payloadNovelId, $payloadChapterId);
            if ($order !== null && $orderNo === '') {
                $orderNo = (string) ($order['order_no'] ?? '');
            }
        }

        $linkId = max(0, (int) ($payload['promotion_link_id'] ?? ($order['promotion_link_id'] ?? ($attribution['promotion_link_id'] ?? 0))));
        $code = preg_replace('/[^a-zA-Z0-9_-]+/', '', (string) ($payload['promotion_code'] ?? $payload['code'] ?? ($order['promotion_code'] ?? ($attribution['code'] ?? ''))));
        $link = null;
        foreach ((array) ($data['promotion_links'] ?? []) as $item) {
            if (($linkId > 0 && (int) ($item['id'] ?? 0) === $linkId) || ($code !== '' && (string) ($item['code'] ?? '') === $code)) {
                $link = $item;
                break;
            }
        }
        if (is_array($link)) {
            $linkId = (int) ($link['id'] ?? $linkId);
            $code = (string) ($link['code'] ?? $code);
        }

        $contentType = in_array((string) ($payloadContentType ?: ($order['content_type'] ?? ($link['content_type'] ?? ''))), ['drama', 'novel'], true)
            ? (string) ($payloadContentType ?: ($order['content_type'] ?? ($link['content_type'] ?? '')))
            : '';
        $type = (string) ($payload['type'] ?? '');
        if (!in_array($type, ['feedback', 'complaint', 'payment', 'content', 'account', 'promotion'], true)) {
            $type = $orderNo !== '' ? 'payment' : ($contentType !== '' ? 'content' : 'feedback');
        }
        $priority = (string) ($payload['priority'] ?? 'normal');
        $priority = in_array($priority, ['low', 'normal', 'high', 'urgent'], true) ? $priority : 'normal';
        $content = $this->limitText(trim((string) ($payload['content'] ?? $payload['message'] ?? '')), 1000);
        if ($content === '') {
            return ['ok' => false, 'message' => '请填写反馈内容。'];
        }

        $now = date('Y-m-d H:i:s');
        $feedbackItems = array_values((array) ($data['feedback_items'] ?? []));
        $nextId = empty($feedbackItems) ? 1 : ((int) max(array_column($feedbackItems, 'id')) + 1);
        $fallbackMeta = $this->trafficMetaFromPayload((array) ($link ?? []));
        $fallbackMeta = $this->trafficMetaFromPayload((array) ($order ?? []), $fallbackMeta);
        $fallbackMeta = $this->trafficMetaFromPayload((array) $attribution, $fallbackMeta);
        $trafficMeta = $this->trafficMetaFromPayload($payload, $fallbackMeta);
        $appKey = $this->feedbackAppKey($payload, $order, $link, $attribution, $data);
        $app = $this->appConfigFromData($appKey, $data);
        $slaHours = $this->feedbackSlaHours($type, $priority);
        $dueAt = date('Y-m-d H:i:s', strtotime($now) + ($slaHours * 3600));
        $suggestion = $this->feedbackSuggestedAction($type, $priority, $content, $order, $contentType);
        $userId = max(0, (int) ($payload['user_id'] ?? ($order['user_id'] ?? ($user['id'] ?? $this->currentUserId()))));
        $feedback = [
            'id' => $nextId,
            'type' => $type,
            'status' => 'pending',
            'priority' => $priority,
            'user_id' => $userId,
            'nickname' => $this->limitText(trim((string) ($payload['nickname'] ?? ($user['nickname'] ?? ''))), 60),
            'phone' => $this->limitText(trim((string) ($payload['phone'] ?? ($user['phone'] ?? ''))), 32),
            'contact' => $this->limitText(trim((string) ($payload['contact'] ?? $payload['wechat'] ?? $payload['email'] ?? '')), 80),
            'app_key' => $appKey,
            'app_name' => $this->limitText((string) (($app['name'] ?? '') ?: ($order['app_name'] ?? ($attribution['app_name'] ?? ''))), 60),
            'title' => $this->limitText(trim((string) ($payload['title'] ?? '')), 80),
            'content' => $content,
            'reply' => '',
            'order_no' => $orderNo,
            'content_type' => $contentType,
            'drama_id' => $contentType === 'drama' ? max(0, (int) ($payload['drama_id'] ?? ($order['drama_id'] ?? ($link['drama_id'] ?? 0)))) : 0,
            'episode_id' => $contentType === 'drama' ? max(0, (int) ($payload['episode_id'] ?? ($order['episode_id'] ?? ($link['episode_id'] ?? 0)))) : 0,
            'novel_id' => $contentType === 'novel' ? max(0, (int) ($payload['novel_id'] ?? ($order['novel_id'] ?? ($link['novel_id'] ?? 0)))) : 0,
            'chapter_id' => $contentType === 'novel' ? max(0, (int) ($payload['chapter_id'] ?? ($order['chapter_id'] ?? ($link['chapter_id'] ?? 0)))) : 0,
            'promotion_link_id' => $linkId,
            'promotion_code' => $code,
            'agent_id' => max(0, (int) ($payload['agent_id'] ?? ($order['agent_id'] ?? ($link['agent_id'] ?? ($attribution['agent_id'] ?? 0))))),
            'handled_by_admin_id' => 0,
            'handled_by_admin_name' => '',
            'handled_at' => '',
            'sla_hours' => $slaHours,
            'due_at' => $dueAt,
            'sla_status' => 'normal',
            'handled_minutes' => 0,
            'suggested_action' => (string) ($suggestion['action'] ?? 'none'),
            'suggested_reason' => (string) ($suggestion['reason'] ?? ''),
            'order_snapshot' => $this->feedbackOrderSnapshot($order),
            'user_snapshot' => $this->feedbackUserSnapshot($user),
            'ip' => $this->limitText(trim((string) ($_SERVER['REMOTE_ADDR'] ?? '')), 64),
            'user_agent' => $this->limitText(trim((string) ($_SERVER['HTTP_USER_AGENT'] ?? '')), 220),
            'created_at' => $now,
            'updated_at' => $now,
        ] + $trafficMeta;

        $data['feedback_items'][] = $feedback;
        $data['feedback_items'] = array_slice(array_values((array) ($data['feedback_items'] ?? [])), -5000);
        $this->store->save($data);

        return ['ok' => true, 'feedback' => $feedback, 'message' => '反馈已提交，我们会尽快处理。'];
    }

    public function updateFeedbackStatus(array $payload): array
    {
        $data = $this->store->load();
        $feedbackId = max(0, (int) ($payload['feedback_id'] ?? $payload['id'] ?? 0));
        if ($feedbackId <= 0) {
            return ['ok' => false, 'message' => '反馈记录不存在。'];
        }
        $status = (string) ($payload['status'] ?? 'processing');
        $status = in_array($status, ['pending', 'processing', 'resolved', 'rejected'], true) ? $status : 'processing';
        $priority = (string) ($payload['priority'] ?? 'normal');
        $priority = in_array($priority, ['low', 'normal', 'high', 'urgent'], true) ? $priority : 'normal';
        $reply = $this->limitText(trim((string) ($payload['reply'] ?? '')), 500);
        $admin = $this->currentAdmin();
        $now = date('Y-m-d H:i:s');

        foreach ($data['feedback_items'] as &$item) {
            if ((int) ($item['id'] ?? 0) !== $feedbackId) {
                continue;
            }
            if (!$this->adminCanAccessFeedbackItem($item, $data)) {
                return ['ok' => false, 'message' => '当前后台角色不能处理该反馈。'];
            }
            $item['status'] = $status;
            $item['priority'] = $priority;
            $item['reply'] = $reply;
            $item['handled_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
            $item['handled_by_admin_name'] = $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60);
            $item['handled_at'] = $now;
            $createdAt = strtotime((string) ($item['created_at'] ?? '')) ?: strtotime($now);
            $item['handled_minutes'] = max(0, (int) floor((strtotime($now) - $createdAt) / 60));
            $item = $this->refreshFeedbackSlaState($item, $now);
            $item['updated_at'] = $now;
            if ($reply !== '' && in_array($status, ['resolved', 'rejected'], true)) {
                $feedbackTypeLabel = [
                    'feedback' => '意见反馈',
                    'complaint' => '投诉',
                    'payment' => '支付问题',
                    'content' => '内容问题',
                    'account' => '账号问题',
                    'promotion' => '推广问题',
                ][(string) ($item['type'] ?? 'feedback')] ?? '反馈';
                $this->appendUserInAppMessageFromTemplate($data, (int) ($item['user_id'] ?? 0), 'feedback_reply_notice', [
                    'type' => $feedbackTypeLabel,
                    'reply' => $reply,
                    'order_no' => (string) ($item['order_no'] ?? ''),
                    'user_id' => (string) ($item['user_id'] ?? 0),
                ], [
                    'source' => 'feedback',
                    'reference_type' => 'feedback',
                    'reference_id' => (int) ($item['id'] ?? 0),
                    'priority' => $priority,
                    'title' => '您的反馈已处理',
                    'body' => '处理结果：' . $reply,
                    'sender_admin_id' => (int) ($admin['id'] ?? 0),
                    'sender_admin_name' => (string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员')),
                    'created_at' => $now,
                    'updated_at' => $now,
                ]);
            }
            $this->store->save($data);

            return ['ok' => true, 'feedback' => $item];
        }
        unset($item);

        return ['ok' => false, 'message' => '反馈记录不存在。'];
    }

    public function syncOperationAlertNotifications(): array
    {
        $data = $this->store->load();
        $scopedData = $this->scopeDashboardData($data, $this->currentAdminScope($data));
        $promotionDashboard = $this->promotionDashboard($scopedData);
        $alertDashboard = $this->operationAlertDashboard($scopedData, $promotionDashboard);
        $alerts = array_merge(
            (array) ($alertDashboard['callback_alerts'] ?? []),
            (array) ($alertDashboard['callback_group_alerts'] ?? []),
            (array) ($alertDashboard['low_conversion_alerts'] ?? []),
            (array) ($alertDashboard['high_refund_alerts'] ?? []),
            (array) ($alertDashboard['low_recovery_alerts'] ?? []),
            (array) ($alertDashboard['auto_paused_alerts'] ?? [])
        );
        if (empty($alerts)) {
            return ['ok' => true, 'created' => 0, 'updated' => 0, 'message' => '当前没有可生成的投放预警。'];
        }

        $admin = $this->currentAdmin();
        $adminName = $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? ($_SESSION['admin_name'] ?? '管理员')))), 60);
        $now = date('Y-m-d H:i:s');
        $created = 0;
        $updated = 0;

        foreach ($alerts as $alert) {
            if (!is_array($alert)) {
                continue;
            }
            $result = $this->upsertOperationAlertNotification($data, $alert, $now, $adminName);
            $created += (int) ($result['created'] ?? 0);
            $updated += (int) ($result['updated'] ?? 0);
        }

        $data['operation_alert_notifications'] = array_slice(array_values($data['operation_alert_notifications']), -5000);
        $this->store->save($data);

        return [
            'ok' => true,
            'created' => $created,
            'updated' => $updated,
            'message' => '投放预警已同步：新增 ' . $created . ' 条，更新 ' . $updated . ' 条。',
        ];
    }

    private function upsertOperationAlertNotification(array &$data, array $alert, string $now, string $reopenActor = '系统'): array
    {
        $data['operation_alert_notifications'] = array_values((array) ($data['operation_alert_notifications'] ?? []));
        $nextId = empty($data['operation_alert_notifications']) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $data['operation_alert_notifications'])) + 1);
        $notification = $this->notificationFromOperationAlert($alert, $nextId, $now);
        $fingerprint = (string) ($notification['fingerprint'] ?? '');

        foreach ($data['operation_alert_notifications'] as $index => $existing) {
            if ((string) ($existing['fingerprint'] ?? '') !== $fingerprint) {
                continue;
            }

            $existing = (array) $existing;
            $existing['type'] = $notification['type'];
            $existing['title'] = $notification['title'];
            $existing['message'] = $notification['message'];
            $existing['suggestion'] = $notification['suggestion'];
            $existing['priority'] = $notification['priority'];
            $existing['last_seen_at'] = $now;
            $existing['occurrence_count'] = max(1, (int) ($existing['occurrence_count'] ?? 1)) + 1;
            $existing['metric_snapshot'] = $notification['metric_snapshot'];
            $existing['source_payload'] = $notification['source_payload'];
            foreach (['promotion_link_id', 'promotion_code', 'order_no', 'agent_id', 'traffic_platform', 'channel_id', 'media_app_id', 'ad_id', 'creative_id', 'material_id'] as $key) {
                $existing[$key] = $notification[$key] ?? ($existing[$key] ?? '');
            }
            if (in_array((string) ($existing['status'] ?? 'pending'), ['resolved', 'ignored'], true)) {
                $existing['status'] = 'pending';
                $existing['reply'] = '异常再次出现，系统已重新打开预警。原处理人：' . $reopenActor;
                $existing['handled_at'] = '';
                $existing['handled_by_admin_id'] = 0;
                $existing['handled_by_admin_name'] = '';
            }
            $existing['updated_at'] = $now;
            $data['operation_alert_notifications'][$index] = $existing;

            return ['created' => 0, 'updated' => 1, 'index' => $index, 'notification' => $existing];
        }

        $data['operation_alert_notifications'][] = $notification;
        $index = array_key_last($data['operation_alert_notifications']);

        return ['created' => 1, 'updated' => 0, 'index' => $index, 'notification' => $notification];
    }

    public function updateOperationAlertNotification(array $payload): array
    {
        $data = $this->store->load();
        $alertId = max(0, (int) ($payload['alert_id'] ?? $payload['id'] ?? 0));
        if ($alertId <= 0) {
            return ['ok' => false, 'message' => '预警记录不存在。'];
        }
        $status = (string) ($payload['status'] ?? 'processing');
        $status = in_array($status, ['pending', 'processing', 'resolved', 'ignored'], true) ? $status : 'processing';
        $reply = $this->limitText(trim((string) ($payload['reply'] ?? '')), 500);
        $admin = $this->currentAdmin();
        $now = date('Y-m-d H:i:s');

        foreach ($data['operation_alert_notifications'] as &$item) {
            if ((int) ($item['id'] ?? 0) !== $alertId) {
                continue;
            }
            if (!$this->adminCanAccessOperationAlertNotification($item, $data)) {
                return ['ok' => false, 'message' => '当前后台角色不能处理该预警。'];
            }
            $item['status'] = $status;
            $item['reply'] = $reply;
            $item['handled_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
            $item['handled_by_admin_name'] = $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60);
            $item['handled_at'] = $now;
            $item['updated_at'] = $now;
            $this->store->save($data);

            return ['ok' => true, 'alert' => $item, 'message' => '预警处理状态已保存。'];
        }
        unset($item);

        return ['ok' => false, 'message' => '预警记录不存在。'];
    }

    public function updateOperationAlertNotificationConfig(array $payload): array
    {
        $data = $this->store->load();
        $channels = $this->operationAlertChannelsFromValue($payload['channels'] ?? [], ['webhook']);
        $urgentChannels = $this->operationAlertChannelsFromValue($payload['urgent_channels'] ?? [], []);
        $failureEscalationChannels = $this->operationAlertChannelsFromValue($payload['failure_escalation_channels'] ?? [], []);
        $statuses = array_values(array_filter(array_map('strval', (array) ($payload['send_statuses'] ?? [])), static fn (string $status): bool => in_array($status, ['pending', 'processing', 'resolved', 'ignored'], true)));
        if (empty($statuses)) {
            $statuses = ['pending', 'processing'];
        }
        $priority = (string) ($payload['min_priority'] ?? 'normal');
        $priority = in_array($priority, ['low', 'normal', 'high', 'urgent'], true) ? $priority : 'normal';

        $data['operation_alert_notification_config'] = [
            'enabled' => !empty($payload['enabled']),
            'channel' => $channels[0] ?? 'webhook',
            'channels' => $channels,
            'webhook_url' => trim((string) ($payload['webhook_url'] ?? '')),
            'secret' => trim((string) ($payload['secret'] ?? '')),
            'wechat_work_url' => trim((string) ($payload['wechat_work_url'] ?? '')),
            'wechat_work_secret' => trim((string) ($payload['wechat_work_secret'] ?? '')),
            'wechat_work_signing_enabled' => !empty($payload['wechat_work_signing_enabled']),
            'email' => $this->limitText(trim((string) ($payload['email'] ?? '')), 120),
            'phone' => $this->limitText(trim((string) ($payload['phone'] ?? '')), 30),
            'title_template' => $this->limitText(trim((string) ($payload['title_template'] ?? '短剧投放预警：{{title}}')), 120),
            'body_template' => $this->limitText(trim((string) ($payload['body_template'] ?? '{{message}}')), 500),
            'email_subject_template' => $this->limitText(trim((string) ($payload['email_subject_template'] ?? $payload['title_template'] ?? '短剧投放预警：{{title}}')), 120),
            'sms_template' => $this->limitText(trim((string) ($payload['sms_template'] ?? '【{{priority}}】{{title}} {{message}}')), 200),
            'send_statuses' => $statuses,
            'min_priority' => $priority,
            'retry_failed' => !empty($payload['retry_failed']),
            'escalation_enabled' => !empty($payload['escalation_enabled']),
            'urgent_channels' => $urgentChannels,
            'failure_escalation_enabled' => !empty($payload['failure_escalation_enabled']),
            'failure_escalation_after_attempts' => max(1, min(10, (int) ($payload['failure_escalation_after_attempts'] ?? 1))),
            'failure_escalation_channels' => $failureEscalationChannels,
            'updated_at' => date('Y-m-d H:i:s'),
        ];
        $data['operation_alert_notification_receivers'] = $this->operationAlertReceiversFromPayload($payload, (array) ($data['operation_alert_notification_receivers'] ?? []));
        $this->store->save($data);

        return ['ok' => true, 'config' => $data['operation_alert_notification_config'], 'message' => '预警通知配置已保存。'];
    }

    public function sendOperationAlertNotification(int $alertId): array
    {
        if ($alertId <= 0) {
            return ['ok' => false, 'status' => 'failed', 'message' => '预警记录不存在。'];
        }

        $data = $this->store->load();
        $config = (array) ($data['operation_alert_notification_config'] ?? []);
        foreach ($data['operation_alert_notifications'] as &$alert) {
            if ((int) ($alert['id'] ?? 0) !== $alertId) {
                continue;
            }
            if (!$this->adminCanAccessOperationAlertNotification($alert, $data)) {
                return ['ok' => false, 'status' => 'skipped', 'message' => '当前后台角色不能发送该预警。'];
            }

            $result = $this->sendOperationAlertNotificationRecord($alert, $config, $data, false);
            $this->store->save($data);

            return $result;
        }
        unset($alert);

        return ['ok' => false, 'status' => 'failed', 'message' => '预警记录不存在。'];
    }

    public function sendPendingOperationAlertNotifications(int $limit = 20): array
    {
        $limit = max(1, min(100, $limit));
        $data = $this->store->load();
        $config = (array) ($data['operation_alert_notification_config'] ?? []);
        $sent = 0;
        $success = 0;
        $processing = 0;
        $failed = 0;
        $skipped = 0;

        foreach ($data['operation_alert_notifications'] as &$alert) {
            if ($sent >= $limit) {
                break;
            }
            if (!$this->adminCanAccessOperationAlertNotification($alert, $data)) {
                continue;
            }
            if (!$this->shouldSendOperationAlertNotification($alert, $config, $data)) {
                continue;
            }

            $sent++;
            $result = $this->sendOperationAlertNotificationRecord($alert, $config, $data, false);
            if (array_key_exists('success', $result) || array_key_exists('failed', $result) || array_key_exists('skipped', $result)) {
                $success += (int) ($result['success'] ?? 0);
                $failed += (int) ($result['failed'] ?? 0);
                $skipped += (int) ($result['skipped'] ?? 0);
            } elseif (($result['status'] ?? '') === 'success') {
                $success++;
            } elseif (($result['status'] ?? '') === 'skipped') {
                $skipped++;
            } else {
                $failed++;
            }
        }
        unset($alert);

        if ($sent > 0) {
            $this->store->save($data);
        }

        return [
            'ok' => true,
            'sent' => $sent,
            'success' => $success,
            'failed' => $failed,
            'skipped' => $skipped,
            'message' => '预警外部通知完成：处理 ' . $sent . ' 条，成功 ' . $success . ' 条，失败 ' . $failed . ' 条，跳过 ' . $skipped . ' 条。',
        ];
    }

    public function executePromotionStopTask(array $payload): array
    {
        $data = $this->store->load();
        $taskId = max(0, (int) ($payload['task_id'] ?? $payload['id'] ?? 0));
        if ($taskId <= 0) {
            return ['ok' => false, 'message' => '停投任务不存在。'];
        }

        foreach ($data['promotion_stop_tasks'] as &$task) {
            if ((int) ($task['id'] ?? 0) !== $taskId) {
                continue;
            }
            if (!$this->adminCanAccessPromotionStopTask($task, $data)) {
                return ['ok' => false, 'message' => '当前后台角色不能执行该停投任务。'];
            }
            $result = $this->executePromotionStopTaskInData($task, $payload, $data);
            $this->store->save($data);

            return $result;
        }
        unset($task);

        return ['ok' => false, 'message' => '停投任务不存在。'];
    }

    public function executePendingPromotionStopTasks(array $payload = []): array
    {
        $limit = max(1, min(100, (int) ($payload['limit'] ?? 20)));
        $data = $this->store->load();
        $handled = 0;
        $success = 0;
        $processing = 0;
        $failed = 0;
        $skipped = 0;
        $now = date('Y-m-d H:i:s');

        foreach ($data['promotion_stop_tasks'] as &$task) {
            if ($handled >= $limit) {
                break;
            }
            if (!in_array((string) ($task['status'] ?? 'pending'), ['pending', 'failed'], true)) {
                continue;
            }
            if (!$this->adminCanAccessPromotionStopTask($task, $data)) {
                continue;
            }
            $retryBlockMessage = $this->promotionStopRetryBlockMessage($task);
            if ($retryBlockMessage !== '') {
                $handled++;
                $skipped++;
                $task['retry_blocked_reason'] = $retryBlockMessage;
                $task['updated_at'] = $now;
                continue;
            }

            $handled++;
            $result = $this->executePromotionStopTaskInData($task, $payload + ['execution_mode' => (string) ($payload['execution_mode'] ?? 'mock_success')], $data);
            $status = (string) ($result['status'] ?? '');
            if ($status === 'success' || $status === 'manual_done') {
                $success++;
            } elseif ($status === 'processing') {
                $processing++;
            } elseif ($status === 'skipped') {
                $skipped++;
            } else {
                $failed++;
            }
        }
        unset($task);

        if ($handled > 0) {
            $this->store->save($data);
        }

        return [
            'ok' => true,
            'handled' => $handled,
            'success' => $success,
            'processing' => $processing,
            'failed' => $failed,
            'skipped' => $skipped,
            'message' => '平台停投任务已处理：执行 ' . $handled . ' 条，成功 ' . $success . ' 条，处理中 ' . $processing . ' 条，失败 ' . $failed . ' 条，跳过 ' . $skipped . ' 条。',
        ];
    }

