    public function savePromotionStopAdapterConfig(array $payload): array
    {
        $data = $this->store->load();
        if ((string) ($this->currentAdminScope($data)['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以维护平台停投适配器。'];
        }

        $presetKey = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['preset_key'] ?? '')));
        $preset = $presetKey !== '' ? (array) ($this->promotionStopAdapterPresets()[$presetKey] ?? []) : [];
        $adapterId = max(0, (int) ($payload['adapter_id'] ?? $payload['id'] ?? 0));
        $data['promotion_stop_adapter_configs'] = array_values((array) ($data['promotion_stop_adapter_configs'] ?? []));
        $targetIndex = null;
        foreach ($data['promotion_stop_adapter_configs'] as $index => $adapter) {
            if ($adapterId > 0 && (int) ($adapter['id'] ?? 0) === $adapterId) {
                $targetIndex = $index;
                break;
            }
        }
        $current = $targetIndex === null ? [] : (array) ($data['promotion_stop_adapter_configs'][$targetIndex] ?? []);
        $nextId = empty($data['promotion_stop_adapter_configs']) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $data['promotion_stop_adapter_configs'])) + 1);
        $adapterKey = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['adapter_key'] ?? $presetKey ?: ($current['adapter_key'] ?? ''))));
        if ($adapterKey === '') {
            $adapterKey = 'stop_adapter_' . ($adapterId > 0 ? $adapterId : $nextId);
        }
        $aliasesText = trim((string) ($payload['provider_aliases_text'] ?? ''));
        $aliases = $aliasesText !== ''
            ? (preg_split('/[\\r\\n,，|]+/u', $aliasesText) ?: [])
            : (array) ($preset['provider_aliases'] ?? ($current['provider_aliases'] ?? []));
        $aliases = array_values(array_unique(array_filter(array_map(static fn (mixed $item): string => trim((string) $item), $aliases), static fn (string $item): bool => $item !== '')));
        $secret = trim((string) ($payload['secret'] ?? ($current['secret'] ?? '')));
        $fieldMapping = $this->callbackFieldMappingFromPayload($payload, (array) ($preset['field_mapping'] ?? ($current['field_mapping'] ?? [])));
        $queryFieldMapping = $this->callbackFieldMappingFromPayload(
            ['field_mapping_text' => (string) ($payload['query_field_mapping_text'] ?? '')],
            (array) ($preset['query_field_mapping'] ?? ($current['query_field_mapping'] ?? []))
        );
        $accountProfiles = $this->promotionStopAccountProfilesFromPayload($payload, (array) ($current['account_profiles'] ?? []));
        $responseConfig = $this->promotionStopResponseConfigFromPayload($payload, (array) ($preset['response_config'] ?? ($current['response_config'] ?? [])));
        $now = date('Y-m-d H:i:s');
        $adapter = [
            'id' => $adapterId > 0 ? $adapterId : $nextId,
            'adapter_key' => $adapterKey,
            'name' => $this->limitText(trim((string) ($payload['name'] ?? ($preset['name'] ?? ($current['name'] ?? '')))) ?: '停投适配器' . ($adapterId > 0 ? $adapterId : $nextId), 80),
            'status' => (string) ($payload['status'] ?? ($current['status'] ?? 'paused')) === 'active' ? 'active' : 'paused',
            'provider_aliases' => array_slice($aliases, 0, 20),
            'endpoint' => trim((string) ($payload['endpoint'] ?? ($preset['endpoint_placeholder'] ?? ($current['endpoint'] ?? '')))),
            'query_endpoint' => trim((string) ($payload['query_endpoint'] ?? ($preset['query_endpoint_placeholder'] ?? ($current['query_endpoint'] ?? '')))),
            'secret' => $secret,
            'auth_config' => $this->callbackAuthConfigFromPayload($payload, (array) ($current['auth_config'] ?? []), $secret),
            'field_mapping' => $fieldMapping,
            'query_field_mapping' => $queryFieldMapping,
            'account_profiles' => $accountProfiles,
            'response_config' => $responseConfig,
            'default_stop_action' => in_array((string) ($payload['default_stop_action'] ?? ($preset['default_stop_action'] ?? ($current['default_stop_action'] ?? 'pause_ad'))), ['pause_ad', 'pause_material', 'pause_campaign', 'manual'], true) ? (string) ($payload['default_stop_action'] ?? ($preset['default_stop_action'] ?? ($current['default_stop_action'] ?? 'pause_ad'))) : 'pause_ad',
            'remark' => $this->limitText(trim((string) ($payload['remark'] ?? ($preset['summary'] ?? ($current['remark'] ?? '')))), 200),
            'last_test_status' => (string) ($current['last_test_status'] ?? ''),
            'last_test_message' => (string) ($current['last_test_message'] ?? ''),
            'last_test_at' => (string) ($current['last_test_at'] ?? ''),
            'last_test_request' => (array) ($current['last_test_request'] ?? []),
            'last_test_response' => (array) ($current['last_test_response'] ?? []),
            'created_at' => (string) ($current['created_at'] ?? $now),
            'updated_at' => $now,
        ];

        if ($targetIndex === null) {
            $data['promotion_stop_adapter_configs'][] = $adapter;
        } else {
            $data['promotion_stop_adapter_configs'][$targetIndex] = $adapter;
        }
        $this->store->save($data);

        return ['ok' => true, 'adapter' => $adapter, 'message' => '平台停投适配器已保存。'];
    }

    private function promotionStopAccountProfilesFromPayload(array $payload, array $fallback = []): array
    {
        $raw = trim((string) ($payload['account_profiles_text'] ?? ''));
        if ($raw !== '') {
            $decoded = json_decode($raw, true);
            if (is_array($decoded)) {
                return $this->normalizePromotionStopAccountProfiles($decoded);
            }
        }

        return $this->normalizePromotionStopAccountProfiles($fallback);
    }

    private function normalizePromotionStopAccountProfiles(array $items): array
    {
        $profiles = [];
        foreach (array_values($items) as $index => $item) {
            if (!is_array($item)) {
                continue;
            }
            $accountKey = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($item['account_key'] ?? $item['key'] ?? '')));
            if ($accountKey === '') {
                $accountKey = 'account_' . ($index + 1);
            }
            $secret = trim((string) ($item['secret'] ?? ''));
            $profiles[] = [
                'account_key' => $accountKey,
                'name' => $this->limitText(trim((string) ($item['name'] ?? $item['account_name'] ?? ('授权账号' . ($index + 1)))), 80),
                'status' => (string) ($item['status'] ?? 'active') === 'paused' ? 'paused' : 'active',
                'priority' => max(0, min(9999, (int) ($item['priority'] ?? 100))),
                'match_agent_ids' => array_slice(array_values(array_unique(array_filter(array_map('intval', (array) ($item['match_agent_ids'] ?? $item['agent_ids'] ?? [])), static fn (int $id): bool => $id > 0))), 0, 100),
                'match_media_app_ids' => $this->promotionStopStringList($item['match_media_app_ids'] ?? $item['media_app_ids'] ?? []),
                'match_channel_ids' => $this->promotionStopStringList($item['match_channel_ids'] ?? $item['channel_ids'] ?? []),
                'match_ad_ids' => $this->promotionStopStringList($item['match_ad_ids'] ?? $item['ad_ids'] ?? []),
                'match_provider_aliases' => $this->promotionStopStringList($item['match_provider_aliases'] ?? $item['provider_aliases'] ?? []),
                'endpoint' => trim((string) ($item['endpoint'] ?? '')),
                'query_endpoint' => trim((string) ($item['query_endpoint'] ?? '')),
                'secret' => $secret,
                'auth_config' => $this->normalizeCallbackAuthConfig((array) ($item['auth_config'] ?? []), $secret),
                'token_expires_at' => trim((string) ($item['token_expires_at'] ?? '')),
                'refresh_endpoint' => trim((string) ($item['refresh_endpoint'] ?? '')),
                'refresh_token' => trim((string) ($item['refresh_token'] ?? '')),
                'refresh_secret' => trim((string) ($item['refresh_secret'] ?? '')),
                'refresh_auth_config' => $this->normalizeCallbackAuthConfig((array) ($item['refresh_auth_config'] ?? []), (string) ($item['refresh_secret'] ?? '')),
                'refresh_field_mapping' => $this->normalizeCallbackFieldMapping((array) ($item['refresh_field_mapping'] ?? [])),
                'refresh_before_minutes' => max(0, min(1440, (int) ($item['refresh_before_minutes'] ?? 30))),
                'auto_refresh' => array_key_exists('auto_refresh', $item) ? !empty($item['auto_refresh']) : true,
                'refresh_access_token_path' => $this->limitText(preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim((string) ($item['refresh_access_token_path'] ?? 'access_token'))) ?: 'access_token', 80),
                'refresh_token_path' => $this->limitText(preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim((string) ($item['refresh_token_path'] ?? 'refresh_token'))) ?: 'refresh_token', 80),
                'refresh_expires_in_path' => $this->limitText(preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim((string) ($item['refresh_expires_in_path'] ?? 'expires_in'))) ?: 'expires_in', 80),
                'refresh_expires_at_path' => $this->limitText(preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim((string) ($item['refresh_expires_at_path'] ?? 'expires_at'))) ?: 'expires_at', 80),
                'last_refresh_status' => in_array((string) ($item['last_refresh_status'] ?? ''), ['success', 'failed', 'skipped'], true) ? (string) $item['last_refresh_status'] : '',
                'last_refresh_message' => $this->limitText(trim((string) ($item['last_refresh_message'] ?? '')), 200),
                'last_refresh_at' => trim((string) ($item['last_refresh_at'] ?? '')),
                'last_refresh_response' => is_array($item['last_refresh_response'] ?? null) ? (array) $item['last_refresh_response'] : [],
                'remark' => $this->limitText(trim((string) ($item['remark'] ?? '')), 160),
            ];
        }
        usort($profiles, static fn (array $a, array $b): int => [(int) ($b['priority'] ?? 0), (string) ($a['account_key'] ?? '')] <=> [(int) ($a['priority'] ?? 0), (string) ($b['account_key'] ?? '')]);

        return array_slice($profiles, 0, 50);
    }

    private function promotionStopStringList(mixed $items): array
    {
        if (!is_array($items)) {
            $items = preg_split('/[\\r\\n,，|]+/u', (string) $items) ?: [];
        }

        return array_slice(array_values(array_unique(array_filter(array_map(static fn (mixed $item): string => trim((string) $item), $items), static fn (string $item): bool => $item !== ''))), 0, 100);
    }

    private function promotionStopResponseConfigFromPayload(array $payload, array $fallback = []): array
    {
        $successValuesText = trim((string) ($payload['response_success_values_text'] ?? ''));
        $successValues = $successValuesText !== ''
            ? (preg_split('/[\\r\\n,，|]+/u', $successValuesText) ?: [])
            : (array) ($fallback['success_values'] ?? ['0', 'true', '1', 'success', 'ok']);
        $successValues = array_values(array_unique(array_filter(array_map(static fn (mixed $item): string => trim((string) $item), $successValues), static fn (string $item): bool => $item !== '')));
        $processingValuesText = trim((string) ($payload['response_processing_values_text'] ?? ''));
        $processingValues = $processingValuesText !== ''
            ? (preg_split('/[\\r\\n,，|]+/u', $processingValuesText) ?: [])
            : (array) ($fallback['processing_values'] ?? ['processing', 'pending', 'running', 'accepted', 'queued', '处理中', '待处理']);
        $processingValues = array_values(array_unique(array_filter(array_map(static fn (mixed $item): string => trim((string) $item), $processingValues), static fn (string $item): bool => $item !== '')));
        $failedValuesText = trim((string) ($payload['response_failed_values_text'] ?? ''));
        $failedValues = $failedValuesText !== ''
            ? (preg_split('/[\\r\\n,，|]+/u', $failedValuesText) ?: [])
            : (array) ($fallback['failed_values'] ?? ['failed', 'fail', 'error', 'rejected', 'cancelled', '失败', '拒绝']);
        $failedValues = array_values(array_unique(array_filter(array_map(static fn (mixed $item): string => trim((string) $item), $failedValues), static fn (string $item): bool => $item !== '')));

        return [
            'success_path' => $this->limitText(preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim((string) ($payload['response_success_path'] ?? ($fallback['success_path'] ?? '')))) ?: '', 80),
            'success_values' => array_slice($successValues, 0, 20),
            'processing_values' => array_slice($processingValues, 0, 20),
            'failed_values' => array_slice($failedValues, 0, 20),
            'request_id_path' => $this->limitText(preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim((string) ($payload['response_request_id_path'] ?? ($fallback['request_id_path'] ?? 'request_id')))) ?: 'request_id', 80),
            'status_path' => $this->limitText(preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim((string) ($payload['response_status_path'] ?? ($fallback['status_path'] ?? 'status')))) ?: 'status', 80),
            'code_path' => $this->limitText(preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim((string) ($payload['response_code_path'] ?? ($fallback['code_path'] ?? 'code')))) ?: 'code', 80),
            'message_path' => $this->limitText(preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim((string) ($payload['response_message_path'] ?? ($fallback['message_path'] ?? 'message')))) ?: 'message', 80),
        ];
    }

    private function promotionStopResponseCheck(array $result, array $config): array
    {
        $config = $this->promotionStopResponseConfigFromPayload([], $config);
        $platformRequestId = $this->promotionStopResponseValue($result, (string) ($config['request_id_path'] ?? 'request_id'))[1] ?? '';
        $platformStatus = $this->promotionStopResponseValue($result, (string) ($config['status_path'] ?? 'status'))[1] ?? '';
        $platformCode = $this->promotionStopResponseValue($result, (string) ($config['code_path'] ?? 'code'))[1] ?? '';
        $platformMessage = $this->promotionStopResponseValue($result, (string) ($config['message_path'] ?? 'message'))[1] ?? '';
        $platformMessageText = $this->limitText($this->scalarText($platformMessage), 200);

        $ok = !empty($result['ok']);
        $taskStatus = $ok ? 'success' : 'failed';
        $message = (string) ($result['message'] ?? ($ok ? '平台停投执行成功。' : '平台停投执行失败。'));
        $successPath = (string) ($config['success_path'] ?? '');
        if ($ok && $successPath !== '') {
            [$found, $successValue] = $this->promotionStopResponseValue($result, $successPath);
            if (!$found) {
                $ok = false;
                $taskStatus = 'failed';
                $message = '平台响应缺少成功字段：' . $successPath . '。';
            } else {
                $expected = array_map(fn (mixed $item): string => strtolower($this->scalarText($item)), (array) ($config['success_values'] ?? []));
                $actual = strtolower($this->scalarText($successValue));
                if (!in_array($actual, $expected, true)) {
                    $ok = false;
                    $taskStatus = 'failed';
                    $message = '平台响应未命中成功值：' . $successPath . '=' . $actual . '。';
                }
            }
        }
        $platformStatusText = strtolower($this->scalarText($platformStatus));
        if ($ok && $platformStatusText !== '') {
            $processingValues = array_map(fn (mixed $item): string => strtolower($this->scalarText($item)), (array) ($config['processing_values'] ?? []));
            $failedValues = array_map(fn (mixed $item): string => strtolower($this->scalarText($item)), (array) ($config['failed_values'] ?? []));
            if (in_array($platformStatusText, $failedValues, true)) {
                $ok = false;
                $taskStatus = 'failed';
                $message = '平台返回失败状态：' . $platformStatusText . '。';
            } elseif (in_array($platformStatusText, $processingValues, true)) {
                $taskStatus = 'processing';
                $message = '平台已受理，等待回查。';
            }
        }
        if (!$ok && $platformMessageText !== '') {
            $message .= ' 平台消息：' . $platformMessageText;
        }

        return [
            'ok' => $ok,
            'task_status' => $taskStatus,
            'message' => $this->limitText($message, 300),
            'platform_request_id' => $this->limitText($this->scalarText($platformRequestId), 120),
            'platform_status' => $this->limitText($this->scalarText($platformStatus), 80),
            'platform_code' => $this->limitText($this->scalarText($platformCode), 80),
            'platform_message' => $platformMessageText,
        ];
    }

    private function promotionStopFailureMeta(array $result, array $responseCheck, array $task, string $phase, string $now): array
    {
        $httpStatus = max(0, (int) ($result['http_status'] ?? 0));
        $body = $result['body'] ?? [];
        $bodyText = is_array($body)
            ? (json_encode($body, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES) ?: '')
            : $this->scalarText($body);
        $haystack = strtolower(implode(' ', array_filter([
            (string) ($result['message'] ?? ''),
            (string) ($responseCheck['message'] ?? ''),
            (string) ($responseCheck['platform_code'] ?? ''),
            (string) ($responseCheck['platform_message'] ?? ''),
            $bodyText,
        ], static fn (string $item): bool => $item !== '')));

        $category = 'platform_failed';
        if (in_array($httpStatus, [401, 403], true) || preg_match('/unauthori[sz]ed|forbidden|invalid[ _-]?token|access[ _-]?token|token[^\\s]*(expired|invalid)|auth[^\\s]*(failed|error)|鉴权|授权失败|授权过期|令牌|登录过期|无权限/u', $haystack) === 1) {
            $category = 'auth_failed';
        } elseif ($httpStatus === 429 || preg_match('/rate[ _-]?limit|too many|throttl|quota|qps|频控|限流|请求过多|访问过快/u', $haystack) === 1) {
            $category = 'rate_limited';
        } elseif ($httpStatus === 0 || $httpStatus >= 500) {
            $category = 'retryable_failed';
        }

        return $this->promotionStopBuildFailureMeta(
            $category,
            (string) ($responseCheck['message'] ?? ($result['message'] ?? '平台停投失败。')),
            $task,
            $phase,
            $now,
            $httpStatus
        );
    }

    private function promotionStopBuildFailureMeta(string $category, string $message, array $task, string $phase, string $now, int $httpStatus = 0): array
    {
        $category = in_array($category, ['auth_failed', 'rate_limited', 'platform_failed', 'retryable_failed', 'config_missing', 'adapter_missing', 'unknown'], true) ? $category : 'unknown';
        $attemptCount = max(1, (int) ($task['attempt_count'] ?? 0), (int) ($task['query_count'] ?? 0));
        $baseTime = strtotime($now) ?: time();
        $nextRetryAt = '';
        $rateLimitedUntil = '';
        $blockedReason = '';

        if ($category === 'auth_failed') {
            $blockedReason = '授权失败，请刷新平台授权账号 token 后再执行。';
        } elseif ($category === 'rate_limited') {
            $minutes = min(120, 30 * max(1, 2 ** max(0, $attemptCount - 1)));
            $nextRetryAt = date('Y-m-d H:i:s', $baseTime + ($minutes * 60));
            $rateLimitedUntil = $nextRetryAt;
            $blockedReason = '平台限流，已进入退避等待。';
        } elseif ($category === 'retryable_failed') {
            $minutes = min(120, 10 * max(1, 2 ** max(0, $attemptCount - 1)));
            $nextRetryAt = date('Y-m-d H:i:s', $baseTime + ($minutes * 60));
        } elseif ($category === 'platform_failed') {
            $minutes = min(120, 30 * max(1, 2 ** max(0, $attemptCount - 1)));
            $nextRetryAt = date('Y-m-d H:i:s', $baseTime + ($minutes * 60));
            $blockedReason = '平台返回失败，等待到期重试或人工复核。';
        } elseif (in_array($category, ['config_missing', 'adapter_missing'], true)) {
            $blockedReason = $category === 'adapter_missing' ? '未匹配平台停投适配器。' : '平台停投配置缺失。';
        }

        return [
            'category' => $category,
            'phase' => $phase,
            'http_status' => $httpStatus,
            'message' => $this->limitText($message, 300),
            'next_retry_at' => $nextRetryAt,
            'rate_limited_until' => $rateLimitedUntil,
            'retry_blocked_reason' => $this->limitText($blockedReason, 300),
        ];
    }

    private function promotionStopApplyFailureMeta(array &$task, array $meta, string $now): void
    {
        $task['error_category'] = (string) ($meta['category'] ?? 'unknown');
        $task['next_retry_at'] = (string) ($meta['next_retry_at'] ?? '');
        $task['rate_limited_until'] = (string) ($meta['rate_limited_until'] ?? '');
        $task['retry_blocked_reason'] = (string) ($meta['retry_blocked_reason'] ?? '');
        $task['last_error_at'] = $now;
    }

    private function promotionStopClearFailureMeta(array &$task): void
    {
        $task['error_category'] = '';
        $task['next_retry_at'] = '';
        $task['rate_limited_until'] = '';
        $task['retry_blocked_reason'] = '';
        $task['last_error_at'] = '';
    }

    private function promotionStopRetryBlockMessage(array $task): string
    {
        if ((string) ($task['status'] ?? '') !== 'failed') {
            return '';
        }

        $category = (string) ($task['error_category'] ?? '');
        if ($category === 'auth_failed') {
            return (string) (($task['retry_blocked_reason'] ?? '') ?: '授权失败，请刷新平台授权账号 token 后单条重试。');
        }
        if (in_array($category, ['adapter_missing', 'config_missing'], true)) {
            return (string) (($task['retry_blocked_reason'] ?? '') ?: '停投配置未补齐，暂不批量重试。');
        }

        $nextRetryAt = trim((string) ($task['next_retry_at'] ?? ''));
        if ($nextRetryAt !== '' && strtotime($nextRetryAt) !== false && strtotime($nextRetryAt) > time()) {
            return '未到下次重试时间：' . $nextRetryAt . '。';
        }

        return '';
    }

    private function upsertPromotionStopOperationAlert(array &$data, array $task, array $meta, string $now): void
    {
        $category = (string) ($meta['category'] ?? 'unknown');
        $type = match ($category) {
            'auth_failed' => 'promotion_stop_auth_failed',
            'rate_limited' => 'promotion_stop_rate_limited',
            default => 'promotion_stop_failed',
        };
        $level = in_array($category, ['auth_failed', 'rate_limited'], true) ? 'high' : 'medium';
        $phaseText = (string) ($meta['phase'] ?? 'execute') === 'query' ? '回查' : '执行';
        $categoryLabel = match ($category) {
            'auth_failed' => '授权失败',
            'rate_limited' => '平台限流',
            'retryable_failed' => '可重试失败',
            'config_missing' => '配置缺失',
            'adapter_missing' => '适配器缺失',
            'platform_failed' => '平台失败',
            default => '未知失败',
        };
        $identity = (string) (($task['task_no'] ?? '') ?: (($task['promotion_code'] ?? '') ?: ('任务 #' . (int) ($task['id'] ?? 0))));
        $messageParts = [
            '平台停投' . $phaseText . '异常：' . $categoryLabel . '。',
            (string) (($task['message'] ?? '') ?: ($meta['message'] ?? '')),
        ];
        if (!empty($task['adapter_account_name']) || !empty($task['adapter_account_key'])) {
            $messageParts[] = '授权账号：' . (string) (($task['adapter_account_name'] ?? '') ?: ($task['adapter_account_key'] ?? '')) . '。';
        }
        if (!empty($meta['next_retry_at'])) {
            $messageParts[] = '下次重试：' . (string) $meta['next_retry_at'] . '。';
        }

        $this->upsertOperationAlertNotification($data, [
            'type' => $type,
            'level' => $level,
            'group_type' => 'promotion_stop_task',
            'key' => 'promotion_stop:' . (int) ($task['id'] ?? 0) . ':' . $category,
            'title' => '平台停投异常：' . $identity,
            'message' => $this->limitText(implode(' ', array_filter($messageParts)), 600),
            'code' => (string) ($task['promotion_code'] ?? ''),
            'promotion_link_id' => (int) ($task['promotion_link_id'] ?? 0),
            'agent_id' => (int) ($task['agent_id'] ?? 0),
            'traffic_platform' => (string) ($task['traffic_platform'] ?? $task['provider'] ?? ''),
            'channel_id' => (string) ($task['channel_id'] ?? ''),
            'media_app_id' => (string) ($task['media_app_id'] ?? ''),
            'ad_id' => (string) ($task['ad_id'] ?? ''),
            'creative_id' => (string) ($task['creative_id'] ?? ''),
            'material_id' => (string) ($task['material_id'] ?? ''),
            'attempt_count' => max(0, (int) ($task['attempt_count'] ?? 0)),
            'query_count' => max(0, (int) ($task['query_count'] ?? 0)),
            'error_category' => $category,
            'next_retry_at' => (string) ($meta['next_retry_at'] ?? ''),
            'rate_limited_until' => (string) ($meta['rate_limited_until'] ?? ''),
            'platform_code' => (string) ($task['platform_code'] ?? ''),
            'platform_message' => (string) ($task['platform_message'] ?? ''),
            'created_at' => $now,
        ], $now, '平台停投任务');
    }

    private function promotionStopResponseValue(array $result, string $path): array
    {
        $path = preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim($path)) ?: '';
        if ($path === '') {
            return [false, null];
        }
        if (!str_starts_with($path, 'body.') && is_array($result['body'] ?? null)) {
            $body = $this->arrayValueByPath((array) $result['body'], $path);
            if ($body[0]) {
                return $body;
            }
        }
        $full = $this->arrayValueByPath($result, $path);
        if ($full[0]) {
            return $full;
        }

        return [false, null];
    }

    private function arrayValueByPath(array $source, string $path): array
    {
        $value = $source;
        foreach (explode('.', $path) as $part) {
            if ($part === '') {
                return [false, null];
            }
            if (is_array($value) && array_key_exists($part, $value)) {
                $value = $value[$part];
                continue;
            }

            return [false, null];
        }

        return [true, $value];
    }

    private function scalarText(mixed $value): string
    {
        if (is_bool($value)) {
            return $value ? 'true' : 'false';
        }
        if ($value === null) {
            return '';
        }
        if (is_scalar($value)) {
            return trim((string) $value);
        }

        return trim(json_encode($value, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES) ?: '');
    }

    public function testPromotionStopAdapterConfig(array $payload): array
    {
        $data = $this->store->load();
        if ((string) ($this->currentAdminScope($data)['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以测试平台停投适配器。'];
        }

        $adapterId = max(0, (int) ($payload['adapter_id'] ?? $payload['id'] ?? 0));
        if ($adapterId <= 0) {
            return ['ok' => false, 'message' => '请选择要测试的平台停投适配器。'];
        }

        $data['promotion_stop_adapter_configs'] = array_values((array) ($data['promotion_stop_adapter_configs'] ?? []));
        foreach ($data['promotion_stop_adapter_configs'] as $index => $adapter) {
            if ((int) ($adapter['id'] ?? 0) !== $adapterId) {
                continue;
            }

            $adapter = (array) $adapter;
            $endpoint = trim((string) ($adapter['endpoint'] ?? ''));
            $now = date('Y-m-d H:i:s');
            if ($endpoint === '') {
                $adapter['last_test_status'] = 'skipped';
                $adapter['last_test_message'] = '未配置平台停投接口地址。';
                $adapter['last_test_at'] = $now;
                $adapter['last_test_request'] = [];
                $adapter['last_test_response'] = [];
                $adapter['updated_at'] = $now;
                $data['promotion_stop_adapter_configs'][$index] = $adapter;
                $this->store->save($data);

                return ['ok' => false, 'status' => 'skipped', 'message' => '未配置平台停投接口地址，无法试连。'];
            }

            $admin = $this->currentAdmin();
            $adminName = $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60);
            $aliases = array_values(array_filter(array_map(static fn (mixed $item): string => trim((string) $item), (array) ($adapter['provider_aliases'] ?? [])), static fn (string $item): bool => $item !== ''));
            $provider = (string) ($aliases[0] ?? ($adapter['name'] ?? ($adapter['adapter_key'] ?? '平台适配器')));
            $basePayload = [
                'event' => 'promotion_stop_adapter_test',
                'task_id' => 0,
                'task_no' => 'TEST-' . date('YmdHis'),
                'stop_action' => (string) ($adapter['default_stop_action'] ?? 'pause_ad'),
                'reason' => '平台停投适配器试连',
                'promotion_link_id' => 0,
                'promotion_code' => 'ADAPTER_TEST',
                'agent_id' => 0,
                'platform' => $provider,
                'provider' => $provider,
                'traffic_platform' => $provider,
                'channel_id' => 'TEST-CHANNEL',
                'media_app_id' => 'TEST-APP',
                'ad_id' => 'TEST-AD',
                'creative_id' => 'TEST-CREATIVE',
                'material_id' => 'TEST-MATERIAL',
                'admin_id' => max(0, (int) ($admin['id'] ?? 0)),
                'admin_name' => $adminName,
                'requested_at' => $now,
            ];
            $fieldMapping = (array) ($adapter['field_mapping'] ?? []);
            $requestPayload = empty($fieldMapping) ? [
                'event' => 'promotion_stop_adapter_test',
                'task' => [
                    'id' => 0,
                    'task_no' => (string) $basePayload['task_no'],
                    'action' => (string) $basePayload['stop_action'],
                    'reason' => (string) $basePayload['reason'],
                ],
                'promotion' => [
                    'promotion_link_id' => 0,
                    'promotion_code' => 'ADAPTER_TEST',
                    'agent_id' => 0,
                ],
                'platform' => [
                    'provider' => $provider,
                    'traffic_platform' => $provider,
                    'channel_id' => 'TEST-CHANNEL',
                    'media_app_id' => 'TEST-APP',
                    'ad_id' => 'TEST-AD',
                    'creative_id' => 'TEST-CREATIVE',
                    'material_id' => 'TEST-MATERIAL',
                ],
                'operator' => [
                    'admin_id' => max(0, (int) ($admin['id'] ?? 0)),
                    'admin_name' => $adminName,
                ],
                'requested_at' => $now,
            ] : $this->callbackPayloadForTemplate($basePayload, $fieldMapping);

            $result = $this->performCallbackRequest($endpoint, $requestPayload, trim((string) ($adapter['secret'] ?? '')), (array) ($adapter['auth_config'] ?? []));
            $responseCheck = $this->promotionStopResponseCheck($result, (array) ($adapter['response_config'] ?? []));
            $result['response_check'] = $responseCheck;
            $ok = !empty($responseCheck['ok']);
            $adapter['last_test_status'] = $ok ? 'success' : 'failed';
            $adapter['last_test_message'] = $this->limitText((string) ($responseCheck['message'] ?? ($ok ? '平台停投适配器试连成功。' : '平台停投适配器试连失败。')), 200);
            $adapter['last_test_at'] = $now;
            $adapter['last_test_request'] = $requestPayload;
            $adapter['last_test_response'] = $result;
            $adapter['updated_at'] = $now;
            $data['promotion_stop_adapter_configs'][$index] = $adapter;
            $this->store->save($data);

            return [
                'ok' => $ok,
                'status' => (string) $adapter['last_test_status'],
                'adapter' => $adapter,
                'message' => ($ok ? '平台停投适配器试连成功：' : '平台停投适配器试连失败：') . (string) $adapter['last_test_message'],
            ];
        }

        return ['ok' => false, 'message' => '平台停投适配器不存在。'];
    }

    private function promotionStopAdapterForTask(array $task, array $data): ?array
    {
        $candidates = array_values(array_filter([
            (string) ($task['provider'] ?? ''),
            (string) ($task['traffic_platform'] ?? ''),
            (string) ($task['media_app_id'] ?? ''),
        ], static fn (string $item): bool => trim($item) !== ''));
        if (empty($candidates)) {
            return null;
        }

        foreach ((array) ($data['promotion_stop_adapter_configs'] ?? []) as $adapter) {
            if ((string) ($adapter['status'] ?? 'paused') !== 'active') {
                continue;
            }
            $aliases = array_values((array) ($adapter['provider_aliases'] ?? []));
            $aliases[] = (string) ($adapter['name'] ?? '');
            $aliases[] = (string) ($adapter['adapter_key'] ?? '');
            foreach ($candidates as $candidate) {
                $candidate = trim($candidate);
                if ($candidate === '') {
                    continue;
                }
                foreach ($aliases as $alias) {
                    $alias = trim((string) $alias);
                    if ($alias === '') {
                        continue;
                    }
                    if ($candidate === $alias || str_contains($candidate, $alias) || str_contains($alias, $candidate)) {
                        return (array) $adapter;
                    }
                }
            }
        }

        return null;
    }

    private function promotionStopAdapterForExecutedTask(array $task, array $data): ?array
    {
        $adapterId = max(0, (int) ($task['adapter_id'] ?? 0));
        $adapterKey = trim((string) ($task['adapter_key'] ?? ''));
        foreach ((array) ($data['promotion_stop_adapter_configs'] ?? []) as $adapter) {
            $adapter = (array) $adapter;
            if ($adapterId > 0 && (int) ($adapter['id'] ?? 0) === $adapterId) {
                return $adapter;
            }
            if ($adapterKey !== '' && (string) ($adapter['adapter_key'] ?? '') === $adapterKey) {
                return $adapter;
            }
        }

        return $this->promotionStopAdapterForTask($task, $data);
    }

    private function promotionStopAdapterAccountForTask(array $task, array $adapter): ?array
    {
        $profiles = array_values((array) ($adapter['account_profiles'] ?? []));
        if (empty($profiles)) {
            return null;
        }

        $bestProfile = null;
        $bestScore = -1;
        foreach ($profiles as $profile) {
            if (!is_array($profile) || (string) ($profile['status'] ?? 'active') !== 'active') {
                continue;
            }
            $score = $this->promotionStopAccountMatchScore($task, $profile);
            if ($score > $bestScore) {
                $bestScore = $score;
                $bestProfile = $profile;
            }
        }

        return $bestScore > 0 ? (array) $bestProfile : null;
    }

    private function promotionStopAdapterAccountForExecutedTask(array $task, array $adapter): ?array
    {
        $accountKey = trim((string) ($task['adapter_account_key'] ?? ''));
        if ($accountKey !== '') {
            foreach ((array) ($adapter['account_profiles'] ?? []) as $profile) {
                if (is_array($profile) && (string) ($profile['account_key'] ?? '') === $accountKey) {
                    return (array) $profile;
                }
            }
        }

        return $this->promotionStopAdapterAccountForTask($task, $adapter);
    }

    private function promotionStopAccountMatchScore(array $task, array $profile): int
    {
        $score = 0;
        $hasRule = false;
        $agentIds = array_map('intval', (array) ($profile['match_agent_ids'] ?? []));
        if (!empty($agentIds)) {
            $hasRule = true;
            if (in_array((int) ($task['agent_id'] ?? 0), $agentIds, true)) {
                $score += 80;
            } else {
                return 0;
            }
        }
        $ruleMap = [
            'match_media_app_ids' => ['media_app_id', 50],
            'match_channel_ids' => ['channel_id', 40],
            'match_ad_ids' => ['ad_id', 35],
            'match_provider_aliases' => ['provider', 25],
        ];
        foreach ($ruleMap as $profileKey => [$taskKey, $weight]) {
            $rules = array_values((array) ($profile[$profileKey] ?? []));
            if (empty($rules)) {
                continue;
            }
            $hasRule = true;
            $candidate = trim((string) ($task[$taskKey] ?? ''));
            if ($profileKey === 'match_provider_aliases' && $candidate === '') {
                $candidate = trim((string) ($task['traffic_platform'] ?? ''));
            }
            if ($this->promotionStopStringRuleMatches($candidate, $rules)) {
                $score += (int) $weight;
            } else {
                return 0;
            }
        }

        if (!$hasRule) {
            $score = 1;
        }

        return $score + max(0, min(9999, (int) ($profile['priority'] ?? 100)));
    }

    private function promotionStopStringRuleMatches(string $candidate, array $rules): bool
    {
        $candidate = trim($candidate);
        if ($candidate === '') {
            return false;
        }
        foreach ($rules as $rule) {
            $rule = trim((string) $rule);
            if ($rule === '') {
                continue;
            }
            if ($candidate === $rule || str_contains($candidate, $rule) || str_contains($rule, $candidate)) {
                return true;
            }
        }

        return false;
    }

    private function promotionStopAccountTokenState(array $profile): array
    {
        $expiresAt = trim((string) ($profile['token_expires_at'] ?? ''));
        if ($expiresAt === '' || strtotime($expiresAt) === false) {
            return ['status' => 'unknown', 'expired' => false, 'should_refresh' => false, 'message' => '未配置 token 到期时间。'];
        }

        $expiresTs = (int) strtotime($expiresAt);
        $now = time();
        $refreshBefore = max(0, min(1440, (int) ($profile['refresh_before_minutes'] ?? 30))) * 60;
        if ($expiresTs <= $now) {
            return ['status' => 'expired', 'expired' => true, 'should_refresh' => true, 'message' => 'token 已过期。'];
        }
        if ($expiresTs <= $now + $refreshBefore) {
            return ['status' => 'expiring', 'expired' => false, 'should_refresh' => true, 'message' => 'token 即将过期。'];
        }

        return ['status' => 'valid', 'expired' => false, 'should_refresh' => false, 'message' => 'token 有效。'];
    }

    private function refreshPromotionStopAdapterAccountForUse(array &$data, array $adapter, ?array $accountProfile, bool $force = false): array
    {
        if ($accountProfile === null) {
            return ['ok' => true, 'adapter' => $adapter, 'account' => null, 'refreshed' => false, 'blocking' => false];
        }

        $state = $this->promotionStopAccountTokenState($accountProfile);
        if (!$force && (empty($state['should_refresh']) || empty($accountProfile['auto_refresh']))) {
            return ['ok' => true, 'adapter' => $adapter, 'account' => $accountProfile, 'refreshed' => false, 'blocking' => false, 'token_state' => $state];
        }

        $adapterId = (int) ($adapter['id'] ?? 0);
        $adapterKey = (string) ($adapter['adapter_key'] ?? '');
        $accountKey = (string) ($accountProfile['account_key'] ?? '');
        foreach ($data['promotion_stop_adapter_configs'] as $adapterIndex => &$storedAdapter) {
            if (($adapterId > 0 && (int) ($storedAdapter['id'] ?? 0) === $adapterId) || ($adapterKey !== '' && (string) ($storedAdapter['adapter_key'] ?? '') === $adapterKey)) {
                foreach ($storedAdapter['account_profiles'] as $profileIndex => &$storedProfile) {
                    if ((string) ($storedProfile['account_key'] ?? '') !== $accountKey) {
                        continue;
                    }
                    $result = $this->refreshPromotionStopAdapterAccountProfile($storedProfile, $force, $state);
                    $storedProfile = $result['account'] ?? $storedProfile;
                    unset($storedProfile);
                    $storedAdapter['account_profiles'][$profileIndex] = $this->normalizePromotionStopAccountProfiles([$storedAdapter['account_profiles'][$profileIndex]])[0] ?? $storedAdapter['account_profiles'][$profileIndex];
                    $updatedAdapter = (array) $storedAdapter;
                    $updatedAccount = (array) ($storedAdapter['account_profiles'][$profileIndex] ?? []);
                    unset($storedAdapter);

                    return $result + [
                        'adapter' => $updatedAdapter,
                        'account' => $updatedAccount,
                        'blocking' => !empty($state['expired']) && empty($result['ok']),
                        'token_state' => $state,
                    ];
                }
                unset($storedProfile);
            }
        }
        unset($storedAdapter);

        return ['ok' => false, 'adapter' => $adapter, 'account' => $accountProfile, 'refreshed' => false, 'blocking' => !empty($state['expired']), 'token_state' => $state, 'message' => '未找到授权账号档案，无法刷新 token。'];
    }

    private function refreshPromotionStopAdapterAccountProfile(array $profile, bool $force, array $state = []): array
    {
        $now = date('Y-m-d H:i:s');
        $endpoint = trim((string) ($profile['refresh_endpoint'] ?? ''));
        if ($endpoint === '') {
            $profile['last_refresh_status'] = 'skipped';
            $profile['last_refresh_message'] = '未配置 token 刷新接口。';
            $profile['last_refresh_at'] = $now;

            return ['ok' => false, 'status' => 'skipped', 'refreshed' => false, 'account' => $profile, 'message' => $profile['last_refresh_message']];
        }
        if (!$force && empty($state['should_refresh'])) {
            return ['ok' => true, 'status' => 'skipped', 'refreshed' => false, 'account' => $profile, 'message' => 'token 暂不需要刷新。'];
        }

        $basePayload = [
            'event' => 'promotion_stop_account_token_refresh',
            'account_key' => (string) ($profile['account_key'] ?? ''),
            'account_name' => (string) ($profile['name'] ?? ''),
            'refresh_token' => (string) ($profile['refresh_token'] ?? ''),
            'requested_at' => $now,
        ];
        $mapping = (array) ($profile['refresh_field_mapping'] ?? []);
        $requestPayload = empty($mapping) ? $basePayload : $this->callbackPayloadForTemplate($basePayload, $mapping);
        $secret = trim((string) ($profile['refresh_secret'] ?? ''));
        $authConfig = (array) ($profile['refresh_auth_config'] ?? []);
        $result = $this->performCallbackRequest($endpoint, $requestPayload, $secret, $authConfig);
        $accessToken = $this->promotionStopResponseValue($result, (string) ($profile['refresh_access_token_path'] ?? 'access_token'))[1] ?? '';
        $accessTokenText = $this->scalarText($accessToken);
        if (!empty($result['ok']) && $accessTokenText !== '') {
            $auth = (array) ($profile['auth_config'] ?? []);
            $auth['mode'] = (string) ($auth['mode'] ?? 'bearer') !== 'none' ? (string) $auth['mode'] : 'bearer';
            $auth['token'] = $accessTokenText;
            $profile['auth_config'] = $this->normalizeCallbackAuthConfig($auth, (string) ($profile['secret'] ?? ''));
            $refreshToken = $this->promotionStopResponseValue($result, (string) ($profile['refresh_token_path'] ?? 'refresh_token'))[1] ?? '';
            $refreshTokenText = $this->scalarText($refreshToken);
            if ($refreshTokenText !== '') {
                $profile['refresh_token'] = $refreshTokenText;
            }
            $expiresAtValue = $this->promotionStopResponseValue($result, (string) ($profile['refresh_expires_at_path'] ?? 'expires_at'))[1] ?? '';
            $expiresAtText = $this->scalarText($expiresAtValue);
            if ($expiresAtText !== '' && strtotime($expiresAtText) !== false) {
                $profile['token_expires_at'] = date('Y-m-d H:i:s', (int) strtotime($expiresAtText));
            } else {
                $expiresInValue = $this->promotionStopResponseValue($result, (string) ($profile['refresh_expires_in_path'] ?? 'expires_in'))[1] ?? '';
                $expiresIn = max(0, (int) $this->scalarText($expiresInValue));
                if ($expiresIn > 0) {
                    $profile['token_expires_at'] = date('Y-m-d H:i:s', time() + $expiresIn);
                }
            }
            $profile['last_refresh_status'] = 'success';
            $profile['last_refresh_message'] = (string) ($result['message'] ?? 'token 刷新成功。');
            $profile['last_refresh_at'] = $now;
            $profile['last_refresh_response'] = $result;

            return ['ok' => true, 'status' => 'success', 'refreshed' => true, 'account' => $profile, 'message' => $profile['last_refresh_message'], 'response' => $result];
        }

        $profile['last_refresh_status'] = 'failed';
        $profile['last_refresh_message'] = !empty($result['ok']) ? '刷新响应缺少 access token。' : (string) ($result['message'] ?? 'token 刷新失败。');
        $profile['last_refresh_at'] = $now;
        $profile['last_refresh_response'] = $result;

        return ['ok' => false, 'status' => 'failed', 'refreshed' => false, 'account' => $profile, 'message' => $profile['last_refresh_message'], 'response' => $result];
    }

    public function refreshPromotionStopAdapterAccountToken(array $payload): array
    {
        $data = $this->store->load();
        if ((string) ($this->currentAdminScope($data)['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以刷新平台授权账号。'];
        }
        $adapterId = max(0, (int) ($payload['adapter_id'] ?? 0));
        $accountKey = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['account_key'] ?? '')));
        if ($adapterId <= 0 || $accountKey === '') {
            return ['ok' => false, 'message' => '请选择要刷新的授权账号。'];
        }

        foreach ($data['promotion_stop_adapter_configs'] as &$adapter) {
            if ((int) ($adapter['id'] ?? 0) !== $adapterId) {
                continue;
            }
            foreach ($adapter['account_profiles'] as &$profile) {
                if ((string) ($profile['account_key'] ?? '') !== $accountKey) {
                    continue;
                }
                $result = $this->refreshPromotionStopAdapterAccountProfile($profile, true);
                $profile = $result['account'] ?? $profile;
                $unblocked = 0;
                if (!empty($result['ok'])) {
                    $now = date('Y-m-d H:i:s');
                    foreach ($data['promotion_stop_tasks'] as &$task) {
                        if ((string) ($task['error_category'] ?? '') !== 'auth_failed') {
                            continue;
                        }
                        if ((int) ($task['adapter_id'] ?? 0) !== $adapterId || (string) ($task['adapter_account_key'] ?? '') !== $accountKey) {
                            continue;
                        }
                        $this->promotionStopClearFailureMeta($task);
                        $task['message'] = '平台授权账号已刷新，可重新执行停投任务。';
                        $task['updated_at'] = $now;
                        $unblocked++;
                    }
                    unset($task);
                }
                $this->store->save($data);

                return [
                    'ok' => !empty($result['ok']),
                    'status' => (string) ($result['status'] ?? ''),
                    'account' => $profile,
                    'message' => !empty($result['ok']) ? ('平台授权账号 token 已刷新，已解锁 ' . $unblocked . ' 条授权失败任务。') : (string) ($result['message'] ?? '平台授权账号 token 刷新失败。'),
                ];
            }
            unset($profile);

            return ['ok' => false, 'message' => '授权账号不存在。'];
        }
        unset($adapter);

        return ['ok' => false, 'message' => '平台停投适配器不存在。'];
    }

    public function queryPromotionStopTaskStatus(array $payload): array
    {
        $data = $this->store->load();
        $taskId = max(0, (int) ($payload['task_id'] ?? $payload['id'] ?? 0));
        if ($taskId <= 0) {
            return ['ok' => false, 'message' => '停投任务不存在。'];
        }

        foreach ($data['promotion_stop_tasks'] as &$task) {
            if ((int) ($task['id'] ?? 0) !== $taskId) {
                continue;
            }
            if (!$this->adminCanAccessPromotionStopTask($task, $data)) {
                return ['ok' => false, 'message' => '当前后台角色不能回查该停投任务。'];
            }
            $result = $this->queryPromotionStopTaskInData($task, $payload, $data);
            $this->store->save($data);

            return $result;
        }
        unset($task);

        return ['ok' => false, 'message' => '停投任务不存在。'];
    }

    public function queryProcessingPromotionStopTasks(array $payload = []): array
    {
        $limit = max(1, min(100, (int) ($payload['limit'] ?? 20)));
        $data = $this->store->load();
        $handled = 0;
        $success = 0;
        $processing = 0;
        $failed = 0;
        $skipped = 0;

        foreach ($data['promotion_stop_tasks'] as &$task) {
            if ($handled >= $limit) {
                break;
            }
            if ((string) ($task['status'] ?? 'pending') !== 'processing') {
                continue;
            }
            if (!$this->adminCanAccessPromotionStopTask($task, $data)) {
                continue;
            }

            $handled++;
            $result = $this->queryPromotionStopTaskInData($task, $payload, $data);
            $status = (string) ($result['status'] ?? '');
            if ($status === 'success') {
                $success++;
            } elseif ($status === 'processing') {
                $processing++;
            } elseif ($status === 'skipped') {
                $skipped++;
            } else {
                $failed++;
            }
        }
        unset($task);

        if ($handled > 0) {
            $this->store->save($data);
        }

        return [
            'ok' => true,
            'handled' => $handled,
            'success' => $success,
            'processing' => $processing,
            'failed' => $failed,
            'skipped' => $skipped,
            'message' => '平台停投结果回查完成：处理 ' . $handled . ' 条，成功 ' . $success . ' 条，仍处理中 ' . $processing . ' 条，失败 ' . $failed . ' 条，跳过 ' . $skipped . ' 条。',
        ];
    }

    private function queryPromotionStopTaskInData(array &$task, array $payload, array &$data): array
    {
        $now = date('Y-m-d H:i:s');
        $admin = $this->currentAdmin();
        $adminName = $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60);
        $adapter = $this->promotionStopAdapterForExecutedTask($task, $data);
        if ($adapter === null) {
            $task['status'] = 'skipped';
            $task['message'] = '未匹配到平台停投适配器，无法回查。';
            $task['last_query_at'] = $now;
            $task['query_count'] = max(0, (int) ($task['query_count'] ?? 0)) + 1;
            $meta = $this->promotionStopBuildFailureMeta('adapter_missing', $task['message'], $task, 'query', $now);
            $this->promotionStopApplyFailureMeta($task, $meta, $now);
            $this->upsertPromotionStopOperationAlert($data, $task, $meta, $now);
            $task['updated_at'] = $now;

            return ['ok' => false, 'status' => 'skipped', 'task' => $task, 'message' => $task['message']];
        }

        $accountProfile = $this->promotionStopAdapterAccountForExecutedTask($task, $adapter);
        $refresh = $this->refreshPromotionStopAdapterAccountForUse($data, $adapter, $accountProfile);
        $adapter = (array) ($refresh['adapter'] ?? $adapter);
        $accountProfile = $refresh['account'] ?? $accountProfile;
        if (!empty($refresh['blocking'])) {
            $task['status'] = 'failed';
            $task['message'] = '授权账号 token 不可用：' . (string) ($refresh['message'] ?? '刷新失败。');
            $task['last_query_at'] = $now;
            $task['query_count'] = max(0, (int) ($task['query_count'] ?? 0)) + 1;
            $task['adapter_id'] = (int) ($adapter['id'] ?? ($task['adapter_id'] ?? 0));
            $task['adapter_key'] = (string) (($adapter['adapter_key'] ?? '') ?: ($task['adapter_key'] ?? ''));
            $task['adapter_name'] = (string) (($adapter['name'] ?? '') ?: ($task['adapter_name'] ?? ''));
            $task['adapter_account_key'] = (string) (($accountProfile['account_key'] ?? '') ?: ($task['adapter_account_key'] ?? ''));
            $task['adapter_account_name'] = (string) (($accountProfile['name'] ?? '') ?: ($task['adapter_account_name'] ?? ''));
            $meta = $this->promotionStopBuildFailureMeta('auth_failed', $task['message'], $task, 'query', $now, 401);
            $this->promotionStopApplyFailureMeta($task, $meta, $now);
            $this->upsertPromotionStopOperationAlert($data, $task, $meta, $now);
            $task['updated_at'] = $now;

            return ['ok' => false, 'status' => 'failed', 'task' => $task, 'message' => $task['message']];
        }
        $endpoint = trim((string) ($payload['query_endpoint'] ?? (($accountProfile['query_endpoint'] ?? '') ?: ($adapter['query_endpoint'] ?? ''))));
        if ($endpoint === '') {
            $task['status'] = 'skipped';
            $task['message'] = '未配置平台停投查询接口，无法回查。';
            $task['last_query_at'] = $now;
            $task['query_count'] = max(0, (int) ($task['query_count'] ?? 0)) + 1;
            $meta = $this->promotionStopBuildFailureMeta('config_missing', $task['message'], $task, 'query', $now);
            $this->promotionStopApplyFailureMeta($task, $meta, $now);
            $this->upsertPromotionStopOperationAlert($data, $task, $meta, $now);
            $task['updated_at'] = $now;

            return ['ok' => false, 'status' => 'skipped', 'task' => $task, 'message' => $task['message']];
        }

        $basePayload = [
            'event' => 'promotion_stop_task_query',
            'task_id' => (int) ($task['id'] ?? 0),
            'task_no' => (string) ($task['task_no'] ?? ''),
            'promotion_code' => (string) ($task['promotion_code'] ?? ''),
            'platform_request_id' => (string) ($task['platform_request_id'] ?? ''),
            'platform_status' => (string) ($task['platform_status'] ?? ''),
            'platform_code' => (string) ($task['platform_code'] ?? ''),
            'platform' => (string) ($task['provider'] ?? ''),
            'provider' => (string) ($task['provider'] ?? ''),
            'traffic_platform' => (string) ($task['traffic_platform'] ?? ''),
            'channel_id' => (string) ($task['channel_id'] ?? ''),
            'media_app_id' => (string) ($task['media_app_id'] ?? ''),
            'ad_id' => (string) ($task['ad_id'] ?? ''),
            'creative_id' => (string) ($task['creative_id'] ?? ''),
            'material_id' => (string) ($task['material_id'] ?? ''),
            'adapter_key' => (string) ($task['adapter_key'] ?? ''),
            'admin_id' => max(0, (int) ($admin['id'] ?? 0)),
            'admin_name' => $adminName,
            'requested_at' => $now,
        ];
        $queryMapping = (array) ($adapter['query_field_mapping'] ?? []);
        $requestPayload = empty($queryMapping) ? [
            'event' => 'promotion_stop_task_query',
            'task' => [
                'id' => (int) ($task['id'] ?? 0),
                'task_no' => (string) ($task['task_no'] ?? ''),
                'platform_request_id' => (string) ($task['platform_request_id'] ?? ''),
            ],
            'promotion' => [
                'promotion_code' => (string) ($task['promotion_code'] ?? ''),
            ],
            'platform' => [
                'provider' => (string) ($task['provider'] ?? ''),
                'traffic_platform' => (string) ($task['traffic_platform'] ?? ''),
                'ad_id' => (string) ($task['ad_id'] ?? ''),
                'material_id' => (string) ($task['material_id'] ?? ''),
            ],
            'operator' => [
                'admin_id' => max(0, (int) ($admin['id'] ?? 0)),
                'admin_name' => $adminName,
            ],
            'requested_at' => $now,
        ] : $this->callbackPayloadForTemplate($basePayload, $queryMapping);

        $secret = trim((string) (($accountProfile['secret'] ?? '') ?: ($adapter['secret'] ?? '')));
        $accountAuthConfig = (array) ($accountProfile['auth_config'] ?? []);
        $useAccountAuth = (string) ($accountAuthConfig['mode'] ?? 'none') !== 'none'
            || trim((string) ($accountAuthConfig['token'] ?? '')) !== ''
            || trim((string) ($accountAuthConfig['secret'] ?? '')) !== '';
        $authConfig = $useAccountAuth ? $accountAuthConfig : (array) ($adapter['auth_config'] ?? []);
        $result = $this->performCallbackRequest($endpoint, $requestPayload, $secret, $authConfig);
        $responseCheck = $this->promotionStopResponseCheck($result, (array) ($adapter['response_config'] ?? []));
        $result['response_check'] = $responseCheck;
        $ok = !empty($responseCheck['ok']);
        $taskStatus = in_array((string) ($responseCheck['task_status'] ?? ''), ['success', 'processing', 'failed'], true) ? (string) $responseCheck['task_status'] : ($ok ? 'success' : 'failed');
        $task['status'] = $taskStatus;
        $task['query_endpoint'] = $endpoint;
        $task['query_count'] = max(0, (int) ($task['query_count'] ?? 0)) + 1;
        $task['last_query_at'] = $now;
        $task['handled_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
        $task['handled_by_admin_name'] = $adminName;
        $task['adapter_account_key'] = (string) (($accountProfile['account_key'] ?? '') ?: ($task['adapter_account_key'] ?? ''));
        $task['adapter_account_name'] = (string) (($accountProfile['name'] ?? '') ?: ($task['adapter_account_name'] ?? ''));
        $task['query_request_payload'] = $requestPayload;
        $task['query_response_payload'] = $result;
        $task['message'] = (string) ($responseCheck['message'] ?? ($ok ? '平台停投结果回查成功。' : '平台停投结果回查失败。'));
        foreach (['platform_request_id', 'platform_status', 'platform_code', 'platform_message'] as $key) {
            $value = (string) ($responseCheck[$key] ?? '');
            if ($value !== '' || $key !== 'platform_request_id') {
                $task[$key] = $value;
            }
        }
        if ($taskStatus === 'success' || $taskStatus === 'failed') {
            $task['completed_at'] = $now;
        }
        if ($taskStatus === 'failed') {
            $meta = $this->promotionStopFailureMeta($result, $responseCheck, $task, 'query', $now);
            $this->promotionStopApplyFailureMeta($task, $meta, $now);
            $this->upsertPromotionStopOperationAlert($data, $task, $meta, $now);
        } else {
            $this->promotionStopClearFailureMeta($task);
        }
        $task['updated_at'] = $now;

        return [
            'ok' => $ok,
            'status' => $taskStatus,
            'task' => $task,
            'message' => (string) $task['message'],
        ];
    }

    private function executePromotionStopTaskInData(array &$task, array $payload, array &$data): array
    {
        $mode = (string) ($payload['execution_mode'] ?? 'adapter');
        $now = date('Y-m-d H:i:s');
        $admin = $this->currentAdmin();
        $adminName = $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60);
        $remark = $this->limitText(trim((string) ($payload['remark'] ?? '')), 300);

        if ($mode === 'manual_done') {
            $task['status'] = 'manual_done';
            $task['completed_at'] = $now;
            $task['handled_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
            $task['handled_by_admin_name'] = $adminName;
            $task['message'] = '已标记为人工停投完成。';
            $task['remark'] = $remark !== '' ? $remark : (string) ($task['remark'] ?? '');
            $this->promotionStopClearFailureMeta($task);
            $task['updated_at'] = $now;

            return ['ok' => true, 'status' => 'manual_done', 'task' => $task, 'message' => '已标记为人工停投完成。'];
        }

        if ($mode === 'cancel') {
            $task['status'] = 'cancelled';
            $task['completed_at'] = $now;
            $task['handled_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
            $task['handled_by_admin_name'] = $adminName;
            $task['message'] = '停投任务已取消。';
            $task['remark'] = $remark !== '' ? $remark : (string) ($task['remark'] ?? '');
            $this->promotionStopClearFailureMeta($task);
            $task['updated_at'] = $now;

            return ['ok' => true, 'status' => 'cancelled', 'task' => $task, 'message' => '停投任务已取消。'];
        }

        $endpoint = trim((string) ($payload['endpoint'] ?? ''));
        $adapter = null;
        $authConfig = [];
        $secret = trim((string) ($payload['secret'] ?? ''));
        $fieldMapping = [];
        $responseConfig = [];
        $accountProfile = null;
        if ($mode === 'mock_success') {
            $endpoint = 'mock://success';
        } elseif ($mode === 'mock_fail') {
            $endpoint = 'mock://fail';
        } elseif ($mode === 'adapter') {
            $adapter = $this->promotionStopAdapterForTask($task, $data);
            if ($adapter === null) {
                $task['status'] = 'skipped';
                $task['message'] = '未匹配到启用的平台停投适配器，已跳过。';
                $task['attempt_count'] = max(0, (int) ($task['attempt_count'] ?? 0)) + 1;
                $task['last_attempt_at'] = $now;
                $task['handled_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
                $task['handled_by_admin_name'] = $adminName;
                $meta = $this->promotionStopBuildFailureMeta('adapter_missing', $task['message'], $task, 'execute', $now);
                $this->promotionStopApplyFailureMeta($task, $meta, $now);
                $this->upsertPromotionStopOperationAlert($data, $task, $meta, $now);
                $task['updated_at'] = $now;

                return ['ok' => false, 'status' => 'skipped', 'task' => $task, 'message' => '未匹配到启用的平台停投适配器，已跳过。'];
            }
            $accountProfile = $this->promotionStopAdapterAccountForTask($task, $adapter);
            $refresh = $this->refreshPromotionStopAdapterAccountForUse($data, $adapter, $accountProfile);
            $adapter = (array) ($refresh['adapter'] ?? $adapter);
            $accountProfile = $refresh['account'] ?? $accountProfile;
            if (!empty($refresh['blocking'])) {
                $task['status'] = 'failed';
                $task['message'] = '授权账号 token 不可用：' . (string) ($refresh['message'] ?? '刷新失败。');
                $task['attempt_count'] = max(0, (int) ($task['attempt_count'] ?? 0)) + 1;
                $task['last_attempt_at'] = $now;
                $task['handled_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
                $task['handled_by_admin_name'] = $adminName;
                $task['adapter_id'] = (int) ($adapter['id'] ?? 0);
                $task['adapter_key'] = (string) ($adapter['adapter_key'] ?? '');
                $task['adapter_name'] = (string) ($adapter['name'] ?? '');
                $task['adapter_account_key'] = (string) ($accountProfile['account_key'] ?? '');
                $task['adapter_account_name'] = (string) ($accountProfile['name'] ?? '');
                $meta = $this->promotionStopBuildFailureMeta('auth_failed', $task['message'], $task, 'execute', $now, 401);
                $this->promotionStopApplyFailureMeta($task, $meta, $now);
                $this->upsertPromotionStopOperationAlert($data, $task, $meta, $now);
                $task['updated_at'] = $now;

                return ['ok' => false, 'status' => 'failed', 'task' => $task, 'message' => $task['message']];
            }
            $endpoint = trim((string) (($accountProfile['endpoint'] ?? '') ?: ($adapter['endpoint'] ?? '')));
            $secret = trim((string) (($accountProfile['secret'] ?? '') ?: ($adapter['secret'] ?? '')));
            $accountAuthConfig = (array) ($accountProfile['auth_config'] ?? []);
            $useAccountAuth = (string) ($accountAuthConfig['mode'] ?? 'none') !== 'none'
                || trim((string) ($accountAuthConfig['token'] ?? '')) !== ''
                || trim((string) ($accountAuthConfig['secret'] ?? '')) !== '';
            $authConfig = $useAccountAuth ? $accountAuthConfig : (array) ($adapter['auth_config'] ?? []);
            $fieldMapping = (array) ($adapter['field_mapping'] ?? []);
            $responseConfig = (array) ($adapter['response_config'] ?? []);
            $task['adapter_id'] = (int) ($adapter['id'] ?? 0);
            $task['adapter_key'] = (string) ($adapter['adapter_key'] ?? '');
            $task['adapter_name'] = (string) ($adapter['name'] ?? '');
            $task['adapter_account_key'] = (string) ($accountProfile['account_key'] ?? '');
            $task['adapter_account_name'] = (string) ($accountProfile['name'] ?? '');
            if ((string) ($task['stop_action'] ?? '') === 'manual' && (string) ($adapter['default_stop_action'] ?? '') !== '') {
                $task['stop_action'] = (string) $adapter['default_stop_action'];
            }
        } elseif ($endpoint === '') {
            $endpoint = trim((string) ($task['endpoint'] ?? ''));
        }
        if ($endpoint === '') {
            $task['status'] = 'skipped';
            $task['message'] = '未配置平台停投接口地址，已跳过。';
            $task['attempt_count'] = max(0, (int) ($task['attempt_count'] ?? 0)) + 1;
            $task['last_attempt_at'] = $now;
            $task['handled_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
            $task['handled_by_admin_name'] = $adminName;
            $meta = $this->promotionStopBuildFailureMeta('config_missing', $task['message'], $task, 'execute', $now);
            $this->promotionStopApplyFailureMeta($task, $meta, $now);
            $this->upsertPromotionStopOperationAlert($data, $task, $meta, $now);
            $task['updated_at'] = $now;

            return ['ok' => false, 'status' => 'skipped', 'task' => $task, 'message' => '未配置平台停投接口地址，已跳过。'];
        }

        $basePayload = [
            'event' => 'promotion_stop_task',
            'task_id' => (int) ($task['id'] ?? 0),
            'task_no' => (string) ($task['task_no'] ?? ''),
            'stop_action' => (string) ($task['stop_action'] ?? 'pause_ad'),
            'reason' => (string) ($task['reason'] ?? ''),
            'promotion_link_id' => (int) ($task['promotion_link_id'] ?? 0),
            'promotion_code' => (string) ($task['promotion_code'] ?? ''),
            'agent_id' => (int) ($task['agent_id'] ?? 0),
            'platform' => (string) ($task['provider'] ?? ''),
            'provider' => (string) ($task['provider'] ?? ''),
            'traffic_platform' => (string) ($task['traffic_platform'] ?? ''),
            'channel_id' => (string) ($task['channel_id'] ?? ''),
            'media_app_id' => (string) ($task['media_app_id'] ?? ''),
            'ad_id' => (string) ($task['ad_id'] ?? ''),
            'creative_id' => (string) ($task['creative_id'] ?? ''),
            'material_id' => (string) ($task['material_id'] ?? ''),
            'admin_id' => max(0, (int) ($admin['id'] ?? 0)),
            'admin_name' => $adminName,
            'requested_at' => $now,
        ];
        $requestPayload = empty($fieldMapping) ? [
            'event' => 'promotion_stop_task',
            'task' => [
                'id' => (int) ($task['id'] ?? 0),
                'task_no' => (string) ($task['task_no'] ?? ''),
                'action' => (string) ($task['stop_action'] ?? 'pause_ad'),
                'reason' => (string) ($task['reason'] ?? ''),
            ],
            'promotion' => [
                'promotion_link_id' => (int) ($task['promotion_link_id'] ?? 0),
                'promotion_code' => (string) ($task['promotion_code'] ?? ''),
                'agent_id' => (int) ($task['agent_id'] ?? 0),
            ],
            'platform' => [
                'provider' => (string) ($task['provider'] ?? ''),
                'traffic_platform' => (string) ($task['traffic_platform'] ?? ''),
                'channel_id' => (string) ($task['channel_id'] ?? ''),
                'media_app_id' => (string) ($task['media_app_id'] ?? ''),
                'ad_id' => (string) ($task['ad_id'] ?? ''),
                'creative_id' => (string) ($task['creative_id'] ?? ''),
                'material_id' => (string) ($task['material_id'] ?? ''),
            ],
            'operator' => [
                'admin_id' => max(0, (int) ($admin['id'] ?? 0)),
                'admin_name' => $adminName,
            ],
            'requested_at' => $now,
        ] : $this->callbackPayloadForTemplate($basePayload, $fieldMapping);

        $task['status'] = 'processing';
        $task['endpoint'] = $endpoint;
        $task['attempt_count'] = max(0, (int) ($task['attempt_count'] ?? 0)) + 1;
        $task['last_attempt_at'] = $now;
        $task['handled_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
        $task['handled_by_admin_name'] = $adminName;
        $task['request_payload'] = $requestPayload;
        $task['remark'] = $remark !== '' ? $remark : (string) ($task['remark'] ?? '');
        $task['retry_blocked_reason'] = '';

        $result = $this->performCallbackRequest($endpoint, $requestPayload, $secret, $authConfig);
        $responseCheck = $this->promotionStopResponseCheck($result, $responseConfig);
        $result['response_check'] = $responseCheck;
        $ok = !empty($responseCheck['ok']);
        $taskStatus = in_array((string) ($responseCheck['task_status'] ?? ''), ['success', 'processing', 'failed'], true) ? (string) $responseCheck['task_status'] : ($ok ? 'success' : 'failed');
        $task['status'] = $taskStatus;
        $task['completed_at'] = $taskStatus === 'success' || $taskStatus === 'failed' ? $now : '';
        $task['message'] = (string) ($responseCheck['message'] ?? ($ok ? '平台停投执行成功。' : '平台停投执行失败。'));
        $task['platform_request_id'] = (string) ($responseCheck['platform_request_id'] ?? '');
        $task['platform_status'] = (string) ($responseCheck['platform_status'] ?? '');
        $task['platform_code'] = (string) ($responseCheck['platform_code'] ?? '');
        $task['platform_message'] = (string) ($responseCheck['platform_message'] ?? '');
        $task['response_payload'] = $result;
        if ($taskStatus === 'failed') {
            $meta = $this->promotionStopFailureMeta($result, $responseCheck, $task, 'execute', $now);
            $this->promotionStopApplyFailureMeta($task, $meta, $now);
            $this->upsertPromotionStopOperationAlert($data, $task, $meta, $now);
        } else {
            $this->promotionStopClearFailureMeta($task);
        }
        $task['updated_at'] = $now;

        return [
            'ok' => $ok,
            'status' => (string) $taskStatus,
            'task' => $task,
            'message' => (string) $task['message'],
        ];
    }

    public function sendCallbackLog(int $logId): array
    {
        if ($logId <= 0) {
            return ['ok' => false, 'status' => 'failed', 'message' => '回传记录不存在。'];
        }

        $data = $this->store->load();
        $config = (array) ($data['callback_config'] ?? []);
        foreach ($data['callback_logs'] as &$log) {
            if ((int) ($log['id'] ?? 0) !== $logId) {
                continue;
            }
            if ((string) ($log['status'] ?? '') === 'failed' && array_key_exists('callback_retry_failed', $log) && empty($log['callback_retry_failed'])) {
                return ['ok' => false, 'status' => 'skipped', 'message' => '该应用策略已关闭失败重试，未再次发送。'];
            }

            $result = $this->sendCallbackLogRecord($log, $config, true);
            $this->store->save($data);

            return $result;
        }
        unset($log);

        return ['ok' => false, 'status' => 'failed', 'message' => '回传记录不存在。'];
    }

    public function sendPendingCallbackLogs(int $limit = 50): array
    {
        $limit = max(1, min(200, $limit));
        $data = $this->store->load();
        $config = (array) ($data['callback_config'] ?? []);
        $processed = 0;
        $sent = 0;
        $success = 0;
        $failed = 0;
        $skipped = 0;

        foreach ($data['callback_logs'] as &$log) {
            if (!in_array((string) ($log['status'] ?? ''), ['pending', 'failed'], true)) {
                continue;
            }
            if ((string) ($log['status'] ?? '') === 'failed' && array_key_exists('callback_retry_failed', $log) && empty($log['callback_retry_failed'])) {
                $processed++;
                $skipped++;
                continue;
            }
            if ($sent >= $limit) {
                break;
            }

            $result = $this->sendCallbackLogRecord($log, $config);
            $processed++;
            if (($result['status'] ?? '') === 'success') {
                $sent++;
                $success++;
            } elseif (($result['status'] ?? '') === 'skipped') {
                $skipped++;
            } else {
                $sent++;
                $failed++;
            }
        }
        unset($log);

        if ($processed > 0) {
            $this->store->save($data);
        }

        return [
            'ok' => true,
            'sent' => $sent,
            'processed' => $processed,
            'success' => $success,
            'failed' => $failed,
            'skipped' => $skipped,
            'message' => '批量回传完成：处理 ' . $processed . ' 条，发送 ' . $sent . ' 条，成功 ' . $success . ' 条，失败 ' . $failed . ' 条，跳过 ' . $skipped . ' 条。',
        ];
    }

    public function manualCallbackOrder(string $orderNo, bool $sendNow = true): array
    {
        $orderNo = trim($orderNo);
        if ($orderNo === '') {
            return ['ok' => false, 'message' => '订单号不能为空。'];
        }

        $data = $this->store->load();
        $order = null;
        foreach ((array) ($data['orders'] ?? []) as $item) {
            if ((string) ($item['order_no'] ?? '') === $orderNo) {
                $order = $item;
                break;
            }
        }
        if (!$order) {
            return ['ok' => false, 'message' => '订单不存在。'];
        }
        if (!$this->adminCanAccessOrder($order, $data)) {
            return ['ok' => false, 'message' => '当前后台角色不能回传该订单。'];
        }
        if (!empty($order['is_test']) || ((string) ($order['type'] ?? '') === 'payment_test')) {
            return ['ok' => true, 'status' => 'skipped', 'message' => '测试订单不参与投放回传，已跳过。'];
        }
        if (!in_array((string) ($order['status'] ?? 'pending'), ['paid', 'partial_refunded', 'refunded'], true)) {
            return ['ok' => true, 'status' => 'skipped', 'message' => '未支付订单无需手动回传，已跳过。'];
        }

        $matchingLogIds = [];
        foreach ((array) ($data['callback_logs'] ?? []) as $log) {
            if ((string) ($log['event'] ?? '') === 'paid' && (string) ($log['order_no'] ?? '') === $orderNo) {
                $logId = (int) ($log['id'] ?? 0);
                if ($logId > 0) {
                    $matchingLogIds[] = $logId;
                }
            }
        }

        if (empty($matchingLogIds)) {
            $this->queueCallbackLog($data, [
                'promotion_link_id' => (int) ($order['promotion_link_id'] ?? 0),
                'code' => (string) ($order['promotion_code'] ?? ''),
                'event' => 'paid',
                'user_id' => (int) ($order['user_id'] ?? 0),
                'order_no' => $orderNo,
                'amount' => round((float) ($order['amount'] ?? 0), 2),
                'created_at' => date('Y-m-d H:i:s'),
            ] + $this->trafficMetaFromPayload($order));
            foreach ((array) ($data['callback_logs'] ?? []) as $log) {
                if ((string) ($log['event'] ?? '') === 'paid' && (string) ($log['order_no'] ?? '') === $orderNo) {
                    $logId = (int) ($log['id'] ?? 0);
                    if ($logId > 0) {
                        $matchingLogIds[] = $logId;
                    }
                }
            }
        }

        $matchingLogIds = array_values(array_unique($matchingLogIds));
        if (empty($matchingLogIds)) {
            return ['ok' => false, 'message' => '订单缺少推广归因，无法生成回传记录。'];
        }

        if (!$sendNow) {
            $this->store->save($data);
            return [
                'ok' => true,
                'callback_log_id' => $matchingLogIds[0],
                'callback_log_ids' => $matchingLogIds,
                'message' => '已生成订单回传记录。',
            ];
        }

        $config = (array) ($data['callback_config'] ?? []);
        $summary = ['success' => 0, 'failed' => 0, 'skipped' => 0];
        $lastResult = null;
        foreach ($data['callback_logs'] as &$log) {
            if (!in_array((int) ($log['id'] ?? 0), $matchingLogIds, true)) {
                continue;
            }
            if ((string) ($log['status'] ?? '') === 'success') {
                $summary['success']++;
                $lastResult = ['ok' => true, 'status' => 'success', 'message' => '该记录已回传成功，无需重复发送。'];
                continue;
            }
            $result = $this->sendCallbackLogRecord($log, $config, true);
            $resultStatus = (string) ($result['status'] ?? 'failed');
            if (isset($summary[$resultStatus])) {
                $summary[$resultStatus]++;
            } else {
                $summary['failed']++;
            }
            $lastResult = $result;
        }
        unset($log);

        $this->store->save($data);
        $total = array_sum($summary);
        $ok = $summary['success'] > 0 && $summary['failed'] <= 0 && $summary['skipped'] <= 0;
        if ($total === 1 && is_array($lastResult)) {
            return [
                'ok' => $ok,
                'callback_log_id' => $matchingLogIds[0],
                'callback_log_ids' => $matchingLogIds,
            ] + $lastResult;
        }

        return [
            'ok' => $ok,
            'callback_log_id' => $matchingLogIds[0],
            'callback_log_ids' => $matchingLogIds,
            'status' => $summary['failed'] > 0 ? 'failed' : ($summary['skipped'] > 0 ? 'skipped' : 'success'),
            'message' => '订单回传已处理：成功 ' . $summary['success'] . ' 条，失败 ' . $summary['failed'] . ' 条，跳过 ' . $summary['skipped'] . ' 条。',
            'summary' => $summary,
        ];
    }

    public function bulkManualCallbackOrders(array $orderNos, bool $sendNow = true, int $limit = 100): array
    {
        $orderNos = array_values(array_unique(array_filter(array_map(static fn ($item): string => trim((string) $item), $orderNos), static fn (string $item): bool => $item !== '')));
        $orderNos = array_slice($orderNos, 0, max(1, min(200, $limit)));
        if (empty($orderNos)) {
            return ['ok' => false, 'message' => '请选择需要回传的订单。', 'processed' => 0, 'success' => 0, 'failed' => 0, 'skipped' => 0];
        }

        $attempted = count($orderNos);
        $processed = 0;
        $success = 0;
        $failed = 0;
        $skipped = 0;
        $messages = [];

        foreach ($orderNos as $orderNo) {
            $result = $this->manualCallbackOrder($orderNo, $sendNow);
            if (!empty($result['ok'])) {
                $processed++;
                if (($result['status'] ?? '') === 'success' || str_contains((string) ($result['message'] ?? ''), '已成功')) {
                    $success++;
                } else {
                    $skipped++;
                }
                continue;
            }

            $failed++;
            if (count($messages) < 5) {
                $messages[] = $orderNo . '：' . (string) ($result['message'] ?? '回传失败');
            }
        }

        return [
            'ok' => true,
            'attempted' => $attempted,
            'processed' => $processed,
            'success' => $success,
            'failed' => $failed,
            'skipped' => $skipped,
            'message' => '批量手动回传完成：尝试 ' . $attempted . ' 笔，成功 ' . $success . ' 笔，跳过/已生成 ' . $skipped . ' 笔，失败 ' . $failed . ' 笔。' . (!empty($messages) ? ' ' . implode('；', $messages) : ''),
        ];
    }

    public function importContentBatch(array $payload): array
    {
        $data = $this->store->load();
        if (!in_array((string) ($this->currentAdminScope($data)['role'] ?? ''), ['super_admin', 'editor'], true)) {
            return ['ok' => false, 'message' => '当前角色不能批量导入内容。'];
        }

        $raw = trim((string) ($payload['content_import_text'] ?? $payload['import_text'] ?? ''));
        if ($raw === '') {
            return ['ok' => false, 'message' => '请粘贴要导入的短剧或小说 JSON。'];
        }

        $itemsResult = $this->contentImportItemsFromText($raw);
        if (empty($itemsResult['ok'])) {
            return ['ok' => false, 'message' => (string) ($itemsResult['message'] ?? '导入内容格式无效。')];
        }

        $items = array_slice(array_values((array) ($itemsResult['items'] ?? [])), 0, 100);
        $now = date('Y-m-d H:i:s');
        $admin = $this->currentAdmin();
        $adminName = $this->limitText(trim((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))), 60);
        $batchNo = 'CIB' . date('YmdHis') . substr(md5($raw . microtime(true)), 0, 6);
        $defaultStatus = (string) ($payload['default_status'] ?? 'draft');
        $defaultStatus = in_array($defaultStatus, ['draft', 'online', 'offline'], true) ? $defaultStatus : 'draft';
        $defaultAuditStatus = (string) ($payload['default_audit_status'] ?? ($defaultStatus === 'online' ? 'online' : 'draft'));
        $defaultAuditStatus = in_array($defaultAuditStatus, ['draft', 'pending', 'approved', 'rejected', 'online', 'offline'], true) ? $defaultAuditStatus : 'draft';
        $defaultGroupId = max(0, (int) ($payload['default_group_id'] ?? 0));
        $defaultTags = $this->contentTagsFromPayload($payload['default_tags'] ?? '');
        $defaultCategory = $this->limitText(trim((string) ($payload['default_category'] ?? '都市')), 40) ?: '都市';
        $nextDramaId = empty($data['dramas']) ? 1 : ((int) max(array_column((array) $data['dramas'], 'id')) + 1);
        $nextNovelId = empty($data['novels']) ? 1 : ((int) max(array_column((array) $data['novels'], 'id')) + 1);
        $summary = [
            'total_count' => count($items),
            'success_count' => 0,
            'failed_count' => 0,
            'drama_count' => 0,
            'novel_count' => 0,
            'episode_count' => 0,
            'chapter_count' => 0,
            'created_ids' => ['dramas' => [], 'novels' => []],
            'errors' => [],
        ];

        foreach ($items as $index => $item) {
            if (!is_array($item)) {
                $summary['failed_count']++;
                $summary['errors'][] = ['row' => $index + 1, 'message' => '该行不是有效对象。'];
                continue;
            }

            $type = (string) ($item['type'] ?? $item['content_type'] ?? '');
            if (!in_array($type, ['drama', 'novel'], true)) {
                $type = isset($item['chapters']) || isset($item['author']) ? 'novel' : 'drama';
            }
            $title = $this->limitText(trim((string) ($item['title'] ?? $item['name'] ?? '')), 100);
            if ($title === '') {
                $summary['failed_count']++;
                $summary['errors'][] = ['row' => $index + 1, 'message' => '标题不能为空。'];
                continue;
            }

            if ($type === 'novel') {
                $novelId = $nextNovelId++;
                $novel = $this->contentImportNovelFromItem($item, $novelId, $defaultCategory, $defaultTags, $defaultGroupId, $defaultStatus, $defaultAuditStatus, $now);
                $data['novels'][] = $novel;
                $summary['success_count']++;
                $summary['novel_count']++;
                $summary['chapter_count'] += count((array) ($novel['chapters'] ?? []));
                $summary['created_ids']['novels'][] = $novelId;
                continue;
            }

            $dramaId = $nextDramaId++;
            $drama = $this->contentImportDramaFromItem($item, $dramaId, $defaultCategory, $defaultTags, $defaultGroupId, $defaultStatus, $defaultAuditStatus, $now);
            $data['dramas'][] = $drama;
            $summary['success_count']++;
            $summary['drama_count']++;
            $summary['episode_count'] += count((array) ($drama['episodes'] ?? []));
            $summary['created_ids']['dramas'][] = $dramaId;
        }

        $status = $summary['failed_count'] > 0 ? ($summary['success_count'] > 0 ? 'partial' : 'failed') : 'success';
        $message = '内容批量导入完成：成功 ' . $summary['success_count'] . ' 条，失败 ' . $summary['failed_count'] . ' 条；短剧 ' . $summary['drama_count'] . ' 部、小说 ' . $summary['novel_count'] . ' 本。';
        $log = array_merge($summary, [
            'id' => empty($data['content_import_logs']) ? 1 : ((int) max(array_column((array) $data['content_import_logs'], 'id')) + 1),
            'batch_no' => $batchNo,
            'source' => $this->limitText(trim((string) ($payload['source'] ?? 'manual')), 40),
            'format' => (string) ($itemsResult['format'] ?? 'json'),
            'status' => $status,
            'admin_id' => max(0, (int) ($admin['id'] ?? 0)),
            'admin_name' => $adminName,
            'message' => $message,
            'created_at' => $now,
        ]);
        $data['content_import_logs'][] = $log;
        $data['content_import_logs'] = array_slice(array_values((array) $data['content_import_logs']), -200);
        $this->store->save($data);

        return ['ok' => $summary['success_count'] > 0, 'message' => $message, 'log' => $log];
    }

