                    $episode['duration'] = trim((string) ($payload['duration'] ?? $episode['duration']));
                    $episode['video_url'] = trim((string) ($payload['video_url'] ?? $episode['video_url']));
                    $episode['is_free'] = !empty($payload['is_free']);
                    $episode['coin_price'] = max(0, (int) ($payload['coin_price'] ?? $episode['coin_price'] ?? $drama['episode_coin_price'] ?? 199));
                    $episode['sort'] = (int) ($payload['sort'] ?? $episode['sort'] ?? 0);
                    $episode['status'] = in_array((string) ($payload['status'] ?? ''), ['online', 'draft', 'offline'], true) ? (string) $payload['status'] : (string) ($episode['status'] ?? $drama['status'] ?? 'draft');
                    $episode['updated_at'] = date('Y-m-d H:i:s');
                    break 2;
                }
            }
        }

        $this->store->save($data);
    }

    public function createEpisode(array $payload): void
    {
