    public function updateNovelChapter(array $payload): void
    {
        $data = $this->store->load();
        foreach ($data['novels'] as &$novel) {
            if ((int) ($novel['id'] ?? 0) !== (int) ($payload['novel_id'] ?? 0)) {
                continue;
            }

            foreach ($novel['chapters'] as &$chapter) {
                if ((int) ($chapter['id'] ?? 0) !== (int) ($payload['chapter_id'] ?? 0)) {
                    continue;
                }

                $chapter['title'] = trim((string) ($payload['title'] ?? $chapter['title'])) ?: '未命名章节';
                $chapter['content'] = trim((string) ($payload['content'] ?? $chapter['content'] ?? ''));
                $chapter['word_count'] = max(0, (int) ($payload['word_count'] ?? 0));
                if ($chapter['word_count'] <= 0) {
                    $chapter['word_count'] = $this->textLength((string) $chapter['content']);
                }
                $chapter['is_free'] = !empty($payload['is_free']);
                $chapter['coin_price'] = max(0, (int) ($payload['coin_price'] ?? $chapter['coin_price'] ?? $novel['chapter_coin_price'] ?? 99));
                $chapter['sort'] = (int) ($payload['sort'] ?? $chapter['sort'] ?? 0);
                $chapter['status'] = in_array((string) ($payload['status'] ?? ''), ['online', 'draft', 'offline'], true) ? (string) $payload['status'] : (string) ($chapter['status'] ?? 'draft');
                $chapter['updated_at'] = date('Y-m-d H:i:s');
                break 2;
            }
        }
        unset($chapter, $novel);

        $this->store->save($data);
    }

