    public function bulkUpdateContentUnits(array $payload): array
    {
        $data = $this->store->load();
        $keys = array_values(array_filter(array_map('strval', (array) ($payload['unit_keys'] ?? []))));
        if (empty($keys)) {
            return ['ok' => false, 'message' => '请选择要批量处理的分集或章节。'];
        }

        $status = (string) ($payload['bulk_status'] ?? 'keep');
        $status = in_array($status, ['keep', 'draft', 'online', 'offline'], true) ? $status : 'keep';
        $freeMode = (string) ($payload['bulk_free_mode'] ?? 'keep');
        $freeMode = in_array($freeMode, ['keep', 'free', 'paid'], true) ? $freeMode : 'keep';
        $coinPriceRaw = trim((string) ($payload['bulk_coin_price'] ?? ''));
        $hasCoinPrice = $coinPriceRaw !== '';
        $coinPrice = max(0, (int) $coinPriceRaw);
        $updated = 0;
        $now = date('Y-m-d H:i:s');

        foreach ($keys as $key) {
            $parts = explode(':', $key);
            if (count($parts) !== 3) {
                continue;
            }

            [$type, $contentIdRaw, $unitIdRaw] = $parts;
            $contentId = (int) $contentIdRaw;
            $unitId = (int) $unitIdRaw;
            if ($type === 'drama') {
                foreach ($data['dramas'] as &$drama) {
                    if ((int) ($drama['id'] ?? 0) !== $contentId) {
                        continue;
                    }
                    foreach ($drama['episodes'] as &$episode) {
                        if ((int) ($episode['id'] ?? 0) !== $unitId) {
                            continue;
                        }
                        if ($status !== 'keep') {
                            $episode['status'] = $status;
                        }
                        if ($freeMode !== 'keep') {
                            $episode['is_free'] = $freeMode === 'free';
                        }
                        if ($hasCoinPrice) {
                            $episode['coin_price'] = $coinPrice;
                        }
                        $episode['updated_at'] = $now;
                        $updated++;
                        break 2;
                    }
                }
                unset($episode, $drama);
                continue;
            }

            if ($type !== 'novel') {
                continue;
            }
            foreach ($data['novels'] as &$novel) {
                if ((int) ($novel['id'] ?? 0) !== $contentId) {
                    continue;
                }
                foreach ($novel['chapters'] as &$chapter) {
                    if ((int) ($chapter['id'] ?? 0) !== $unitId) {
                        continue;
                    }
                    if ($status !== 'keep') {
                        $chapter['status'] = $status;
                    }
                    if ($freeMode !== 'keep') {
                        $chapter['is_free'] = $freeMode === 'free';
                    }
                    if ($hasCoinPrice) {
                        $chapter['coin_price'] = $coinPrice;
                    }
                    $chapter['updated_at'] = $now;
                    $novel['updated_at'] = $now;
                    $updated++;
                    break 2;
                }
            }
            unset($chapter, $novel);
        }

        if ($updated <= 0) {
            return ['ok' => false, 'message' => '没有匹配到可更新的分集或章节。'];
        }

        $this->store->save($data);

        return ['ok' => true, 'updated' => $updated, 'message' => '已批量更新 ' . $updated . ' 个分集/章节。'];
    }

    public function bulkUpdateWorkStatus(array $payload): array
    {
        $data = $this->store->load();
        $keys = array_values(array_unique(array_filter(array_map(static fn (mixed $item): string => trim((string) $item), (array) ($payload['work_keys'] ?? [])))));
        if (empty($keys)) {
            return ['ok' => false, 'message' => '请先勾选要操作的作品。'];
        }

        $status = (string) ($payload['bulk_status'] ?? '');
        if (!in_array($status, ['online', 'offline'], true)) {
            return ['ok' => false, 'message' => '请选择批量上架或批量下架。'];
        }

        $targets = [];
        foreach ($keys as $key) {
            $parts = explode(':', $key, 2);
            if (count($parts) !== 2) {
                continue;
            }
            [$type, $idRaw] = $parts;
            $id = (int) $idRaw;
            if ($id <= 0 || !in_array($type, ['drama', 'novel', 'image', 'h5'], true)) {
                continue;
            }
            $targets[$type . ':' . $id] = ['type' => $type, 'id' => $id];
        }
        if (empty($targets)) {
            return ['ok' => false, 'message' => '没有匹配到可操作的作品。'];
        }

        $updated = 0;
        $touched = 0;
        $now = date('Y-m-d H:i:s');
        foreach ($data['dramas'] as &$drama) {
            $targetKey = 'drama:' . (int) ($drama['id'] ?? 0);
            if (!isset($targets[$targetKey])) {
                continue;
            }
            $changed = (string) ($drama['status'] ?? 'draft') !== $status || (string) ($drama['audit_status'] ?? '') !== $status;
            if ($changed) {
                $updated++;
            }
            $drama['status'] = $status;
            $drama['audit_status'] = $status;
            $drama['updated_at'] = $now;
            $touched++;
        }
        unset($drama);

        foreach ($data['novels'] as &$novel) {
            $targetKey = 'novel:' . (int) ($novel['id'] ?? 0);
            if (!isset($targets[$targetKey])) {
                continue;
            }
            $changed = (string) ($novel['status'] ?? 'draft') !== $status || (string) ($novel['audit_status'] ?? '') !== $status;
            if ($changed) {
                $updated++;
            }
            $novel['status'] = $status;
            $novel['audit_status'] = $status;
            $novel['updated_at'] = $now;
            $touched++;
        }
        unset($novel);

        $mediaItems = array_values((array) ($data['media_contents'] ?? []));
        foreach ($mediaItems as &$media) {
            $type = (string) ($media['type'] ?? 'image') === 'h5' ? 'h5' : 'image';
            $targetKey = $type . ':' . (int) ($media['id'] ?? 0);
            if (!isset($targets[$targetKey])) {
                continue;
            }
            if ((string) ($media['status'] ?? 'draft') !== $status) {
                $updated++;
            }
            $media['status'] = $status;
            $media['updated_at'] = $now;
            $touched++;
        }
        unset($media);
        $data['media_contents'] = $mediaItems;

        if ($touched <= 0) {
            return ['ok' => false, 'message' => '没有匹配到可操作的作品。'];
        }

        $this->store->save($data);

        if ($updated <= 0) {
            return ['ok' => true, 'updated' => 0, 'message' => '所选作品已经是' . ($status === 'online' ? '上架' : '下架') . '状态。'];
        }

        return ['ok' => true, 'updated' => $updated, 'message' => '已批量' . ($status === 'online' ? '上架' : '下架') . ' ' . $updated . ' 个作品。'];
    }

    public function bulkDeleteWorks(array $payload): array
    {
        $data = $this->store->load();
        $keys = array_values(array_unique(array_filter(array_map(static fn (mixed $item): string => trim((string) $item), (array) ($payload['work_keys'] ?? [])))));
        if (empty($keys)) {
            return ['ok' => false, 'message' => '请先勾选要删除的作品。'];
        }

        $targets = [];
        foreach ($keys as $key) {
            $parts = explode(':', $key, 2);
            if (count($parts) !== 2) {
                continue;
            }
            [$type, $idRaw] = $parts;
            $id = (int) $idRaw;
            if ($id <= 0 || !in_array($type, ['drama', 'novel', 'image', 'h5'], true)) {
                continue;
            }
            $targets[$type . ':' . $id] = true;
        }
        if (empty($targets)) {
            return ['ok' => false, 'message' => '没有匹配到可删除的作品。'];
        }

        $deleted = 0;
        $data['dramas'] = array_values(array_filter((array) ($data['dramas'] ?? []), static function (array $drama) use ($targets, &$deleted): bool {
            $key = 'drama:' . (int) ($drama['id'] ?? 0);
            if (!isset($targets[$key])) {
                return true;
            }
            $deleted++;
            return false;
        }));
        $data['novels'] = array_values(array_filter((array) ($data['novels'] ?? []), static function (array $novel) use ($targets, &$deleted): bool {
            $key = 'novel:' . (int) ($novel['id'] ?? 0);
            if (!isset($targets[$key])) {
                return true;
            }
            $deleted++;
            return false;
        }));
        $data['media_contents'] = array_values(array_filter((array) ($data['media_contents'] ?? []), static function (array $media) use ($targets, &$deleted): bool {
            $type = (string) ($media['type'] ?? 'image') === 'h5' ? 'h5' : 'image';
            $key = $type . ':' . (int) ($media['id'] ?? 0);
            if (!isset($targets[$key])) {
                return true;
            }
            $deleted++;
            return false;
        }));

        if ($deleted <= 0) {
            return ['ok' => false, 'message' => '没有匹配到可删除的作品。'];
        }

        $this->store->save($data);

        return ['ok' => true, 'deleted' => $deleted, 'message' => '已删除 ' . $deleted . ' 个作品。历史订单和权益记录已保留。'];
    }

    public function saveMediaContent(array $payload): array
    {
        $data = $this->store->load();
        $type = in_array((string) ($payload['media_type'] ?? $payload['type'] ?? ''), ['image', 'h5'], true) ? (string) ($payload['media_type'] ?? $payload['type']) : 'image';
        $title = $this->limitText(trim((string) ($payload['title'] ?? '')), 100);
        if ($title === '') {
            return ['ok' => false, 'message' => '作品名称不能为空。'];
        }

        $mediaItems = array_values((array) ($data['media_contents'] ?? []));
        $payloadId = max(0, (int) ($payload['media_id'] ?? $payload['id'] ?? 0));
        $now = date('Y-m-d H:i:s');
        $item = [
            'id' => $payloadId,
            'type' => $type,
            'title' => $title,
            'cover' => trim((string) ($payload['cover'] ?? '/assets/cover-1.svg')) ?: '/assets/cover-1.svg',
            'resource_url' => trim((string) ($payload['resource_url'] ?? $payload['url'] ?? '')),
            'author' => $this->limitText(trim((string) ($payload['author'] ?? '')), 40),
            'category' => $this->limitText(trim((string) ($payload['category'] ?? '都市')), 40) ?: '都市',
            'tags' => $this->contentTagsFromPayload($payload['tags'] ?? ''),
            'price_coins' => max(0, (int) ($payload['price_coins'] ?? 99)),
            'is_finished' => !empty($payload['is_finished']),
            'is_vip' => !empty($payload['is_vip']),
            'buy_start' => max(0, (int) ($payload['buy_start'] ?? 1)),
            'read_count' => max(0, (int) ($payload['read_count'] ?? 0)),
            'quality' => in_array((string) ($payload['quality'] ?? 'normal'), ['normal', 'featured', 'premium'], true) ? (string) ($payload['quality'] ?? 'normal') : 'normal',
            'status' => in_array((string) ($payload['status'] ?? 'draft'), ['online', 'draft', 'offline'], true) ? (string) ($payload['status'] ?? 'draft') : 'draft',
            'description' => $this->limitText(trim((string) ($payload['description'] ?? '')), 500),
            'sort' => (int) ($payload['sort'] ?? 100),
            'created_at' => $now,
            'updated_at' => $now,
        ];

        foreach ($mediaItems as $index => $current) {
            if ((int) ($current['id'] ?? 0) !== $payloadId || (string) ($current['type'] ?? '') !== $type || $payloadId <= 0) {
                continue;
            }
            $item['created_at'] = (string) ($current['created_at'] ?? $now);
            if (!array_key_exists('resource_url', $payload) && !array_key_exists('url', $payload)) {
                $item['resource_url'] = (string) ($current['resource_url'] ?? '');
            }
            if (!array_key_exists('description', $payload)) {
                $item['description'] = (string) ($current['description'] ?? '');
            }
            if (!array_key_exists('sort', $payload)) {
                $item['sort'] = (int) ($current['sort'] ?? 100);
            }
            $mediaItems[$index] = $item;
            $data['media_contents'] = $mediaItems;
            $this->store->save($data);

            return ['ok' => true, 'message' => ($type === 'h5' ? 'H5作品已保存。' : '壁纸作品已保存。'), 'item' => $item];
        }

        $item['id'] = empty($mediaItems) ? 1 : ((int) max(array_column($mediaItems, 'id')) + 1);
        $mediaItems[] = $item;
        $data['media_contents'] = $mediaItems;
        $this->store->save($data);

        return ['ok' => true, 'message' => ($type === 'h5' ? 'H5作品已创建。' : '壁纸作品已创建。'), 'item' => $item];
    }

    public function updateBanner(array $payload): void
    {
        $data = $this->store->load();
