            'subtitle' => trim((string) ($payload['banner_subtitle'] ?? $data['banners'][0]['subtitle'] ?? '')),
            'link' => trim((string) ($payload['banner_link'] ?? $data['banners'][0]['link'] ?? '/')),
        ];

        $this->store->save($data);
    }

    public function updatePaymentConfig(array $payload): array
    {
        $data = $this->store->load();
        $snapshot = $this->buildPaymentConfigSnapshot($payload, $data);
        if (empty($snapshot['ok'])) {
            return ['ok' => false, 'message' => (string) ($snapshot['message'] ?? '支付配置内容无效。')];
        }
        if ($this->configApprovalPolicyEnabled($data, 'payment_config') && empty($payload['skip_config_approval'])) {
            return $this->createConfigChangeRequestFromSnapshot('payment_config', $snapshot, [
                'title' => $this->limitText(trim((string) ($payload['change_title'] ?? '')) ?: (string) ($snapshot['title'] ?? '支付配置变更'), 120),
                'reason' => $this->limitText(trim((string) ($payload['change_reason'] ?? '直接保存支付配置触发强制审批')), 240),
            ]);
        }

        $apply = $this->applyConfigSnapshot($data, ['config_type' => 'payment_config', 'target_key' => 'payment_config'], (array) ($snapshot['after_snapshot'] ?? []), false);
        if (empty($apply['ok'])) {
            return ['ok' => false, 'message' => (string) ($apply['message'] ?? '支付配置保存失败。')];
        }
        $this->store->save($data);

        return ['ok' => true, 'message' => '默认支付配置已保存。'];
    }

    private function buildPaymentConfigSnapshot(array $payload, array $data): array
    {
        $current = $data['payment_config'] ?? [];
        $routes = array_values((array) ($current['routes'] ?? []));
        $routeId = trim((string) (($payload['payment_route_id'] ?? '') ?: ($current['default_route_id'] ?? '')));
        if ($routeId === '') {
            $routeId = $this->nextPaymentRouteId($routes);
            $payload['payment_route_id'] = $routeId;
        }
        $baseRoute = $this->findRouteInList($routes, $routeId) ?? $this->defaultPaymentRoute();
        $route = $this->buildPaymentRouteFromPayload($payload, $baseRoute);
        $route['is_default'] = true;
        $route['enabled'] = !empty($payload['enabled']);
        $route['created_at'] = (string) (($baseRoute['created_at'] ?? '') ?: date('Y-m-d H:i:s'));
        $route['updated_at'] = date('Y-m-d H:i:s');

        $replaced = false;
        foreach ($routes as &$item) {
            if ((string) ($item['id'] ?? '') !== (string) $route['id']) {
                $item['is_default'] = false;
                continue;
            }

            $item = $route;
            $replaced = true;
        }
        unset($item);
        if (!$replaced) {
            foreach ($routes as &$item) {
                $item['is_default'] = false;
            }
            unset($item);
            $routes[] = $route;
        }

        return [
            'ok' => true,
            'title' => '默认支付配置变更',
            'target_key' => 'payment_config',
            'before_snapshot' => $current,
            'after_snapshot' => $this->paymentConfigFromDefaultRoute($current, $route, $routes),
        ];
    }

    public function savePaymentRoute(array $payload): void
    {
        $data = $this->store->load();
        $current = $data['payment_config'] ?? [];
        $routes = array_values((array) ($current['routes'] ?? []));
        $routeId = trim((string) ($payload['payment_route_id'] ?? ''));
        if ($routeId === '' || !empty($payload['create_new_route'])) {
            $routeId = $this->nextPaymentRouteId($routes);
            $payload['payment_route_id'] = $routeId;
        }
        $baseRoute = $this->findRouteInList($routes, $routeId) ?? $this->defaultPaymentRoute();
        $route = $this->buildPaymentRouteFromPayload($payload, $baseRoute);
        $route['enabled'] = array_key_exists('enabled', $payload) ? (string) $payload['enabled'] === '1' : !empty($baseRoute['enabled']);
        $makeDefault = array_key_exists('is_default', $payload) ? !empty($payload['is_default']) : (!empty($baseRoute['is_default']) || empty($routes));
        $route['is_default'] = $makeDefault;
        $route['created_at'] = (string) (($baseRoute['created_at'] ?? '') ?: date('Y-m-d H:i:s'));
        $route['updated_at'] = date('Y-m-d H:i:s');

        $replaced = false;
        foreach ($routes as &$item) {
            if ((string) ($item['id'] ?? '') !== (string) $route['id']) {
                if ($makeDefault) {
                    $item['is_default'] = false;
                }
                continue;
            }

            $item = $route;
            $replaced = true;
        }
        unset($item);
        if (!$replaced) {
            if ($makeDefault) {
                foreach ($routes as &$item) {
                    $item['is_default'] = false;
                }
                unset($item);
            }
            $routes[] = $route;
        }

        $defaultRoute = $makeDefault ? $route : ($this->findRouteInList($routes, (string) ($current['default_route_id'] ?? '')) ?? $route);
        $data['payment_config'] = $this->paymentConfigFromDefaultRoute($current, $defaultRoute, $routes);

        $this->store->save($data);
    }

    public function updatePaymentRoutePolicy(array $payload): void
    {
        $data = $this->store->load();
        $current = (array) ($data['payment_config'] ?? []);
        $currentPolicy = (array) ($current['route_policy'] ?? []);
        $mode = (string) ($payload['route_policy_mode'] ?? $payload['mode'] ?? ($currentPolicy['mode'] ?? 'default'));
        $data['payment_config']['route_policy'] = [
            'mode' => in_array($mode, ['default', 'success_rate', 'round_robin'], true) ? $mode : 'default',
            'success_window_days' => max(1, min(90, (int) ($payload['route_policy_success_window_days'] ?? ($currentPolicy['success_window_days'] ?? 7)))),
            'min_sample_orders' => max(0, min(1000, (int) ($payload['route_policy_min_sample_orders'] ?? ($currentPolicy['min_sample_orders'] ?? 3)))),
            'updated_at' => date('Y-m-d H:i:s'),
        ];

        $this->store->save($data);
    }

    public function updateAdminAccount(array $payload): void
    {
        $data = $this->store->load();
        $adminId = (int) ($_SESSION['admin_id'] ?? 0);
        foreach ($data['admins'] as &$admin) {
            if ((int) $admin['id'] !== $adminId) {
                continue;
            }

            $username = trim((string) ($payload['username'] ?? ''));
            $nickname = trim((string) ($payload['nickname'] ?? ''));
            $password = (string) ($payload['password'] ?? '');
            $email = trim((string) ($payload['email'] ?? ($admin['email'] ?? '')));
            $phone = preg_replace('/\D+/', '', (string) ($payload['phone'] ?? ($admin['phone'] ?? ''))) ?: '';
            $role = (string) ($payload['role'] ?? ($admin['role'] ?? 'super_admin'));
            $role = in_array($role, ['super_admin', 'business', 'leader', 'agent', 'editor'], true) ? $role : 'super_admin';
            $agentId = max(0, (int) ($payload['agent_id'] ?? ($admin['agent_id'] ?? 0)));

            if ($username !== '') {
                $admin['username'] = $username;
            }
            if ($nickname !== '') {
                $admin['nickname'] = $nickname;
                $_SESSION['admin_name'] = $nickname;
            }
            if ($email === '' || filter_var($email, FILTER_VALIDATE_EMAIL)) {
                $admin['email'] = $this->limitText($email, 120);
            }
            $admin['phone'] = $this->limitText($phone, 20);
            $admin['role'] = $role;
            $admin['agent_id'] = in_array($role, ['business', 'leader', 'agent'], true) ? $agentId : 0;
            $admin['status'] = 'active';
            $admin['updated_at'] = date('Y-m-d H:i:s');
            if ($password !== '') {
                $admin['password_hash'] = password_hash($password, PASSWORD_DEFAULT);
            }
            break;
        }

        $this->store->save($data);
    }

    public function adminAccounts(?array $data = null): array
    {
        $data ??= $this->store->load();
        $items = array_values((array) ($data['admins'] ?? []));
        usort($items, static fn (array $a, array $b): int => [(int) ($a['id'] ?? 0)] <=> [(int) ($b['id'] ?? 0)]);

        return $items;
    }

    public function saveAdminAccount(array $payload): array
    {
        $data = $this->store->load();
        if ((string) ($this->currentAdminScope($data)['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以管理后台账号。'];
        }

        $admins = array_values((array) ($data['admins'] ?? []));
        $accountId = max(0, (int) ($payload['admin_account_id'] ?? $payload['id'] ?? 0));
        $current = [];
        foreach ($admins as $admin) {
            if ((int) ($admin['id'] ?? 0) === $accountId) {
                $current = $admin;
                break;
            }
        }

        $username = preg_replace('/[^a-zA-Z0-9_.@-]+/', '', trim((string) ($payload['account_username'] ?? $payload['username'] ?? ($current['username'] ?? '')))) ?: '';
        if ($username === '') {
            return ['ok' => false, 'message' => '后台登录账号不能为空。'];
        }
        foreach ($admins as $admin) {
            if ((int) ($admin['id'] ?? 0) !== $accountId && strcasecmp((string) ($admin['username'] ?? ''), $username) === 0) {
                return ['ok' => false, 'message' => '后台登录账号已存在。'];
            }
        }

        $nickname = $this->limitText(trim((string) ($payload['account_nickname'] ?? $payload['nickname'] ?? ($current['nickname'] ?? $username))), 60);
        if ($nickname === '') {
            $nickname = $username;
        }
        $email = trim((string) ($payload['account_email'] ?? $payload['email'] ?? ($current['email'] ?? '')));
        if ($email !== '' && !filter_var($email, FILTER_VALIDATE_EMAIL)) {
            return ['ok' => false, 'message' => '通知邮箱格式不正确。'];
        }
        $phone = preg_replace('/\D+/', '', (string) ($payload['account_phone'] ?? $payload['phone'] ?? ($current['phone'] ?? ''))) ?: '';
        $role = (string) ($payload['account_role'] ?? $payload['role'] ?? ($current['role'] ?? 'editor'));
        $role = in_array($role, ['super_admin', 'business', 'leader', 'agent', 'editor'], true) ? $role : 'editor';
        $agentId = max(0, (int) ($payload['account_agent_id'] ?? $payload['agent_id'] ?? ($current['agent_id'] ?? 0)));
        if (in_array($role, ['super_admin', 'editor'], true)) {
            $agentId = 0;
        }
        $status = (string) ($payload['account_status'] ?? $payload['status'] ?? ($current['status'] ?? 'active'));
        $status = in_array($status, ['active', 'paused'], true) ? $status : 'active';
        $password = (string) ($payload['account_password'] ?? $payload['password'] ?? '');
        if ($accountId <= 0 && $password === '') {
            return ['ok' => false, 'message' => '新建后台账号必须设置初始密码。'];
        }

        $superAdminCount = 0;
        foreach ($admins as $admin) {
            if ((int) ($admin['id'] ?? 0) === $accountId) {
                if ($role === 'super_admin' && $status === 'active') {
                    $superAdminCount++;
                }
                continue;
            }
            if ((string) ($admin['role'] ?? '') === 'super_admin' && (string) ($admin['status'] ?? 'active') === 'active') {
                $superAdminCount++;
            }
        }
        if ($superAdminCount <= 0) {
            return ['ok' => false, 'message' => '至少保留一个启用的管理员账号。'];
        }

        $now = date('Y-m-d H:i:s');
        $account = [
            'id' => $accountId > 0 ? $accountId : (empty($admins) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $admins)) + 1)),
            'username' => $this->limitText($username, 80),
            'password_hash' => (string) ($current['password_hash'] ?? ''),
            'nickname' => $nickname,
            'email' => $this->limitText($email, 120),
            'phone' => $this->limitText($phone, 20),
            'role' => $role,
            'agent_id' => $agentId,
            'status' => $status,
            'created_at' => (string) (($current['created_at'] ?? '') ?: $now),
            'updated_at' => $now,
        ];
        if ($password !== '') {
            $account['password_hash'] = password_hash($password, PASSWORD_DEFAULT);
            $account['password_changed_at'] = $now;
        }

        $replaced = false;
        foreach ($admins as &$admin) {
            if ((int) ($admin['id'] ?? 0) !== (int) $account['id']) {
                continue;
            }
            $admin = $account;
            $replaced = true;
            break;
        }
        unset($admin);
        if (!$replaced) {
            $admins[] = $account;
        }
        $data['admins'] = $admins;
        $this->store->save($data);

        return ['ok' => true, 'account' => $account, 'message' => '后台账号已保存。'];
    }

    public function updateBaseConfig(array $payload): void
    {
        $data = $this->store->load();
        $clip = static function (string $value, int $length): string {
            if (function_exists('mb_substr')) {
                return (string) mb_substr($value, 0, $length);
            }

            $chars = preg_split('//u', $value, -1, PREG_SPLIT_NO_EMPTY);
            if ($chars === false) {
                return substr($value, 0, $length);
            }

            return implode('', array_slice($chars, 0, $length));
        };

        $siteName = trim((string) ($payload['site_name'] ?? ''));
        $icpNumber = trim((string) ($payload['icp_number'] ?? ''));

        $data['site_config']['site_name'] = $clip($siteName !== '' ? $siteName : '精秀短剧', 40);
        $data['site_config']['icp_number'] = $clip($icpNumber, 80);

        $this->store->save($data);
    }

