    public function saveMessageTemplate(array $payload): array
    {
        $data = $this->store->load();
        if ((string) ($this->currentAdminScope($data)['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以维护消息模板。'];
        }

        $templates = array_values((array) ($data['message_templates'] ?? []));
        $templateId = max(0, (int) ($payload['template_id'] ?? $payload['id'] ?? 0));
        $current = [];
        foreach ($templates as $template) {
            if ((int) ($template['id'] ?? 0) === $templateId) {
                $current = $template;
                break;
            }
        }

        $channel = (string) ($payload['channel'] ?? ($current['channel'] ?? 'system'));
        $channel = in_array($channel, ['system', 'sms', 'email', 'webhook', 'in_app'], true) ? $channel : 'system';
        $scenario = (string) ($payload['scenario'] ?? ($current['scenario'] ?? 'system_notice'));
        $scenario = in_array($scenario, ['login_code', 'config_approval', 'operation_alert', 'agent_settlement', 'feedback_reply', 'rights_repair', 'payment_success', 'activity', 'system_notice'], true) ? $scenario : 'system_notice';
        $key = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['template_key'] ?? $payload['key'] ?? ($current['template_key'] ?? ''))));
        if ($key === '') {
            $key = $scenario . '_' . $channel;
        }
        foreach ($templates as $template) {
            if ((int) ($template['id'] ?? 0) === $templateId) {
                continue;
            }
            if ((string) ($template['template_key'] ?? '') === $key) {
                return ['ok' => false, 'message' => '模板编码已存在。'];
            }
        }

        $name = $this->limitText(trim((string) ($payload['name'] ?? ($current['name'] ?? ''))), 80);
        $body = $this->limitText(trim((string) ($payload['body_template'] ?? $payload['body'] ?? ($current['body_template'] ?? ''))), 1200);
        if ($name === '') {
            return ['ok' => false, 'message' => '模板名称不能为空。'];
        }
        if ($body === '') {
            return ['ok' => false, 'message' => '模板内容不能为空。'];
        }

        $admin = $this->currentAdmin();
        $now = date('Y-m-d H:i:s');
        $nextId = empty($templates) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $templates)) + 1);
        $template = array_merge($current, [
            'id' => $templateId > 0 ? $templateId : $nextId,
            'template_key' => $key,
            'name' => $name,
            'scenario' => $scenario,
            'channel' => $channel,
            'status' => in_array((string) ($payload['status'] ?? ($current['status'] ?? 'active')), ['active', 'paused'], true) ? (string) ($payload['status'] ?? ($current['status'] ?? 'active')) : 'active',
            'title_template' => $this->limitText(trim((string) ($payload['title_template'] ?? ($current['title_template'] ?? ''))), 160),
            'body_template' => $body,
            'placeholders' => $this->identifierListFromPayload($payload['placeholders'] ?? ($current['placeholders'] ?? []), 24, 40),
            'remark' => $this->limitText(trim((string) ($payload['remark'] ?? ($current['remark'] ?? ''))), 240),
            'sort' => (int) ($payload['sort'] ?? ($current['sort'] ?? 100)),
            'created_by_admin_id' => (int) ($current['created_by_admin_id'] ?? ($admin['id'] ?? 0)),
            'created_by_admin_name' => (string) ($current['created_by_admin_name'] ?? (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员'))),
            'updated_by_admin_id' => (int) ($admin['id'] ?? 0),
            'updated_by_admin_name' => (string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员')),
            'created_at' => (string) (($current['created_at'] ?? '') ?: $now),
            'updated_at' => $now,
        ]);

        $replaced = false;
        foreach ($templates as &$item) {
            if ((int) ($item['id'] ?? 0) !== (int) $template['id']) {
                continue;
            }
            $item = $template;
            $replaced = true;
            break;
        }
        unset($item);
        if (!$replaced) {
            $templates[] = $template;
        }

        $data['message_templates'] = $templates;
        $this->store->save($data);

        return ['ok' => true, 'template' => $template, 'message' => '消息模板已保存。'];
    }

    public function sendInAppMessage(array $payload): array
    {
        $data = $this->store->load();
        $adminScope = $this->currentAdminScope($data);
        if ((string) ($adminScope['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以发送站内消息。'];
        }

        $template = $this->messageTemplateByIdOrKey($data, (int) ($payload['template_id'] ?? 0), (string) ($payload['template_key'] ?? ''));
        $variables = $this->messageVariablesFromText((string) ($payload['variables_text'] ?? ''));
        $title = $this->limitText(trim((string) ($payload['title'] ?? '')), 160);
        $body = $this->limitText(trim((string) ($payload['body'] ?? '')), 1200);
        if (!empty($template)) {
            $rendered = $this->renderGeneralMessageTemplate($template, $variables);
            $title = $title !== '' ? $title : (string) ($rendered['title'] ?? '');
            $body = $body !== '' ? $body : (string) ($rendered['body'] ?? '');
        }
        if ($title === '') {
            $title = '站内消息';
        }
        if ($body === '') {
            return ['ok' => false, 'message' => '站内消息内容不能为空。'];
        }

        $recipients = $this->inAppRecipientsFromPayload($payload, $data);
        if (empty($recipients)) {
            return ['ok' => false, 'message' => '未匹配到站内消息接收人。'];
        }

        $admin = $this->currentAdmin();
        $now = date('Y-m-d H:i:s');
        $created = 0;
        foreach ($recipients as $recipient) {
            $this->appendInAppMessage($data, [
                'recipient_type' => (string) ($recipient['recipient_type'] ?? 'user'),
                'user_id' => (int) ($recipient['user_id'] ?? 0),
                'admin_id' => (int) ($recipient['admin_id'] ?? 0),
                'agent_id' => (int) ($recipient['agent_id'] ?? 0),
                'recipient_name' => (string) ($recipient['recipient_name'] ?? ''),
                'recipient_contact' => (string) ($recipient['recipient_contact'] ?? ''),
                'scenario' => (string) ($template['scenario'] ?? $payload['scenario'] ?? 'system_notice'),
                'template_key' => (string) ($template['template_key'] ?? $payload['template_key'] ?? ''),
                'source' => 'manual',
                'reference_type' => (string) ($payload['reference_type'] ?? ''),
                'reference_id' => (int) ($payload['reference_id'] ?? 0),
                'title' => $title,
                'body' => $body,
                'priority' => (string) ($payload['priority'] ?? 'normal'),
                'sender_admin_id' => (int) ($admin['id'] ?? 0),
                'sender_admin_name' => (string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员')),
                'created_at' => $now,
                'updated_at' => $now,
            ]);
            $created++;
        }
        $this->store->save($data);

        return ['ok' => true, 'message' => '站内消息已投递 ' . $created . ' 条。', 'sent' => $created];
    }

    public function resendBusinessInAppMessage(array $payload): array
    {
        $data = $this->store->load();
        $adminScope = $this->currentAdminScope($data);
        if ((string) ($adminScope['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以重发业务站内消息。'];
        }

        $referenceType = (string) ($payload['reference_type'] ?? 'order');
        $referenceType = in_array($referenceType, ['feedback', 'order', 'rights_repair', 'activity_log'], true) ? $referenceType : 'order';
        $referenceId = max(0, (int) ($payload['reference_id'] ?? $payload['id'] ?? 0));
        $orderNo = trim((string) ($payload['order_no'] ?? ''));
        $admin = $this->currentAdmin();
        $sender = [
            'sender_admin_id' => (int) ($admin['id'] ?? 0),
            'sender_admin_name' => (string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员')),
            'created_at' => date('Y-m-d H:i:s'),
            'updated_at' => date('Y-m-d H:i:s'),
        ];

        if ($referenceType === 'feedback') {
            foreach ((array) ($data['feedback_items'] ?? []) as $feedback) {
                if ((int) ($feedback['id'] ?? 0) !== $referenceId) {
                    continue;
                }
                $reply = trim((string) ($feedback['reply'] ?? ''));
                if ($reply === '') {
                    return ['ok' => false, 'message' => '该反馈还没有处理回复，不能重发。'];
                }
                $feedbackTypeLabel = [
                    'feedback' => '意见反馈',
                    'complaint' => '投诉',
                    'payment' => '支付问题',
                    'content' => '内容问题',
                    'account' => '账号问题',
                    'promotion' => '推广问题',
                ][(string) ($feedback['type'] ?? 'feedback')] ?? '反馈';
                $message = $this->appendUserInAppMessageFromTemplate($data, (int) ($feedback['user_id'] ?? 0), 'feedback_reply_notice', [
                    'type' => $feedbackTypeLabel,
                    'reply' => $reply,
                    'order_no' => (string) ($feedback['order_no'] ?? ''),
                    'user_id' => (string) ($feedback['user_id'] ?? 0),
                ], $sender + [
                    'source' => 'feedback_resend',
                    'reference_type' => 'feedback',
                    'reference_id' => (int) ($feedback['id'] ?? 0),
                    'priority' => (string) ($feedback['priority'] ?? 'normal'),
                    'title' => '您的反馈已处理',
                    'body' => '处理结果：' . $reply,
                ]);
                if ($message === null) {
                    return ['ok' => false, 'message' => '反馈接收用户不存在或模板内容为空。'];
                }
                $this->store->save($data);

                return ['ok' => true, 'message' => '反馈处理站内消息已重发。', 'sent' => 1, 'message_id' => (int) ($message['id'] ?? 0)];
            }

            return ['ok' => false, 'message' => '反馈记录不存在。'];
        }

        if ($referenceType === 'order') {
            foreach ((array) ($data['orders'] ?? []) as $order) {
                $sameOrder = $orderNo !== '' && (string) ($order['order_no'] ?? '') === $orderNo;
                $sameId = $referenceId > 0 && (int) ($order['id'] ?? 0) === $referenceId;
                if (!$sameOrder && !$sameId) {
                    continue;
                }
                if (!in_array((string) ($order['status'] ?? 'pending'), ['paid', 'partial_refunded'], true)) {
                    return ['ok' => false, 'message' => '只有已支付订单可以重发支付成功站内消息。'];
                }
                if (!empty($order['is_test'])) {
                    return ['ok' => false, 'message' => '测试订单不发送用户站内消息。'];
                }
                $contentTitle = (string) ($order['type'] ?? '') === 'membership'
                    ? 'VIP会员'
                    : $this->contentTitleFromData($data, (string) ($order['content_type'] ?? 'drama'), (int) ($order['drama_id'] ?? 0), (int) ($order['novel_id'] ?? 0));
                $message = $this->appendUserInAppMessageFromTemplate($data, (int) ($order['user_id'] ?? 0), 'payment_success_notice', [
                    'order_no' => (string) ($order['order_no'] ?? ''),
                    'amount' => number_format((float) ($order['amount'] ?? 0), 2, '.', ''),
                    'content' => $contentTitle,
                    'rights' => $this->orderRightsLabel($order),
                ], $sender + [
                    'source' => 'payment_resend',
                    'reference_type' => 'order',
                    'reference_id' => (int) ($order['id'] ?? 0),
                    'priority' => 'normal',
                    'title' => '支付成功：' . $contentTitle,
                    'body' => '订单 ' . (string) ($order['order_no'] ?? '') . ' 已支付成功，对应权益已发放。',
                ]);
                if ($message === null) {
                    return ['ok' => false, 'message' => '订单接收用户不存在或模板内容为空。'];
                }
                $this->store->save($data);

                return ['ok' => true, 'message' => '支付成功站内消息已重发。', 'sent' => 1, 'message_id' => (int) ($message['id'] ?? 0)];
            }

            return ['ok' => false, 'message' => '订单不存在。'];
        }

        if ($referenceType === 'rights_repair') {
            foreach ((array) ($data['rights_repair_logs'] ?? []) as $log) {
                if ((int) ($log['id'] ?? 0) !== $referenceId) {
                    continue;
                }
                if ((string) ($log['status'] ?? 'success') !== 'success') {
                    return ['ok' => false, 'message' => '只有成功的权益处理记录可以重发。'];
                }
                $action = (string) ($log['action'] ?? '');
                $contentName = match ($action) {
                    'grant_coin', 'deduct_coin' => abs((int) ($log['coins'] ?? 0) + (int) ($log['bonus_coins'] ?? 0)) . ' K币',
                    'grant_vip', 'revoke_vip' => ((int) ($log['vip_days'] ?? 0) > 0 ? ((int) $log['vip_days'] . ' 天 VIP') : 'VIP 权益'),
                    default => $this->contentTitleFromData($data, (string) ($log['content_type'] ?? 'drama'), (int) ($log['drama_id'] ?? 0), (int) ($log['novel_id'] ?? 0)),
                };
                $message = $this->appendUserInAppMessageFromTemplate($data, (int) ($log['user_id'] ?? 0), 'rights_repair_notice', [
                    'action' => $this->rightsRepairActionLabel($action),
                    'message' => (string) ($log['message'] ?? ''),
                    'content' => $contentName,
                    'coins' => (string) abs((int) ($log['coins'] ?? 0) + (int) ($log['bonus_coins'] ?? 0)),
                    'vip_days' => (string) ($log['vip_days'] ?? 0),
                    'remark' => (string) ($log['remark'] ?? ''),
                ], $sender + [
                    'source' => 'rights_repair_resend',
                    'reference_type' => 'rights_repair',
                    'reference_id' => (int) ($log['id'] ?? 0),
                    'priority' => in_array($action, ['deduct_coin', 'revoke_vip', 'revoke_content'], true) ? 'high' : 'normal',
                    'title' => '权益变更：' . $this->rightsRepairActionLabel($action),
                    'body' => trim((string) ($log['message'] ?? '') . ' ' . $contentName . ' ' . (string) ($log['remark'] ?? '')),
                ]);
                if ($message === null) {
                    return ['ok' => false, 'message' => '权益记录接收用户不存在或模板内容为空。'];
                }
                $this->store->save($data);

                return ['ok' => true, 'message' => '权益变更站内消息已重发。', 'sent' => 1, 'message_id' => (int) ($message['id'] ?? 0)];
            }

            return ['ok' => false, 'message' => '权益处理记录不存在。'];
        }

        foreach ((array) ($data['activity_participation_logs'] ?? []) as $log) {
            if ((int) ($log['id'] ?? 0) !== $referenceId) {
                continue;
            }
            if ((string) ($log['status'] ?? '') !== 'success') {
                return ['ok' => false, 'message' => '只有成功的活动领奖记录可以重发。'];
            }
            $rewardText = $this->activityRewardText((string) ($log['reward_type'] ?? 'none'), (int) ($log['coin_amount'] ?? 0), (int) ($log['bonus_coin_amount'] ?? 0), (int) ($log['vip_days'] ?? 0));
            $message = $this->appendUserInAppMessageFromTemplate($data, (int) ($log['user_id'] ?? 0), 'activity_reward_notice', [
                'activity_name' => (string) ($log['activity_name'] ?? '活动'),
                'message' => (string) ($log['message'] ?? '活动奖励已发放。'),
                'reward_type' => (string) ($log['reward_type'] ?? 'none'),
                'reward_text' => $rewardText,
            ], $sender + [
                'source' => 'activity_resend',
                'reference_type' => 'activity_log',
                'reference_id' => (int) ($log['id'] ?? 0),
                'priority' => 'normal',
                'title' => '活动奖励：' . (string) ($log['activity_name'] ?? '活动'),
                'body' => trim((string) ($log['message'] ?? '活动奖励已发放。') . ' 奖励：' . $rewardText),
            ]);
            if ($message === null) {
                return ['ok' => false, 'message' => '活动记录接收用户不存在或模板内容为空。'];
            }
            $this->store->save($data);

            return ['ok' => true, 'message' => '活动奖励站内消息已重发。', 'sent' => 1, 'message_id' => (int) ($message['id'] ?? 0)];
        }

        return ['ok' => false, 'message' => '活动领奖记录不存在。'];
    }

    public function userInAppMessages(array $payload = [], ?int $userId = null): array
    {
        $data = $this->store->load();
        $userId = max(0, (int) ($userId ?? $this->currentUserId()));
        $status = (string) ($payload['status'] ?? 'active');
        $items = array_values(array_filter((array) ($data['in_app_messages'] ?? []), static function (array $item) use ($userId, $status): bool {
            if ((string) ($item['recipient_type'] ?? '') !== 'user' || (int) ($item['user_id'] ?? 0) !== $userId) {
                return false;
            }
            if ($status === 'all') {
                return true;
            }
            if ($status === 'unread') {
                return (string) ($item['status'] ?? 'unread') === 'unread';
            }

            return (string) ($item['status'] ?? 'unread') !== 'archived';
        }));
        usort($items, static fn (array $a, array $b): int => strcmp((string) ($b['created_at'] ?? ''), (string) ($a['created_at'] ?? '')));
        $limit = max(1, min(100, (int) ($payload['limit'] ?? 50)));

        return [
            'ok' => true,
            'unread_count' => count(array_filter($items, static fn (array $item): bool => (string) ($item['status'] ?? 'unread') === 'unread')),
            'messages' => array_slice($items, 0, $limit),
        ];
    }

    public function markUserInAppMessagesRead(array $payload = [], ?int $userId = null): array
    {
        $data = $this->store->load();
        $userId = max(0, (int) ($userId ?? $this->currentUserId()));
        $rawIds = $payload['ids'] ?? $payload['message_ids'] ?? [];
        if (!is_array($rawIds)) {
            $rawIds = preg_split('/[\s,，|]+/u', (string) $rawIds) ?: [];
        }
        $ids = array_values(array_unique(array_filter(array_map('intval', $rawIds), static fn (int $id): bool => $id > 0)));
        $markAll = !empty($payload['all']) || empty($ids);
        $now = date('Y-m-d H:i:s');
        $updated = 0;
        $data['in_app_messages'] = array_values((array) ($data['in_app_messages'] ?? []));
        foreach ($data['in_app_messages'] as &$message) {
            if ((string) ($message['recipient_type'] ?? '') !== 'user' || (int) ($message['user_id'] ?? 0) !== $userId) {
                continue;
            }
            if (!$markAll && !in_array((int) ($message['id'] ?? 0), $ids, true)) {
                continue;
            }
            if ((string) ($message['status'] ?? 'unread') === 'read') {
                continue;
            }
            $message['status'] = 'read';
            $message['read_at'] = $now;
            $message['updated_at'] = $now;
            $updated++;
        }
        unset($message);
        if ($updated > 0) {
            $this->store->save($data);
        }

        return ['ok' => true, 'message' => '站内消息已标记已读。', 'updated' => $updated];
    }

    public function archiveUserInAppMessages(array $payload = [], ?int $userId = null): array
    {
        $data = $this->store->load();
        $userId = max(0, (int) ($userId ?? $this->currentUserId()));
        $ids = $this->messageIdsFromPayload($payload);
        $markAll = !empty($payload['all']);
        if (!$markAll && empty($ids)) {
            return ['ok' => false, 'message' => '请选择要归档的站内消息。'];
        }

        $now = date('Y-m-d H:i:s');
        $updated = 0;
        $data['in_app_messages'] = array_values((array) ($data['in_app_messages'] ?? []));
        foreach ($data['in_app_messages'] as &$message) {
            if ((string) ($message['recipient_type'] ?? '') !== 'user' || (int) ($message['user_id'] ?? 0) !== $userId) {
                continue;
            }
            if (!$markAll && !in_array((int) ($message['id'] ?? 0), $ids, true)) {
                continue;
            }
            if ((string) ($message['status'] ?? 'unread') === 'archived') {
                continue;
            }
            $message['status'] = 'archived';
            $message['updated_at'] = $now;
            if ((string) ($message['read_at'] ?? '') === '') {
                $message['read_at'] = $now;
            }
            $updated++;
        }
        unset($message);
        if ($updated > 0) {
            $this->store->save($data);
        }

        return ['ok' => true, 'message' => '站内消息已归档。', 'updated' => $updated];
    }

    public function deleteUserInAppMessages(array $payload = [], ?int $userId = null): array
    {
        $data = $this->store->load();
        $userId = max(0, (int) ($userId ?? $this->currentUserId()));
        $ids = $this->messageIdsFromPayload($payload);
        $deleteAll = !empty($payload['all']);
        if (!$deleteAll && empty($ids)) {
            return ['ok' => false, 'message' => '请选择要删除的站内消息。'];
        }

        $deleted = 0;
        $data['in_app_messages'] = array_values(array_filter((array) ($data['in_app_messages'] ?? []), static function (array $message) use ($userId, $ids, $deleteAll, &$deleted): bool {
            if ((string) ($message['recipient_type'] ?? '') !== 'user' || (int) ($message['user_id'] ?? 0) !== $userId) {
                return true;
            }
            if (!$deleteAll && !in_array((int) ($message['id'] ?? 0), $ids, true)) {
                return true;
            }
            $deleted++;

            return false;
        }));
        if ($deleted > 0) {
            $this->store->save($data);
        }

        return ['ok' => true, 'message' => '站内消息已删除。', 'deleted' => $deleted];
    }

    private function messageIdsFromPayload(array $payload): array
    {
        $rawIds = $payload['ids'] ?? $payload['message_ids'] ?? $payload['message_id'] ?? [];
        if (!is_array($rawIds)) {
            $rawIds = preg_split('/[\s,，|]+/u', (string) $rawIds) ?: [];
        }

        return array_values(array_unique(array_filter(array_map('intval', $rawIds), static fn (int $id): bool => $id > 0)));
    }

    private function messageTemplateByIdOrKey(array $data, int $templateId = 0, string $templateKey = ''): array
    {
        $templateKey = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim($templateKey)) ?: '';
        foreach ((array) ($data['message_templates'] ?? []) as $template) {
            if (!is_array($template) || (string) ($template['status'] ?? 'active') !== 'active') {
                continue;
            }
            if ($templateId > 0 && (int) ($template['id'] ?? 0) === $templateId) {
                return $template;
            }
            if ($templateKey !== '' && (string) ($template['template_key'] ?? '') === $templateKey) {
                return $template;
            }
        }

        return [];
    }

    private function messageVariablesFromText(string $text): array
    {
        $variables = [];
        foreach (preg_split('/[\r\n]+/', $text) ?: [] as $line) {
            $line = trim((string) $line);
            if ($line === '' || !str_contains($line, '=')) {
                continue;
            }
            [$key, $value] = array_map('trim', explode('=', $line, 2));
            $key = preg_replace('/[^a-zA-Z0-9_-]+/', '', $key) ?: '';
            if ($key !== '') {
                $variables[$key] = $this->limitText($value, 500);
            }
        }

        return $variables;
    }

    private function renderGeneralMessageTemplate(array $template, array $variables): array
    {
        $replace = [];
        foreach ($variables as $key => $value) {
            $replace['{' . $key . '}'] = (string) $value;
            $replace['{{' . $key . '}}'] = (string) $value;
        }

        return [
            'title' => $this->limitText(strtr((string) ($template['title_template'] ?? ''), $replace), 160),
            'body' => $this->limitText(strtr((string) ($template['body_template'] ?? ''), $replace), 1200),
        ];
    }

    private function inAppRecipientsFromPayload(array $payload, array $data): array
    {
        $type = (string) ($payload['receiver_type'] ?? 'user');
        $receiverId = max(0, (int) ($payload['receiver_id'] ?? 0));
        $recipients = [];
        if ($type === 'user') {
            foreach ((array) ($data['users'] ?? []) as $user) {
                if ($receiverId > 0 && (int) ($user['id'] ?? 0) !== $receiverId) {
                    continue;
                }
                if ($receiverId <= 0) {
                    break;
                }
                $recipients[] = [
                    'recipient_type' => 'user',
                    'user_id' => (int) ($user['id'] ?? 0),
                    'recipient_name' => (string) ($user['nickname'] ?? ('用户' . (int) ($user['id'] ?? 0))),
                    'recipient_contact' => (string) ($user['phone'] ?? ''),
                ];
            }
        } elseif ($type === 'admin') {
            foreach ((array) ($data['admins'] ?? []) as $admin) {
                if ($receiverId > 0 && (int) ($admin['id'] ?? 0) !== $receiverId) {
                    continue;
                }
                if ($receiverId <= 0) {
                    break;
                }
                $recipients[] = $this->adminInAppRecipient($admin);
            }
        } elseif ($type === 'all_admins') {
            foreach ((array) ($data['admins'] ?? []) as $admin) {
                if ((string) ($admin['status'] ?? 'active') === 'active') {
                    $recipients[] = $this->adminInAppRecipient($admin);
                }
            }
        } elseif ($type === 'role') {
            $role = (string) ($payload['receiver_role'] ?? '');
            foreach ((array) ($data['admins'] ?? []) as $admin) {
                if ((string) ($admin['status'] ?? 'active') === 'active' && (string) ($admin['role'] ?? '') === $role) {
                    $recipients[] = $this->adminInAppRecipient($admin);
                }
            }
        }

        $dedup = [];
        $unique = [];
        foreach ($recipients as $recipient) {
            $key = (string) ($recipient['recipient_type'] ?? 'user') . ':' . (int) ($recipient['user_id'] ?? $recipient['admin_id'] ?? 0);
            if (isset($dedup[$key])) {
                continue;
            }
            $dedup[$key] = true;
            $unique[] = $recipient;
        }

        return array_slice($unique, 0, 500);
    }

    private function adminInAppRecipient(array $admin): array
    {
        return [
            'recipient_type' => 'admin',
            'admin_id' => (int) ($admin['id'] ?? 0),
            'agent_id' => (int) ($admin['agent_id'] ?? 0),
            'recipient_name' => (string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? ('管理员' . (int) ($admin['id'] ?? 0)))),
            'recipient_contact' => (string) (($admin['email'] ?? '') ?: ($admin['phone'] ?? '')),
        ];
    }

    private function userInAppRecipient(array $user): array
    {
        return [
            'recipient_type' => 'user',
            'user_id' => (int) ($user['id'] ?? 0),
            'recipient_name' => (string) (($user['nickname'] ?? '') ?: ('用户' . (int) ($user['id'] ?? 0))),
            'recipient_contact' => (string) ($user['phone'] ?? ''),
        ];
    }

    private function appendUserInAppMessageFromTemplate(array &$data, int $userId, string $templateKey, array $variables, array $options = []): ?array
    {
        if ($userId <= 0) {
            return null;
        }
        $user = null;
        foreach ((array) ($data['users'] ?? []) as $candidate) {
            if ((int) ($candidate['id'] ?? 0) === $userId) {
                $user = $candidate;
                break;
            }
        }
        if (!is_array($user)) {
            return null;
        }

        $template = $this->messageTemplateByIdOrKey($data, 0, $templateKey);
        if (!empty($template) && !in_array((string) ($template['channel'] ?? 'in_app'), ['in_app', 'system'], true)) {
            $template = [];
        }
        $rendered = !empty($template) ? $this->renderGeneralMessageTemplate($template, $variables) : ['title' => '', 'body' => ''];
        $fallbackTitle = trim((string) ($options['title'] ?? ''));
        $fallbackBody = trim((string) ($options['body'] ?? ''));
        $title = $this->limitText(trim((string) (($rendered['title'] ?? '') ?: $fallbackTitle)), 160);
        $body = $this->limitText(trim((string) (($rendered['body'] ?? '') ?: $fallbackBody)), 1200);
        if ($title === '') {
            $title = '站内消息';
        }
        if ($body === '') {
            return null;
        }

        $recipient = $this->userInAppRecipient($user);

        return $this->appendInAppMessage($data, [
            'recipient_type' => 'user',
            'user_id' => (int) ($recipient['user_id'] ?? 0),
            'recipient_name' => (string) ($recipient['recipient_name'] ?? ''),
            'recipient_contact' => (string) ($recipient['recipient_contact'] ?? ''),
            'scenario' => (string) ($template['scenario'] ?? $options['scenario'] ?? 'system_notice'),
            'template_key' => (string) ($template['template_key'] ?? $templateKey),
            'source' => (string) ($options['source'] ?? 'system'),
            'reference_type' => (string) ($options['reference_type'] ?? ''),
            'reference_id' => (int) ($options['reference_id'] ?? 0),
            'title' => $title,
            'body' => $body,
            'priority' => (string) ($options['priority'] ?? 'normal'),
            'sender_admin_id' => (int) ($options['sender_admin_id'] ?? 0),
            'sender_admin_name' => (string) ($options['sender_admin_name'] ?? ''),
            'created_at' => (string) ($options['created_at'] ?? ''),
            'updated_at' => (string) ($options['updated_at'] ?? ''),
        ]);
    }

    private function rightsRepairActionLabel(string $action): string
    {
        return [
            'grant_coin' => '补发 K币',
            'deduct_coin' => '扣减 K币',
            'grant_vip' => '补发 VIP',
            'revoke_vip' => '撤销 VIP',
            'grant_content' => '补发内容权益',
            'revoke_content' => '撤销内容权益',
        ][$action] ?? '权益调整';
    }

    private function contentTitleFromData(array $data, string $contentType, int $dramaId = 0, int $novelId = 0): string
    {
        if ($contentType === 'novel') {
            foreach ((array) ($data['novels'] ?? []) as $novel) {
                if ((int) ($novel['id'] ?? 0) === $novelId) {
                    return (string) (($novel['title'] ?? '') ?: ('小说#' . $novelId));
                }
            }

            return $novelId > 0 ? ('小说#' . $novelId) : '小说权益';
        }

        foreach ((array) ($data['dramas'] ?? []) as $drama) {
            if ((int) ($drama['id'] ?? 0) === $dramaId) {
                return (string) (($drama['title'] ?? '') ?: ('短剧#' . $dramaId));
            }
        }

        return $dramaId > 0 ? ('短剧#' . $dramaId) : '短剧权益';
    }

    private function orderRightsLabel(array $order): string
    {
        return match ((string) ($order['type'] ?? '')) {
            'membership' => 'VIP 权益',
            'drama_unlock' => '全集权益',
            'episode_unlock' => '单集权益',
            'novel_unlock' => '整本小说权益',
            'novel_chapter_unlock' => '章节权益',
            default => '对应权益',
        };
    }

    private function activityRewardText(string $rewardType, int $coinAmount = 0, int $bonusCoinAmount = 0, int $vipDays = 0): string
    {
        $totalCoins = max(0, $coinAmount) + max(0, $bonusCoinAmount);
        $parts = [];
        if ($totalCoins > 0) {
            $parts[] = $totalCoins . ' K币';
        }
        if ($vipDays > 0) {
            $parts[] = $vipDays . ' 天 VIP';
        }
        if (!empty($parts)) {
            return implode(' + ', $parts);
        }

        return match ($rewardType) {
            'redeem_code' => '兑换码奖励',
            'none' => '参与资格',
            default => '活动奖励',
        };
    }

    private function appendInAppMessage(array &$data, array $message): array
    {
        $data['in_app_messages'] = array_values((array) ($data['in_app_messages'] ?? []));
        $nextId = empty($data['in_app_messages']) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $data['in_app_messages'])) + 1);
        $now = date('Y-m-d H:i:s');
        $row = [
            'id' => $nextId,
            'recipient_type' => in_array((string) ($message['recipient_type'] ?? 'user'), ['user', 'admin'], true) ? (string) $message['recipient_type'] : 'user',
            'user_id' => max(0, (int) ($message['user_id'] ?? 0)),
            'admin_id' => max(0, (int) ($message['admin_id'] ?? 0)),
            'agent_id' => max(0, (int) ($message['agent_id'] ?? 0)),
            'recipient_name' => $this->limitText(trim((string) ($message['recipient_name'] ?? '')), 80),
            'recipient_contact' => $this->limitText(trim((string) ($message['recipient_contact'] ?? '')), 120),
            'scenario' => $this->limitText(trim((string) ($message['scenario'] ?? 'system_notice')), 60),
            'template_key' => preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($message['template_key'] ?? ''))),
            'channel' => 'in_app',
            'source' => $this->limitText(trim((string) ($message['source'] ?? 'manual')), 60),
            'reference_type' => $this->limitText(trim((string) ($message['reference_type'] ?? '')), 60),
            'reference_id' => max(0, (int) ($message['reference_id'] ?? 0)),
            'title' => $this->limitText(trim((string) ($message['title'] ?? '站内消息')), 160),
            'body' => $this->limitText(trim((string) ($message['body'] ?? '')), 1200),
            'priority' => in_array((string) ($message['priority'] ?? 'normal'), ['low', 'normal', 'high', 'urgent'], true) ? (string) $message['priority'] : 'normal',
            'status' => 'unread',
            'read_at' => '',
            'sender_admin_id' => max(0, (int) ($message['sender_admin_id'] ?? 0)),
            'sender_admin_name' => $this->limitText(trim((string) ($message['sender_admin_name'] ?? '')), 80),
            'created_at' => (string) (($message['created_at'] ?? '') ?: $now),
            'updated_at' => (string) (($message['updated_at'] ?? '') ?: $now),
        ];
        $data['in_app_messages'][] = $row;
        $data['in_app_messages'] = array_slice(array_values($data['in_app_messages']), -5000);

        return $row;
    }

    private function notificationRecordDashboard(array $data, array $scopedData, array $adminScope): array
    {
        $rows = [];
        $isSuperAdmin = (string) ($adminScope['role'] ?? 'super_admin') === 'super_admin';
        if ($isSuperAdmin) {
            foreach ((array) ($data['sms_codes'] ?? []) as $log) {
                $rows[] = $this->notificationRecordRow([
                    'source' => 'sms_code',
                    'source_label' => '短信验证码',
                    'channel' => 'sms',
                    'title' => '验证码短信',
                    'receiver' => (string) ($log['phone'] ?? ''),
                    'content' => (string) (($log['message'] ?? '') ?: ('模板 ' . (string) ($log['template_id'] ?? ''))),
                    'status' => (string) ($log['send_status'] ?? 'mocked'),
                    'reference' => 'SMS#' . (int) ($log['id'] ?? 0),
                    'created_at' => (string) ($log['created_at'] ?? ''),
                ]);
            }
            foreach ((array) ($data['email_delivery_logs'] ?? []) as $log) {
                $rows[] = $this->notificationRecordRow([
                    'source' => 'email_delivery',
                    'source_label' => '邮件发送',
                    'channel' => 'email',
                    'title' => (string) ($log['subject'] ?? '邮件通知'),
                    'receiver' => (string) ($log['to_email'] ?? ''),
                    'content' => (string) ($log['message'] ?? ''),
                    'status' => (string) ($log['status'] ?? 'success'),
                    'reference' => 'MAIL#' . (int) ($log['id'] ?? 0),
                    'created_at' => (string) ($log['created_at'] ?? ''),
                ]);
            }
            foreach ((array) ($data['config_change_notification_logs'] ?? []) as $log) {
                $rows[] = $this->notificationRecordRow([
                    'source' => 'config_change',
                    'source_label' => '配置审批',
                    'channel' => (string) ($log['channel'] ?? 'system'),
                    'title' => (string) ($log['title'] ?? '配置审批通知'),
                    'receiver' => trim((string) ($log['receiver_name'] ?? '') . ' ' . (string) ($log['receiver_contact'] ?? '')),
                    'content' => (string) ($log['message'] ?? ''),
                    'status' => (string) ($log['status'] ?? 'success'),
                    'reference' => '审批#' . (int) ($log['request_id'] ?? 0),
                    'created_at' => (string) ($log['created_at'] ?? ''),
                ]);
            }
            foreach ((array) ($data['in_app_messages'] ?? []) as $log) {
                $rows[] = $this->notificationRecordRow([
                    'source' => 'in_app_message',
                    'source_label' => '站内消息',
                    'channel' => (string) ($log['channel'] ?? 'in_app'),
                    'title' => (string) ($log['title'] ?? '站内消息'),
                    'receiver' => trim((string) ($log['recipient_name'] ?? '') . ' ' . (string) ($log['recipient_contact'] ?? '')),
                    'content' => (string) ($log['body'] ?? ''),
                    'status' => (string) ($log['status'] ?? 'unread'),
                    'reference' => 'MSG#' . (int) ($log['id'] ?? 0),
                    'created_at' => (string) ($log['created_at'] ?? ''),
                ]);
            }
        }

        foreach ((array) ($scopedData['operation_alert_notification_logs'] ?? []) as $log) {
            $rows[] = $this->notificationRecordRow([
                'source' => 'operation_alert',
                'source_label' => '投放预警',
                'channel' => (string) ($log['channel'] ?? 'webhook'),
                'title' => '投放预警外发',
                'receiver' => trim((string) ($log['receiver_name'] ?? '') . ' ' . (string) (($log['receiver_contact'] ?? '') ?: ($log['endpoint'] ?? ''))),
                'content' => (string) ($log['message'] ?? ''),
                'status' => (string) ($log['status'] ?? 'pending'),
                'reference' => '预警#' . (int) ($log['alert_id'] ?? 0),
                'created_at' => (string) (($log['created_at'] ?? '') ?: ($log['last_attempt_at'] ?? '')),
            ]);
        }

        foreach ((array) ($scopedData['agent_settlement_notification_logs'] ?? []) as $log) {
            $rows[] = $this->notificationRecordRow([
                'source' => 'agent_settlement',
                'source_label' => '代理结算',
                'channel' => (string) ($log['channel'] ?? 'in_app'),
                'title' => (string) ($log['title'] ?? '代理结算通知'),
                'receiver' => trim((string) ($log['receiver_name'] ?? '') . ' ' . (string) ($log['receiver_contact'] ?? '')),
                'content' => (string) ($log['message'] ?? ''),
                'status' => (string) ($log['status'] ?? 'success'),
                'reference' => '结算#' . (int) ($log['settlement_id'] ?? 0),
                'created_at' => (string) ($log['created_at'] ?? ''),
            ]);
        }

        usort($rows, static fn (array $a, array $b): int => strcmp((string) ($b['created_at'] ?? ''), (string) ($a['created_at'] ?? '')));
        $rows = array_slice($rows, 0, 300);
        $summary = ['total' => count($rows), 'success' => 0, 'failed' => 0, 'skipped' => 0, 'pending' => 0, 'channels' => 0, 'sources' => 0];
        $channels = [];
        $sources = [];
        foreach ($rows as $row) {
            $group = (string) ($row['status_group'] ?? 'pending');
            $summary[$group] = (int) ($summary[$group] ?? 0) + 1;
            $channel = (string) ($row['channel'] ?? 'system');
            $source = (string) ($row['source'] ?? 'system');
            $channels[$channel] ??= ['channel' => $channel, 'label' => (string) ($row['channel_label'] ?? $channel), 'total' => 0, 'success' => 0, 'failed' => 0, 'skipped' => 0, 'pending' => 0];
            $channels[$channel]['total']++;
            $channels[$channel][$group] = (int) ($channels[$channel][$group] ?? 0) + 1;
            $sources[$source] ??= ['source' => $source, 'label' => (string) ($row['source_label'] ?? $source), 'total' => 0, 'success' => 0, 'failed' => 0, 'skipped' => 0, 'pending' => 0];
            $sources[$source]['total']++;
            $sources[$source][$group] = (int) ($sources[$source][$group] ?? 0) + 1;
        }
        $summary['channels'] = count($channels);
        $summary['sources'] = count($sources);
        $sortRows = static fn (array $a, array $b): int => (int) ($b['total'] ?? 0) <=> (int) ($a['total'] ?? 0);
        $channelRows = array_values($channels);
        $sourceRows = array_values($sources);
        usort($channelRows, $sortRows);
        usort($sourceRows, $sortRows);

        return [
            'summary' => $summary,
            'rows' => $rows,
            'channel_rows' => $channelRows,
            'source_rows' => $sourceRows,
        ];
    }

    private function notificationRecordRow(array $row): array
    {
        $channelLabels = ['system' => '站内', 'sms' => '短信', 'email' => '邮件', 'webhook' => 'Webhook', 'wechat_work' => '企业微信', 'in_app' => '站内'];
        $status = strtolower(trim((string) ($row['status'] ?? 'pending')));
        $group = match (true) {
            in_array($status, ['success', 'sent', 'mocked', 'delivered', 'used'], true) => 'success',
            in_array($status, ['failed', 'error'], true) => 'failed',
            in_array($status, ['skipped', 'paused'], true) => 'skipped',
            default => 'pending',
        };
        $statusLabel = match ($group) {
            'success' => '成功',
            'failed' => '失败',
            'skipped' => '跳过',
            default => '待处理',
        };
        $channel = (string) ($row['channel'] ?? 'system');

        return [
            'source' => (string) ($row['source'] ?? ''),
            'source_label' => (string) ($row['source_label'] ?? ''),
            'channel' => $channel,
            'channel_label' => $channelLabels[$channel] ?? $channel,
            'title' => $this->limitText(trim((string) ($row['title'] ?? '通知记录')), 120),
            'receiver' => $this->limitText(trim((string) ($row['receiver'] ?? '')), 160),
            'content' => $this->limitText(trim((string) ($row['content'] ?? '')), 240),
            'status' => $status,
            'status_group' => $group,
            'status_label' => $statusLabel,
            'reference' => $this->limitText(trim((string) ($row['reference'] ?? '')), 80),
            'created_at' => (string) ($row['created_at'] ?? ''),
        ];
    }

    private function identifierListFromPayload(mixed $value, int $limit = 24, int $maxLength = 40): array
    {
        $items = is_array($value) ? $value : preg_split('/[\s,，|]+/u', (string) $value);
        $result = [];
        foreach ((array) $items as $item) {
            $text = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) $item)) ?: '';
            $text = $this->limitText($text, $maxLength);
            if ($text === '' || in_array($text, $result, true)) {
                continue;
            }
            $result[] = $text;
            if (count($result) >= $limit) {
                break;
            }
        }

        return $result;
    }

    private function sendTestEmail(array $payload): array
    {
        $data = $this->store->load();
        $data['email_delivery_logs'] ??= [];
        $config = $this->emailConfig($data);
        $toEmail = trim((string) ($payload['test_email'] ?? ''));
        if (!filter_var($toEmail, FILTER_VALIDATE_EMAIL)) {
            return ['ok' => false, 'message' => '请输入正确的测试邮箱。'];
        }
        $now = date('Y-m-d H:i:s');
        $provider = (string) ($config['provider'] ?? 'mock');
        $status = (string) ($config['status'] ?? 'paused') === 'active' ? 'success' : 'skipped';
        $message = $status === 'success'
            ? ($provider === 'mock' ? '模拟邮件已记录。' : '邮件已进入发送队列。')
            : '邮件通道已停用，仅记录测试请求。';
        $subject = (string) ($config['test_subject'] ?? '精秀短剧邮件测试');
        $body = strtr((string) ($config['test_template'] ?? '这是一封系统测试邮件，发送时间：{time}。'), [
            '{time}' => $now,
            '{site}' => (string) ($data['site_config']['site_name'] ?? '精秀短剧'),
        ]);
        $delivery = $status === 'skipped'
            ? ['ok' => false, 'status' => 'skipped', 'message' => $message, 'provider' => $provider]
            : $this->deliverEmailMessage($config, $toEmail, $subject, $body);
        $this->appendEmailDeliveryLog($data, $toEmail, $subject, $body, $delivery, $now);
        $this->store->save($data);

        return [
            'ok' => !empty($delivery['ok']),
            'message' => (string) ($delivery['message'] ?? $message),
            'provider' => $provider,
            'to_email' => $toEmail,
        ];
    }

    private function appendEmailDeliveryLog(array &$data, string $toEmail, string $subject, string $body, array $delivery, string $now): void
    {
        $data['email_delivery_logs'] = array_values((array) ($data['email_delivery_logs'] ?? []));
        $nextId = empty($data['email_delivery_logs']) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $data['email_delivery_logs'])) + 1);
        $status = (string) ($delivery['status'] ?? (!empty($delivery['ok']) ? 'success' : 'failed'));
        $data['email_delivery_logs'][] = [
            'id' => $nextId,
            'to_email' => $toEmail,
            'subject' => $this->limitText($subject, 120),
            'body' => $this->limitText($body, 1000),
            'provider' => (string) ($delivery['provider'] ?? 'mock'),
            'status' => in_array($status, ['success', 'failed', 'skipped'], true) ? $status : 'failed',
            'message' => $this->limitText((string) ($delivery['message'] ?? ''), 200),
            'response_payload' => (array) ($delivery['response_payload'] ?? []),
            'created_at' => $now,
        ];
        $data['email_delivery_logs'] = array_slice(array_values($data['email_delivery_logs']), -500);
    }

    private function deliverEmailMessage(array $config, string $toEmail, string $subject, string $body): array
    {
        $provider = (string) ($config['provider'] ?? 'mock');
        if ($provider === 'mock') {
            return [
                'ok' => true,
                'status' => 'success',
                'provider' => $provider,
                'message' => '模拟邮件已记录。',
                'response_payload' => ['mode' => 'mock'],
            ];
        }

        $host = trim((string) ($config['host'] ?? ''));
        if (in_array($provider, ['smtp', 'custom'], true) || $host !== '') {
            return $this->sendSmtpEmail($config, $toEmail, $subject, $body);
        }

        return [
            'ok' => true,
            'status' => 'success',
            'provider' => $provider,
            'message' => '邮件已进入' . $provider . '发送队列。',
            'response_payload' => ['queued' => true, 'provider' => $provider],
        ];
    }

    private function sendSmtpEmail(array $config, string $toEmail, string $subject, string $body): array
    {
        $host = trim((string) ($config['host'] ?? ''));
        $provider = (string) ($config['provider'] ?? 'smtp');
        if ($host === '') {
            return ['ok' => false, 'status' => 'failed', 'provider' => $provider, 'message' => 'SMTP Host 未配置。'];
        }
        if (str_starts_with($host, 'mock://smtp-success')) {
            return [
                'ok' => true,
                'status' => 'success',
                'provider' => $provider,
                'message' => '模拟 SMTP 发送成功。',
                'response_payload' => ['mode' => 'smtp', 'mock' => true, 'host' => $host],
            ];
        }
        if (str_starts_with($host, 'mock://smtp-fail')) {
            return [
                'ok' => false,
                'status' => 'failed',
                'provider' => $provider,
                'message' => '模拟 SMTP 发送失败。',
                'response_payload' => ['mode' => 'smtp', 'mock' => true, 'host' => $host],
            ];
        }
        if (!function_exists('stream_socket_client')) {
            return ['ok' => false, 'status' => 'failed', 'provider' => $provider, 'message' => '当前 PHP 环境不支持 SMTP Socket。'];
        }

        $port = max(1, min(65535, (int) ($config['port'] ?? 465)));
        $secure = (string) ($config['secure'] ?? 'tls');
        $fromEmail = trim((string) ($config['from_email'] ?? 'noreply@example.com'));
        $fromName = trim((string) ($config['from_name'] ?? '精秀短剧'));
        $username = trim((string) ($config['username'] ?? ''));
        $password = (string) ($config['password'] ?? '');
        $remote = ($secure === 'ssl' ? 'ssl://' : 'tcp://') . $host . ':' . $port;
        $errno = 0;
        $errstr = '';
        $socket = @stream_socket_client($remote, $errno, $errstr, 8, STREAM_CLIENT_CONNECT);
        if (!is_resource($socket)) {
            return [
                'ok' => false,
                'status' => 'failed',
                'provider' => $provider,
                'message' => 'SMTP 连接失败：' . ($errstr !== '' ? $errstr : ('错误码 ' . $errno)),
                'response_payload' => ['host' => $host, 'port' => $port, 'secure' => $secure],
            ];
        }
        stream_set_timeout($socket, 8);

        $transcript = [];
        $read = static function () use ($socket, &$transcript): array {
            $lines = [];
            while (($line = fgets($socket, 512)) !== false) {
                $line = rtrim($line, "\r\n");
                $lines[] = $line;
                if (strlen($line) < 4 || substr($line, 3, 1) === ' ') {
                    break;
                }
            }
            $transcript[] = implode("\n", $lines);
            $code = isset($lines[0]) ? (int) substr($lines[0], 0, 3) : 0;

            return ['code' => $code, 'lines' => $lines];
        };
        $send = static function (string $command, array $okCodes) use ($socket, $read, &$transcript): array {
            $transcript[] = preg_match('/^(AUTH|PASS)/i', $command) === 1 ? '[sensitive command hidden]' : $command;
            fwrite($socket, $command . "\r\n");
            $response = $read();
            $response['ok'] = in_array((int) ($response['code'] ?? 0), $okCodes, true);

            return $response;
        };
        $fail = function (string $message) use (&$transcript, $socket, $provider): array {
            if (is_resource($socket)) {
                @fwrite($socket, "QUIT\r\n");
                @fclose($socket);
            }

            return [
                'ok' => false,
                'status' => 'failed',
                'provider' => $provider,
                'message' => $message,
                'response_payload' => ['smtp_transcript' => array_slice($transcript, -12)],
            ];
        };

        $banner = $read();
        if (($banner['code'] ?? 0) !== 220) {
            return $fail('SMTP 服务响应异常。');
        }
        $ehloHost = (string) ($_SERVER['SERVER_NAME'] ?? 'localhost');
        $ehlo = $send('EHLO ' . $ehloHost, [250]);
        if (empty($ehlo['ok'])) {
            $helo = $send('HELO ' . $ehloHost, [250]);
            if (empty($helo['ok'])) {
                return $fail('SMTP HELO/EHLO 失败。');
            }
        }
        if ($secure === 'tls') {
            $startTls = $send('STARTTLS', [220]);
            if (empty($startTls['ok'])) {
                return $fail('SMTP STARTTLS 失败。');
            }
            if (!@stream_socket_enable_crypto($socket, true, STREAM_CRYPTO_METHOD_TLS_CLIENT)) {
                return $fail('SMTP TLS 握手失败。');
            }
            $ehlo = $send('EHLO ' . $ehloHost, [250]);
            if (empty($ehlo['ok'])) {
                return $fail('SMTP TLS 后 EHLO 失败。');
            }
        }
        if ($username !== '') {
            if (empty($send('AUTH LOGIN', [334])['ok'])) {
                return $fail('SMTP AUTH LOGIN 失败。');
            }
            if (empty($send(base64_encode($username), [334])['ok'])) {
                return $fail('SMTP 用户名认证失败。');
            }
            if (empty($send(base64_encode($password), [235])['ok'])) {
                return $fail('SMTP 密码认证失败。');
            }
        }
        if (empty($send('MAIL FROM:<' . $fromEmail . '>', [250])['ok'])) {
            return $fail('SMTP 发件人被拒绝。');
        }
        if (empty($send('RCPT TO:<' . $toEmail . '>', [250, 251])['ok'])) {
            return $fail('SMTP 收件人被拒绝。');
        }
        if (empty($send('DATA', [354])['ok'])) {
            return $fail('SMTP DATA 被拒绝。');
        }

        $encodedSubject = '=?UTF-8?B?' . base64_encode($subject) . '?=';
        $encodedFromName = '=?UTF-8?B?' . base64_encode($fromName) . '?=';
        $headers = [
            'From: ' . $encodedFromName . ' <' . $fromEmail . '>',
            'To: <' . $toEmail . '>',
            'Subject: ' . $encodedSubject,
            'MIME-Version: 1.0',
            'Content-Type: text/plain; charset=UTF-8',
            'Content-Transfer-Encoding: 8bit',
        ];
        $data = implode("\r\n", $headers) . "\r\n\r\n" . preg_replace('/^\./m', '..', $body) . "\r\n.";
        fwrite($socket, $data . "\r\n");
        $response = $read();
        if (!in_array((int) ($response['code'] ?? 0), [250], true)) {
            return $fail('SMTP 正文发送失败。');
        }
        @fwrite($socket, "QUIT\r\n");
        @fclose($socket);

        return [
            'ok' => true,
            'status' => 'success',
            'provider' => $provider,
            'message' => 'SMTP 邮件发送成功。',
            'response_payload' => ['smtp_transcript' => array_slice($transcript, -12), 'host' => $host, 'port' => $port, 'secure' => $secure],
        ];
    }

    public function saveSystemConfigFragment(array $payload): array
    {
        $data = $this->store->load();
        $items = array_values((array) ($data['system_config_fragments'] ?? []));
        $fragmentId = max(0, (int) ($payload['fragment_id'] ?? $payload['id'] ?? 0));
        $key = preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim((string) ($payload['key'] ?? '')));
        if ($key === '') {
            return ['ok' => false, 'message' => '配置键不能为空。'];
        }
        foreach ($items as $item) {
            if ((int) ($item['id'] ?? 0) === $fragmentId) {
                continue;
            }
            if ((string) ($item['key'] ?? '') === $key) {
                return ['ok' => false, 'message' => '配置键已存在。'];
            }
        }

        $current = [];
        foreach ($items as $item) {
            if ((int) ($item['id'] ?? 0) === $fragmentId) {
                $current = $item;
                break;
            }
        }
        $type = (string) ($payload['type'] ?? ($current['type'] ?? 'text'));
        $type = in_array($type, ['text', 'json', 'url', 'secret'], true) ? $type : 'text';
        $status = (string) ($payload['status'] ?? ($current['status'] ?? 'active'));
        $status = in_array($status, ['active', 'paused'], true) ? $status : 'active';
        $value = trim((string) ($payload['value'] ?? ''));
        if ($value === '' && $fragmentId > 0 && !empty($current['sensitive'])) {
            $value = (string) ($current['value'] ?? '');
        }
        if ($type === 'json' && $value !== '') {
            json_decode($value, true);
            if (json_last_error() !== JSON_ERROR_NONE) {
                return ['ok' => false, 'message' => 'JSON 配置片段格式不正确。'];
            }
        }

        $admin = $this->currentAdmin();
        $now = date('Y-m-d H:i:s');
        $fragment = [
            'id' => $fragmentId > 0 ? $fragmentId : (empty($items) ? 1 : ((int) max(array_column($items, 'id')) + 1)),
            'key' => $this->limitText($key, 80),
            'name' => $this->limitText(trim((string) ($payload['name'] ?? '')) ?: $key, 80),
            'group' => $this->limitText(trim((string) ($payload['group'] ?? 'system')) ?: 'system', 40),
            'type' => $type,
            'value' => $this->limitText($value, 4000),
            'sensitive' => !empty($payload['sensitive']) || $type === 'secret',
            'status' => $status,
            'remark' => $this->limitText(trim((string) ($payload['remark'] ?? '')), 160),
            'updated_by' => $this->limitText((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员')), 60),
            'created_at' => (string) (($current['created_at'] ?? '') ?: $now),
            'updated_at' => $now,
        ];

        $replaced = false;
        foreach ($items as &$item) {
            if ((int) ($item['id'] ?? 0) !== (int) $fragment['id']) {
                continue;
            }
            $item = $fragment;
            $replaced = true;
            break;
        }
        unset($item);
        if (!$replaced) {
            $items[] = $fragment;
        }

        $data['system_config_fragments'] = $items;
        $this->store->save($data);

        return ['ok' => true, 'fragment' => $fragment, 'message' => '配置片段已保存。'];
    }

    public function createConfigChangeRequest(array $payload): array
    {
        $data = $this->store->load();
        $data['config_change_requests'] ??= [];
        $configType = (string) ($payload['change_config_type'] ?? $payload['config_type'] ?? 'base_config');
        if (!in_array($configType, ['base_config', 'notification_config', 'config_fragment', 'payment_config', 'app_config'], true)) {
            return ['ok' => false, 'message' => '不支持的配置变更类型。'];
        }
        $snapshot = $this->buildConfigChangeSnapshot($configType, $payload, $data);
        if (empty($snapshot['ok'])) {
            return ['ok' => false, 'message' => (string) ($snapshot['message'] ?? '配置变更内容无效。')];
        }

        return $this->createConfigChangeRequestFromSnapshot($configType, $snapshot, [
            'title' => $this->limitText(trim((string) ($payload['change_title'] ?? '')) ?: (string) $snapshot['title'], 120),
            'reason' => $this->limitText(trim((string) ($payload['change_reason'] ?? '')), 240),
        ]);
    }

    private function createConfigChangeRequestFromSnapshot(string $configType, array $snapshot, array $meta = []): array
    {
        $data = $this->store->load();
        $data['config_change_requests'] ??= [];
        $admin = $this->currentAdmin();
        $now = date('Y-m-d H:i:s');
        $requests = array_values((array) ($data['config_change_requests'] ?? []));
        $request = [
            'id' => empty($requests) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $requests)) + 1),
            'title' => $this->limitText(trim((string) ($meta['title'] ?? '')) ?: (string) ($snapshot['title'] ?? '配置变更'), 120),
            'config_type' => $configType,
            'target_key' => (string) ($snapshot['target_key'] ?? ''),
            'status' => 'pending',
            'reason' => $this->limitText(trim((string) ($meta['reason'] ?? '')), 240),
            'before_snapshot' => (array) ($snapshot['before_snapshot'] ?? []),
            'after_snapshot' => (array) ($snapshot['after_snapshot'] ?? []),
            'created_by_admin_id' => max(0, (int) ($admin['id'] ?? 0)),
            'created_by_admin_name' => $this->limitText((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员')), 60),
            'reviewed_by_admin_id' => 0,
            'reviewed_by_admin_name' => '',
            'review_note' => '',
            'created_at' => $now,
            'reviewed_at' => '',
            'applied_at' => '',
            'updated_at' => $now,
        ];
        $requests[] = $request;
        $data['config_change_requests'] = $requests;
        $this->appendConfigChangeNotificationLogs($data, $request, 'submitted');
        $this->store->save($data);

        return ['ok' => true, 'request' => $request, 'message' => '配置变更申请已提交。'];
    }

    public function reviewConfigChangeRequest(array $payload): array
    {
        $data = $this->store->load();
        if ((string) ($this->currentAdminScope($data)['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以审批配置变更。'];
        }
        $requestId = max(0, (int) ($payload['config_change_id'] ?? $payload['id'] ?? 0));
        $decision = (string) ($payload['decision'] ?? 'approve');
        if (!in_array($decision, ['approve', 'reject'], true)) {
            return ['ok' => false, 'message' => '审批动作无效。'];
        }
        $requests = array_values((array) ($data['config_change_requests'] ?? []));
        $index = null;
        foreach ($requests as $key => $request) {
            if ((int) ($request['id'] ?? 0) === $requestId) {
                $index = $key;
                break;
            }
        }
        if ($index === null) {
            return ['ok' => false, 'message' => '配置变更申请不存在。'];
        }
        if ((string) ($requests[$index]['status'] ?? 'pending') !== 'pending') {
            return ['ok' => false, 'message' => '该配置变更已处理。'];
        }
        $admin = $this->currentAdmin();
        $now = date('Y-m-d H:i:s');
        $requests[$index]['reviewed_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
        $requests[$index]['reviewed_by_admin_name'] = $this->limitText((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员')), 60);
        $requests[$index]['review_note'] = $this->limitText(trim((string) ($payload['review_note'] ?? '')), 240);
        $requests[$index]['reviewed_at'] = $now;
        $requests[$index]['updated_at'] = $now;
        if ($decision === 'reject') {
            $requests[$index]['status'] = 'rejected';
            $data['config_change_requests'] = $requests;
            $this->appendConfigChangeNotificationLogs($data, $requests[$index], 'rejected');
            $this->store->save($data);
            return ['ok' => true, 'message' => '配置变更已驳回。', 'request' => $requests[$index]];
        }

        $apply = $this->applyConfigChangeSnapshot($data, $requests[$index]);
        if (empty($apply['ok'])) {
            return ['ok' => false, 'message' => (string) ($apply['message'] ?? '配置变更发布失败。')];
        }
        $requests[$index]['status'] = 'applied';
        $requests[$index]['applied_at'] = $now;
        $requests[$index]['updated_at'] = $now;
        $data['config_change_requests'] = $requests;
        $this->appendConfigChangeNotificationLogs($data, $requests[$index], 'approved');
        $this->store->save($data);

        return ['ok' => true, 'message' => '配置变更已审批并发布。', 'request' => $requests[$index]];
    }

    public function rollbackConfigChangeRequest(array $payload): array
    {
        $data = $this->store->load();
        if ((string) ($this->currentAdminScope($data)['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以回滚配置变更。'];
        }
        $requestId = max(0, (int) ($payload['config_change_id'] ?? $payload['id'] ?? 0));
        $requests = array_values((array) ($data['config_change_requests'] ?? []));
        $index = null;
        foreach ($requests as $key => $request) {
            if ((int) ($request['id'] ?? 0) === $requestId) {
                $index = $key;
                break;
            }
        }
        if ($index === null) {
            return ['ok' => false, 'message' => '配置变更申请不存在。'];
        }
        if ((string) ($requests[$index]['status'] ?? '') !== 'applied') {
            return ['ok' => false, 'message' => '只有已发布的配置变更可以回滚。'];
        }

        $rollback = $this->rollbackConfigChangeSnapshot($data, $requests[$index]);
        if (empty($rollback['ok'])) {
            return ['ok' => false, 'message' => (string) ($rollback['message'] ?? '配置回滚失败。')];
        }

        $admin = $this->currentAdmin();
        $now = date('Y-m-d H:i:s');
        $requests[$index]['status'] = 'rolled_back';
        $requests[$index]['rolled_back_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
        $requests[$index]['rolled_back_by_admin_name'] = $this->limitText((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员')), 60);
        $requests[$index]['rollback_note'] = $this->limitText(trim((string) ($payload['rollback_note'] ?? '')), 240);
        $requests[$index]['rolled_back_at'] = $now;
        $requests[$index]['updated_at'] = $now;
        $data['config_change_requests'] = $requests;
        $this->appendConfigChangeNotificationLogs($data, $requests[$index], 'rolled_back');
        $this->store->save($data);

        return ['ok' => true, 'message' => '配置已回滚到发布前版本。', 'request' => $requests[$index]];
    }

    public function sendConfigChangeSlaReminder(array $payload): array
    {
        $data = $this->store->load();
        if ((string) ($this->currentAdminScope($data)['role'] ?? '') !== 'super_admin') {
            return ['ok' => false, 'message' => '只有管理员可以发送审批催办。'];
        }
        $requests = array_values((array) ($data['config_change_requests'] ?? []));
        $requestId = max(0, (int) ($payload['config_change_id'] ?? $payload['id'] ?? 0));
        $bulkOverdue = !empty($payload['bulk_overdue']);
        $matchedIndexes = [];
        $now = time();
        $policy = $this->configApprovalPolicy($data);
        $escalateMultiplier = max(1, (int) ($policy['escalate_after_multiplier'] ?? 2));
        $quietNow = $this->configApprovalQuietHoursActive($policy, $now);
        foreach ($requests as $index => $request) {
            if ((string) ($request['status'] ?? 'pending') !== 'pending') {
                continue;
            }
            if ($requestId > 0 && (int) ($request['id'] ?? 0) !== $requestId) {
                continue;
            }
            $createdAt = strtotime((string) ($request['created_at'] ?? '')) ?: 0;
            $deadlineMinutes = $this->configChangeSlaMinutes((string) ($request['config_type'] ?? 'base_config'));
            $overdue = $createdAt > 0 && ($now - $createdAt) > ($deadlineMinutes * 60);
            if (!$overdue && ($bulkOverdue || empty($payload['force_reminder']))) {
                continue;
            }
            $matchedIndexes[] = $index;
        }
        if (empty($matchedIndexes)) {
            return ['ok' => false, 'message' => $requestId > 0 ? '该配置变更未超时或已处理。' : '暂无超时待审批配置。'];
        }

        $admin = $this->currentAdmin();
        $sentCount = 0;
        foreach ($matchedIndexes as $index) {
            $createdAt = strtotime((string) ($requests[$index]['created_at'] ?? '')) ?: $now;
            $deadlineMinutes = $this->configChangeSlaMinutes((string) ($requests[$index]['config_type'] ?? 'base_config'));
            $elapsedMinutes = max(0, (int) floor(($now - $createdAt) / 60));
            $requests[$index]['last_reminded_at'] = date('Y-m-d H:i:s', $now);
            $requests[$index]['last_reminded_by_admin_id'] = max(0, (int) ($admin['id'] ?? 0));
            $requests[$index]['last_reminded_by_admin_name'] = $this->limitText((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员')), 60);
            $requests[$index]['reminder_count'] = max(0, (int) ($requests[$index]['reminder_count'] ?? 0)) + 1;
            $requests[$index]['updated_at'] = date('Y-m-d H:i:s', $now);
            $requests[$index]['sla_snapshot'] = [
                'deadline_minutes' => $deadlineMinutes,
                'elapsed_minutes' => $elapsedMinutes,
                'overdue_minutes' => max(0, $elapsedMinutes - $deadlineMinutes),
                'quiet_hours_active' => $quietNow,
                'escalate_after_multiplier' => $escalateMultiplier,
            ];
            $event = $elapsedMinutes >= $deadlineMinutes * $escalateMultiplier ? 'escalated' : 'reminded';
            $this->appendConfigChangeNotificationLogs($data, $requests[$index], $event);
            $sentCount++;
        }
        $data['config_change_requests'] = $requests;
        $this->store->save($data);

        return ['ok' => true, 'message' => '已发送 ' . $sentCount . ' 条审批催办。', 'count' => $sentCount];
    }

    public function configChangeSlaDashboard(array $requests, array $apps = []): array
    {
        $now = time();
        $summary = [
            'total' => 0,
            'pending' => 0,
            'overdue_pending' => 0,
            'approved' => 0,
            'applied' => 0,
            'rejected' => 0,
            'rolled_back' => 0,
            'sla_met' => 0,
            'sla_total' => 0,
            'avg_review_minutes' => 0,
            'avg_apply_minutes' => 0,
            'sla_rate' => 0.0,
        ];
        $typeRows = [];
        $targetRows = [];
        $pendingRows = [];
        $adminRows = [];
        $reviewMinutes = [];
        $applyMinutes = [];
        $appNameByKey = [];
        foreach (array_values($apps) as $app) {
            if (!is_array($app)) {
                continue;
            }
            $appKey = (string) ($app['app_key'] ?? '');
            if ($appKey !== '') {
                $appNameByKey[$appKey] = (string) ($app['name'] ?? $appKey);
            }
        }

        foreach (array_values($requests) as $request) {
            if (!is_array($request)) {
                continue;
            }
            $type = (string) ($request['config_type'] ?? 'base_config');
            $target = (string) ($request['target_key'] ?? '');
            $status = (string) ($request['status'] ?? 'pending');
            $createdAt = strtotime((string) ($request['created_at'] ?? '')) ?: 0;
            $reviewedAt = strtotime((string) ($request['reviewed_at'] ?? '')) ?: 0;
            $appliedAt = strtotime((string) ($request['applied_at'] ?? '')) ?: 0;
            $deadlineMinutes = $this->configChangeSlaMinutes($type);
            $elapsedMinutes = $createdAt > 0 ? (int) floor((($status === 'pending' ? $now : max($reviewedAt, $appliedAt, $createdAt)) - $createdAt) / 60) : 0;
            $overdue = $status === 'pending' && $createdAt > 0 && ($now - $createdAt) > ($deadlineMinutes * 60);

            $summary['total']++;
            if (isset($summary[$status])) {
                $summary[$status]++;
            }
            if ($overdue) {
                $summary['overdue_pending']++;
            }
            if ($reviewedAt > 0 && $createdAt > 0) {
                $minutes = max(0, (int) floor(($reviewedAt - $createdAt) / 60));
                $reviewMinutes[] = $minutes;
                $summary['sla_total']++;
                if ($minutes <= $deadlineMinutes) {
                    $summary['sla_met']++;
                }
            }
            if ($appliedAt > 0 && $createdAt > 0) {
                $applyMinutes[] = max(0, (int) floor(($appliedAt - $createdAt) / 60));
            }

            $typeRows[$type] ??= $this->emptyConfigChangeSlaRow($type, '', $deadlineMinutes);
            $this->accumulateConfigChangeSlaRow($typeRows[$type], $status, $overdue, $reviewedAt, $createdAt, $appliedAt, $deadlineMinutes);

            $targetKey = $type . ':' . $target;
            $targetRows[$targetKey] ??= $this->emptyConfigChangeSlaRow($type, $target, $deadlineMinutes);
            $targetRows[$targetKey]['label'] = $this->configChangeTargetLabel($type, $target, $appNameByKey);
            $this->accumulateConfigChangeSlaRow($targetRows[$targetKey], $status, $overdue, $reviewedAt, $createdAt, $appliedAt, $deadlineMinutes);

            if ($status === 'pending') {
                $pendingRows[] = [
                    'id' => (int) ($request['id'] ?? 0),
                    'title' => (string) ($request['title'] ?? '配置变更'),
                    'config_type' => $type,
                    'target_key' => $target,
                    'target_label' => $this->configChangeTargetLabel($type, $target, $appNameByKey),
                    'created_by_admin_name' => (string) ($request['created_by_admin_name'] ?? ''),
                    'created_at' => (string) ($request['created_at'] ?? ''),
                    'elapsed_minutes' => $elapsedMinutes,
                    'deadline_minutes' => $deadlineMinutes,
                    'overdue' => $overdue,
                    'remaining_minutes' => max(0, $deadlineMinutes - $elapsedMinutes),
                ];
            }
            $creatorId = (int) ($request['created_by_admin_id'] ?? 0);
            $creatorName = (string) (($request['created_by_admin_name'] ?? '') ?: ($creatorId > 0 ? ('管理员 #' . $creatorId) : '未知申请人'));
            $creatorKey = 'creator:' . $creatorId . ':' . $creatorName;
            $adminRows[$creatorKey] ??= $this->emptyConfigChangeAdminSlaRow($creatorId, $creatorName, '申请人');
            $adminRows[$creatorKey]['submitted']++;
            if ($status === 'pending') {
                $adminRows[$creatorKey]['pending_created']++;
                if ($overdue) {
                    $adminRows[$creatorKey]['overdue_created']++;
                }
            }

            $reviewerId = (int) ($request['reviewed_by_admin_id'] ?? 0);
            $reviewerName = (string) ($request['reviewed_by_admin_name'] ?? '');
            if ($reviewerId > 0 || $reviewerName !== '') {
                $reviewerKey = 'reviewer:' . $reviewerId . ':' . $reviewerName;
                $adminRows[$reviewerKey] ??= $this->emptyConfigChangeAdminSlaRow($reviewerId, $reviewerName !== '' ? $reviewerName : ('管理员 #' . $reviewerId), '审批人');
                if ($reviewedAt > 0 && $createdAt > 0) {
                    $minutes = max(0, (int) floor(($reviewedAt - $createdAt) / 60));
                    $adminRows[$reviewerKey]['reviewed']++;
                    $adminRows[$reviewerKey]['review_minutes'][] = $minutes;
                    $adminRows[$reviewerKey]['sla_total']++;
                    if ($minutes <= $deadlineMinutes) {
                        $adminRows[$reviewerKey]['sla_met']++;
                    }
                }
                if ($status === 'applied') {
                    $adminRows[$reviewerKey]['applied']++;
                } elseif ($status === 'rejected') {
                    $adminRows[$reviewerKey]['rejected']++;
                }
            }

            $rollbackId = (int) ($request['rolled_back_by_admin_id'] ?? 0);
            $rollbackName = (string) ($request['rolled_back_by_admin_name'] ?? '');
            if ($status === 'rolled_back' && ($rollbackId > 0 || $rollbackName !== '')) {
                $rollbackKey = 'reviewer:' . $rollbackId . ':' . $rollbackName;
                $adminRows[$rollbackKey] ??= $this->emptyConfigChangeAdminSlaRow($rollbackId, $rollbackName !== '' ? $rollbackName : ('管理员 #' . $rollbackId), '审批人');
                $adminRows[$rollbackKey]['rolled_back']++;
            }
            $reminderId = (int) ($request['last_reminded_by_admin_id'] ?? 0);
            $reminderName = (string) ($request['last_reminded_by_admin_name'] ?? '');
            if ($reminderId > 0 || $reminderName !== '') {
                $reminderKey = 'reviewer:' . $reminderId . ':' . $reminderName;
                $adminRows[$reminderKey] ??= $this->emptyConfigChangeAdminSlaRow($reminderId, $reminderName !== '' ? $reminderName : ('管理员 #' . $reminderId), '审批人');
                $adminRows[$reminderKey]['reminders_sent'] += max(0, (int) ($request['reminder_count'] ?? 0));
            }
        }

        foreach ($typeRows as &$row) {
            $this->finalizeConfigChangeSlaRow($row);
        }
        unset($row);
        foreach ($targetRows as &$row) {
            $this->finalizeConfigChangeSlaRow($row);
        }
        unset($row);
        foreach ($adminRows as &$row) {
            $this->finalizeConfigChangeAdminSlaRow($row);
        }
        unset($row);
        $typeRows = array_values($typeRows);
        $targetRows = array_values($targetRows);
        $adminRows = array_values($adminRows);
        usort($typeRows, static fn (array $a, array $b): int => [(int) ($b['overdue_pending'] ?? 0), (int) ($b['pending'] ?? 0), (int) ($b['total'] ?? 0)] <=> [(int) ($a['overdue_pending'] ?? 0), (int) ($a['pending'] ?? 0), (int) ($a['total'] ?? 0)]);
        usort($targetRows, static fn (array $a, array $b): int => [(int) ($b['overdue_pending'] ?? 0), (int) ($b['pending'] ?? 0), (int) ($b['total'] ?? 0)] <=> [(int) ($a['overdue_pending'] ?? 0), (int) ($a['pending'] ?? 0), (int) ($a['total'] ?? 0)]);
        usort($adminRows, static fn (array $a, array $b): int => [(int) ($b['overdue_created'] ?? 0), (int) ($b['pending_created'] ?? 0), (int) ($b['reviewed'] ?? 0), (int) ($b['submitted'] ?? 0)] <=> [(int) ($a['overdue_created'] ?? 0), (int) ($a['pending_created'] ?? 0), (int) ($a['reviewed'] ?? 0), (int) ($a['submitted'] ?? 0)]);
        usort($pendingRows, static fn (array $a, array $b): int => [(bool) ($b['overdue'] ?? false), (int) ($b['elapsed_minutes'] ?? 0)] <=> [(bool) ($a['overdue'] ?? false), (int) ($a['elapsed_minutes'] ?? 0)]);

        $summary['avg_review_minutes'] = empty($reviewMinutes) ? 0 : (int) round(array_sum($reviewMinutes) / count($reviewMinutes));
        $summary['avg_apply_minutes'] = empty($applyMinutes) ? 0 : (int) round(array_sum($applyMinutes) / count($applyMinutes));
        $summary['sla_rate'] = $summary['sla_total'] > 0 ? round($summary['sla_met'] / $summary['sla_total'] * 100, 1) : 0.0;

        return [
            'summary' => $summary,
            'type_rows' => $typeRows,
            'target_rows' => array_slice($targetRows, 0, 20),
            'pending_rows' => array_slice($pendingRows, 0, 20),
            'admin_rows' => array_slice($adminRows, 0, 20),
        ];
    }

    private function configChangeSlaMinutes(string $configType): int
    {
        return match ($configType) {
            'payment_config', 'app_config' => 120,
            'notification_config' => 240,
            default => 480,
        };
    }

    private function emptyConfigChangeSlaRow(string $configType, string $targetKey, int $deadlineMinutes): array
    {
        return [
            'config_type' => $configType,
            'target_key' => $targetKey,
            'label' => $targetKey,
            'deadline_minutes' => $deadlineMinutes,
            'total' => 0,
            'pending' => 0,
            'overdue_pending' => 0,
            'approved' => 0,
            'applied' => 0,
            'rejected' => 0,
            'rolled_back' => 0,
            'review_minutes' => [],
            'apply_minutes' => [],
            'sla_met' => 0,
            'sla_total' => 0,
            'avg_review_minutes' => 0,
            'avg_apply_minutes' => 0,
            'sla_rate' => 0.0,
        ];
    }

    private function accumulateConfigChangeSlaRow(array &$row, string $status, bool $overdue, int $reviewedAt, int $createdAt, int $appliedAt, int $deadlineMinutes): void
    {
        $row['total']++;
        if (isset($row[$status])) {
            $row[$status]++;
        }
        if ($overdue) {
            $row['overdue_pending']++;
        }
        if ($reviewedAt > 0 && $createdAt > 0) {
            $minutes = max(0, (int) floor(($reviewedAt - $createdAt) / 60));
            $row['review_minutes'][] = $minutes;
            $row['sla_total']++;
            if ($minutes <= $deadlineMinutes) {
                $row['sla_met']++;
            }
        }
        if ($appliedAt > 0 && $createdAt > 0) {
            $row['apply_minutes'][] = max(0, (int) floor(($appliedAt - $createdAt) / 60));
        }
    }

    private function finalizeConfigChangeSlaRow(array &$row): void
    {
        $reviewMinutes = (array) ($row['review_minutes'] ?? []);
        $applyMinutes = (array) ($row['apply_minutes'] ?? []);
        $row['avg_review_minutes'] = empty($reviewMinutes) ? 0 : (int) round(array_sum($reviewMinutes) / count($reviewMinutes));
        $row['avg_apply_minutes'] = empty($applyMinutes) ? 0 : (int) round(array_sum($applyMinutes) / count($applyMinutes));
        $row['sla_rate'] = (int) ($row['sla_total'] ?? 0) > 0 ? round((int) ($row['sla_met'] ?? 0) / (int) ($row['sla_total'] ?? 1) * 100, 1) : 0.0;
        unset($row['review_minutes'], $row['apply_minutes']);
    }

    private function emptyConfigChangeAdminSlaRow(int $adminId, string $adminName, string $roleLabel): array
    {
        return [
            'admin_id' => max(0, $adminId),
            'admin_name' => $adminName !== '' ? $adminName : '未知管理员',
            'role_label' => $roleLabel,
            'submitted' => 0,
            'pending_created' => 0,
            'overdue_created' => 0,
            'reviewed' => 0,
            'applied' => 0,
            'rejected' => 0,
            'rolled_back' => 0,
            'reminders_sent' => 0,
            'review_minutes' => [],
            'avg_review_minutes' => 0,
            'sla_met' => 0,
            'sla_total' => 0,
            'sla_rate' => 0.0,
        ];
    }

    private function finalizeConfigChangeAdminSlaRow(array &$row): void
    {
        $reviewMinutes = (array) ($row['review_minutes'] ?? []);
        $row['avg_review_minutes'] = empty($reviewMinutes) ? 0 : (int) round(array_sum($reviewMinutes) / count($reviewMinutes));
        $row['sla_rate'] = (int) ($row['sla_total'] ?? 0) > 0 ? round((int) ($row['sla_met'] ?? 0) / (int) ($row['sla_total'] ?? 1) * 100, 1) : 0.0;
        unset($row['review_minutes']);
    }

    private function configChangeTargetLabel(string $configType, string $targetKey, array $appNameByKey): string
    {
        if ($configType === 'app_config') {
            return (string) ($appNameByKey[$targetKey] ?? ($targetKey !== '' ? $targetKey : '应用配置'));
        }
        if ($configType === 'payment_config') {
            return '支付配置';
        }
        if ($configType === 'notification_config') {
            return '短信邮件';
        }
        if ($configType === 'base_config') {
            return '基础配置';
        }

        return $targetKey !== '' ? $targetKey : '配置片段';
    }

    private function buildConfigChangeSnapshot(string $configType, array $payload, array $data): array
    {
        if ($configType === 'payment_config') {
            return $this->buildPaymentConfigSnapshot($payload, $data);
        }
        if ($configType === 'app_config') {
            return $this->buildAppConfigSnapshot($payload, $data);
        }
        if ($configType === 'base_config') {
            $before = [
                'site_name' => (string) ($data['site_config']['site_name'] ?? '精秀短剧'),
                'icp_number' => (string) ($data['site_config']['icp_number'] ?? ''),
                'config_approval_policy' => (array) ($data['site_config']['config_approval_policy'] ?? []),
            ];
            $approvalPolicy = (array) ($before['config_approval_policy'] ?? []);
            $after = [
                'site_name' => $this->limitText(trim((string) ($payload['change_site_name'] ?? $before['site_name'])) ?: '精秀短剧', 40),
                'icp_number' => $this->limitText(trim((string) ($payload['change_icp_number'] ?? $before['icp_number'])), 80),
                'config_approval_policy' => [
                    'payment_config' => array_key_exists('change_approval_payment_config', $payload) ? !empty($payload['change_approval_payment_config']) : !empty($approvalPolicy['payment_config']),
                    'app_config' => array_key_exists('change_approval_app_config', $payload) ? !empty($payload['change_approval_app_config']) : !empty($approvalPolicy['app_config']),
                    'quiet_hours_enabled' => array_key_exists('change_approval_quiet_hours_enabled', $payload) ? !empty($payload['change_approval_quiet_hours_enabled']) : !empty($approvalPolicy['quiet_hours_enabled']),
                    'quiet_start' => $this->timeOfDayFromPayload((string) ($payload['change_approval_quiet_start'] ?? ($approvalPolicy['quiet_start'] ?? '22:00')), '22:00'),
                    'quiet_end' => $this->timeOfDayFromPayload((string) ($payload['change_approval_quiet_end'] ?? ($approvalPolicy['quiet_end'] ?? '08:00')), '08:00'),
                    'escalate_after_multiplier' => max(1, min(12, (int) ($payload['change_approval_escalate_multiplier'] ?? ($approvalPolicy['escalate_after_multiplier'] ?? 2)))),
                ],
            ];
            return ['ok' => true, 'title' => '基础配置变更', 'target_key' => 'site_config', 'before_snapshot' => $before, 'after_snapshot' => $after];
        }
        if ($configType === 'notification_config') {
            $before = [
                'sms_config' => (array) ($data['site_config']['sms_config'] ?? []),
                'email_config' => (array) ($data['site_config']['email_config'] ?? []),
            ];
            $after = $before;
            $after['sms_config']['status'] = (string) ($payload['change_sms_status'] ?? ($before['sms_config']['status'] ?? 'active'));
            $after['sms_config']['provider'] = (string) ($payload['change_sms_provider'] ?? ($before['sms_config']['provider'] ?? 'mock'));
            $after['sms_config']['sign_name'] = $this->limitText(trim((string) ($payload['change_sms_sign_name'] ?? ($before['sms_config']['sign_name'] ?? '精秀短剧'))), 40);
            $after['sms_config']['template_id'] = $this->limitText(trim((string) ($payload['change_sms_template_id'] ?? ($before['sms_config']['template_id'] ?? 'SMS_LOGIN'))), 80);
            $after['sms_config']['template_content'] = $this->limitText(trim((string) ($payload['change_sms_template_content'] ?? ($before['sms_config']['template_content'] ?? '您的验证码为 {code}，{minutes} 分钟内有效。'))), 200);
            $after['email_config']['status'] = (string) ($payload['change_email_status'] ?? ($before['email_config']['status'] ?? 'paused'));
            $after['email_config']['provider'] = (string) ($payload['change_email_provider'] ?? ($before['email_config']['provider'] ?? 'mock'));
            $after['email_config']['from_email'] = $this->limitText(trim((string) ($payload['change_email_from_email'] ?? ($before['email_config']['from_email'] ?? 'noreply@example.com'))), 120);
            $after['email_config']['from_name'] = $this->limitText(trim((string) ($payload['change_email_from_name'] ?? ($before['email_config']['from_name'] ?? '精秀短剧'))), 60);
            return ['ok' => true, 'title' => '短信邮件配置变更', 'target_key' => 'notification', 'before_snapshot' => $before, 'after_snapshot' => $after];
        }

        $key = preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim((string) ($payload['change_fragment_key'] ?? ''))) ?: '';
        if ($key === '') {
            return ['ok' => false, 'message' => '配置片段键不能为空。'];
        }
        $before = [];
        foreach ((array) ($data['system_config_fragments'] ?? []) as $fragment) {
            if ((string) ($fragment['key'] ?? '') === $key) {
                $before = $fragment;
                break;
            }
        }
        $type = (string) ($payload['change_fragment_type'] ?? ($before['type'] ?? 'text'));
        $type = in_array($type, ['text', 'json', 'url', 'secret'], true) ? $type : 'text';
        $value = trim((string) ($payload['change_fragment_value'] ?? ($before['value'] ?? '')));
        if ($type === 'json' && $value !== '') {
            json_decode($value, true);
            if (json_last_error() !== JSON_ERROR_NONE) {
                return ['ok' => false, 'message' => '配置片段 JSON 格式不正确。'];
            }
        }
        $after = [
            'key' => $this->limitText($key, 80),
            'name' => $this->limitText(trim((string) ($payload['change_fragment_name'] ?? ($before['name'] ?? $key))) ?: $key, 80),
            'group' => $this->limitText(trim((string) ($payload['change_fragment_group'] ?? ($before['group'] ?? 'system'))) ?: 'system', 40),
            'type' => $type,
            'value' => $this->limitText($value, 4000),
            'sensitive' => !empty($payload['change_fragment_sensitive']) || $type === 'secret',
            'status' => in_array((string) ($payload['change_fragment_status'] ?? ($before['status'] ?? 'active')), ['active', 'paused'], true) ? (string) ($payload['change_fragment_status'] ?? ($before['status'] ?? 'active')) : 'active',
            'remark' => $this->limitText(trim((string) ($payload['change_fragment_remark'] ?? ($before['remark'] ?? ''))), 160),
        ];

        return ['ok' => true, 'title' => '配置片段变更：' . $key, 'target_key' => $key, 'before_snapshot' => $before, 'after_snapshot' => $after];
    }

    private function appendConfigChangeNotificationLogs(array &$data, array $request, string $event): void
    {
        $data['config_change_notification_logs'] = array_values((array) ($data['config_change_notification_logs'] ?? []));
        $receivers = $this->configChangeNotificationReceivers($data, $request, $event);
        if (empty($receivers)) {
            return;
        }
        $nextId = empty($data['config_change_notification_logs'])
            ? 1
            : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $data['config_change_notification_logs'])) + 1);
        $now = date('Y-m-d H:i:s');
        $title = $this->configChangeNotificationTitle($request, $event);
        $message = $this->configChangeNotificationMessage($request, $event);
        foreach ($receivers as $receiver) {
            $channels = $this->configChangeNotificationChannels($receiver);
            foreach ($channels as $channel => $contact) {
                $data['config_change_notification_logs'][] = [
                    'id' => $nextId++,
                    'request_id' => (int) ($request['id'] ?? 0),
                    'event' => $event,
                    'channel' => $channel,
                    'receiver_admin_id' => (int) ($receiver['id'] ?? 0),
                    'receiver_name' => $this->limitText((string) (($receiver['nickname'] ?? '') ?: ($receiver['username'] ?? '管理员')), 60),
                    'receiver_contact' => $this->limitText((string) $contact, 120),
                    'title' => $title,
                    'message' => $message,
                    'status' => $channel === 'system' || $contact !== '' ? 'success' : 'skipped',
                    'created_at' => $now,
                ];
            }
        }
        $data['config_change_notification_logs'] = array_slice(array_values($data['config_change_notification_logs']), -1000);
    }

    private function configChangeNotificationReceivers(array $data, array $request, string $event): array
    {
        $admins = array_values(array_filter((array) ($data['admins'] ?? []), static fn (array $admin): bool => (string) ($admin['status'] ?? 'active') === 'active'));
        $quietActive = !empty(((array) ($request['sla_snapshot'] ?? []))['quiet_hours_active']);
        if (in_array($event, ['submitted', 'reminded', 'escalated'], true)) {
            $receivers = array_values(array_filter($admins, static fn (array $admin): bool => (string) ($admin['role'] ?? '') === 'super_admin'));
            return array_map(static function (array $admin) use ($quietActive): array {
                if ($quietActive) {
                    $admin['_quiet_hours_active'] = true;
                }
                return $admin;
            }, $receivers);
        }
        $creatorId = (int) ($request['created_by_admin_id'] ?? 0);
        foreach ($admins as $admin) {
            if ((int) ($admin['id'] ?? 0) === $creatorId) {
                if ($quietActive) {
                    $admin['_quiet_hours_active'] = true;
                }
                return [$admin];
            }
        }

        return [];
    }

    private function configChangeNotificationChannels(array $receiver): array
    {
        $channels = ['system' => ''];
        $quietActive = !empty($receiver['_quiet_hours_active']);
        if ($quietActive) {
            return $channels;
        }
        $email = trim((string) ($receiver['email'] ?? ''));
        if ($email !== '' && filter_var($email, FILTER_VALIDATE_EMAIL)) {
            $channels['email'] = $email;
        }
        $phone = preg_replace('/\D+/', '', (string) ($receiver['phone'] ?? '')) ?: '';
        if ($phone !== '') {
            $channels['sms'] = $phone;
        }

        return $channels;
    }

    private function configApprovalQuietHoursActive(array $policy, ?int $timestamp = null): bool
    {
        if (empty($policy['quiet_hours_enabled'])) {
            return false;
        }
        $timestamp ??= time();
        $start = $this->minutesFromTimeOfDay((string) ($policy['quiet_start'] ?? '22:00'));
        $end = $this->minutesFromTimeOfDay((string) ($policy['quiet_end'] ?? '08:00'));
        $current = ((int) date('G', $timestamp)) * 60 + (int) date('i', $timestamp);
        if ($start === $end) {
            return false;
        }
        if ($start < $end) {
            return $current >= $start && $current < $end;
        }

        return $current >= $start || $current < $end;
    }

    private function minutesFromTimeOfDay(string $value): int
    {
        $time = $this->timeOfDayFromPayload($value, '00:00');
        [$hour, $minute] = array_map('intval', explode(':', $time));

        return $hour * 60 + $minute;
    }

    private function configChangeNotificationTitle(array $request, string $event): string
    {
        $prefix = match ($event) {
            'submitted' => '待审批',
            'approved' => '已发布',
            'rejected' => '已驳回',
            'rolled_back' => '已回滚',
            'reminded' => '审批催办',
            'escalated' => '超时升级',
            default => '配置审批',
        };

        return $this->limitText($prefix . '：' . (string) ($request['title'] ?? '配置变更'), 120);
    }

    private function configChangeNotificationMessage(array $request, string $event): string
    {
        $type = (string) ($request['config_type'] ?? 'base_config');
        $target = (string) ($request['target_key'] ?? '');
        $operator = match ($event) {
            'submitted' => (string) ($request['created_by_admin_name'] ?? ''),
            'approved', 'rejected' => (string) ($request['reviewed_by_admin_name'] ?? ''),
            'rolled_back' => (string) ($request['rolled_back_by_admin_name'] ?? ''),
            'reminded', 'escalated' => (string) ($request['last_reminded_by_admin_name'] ?? ''),
            default => '',
        };
        $status = match ($event) {
            'submitted' => '提交了配置变更，等待审批',
            'approved' => '审批通过并发布了配置变更',
            'rejected' => '驳回了配置变更',
            'rolled_back' => '回滚了已发布配置',
            'reminded' => '催办了超时审批',
            'escalated' => '升级提醒了严重超时审批',
            default => '处理了配置变更',
        };

        $sla = (array) ($request['sla_snapshot'] ?? []);
        $slaText = '';
        if (in_array($event, ['reminded', 'escalated'], true)) {
            $slaText = '，已耗时 ' . (int) ($sla['elapsed_minutes'] ?? 0) . ' 分钟，超时 ' . (int) ($sla['overdue_minutes'] ?? 0) . ' 分钟';
            if (!empty($sla['quiet_hours_active'])) {
                $slaText .= '，免打扰期间仅站内提醒';
            }
        }

        return $this->limitText(trim($operator . ' ' . $status . '。类型：' . $type . '，目标：' . $target . $slaText), 240);
    }

    private function applyConfigChangeSnapshot(array &$data, array $request): array
    {
        $type = (string) ($request['config_type'] ?? '');
        $after = (array) ($request['after_snapshot'] ?? []);
        return $this->applyConfigSnapshot($data, $request, $after, false);
    }

    private function rollbackConfigChangeSnapshot(array &$data, array $request): array
    {
        $before = (array) ($request['before_snapshot'] ?? []);
        return $this->applyConfigSnapshot($data, $request, $before, true);
    }

    private function configApprovalPolicyEnabled(array $data, string $key): bool
    {
        $policy = (array) ($data['site_config']['config_approval_policy'] ?? []);

        return !empty($policy[$key]);
    }

    private function configApprovalPolicy(array $data): array
    {
        $policy = (array) ($data['site_config']['config_approval_policy'] ?? []);

        return [
            'payment_config' => !empty($policy['payment_config']),
            'app_config' => !empty($policy['app_config']),
            'quiet_hours_enabled' => !empty($policy['quiet_hours_enabled']),
            'quiet_start' => $this->timeOfDayFromPayload((string) ($policy['quiet_start'] ?? '22:00'), '22:00'),
            'quiet_end' => $this->timeOfDayFromPayload((string) ($policy['quiet_end'] ?? '08:00'), '08:00'),
            'escalate_after_multiplier' => max(1, min(12, (int) ($policy['escalate_after_multiplier'] ?? 2))),
        ];
    }

    private function timeOfDayFromPayload(string $value, string $fallback = '00:00'): string
    {
        $value = trim($value);
        if (preg_match('/^(\d{1,2}):(\d{1,2})$/', $value, $matches) !== 1) {
            return $fallback;
        }
        $hour = max(0, min(23, (int) $matches[1]));
        $minute = max(0, min(59, (int) $matches[2]));

        return sprintf('%02d:%02d', $hour, $minute);
    }

    private function applyConfigSnapshot(array &$data, array $request, array $snapshot, bool $deleteMissingFragment): array
    {
        $type = (string) ($request['config_type'] ?? '');
        if ($type === 'base_config') {
            $data['site_config']['site_name'] = $this->limitText(trim((string) ($snapshot['site_name'] ?? '精秀短剧')) ?: '精秀短剧', 40);
            $data['site_config']['icp_number'] = $this->limitText(trim((string) ($snapshot['icp_number'] ?? '')), 80);
            $approvalPolicy = (array) ($snapshot['config_approval_policy'] ?? []);
            $data['site_config']['config_approval_policy'] = [
                'payment_config' => !empty($approvalPolicy['payment_config']),
                'app_config' => !empty($approvalPolicy['app_config']),
                'quiet_hours_enabled' => !empty($approvalPolicy['quiet_hours_enabled']),
                'quiet_start' => $this->timeOfDayFromPayload((string) ($approvalPolicy['quiet_start'] ?? '22:00'), '22:00'),
                'quiet_end' => $this->timeOfDayFromPayload((string) ($approvalPolicy['quiet_end'] ?? '08:00'), '08:00'),
                'escalate_after_multiplier' => max(1, min(12, (int) ($approvalPolicy['escalate_after_multiplier'] ?? 2))),
            ];
            return ['ok' => true];
        }
        if ($type === 'notification_config') {
            $data['site_config']['sms_config'] = (array) ($snapshot['sms_config'] ?? []);
            $data['site_config']['email_config'] = (array) ($snapshot['email_config'] ?? []);
            return ['ok' => true];
        }
        if ($type === 'payment_config') {
            $data['payment_config'] = $snapshot;
            return ['ok' => true];
        }
        if ($type === 'app_config') {
            $apps = array_values((array) ($data['apps'] ?? []));
            $appKey = (string) ($snapshot['app_key'] ?? $request['target_key'] ?? '');
            if ($appKey === '') {
                return ['ok' => false, 'message' => '应用标识不能为空。'];
            }
            if ($deleteMissingFragment && empty($snapshot)) {
                $data['apps'] = array_values(array_filter($apps, static fn (array $item): bool => (string) ($item['app_key'] ?? '') !== $appKey));
                return ['ok' => true];
            }
            $replaced = false;
            foreach ($apps as &$item) {
                if ((string) ($item['app_key'] ?? '') !== $appKey && (int) ($item['id'] ?? 0) !== (int) ($snapshot['id'] ?? 0)) {
                    continue;
                }
                $item = $snapshot;
                $replaced = true;
                break;
            }
            unset($item);
            if (!$replaced) {
                $apps[] = $snapshot;
            }
            $data['apps'] = $apps;
            return ['ok' => true];
        }
        if ($type === 'config_fragment') {
            $fragments = array_values((array) ($data['system_config_fragments'] ?? []));
            $key = (string) ($snapshot['key'] ?? $request['target_key'] ?? '');
            if ($key === '') {
                return ['ok' => false, 'message' => '配置片段键不能为空。'];
            }
            if ($deleteMissingFragment && empty($snapshot)) {
                $data['system_config_fragments'] = array_values(array_filter($fragments, static fn (array $item): bool => (string) ($item['key'] ?? '') !== $key));
                return ['ok' => true];
            }
            $admin = $this->currentAdmin();
            $now = date('Y-m-d H:i:s');
            $fragment = $snapshot + [
                'id' => empty($fragments) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $fragments)) + 1),
                'created_at' => $now,
            ];
            foreach ($fragments as $existing) {
                if ((string) ($existing['key'] ?? '') === $key) {
                    $fragment['id'] = (int) ($existing['id'] ?? $fragment['id']);
                    $fragment['created_at'] = (string) ($existing['created_at'] ?? $now);
                    break;
                }
            }
            $fragment['updated_by'] = $this->limitText((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员')), 60);
            $fragment['updated_at'] = $now;
            $replaced = false;
            foreach ($fragments as &$item) {
                if ((string) ($item['key'] ?? '') !== $key) {
                    continue;
                }
                $item = $fragment;
                $replaced = true;
                break;
            }
            unset($item);
            if (!$replaced) {
                $fragments[] = $fragment;
            }
            $data['system_config_fragments'] = $fragments;
            return ['ok' => true];
        }

        return ['ok' => false, 'message' => '不支持的配置变更类型。'];
    }

    public function updateHomepageTemplate(array $payload): void
    {
        $data = $this->store->load();
        $template = (string) ($payload['homepage_template'] ?? 'mini');
        $novelTemplate = (string) ($payload['novel_homepage_template'] ?? 'library');
        $data['site_config']['homepage_template'] = in_array($template, ['mini', 'marketing'], true) ? $template : 'mini';
        $data['site_config']['novel_homepage_template'] = in_array($novelTemplate, ['library', 'ranking'], true) ? $novelTemplate : 'library';

        $this->store->save($data);
    }

    public function updateDesignHome(array $payload): void
    {
        $data = $this->store->load();
        $current = $data['design_config']['home'] ?? [];
        $clip = static function (string $value, int $length): string {
            if (function_exists('mb_substr')) {
                return (string) mb_substr($value, 0, $length);
            }

            $chars = preg_split('//u', $value, -1, PREG_SPLIT_NO_EMPTY);
            if ($chars === false) {
                return substr($value, 0, $length);
            }

            return implode('', array_slice($chars, 0, $length));
        };
        $text = static function (string $key, string $default = '') use ($payload, $current, $clip): string {
            $value = trim((string) ($payload[$key] ?? ($current[$key] ?? $default)));
            return $clip($value, 80);
        };
        $color = static function (string $key, string $default) use ($payload, $current): string {
            $value = trim((string) ($payload[$key] ?? ($current[$key] ?? $default)));
            return preg_match('/^#[0-9a-fA-F]{6}$/', $value) === 1 ? $value : $default;
        };

        $allowedModules = ['search', 'banner', 'quick_nav', 'notice', 'rank', 'drama_grid', 'reward', 'bottom_nav'];
        $modules = array_values(array_intersect($allowedModules, array_map('strval', (array) ($payload['modules'] ?? []))));
        if (empty($modules)) {
            $modules = ['banner', 'rank', 'drama_grid'];
        }

        $quickNavs = [];
        for ($i = 1; $i <= 4; $i++) {
            $label = trim((string) ($payload['quick_nav_label_' . $i] ?? ''));
            $link = trim((string) ($payload['quick_nav_link_' . $i] ?? '#'));
            if ($label === '') {
                continue;
            }
            $quickNavs[] = [
                'label' => $clip($label, 12),
                'link' => $link === '' ? '#' : $clip($link, 160),
            ];
        }
        if (empty($quickNavs)) {
            $quickNavs = $current['quick_navs'] ?? [];
        }

        $data['design_config']['home'] = [
            'brand_title' => $text('brand_title', '精秀短剧'),
            'search_placeholder' => $text('search_placeholder', '请搜索您感兴趣的剧...'),
            'hero_title' => $text('hero_title', '逆袭总裁的秘密'),
            'hero_subtitle' => $text('hero_subtitle', '今日热播 · 支付即解锁'),
            'notice_text' => $text('notice_text', '添加到「我的小程序」追剧更方便'),
            'section_title' => $text('section_title', '全部剧集'),
            'primary_color' => $color('primary_color', '#ef5b5f'),
            'accent_color' => $color('accent_color', '#ff955d'),
            'modules' => $modules,
            'quick_navs' => $quickNavs,
        ];
        $data['design_config']['updated_at'] = date('Y-m-d H:i:s');
        foreach ($data['design_config']['pages'] as &$page) {
            if (($page['template'] ?? '') === 'diy') {
                $page['updated_at'] = $data['design_config']['updated_at'];
                break;
            }
        }
        if (!empty($payload['apply_home_diy'])) {
            $data['site_config']['homepage_template'] = 'diy';
        }

        $this->store->save($data);
    }

    public function updateUser(array $payload): void
    {
        $data = $this->store->load();
        foreach ($data['users'] as &$user) {
            if ((int) $user['id'] === (int) ($payload['user_id'] ?? 0)) {
                $user['nickname'] = trim((string) ($payload['nickname'] ?? $user['nickname']));
                $user['phone'] = trim((string) ($payload['phone'] ?? $user['phone']));
                $user['role'] = trim((string) ($payload['role'] ?? $user['role']));
                $user['membership'] = !empty($payload['membership']);
                $user['membership_expires_at'] = !empty($payload['membership_expires_at']) ? trim((string) $payload['membership_expires_at']) : null;
                $user['coin_balance'] = max(0, (int) ($payload['coin_balance'] ?? $user['coin_balance'] ?? 0));
                $user['bonus_coin_balance'] = max(0, (int) ($payload['bonus_coin_balance'] ?? $user['bonus_coin_balance'] ?? 0));
                $user['auto_unlock_next'] = !empty($payload['auto_unlock_next']);
                break;
            }
        }

        $this->store->save($data);
    }

