    public function contentLibrary(?array $data = null): array
    {
        $data ??= $this->store->load();
        $groupNameById = [];
        foreach ((array) ($data['content_groups'] ?? []) as $group) {
            $groupNameById[(int) ($group['id'] ?? 0)] = (string) ($group['name'] ?? '未分组');
        }

        $metrics = [];
        foreach ((array) ($data['orders'] ?? []) as $order) {
            if (!empty($order['is_test'])) {
                continue;
            }
            $contentType = (string) ($order['content_type'] ?? 'drama');
            $contentId = $contentType === 'novel' ? (int) ($order['novel_id'] ?? 0) : (int) ($order['drama_id'] ?? 0);
            if ($contentId <= 0) {
                continue;
            }
            $key = $contentType . ':' . $contentId;
            $metrics[$key] ??= ['orders' => 0, 'paid_orders' => 0, 'revenue' => 0.0];
            $metrics[$key]['orders']++;
            if (!in_array((string) ($order['status'] ?? 'pending'), ['paid', 'partial_refunded', 'refunded'], true)) {
                continue;
            }
            $amount = (float) ($order['amount'] ?? 0);
            $refund = min($amount, max(0.0, (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0)));
            $metrics[$key]['paid_orders']++;
            $metrics[$key]['revenue'] += max(0.0, $amount - $refund);
        }

        $rows = [];
        foreach ((array) ($data['dramas'] ?? []) as $drama) {
            $id = (int) ($drama['id'] ?? 0);
            $key = 'drama:' . $id;
            $groupId = (int) ($drama['group_id'] ?? 0);
            $rows[] = [
                'key' => $key,
                'content_type' => 'drama',
                'content_label' => '短剧',
                'id' => $id,
                'title' => (string) ($drama['title'] ?? '未命名短剧'),
                'category' => (string) ($drama['category'] ?? ''),
                'tags' => array_values((array) ($drama['tags'] ?? [])),
                'group_id' => $groupId,
                'group_name' => $groupNameById[$groupId] ?? '未分组',
                'status' => (string) ($drama['status'] ?? 'draft'),
                'audit_status' => (string) ($drama['audit_status'] ?? 'draft'),
                'audit_note' => (string) ($drama['audit_note'] ?? ''),
                'reviewed_by' => (string) ($drama['reviewed_by'] ?? ''),
                'reviewed_at' => (string) ($drama['reviewed_at'] ?? ''),
                'unit_count' => count((array) ($drama['episodes'] ?? [])),
                'orders' => (int) ($metrics[$key]['orders'] ?? 0),
                'paid_orders' => (int) ($metrics[$key]['paid_orders'] ?? 0),
                'revenue' => round((float) ($metrics[$key]['revenue'] ?? 0), 2),
                'sort' => (int) ($drama['sort'] ?? 0),
            ];
        }
        foreach ((array) ($data['novels'] ?? []) as $novel) {
            $id = (int) ($novel['id'] ?? 0);
            $key = 'novel:' . $id;
            $groupId = (int) ($novel['group_id'] ?? 0);
            $rows[] = [
                'key' => $key,
                'content_type' => 'novel',
                'content_label' => '小说',
                'id' => $id,
                'title' => (string) ($novel['title'] ?? '未命名小说'),
                'category' => (string) ($novel['category'] ?? ''),
                'tags' => array_values((array) ($novel['tags'] ?? [])),
                'group_id' => $groupId,
                'group_name' => $groupNameById[$groupId] ?? '未分组',
                'status' => (string) ($novel['status'] ?? 'draft'),
                'audit_status' => (string) ($novel['audit_status'] ?? 'draft'),
                'audit_note' => (string) ($novel['audit_note'] ?? ''),
                'reviewed_by' => (string) ($novel['reviewed_by'] ?? ''),
                'reviewed_at' => (string) ($novel['reviewed_at'] ?? ''),
                'unit_count' => count((array) ($novel['chapters'] ?? [])),
                'orders' => (int) ($metrics[$key]['orders'] ?? 0),
                'paid_orders' => (int) ($metrics[$key]['paid_orders'] ?? 0),
                'revenue' => round((float) ($metrics[$key]['revenue'] ?? 0), 2),
                'sort' => (int) ($novel['sort'] ?? 0),
            ];
        }
        return $this->sortAdminWorks($rows);
    }

    private function sortAdminWorks(array $items): array
    {
        usort($items, function (array $a, array $b): int {
            return $this->adminWorkSortKey($a) <=> $this->adminWorkSortKey($b);
        });

        return array_values($items);
    }

    private function adminWorkSortKey(array $item): array
    {
        $title = trim((string) ($item['title'] ?? ''));
        $status = (string) ($item['status'] ?? 'draft');
        $statusRank = [
            'online' => 0,
            'offline' => 1,
            'draft' => 2,
            'deleted' => 3,
        ][$status] ?? 1;
        $unitCount = array_key_exists('unit_count', $item)
            ? (int) $item['unit_count']
            : max(count((array) ($item['episodes'] ?? [])), count((array) ($item['chapters'] ?? [])));
        $isPlaceholder = ($title === '' || str_starts_with($title, '未命名')) && $unitCount === 0;

        return [
            $isPlaceholder ? 1 : 0,
            $statusRank,
            -(int) ($item['sort'] ?? 0),
            -$unitCount,
            -(int) ($item['id'] ?? 0),
        ];
    }

