    public function saveContentTag(array $payload): array
    {
        $data = $this->store->load();
        $tags = array_values((array) ($data['content_tags'] ?? []));
        $tagId = max(0, (int) ($payload['tag_id'] ?? 0));
        $name = $this->limitText(trim((string) ($payload['name'] ?? '')), 24);
        if ($name === '') {
            return ['ok' => false, 'message' => '标签名称不能为空。'];
        }

        foreach ($tags as $tag) {
            if ((int) ($tag['id'] ?? 0) !== $tagId && (string) ($tag['name'] ?? '') === $name) {
                return ['ok' => false, 'message' => '标签名称已存在。'];
            }
        }

        $now = date('Y-m-d H:i:s');
        $tag = [
            'id' => $tagId > 0 ? $tagId : (empty($tags) ? 1 : ((int) max(array_column($tags, 'id')) + 1)),
            'name' => $name,
            'color' => preg_match('/^#[0-9a-fA-F]{6}$/', (string) ($payload['color'] ?? '')) === 1 ? (string) $payload['color'] : '#64748b',
            'status' => in_array((string) ($payload['status'] ?? 'active'), ['active', 'paused'], true) ? (string) $payload['status'] : 'active',
            'sort' => (int) ($payload['sort'] ?? 100),
            'updated_at' => $now,
        ];
        $replaced = false;
        foreach ($tags as &$item) {
            if ((int) ($item['id'] ?? 0) !== $tag['id']) {
                continue;
            }
            $tag['created_at'] = (string) ($item['created_at'] ?? $now);
            $item = $tag;
            $replaced = true;
            break;
        }
        unset($item);
        if (!$replaced) {
            $tag['created_at'] = $now;
            $tags[] = $tag;
        }

        $data['content_tags'] = $tags;
        $this->store->save($data);

        return ['ok' => true, 'tag' => $tag];
    }

    public function saveContentGroup(array $payload): array
    {
        $data = $this->store->load();
        $groups = array_values((array) ($data['content_groups'] ?? []));
        $groupId = max(0, (int) ($payload['group_id'] ?? 0));
        $name = $this->limitText(trim((string) ($payload['name'] ?? '')), 40);
        if ($name === '') {
            return ['ok' => false, 'message' => '分组名称不能为空。'];
        }

        $now = date('Y-m-d H:i:s');
        $group = [
            'id' => $groupId > 0 ? $groupId : (empty($groups) ? 1 : ((int) max(array_column($groups, 'id')) + 1)),
            'name' => $name,
            'description' => $this->limitText(trim((string) ($payload['description'] ?? '')), 120),
            'status' => in_array((string) ($payload['status'] ?? 'active'), ['active', 'paused'], true) ? (string) $payload['status'] : 'active',
            'sort' => (int) ($payload['sort'] ?? 100),
            'updated_at' => $now,
        ];
        $replaced = false;
        foreach ($groups as &$item) {
            if ((int) ($item['id'] ?? 0) !== $group['id']) {
                continue;
            }
            $group['created_at'] = (string) ($item['created_at'] ?? $now);
            $item = $group;
            $replaced = true;
            break;
        }
        unset($item);
        if (!$replaced) {
            $group['created_at'] = $now;
            $groups[] = $group;
        }

        $data['content_groups'] = $groups;
        $this->store->save($data);

        return ['ok' => true, 'group' => $group];
    }

    public function updateContentOps(array $payload): array
    {
        $data = $this->store->load();
        $contentType = in_array((string) ($payload['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $payload['content_type'] : 'drama';
        $contentId = max(0, (int) ($payload['content_id'] ?? 0));
        if ($contentId <= 0) {
            return ['ok' => false, 'message' => '请选择内容。'];
        }

        $groupIds = array_map(static fn (array $group): int => (int) ($group['id'] ?? 0), (array) ($data['content_groups'] ?? []));
        $groupId = max(0, (int) ($payload['group_id'] ?? 0));
        if ($groupId > 0 && !in_array($groupId, $groupIds, true)) {
            $groupId = 0;
        }
        $auditStatus = in_array((string) ($payload['audit_status'] ?? ''), ['draft', 'pending', 'approved', 'rejected', 'online', 'offline'], true)
            ? (string) $payload['audit_status']
            : 'draft';
        $tags = $this->contentTagsFromPayload($payload['tags'] ?? []);
        $now = date('Y-m-d H:i:s');
        $admin = $this->currentAdmin();
        $reviewedBy = (string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? ($_SESSION['admin_name'] ?? '管理员')));
        $listKey = $contentType === 'novel' ? 'novels' : 'dramas';

        foreach ($data[$listKey] as &$item) {
            if ((int) ($item['id'] ?? 0) !== $contentId) {
                continue;
            }
            $item['tags'] = $tags;
            $item['group_id'] = $groupId;
            $item['audit_status'] = $auditStatus;
            $item['audit_note'] = $this->limitText(trim((string) ($payload['audit_note'] ?? '')), 160);
            $item['reviewed_by'] = $reviewedBy;
            $item['reviewed_at'] = $now;
            if (in_array($auditStatus, ['online', 'offline', 'draft'], true)) {
                $item['status'] = $auditStatus;
            } elseif ($auditStatus === 'approved' && (string) ($item['status'] ?? 'draft') === 'draft') {
                $item['status'] = 'online';
            }
            $item['updated_at'] = $now;
            $this->store->save($data);

            return ['ok' => true, 'content' => $item];
        }
        unset($item);

        return ['ok' => false, 'message' => '内容不存在。'];
    }

    public function findOrder(string $orderNo, ?array $data = null): ?array
    {
        $orders = $data === null
            ? $this->orders()
            : array_map(fn (array $order): array => $this->normalizeOrderState($order), (array) ($data['orders'] ?? []));
        foreach ($orders as $order) {
            if ($order['order_no'] === $orderNo) {
                return $this->normalizeOrderState($order);
            }
        }

        return null;
    }

    public function userProfile(int $userId, ?array $data = null): ?array
    {
        if ($userId <= 0) {
            return null;
        }

        $data ??= $this->store->load();
        $user = null;
        foreach ((array) ($data['users'] ?? []) as $item) {
            if ((int) ($item['id'] ?? 0) === $userId) {
                $user = $item;
                break;
            }
        }
        if ($user === null) {
            return null;
        }

        $sourceOrders = array_map(fn (array $order): array => $this->normalizeOrderState($order), (array) ($data['orders'] ?? []));
        $orders = array_values(array_filter($sourceOrders, static fn (array $order): bool => (int) ($order['user_id'] ?? 0) === $userId && empty($order['is_test'])));
        usort($orders, static fn (array $a, array $b): int => strcmp((string) ($b['created_at'] ?? ''), (string) ($a['created_at'] ?? '')));

        $settledStatuses = ['paid', 'partial_refunded', 'refunded'];
        $paidOrders = array_values(array_filter($orders, static fn (array $order): bool => in_array((string) ($order['status'] ?? 'pending'), $settledStatuses, true)));
        $paidAmount = 0.0;
        $refundAmount = 0.0;
        foreach ($paidOrders as $order) {
            $amount = (float) ($order['amount'] ?? 0);
            $refund = min($amount, max(0.0, (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0)));
            $paidAmount += $amount;
            $refundAmount += $refund;
        }

        $firstOrder = $orders[array_key_last($orders)] ?? null;
        $latestOrder = $orders[0] ?? null;
        $firstPaidOrder = $paidOrders[array_key_last($paidOrders)] ?? null;
        $latestPaidOrder = $paidOrders[0] ?? null;
        $attributedOrder = null;
        foreach ($orders as $order) {
            if ((int) ($order['promotion_link_id'] ?? 0) > 0 || (string) ($order['promotion_code'] ?? '') !== '') {
                $attributedOrder = $order;
                break;
            }
        }

        $promotionEvents = array_values(array_filter((array) ($data['promotion_events'] ?? []), static fn (array $event): bool => (int) ($event['user_id'] ?? 0) === $userId));
        usort($promotionEvents, static fn (array $a, array $b): int => strcmp((string) ($b['created_at'] ?? ''), (string) ($a['created_at'] ?? '')));

        $contentEvents = array_values(array_filter((array) ($data['content_events'] ?? []), static fn (array $event): bool => (int) ($event['user_id'] ?? 0) === $userId));
        usort($contentEvents, static fn (array $a, array $b): int => strcmp((string) ($b['created_at'] ?? ''), (string) ($a['created_at'] ?? '')));

        $entitlements = $this->userEntitlements($userId);
        usort($entitlements, static fn (array $a, array $b): int => strcmp((string) ($b['granted_at'] ?? ''), (string) ($a['granted_at'] ?? '')));

        return [
            'user' => $user,
            'orders' => $orders,
            'paid_orders' => $paidOrders,
            'entitlements' => $entitlements,
            'coin_transactions' => array_slice(array_values(array_filter((array) ($data['coin_transactions'] ?? []), static fn (array $item): bool => (int) ($item['user_id'] ?? 0) === $userId)), 0, 30),
            'watch_history' => array_slice(array_values(array_filter((array) ($data['watch_history'] ?? []), static fn (array $item): bool => (int) ($item['user_id'] ?? 0) === $userId)), 0, 30),
            'followed_dramas' => array_slice(array_values(array_filter((array) ($data['followed_dramas'] ?? []), static fn (array $item): bool => (int) ($item['user_id'] ?? 0) === $userId)), 0, 30),
            'promotion_events' => array_slice($promotionEvents, 0, 30),
            'content_events' => array_slice($contentEvents, 0, 30),
            'summary' => [
                'order_count' => count($orders),
                'paid_order_count' => count($paidOrders),
                'gross_amount' => round($paidAmount, 2),
                'refund_amount' => round($refundAmount, 2),
                'net_amount' => round(max(0, $paidAmount - $refundAmount), 2),
                'entitlement_count' => count($entitlements),
                'coin_balance' => (int) ($user['coin_balance'] ?? 0),
                'bonus_coin_balance' => (int) ($user['bonus_coin_balance'] ?? 0),
                'first_order_at' => (string) ($firstOrder['created_at'] ?? ''),
                'latest_order_at' => (string) ($latestOrder['created_at'] ?? ''),
                'first_paid_at' => (string) ($firstPaidOrder['paid_at'] ?? $firstPaidOrder['created_at'] ?? ''),
                'latest_paid_at' => (string) ($latestPaidOrder['paid_at'] ?? $latestPaidOrder['created_at'] ?? ''),
            ],
            'attribution' => [
                'promotion_link_id' => (int) ($attributedOrder['promotion_link_id'] ?? 0),
                'promotion_code' => (string) ($attributedOrder['promotion_code'] ?? ''),
                'source' => (string) ($attributedOrder['traffic_source'] ?? ''),
                'campaign' => (string) ($attributedOrder['campaign'] ?? ''),
                'traffic_platform' => (string) ($attributedOrder['traffic_platform'] ?? ''),
                'channel_id' => (string) ($attributedOrder['channel_id'] ?? ''),
                'media_app_id' => (string) ($attributedOrder['media_app_id'] ?? ''),
                'ad_id' => (string) ($attributedOrder['ad_id'] ?? ''),
                'creative_id' => (string) ($attributedOrder['creative_id'] ?? ''),
                'material_id' => (string) ($attributedOrder['material_id'] ?? ''),
            ],
        ];
    }

