    public function frontDramas(?string $category = null): array
    {
        $category = trim((string) $category);
        $dramas = array_values(array_filter($this->dramas(), static function (array $drama) use ($category): bool {
            if (($drama['status'] ?? 'online') !== 'online') {
                return false;
            }

            return $category === '' || $category === '全部' || (string) ($drama['category'] ?? '') === $category;
        }));
        usort($dramas, static fn (array $a, array $b): int => [(int) ($b['sort'] ?? 0), (int) ($b['id'] ?? 0)] <=> [(int) ($a['sort'] ?? 0), (int) ($a['id'] ?? 0)]);

        return $dramas;
    }

