            return array_map(static fn (array $product): array => [
                'code' => (string) ($product['code'] ?? ''),
                'name' => (string) ($product['name'] ?? 'VIP 套餐'),
                'days' => max(1, (int) ($product['vip_days'] ?? 30)),
                'price' => round(max(0, (float) ($product['price'] ?? 0)), 2),
                'badge' => (string) (($product['badge'] ?? '') ?: ($product['description'] ?? '畅看权益')),
                'enabled' => !isset($product['enabled']) || !empty($product['enabled']),
            ], $products);
        }

        return array_values(array_filter($data['vip_plans'] ?? [], static fn (array $plan): bool => !isset($plan['enabled']) || !empty($plan['enabled'])));
    }

