    public function coinPackages(?string $appKey = null): array
    {
        $data = $this->store->load();
        $products = $this->rechargeProductsForApp($appKey, 'coin');
        if (!empty($products)) {
            $defaultCodes = array_map('strval', (array) ($this->rechargeProductTemplate($appKey)['product_codes'] ?? []));
            if (!empty($defaultCodes)) {
                $rank = array_flip($defaultCodes);
                usort($products, static fn (array $a, array $b): int => [isset($rank[(string) ($a['code'] ?? '')]) ? 0 : 1, $rank[(string) ($a['code'] ?? '')] ?? 9999, (int) ($a['sort'] ?? 0)] <=> [isset($rank[(string) ($b['code'] ?? '')]) ? 0 : 1, $rank[(string) ($b['code'] ?? '')] ?? 9999, (int) ($b['sort'] ?? 0)]);
            }
            $packages = array_map(static fn (array $product): array => [
                'code' => (string) ($product['code'] ?? ''),
                'name' => (string) ($product['name'] ?? 'K币套餐'),
                'coins' => max(0, (int) ($product['coins'] ?? 0)),
                'bonus_coins' => max(0, (int) ($product['bonus_coins'] ?? 0)),
                'price' => round(max(0, (float) ($product['price'] ?? 0)), 2),
                'badge' => (string) ($product['badge'] ?? ''),
                'enabled' => !isset($product['enabled']) || !empty($product['enabled']),
            ], $products);

            if (!empty($defaultCodes)) {
                $filtered = array_values(array_filter($packages, static fn (array $package): bool => in_array((string) ($package['code'] ?? ''), $defaultCodes, true)));
                return !empty($filtered) ? $filtered : $packages;
            }

            return $packages;
        }

        return array_values(array_filter($data['coin_packages'] ?? [], static fn (array $package): bool => !isset($package['enabled']) || !empty($package['enabled'])));
    }

    public function coinPackage(string $code, ?string $appKey = null): ?array
    {
        foreach ($this->coinPackages($appKey) as $package) {
            if ((string) ($package['code'] ?? '') === $code) {
                return $package;
            }
        }

        return null;
    }

    public function rechargeProducts(bool $enabledOnly = true): array
    {
        $products = array_values($this->store->load()['recharge_products'] ?? []);
        if ($enabledOnly) {
            $products = array_values(array_filter($products, static fn (array $product): bool => !isset($product['enabled']) || !empty($product['enabled'])));
        }
        usort($products, static fn (array $a, array $b): int => [(int) ($a['sort'] ?? 0), (float) ($a['price'] ?? 0)] <=> [(int) ($b['sort'] ?? 0), (float) ($b['price'] ?? 0)]);

        return $products;
    }

