            if ((string) ($product['code'] ?? '') === $code) {
                return $product;
            }
        }

        return null;
    }

    public function currentAppKey(array $payload = []): string
    {
        $attribution = $this->currentPromotionAttribution();
        $candidates = [
            $payload['app_key'] ?? '',
            $payload['media_app_id'] ?? '',
            $payload['app_id'] ?? '',
            $_POST['app_key'] ?? '',
            $_GET['app_key'] ?? '',
            $_POST['media_app_id'] ?? '',
            $_GET['media_app_id'] ?? '',
            $_POST['app_id'] ?? '',
            $_GET['app_id'] ?? '',
            $attribution['app_key'] ?? '',
            $attribution['media_app_id'] ?? '',
        ];

        foreach ($candidates as $candidate) {
            $appKey = $this->normalizeAppKey((string) $candidate);
            if ($appKey !== '') {
                $app = $this->appConfig($appKey);
                return (string) ($app['app_key'] ?? $appKey);
            }
        }

        return 'default';
    }

    public function rechargeProductTemplate(?string $appKey = null): array
    {
        $data = $this->store->load();
        $templates = array_values((array) ($data['recharge_config']['app_product_templates'] ?? []));
        $targetAppKey = $this->normalizeAppKey((string) ($appKey ?? $this->currentAppKey()));
        $targetAppKey = $targetAppKey !== '' ? $targetAppKey : 'default';
        $app = $this->appConfig($targetAppKey);
        $templateAppKey = $this->normalizeAppKey((string) ($app['product_template_key'] ?? ''));
        if ($templateAppKey !== '') {
            $targetAppKey = $templateAppKey;
        }
        $defaultTemplate = null;

        foreach ($templates as $template) {
            $templateKey = $this->normalizeAppKey((string) ($template['app_key'] ?? ''));
            if ($templateKey === 'default') {
                $defaultTemplate = $template;
            }
            if ($templateKey === $targetAppKey && (string) ($template['status'] ?? 'active') === 'active') {
                return $template;
            }
        }

        if (is_array($defaultTemplate)) {
            return $defaultTemplate;
        }

        return [
            'id' => 0,
            'name' => '默认应用模板',
            'app_key' => 'default',
            'app_name' => '默认应用',
            'product_codes' => array_values((array) ($data['recharge_config']['global_product_codes'] ?? [])),
            'retention_product_code' => (string) ($data['recharge_config']['retention_product_code'] ?? ''),
            'status' => 'active',
            'sort' => 0,
            'remark' => '',
        ];
    }

    public function rechargeProductsForApp(?string $appKey = null, ?string $type = null): array
    {
        $products = $this->rechargeProducts(true);
        if ($type !== null) {
            $products = array_values(array_filter($products, static fn (array $product): bool => (string) ($product['type'] ?? '') === $type));
        }

        $template = $this->rechargeProductTemplate($appKey);
        $codes = array_values(array_filter(array_map('strval', (array) ($template['product_codes'] ?? [])), static fn (string $code): bool => $code !== ''));
        if (empty($codes)) {
            return $products;
        }

        $rank = array_flip($codes);
        $matched = array_values(array_filter($products, static fn (array $product): bool => isset($rank[(string) ($product['code'] ?? '')])));
        if (empty($matched)) {
            return $products;
        }

        usort($matched, static fn (array $a, array $b): int => [
            $rank[(string) ($a['code'] ?? '')] ?? 9999,
            (int) ($a['sort'] ?? 0),
            (float) ($a['price'] ?? 0),
        ] <=> [
            $rank[(string) ($b['code'] ?? '')] ?? 9999,
            (int) ($b['sort'] ?? 0),
            (float) ($b['price'] ?? 0),
        ]);

        return $matched;
    }

    public function updateRechargeProduct(array $payload): void
    {
        $data = $this->store->load();
        $products = array_values((array) ($data['recharge_products'] ?? []));
        $code = preg_replace('/[^a-zA-Z0-9_-]+/', '', (string) ($payload['product_code'] ?? ''));
        $createNew = $code === '' || !empty($payload['create_new_product']);
        if ($createNew) {
            $pricePart = preg_replace('/\D+/', '', (string) ($payload['price'] ?? '')) ?: (string) (count($products) + 1);
            $code = strtolower((string) ($payload['type'] ?? 'coin')) . '_' . $pricePart . '_' . substr(sha1((string) microtime(true)), 0, 5);
        }

        $product = [
            'code' => $code,
            'name' => $this->limitText(trim((string) ($payload['name'] ?? '')) ?: '充值商品', 60),
            'type' => in_array((string) ($payload['type'] ?? ''), ['coin', 'vip', 'full_unlock'], true) ? (string) $payload['type'] : 'coin',
            'price' => round(max(0.01, (float) ($payload['price'] ?? 0)), 2),
            'coins' => max(0, (int) ($payload['coins'] ?? 0)),
            'bonus_coins' => max(0, (int) ($payload['bonus_coins'] ?? 0)),
            'vip_days' => max(0, (int) ($payload['vip_days'] ?? 0)),
            'unlock_count' => max(0, (int) ($payload['unlock_count'] ?? 0)),
            'badge' => $this->limitText(trim((string) ($payload['badge'] ?? '')), 20),
            'description' => $this->limitText(trim((string) ($payload['description'] ?? '')), 80),
            'is_recommended' => !empty($payload['is_recommended']),
            'enabled' => !empty($payload['enabled']),
            'sort' => (int) ($payload['sort'] ?? 100),
            'updated_at' => date('Y-m-d H:i:s'),
        ];
        if ($product['type'] === 'vip' && $product['vip_days'] <= 0) {
            $product['vip_days'] = 30;
        }
        if ($product['type'] === 'coin' && $product['coins'] <= 0) {
            $product['coins'] = max(1, (int) round($product['price'] * 100));
        }
        if ($product['type'] === 'full_unlock' && $product['unlock_count'] <= 0) {
            $product['unlock_count'] = 1;
        }

        $replaced = false;
        foreach ($products as &$item) {
            if ((string) ($item['code'] ?? '') === $code) {
                $product['created_at'] = (string) ($item['created_at'] ?? date('Y-m-d H:i:s'));
                $item = $product;
                $replaced = true;
                break;
            }
        }
        unset($item);
        if (!$replaced) {
            $product['created_at'] = date('Y-m-d H:i:s');
            $products[] = $product;
        }

        $data['recharge_products'] = $products;
        $this->syncRechargeLegacyPackages($data);
        $this->store->save($data);
    }

    public function updateRechargeConfig(array $payload): void
    {
        $data = $this->store->load();
        $enabledCodes = array_map(static fn (array $product): string => (string) ($product['code'] ?? ''), array_filter((array) ($data['recharge_products'] ?? []), static fn (array $product): bool => !empty($product['enabled'])));
        $globalCodes = array_values(array_intersect(array_map('strval', (array) ($payload['global_product_codes'] ?? [])), $enabledCodes));
        $retentionCode = (string) ($payload['retention_product_code'] ?? '');
        if (!in_array($retentionCode, $enabledCodes, true)) {
            $retentionCode = $globalCodes[0] ?? ($enabledCodes[0] ?? '');
        }

        $data['recharge_config'] = [
            'global_product_codes' => $globalCodes,
            'retention_product_code' => $retentionCode,
            'retention_once_per_user' => !empty($payload['retention_once_per_user']),
            'app_product_templates' => array_values((array) ($data['recharge_config']['app_product_templates'] ?? [])),
            'updated_at' => date('Y-m-d H:i:s'),
        ];
        $this->store->save($data);
    }

    public function updateRechargeTemplate(array $payload): array
    {
        $data = $this->store->load();
        $templates = array_values((array) ($data['recharge_config']['app_product_templates'] ?? []));
        $enabledCodes = array_map(static fn (array $product): string => (string) ($product['code'] ?? ''), array_filter((array) ($data['recharge_products'] ?? []), static fn (array $product): bool => !empty($product['enabled'])));
        $templateId = max(0, (int) ($payload['template_id'] ?? 0));
        $appKey = $this->normalizeAppKey((string) ($payload['app_key'] ?? ''));
        if ($appKey === '') {
            return ['ok' => false, 'message' => '应用标识不能为空。'];
        }

        $productCodes = array_values(array_intersect(array_map('strval', (array) ($payload['product_codes'] ?? [])), $enabledCodes));
        if (empty($productCodes)) {
            return ['ok' => false, 'message' => '请至少选择一个启用商品。'];
        }

        $retentionCode = (string) ($payload['retention_product_code'] ?? '');
        if (!in_array($retentionCode, $enabledCodes, true)) {
            $retentionCode = $productCodes[0] ?? '';
        }

        $now = date('Y-m-d H:i:s');
        $template = [
            'id' => $templateId > 0 ? $templateId : (empty($templates) ? 1 : ((int) max(array_column($templates, 'id')) + 1)),
            'name' => $this->limitText(trim((string) ($payload['name'] ?? '')) ?: '应用商品模板', 60),
            'app_key' => $appKey,
            'app_name' => $this->limitText(trim((string) ($payload['app_name'] ?? '')) ?: ($appKey === 'default' ? '默认应用' : $appKey), 60),
            'product_codes' => $productCodes,
            'retention_product_code' => $retentionCode,
            'status' => in_array((string) ($payload['status'] ?? 'active'), ['active', 'paused'], true) ? (string) $payload['status'] : 'active',
            'sort' => (int) ($payload['sort'] ?? 100),
            'remark' => $this->limitText(trim((string) ($payload['remark'] ?? '')), 120),
            'updated_at' => $now,
        ];

        foreach ($templates as $item) {
            if ((int) ($item['id'] ?? 0) === $template['id']) {
                continue;
            }
            if ($this->normalizeAppKey((string) ($item['app_key'] ?? '')) === $appKey) {
                return ['ok' => false, 'message' => '同一个应用标识只能配置一个商品模板。'];
            }
        }

        $replaced = false;
        foreach ($templates as &$item) {
            if ((int) ($item['id'] ?? 0) !== $template['id']) {
                continue;
            }
            $template['created_at'] = (string) ($item['created_at'] ?? $now);
            $item = $template;
            $replaced = true;
            break;
        }
        unset($item);

        if (!$replaced) {
            $template['created_at'] = $now;
            $templates[] = $template;
        }

        $data['recharge_config']['app_product_templates'] = $templates;
        $data['recharge_config']['updated_at'] = $now;
        $this->store->save($data);

        return ['ok' => true, 'template' => $template];
    }

    public function coinTransactions(?int $userId = null): array
    {
        $items = array_values($this->store->load()['coin_transactions'] ?? []);
        if ($userId !== null) {
            $items = array_values(array_filter($items, static fn (array $item): bool => (int) ($item['user_id'] ?? 0) === $userId));
        }
        usort($items, static fn (array $a, array $b): int => strcmp((string) ($b['created_at'] ?? ''), (string) ($a['created_at'] ?? '')));

        return $items;
    }

    public function saveRedeemCode(array $payload): array
    {
        $data = $this->store->load();
        $items = array_values((array) ($data['redeem_codes'] ?? []));
        $codeId = max(0, (int) ($payload['redeem_code_id'] ?? $payload['id'] ?? 0));
        $code = strtoupper((string) preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['code'] ?? ''))));
        if ($code === '') {
            $code = 'RC' . strtoupper(base_convert((string) time(), 10, 36));
        }
        foreach ($items as $item) {
            if ((int) ($item['id'] ?? 0) !== $codeId && strtoupper((string) ($item['code'] ?? '')) === $code) {
                return ['ok' => false, 'message' => '兑换码已存在。'];
            }
        }

        $name = $this->limitText(trim((string) ($payload['name'] ?? '')), 80);
        if ($name === '') {
            return ['ok' => false, 'message' => '兑换码名称不能为空。'];
        }

        $rewardType = (string) ($payload['reward_type'] ?? 'coin');
        $coinAmount = max(0, (int) ($payload['coin_amount'] ?? 0));
        $bonusCoinAmount = max(0, (int) ($payload['bonus_coin_amount'] ?? 0));
        $vipDays = max(0, (int) ($payload['vip_days'] ?? 0));
        if (!in_array($rewardType, ['coin', 'vip', 'mixed'], true)) {
            $rewardType = 'coin';
        }
        if ($rewardType === 'coin') {
            $vipDays = 0;
        } elseif ($rewardType === 'vip') {
            $coinAmount = 0;
            $bonusCoinAmount = 0;
        }
        if (($coinAmount + $bonusCoinAmount + $vipDays) <= 0) {
            return ['ok' => false, 'message' => '请至少配置 K币、赠币或 VIP 天数中的一种奖励。'];
        }

        $startedAt = $this->normalizeDateTime((string) ($payload['started_at'] ?? ''), '');
        $endedAt = $this->normalizeDateTime((string) ($payload['ended_at'] ?? ''), '');
        if ($startedAt !== '' && $endedAt !== '' && strtotime($endedAt) < strtotime($startedAt)) {
            return ['ok' => false, 'message' => '结束时间不能早于开始时间。'];
        }
        $scope = $this->redeemCodeScopeFromPayload($payload);

        $current = [];
        foreach ($items as $item) {
            if ((int) ($item['id'] ?? 0) === $codeId) {
                $current = $item;
                break;
            }
        }

        $appKey = $this->normalizeAppKey((string) ($payload['app_key'] ?? ''));
        if ($appKey === '') {
            $appKey = 'all';
        }
        $status = (string) ($payload['status'] ?? 'active');
        $now = date('Y-m-d H:i:s');
        $codeItem = [
            'id' => $codeId > 0 ? $codeId : (empty($items) ? 1 : ((int) max(array_column($items, 'id')) + 1)),
            'code' => $this->limitText($code, 40),
            'name' => $name,
            'status' => in_array($status, ['active', 'paused'], true) ? $status : 'active',
            'reward_type' => $rewardType,
            'coin_amount' => $coinAmount,
            'bonus_coin_amount' => $bonusCoinAmount,
            'vip_days' => $vipDays,
            'total_limit' => max(0, (int) ($payload['total_limit'] ?? 0)),
            'per_user_limit' => max(1, (int) ($payload['per_user_limit'] ?? 1)),
            'app_key' => $appKey,
            'promotion_code' => $scope['promotion_code'],
            'agent_id' => $scope['agent_id'],
            'channel_id' => $scope['channel_id'],
            'allowed_user_ids' => $scope['allowed_user_ids'],
            'source' => (string) ($current['source'] ?? 'manual'),
            'imported_at' => (string) ($current['imported_at'] ?? ''),
            'started_at' => $startedAt,
            'ended_at' => $endedAt,
            'remark' => $this->limitText(trim((string) ($payload['remark'] ?? '')), 160),
            'created_at' => (string) (($current['created_at'] ?? '') ?: $now),
            'updated_at' => $now,
        ];

        $replaced = false;
        foreach ($items as &$item) {
            if ((int) ($item['id'] ?? 0) !== (int) $codeItem['id']) {
                continue;
            }
            $item = $codeItem;
            $replaced = true;
            break;
        }
        unset($item);
        if (!$replaced) {
            $items[] = $codeItem;
        }

        $data['redeem_codes'] = $items;
        $this->store->save($data);

        return ['ok' => true, 'redeem_code' => $codeItem, 'message' => '兑换码已保存。'];
    }

    public function generateRedeemCodeBatch(array $payload): array
    {
        $count = max(1, min(1000, (int) ($payload['batch_count'] ?? $payload['count'] ?? 0)));
        $prefix = strtoupper((string) preg_replace('/[^a-zA-Z0-9]+/', '', trim((string) ($payload['batch_prefix'] ?? ''))));
        if ($prefix === '') {
            $prefix = 'RC';
        }
        $prefix = $this->limitText($prefix, 10);
        $batchName = $this->limitText(trim((string) ($payload['batch_name'] ?? $payload['name'] ?? '')), 80);
        if ($batchName === '') {
            return ['ok' => false, 'message' => '批量码包名称不能为空。'];
        }

        $rewardType = (string) ($payload['reward_type'] ?? 'coin');
        $coinAmount = max(0, (int) ($payload['coin_amount'] ?? 0));
        $bonusCoinAmount = max(0, (int) ($payload['bonus_coin_amount'] ?? 0));
        $vipDays = max(0, (int) ($payload['vip_days'] ?? 0));
        if (!in_array($rewardType, ['coin', 'vip', 'mixed'], true)) {
            $rewardType = 'coin';
        }
        if ($rewardType === 'coin') {
            $vipDays = 0;
        } elseif ($rewardType === 'vip') {
            $coinAmount = 0;
            $bonusCoinAmount = 0;
        }
        if (($coinAmount + $bonusCoinAmount + $vipDays) <= 0) {
            return ['ok' => false, 'message' => '请至少配置 K币、赠币或 VIP 天数中的一种奖励。'];
        }

        $startedAt = $this->normalizeDateTime((string) ($payload['started_at'] ?? ''), '');
        $endedAt = $this->normalizeDateTime((string) ($payload['ended_at'] ?? ''), '');
        if ($startedAt !== '' && $endedAt !== '' && strtotime($endedAt) < strtotime($startedAt)) {
            return ['ok' => false, 'message' => '结束时间不能早于开始时间。'];
        }
        $scope = $this->redeemCodeScopeFromPayload($payload, true);

        $data = $this->store->load();
        $items = array_values((array) ($data['redeem_codes'] ?? []));
        $existingCodes = [];
        $maxId = 0;
        foreach ($items as $item) {
            $existingCodes[strtoupper((string) ($item['code'] ?? ''))] = true;
            $maxId = max($maxId, (int) ($item['id'] ?? 0));
        }

        $appKey = $this->normalizeAppKey((string) ($payload['app_key'] ?? ''));
        if ($appKey === '') {
            $appKey = 'all';
        }
        $now = date('Y-m-d H:i:s');
        $batchNo = 'B' . date('YmdHis') . strtoupper(substr(bin2hex(random_bytes(3)), 0, 6));
        $remark = $this->limitText(trim((string) ($payload['remark'] ?? '')), 160);
        $created = [];
        for ($i = 0; $i < $count; $i++) {
            $code = $this->nextRedeemCodeForBatch($prefix, $existingCodes);
            $existingCodes[$code] = true;
            $created[] = [
                'id' => ++$maxId,
                'code' => $code,
                'name' => $batchName . '-' . str_pad((string) ($i + 1), 3, '0', STR_PAD_LEFT),
                'status' => 'active',
                'batch_no' => $batchNo,
                'batch_size' => $count,
                'is_single_use' => true,
                'source' => 'batch_generated',
                'imported_at' => '',
                'reward_type' => $rewardType,
                'coin_amount' => $coinAmount,
                'bonus_coin_amount' => $bonusCoinAmount,
                'vip_days' => $vipDays,
                'total_limit' => 1,
                'per_user_limit' => 1,
                'app_key' => $appKey,
                'promotion_code' => $scope['promotion_code'],
                'agent_id' => $scope['agent_id'],
                'channel_id' => $scope['channel_id'],
                'allowed_user_ids' => $scope['allowed_user_ids'],
                'started_at' => $startedAt,
                'ended_at' => $endedAt,
                'remark' => $remark,
                'created_at' => $now,
                'updated_at' => $now,
            ];
        }

        $data['redeem_codes'] = array_merge($items, $created);
        $this->store->save($data);

        return [
            'ok' => true,
            'message' => '批量兑换码已生成。',
            'batch_no' => $batchNo,
            'count' => count($created),
            'codes' => array_column($created, 'code'),
        ];
    }

    private function nextRedeemCodeForBatch(string $prefix, array $existingCodes): string
    {
        do {
            $code = $prefix . strtoupper(substr(bin2hex(random_bytes(6)), 0, 12));
        } while (isset($existingCodes[$code]));

        return $this->limitText($code, 40);
    }

    private function redeemCodeScopeFromPayload(array $payload, bool $batch = false): array
    {
        $prefix = $batch ? 'batch_' : '';
        $promotionCode = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload[$prefix . 'promotion_code'] ?? $payload['promotion_code'] ?? ''))) ?: '';
        $channelId = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload[$prefix . 'channel_id'] ?? $payload['channel_id'] ?? ''))) ?: '';
        $allowedUserIds = $payload[$prefix . 'allowed_user_ids'] ?? $payload['allowed_user_ids'] ?? [];
        if (is_string($allowedUserIds)) {
            $allowedUserIds = preg_split('/[\s,，|]+/u', $allowedUserIds) ?: [];
        }
        $users = [];
        foreach ((array) $allowedUserIds as $userId) {
            $id = max(0, (int) $userId);
            if ($id > 0 && !in_array($id, $users, true)) {
                $users[] = $id;
            }
        }

        return [
            'promotion_code' => $this->limitText((string) $promotionCode, 80),
            'agent_id' => max(0, (int) ($payload[$prefix . 'agent_id'] ?? $payload['agent_id'] ?? 0)),
            'channel_id' => $this->limitText((string) $channelId, 80),
            'allowed_user_ids' => array_slice($users, 0, 200),
        ];
    }

    public function importRedeemCodePool(array $payload): array
    {
        $fileResult = $this->redeemCodePoolTextFromUpload($payload['import_codes_file'] ?? $payload['codes_file'] ?? null);
        if (empty($fileResult['ok'])) {
            return ['ok' => false, 'message' => (string) ($fileResult['message'] ?? '外部码池文件读取失败。')];
        }
        $rawTextParts = [
            trim((string) ($payload['import_codes'] ?? $payload['codes'] ?? '')),
            trim((string) ($fileResult['text'] ?? '')),
        ];
        $rawText = trim(implode("\n", array_filter($rawTextParts, static fn (string $text): bool => $text !== '')));
        if ($rawText === '') {
            return ['ok' => false, 'message' => '请粘贴兑换码或上传 TXT/CSV 码池文件。'];
        }

        $batchName = $this->limitText(trim((string) ($payload['import_batch_name'] ?? $payload['batch_name'] ?? $payload['name'] ?? '')), 80);
        if ($batchName === '') {
            return ['ok' => false, 'message' => '导入码包名称不能为空。'];
        }

        $rewardType = (string) ($payload['reward_type'] ?? 'coin');
        $coinAmount = max(0, (int) ($payload['coin_amount'] ?? 0));
        $bonusCoinAmount = max(0, (int) ($payload['bonus_coin_amount'] ?? 0));
        $vipDays = max(0, (int) ($payload['vip_days'] ?? 0));
        if (!in_array($rewardType, ['coin', 'vip', 'mixed'], true)) {
            $rewardType = 'coin';
        }
        if ($rewardType === 'coin') {
            $vipDays = 0;
        } elseif ($rewardType === 'vip') {
            $coinAmount = 0;
            $bonusCoinAmount = 0;
        }
        if (($coinAmount + $bonusCoinAmount + $vipDays) <= 0) {
            return ['ok' => false, 'message' => '请至少配置 K币、赠币或 VIP 天数中的一种奖励。'];
        }

        $startedAt = $this->normalizeDateTime((string) ($payload['started_at'] ?? ''), '');
        $endedAt = $this->normalizeDateTime((string) ($payload['ended_at'] ?? ''), '');
        if ($startedAt !== '' && $endedAt !== '' && strtotime($endedAt) < strtotime($startedAt)) {
            return ['ok' => false, 'message' => '结束时间不能早于开始时间。'];
        }

        $parsed = $this->parseRedeemCodePoolText($rawText);
        if (empty($parsed)) {
            return ['ok' => false, 'message' => '没有解析到合法兑换码。'];
        }
        $parsed = array_slice($parsed, 0, 1000, true);

        $data = $this->store->load();
        $items = array_values((array) ($data['redeem_codes'] ?? []));
        $existingCodes = [];
        $maxId = 0;
        foreach ($items as $item) {
            $existingCodes[strtoupper((string) ($item['code'] ?? ''))] = true;
            $maxId = max($maxId, (int) ($item['id'] ?? 0));
        }

        $appKey = $this->normalizeAppKey((string) ($payload['app_key'] ?? ''));
        if ($appKey === '') {
            $appKey = 'all';
        }
        $scope = $this->redeemCodeScopeFromPayload($payload, true);
        $now = date('Y-m-d H:i:s');
        $batchNo = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['import_batch_no'] ?? $payload['batch_no'] ?? '')));
        if ($batchNo === '') {
            $batchNo = 'I' . date('YmdHis') . strtoupper(substr(bin2hex(random_bytes(3)), 0, 6));
        }
        $baseBatchNo = $batchNo;
        $suffix = 2;
        $existingBatchNos = array_fill_keys(array_map(static fn (array $item): string => (string) ($item['batch_no'] ?? ''), $items), true);
        while (isset($existingBatchNos[$batchNo])) {
            $batchNo = $baseBatchNo . '-' . $suffix;
            $suffix++;
        }

        $remark = $this->limitText(trim((string) ($payload['remark'] ?? '')), 160);
        $created = [];
        $skippedDuplicate = 0;
        foreach ($parsed as $code => $lineName) {
            if (isset($existingCodes[$code])) {
                $skippedDuplicate++;
                continue;
            }
            $existingCodes[$code] = true;
            $name = $this->limitText(trim((string) $lineName), 80);
            if ($name === '') {
                $name = $batchName . '-' . str_pad((string) (count($created) + 1), 3, '0', STR_PAD_LEFT);
            }
            $created[] = [
                'id' => ++$maxId,
                'code' => $this->limitText($code, 40),
                'name' => $name,
                'status' => 'active',
                'batch_no' => $batchNo,
                'batch_size' => 0,
                'is_single_use' => true,
                'source' => 'external_import',
                'imported_at' => $now,
                'import_file_name' => (string) ($fileResult['file_name'] ?? ''),
                'import_file_size' => (int) ($fileResult['file_size'] ?? 0),
                'reward_type' => $rewardType,
                'coin_amount' => $coinAmount,
                'bonus_coin_amount' => $bonusCoinAmount,
                'vip_days' => $vipDays,
                'total_limit' => 1,
                'per_user_limit' => 1,
                'app_key' => $appKey,
                'promotion_code' => $scope['promotion_code'],
                'agent_id' => $scope['agent_id'],
                'channel_id' => $scope['channel_id'],
                'allowed_user_ids' => $scope['allowed_user_ids'],
                'started_at' => $startedAt,
                'ended_at' => $endedAt,
                'remark' => $remark,
                'created_at' => $now,
                'updated_at' => $now,
            ];
        }

        if (empty($created)) {
            return ['ok' => false, 'message' => '导入失败：兑换码均已存在。', 'skipped_duplicate' => $skippedDuplicate];
        }
        $batchSize = count($created);
        foreach ($created as &$item) {
            $item['batch_size'] = $batchSize;
        }
        unset($item);

        $data['redeem_codes'] = array_merge($items, $created);
        $this->store->save($data);

        return [
            'ok' => true,
            'message' => '外部兑换码已导入。',
            'batch_no' => $batchNo,
            'count' => count($created),
            'skipped_duplicate' => $skippedDuplicate,
            'codes' => array_column($created, 'code'),
        ];
    }

    private function redeemCodePoolTextFromUpload(mixed $file): array
    {
        if (!is_array($file) || (int) ($file['error'] ?? UPLOAD_ERR_NO_FILE) === UPLOAD_ERR_NO_FILE) {
            return ['ok' => true, 'text' => '', 'file_name' => '', 'file_size' => 0];
        }

        $error = (int) ($file['error'] ?? UPLOAD_ERR_OK);
        if ($error !== UPLOAD_ERR_OK) {
            return ['ok' => false, 'message' => '码池文件上传失败，错误码：' . $error . '。'];
        }

        $tmpName = (string) ($file['tmp_name'] ?? '');
        if ($tmpName === '' || !is_file($tmpName)) {
            return ['ok' => false, 'message' => '码池文件不存在。'];
        }

        $size = max(0, (int) ($file['size'] ?? filesize($tmpName) ?: 0));
        if ($size <= 0) {
            return ['ok' => false, 'message' => '码池文件为空。'];
        }
        if ($size > 2 * 1024 * 1024) {
            return ['ok' => false, 'message' => '码池文件不能超过 2MB。'];
        }

        $originalName = $this->limitText(trim(basename((string) ($file['name'] ?? 'codes.txt'))), 160);
        $extension = strtolower(pathinfo($originalName, PATHINFO_EXTENSION));
        if (!in_array($extension, ['txt', 'csv'], true)) {
            return ['ok' => false, 'message' => '码池文件仅支持 TXT 或 CSV。'];
        }

        $text = file_get_contents($tmpName);
        if ($text === false) {
            return ['ok' => false, 'message' => '码池文件读取失败。'];
        }
        $text = preg_replace('/^\\xEF\\xBB\\xBF/', '', $text) ?? $text;

        return [
            'ok' => true,
            'text' => $text,
            'file_name' => $originalName,
            'file_size' => $size,
        ];
    }

    private function parseRedeemCodePoolText(string $rawText): array
    {
        $rows = preg_split('/\R/u', $rawText) ?: [];
        $codes = [];
        foreach ($rows as $line) {
            $line = trim((string) $line);
            if ($line === '') {
                continue;
            }
            $parts = str_getcsv($line, ',', '"', '');
            if (count($parts) >= 2) {
                $code = strtoupper((string) preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($parts[0] ?? ''))));
                $secondAsCode = strtoupper((string) preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($parts[1] ?? ''))));
                if ($code !== '' && strlen($code) >= 3 && ($secondAsCode === '' || $secondAsCode !== strtoupper(trim((string) ($parts[1] ?? ''))))) {
                    $codes[$code] = trim((string) ($parts[1] ?? ''));
                    continue;
                }
            }
            foreach (preg_split('/[\s,，;；|]+/u', $line) ?: [] as $token) {
                $code = strtoupper((string) preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) $token)));
                if ($code !== '' && strlen($code) >= 3) {
                    $codes[$code] = '';
                }
            }
        }

        return $codes;
    }

