    public function activityFunnelDashboard(array $activities = [], array $logs = []): array
    {
        $activityById = [];
        $activityByCode = [];
        foreach (array_values($activities) as $activity) {
            if (!is_array($activity)) {
                continue;
            }
            $activityById[(int) ($activity['id'] ?? 0)] = $activity;
            $activityByCode[(string) ($activity['code'] ?? '')] = $activity;
        }

        $rows = [];
        $summary = [
            'exposure' => 0,
            'click' => 0,
            'claim_success' => 0,
            'claim_failed' => 0,
            'experiment_count' => 0,
            'variant_count' => 0,
            'tier_count' => 0,
            'budget_limited_count' => 0,
            'budget_exhausted_count' => 0,
            'budget_auto_paused_count' => 0,
            'click_rate' => 0.0,
            'claim_rate' => 0.0,
        ];
        $tierLabels = [
            'new' => '新客',
            'unpaid' => '未付费',
            'paid' => '已付费',
            'member' => '会员',
            'unknown' => '未识别人群',
        ];
        $tierRows = [];
        foreach (array_values($logs) as $log) {
            if (!is_array($log)) {
                continue;
            }
            $eventType = (string) ($log['event_type'] ?? 'claim');
            if (!in_array($eventType, ['exposure', 'click', 'claim'], true)) {
                $eventType = 'claim';
            }
            $activityId = (int) ($log['activity_id'] ?? 0);
            $activityCode = (string) ($log['activity_code'] ?? '');
            $activity = $activityById[$activityId] ?? $activityByCode[$activityCode] ?? [];
            $experimentKey = $this->normalizeActivityExperimentKey((string) (($log['experiment_key'] ?? '') ?: ($activity['experiment_key'] ?? '')));
            $variantKey = $this->normalizeActivityVariantKey((string) (($log['variant_key'] ?? '') ?: ($activity['variant_key'] ?? '')));
            $rowKey = ($activityId > 0 ? 'id:' . $activityId : 'code:' . $activityCode) . '|exp:' . $experimentKey . '|var:' . $variantKey;
            $context = is_array($log['context'] ?? null) ? (array) $log['context'] : [];
            $tierKey = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($context['user_tier'] ?? ''))) ?: 'unknown';
            if (!isset($tierLabels[$tierKey])) {
                $tierKey = 'unknown';
            }
            $rows[$rowKey] ??= [
                'activity_id' => $activityId,
                'activity_code' => $activityCode,
                'activity_name' => (string) (($log['activity_name'] ?? '') ?: ($activity['name'] ?? '活动')),
                'activity_type' => (string) (($log['activity_type'] ?? '') ?: ($activity['activity_type'] ?? 'general')),
                'app_key' => (string) ($log['app_key'] ?? ($activity['app_key'] ?? 'default')),
                'experiment_key' => $experimentKey,
                'variant_key' => $variantKey,
                'traffic_percent' => max(0, min(100, (int) ($activity['traffic_percent'] ?? 100))),
                'exposure' => 0,
                'click' => 0,
                'claim_success' => 0,
                'claim_failed' => 0,
                'click_rate' => 0.0,
                'claim_rate' => 0.0,
                'latest_at' => '',
            ];
            $tierRows[$tierKey] ??= [
                'user_tier' => $tierKey,
                'tier_name' => $tierLabels[$tierKey],
                'exposure' => 0,
                'click' => 0,
                'claim_success' => 0,
                'claim_failed' => 0,
                'unique_users' => 0,
                'user_ids' => [],
                'click_rate' => 0.0,
                'claim_rate' => 0.0,
                'fail_rate' => 0.0,
                'latest_at' => '',
            ];
            $userId = max(0, (int) ($log['user_id'] ?? 0));
            if ($userId > 0) {
                $tierRows[$tierKey]['user_ids'][$userId] = true;
            }
            if ($eventType === 'exposure' && (string) ($log['status'] ?? 'tracked') !== 'failed') {
                $rows[$rowKey]['exposure']++;
                $tierRows[$tierKey]['exposure']++;
                $summary['exposure']++;
            } elseif ($eventType === 'click' && (string) ($log['status'] ?? 'tracked') !== 'failed') {
                $rows[$rowKey]['click']++;
                $tierRows[$tierKey]['click']++;
                $summary['click']++;
            } elseif ($eventType === 'claim') {
                if ((string) ($log['status'] ?? '') === 'success') {
                    $rows[$rowKey]['claim_success']++;
                    $tierRows[$tierKey]['claim_success']++;
                    $summary['claim_success']++;
                } elseif ((string) ($log['status'] ?? '') === 'failed') {
                    $rows[$rowKey]['claim_failed']++;
                    $tierRows[$tierKey]['claim_failed']++;
                    $summary['claim_failed']++;
                }
            }
            if (strcmp((string) ($log['created_at'] ?? ''), (string) ($rows[$rowKey]['latest_at'] ?? '')) > 0) {
                $rows[$rowKey]['latest_at'] = (string) ($log['created_at'] ?? '');
            }
            if (strcmp((string) ($log['created_at'] ?? ''), (string) ($tierRows[$tierKey]['latest_at'] ?? '')) > 0) {
                $tierRows[$tierKey]['latest_at'] = (string) ($log['created_at'] ?? '');
            }
        }

        $experimentKeys = [];
        $variantKeys = [];
        foreach ($rows as &$row) {
            $exposure = max(0, (int) ($row['exposure'] ?? 0));
            $click = max(0, (int) ($row['click'] ?? 0));
            $claimSuccess = max(0, (int) ($row['claim_success'] ?? 0));
            $row['click_rate'] = $exposure > 0 ? round($click / $exposure * 100, 2) : 0.0;
            $row['claim_rate'] = $click > 0 ? round($claimSuccess / $click * 100, 2) : 0.0;
            if ((string) ($row['experiment_key'] ?? '') !== '') {
                $experimentKeys[(string) $row['experiment_key']] = true;
                $variantKeys[(string) $row['experiment_key'] . ':' . (string) ($row['variant_key'] ?? '')] = true;
            }
        }
        unset($row);
        foreach ($tierRows as &$tierRow) {
            $exposure = max(0, (int) ($tierRow['exposure'] ?? 0));
            $click = max(0, (int) ($tierRow['click'] ?? 0));
            $claimSuccess = max(0, (int) ($tierRow['claim_success'] ?? 0));
            $claimFailed = max(0, (int) ($tierRow['claim_failed'] ?? 0));
            $claimTotal = $claimSuccess + $claimFailed;
            $tierRow['unique_users'] = count((array) ($tierRow['user_ids'] ?? []));
            unset($tierRow['user_ids']);
            $tierRow['click_rate'] = $exposure > 0 ? round($click / $exposure * 100, 2) : 0.0;
            $tierRow['claim_rate'] = $click > 0 ? round($claimSuccess / $click * 100, 2) : 0.0;
            $tierRow['fail_rate'] = $claimTotal > 0 ? round($claimFailed / $claimTotal * 100, 2) : 0.0;
        }
        unset($tierRow);
        $summary['experiment_count'] = count($experimentKeys);
        $summary['variant_count'] = count($variantKeys);
        $summary['tier_count'] = count($tierRows);
        $summary['click_rate'] = $summary['exposure'] > 0 ? round($summary['click'] / $summary['exposure'] * 100, 2) : 0.0;
        $summary['claim_rate'] = $summary['click'] > 0 ? round($summary['claim_success'] / $summary['click'] * 100, 2) : 0.0;
        $rows = array_values($rows);
        usort($rows, static fn (array $a, array $b): int => strcmp((string) ($b['latest_at'] ?? ''), (string) ($a['latest_at'] ?? '')));
        $tierRows = array_values($tierRows);
        usort($tierRows, static fn (array $a, array $b): int => [(int) ($b['claim_success'] ?? 0), (float) ($b['claim_rate'] ?? 0), (int) ($b['click'] ?? 0)] <=> [(int) ($a['claim_success'] ?? 0), (float) ($a['claim_rate'] ?? 0), (int) ($a['click'] ?? 0)]);
        $budgetRows = [];
        foreach (array_values($activities) as $activity) {
            if (!is_array($activity)) {
                continue;
            }
            $budget = $this->activityBudgetState($activity, $logs);
            if ((int) ($budget['limit'] ?? 0) > 0) {
                $summary['budget_limited_count']++;
            }
            if (!empty($budget['exhausted'])) {
                $summary['budget_exhausted_count']++;
            }
            if (!empty($activity['auto_pause_on_budget']) && (string) ($activity['status'] ?? 'active') === 'paused' && (string) ($activity['budget_auto_paused_at'] ?? '') !== '') {
                $summary['budget_auto_paused_count']++;
            }
            $budgetRows[] = [
                'activity_id' => (int) ($activity['id'] ?? 0),
                'activity_code' => (string) ($activity['code'] ?? ''),
                'activity_name' => (string) ($activity['name'] ?? '活动'),
                'status' => (string) ($activity['status'] ?? 'active'),
                'budget_limit' => (int) ($budget['limit'] ?? 0),
                'budget_used' => (int) ($budget['used'] ?? 0),
                'budget_remaining' => (int) ($budget['remaining'] ?? 0),
                'budget_usage_rate' => (float) ($budget['usage_rate'] ?? 0),
                'auto_pause_on_budget' => !empty($activity['auto_pause_on_budget']),
                'budget_auto_paused_at' => (string) ($activity['budget_auto_paused_at'] ?? ''),
                'budget_auto_paused_reason' => (string) ($activity['budget_auto_paused_reason'] ?? ''),
            ];
        }
        usort($budgetRows, static fn (array $a, array $b): int => [(int) ($b['budget_limit'] ?? 0), (float) ($b['budget_usage_rate'] ?? 0)] <=> [(int) ($a['budget_limit'] ?? 0), (float) ($a['budget_usage_rate'] ?? 0)]);

        return [
            'summary' => $summary,
            'rows' => array_slice($rows, 0, 200),
            'tier_rows' => $tierRows,
            'budget_rows' => array_slice($budgetRows, 0, 500),
            'recommendations' => $this->activityFunnelRecommendations($summary, $tierRows),
        ];
    }

    private function activityBudgetState(array $activity, array $logs, int $projectedCost = 0): array
    {
        $limit = max(0, (int) ($activity['budget_coin_limit'] ?? 0));
        $used = 0;
        foreach (array_values($logs) as $log) {
            if (!is_array($log) || !$this->activityLogMatchesActivity($activity, $log)) {
                continue;
            }
            if ((string) ($log['event_type'] ?? 'claim') !== 'claim' || (string) ($log['status'] ?? '') !== 'success') {
                continue;
            }
            $used += $this->activityLogBudgetCost($activity, $log);
        }

        $remaining = $limit > 0 ? max(0, $limit - $used) : 0;
        return [
            'limit' => $limit,
            'used' => $used,
            'remaining' => $remaining,
            'projected_cost' => max(0, $projectedCost),
            'projected_used' => $used + max(0, $projectedCost),
            'usage_rate' => $limit > 0 ? round(min(999.99, $used / max(1, $limit) * 100), 2) : 0.0,
            'projected_usage_rate' => $limit > 0 ? round(min(999.99, ($used + max(0, $projectedCost)) / max(1, $limit) * 100), 2) : 0.0,
            'exhausted' => $limit > 0 && $used >= $limit,
            'will_exceed' => $limit > 0 && $projectedCost > 0 && ($used + $projectedCost) > $limit,
        ];
    }

    private function activityLogMatchesActivity(array $activity, array $log): bool
    {
        $activityId = (int) ($activity['id'] ?? 0);
        if ($activityId > 0 && (int) ($log['activity_id'] ?? 0) === $activityId) {
            return true;
        }

        $activityCode = (string) ($activity['code'] ?? '');
        return $activityCode !== '' && (string) ($log['activity_code'] ?? '') === $activityCode;
    }

    private function activityLogBudgetCost(array $activity, array $log): int
    {
        $context = is_array($log['context'] ?? null) ? (array) $log['context'] : [];
        if (array_key_exists('budget_cost', $context)) {
            return max(0, (int) $context['budget_cost']);
        }

        $coins = max(0, (int) ($log['coin_amount'] ?? 0)) + max(0, (int) ($log['bonus_coin_amount'] ?? 0));
        $vipDays = max(0, (int) ($log['vip_days'] ?? 0));
        return $coins + ($vipDays * $this->activityVipDayBudgetCoins($activity));
    }

    private function activityProjectedBudgetCost(array $activity, array $data): int
    {
        $rewardType = (string) ($activity['reward_type'] ?? 'none');
        if ($rewardType === 'coin') {
            return max(0, (int) ($activity['coin_amount'] ?? 0));
        }
        if ($rewardType === 'vip') {
            return max(0, (int) ($activity['vip_days'] ?? 0)) * $this->activityVipDayBudgetCoins($activity);
        }
        if ($rewardType === 'redeem_code') {
            $codeItem = $this->findItemById((array) ($data['redeem_codes'] ?? []), max(0, (int) ($activity['redeem_code_id'] ?? 0)));
            if (empty($codeItem)) {
                return 0;
            }
            $coins = max(0, (int) ($codeItem['coin_amount'] ?? 0)) + max(0, (int) ($codeItem['bonus_coin_amount'] ?? 0));
            $vipDays = max(0, (int) ($codeItem['vip_days'] ?? 0));
            return $coins + ($vipDays * $this->activityVipDayBudgetCoins($activity));
        }

        return 0;
    }

    private function activityVipDayBudgetCoins(array $activity): int
    {
        return max(0, (int) ($activity['vip_day_budget_coins'] ?? 100));
    }

    private function pauseActivityForBudget(array &$data, array $activity, string $now, string $reason): void
    {
        $data['activity_configs'] ??= [];
        foreach ($data['activity_configs'] as &$item) {
            if (!is_array($item) || !$this->activityLogMatchesActivity($item, [
                'activity_id' => (int) ($activity['id'] ?? 0),
                'activity_code' => (string) ($activity['code'] ?? ''),
            ])) {
                continue;
            }
            $item['status'] = 'paused';
            $item['budget_auto_paused_at'] = $now;
            $item['budget_auto_paused_reason'] = $this->limitText($reason, 160);
            $item['updated_at'] = $now;
            break;
        }
        unset($item);
    }

    private function activityFunnelRecommendations(array $summary, array $tierRows): array
    {
        if (empty($tierRows)) {
            return ['暂无足够活动数据，先确认客户端已上报曝光、点击和领奖事件。'];
        }

        $suggestions = [];
        if ((int) ($summary['exposure'] ?? 0) > 0 && (int) ($summary['click'] ?? 0) === 0) {
            $suggestions[] = '活动有曝光但没有点击，优先检查入口文案、位置和活动利益点是否足够明确。';
        }
        if ((int) ($summary['click'] ?? 0) > 0 && (int) ($summary['claim_success'] ?? 0) === 0) {
            $suggestions[] = '活动有点击但没有领奖成功，优先检查领奖接口、奖励配置、库存和用户次数限制。';
        }

        $clickCandidates = array_values(array_filter($tierRows, static fn (array $row): bool => (int) ($row['exposure'] ?? 0) >= 10));
        usort($clickCandidates, static fn (array $a, array $b): int => [(float) ($b['click_rate'] ?? 0), (int) ($b['exposure'] ?? 0)] <=> [(float) ($a['click_rate'] ?? 0), (int) ($a['exposure'] ?? 0)]);
        if (!empty($clickCandidates) && (float) ($clickCandidates[0]['click_rate'] ?? 0) > 0) {
            $suggestions[] = (string) ($clickCandidates[0]['tier_name'] ?? '目标人群') . '点击率最高，适合优先放大入口曝光或作为下一轮活动主投人群。';
        }

        $claimCandidates = array_values(array_filter($tierRows, static fn (array $row): bool => (int) ($row['click'] ?? 0) >= 5));
        usort($claimCandidates, static fn (array $a, array $b): int => [(float) ($b['claim_rate'] ?? 0), (int) ($b['claim_success'] ?? 0)] <=> [(float) ($a['claim_rate'] ?? 0), (int) ($a['claim_success'] ?? 0)]);
        if (!empty($claimCandidates) && (float) ($claimCandidates[0]['claim_rate'] ?? 0) > 0) {
            $suggestions[] = (string) ($claimCandidates[0]['tier_name'] ?? '目标人群') . '领奖转化最好，可考虑给该人群配置更高价值奖励或单独活动版本。';
        }

        $failureRows = array_values(array_filter($tierRows, static fn (array $row): bool => (int) ($row['claim_failed'] ?? 0) >= 3 && (float) ($row['fail_rate'] ?? 0) >= 50));
        usort($failureRows, static fn (array $a, array $b): int => [(float) ($b['fail_rate'] ?? 0), (int) ($b['claim_failed'] ?? 0)] <=> [(float) ($a['fail_rate'] ?? 0), (int) ($a['claim_failed'] ?? 0)]);
        if (!empty($failureRows)) {
            $suggestions[] = (string) ($failureRows[0]['tier_name'] ?? '目标人群') . '领奖失败率偏高，建议检查人群限制、每日上限、总库存和活动有效期。';
        }

        if (empty($suggestions)) {
            $suggestions[] = '当前活动漏斗未发现明显异常，可继续积累样本后再比较不同人群和版本。';
        }

        return array_slice(array_values(array_unique($suggestions)), 0, 4);
    }

    public function recordActivityEvent(array $payload = [], ?int $userId = null): array
    {
        $data = $this->store->load();
        $data['activity_participation_logs'] ??= [];
        $now = date('Y-m-d H:i:s');
        $userId = max(0, (int) ($userId ?? $this->currentUserId()));
        $appKey = $this->currentAppKey($payload);
        $activityId = max(0, (int) ($payload['activity_id'] ?? $payload['id'] ?? 0));
        $activityCode = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['activity_code'] ?? $payload['code'] ?? '')));
        $eventType = (string) ($payload['event'] ?? $payload['event_type'] ?? 'exposure');
        $eventType = in_array($eventType, ['exposure', 'click'], true) ? $eventType : 'exposure';
        $context = [
            'source' => $this->limitText(trim((string) ($payload['source'] ?? 'api')), 40),
            'trigger' => $this->limitText(trim((string) ($payload['trigger'] ?? '')), 40),
            'slot' => $this->limitText(trim((string) ($payload['slot'] ?? '')), 40),
            'content_type' => $this->limitText(trim((string) ($payload['content_type'] ?? '')), 20),
            'content_id' => max(0, (int) ($payload['content_id'] ?? 0)),
        ];

        $activity = null;
        foreach ((array) ($data['activity_configs'] ?? []) as $item) {
            $sameId = $activityId > 0 && (int) ($item['id'] ?? 0) === $activityId;
            $sameCode = $activityCode !== '' && (string) ($item['code'] ?? '') === $activityCode;
            if ($sameId || $sameCode) {
                $activity = $item;
                break;
            }
        }
        if (!is_array($activity)) {
            $message = '活动不存在。';
            $this->appendActivityParticipationLog($data, [], $userId, $appKey, 'failed', $message, $context, $now, ['event_type' => $eventType]);
            $this->store->save($data);
            return ['ok' => false, 'message' => $message];
        }
        if (!$this->operationItemActiveForApp($activity, $appKey, $now)) {
            $message = '活动未开始、已结束、已停用或不适用于当前应用。';
            $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'failed', $message, $context, $now, ['event_type' => $eventType]);
            $this->store->save($data);
            return ['ok' => false, 'message' => $message];
        }
        $app = $this->appConfig($appKey) ?? [];
        $userTier = $this->resolveAppUserTier($app, $userId);
        if (!$this->activityMatchesUserTier($activity, $userTier)) {
            $message = '该活动不适用于当前用户人群。';
            $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'failed', $message, $context + ['user_tier' => (string) ($userTier['key'] ?? '')], $now, ['event_type' => $eventType]);
            $this->store->save($data);
            return ['ok' => false, 'message' => $message, 'current_user_tier' => $userTier];
        }
        $eligibleActivities = array_values(array_filter((array) ($data['activity_configs'] ?? []), fn (array $item): bool => $this->operationItemActiveForApp($item, $appKey, $now) && $this->activityMatchesUserTier($item, $userTier)));
        if (!$this->activityVisibleInExperiment($activity, $eligibleActivities, $appKey, $userId)) {
            $message = '该活动版本不适用于当前用户分组。';
            $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'failed', $message, $context + ['user_tier' => (string) ($userTier['key'] ?? '')], $now, ['event_type' => $eventType]);
            $this->store->save($data);
            return ['ok' => false, 'message' => $message, 'current_user_tier' => $userTier];
        }

        $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'tracked', $eventType === 'click' ? '活动点击已记录。' : '活动曝光已记录。', $context + ['user_tier' => (string) ($userTier['key'] ?? '')], $now, ['event_type' => $eventType]);
        $data['activity_participation_logs'] = array_slice(array_values((array) ($data['activity_participation_logs'] ?? [])), -10000);
        $this->store->save($data);

        return [
            'ok' => true,
            'message' => $eventType === 'click' ? '活动点击已记录。' : '活动曝光已记录。',
            'event_type' => $eventType,
            'activity' => $this->publicActivityConfig($activity),
        ];
    }

    public function repairUserRights(array $payload): array
    {
        $data = $this->store->load();
        $data['rights_repair_logs'] ??= [];
        $data['coin_transactions'] ??= [];
        $data['entitlements'] ??= [];

        $now = date('Y-m-d H:i:s');
        $userId = max(0, (int) ($payload['user_id'] ?? 0));
        $action = (string) ($payload['rights_action'] ?? $payload['action'] ?? '');
        $allowedActions = ['grant_coin', 'deduct_coin', 'grant_vip', 'revoke_vip', 'grant_content', 'revoke_content'];
        if (!in_array($action, $allowedActions, true)) {
            $action = 'grant_coin';
        }
        $contentType = in_array((string) ($payload['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $payload['content_type'] : 'drama';
        $entitlementType = (string) ($payload['entitlement_type'] ?? '');
        $coins = max(0, (int) ($payload['coins'] ?? 0));
        $bonusCoins = max(0, (int) ($payload['bonus_coins'] ?? 0));
        $vipDays = max(0, (int) ($payload['vip_days'] ?? 0));
        $dramaId = max(0, (int) ($payload['drama_id'] ?? 0));
        $episodeId = max(0, (int) ($payload['episode_id'] ?? 0));
        $novelId = max(0, (int) ($payload['novel_id'] ?? 0));
        $chapterId = max(0, (int) ($payload['chapter_id'] ?? 0));
        $remark = $this->limitText(trim((string) ($payload['remark'] ?? '')), 240);

        $userIndex = null;
        foreach ((array) ($data['users'] ?? []) as $index => $user) {
            if ((int) ($user['id'] ?? 0) === $userId) {
                $userIndex = $index;
                break;
            }
        }

        $beforeSnapshot = $userIndex !== null ? $this->rightsRepairSnapshot($data, $userId) : [];
        $result = ['ok' => false, 'message' => '用户不存在。'];

        if ($userId <= 0 || $userIndex === null) {
            $this->appendRightsRepairLog($data, [
                'user_id' => $userId,
                'action' => $action,
                'content_type' => $contentType,
                'drama_id' => $dramaId,
                'episode_id' => $episodeId > 0 ? $episodeId : null,
                'novel_id' => $novelId,
                'chapter_id' => $chapterId > 0 ? $chapterId : null,
                'coins' => $coins,
                'bonus_coins' => $bonusCoins,
                'vip_days' => $vipDays,
                'entitlement_type' => $entitlementType,
                'status' => 'failed',
                'message' => $result['message'],
                'before_snapshot' => $beforeSnapshot,
                'after_snapshot' => [],
                'remark' => $remark,
                'created_at' => $now,
            ]);
            $this->store->save($data);

            return $result;
        }

        switch ($action) {
            case 'grant_coin':
                $result = $this->repairGrantCoins($data, $userIndex, $userId, $coins, $bonusCoins, $remark, $now);
                break;
            case 'deduct_coin':
                $result = $this->repairDeductCoins($data, $userIndex, $userId, $coins, $bonusCoins, $remark, $now);
                break;
            case 'grant_vip':
                $result = $this->repairGrantVip($data, $userIndex, $userId, $vipDays, $remark, $now);
                $entitlementType = 'membership';
                break;
            case 'revoke_vip':
                $result = $this->repairRevokeVip($data, $userIndex, $userId);
                $entitlementType = 'membership';
                break;
            case 'grant_content':
                $result = $this->repairGrantContent($data, $userId, $contentType, $dramaId, $episodeId, $novelId, $chapterId, $entitlementType, $remark, $now);
                $entitlementType = (string) ($result['entitlement_type'] ?? $entitlementType);
                break;
            case 'revoke_content':
                $result = $this->repairRevokeContent($data, $userId, $contentType, $dramaId, $episodeId, $novelId, $chapterId, $entitlementType);
                $entitlementType = (string) ($result['entitlement_type'] ?? $entitlementType);
                break;
        }

        $afterSnapshot = $this->rightsRepairSnapshot($data, $userId);
        $this->appendRightsRepairLog($data, [
            'user_id' => $userId,
            'action' => $action,
            'content_type' => $contentType,
            'drama_id' => $dramaId,
            'episode_id' => $episodeId > 0 ? $episodeId : null,
            'novel_id' => $novelId,
            'chapter_id' => $chapterId > 0 ? $chapterId : null,
            'coins' => in_array($action, ['deduct_coin'], true) ? -$coins : $coins,
            'bonus_coins' => in_array($action, ['deduct_coin'], true) ? -$bonusCoins : $bonusCoins,
            'vip_days' => $vipDays,
            'entitlement_type' => $entitlementType,
            'status' => !empty($result['ok']) ? 'success' : 'failed',
            'message' => (string) ($result['message'] ?? ''),
            'before_snapshot' => $beforeSnapshot,
            'after_snapshot' => $afterSnapshot,
            'remark' => $remark,
            'created_at' => $now,
        ]);
        if (!empty($result['ok'])) {
            $admin = $this->currentAdmin();
            $contentName = match ($action) {
                'grant_coin', 'deduct_coin' => (($coins + $bonusCoins) > 0 ? (($coins + $bonusCoins) . ' K币') : 'K币权益'),
                'grant_vip', 'revoke_vip' => $vipDays > 0 ? ($vipDays . ' 天 VIP') : 'VIP 权益',
                default => $this->contentTitleFromData($data, $contentType, $dramaId, $novelId),
            };
            $this->appendUserInAppMessageFromTemplate($data, $userId, 'rights_repair_notice', [
                'action' => $this->rightsRepairActionLabel($action),
                'message' => (string) ($result['message'] ?? ''),
                'content' => $contentName,
                'coins' => (string) ($coins + $bonusCoins),
                'vip_days' => (string) $vipDays,
                'remark' => $remark,
            ], [
                'source' => 'rights_repair',
                'reference_type' => 'rights_repair',
                'reference_id' => 0,
                'priority' => in_array($action, ['deduct_coin', 'revoke_vip', 'revoke_content'], true) ? 'high' : 'normal',
                'title' => '权益变更：' . $this->rightsRepairActionLabel($action),
                'body' => trim((string) ($result['message'] ?? '') . ' ' . $contentName . ' ' . $remark),
                'sender_admin_id' => (int) ($admin['id'] ?? 0),
                'sender_admin_name' => (string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? '管理员')),
                'created_at' => $now,
                'updated_at' => $now,
            ]);
        }
        $this->store->save($data);

        return $result;
    }

    private function repairGrantCoins(array &$data, int $userIndex, int $userId, int $coins, int $bonusCoins, string $remark, string $now): array
    {
        if (($coins + $bonusCoins) <= 0) {
            return ['ok' => false, 'message' => '补发 K币或赠币数量必须大于 0。'];
        }

        $data['users'][$userIndex]['coin_balance'] = max(0, (int) ($data['users'][$userIndex]['coin_balance'] ?? 0)) + $coins;
        $data['users'][$userIndex]['bonus_coin_balance'] = max(0, (int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0)) + $bonusCoins;
        $this->appendCoinTransaction($data, [
            'user_id' => $userId,
            'type' => 'adjustment',
            'scene' => 'rights_repair',
            'coins' => $coins + $bonusCoins,
            'coin_amount' => $coins,
            'bonus_coin_amount' => $bonusCoins,
            'balance_after' => $this->userTotalCoinBalance($data['users'][$userIndex]),
            'remark' => $remark !== '' ? $remark : '后台权益补发 K币',
            'created_at' => $now,
        ]);

        return ['ok' => true, 'message' => 'K币权益已补发。'];
    }

    private function repairDeductCoins(array &$data, int $userIndex, int $userId, int $coins, int $bonusCoins, string $remark, string $now): array
    {
        if (($coins + $bonusCoins) <= 0) {
            return ['ok' => false, 'message' => '扣减 K币或赠币数量必须大于 0。'];
        }

        $currentCoins = max(0, (int) ($data['users'][$userIndex]['coin_balance'] ?? 0));
        $currentBonusCoins = max(0, (int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0));
        if ($coins > $currentCoins || $bonusCoins > $currentBonusCoins) {
            return ['ok' => false, 'message' => '用户余额不足，不能扣成负数。'];
        }

        $data['users'][$userIndex]['coin_balance'] = $currentCoins - $coins;
        $data['users'][$userIndex]['bonus_coin_balance'] = $currentBonusCoins - $bonusCoins;
        $this->appendCoinTransaction($data, [
            'user_id' => $userId,
            'type' => 'adjustment',
            'scene' => 'rights_repair',
            'coins' => -($coins + $bonusCoins),
            'coin_amount' => -$coins,
            'bonus_coin_amount' => -$bonusCoins,
            'balance_after' => $this->userTotalCoinBalance($data['users'][$userIndex]),
            'remark' => $remark !== '' ? $remark : '后台权益扣减 K币',
            'created_at' => $now,
        ]);

        return ['ok' => true, 'message' => 'K币权益已扣减。'];
    }

    private function repairGrantVip(array &$data, int $userIndex, int $userId, int $vipDays, string $remark, string $now): array
    {
        if ($vipDays <= 0) {
            return ['ok' => false, 'message' => 'VIP 补发天数必须大于 0。'];
        }

        $currentExpiresAt = strtotime((string) ($data['users'][$userIndex]['membership_expires_at'] ?? '')) ?: time();
        $base = max(time(), $currentExpiresAt);
        $data['users'][$userIndex]['membership'] = true;
        $data['users'][$userIndex]['membership_expires_at'] = date('Y-m-d H:i:s', $base + $vipDays * 86400);
        $data['entitlements'][] = [
            'user_id' => $userId,
            'content_type' => 'drama',
            'drama_id' => 0,
            'episode_id' => null,
            'novel_id' => 0,
            'chapter_id' => null,
            'type' => 'membership',
            'source' => 'rights_repair',
            'remark' => $remark,
            'granted_at' => $now,
        ];

        return ['ok' => true, 'message' => 'VIP 天数已补发。'];
    }

    private function repairRevokeVip(array &$data, int $userIndex, int $userId): array
    {
        $data['users'][$userIndex]['membership'] = false;
        $data['users'][$userIndex]['membership_expires_at'] = null;
        $data['entitlements'] = array_values(array_filter((array) ($data['entitlements'] ?? []), static fn (array $item): bool => !(
            (int) ($item['user_id'] ?? 0) === $userId && (string) ($item['type'] ?? '') === 'membership'
        )));

        return ['ok' => true, 'message' => 'VIP 权益已撤销。'];
    }

    private function repairGrantContent(array &$data, int $userId, string $contentType, int $dramaId, int $episodeId, int $novelId, int $chapterId, string $entitlementType, string $remark, string $now): array
    {
        if ($contentType === 'novel') {
            $entitlementType = in_array($entitlementType, ['novel_unlock', 'novel_chapter_unlock'], true) ? $entitlementType : ($chapterId > 0 ? 'novel_chapter_unlock' : 'novel_unlock');
            if ($novelId <= 0 || ($entitlementType === 'novel_chapter_unlock' && $chapterId <= 0)) {
                return ['ok' => false, 'message' => '请填写小说ID；章节权益还需要章节ID。', 'entitlement_type' => $entitlementType];
            }
            $dramaId = 0;
            $episodeId = 0;
        } else {
            $entitlementType = in_array($entitlementType, ['drama_unlock', 'episode_unlock'], true) ? $entitlementType : ($episodeId > 0 ? 'episode_unlock' : 'drama_unlock');
            if ($dramaId <= 0 || ($entitlementType === 'episode_unlock' && $episodeId <= 0)) {
                return ['ok' => false, 'message' => '请填写短剧ID；单集权益还需要分集ID。', 'entitlement_type' => $entitlementType];
            }
            $novelId = 0;
            $chapterId = 0;
        }

        $episodeValue = $entitlementType === 'drama_unlock' || $contentType === 'novel' ? null : $episodeId;
        $chapterValue = $entitlementType === 'novel_unlock' || $contentType === 'drama' ? null : $chapterId;
        foreach ((array) ($data['entitlements'] ?? []) as $item) {
            if ($this->sameEntitlement($item, $userId, $contentType, $dramaId, $episodeValue, $novelId, $chapterValue, $entitlementType)) {
                return ['ok' => false, 'message' => '该用户已拥有对应内容权益。', 'entitlement_type' => $entitlementType];
            }
        }

        $data['entitlements'][] = [
            'user_id' => $userId,
            'content_type' => $contentType,
            'drama_id' => $dramaId,
            'episode_id' => $episodeValue,
            'novel_id' => $novelId,
            'chapter_id' => $chapterValue,
            'type' => $entitlementType,
            'source' => 'rights_repair',
            'remark' => $remark,
            'granted_at' => $now,
        ];

        return ['ok' => true, 'message' => '内容权益已补发。', 'entitlement_type' => $entitlementType];
    }

    private function repairRevokeContent(array &$data, int $userId, string $contentType, int $dramaId, int $episodeId, int $novelId, int $chapterId, string $entitlementType): array
    {
        if ($contentType === 'novel') {
            $entitlementType = in_array($entitlementType, ['novel_unlock', 'novel_chapter_unlock'], true) ? $entitlementType : ($chapterId > 0 ? 'novel_chapter_unlock' : 'novel_unlock');
            if ($novelId <= 0 || ($entitlementType === 'novel_chapter_unlock' && $chapterId <= 0)) {
                return ['ok' => false, 'message' => '请填写小说ID；章节权益还需要章节ID。', 'entitlement_type' => $entitlementType];
            }
            $dramaId = 0;
            $episodeId = 0;
        } else {
            $entitlementType = in_array($entitlementType, ['drama_unlock', 'episode_unlock'], true) ? $entitlementType : ($episodeId > 0 ? 'episode_unlock' : 'drama_unlock');
            if ($dramaId <= 0 || ($entitlementType === 'episode_unlock' && $episodeId <= 0)) {
                return ['ok' => false, 'message' => '请填写短剧ID；单集权益还需要分集ID。', 'entitlement_type' => $entitlementType];
            }
            $novelId = 0;
            $chapterId = 0;
        }

        $episodeValue = $entitlementType === 'drama_unlock' || $contentType === 'novel' ? null : $episodeId;
        $chapterValue = $entitlementType === 'novel_unlock' || $contentType === 'drama' ? null : $chapterId;
        $beforeCount = count((array) ($data['entitlements'] ?? []));
        $data['entitlements'] = array_values(array_filter((array) ($data['entitlements'] ?? []), function (array $item) use ($userId, $contentType, $dramaId, $episodeValue, $novelId, $chapterValue, $entitlementType): bool {
            return !$this->sameEntitlement($item, $userId, $contentType, $dramaId, $episodeValue, $novelId, $chapterValue, $entitlementType);
        }));
        $removed = $beforeCount - count((array) ($data['entitlements'] ?? []));

        if ($removed <= 0) {
            return ['ok' => false, 'message' => '未找到可撤销的内容权益。', 'entitlement_type' => $entitlementType];
        }

        return ['ok' => true, 'message' => '内容权益已撤销。', 'entitlement_type' => $entitlementType, 'removed_count' => $removed];
    }

    private function appendRightsRepairLog(array &$data, array $log): void
    {
        $logs = array_values((array) ($data['rights_repair_logs'] ?? []));
        $admin = $this->currentAdmin();
        $logs[] = [
            'id' => empty($logs) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $logs)) + 1),
            'user_id' => max(0, (int) ($log['user_id'] ?? 0)),
            'action' => (string) ($log['action'] ?? ''),
            'content_type' => (string) ($log['content_type'] ?? 'drama'),
            'drama_id' => max(0, (int) ($log['drama_id'] ?? 0)),
            'episode_id' => empty($log['episode_id']) ? null : max(0, (int) $log['episode_id']),
            'novel_id' => max(0, (int) ($log['novel_id'] ?? 0)),
            'chapter_id' => empty($log['chapter_id']) ? null : max(0, (int) $log['chapter_id']),
            'coins' => (int) ($log['coins'] ?? 0),
            'bonus_coins' => (int) ($log['bonus_coins'] ?? 0),
            'vip_days' => max(0, (int) ($log['vip_days'] ?? 0)),
            'entitlement_type' => (string) ($log['entitlement_type'] ?? ''),
            'status' => (string) ($log['status'] ?? 'success') === 'failed' ? 'failed' : 'success',
            'message' => $this->limitText(trim((string) ($log['message'] ?? '')), 200),
            'admin_id' => (int) ($admin['id'] ?? ($_SESSION['admin_id'] ?? 0)),
            'admin_name' => $this->limitText((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? ($_SESSION['admin_name'] ?? '管理员'))), 60),
            'before_snapshot' => is_array($log['before_snapshot'] ?? null) ? $log['before_snapshot'] : [],
            'after_snapshot' => is_array($log['after_snapshot'] ?? null) ? $log['after_snapshot'] : [],
            'remark' => $this->limitText(trim((string) ($log['remark'] ?? '')), 240),
            'created_at' => trim((string) ($log['created_at'] ?? '')) ?: date('Y-m-d H:i:s'),
        ];
        $data['rights_repair_logs'] = array_slice($logs, -10000);
    }

    private function appendCoinTransaction(array &$data, array $transaction): void
    {
        $items = array_values((array) ($data['coin_transactions'] ?? []));
        $items[] = [
            'id' => empty($items) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $items)) + 1),
            'user_id' => max(0, (int) ($transaction['user_id'] ?? 0)),
            'type' => (string) ($transaction['type'] ?? 'adjustment'),
            'scene' => (string) ($transaction['scene'] ?? 'rights_repair'),
            'coins' => (int) ($transaction['coins'] ?? 0),
            'coin_amount' => (int) ($transaction['coin_amount'] ?? 0),
            'bonus_coin_amount' => (int) ($transaction['bonus_coin_amount'] ?? 0),
            'balance_after' => max(0, (int) ($transaction['balance_after'] ?? 0)),
            'remark' => $this->limitText(trim((string) ($transaction['remark'] ?? '')), 160),
            'created_at' => trim((string) ($transaction['created_at'] ?? '')) ?: date('Y-m-d H:i:s'),
        ];
        $data['coin_transactions'] = array_slice($items, -10000);
    }

    private function rightsRepairSnapshot(array $data, int $userId): array
    {
        $user = [];
        foreach ((array) ($data['users'] ?? []) as $item) {
            if ((int) ($item['id'] ?? 0) === $userId) {
                $user = $item;
                break;
            }
        }

        $entitlements = array_values(array_filter((array) ($data['entitlements'] ?? []), static fn (array $item): bool => (int) ($item['user_id'] ?? 0) === $userId));

        return [
            'coin_balance' => max(0, (int) ($user['coin_balance'] ?? 0)),
            'bonus_coin_balance' => max(0, (int) ($user['bonus_coin_balance'] ?? 0)),
            'membership' => !empty($user['membership']),
            'membership_expires_at' => $user['membership_expires_at'] ?? null,
            'entitlement_count' => count($entitlements),
        ];
    }

    private function userTotalCoinBalance(array $user): int
    {
        return max(0, (int) ($user['coin_balance'] ?? 0)) + max(0, (int) ($user['bonus_coin_balance'] ?? 0));
    }

    private function sameEntitlement(array $item, int $userId, string $contentType, int $dramaId, ?int $episodeId, int $novelId, ?int $chapterId, string $entitlementType): bool
    {
        $itemContentType = in_array((string) ($item['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $item['content_type'] : 'drama';

        return (int) ($item['user_id'] ?? 0) === $userId
            && $itemContentType === $contentType
            && (int) ($item['drama_id'] ?? 0) === $dramaId
            && (int) ($item['episode_id'] ?? 0) === (int) ($episodeId ?? 0)
            && (int) ($item['novel_id'] ?? 0) === $novelId
            && (int) ($item['chapter_id'] ?? 0) === (int) ($chapterId ?? 0)
            && (string) ($item['type'] ?? '') === $entitlementType;
    }

    public function claimActivityReward(array $payload = [], ?int $userId = null): array
    {
        $data = $this->store->load();
        $data['activity_participation_logs'] ??= [];
        $data['coin_transactions'] ??= [];
        $data['entitlements'] ??= [];
        $data['redeem_code_logs'] ??= [];

        $now = date('Y-m-d H:i:s');
        $today = date('Y-m-d');
        $userId = max(0, (int) ($userId ?? $this->currentUserId()));
        $appKey = $this->currentAppKey($payload);
        $activityId = max(0, (int) ($payload['activity_id'] ?? $payload['id'] ?? 0));
        $activityCode = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['activity_code'] ?? $payload['code'] ?? '')));
        $context = [
            'source' => $this->limitText(trim((string) ($payload['source'] ?? 'api')), 40),
            'trigger' => $this->limitText(trim((string) ($payload['trigger'] ?? '')), 40),
            'content_type' => $this->limitText(trim((string) ($payload['content_type'] ?? '')), 20),
            'content_id' => max(0, (int) ($payload['content_id'] ?? 0)),
            'order_no' => $this->limitText(trim((string) ($payload['order_no'] ?? '')), 80),
        ];

        $activity = null;
        foreach ((array) ($data['activity_configs'] ?? []) as $item) {
            $sameId = $activityId > 0 && (int) ($item['id'] ?? 0) === $activityId;
            $sameCode = $activityCode !== '' && (string) ($item['code'] ?? '') === $activityCode;
            if ($sameId || $sameCode) {
                $activity = $item;
                break;
            }
        }

        $userIndex = null;
        foreach ((array) ($data['users'] ?? []) as $index => $user) {
            if ((int) ($user['id'] ?? 0) === $userId) {
                $userIndex = $index;
                break;
            }
        }

        if (!is_array($activity)) {
            $message = '活动不存在。';
            $this->appendActivityParticipationLog($data, [], $userId, $appKey, 'failed', $message, $context, $now);
            $this->store->save($data);
            return ['ok' => false, 'message' => $message];
        }
        if ($userId <= 0 || $userIndex === null) {
            $message = '用户不存在，请先登录。';
            $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'failed', $message, $context, $now);
            $this->store->save($data);
            return ['ok' => false, 'message' => $message];
        }
        if (!$this->operationItemActiveForApp($activity, $appKey, $now)) {
            $message = '活动未开始、已结束、已停用或不适用于当前应用。';
            $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'failed', $message, $context, $now);
            $this->store->save($data);
            return ['ok' => false, 'message' => $message];
        }
        $app = $this->appConfig($appKey) ?? [];
        $userTier = $this->resolveAppUserTier($app, $userId);
        $context['user_tier'] = (string) ($userTier['key'] ?? '');
        if (!$this->activityMatchesUserTier($activity, $userTier)) {
            $message = '该活动不适用于当前用户人群。';
            $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'failed', $message, $context + ['user_tier' => (string) ($userTier['key'] ?? '')], $now);
            $this->store->save($data);
            return ['ok' => false, 'message' => $message, 'current_user_tier' => $userTier];
        }
        $eligibleActivities = array_values(array_filter((array) ($data['activity_configs'] ?? []), fn (array $item): bool => $this->operationItemActiveForApp($item, $appKey, $now) && $this->activityMatchesUserTier($item, $userTier)));
        if (!$this->activityVisibleInExperiment($activity, $eligibleActivities, $appKey, $userId)) {
            $message = '该活动版本不适用于当前用户分组。';
            $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'failed', $message, $context + ['user_tier' => (string) ($userTier['key'] ?? '')], $now);
            $this->store->save($data);
            return ['ok' => false, 'message' => $message, 'current_user_tier' => $userTier];
        }

        $limitMessage = $this->activityLimitFailureReason($activity, (array) ($data['activity_participation_logs'] ?? []), $userId, $today);
        if ($limitMessage !== '') {
            $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'failed', $limitMessage, $context, $now);
            $this->store->save($data);
            return ['ok' => false, 'message' => $limitMessage];
        }

        $projectedBudgetCost = $this->activityProjectedBudgetCost($activity, $data);
        $budgetState = $this->activityBudgetState($activity, (array) ($data['activity_participation_logs'] ?? []), $projectedBudgetCost);
        if (!empty($budgetState['will_exceed'])) {
            $message = '活动权益预算不足，已停止本次领取。';
            $context['budget_cost'] = $projectedBudgetCost;
            $context['budget_used'] = (int) ($budgetState['used'] ?? 0);
            $context['budget_limit'] = (int) ($budgetState['limit'] ?? 0);
            if (!empty($activity['auto_pause_on_budget'])) {
                $this->pauseActivityForBudget($data, $activity, $now, $message);
                $message = '活动权益预算不足，活动已自动停用。';
            }
            $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'failed', $message, $context, $now);
            $this->store->save($data);
            return ['ok' => false, 'message' => $message, 'budget' => $budgetState];
        }

        $rewardType = (string) ($activity['reward_type'] ?? 'none');
        $coinAmount = 0;
        $bonusCoinAmount = 0;
        $vipDays = 0;
        $redeemCodeId = 0;
        $message = '活动参与成功。';

        if ($rewardType === 'coin') {
            $coinAmount = max(0, (int) ($activity['coin_amount'] ?? 0));
            if ($coinAmount <= 0) {
                $message = '活动 K币奖励配置无效。';
                $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'failed', $message, $context, $now);
                $this->store->save($data);
                return ['ok' => false, 'message' => $message];
            }
            $data['users'][$userIndex]['bonus_coin_balance'] = max(0, (int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0)) + $coinAmount;
            $bonusCoinAmount = $coinAmount;
            $this->appendCoinTransaction($data, [
                'user_id' => $userId,
                'type' => 'reward',
                'scene' => 'activity_reward',
                'coins' => $coinAmount,
                'coin_amount' => 0,
                'bonus_coin_amount' => $coinAmount,
                'balance_after' => $this->userTotalCoinBalance($data['users'][$userIndex]),
                'remark' => '活动奖励：' . (string) ($activity['name'] ?? $activity['code'] ?? '活动'),
                'created_at' => $now,
            ]);
            $message = '活动奖励已发放。';
        } elseif ($rewardType === 'vip') {
            $vipDays = max(0, (int) ($activity['vip_days'] ?? 0));
            if ($vipDays <= 0) {
                $message = '活动 VIP 奖励配置无效。';
                $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'failed', $message, $context, $now);
                $this->store->save($data);
                return ['ok' => false, 'message' => $message];
            }
            $currentExpiresAt = strtotime((string) ($data['users'][$userIndex]['membership_expires_at'] ?? '')) ?: time();
            $base = max(time(), $currentExpiresAt);
            $data['users'][$userIndex]['membership'] = true;
            $data['users'][$userIndex]['membership_expires_at'] = date('Y-m-d H:i:s', $base + $vipDays * 86400);
            $data['entitlements'][] = [
                'user_id' => $userId,
                'content_type' => 'drama',
                'drama_id' => 0,
                'episode_id' => null,
                'novel_id' => 0,
                'chapter_id' => null,
                'type' => 'membership',
                'source' => 'activity_reward',
                'source_activity_id' => (int) ($activity['id'] ?? 0),
                'source_activity_code' => (string) ($activity['code'] ?? ''),
                'granted_at' => $now,
            ];
            $message = '活动 VIP 奖励已发放。';
        } elseif ($rewardType === 'redeem_code') {
            $redeemCodeId = max(0, (int) ($activity['redeem_code_id'] ?? 0));
            $codeItem = $this->findItemById((array) ($data['redeem_codes'] ?? []), $redeemCodeId);
            if (empty($codeItem)) {
                $message = '活动关联兑换码不存在。';
                $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'failed', $message, $context, $now);
                $this->store->save($data);
                return ['ok' => false, 'message' => $message];
            }
            $code = strtoupper((string) ($codeItem['code'] ?? ''));
            $failMessage = $this->redeemCodeFailureReason($codeItem, (array) ($data['redeem_code_logs'] ?? []), $userId, $appKey, $now, $context);
            if ($failMessage !== '') {
                $this->appendRedeemCodeLog($data, $codeItem, $code, $userId, $appKey, 'failed', $failMessage, $now);
                $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'failed', $failMessage, $context, $now);
                $this->store->save($data);
                return ['ok' => false, 'message' => $failMessage];
            }
            $coinAmount = max(0, (int) ($codeItem['coin_amount'] ?? 0));
            $bonusCoinAmount = max(0, (int) ($codeItem['bonus_coin_amount'] ?? 0));
            $vipDays = max(0, (int) ($codeItem['vip_days'] ?? 0));
            if (($coinAmount + $bonusCoinAmount + $vipDays) <= 0) {
                $message = '活动兑换码奖励配置无效。';
                $this->appendRedeemCodeLog($data, $codeItem, $code, $userId, $appKey, 'failed', $message, $now);
                $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'failed', $message, $context, $now);
                $this->store->save($data);
                return ['ok' => false, 'message' => $message];
            }
            $data['users'][$userIndex]['coin_balance'] = max(0, (int) ($data['users'][$userIndex]['coin_balance'] ?? 0)) + $coinAmount;
            $data['users'][$userIndex]['bonus_coin_balance'] = max(0, (int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0)) + $bonusCoinAmount;
            if ($vipDays > 0) {
                $currentExpiresAt = strtotime((string) ($data['users'][$userIndex]['membership_expires_at'] ?? '')) ?: time();
                $base = max(time(), $currentExpiresAt);
                $data['users'][$userIndex]['membership'] = true;
                $data['users'][$userIndex]['membership_expires_at'] = date('Y-m-d H:i:s', $base + $vipDays * 86400);
                $data['entitlements'][] = [
                    'user_id' => $userId,
                    'content_type' => 'drama',
                    'drama_id' => 0,
                    'episode_id' => null,
                    'type' => 'membership',
                    'source_redeem_code' => $code,
                    'source_activity_id' => (int) ($activity['id'] ?? 0),
                    'granted_at' => $now,
                ];
            }
            if (($coinAmount + $bonusCoinAmount) > 0) {
                $this->appendCoinTransaction($data, [
                    'user_id' => $userId,
                    'type' => 'reward',
                    'scene' => 'activity_redeem_code',
                    'coins' => $coinAmount + $bonusCoinAmount,
                    'coin_amount' => $coinAmount,
                    'bonus_coin_amount' => $bonusCoinAmount,
                    'balance_after' => $this->userTotalCoinBalance($data['users'][$userIndex]),
                    'remark' => '活动兑换码奖励：' . (string) ($activity['name'] ?? $code),
                    'created_at' => $now,
                ]);
            }
            $this->appendRedeemCodeLog($data, $codeItem, $code, $userId, $appKey, 'success', '活动奖励兑换成功。', $now);
            $message = '活动兑换码奖励已发放。';
        } elseif ($rewardType !== 'none') {
            $message = '活动奖励类型无效。';
            $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'failed', $message, $context, $now);
            $this->store->save($data);
            return ['ok' => false, 'message' => $message];
        }

        if ($projectedBudgetCost > 0) {
            $context['budget_cost'] = $projectedBudgetCost;
            $context['budget_used_before'] = (int) ($budgetState['used'] ?? 0);
            $context['budget_limit'] = (int) ($budgetState['limit'] ?? 0);
        }
        $this->appendActivityParticipationLog($data, $activity, $userId, $appKey, 'success', $message, $context, $now, [
            'coin_amount' => $coinAmount,
            'bonus_coin_amount' => $bonusCoinAmount,
            'vip_days' => $vipDays,
            'redeem_code_id' => $redeemCodeId,
            'reward_type' => $rewardType,
        ]);
        $rewardText = $this->activityRewardText($rewardType, $coinAmount, $bonusCoinAmount, $vipDays);
        $this->appendUserInAppMessageFromTemplate($data, $userId, 'activity_reward_notice', [
            'activity_name' => (string) ($activity['name'] ?? $activity['code'] ?? '活动'),
            'message' => $message,
            'reward_type' => $rewardType,
            'reward_text' => $rewardText,
        ], [
            'source' => 'activity',
            'reference_type' => 'activity',
            'reference_id' => (int) ($activity['id'] ?? 0),
            'priority' => 'normal',
            'title' => '活动奖励：' . (string) ($activity['name'] ?? $activity['code'] ?? '活动'),
            'body' => trim($message . ' 奖励：' . $rewardText),
            'created_at' => $now,
            'updated_at' => $now,
        ]);
        $budgetAfterClaim = $this->activityBudgetState($activity, (array) ($data['activity_participation_logs'] ?? []));
        if (!empty($activity['auto_pause_on_budget']) && (int) ($budgetAfterClaim['limit'] ?? 0) > 0 && !empty($budgetAfterClaim['exhausted'])) {
            $this->pauseActivityForBudget($data, $activity, $now, '活动权益预算已用完，自动停用。');
        }
        $data['activity_participation_logs'] = array_slice(array_values((array) ($data['activity_participation_logs'] ?? [])), -10000);
        $data['redeem_code_logs'] = array_slice(array_values((array) ($data['redeem_code_logs'] ?? [])), -10000);
        $this->store->save($data);

        return [
            'ok' => true,
            'message' => $message,
            'reward' => [
                'reward_type' => $rewardType,
                'coin_amount' => $coinAmount,
                'bonus_coin_amount' => $bonusCoinAmount,
                'vip_days' => $vipDays,
                'redeem_code_id' => $redeemCodeId,
            ],
            'user' => $this->currentUser(),
            'budget' => $budgetAfterClaim,
        ];
    }

    private function activityLimitFailureReason(array $activity, array $logs, int $userId, string $today): string
    {
        $activityId = (int) ($activity['id'] ?? 0);
        $activityCode = (string) ($activity['code'] ?? '');
        $dailyLimit = max(0, (int) ($activity['daily_limit'] ?? 0));
        $totalLimit = max(0, (int) ($activity['total_limit'] ?? 0));
        $dailyCount = 0;
        $totalCount = 0;
        foreach ($logs as $log) {
            if ((string) ($log['status'] ?? '') !== 'success') {
                continue;
            }
            $sameActivity = $activityId > 0
                ? (int) ($log['activity_id'] ?? 0) === $activityId
                : (string) ($log['activity_code'] ?? '') === $activityCode;
            if (!$sameActivity) {
                continue;
            }
            if ($totalLimit > 0) {
                $totalCount++;
            }
            if ((int) ($log['user_id'] ?? 0) === $userId && (string) ($log['participation_date'] ?? substr((string) ($log['created_at'] ?? ''), 0, 10)) === $today) {
                $dailyCount++;
            }
        }
        if ($dailyLimit > 0 && $dailyCount >= $dailyLimit) {
            return '你今天已达到该活动领取上限。';
        }
        if ($totalLimit > 0 && $totalCount >= $totalLimit) {
            return '活动奖励已被领完。';
        }

        return '';
    }

    private function appendActivityParticipationLog(array &$data, array $activity, int $userId, string $appKey, string $status, string $message, array $context, string $now, array $reward = []): void
    {
        $logs = array_values((array) ($data['activity_participation_logs'] ?? []));
        $logs[] = [
            'id' => empty($logs) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $logs)) + 1),
            'activity_id' => max(0, (int) ($activity['id'] ?? 0)),
            'activity_code' => (string) ($activity['code'] ?? ''),
            'activity_name' => (string) ($activity['name'] ?? ''),
            'activity_type' => (string) ($activity['activity_type'] ?? 'general'),
            'event_type' => in_array((string) ($reward['event_type'] ?? 'claim'), ['exposure', 'click', 'claim'], true) ? (string) ($reward['event_type'] ?? 'claim') : 'claim',
            'experiment_key' => (string) ($activity['experiment_key'] ?? ''),
            'variant_key' => (string) ($activity['variant_key'] ?? ''),
            'user_id' => max(0, $userId),
            'app_key' => $appKey !== '' ? $appKey : 'default',
            'reward_type' => (string) ($reward['reward_type'] ?? ($activity['reward_type'] ?? 'none')),
            'coin_amount' => max(0, (int) ($reward['coin_amount'] ?? 0)),
            'bonus_coin_amount' => max(0, (int) ($reward['bonus_coin_amount'] ?? 0)),
            'vip_days' => max(0, (int) ($reward['vip_days'] ?? 0)),
            'redeem_code_id' => max(0, (int) ($reward['redeem_code_id'] ?? ($activity['redeem_code_id'] ?? 0))),
            'status' => in_array($status, ['success', 'failed', 'tracked'], true) ? $status : 'failed',
            'message' => $this->limitText($message, 160),
            'context' => $context,
            'participation_date' => substr($now, 0, 10),
            'created_at' => $now,
        ];
        $data['activity_participation_logs'] = array_slice($logs, -10000);
    }

    public function redeemCode(string $rawCode, ?int $userId = null, array $context = []): array
    {
        $data = $this->store->load();
        $userId = max(0, (int) ($userId ?? $this->currentUserId()));
        $code = strtoupper((string) preg_replace('/[^a-zA-Z0-9_-]+/', '', trim($rawCode)));
        $appKey = $this->currentAppKey($context);
        $now = date('Y-m-d H:i:s');
        if ($code === '') {
            return ['ok' => false, 'message' => '请输入兑换码。'];
        }
        if ($userId <= 0) {
            return ['ok' => false, 'message' => '请先登录后再兑换。'];
        }

        $userIndex = null;
        foreach ((array) ($data['users'] ?? []) as $index => $user) {
            if ((int) ($user['id'] ?? 0) === $userId) {
                $userIndex = $index;
                break;
            }
        }
        if ($userIndex === null) {
            return ['ok' => false, 'message' => '用户不存在。'];
        }

        $codeIndex = null;
        foreach ((array) ($data['redeem_codes'] ?? []) as $index => $item) {
            if (strtoupper((string) ($item['code'] ?? '')) === $code) {
                $codeIndex = $index;
                break;
            }
        }
        if ($codeIndex === null) {
            $this->appendRedeemCodeLog($data, [], $code, $userId, $appKey, 'failed', '兑换码不存在。', $now);
            $this->store->save($data);
            return ['ok' => false, 'message' => '兑换码不存在。'];
        }

        $codeItem = (array) $data['redeem_codes'][$codeIndex];
        $failMessage = $this->redeemCodeFailureReason($codeItem, (array) ($data['redeem_code_logs'] ?? []), $userId, $appKey, $now, $context);
        if ($failMessage !== '') {
            $this->appendRedeemCodeLog($data, $codeItem, $code, $userId, $appKey, 'failed', $failMessage, $now);
            $this->store->save($data);
            return ['ok' => false, 'message' => $failMessage];
        }

        $coinAmount = max(0, (int) ($codeItem['coin_amount'] ?? 0));
        $bonusCoinAmount = max(0, (int) ($codeItem['bonus_coin_amount'] ?? 0));
        $vipDays = max(0, (int) ($codeItem['vip_days'] ?? 0));
        if (($coinAmount + $bonusCoinAmount + $vipDays) <= 0) {
            $message = '兑换码奖励配置无效。';
            $this->appendRedeemCodeLog($data, $codeItem, $code, $userId, $appKey, 'failed', $message, $now);
            $this->store->save($data);
            return ['ok' => false, 'message' => $message];
        }

        $data['users'][$userIndex]['coin_balance'] = max(0, (int) ($data['users'][$userIndex]['coin_balance'] ?? 0)) + $coinAmount;
        $data['users'][$userIndex]['bonus_coin_balance'] = max(0, (int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0)) + $bonusCoinAmount;
        if ($vipDays > 0) {
            $currentExpiresAt = strtotime((string) ($data['users'][$userIndex]['membership_expires_at'] ?? '')) ?: time();
            $base = max(time(), $currentExpiresAt);
            $data['users'][$userIndex]['membership'] = true;
            $data['users'][$userIndex]['membership_expires_at'] = date('Y-m-d H:i:s', $base + $vipDays * 86400);
            $data['entitlements'][] = [
                'user_id' => $userId,
                'content_type' => 'drama',
                'drama_id' => 0,
                'episode_id' => null,
                'type' => 'membership',
                'source_redeem_code' => $code,
                'granted_at' => $now,
            ];
        }

        if (($coinAmount + $bonusCoinAmount) > 0) {
            $data['coin_transactions'][] = [
                'id' => count((array) ($data['coin_transactions'] ?? [])) + 1,
                'user_id' => $userId,
                'type' => 'reward',
                'scene' => 'redeem_code',
                'coins' => $coinAmount + $bonusCoinAmount,
                'balance_after' => (int) ($data['users'][$userIndex]['coin_balance'] ?? 0) + (int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0),
                'source_redeem_code_id' => (int) ($codeItem['id'] ?? 0),
                'source_redeem_code' => $code,
                'remark' => '兑换码奖励：' . (string) ($codeItem['name'] ?? $code),
                'created_at' => $now,
            ];
        }

        $this->appendRedeemCodeLog($data, $codeItem, $code, $userId, $appKey, 'success', '兑换成功。', $now);
        $data['redeem_code_logs'] = array_slice(array_values((array) ($data['redeem_code_logs'] ?? [])), -10000);
        $this->store->save($data);

        return [
            'ok' => true,
            'message' => '兑换成功。',
            'reward' => [
                'reward_type' => (string) ($codeItem['reward_type'] ?? 'coin'),
                'coin_amount' => $coinAmount,
                'bonus_coin_amount' => $bonusCoinAmount,
                'vip_days' => $vipDays,
            ],
            'user' => $this->currentUser(),
        ];
    }

    public function redeemCodeBatch(string $rawBatchNo, ?int $userId = null, array $context = []): array
    {
        $data = $this->store->load();
        $userId = max(0, (int) ($userId ?? $this->currentUserId()));
        $batchNo = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim($rawBatchNo)) ?: '';
        $appKey = $this->currentAppKey($context);
        $now = date('Y-m-d H:i:s');
        if ($batchNo === '') {
            return ['ok' => false, 'message' => '请输入兑换码批次号。'];
        }
        if ($userId <= 0) {
            return ['ok' => false, 'message' => '请先登录后再领取。', 'batch_no' => $batchNo];
        }

        $hasBatch = false;
        $failureReasons = [];
        $failedCodeItem = [];
        $failedCode = '';
        foreach ((array) ($data['redeem_codes'] ?? []) as $item) {
            $codeItem = (array) $item;
            if ((string) ($codeItem['batch_no'] ?? '') !== $batchNo) {
                continue;
            }
            $hasBatch = true;
            $failMessage = $this->redeemCodeFailureReason($codeItem, (array) ($data['redeem_code_logs'] ?? []), $userId, $appKey, $now, $context);
            if ($failMessage !== '') {
                $failureReasons[$failMessage] = true;
                if (empty($failedCodeItem)) {
                    $failedCodeItem = $codeItem;
                    $failedCode = strtoupper((string) ($codeItem['code'] ?? ''));
                }
                continue;
            }

            $code = strtoupper((string) ($codeItem['code'] ?? ''));
            $result = $this->redeemCode($code, $userId, array_merge($context, [
                'batch_no' => $batchNo,
                'redeem_batch_auto' => 1,
            ]));
            $result['batch_no'] = $batchNo;
            $result['code'] = $code;

            return $result;
        }

        if (!$hasBatch) {
            return ['ok' => false, 'message' => '兑换码批次不存在。', 'batch_no' => $batchNo];
        }

        $reason = array_key_first($failureReasons);
        $message = $reason !== null && $reason !== ''
            ? '当前批次暂无可领取兑换码：' . $reason
            : '当前批次暂无可领取兑换码。';
        if (!empty($failedCodeItem)) {
            $this->appendRedeemCodeLog($data, $failedCodeItem, $failedCode, $userId, $appKey, 'failed', $message, $now);
            $data['redeem_code_logs'] = array_slice(array_values((array) ($data['redeem_code_logs'] ?? [])), -10000);
            $this->store->save($data);
        }

        return ['ok' => false, 'message' => $message, 'batch_no' => $batchNo];
    }

    public function watchHistory(?int $userId = null): array
    {
        $items = array_values($this->store->load()['watch_history'] ?? []);
        if ($userId !== null) {
            $items = array_values(array_filter($items, static fn (array $item): bool => (int) ($item['user_id'] ?? 0) === $userId));
        }
        usort($items, static fn (array $a, array $b): int => strcmp((string) ($b['updated_at'] ?? ''), (string) ($a['updated_at'] ?? '')));

        return $items;
    }

    public function followedDramas(?int $userId = null): array
    {
        $items = array_values($this->store->load()['followed_dramas'] ?? []);
        if ($userId !== null) {
            $items = array_values(array_filter($items, static fn (array $item): bool => (int) ($item['user_id'] ?? 0) === $userId));
        }
        usort($items, static fn (array $a, array $b): int => strcmp((string) ($b['created_at'] ?? ''), (string) ($a['created_at'] ?? '')));

        return $items;
    }

    public function smsCodes(?string $phone = null): array
    {
        $items = array_values($this->store->load()['sms_codes'] ?? []);
        if ($phone !== null && $phone !== '') {
            $items = array_values(array_filter($items, static fn (array $item): bool => (string) ($item['phone'] ?? '') === $phone));
        }
        usort($items, static fn (array $a, array $b): int => strcmp((string) ($b['created_at'] ?? ''), (string) ($a['created_at'] ?? '')));

        return $items;
    }

    public function recordContentEvent(string $eventType, array $payload = []): array
    {
        $eventType = in_array($eventType, ['view', 'lock_exposure', 'unlock_success', 'order_created'], true) ? $eventType : 'view';
        $contentType = in_array((string) ($payload['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $payload['content_type'] : 'drama';
        $data = $this->store->load();
        $attribution = $this->currentPromotionAttribution();
        $now = date('Y-m-d H:i:s');
        $trafficMeta = $this->trafficMetaFromPayload($payload, $attribution);
        $event = [
            'id' => count($data['content_events'] ?? []) + 1,
            'content_type' => $contentType,
            'event' => $eventType,
            'drama_id' => $contentType === 'drama' ? max(0, (int) ($payload['drama_id'] ?? 0)) : 0,
            'episode_id' => $contentType === 'drama' ? max(0, (int) ($payload['episode_id'] ?? 0)) : 0,
            'novel_id' => $contentType === 'novel' ? max(0, (int) ($payload['novel_id'] ?? 0)) : 0,
            'chapter_id' => $contentType === 'novel' ? max(0, (int) ($payload['chapter_id'] ?? 0)) : 0,
            'user_id' => max(0, (int) ($payload['user_id'] ?? $this->currentUserId())),
            'order_no' => trim((string) ($payload['order_no'] ?? '')),
            'amount' => round(max(0, (float) ($payload['amount'] ?? 0)), 2),
            'promotion_link_id' => max(0, (int) ($payload['promotion_link_id'] ?? ($attribution['promotion_link_id'] ?? 0))),
            'code' => (string) ($payload['code'] ?? ($attribution['code'] ?? '')),
            'path' => trim((string) ($payload['path'] ?? ($_SERVER['REQUEST_URI'] ?? ''))),
            'created_at' => $now,
        ] + $trafficMeta;

        $data['content_events'][] = $event;
        $data['content_events'] = array_slice(array_values((array) ($data['content_events'] ?? [])), -10000);
        $this->store->save($data);

        return ['ok' => true, 'event' => $event];
    }

    public function isEpisodeFree(array $drama, array $episode): bool
    {
        if (!empty($episode['is_free'])) {
            return true;
        }

        $freeCount = max(0, (int) ($drama['free_episode_count'] ?? 0));
        if ($freeCount <= 0) {
            return false;
        }

        foreach (array_values((array) ($drama['episodes'] ?? [])) as $index => $item) {
            if ((int) ($item['id'] ?? 0) === (int) ($episode['id'] ?? 0)) {
                return $index < $freeCount;
            }
        }

        return false;
    }

    public function isNovelChapterFree(array $novel, array $chapter): bool
    {
        if (!empty($chapter['is_free'])) {
            return true;
        }

        $freeCount = max(0, (int) ($novel['free_chapter_count'] ?? 0));
        if ($freeCount <= 0) {
            return false;
        }

        foreach (array_values((array) ($novel['chapters'] ?? [])) as $index => $item) {
            if ((int) ($item['id'] ?? 0) === (int) ($chapter['id'] ?? 0)) {
                return $index < $freeCount;
            }
        }

        return false;
    }

    public function episodeAccessMap(int $dramaId, int $userId): array
    {
        $drama = $this->findDrama($dramaId);
        $map = [];
        foreach ((array) ($drama['episodes'] ?? []) as $episode) {
            $episodeId = (int) ($episode['id'] ?? 0);
            $map[$episodeId] = $this->isEpisodeFree($drama, $episode) || $this->hasAccess($userId, $dramaId, $episodeId);
        }

        return $map;
    }

    public function novelChapterAccessMap(int $novelId, int $userId): array
    {
        $novel = $this->findNovel($novelId);
        $map = [];
        foreach ((array) ($novel['chapters'] ?? []) as $chapter) {
            $chapterId = (int) ($chapter['id'] ?? 0);
            $map[$chapterId] = $this->isNovelChapterFree((array) $novel, $chapter) || $this->hasNovelAccess($userId, $novelId, $chapterId);
        }

        return $map;
    }

    public function sendMockSmsCode(string $phone): array
    {
        $phone = preg_replace('/\D+/', '', $phone) ?? '';
        if (!preg_match('/^1\d{10}$/', $phone)) {
            return ['ok' => false, 'message' => '请输入正确的手机号。'];
        }

        $data = $this->store->load();
        $smsConfig = $this->smsConfig($data);
        if ((string) ($smsConfig['status'] ?? 'active') !== 'active') {
            return ['ok' => false, 'message' => '短信通道已停用。'];
        }
        $code = (string) random_int(100000, 999999);
        $expireMinutes = max(1, min(30, (int) ($smsConfig['expire_minutes'] ?? 10)));
        $provider = (string) ($smsConfig['provider'] ?? 'mock');
        $message = strtr((string) ($smsConfig['template_content'] ?? '您的验证码为 {code}，{minutes} 分钟内有效。'), [
            '{code}' => $code,
            '{minutes}' => (string) $expireMinutes,
            '{sign}' => (string) ($smsConfig['sign_name'] ?? '精秀短剧'),
        ]);
        $delivery = $this->deliverSmsMessage($smsConfig, $phone, $message, 'login_code');
        $sendStatus = $provider === 'mock' ? 'mocked' : (!empty($delivery['ok']) ? 'success' : 'failed');
        $data['sms_codes'][] = [
            'id' => count($data['sms_codes'] ?? []) + 1,
            'phone' => $phone,
            'code' => $code,
            'scene' => 'login',
            'provider' => $provider,
            'provider_request_id' => (string) ($delivery['provider_request_id'] ?? ''),
            'sign_name' => (string) ($smsConfig['sign_name'] ?? ''),
            'template_id' => (string) ($smsConfig['template_id'] ?? ''),
            'message' => $this->limitText($message, 240),
            'send_status' => $sendStatus,
            'response_payload' => (array) ($delivery['response_payload'] ?? []),
            'used' => false,
            'expires_at' => date('Y-m-d H:i:s', time() + $expireMinutes * 60),
            'created_at' => date('Y-m-d H:i:s'),
        ];
        $data['sms_codes'] = array_slice(array_values($data['sms_codes']), -120);
        $this->store->save($data);

        return [
            'ok' => !empty($delivery['ok']),
            'message' => $provider === 'mock' ? '验证码已生成，当前为模拟短信。' : (string) ($delivery['message'] ?? '短信发送失败。'),
            'code' => $provider === 'mock' ? $code : '',
            'phone' => $phone,
            'provider' => $provider,
            'expires_in' => $expireMinutes * 60,
            'send_status' => $sendStatus,
        ];
    }

    public function loginBySmsCode(string $phone, string $code): array
    {
        $phone = preg_replace('/\D+/', '', $phone) ?? '';
        $code = trim($code);
        if (!preg_match('/^1\d{10}$/', $phone) || $code === '') {
            return ['ok' => false, 'message' => '手机号或验证码不能为空。'];
        }

        $data = $this->store->load();
        $matchedIndex = null;
        foreach (array_reverse($data['sms_codes'] ?? [], true) as $index => $item) {
            if ((string) ($item['phone'] ?? '') !== $phone || !empty($item['used'])) {
                continue;
            }
            if (strtotime((string) ($item['expires_at'] ?? '')) < time()) {
                continue;
            }
            if (hash_equals((string) ($item['code'] ?? ''), $code)) {
                $matchedIndex = $index;
                break;
            }
        }

        if ($matchedIndex === null) {
            return ['ok' => false, 'message' => '验证码错误或已过期。'];
        }

        $currentUserId = $this->currentUserId();
        $targetUserId = 0;
        foreach ($data['users'] as $user) {
            if ((string) ($user['phone'] ?? '') === $phone) {
                $targetUserId = (int) $user['id'];
                break;
            }
        }

        if ($targetUserId === 0) {
            $targetUserId = empty($data['users']) ? 1 : ((int) max(array_column($data['users'], 'id')) + 1);
            $data['users'][] = [
                'id' => $targetUserId,
                'nickname' => '用户' . substr($phone, -4),
                'phone' => $phone,
                'role' => 'user',
                'membership' => false,
                'membership_expires_at' => null,
                'coin_balance' => 300,
                'bonus_coin_balance' => 0,
                'bonus_expires_at' => null,
                'auto_unlock_next' => false,
                'created_at' => date('Y-m-d H:i:s'),
            ];
        }

        foreach ($data['users'] as &$user) {
            if ((int) $user['id'] === $targetUserId) {
                $user['phone'] = $phone;
                $user['role'] = 'user';
                if (trim((string) ($user['nickname'] ?? '')) === '') {
                    $user['nickname'] = '用户' . substr($phone, -4);
                }
                $user['created_at'] = (string) (($user['created_at'] ?? '') ?: date('Y-m-d H:i:s'));
                break;
            }
        }
        unset($user);

        if ($currentUserId !== $targetUserId) {
            $this->transferUserAssets($data, $currentUserId, $targetUserId);
        }

        $data['sms_codes'][$matchedIndex]['used'] = true;
        $data['sms_codes'][$matchedIndex]['used_at'] = date('Y-m-d H:i:s');
        $this->appendPromotionEventFromAttribution($data, 'register', $targetUserId);
        $_SESSION['user_id'] = $targetUserId;
        $this->store->save($data);

        return ['ok' => true, 'message' => '登录成功。', 'user' => $this->currentUser()];
    }

    public function recordWatchHistory(int $dramaId, int $episodeId, int $progress = 0): array
    {
        $data = $this->store->load();
        $userId = $this->currentUserId();
        $now = date('Y-m-d H:i:s');
        $updated = false;
        foreach ($data['watch_history'] as &$item) {
            if ((int) ($item['user_id'] ?? 0) === $userId && (int) ($item['drama_id'] ?? 0) === $dramaId) {
                $item['episode_id'] = $episodeId;
                $item['progress'] = max(0, min(100, $progress));
                $item['updated_at'] = $now;
                $updated = true;
                break;
            }
        }
        unset($item);
        if (!$updated) {
            $data['watch_history'][] = [
                'user_id' => $userId,
                'drama_id' => $dramaId,
                'episode_id' => $episodeId,
                'progress' => max(0, min(100, $progress)),
                'created_at' => $now,
                'updated_at' => $now,
            ];
        }
        $this->store->save($data);

        return ['ok' => true, 'history' => $this->watchHistory($userId)];
    }

    public function toggleFollowDrama(int $dramaId): array
    {
        $data = $this->store->load();
        $userId = $this->currentUserId();
        $found = false;
        $data['followed_dramas'] = array_values(array_filter((array) ($data['followed_dramas'] ?? []), static function (array $item) use ($userId, $dramaId, &$found): bool {
            $same = (int) ($item['user_id'] ?? 0) === $userId && (int) ($item['drama_id'] ?? 0) === $dramaId;
            if ($same) {
                $found = true;
                return false;
            }

            return true;
        }));

        if (!$found) {
            $data['followed_dramas'][] = [
                'user_id' => $userId,
                'drama_id' => $dramaId,
                'created_at' => date('Y-m-d H:i:s'),
            ];
        }
        $this->store->save($data);

        return ['ok' => true, 'followed' => !$found, 'items' => $this->followedDramas($userId)];
    }

    public function setAutoUnlockNext(bool $enabled): array
    {
        $data = $this->store->load();
        $userId = $this->currentUserId();
        foreach ($data['users'] as &$user) {
            if ((int) ($user['id'] ?? 0) === $userId) {
                $user['auto_unlock_next'] = $enabled;
                break;
            }
        }
        unset($user);
        $this->store->save($data);

        return ['ok' => true, 'enabled' => $enabled, 'user' => $this->currentUser()];
    }

    public function unlockWithCoins(int $dramaId, ?int $episodeId = null, string $type = 'episode_unlock'): array
    {
        $data = $this->store->load();
        $userId = $this->currentUserId();
        $drama = null;
        foreach ($data['dramas'] as $item) {
            if ((int) ($item['id'] ?? 0) === $dramaId) {
                $drama = $item;
                break;
            }
        }
        if (!$drama) {
            return ['ok' => false, 'message' => '短剧不存在。'];
        }
        if ($episodeId !== null && $this->hasAccess($userId, $dramaId, $episodeId)) {
            return ['ok' => true, 'unlocked' => true, 'message' => '当前剧集已解锁。'];
        }

        $coins = $type === 'drama_unlock'
            ? max(1, (int) round((float) ($drama['full_unlock_price'] ?? 0) * 100))
            : max(1, (int) ($drama['episode_coin_price'] ?? 199));
        $userIndex = null;
        foreach ($data['users'] as $index => $user) {
            if ((int) ($user['id'] ?? 0) === $userId) {
                $userIndex = $index;
                break;
            }
        }
        if ($userIndex === null) {
            return ['ok' => false, 'message' => '用户不存在。'];
        }

        $available = (int) ($data['users'][$userIndex]['coin_balance'] ?? 0) + (int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0);
        if ($available < $coins) {
            return ['ok' => false, 'need_payment' => true, 'message' => 'K币余额不足，请选择支付解锁。', 'required_coins' => $coins, 'available_coins' => $available];
        }

        $remaining = $coins;
        $bonusUse = min((int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0), $remaining);
        $data['users'][$userIndex]['bonus_coin_balance'] -= $bonusUse;
        $remaining -= $bonusUse;
        $data['users'][$userIndex]['coin_balance'] = max(0, (int) ($data['users'][$userIndex]['coin_balance'] ?? 0) - $remaining);

        $order = [
            'user_id' => $userId,
            'drama_id' => $dramaId,
            'episode_id' => $type === 'drama_unlock' ? null : $episodeId,
            'type' => $type,
        ];
        $this->grantEntitlement($data, $order);
        $data['coin_transactions'][] = [
            'id' => count($data['coin_transactions'] ?? []) + 1,
            'user_id' => $userId,
            'type' => 'consume',
            'scene' => $type,
            'drama_id' => $dramaId,
            'episode_id' => $type === 'drama_unlock' ? null : $episodeId,
            'coins' => -$coins,
            'balance_after' => (int) ($data['users'][$userIndex]['coin_balance'] ?? 0) + (int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0),
            'remark' => $type === 'drama_unlock' ? 'K币解锁全集' : 'K币解锁单集',
            'created_at' => date('Y-m-d H:i:s'),
        ];
        $this->appendContentEvent($data, 'unlock_success', [
            'content_type' => 'drama',
            'drama_id' => $dramaId,
            'episode_id' => $type === 'drama_unlock' ? 0 : (int) $episodeId,
            'user_id' => $userId,
            'amount' => round($coins / 100, 2),
        ]);
        $this->store->save($data);

        return ['ok' => true, 'unlocked' => true, 'message' => 'K币扣除成功，剧集已解锁。', 'coins' => $coins, 'user' => $this->currentUser()];
    }

    public function unlockNovelWithCoins(int $novelId, ?int $chapterId = null, string $type = 'novel_chapter_unlock'): array
    {
        $data = $this->store->load();
        $userId = $this->currentUserId();
        $novel = null;
        $chapter = null;
        foreach ($data['novels'] as $item) {
            if ((int) ($item['id'] ?? 0) !== $novelId) {
                continue;
            }
            $novel = $item;
            foreach ((array) ($item['chapters'] ?? []) as $chapterItem) {
                if ((int) ($chapterItem['id'] ?? 0) === (int) $chapterId) {
                    $chapter = $chapterItem;
                    break;
                }
            }
            break;
        }
        if (!$novel) {
            return ['ok' => false, 'message' => '小说不存在。'];
        }
        if ($type !== 'novel_unlock' && !$chapter) {
            return ['ok' => false, 'message' => '章节不存在。'];
        }
        if ($type === 'novel_unlock' ? $this->hasNovelAccess($userId, $novelId) : $this->hasNovelAccess($userId, $novelId, $chapterId)) {
            return ['ok' => true, 'unlocked' => true, 'message' => '当前小说内容已解锁。'];
        }

        $coins = $type === 'novel_unlock'
            ? max(1, (int) round((float) ($novel['full_unlock_price'] ?? 0) * 100))
            : max(1, (int) ($novel['chapter_coin_price'] ?? 99));
        $userIndex = null;
        foreach ($data['users'] as $index => $user) {
            if ((int) ($user['id'] ?? 0) === $userId) {
                $userIndex = $index;
                break;
            }
        }
        if ($userIndex === null) {
            return ['ok' => false, 'message' => '用户不存在。'];
        }

        $available = (int) ($data['users'][$userIndex]['coin_balance'] ?? 0) + (int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0);
        if ($available < $coins) {
            return ['ok' => false, 'need_payment' => true, 'message' => 'K币余额不足，请选择支付解锁。', 'required_coins' => $coins, 'available_coins' => $available];
        }

        $remaining = $coins;
        $bonusUse = min((int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0), $remaining);
        $data['users'][$userIndex]['bonus_coin_balance'] -= $bonusUse;
        $remaining -= $bonusUse;
        $data['users'][$userIndex]['coin_balance'] = max(0, (int) ($data['users'][$userIndex]['coin_balance'] ?? 0) - $remaining);

        $order = [
            'user_id' => $userId,
            'content_type' => 'novel',
            'drama_id' => 0,
            'episode_id' => null,
            'novel_id' => $novelId,
            'chapter_id' => $type === 'novel_unlock' ? null : $chapterId,
            'type' => $type,
        ];
        $this->grantEntitlement($data, $order);
        $data['coin_transactions'][] = [
            'id' => count($data['coin_transactions'] ?? []) + 1,
            'user_id' => $userId,
            'type' => 'consume',
            'scene' => $type,
            'drama_id' => 0,
            'episode_id' => null,
            'novel_id' => $novelId,
            'chapter_id' => $type === 'novel_unlock' ? null : $chapterId,
            'coins' => -$coins,
            'balance_after' => (int) ($data['users'][$userIndex]['coin_balance'] ?? 0) + (int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0),
            'remark' => $type === 'novel_unlock' ? 'K币解锁整本小说' : 'K币解锁小说章节',
            'created_at' => date('Y-m-d H:i:s'),
        ];
        $this->appendContentEvent($data, 'unlock_success', [
            'content_type' => 'novel',
            'novel_id' => $novelId,
            'chapter_id' => $type === 'novel_unlock' ? 0 : (int) $chapterId,
            'user_id' => $userId,
            'amount' => round($coins / 100, 2),
        ]);
        $this->store->save($data);

        return ['ok' => true, 'unlocked' => true, 'message' => 'K币扣除成功，小说内容已解锁。', 'coins' => $coins, 'user' => $this->currentUser()];
    }

    public function buyVipWithCoins(string $planCode, ?string $appKey = null): array
    {
        $plan = $this->vipPlan($planCode, $appKey);
        if (!$plan) {
            return ['ok' => false, 'message' => 'VIP 套餐不存在。'];
        }

        $data = $this->store->load();
        $userId = $this->currentUserId();
        $coins = max(1, (int) round((float) ($plan['price'] ?? 0) * 100));
        $userIndex = null;
        foreach ($data['users'] as $index => $user) {
            if ((int) ($user['id'] ?? 0) === $userId) {
                $userIndex = $index;
                break;
            }
        }
        if ($userIndex === null) {
            return ['ok' => false, 'message' => '用户不存在。'];
        }

        $available = (int) ($data['users'][$userIndex]['coin_balance'] ?? 0) + (int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0);
        if ($available < $coins) {
            return ['ok' => false, 'need_payment' => true, 'message' => 'K币余额不足，请选择支付开通。', 'required_coins' => $coins, 'available_coins' => $available];
        }

        $remaining = $coins;
        $bonusUse = min((int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0), $remaining);
        $data['users'][$userIndex]['bonus_coin_balance'] -= $bonusUse;
        $remaining -= $bonusUse;
        $data['users'][$userIndex]['coin_balance'] = max(0, (int) ($data['users'][$userIndex]['coin_balance'] ?? 0) - $remaining);
        $currentExpiresAt = strtotime((string) ($data['users'][$userIndex]['membership_expires_at'] ?? '')) ?: time();
        $base = max(time(), $currentExpiresAt);
        $data['users'][$userIndex]['membership'] = true;
        $data['users'][$userIndex]['membership_expires_at'] = date('Y-m-d H:i:s', $base + max(1, (int) ($plan['days'] ?? 30)) * 86400);
        $data['entitlements'][] = [
            'user_id' => $userId,
            'drama_id' => 0,
            'episode_id' => null,
            'type' => 'membership',
            'plan_code' => $planCode,
            'granted_at' => date('Y-m-d H:i:s'),
        ];
        $data['coin_transactions'][] = [
            'id' => count($data['coin_transactions'] ?? []) + 1,
            'user_id' => $userId,
            'type' => 'consume',
            'scene' => $planCode,
            'drama_id' => 0,
            'episode_id' => null,
            'coins' => -$coins,
            'balance_after' => (int) ($data['users'][$userIndex]['coin_balance'] ?? 0) + (int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0),
            'remark' => 'K币开通' . (string) ($plan['name'] ?? 'VIP'),
            'created_at' => date('Y-m-d H:i:s'),
        ];
        $this->store->save($data);

        return ['ok' => true, 'unlocked' => true, 'message' => 'K币扣除成功，VIP 已开通。', 'coins' => $coins, 'user' => $this->currentUser()];
    }

    public function createOrder(array $payload): array
    {
        $data = $this->store->load();
        $attribution = $this->currentPromotionAttribution();
        $appKey = $this->currentAppKey($payload);
        $productTemplate = $this->rechargeProductTemplate($appKey);
        $payloadType = (string) ($payload['type'] ?? '');
        $contentType = in_array((string) ($payload['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $payload['content_type'] : 'drama';
        $dramaId = $contentType === 'drama' ? max(0, (int) ($payload['drama_id'] ?? 0)) : 0;
        $episodeId = $contentType === 'drama' ? max(0, (int) ($payload['episode_id'] ?? 0)) : 0;
        $novelId = max(0, (int) ($payload['novel_id'] ?? 0));
        $chapterId = max(0, (int) ($payload['chapter_id'] ?? 0));
        $reusableOrderTypes = ['episode', 'episode_unlock', 'drama_unlock', 'novel_chapter_unlock', 'novel_unlock'];
        $app = $this->appConfig($appKey);
        $preferredRouteId = (string) ($payload['payment_route_id'] ?? '');
        $forceRoute = trim($preferredRouteId) !== '';
        if ($preferredRouteId === '') {
            $preferredRouteId = (string) ($app['payment_route_id'] ?? '');
        }
        $preferredRoute = $this->selectPaymentRouteForPayload($data, [
            'payment_route_id' => $preferredRouteId,
            'force_route' => $forceRoute,
            'amount' => (float) ($payload['amount'] ?? 0),
            'user_id' => (int) ($payload['user_id'] ?? 0),
            'app_key' => $appKey,
        ]);
        $paymentMeta = $this->paymentDisplayForOrder([
            'payment_route_id' => $preferredRoute['id'] ?? '',
            'payment_provider' => $preferredRoute['provider'] ?? 'jingxiu',
            'payment_provider_name' => $preferredRoute['provider_name'] ?? '精秀聚合支付',
            'payment_channel_name' => $preferredRoute['channel_name'] ?? '精秀主通道',
            'payment_method' => $preferredRoute['payment_method'] ?? 'alipay',
            'payment_method_name' => $preferredRoute['payment_method_name'] ?? '支付宝',
            'gateway_trade_type' => $preferredRoute['trade_type'] ?? $preferredRoute['pay_type'] ?? 'alipayWap',
        ]);
        foreach ($data['orders'] as $order) {
            $orderContentType = in_array((string) ($order['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $order['content_type'] : 'drama';
            if ((int) $order['user_id'] === (int) $payload['user_id']
                && $orderContentType === $contentType
                && (int) ($order['drama_id'] ?? 0) === $dramaId
                && (int) ($order['episode_id'] ?? 0) === $episodeId
                && (int) ($order['novel_id'] ?? 0) === $novelId
                && (int) ($order['chapter_id'] ?? 0) === $chapterId
                && $order['type'] === $payload['type']
                && (float) ($order['amount'] ?? 0) === (float) ($payload['amount'] ?? 0)
            ) {
                $orderStatus = (string) ($order['status'] ?? 'pending');
                $canReuseOrder = in_array($payloadType, $reusableOrderTypes, true)
                    || ($orderStatus === 'pending' && $payloadType !== 'coin_recharge');
                if (!$canReuseOrder) {
                    continue;
                }
                if (($order['status'] ?? 'pending') === 'pending' && empty($order['gateway_payment_url'])) {
                    $gatewayPatch = [
                        'payment_route_id' => $paymentMeta['route_id'],
                        'payment_provider' => $paymentMeta['provider'],
                        'payment_provider_name' => $paymentMeta['provider_name'],
                        'payment_channel_name' => $paymentMeta['channel_name'],
                        'payment_method' => $paymentMeta['method'],
                        'payment_method_name' => $paymentMeta['method_name'],
                        'gateway_trade_type' => $paymentMeta['trade_type'],
                    ];
                    if (!empty($attribution)) {
                        $attributionTrafficMeta = $this->trafficMetaFromPayload($attribution);
                        if (empty($order['promotion_link_id'])) {
                            $gatewayPatch = array_merge($gatewayPatch, [
                                'promotion_link_id' => (int) ($attribution['promotion_link_id'] ?? 0),
                                'promotion_code' => (string) ($attribution['code'] ?? ''),
                                'agent_id' => (int) ($attribution['agent_id'] ?? 0),
                                'traffic_source' => (string) ($attribution['source'] ?? ''),
                                'campaign' => (string) ($attribution['campaign'] ?? ''),
                            ], $attributionTrafficMeta);
                        } else {
                            foreach ($attributionTrafficMeta as $key => $value) {
                                if ($value !== '' && trim((string) ($order[$key] ?? '')) === '') {
                                    $gatewayPatch[$key] = $value;
                                }
                            }
                        }
                    }
                    $this->updateOrderGatewayData((string) $order['order_no'], $gatewayPatch);
                    $order = array_merge($order, [
                        'payment_route_id' => $paymentMeta['route_id'],
                        'payment_provider' => $paymentMeta['provider'],
                        'payment_provider_name' => $paymentMeta['provider_name'],
                        'payment_channel_name' => $paymentMeta['channel_name'],
                        'payment_method' => $paymentMeta['method'],
                        'payment_method_name' => $paymentMeta['method_name'],
                        'gateway_trade_type' => $paymentMeta['trade_type'],
                    ], $gatewayPatch);
                }

                return $order;
            }
        }

        $id = count($data['orders']) + 1;
        $trafficMeta = $this->trafficMetaFromPayload($payload, $attribution);

        $order = [
            'id' => $id,
            'order_no' => 'OD' . date('YmdHis') . str_pad((string) $id, 4, '0', STR_PAD_LEFT),
            'user_id' => $payload['user_id'],
            'content_type' => $contentType,
            'drama_id' => $dramaId,
            'episode_id' => $episodeId > 0 ? $episodeId : null,
            'novel_id' => $novelId,
            'chapter_id' => $chapterId > 0 ? $chapterId : null,
            'type' => $payload['type'],
            'amount' => $payload['amount'],
            'status' => 'pending',
            'status_reason' => '订单已创建，等待支付。',
            'refund_status' => 'none',
            'refund_pending' => false,
            'refund_failed_reason' => '',
            'last_status_checked_at' => null,
            'paid_confirmed_by' => '',
            'payment_route_id' => $paymentMeta['route_id'],
            'payment_provider' => $paymentMeta['provider'],
            'payment_provider_name' => $paymentMeta['provider_name'],
            'payment_channel_name' => $paymentMeta['channel_name'],
            'payment_method' => $paymentMeta['method'],
            'payment_method_name' => $paymentMeta['method_name'],
            'gateway_trade_type' => $paymentMeta['trade_type'],
            'app_key' => $appKey,
            'app_name' => (string) (($app['name'] ?? '') ?: ($productTemplate['app_name'] ?? '')),
            'product_template_id' => (int) ($productTemplate['id'] ?? 0),
            'product_template_name' => (string) ($productTemplate['name'] ?? ''),
            'created_at' => date('Y-m-d H:i:s'),
        ] + $trafficMeta;
        if (!empty($attribution)) {
            $order['promotion_link_id'] = (int) ($attribution['promotion_link_id'] ?? 0);
            $order['promotion_code'] = (string) ($attribution['code'] ?? '');
            $order['agent_id'] = (int) ($attribution['agent_id'] ?? 0);
            $order['traffic_source'] = (string) ($attribution['source'] ?? '');
            $order['campaign'] = (string) ($attribution['campaign'] ?? '');
            $order = $this->mergeTrafficMeta($order, $attribution, false);
        }
        foreach (['coin_amount', 'bonus_coin_amount', 'vip_days', 'package_code', 'plan_code', 'subject', 'product_code', 'product_name', 'product_type'] as $extraKey) {
            if (array_key_exists($extraKey, $payload)) {
                $order[$extraKey] = $payload[$extraKey];
            }
        }

        $data['orders'][] = $order;
        $this->appendContentEvent($data, 'order_created', [
            'content_type' => $contentType,
            'drama_id' => (int) ($order['drama_id'] ?? 0),
            'episode_id' => (int) ($order['episode_id'] ?? 0),
            'novel_id' => (int) ($order['novel_id'] ?? 0),
            'chapter_id' => (int) ($order['chapter_id'] ?? 0),
            'user_id' => (int) ($order['user_id'] ?? 0),
            'order_no' => (string) ($order['order_no'] ?? ''),
            'amount' => (float) ($order['amount'] ?? 0),
        ] + $this->trafficMetaFromPayload($order));
        $this->store->save($data);

        return $order;
    }

    public function createTestPaymentOrder(array $payload): array
    {
        $data = $this->store->load();
        $preferredRoute = $this->selectPaymentRouteForPayload($data, [
            'payment_route_id' => (string) ($payload['payment_route_id'] ?? ''),
            'amount' => (float) ($payload['amount'] ?? 0),
            'user_id' => $this->currentUserId(),
            'is_test' => true,
        ]);
        $paymentMeta = $this->paymentDisplayForOrder([
            'payment_route_id' => $preferredRoute['id'] ?? '',
            'payment_provider' => $preferredRoute['provider'] ?? 'jingxiu',
            'payment_provider_name' => $preferredRoute['provider_name'] ?? '精秀聚合支付',
            'payment_channel_name' => $preferredRoute['channel_name'] ?? '精秀主通道',
            'payment_method' => $preferredRoute['payment_method'] ?? 'alipay',
            'payment_method_name' => $preferredRoute['payment_method_name'] ?? '支付宝',
            'gateway_trade_type' => $preferredRoute['trade_type'] ?? $preferredRoute['pay_type'] ?? 'alipayWap',
        ]);
        $id = count($data['orders']) + 1;
        $admin = $this->currentAdmin();
        $subject = trim((string) ($payload['test_subject'] ?? ''));
        if ($subject === '') {
            $subject = '支付通道测试';
        }
        $subject = function_exists('mb_substr') ? mb_substr($subject, 0, 40) : substr($subject, 0, 120);

        $order = [
            'id' => $id,
            'order_no' => 'TS' . date('YmdHis') . str_pad((string) $id, 4, '0', STR_PAD_LEFT),
            'user_id' => $this->currentUserId(),
            'drama_id' => 0,
            'episode_id' => null,
            'type' => 'payment_test',
            'is_test' => true,
            'test_subject' => $subject,
            'created_by_admin_id' => (int) ($admin['id'] ?? ($_SESSION['admin_id'] ?? 0)),
            'created_by_admin_name' => (string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? ($_SESSION['admin_name'] ?? '管理员'))),
            'amount' => round((float) ($payload['amount'] ?? 0), 2),
            'status' => 'pending',
            'status_reason' => '测试订单已创建，等待支付。',
            'refund_status' => 'none',
            'refund_pending' => false,
            'refund_failed_reason' => '',
            'last_status_checked_at' => null,
            'paid_confirmed_by' => '',
            'payment_route_id' => $paymentMeta['route_id'],
            'payment_provider' => $paymentMeta['provider'],
            'payment_provider_name' => $paymentMeta['provider_name'],
            'payment_channel_name' => $paymentMeta['channel_name'],
            'payment_method' => $paymentMeta['method'],
            'payment_method_name' => $paymentMeta['method_name'],
            'gateway_trade_type' => $paymentMeta['trade_type'],
            'created_at' => date('Y-m-d H:i:s'),
        ];

        $data['orders'][] = $order;
        $this->store->save($data);
        $this->recordOrderAction(
            (string) $order['order_no'],
            'create_test_payment',
            '后台创建支付通道测试订单。',
            [
                'payment_route_id' => $paymentMeta['route_id'],
                'amount' => $order['amount'],
                'subject' => $order['test_subject'],
            ],
            true
        );

        return $order;
    }

    public function updateOrderGatewayData(string $orderNo, array $gatewayData): void
    {
        $data = $this->store->load();
        foreach ($data['orders'] as &$order) {
            if ($order['order_no'] === $orderNo) {
                $order = array_merge($order, $gatewayData);
                break;
            }
        }

        $this->store->save($data);
    }

    public function recordOrderGatewayLog(string $orderNo, string $scene, string $apiUrl, array $requestParams, mixed $responseParams, ?string $error = null, ?bool $success = null): void
    {
        $data = $this->store->load();
        foreach ($data['orders'] as &$order) {
            if ($order['order_no'] !== $orderNo) {
                continue;
            }

            $logs = array_values((array) ($order['gateway_logs'] ?? []));
            $logs[] = [
                'scene' => $scene,
                'api_url' => $apiUrl,
                'method' => 'POST',
                'request_params' => $requestParams,
                'response_params' => $responseParams,
                'error' => $error,
                'success' => $success,
                'created_at' => date('Y-m-d H:i:s'),
            ];

            $order['gateway_logs'] = array_slice($logs, -30);
            $order['gateway_last_scene'] = $scene;
            $order['gateway_last_request_params'] = $requestParams;
            $order['gateway_last_response_params'] = $responseParams;
            $order['gateway_last_error'] = $error;
            $order['gateway_last_success'] = $success;
            $order['gateway_last_at'] = date('Y-m-d H:i:s');
            break;
        }

        $this->store->save($data);
    }

    public function recordOrderAction(string $orderNo, string $action, string $message, array $context = [], ?bool $success = null): void
    {
        $data = $this->store->load();
        $logs = array_values((array) ($data['order_action_logs'] ?? []));
        $logs[] = [
            'id' => count($logs) + 1,
            'order_no' => $orderNo,
            'action' => $action,
            'message' => $message,
            'context' => $context,
            'success' => $success,
            'admin_id' => (int) ($_SESSION['admin_id'] ?? 0),
            'admin_name' => (string) ($_SESSION['admin_name'] ?? ''),
            'created_at' => date('Y-m-d H:i:s'),
        ];

        $data['order_action_logs'] = array_slice($logs, -200);
        $this->store->save($data);
    }

    public function recordAdminOperation(string $action, string $section, string $status, string $message, array $payload = []): void
    {
        $data = $this->store->load();
        $logs = array_values((array) ($data['admin_operation_logs'] ?? []));
        $admin = $this->currentAdmin();
        $scope = $this->currentAdminScope($data);
        $logs[] = [
            'id' => count($logs) + 1,
            'action' => $this->limitText($action, 80),
            'section' => $this->limitText($section, 60),
            'status' => in_array($status, ['success', 'failed', 'denied'], true) ? $status : 'success',
            'message' => $this->limitText($message, 200),
            'admin_id' => (int) ($admin['id'] ?? ($_SESSION['admin_id'] ?? 0)),
            'admin_name' => $this->limitText((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? ($_SESSION['admin_name'] ?? '管理员'))), 60),
            'admin_role' => (string) ($scope['role'] ?? ($admin['role'] ?? 'super_admin')),
            'ip' => $this->limitText((string) ($_SERVER['REMOTE_ADDR'] ?? ''), 80),
            'user_agent' => $this->limitText((string) ($_SERVER['HTTP_USER_AGENT'] ?? ''), 180),
            'summary' => $this->adminOperationSummary($payload),
            'created_at' => date('Y-m-d H:i:s'),
        ];
        $data['admin_operation_logs'] = array_slice($logs, -2000);
        $this->store->save($data);
    }

    private function adminOperationLogsForScope(array $data, array $scope): array
    {
        $logs = array_values((array) ($data['admin_operation_logs'] ?? []));
        if (!empty($scope['restricted'])) {
            $adminId = (int) ($_SESSION['admin_id'] ?? 0);
            $logs = array_values(array_filter($logs, static fn (array $log): bool => (int) ($log['admin_id'] ?? 0) === $adminId));
        }
        usort($logs, static fn (array $a, array $b): int => strcmp((string) ($b['created_at'] ?? ''), (string) ($a['created_at'] ?? '')));

        return array_slice($logs, 0, 500);
    }

    private function apiLogsForDashboard(array $data): array
    {
        $logs = [];
        foreach ((array) ($data['orders'] ?? []) as $order) {
            $orderNo = (string) ($order['order_no'] ?? '');
            foreach ((array) ($order['gateway_logs'] ?? []) as $log) {
                $success = $log['success'] ?? null;
                $logs[] = [
                    'source' => '支付网关',
                    'scene' => (string) ($log['scene'] ?? 'create'),
                    'status' => $success === null ? 'pending' : (!empty($success) ? 'success' : 'failed'),
                    'order_no' => $orderNo,
                    'api_url' => (string) ($log['api_url'] ?? ''),
                    'method' => (string) ($log['method'] ?? 'POST'),
                    'message' => (string) (($log['error'] ?? '') ?: ($success === null ? '等待通道返回。' : (!empty($success) ? '接口调用成功。' : '接口调用失败。'))),
                    'created_at' => (string) ($log['created_at'] ?? ''),
                ];
            }
        }
        foreach ((array) ($data['callback_logs'] ?? []) as $log) {
            $logs[] = [
                'source' => '回传接口',
                'scene' => (string) ($log['event'] ?? 'callback'),
                'status' => (string) ($log['status'] ?? 'pending'),
                'order_no' => (string) ($log['order_no'] ?? ''),
                'api_url' => (string) ($log['endpoint'] ?? ''),
                'method' => 'POST',
                'message' => (string) ($log['message'] ?? ''),
                'created_at' => (string) (($log['updated_at'] ?? '') ?: ($log['created_at'] ?? '')),
            ];
        }
        foreach ((array) ($data['mini_program_sync_tasks'] ?? []) as $task) {
            $request = (array) ($task['request_snapshot'] ?? []);
            foreach ((array) ($task['action_logs'] ?? []) as $log) {
                $logs[] = [
                    'source' => '小程序接口',
                    'scene' => (string) ($log['action'] ?? ($task['last_action'] ?? 'sync')),
                    'status' => (string) ($log['status'] ?? 'pending'),
                    'order_no' => '',
                    'api_url' => (string) ($request['api_url'] ?? ($request['endpoint'] ?? '')),
                    'method' => (string) ($request['method'] ?? 'POST'),
                    'message' => (string) ($log['message'] ?? ($task['message'] ?? '')),
                    'created_at' => (string) ($log['created_at'] ?? ($task['updated_at'] ?? '')),
                ];
            }
        }
        usort($logs, static fn (array $a, array $b): int => strcmp((string) ($b['created_at'] ?? ''), (string) ($a['created_at'] ?? '')));

        return array_slice($logs, 0, 300);
    }

    private function filterPresetsForAdmin(array $data, array $scope): array
    {
        $adminId = (int) ($_SESSION['admin_id'] ?? 0);
        $presets = array_values(array_filter((array) ($data['filter_presets'] ?? []), static function (array $preset) use ($adminId): bool {
            return !empty($preset['is_shared']) || (int) ($preset['admin_id'] ?? 0) === $adminId;
        }));
        usort($presets, static fn (array $a, array $b): int => strcmp((string) ($b['updated_at'] ?? ''), (string) ($a['updated_at'] ?? '')));

        return array_slice($presets, 0, !empty($scope['restricted']) ? 80 : 120);
    }

    private function normalizeFilterPresetScope(string $scope): string
    {
        return in_array($scope, ['orders', 'callback_logs', 'analytics'], true) ? $scope : 'orders';
    }

    private function filterPresetPayload(string $scope, array $payload): array
    {
        $hasNestedFilters = is_array($payload['filters'] ?? null);
        $source = $hasNestedFilters ? (array) $payload['filters'] : $payload;
        if ($scope === 'analytics') {
            $mapping = $hasNestedFilters
                ? [
                    'date_preset' => ['date_preset', 'analytics_date_preset'],
                    'date_start' => ['date_start', 'analytics_date_start'],
                    'date_end' => ['date_end', 'analytics_date_end'],
                    'app_key' => ['app_key', 'analytics_app_key'],
                    'business_id' => ['business_id', 'analytics_business_id'],
                    'leader_id' => ['leader_id', 'analytics_leader_id'],
                    'agent_id' => ['agent_id', 'analytics_agent_id'],
                    'promotion_link_id' => ['promotion_link_id', 'analytics_promotion_link_id'],
                    'promotion_code' => ['promotion_code', 'analytics_promotion_code'],
                    'traffic_platform' => ['traffic_platform', 'analytics_traffic_platform'],
                    'channel_id' => ['channel_id', 'analytics_channel_id'],
                    'ad_id' => ['ad_id', 'analytics_ad_id'],
                    'material_id' => ['material_id', 'analytics_material_id'],
                ]
                : [
                    'date_preset' => ['analytics_date_preset'],
                    'date_start' => ['analytics_date_start'],
                    'date_end' => ['analytics_date_end'],
                    'app_key' => ['analytics_app_key'],
                    'business_id' => ['analytics_business_id'],
                    'leader_id' => ['analytics_leader_id'],
                    'agent_id' => ['analytics_agent_id'],
                    'promotion_link_id' => ['analytics_promotion_link_id'],
                    'promotion_code' => ['analytics_promotion_code'],
                    'traffic_platform' => ['analytics_traffic_platform'],
                    'channel_id' => ['analytics_channel_id'],
                    'ad_id' => ['analytics_ad_id'],
                    'material_id' => ['analytics_material_id'],
                ];
        } elseif ($scope === 'callback_logs') {
            $mapping = $hasNestedFilters
                ? [
                    'status' => ['status', 'callback_status'],
                    'event' => ['event', 'callback_event'],
                    'order_no' => ['order_no', 'callback_order_no'],
                    'code' => ['code', 'callback_code'],
                    'platform' => ['platform', 'callback_platform'],
                    'app_key' => ['app_key', 'callback_app_key'],
                    'ad_id' => ['ad_id', 'callback_ad_id'],
                    'material_id' => ['material_id', 'callback_material_id'],
                ]
                : [
                    'status' => ['callback_status'],
                    'event' => ['callback_event'],
                    'order_no' => ['callback_order_no'],
                    'code' => ['callback_code'],
                    'platform' => ['callback_platform'],
                    'app_key' => ['callback_app_key'],
                    'ad_id' => ['callback_ad_id'],
                    'material_id' => ['callback_material_id'],
                ];
        } else {
            $mapping = [
                'order_no' => ['order_no'],
                'user_keyword' => ['user_keyword'],
                'payment_route_id' => ['payment_route_id'],
                'promotion_code' => ['promotion_code'],
                'traffic_platform' => ['traffic_platform'],
                'channel_id' => ['channel_id'],
                'media_app_id' => ['media_app_id'],
                'ad_id' => ['ad_id'],
                'material_id' => ['material_id'],
                'status' => ['status'],
                'per_page' => ['per_page'],
            ];
        }

        $filters = [];
        foreach ($mapping as $target => $keys) {
            $value = '';
            foreach ($keys as $key) {
                if (array_key_exists($key, $source)) {
                    $value = trim((string) $source[$key]);
                    break;
                }
            }
            if (in_array($target, ['business_id', 'leader_id', 'agent_id', 'promotion_link_id'], true)) {
                $value = (string) max(0, (int) $value);
            } elseif ($target === 'app_key') {
                $value = $this->normalizeAppKey($value);
            } elseif ($target === 'promotion_code') {
                $value = preg_replace('/[^a-zA-Z0-9_-]+/', '', $value) ?: '';
            } elseif ($target === 'date_preset') {
                $value = in_array($value, ['today', 'yesterday', 'last_7_days', 'last_30_days', 'last_90_days', 'this_month', 'last_month', 'custom'], true) ? $value : 'all';
            } elseif (in_array($target, ['date_start', 'date_end'], true)) {
                $value = preg_match('/^\d{4}-\d{2}-\d{2}$/', $value) === 1 ? $value : '';
            } elseif ($target === 'status' && $scope === 'orders') {
                $value = in_array($value, ['all', 'pending', 'paid', 'refund_pending', 'partial_refunded', 'refunded', 'failed', 'closed', 'expired'], true) ? $value : 'all';
            } elseif ($target === 'status') {
                $value = in_array($value, ['all', 'pending', 'success', 'failed', 'skipped'], true) ? $value : 'all';
            } elseif ($target === 'event') {
                $value = in_array($value, ['all', 'add_desktop', 'paid'], true) ? $value : 'all';
            } elseif ($target === 'per_page') {
                $perPage = (int) $value;
                $value = (string) (in_array($perPage, [10, 100], true) ? $perPage : 10);
            } else {
                $value = $this->limitText($value, 100);
            }

            if ($value === '' || $value === '0' || $value === 'all' || ($target === 'per_page' && $value === '10')) {
                continue;
            }
            $filters[$target] = $value;
        }

        return $filters;
    }

    private function nextFilterPresetId(array $presets): int
    {
        $ids = array_map(static fn (array $preset): int => (int) ($preset['id'] ?? 0), $presets);

        return empty($ids) ? 1 : (max($ids) + 1);
    }

    private function adminOperationSummary(array $payload): array
    {
        $summary = [];
        $blockedPatterns = ['password', 'secret', 'private_key', 'public_key', 'token', 'sign', 'key'];
        foreach ($payload as $key => $value) {
            $keyText = strtolower((string) $key);
            if (in_array($keyText, ['csrf_token', 'admin_action', 'admin_section'], true)) {
                continue;
            }
            $sensitive = false;
            foreach ($blockedPatterns as $pattern) {
                if (str_contains($keyText, $pattern)) {
                    $sensitive = true;
                    break;
                }
            }
            if ($sensitive) {
                $summary[$key] = '[已隐藏]';
                continue;
            }
            if (is_array($value)) {
                $summary[$key] = 'array(' . count($value) . ')';
                continue;
            }
            $text = trim((string) $value);
            if ($text === '') {
                continue;
            }
            $summary[$key] = $this->limitText($text, 120);
            if (count($summary) >= 12) {
                break;
            }
        }

        return $summary;
    }

    public function payOrder(string $orderNo): ?array
    {
        return $this->confirmOrderPaid($orderNo, 'system', '支付成功已确认。');
    }

    public function confirmOrderPaid(string $orderNo, string $confirmedBy = 'system', string $reason = '支付成功已确认。'): ?array
    {
        $data = $this->store->load();
        foreach ($data['orders'] as &$order) {
            if ($order['order_no'] === $orderNo) {
                $order = $this->normalizeOrderState($order);
                if (($order['status'] ?? '') === 'refunded') {
                    $order['last_status_checked_at'] = date('Y-m-d H:i:s');
                    return $order;
                }
                if (in_array(($order['status'] ?? ''), ['paid', 'partial_refunded'], true)) {
                    $order['last_status_checked_at'] = date('Y-m-d H:i:s');
                    return $order;
                }
                if (($order['status'] ?? '') !== 'paid') {
                    $order['status'] = 'paid';
                    $order['status_reason'] = $reason;
                    $order['paid_confirmed_by'] = $confirmedBy;
                    $order['last_status_checked_at'] = date('Y-m-d H:i:s');
                    $order['paid_at'] = date('Y-m-d H:i:s');
                    if (!empty($order['is_test'])) {
                        $order['test_paid_at'] = $order['paid_at'];
                    } else {
                        $this->grantEntitlement($data, $order);
                        $this->appendContentEvent($data, 'unlock_success', [
                            'content_type' => (string) ($order['content_type'] ?? 'drama'),
                            'drama_id' => (int) ($order['drama_id'] ?? 0),
                            'episode_id' => (int) ($order['episode_id'] ?? 0),
                            'novel_id' => (int) ($order['novel_id'] ?? 0),
                            'chapter_id' => (int) ($order['chapter_id'] ?? 0),
                            'user_id' => (int) ($order['user_id'] ?? 0),
                            'order_no' => (string) ($order['order_no'] ?? ''),
                            'amount' => (float) ($order['amount'] ?? 0),
                        ] + $this->trafficMetaFromPayload($order));
                        $this->appendPromotionEventFromOrder($data, $order, 'activate');
                        $this->recordPromotionPaidEvent($data, $order);
                        $data['stats']['orders'] = (int) ($data['stats']['orders'] ?? 0) + 1;
                        $data['stats']['revenue'] = (float) ($data['stats']['revenue'] ?? 0) + (float) $order['amount'];
                        $contentTitle = (string) ($order['type'] ?? '') === 'membership'
                            ? 'VIP会员'
                            : $this->contentTitleFromData($data, (string) ($order['content_type'] ?? 'drama'), (int) ($order['drama_id'] ?? 0), (int) ($order['novel_id'] ?? 0));
                        $this->appendUserInAppMessageFromTemplate($data, (int) ($order['user_id'] ?? 0), 'payment_success_notice', [
                            'order_no' => (string) ($order['order_no'] ?? ''),
                            'amount' => number_format((float) ($order['amount'] ?? 0), 2, '.', ''),
                            'content' => $contentTitle,
                            'rights' => $this->orderRightsLabel($order),
                        ], [
                            'source' => 'payment',
                            'reference_type' => 'order',
                            'reference_id' => (int) ($order['id'] ?? 0),
                            'priority' => 'normal',
                            'title' => '支付成功：' . $contentTitle,
                            'body' => '订单 ' . (string) ($order['order_no'] ?? '') . ' 已支付成功，对应权益已发放。',
                            'created_at' => (string) ($order['paid_at'] ?? date('Y-m-d H:i:s')),
                            'updated_at' => (string) ($order['paid_at'] ?? date('Y-m-d H:i:s')),
                        ]);
                    }
                    $this->store->save($data);
                }

                return $order;
            }
        }

        return null;
    }

    public function updateOrderPaymentState(string $orderNo, string $remoteStatus, string $message = '', string $checkedBy = 'query'): ?array
    {
        $status = strtoupper(trim(str_replace(['-', ' '], '_', $remoteStatus)));
        $localStatus = match ($status) {
            'SUCCESS', 'CALL_FAIL', 'TRADE_SUCCESS', 'PAID', 'PAY_SUCCESS', 'PAYED', 'ORDER_PAID', 'FINISHED', 'COMPLETE', 'COMPLETED' => 'paid',
            'TIME_OUT', 'TIMEOUT', 'EXPIRED' => 'expired',
            'FAIL', 'FAILED', 'PAY_FAIL', 'PAY_FAILED' => 'failed',
            'CLOSE', 'CLOSED' => 'closed',
            default => 'pending',
        };

        if ($localStatus === 'paid') {
            return $this->confirmOrderPaid($orderNo, $checkedBy, $message !== '' ? $message : '支付成功已确认。');
        }

        $data = $this->store->load();
        foreach ($data['orders'] as &$order) {
            if ((string) ($order['order_no'] ?? '') !== $orderNo) {
                continue;
            }

            $order = $this->normalizeOrderState($order);
            if (!in_array((string) ($order['status'] ?? 'pending'), ['paid', 'partial_refunded', 'refunded'], true)) {
                $order['status'] = $localStatus;
                $order['status_reason'] = $message !== '' ? $message : match ($localStatus) {
                    'expired' => '订单已过期。',
                    'failed' => '订单支付失败。',
                    'closed' => '订单已关闭。',
                    default => '订单仍待支付。',
                };
            }
            $order['last_status_checked_at'] = date('Y-m-d H:i:s');
            $order['paid_confirmed_by'] = $checkedBy;
            $this->store->save($data);

            return $order;
        }

        return null;
    }

    public function latestPendingRefundRequest(array $order): ?array
    {
        $requests = array_reverse(array_values((array) ($order['refund_requests'] ?? [])));
        foreach ($requests as $request) {
            $status = (string) ($request['status'] ?? 'processing');
            if (in_array($status, ['pending', 'processing'], true)) {
                return $request;
            }
        }

        if (!empty($order['refund_pending']) && !empty($order['refund_no'])) {
            return [
                'refund_no' => (string) $order['refund_no'],
                'gateway_refund_no' => (string) ($order['gateway_refund_no'] ?? ''),
                'amount' => (float) ($order['last_refund_amount'] ?? 0),
                'status' => 'processing',
                'created_at' => (string) ($order['refund_requested_at'] ?? $order['refunded_at'] ?? ''),
                'apply_response' => $order['refund_response'] ?? null,
            ];
        }

        return null;
    }

    public function createRefundRequest(string $orderNo, float $amount, string $refundNo, string $gatewayRefundNo = '', array|string|null $remoteResponse = null): ?array
    {
        $data = $this->store->load();
        foreach ($data['orders'] as &$order) {
            if ($order['order_no'] !== $orderNo) {
                continue;
            }

            $now = date('Y-m-d H:i:s');
            $requests = array_values((array) ($order['refund_requests'] ?? []));
            $requests[] = [
                'refund_no' => $refundNo,
                'gateway_refund_no' => $gatewayRefundNo,
                'amount' => round($amount, 2),
                'status' => 'processing',
                'created_at' => $now,
                'updated_at' => $now,
                'apply_response' => $remoteResponse,
                'query_response' => null,
            ];

            $order['refund_requests'] = $requests;
            $order['status'] = 'refund_pending';
            $order['status_reason'] = '退款申请已提交，等待通道确认。';
            $order['refund_pending'] = true;
            $order['refund_status'] = 'processing';
            $order['refund_no'] = $refundNo;
            $order['gateway_refund_no'] = $gatewayRefundNo;
            $order['last_refund_amount'] = round($amount, 2);
            $order['refund_requested_at'] = $now;
            $order['refund_response'] = $remoteResponse;
            $this->store->save($data);

            return $order;
        }

        return null;
    }

    public function createFailedRefundRequest(string $orderNo, float $amount, string $refundNo, array|string|null $remoteResponse = null, string $message = ''): ?array
    {
        $data = $this->store->load();
        foreach ($data['orders'] as &$order) {
            if ($order['order_no'] !== $orderNo) {
                continue;
            }

            $now = date('Y-m-d H:i:s');
            $requests = array_values((array) ($order['refund_requests'] ?? []));
            $requests[] = [
                'refund_no' => $refundNo,
                'gateway_refund_no' => '',
                'amount' => round($amount, 2),
                'status' => 'failed',
                'message' => $message,
                'created_at' => $now,
                'updated_at' => $now,
                'failed_at' => $now,
                'apply_response' => $remoteResponse,
                'query_response' => null,
            ];

            $order['refund_requests'] = $requests;
            $order['refund_pending'] = $this->hasPendingRefundRequest($requests);
            $order['refund_status'] = $order['refund_pending'] ? 'processing' : 'failed';
            $order['refund_failed_reason'] = $message;
            $order['refund_no'] = $refundNo;
            $order['last_refund_amount'] = round($amount, 2);
            $order['refund_failed_at'] = $now;
            $order['refund_response'] = $remoteResponse;
            $this->store->save($data);

            return $order;
        }

        return null;
    }

    public function refundOrder(string $orderNo, float $amount, string $refundNo, array|string|null $remoteResponse = null): ?array
    {
        $data = $this->store->load();
        foreach ($data['orders'] as &$order) {
            if ($order['order_no'] !== $orderNo) {
                continue;
            }

            $orderAmount = (float) ($order['amount'] ?? 0);
            $existingRefund = (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0);
            $requests = array_values((array) ($order['refund_requests'] ?? []));
            foreach ($requests as $request) {
                if (($request['refund_no'] ?? '') === $refundNo && ($request['status'] ?? '') === 'success' && !empty($request['finalized_at'])) {
                    return $order;
                }
            }
            if (($order['status'] ?? '') === 'refunded' && $existingRefund >= $orderAmount) {
                return $order;
            }

            $refundTotal = min($orderAmount, round($existingRefund + $amount, 2));
            $isFullRefund = $orderAmount > 0 && $refundTotal >= round($orderAmount, 2);
            $now = date('Y-m-d H:i:s');

            $order['status'] = $isFullRefund ? 'refunded' : 'partial_refunded';
            $order['refund_no'] = $refundNo;
            $order['refund_amount'] = $refundTotal;
            $order['refund_total'] = $refundTotal;
            $order['last_refund_amount'] = $amount;
            $order['refunded_at'] = $now;
            $order['refund_response'] = $remoteResponse;
            $matchedRequest = false;
            foreach ($requests as &$request) {
                if (($request['refund_no'] ?? '') !== $refundNo) {
                    continue;
                }

                $request['status'] = 'success';
                $request['amount'] = round($amount, 2);
                $request['query_response'] = $remoteResponse;
                $request['updated_at'] = $now;
                $request['refunded_at'] = $now;
                $request['finalized_at'] = $now;
                $matchedRequest = true;
                break;
            }
            unset($request);
            if (!$matchedRequest) {
                $requests[] = [
                    'refund_no' => $refundNo,
                    'gateway_refund_no' => (string) ($order['gateway_refund_no'] ?? ''),
                    'amount' => round($amount, 2),
                    'status' => 'success',
                    'created_at' => $now,
                    'updated_at' => $now,
                    'refunded_at' => $now,
                    'finalized_at' => $now,
                    'apply_response' => $remoteResponse,
                    'query_response' => $remoteResponse,
                ];
            }
            $order['refund_requests'] = $requests;
            $order['refund_pending'] = $this->hasPendingRefundRequest($requests);
            $order['refund_status'] = $order['refund_pending'] ? 'processing' : 'success';
            $order['refund_history'] = array_values($order['refund_history'] ?? []);
            $order['refund_history'][] = [
                'refund_no' => $refundNo,
                'amount' => $amount,
                'status' => 'success',
                'created_at' => $order['refunded_at'],
                'remote_response' => $remoteResponse,
            ];

            if ($isFullRefund) {
                $this->revokeEntitlement($data, $order);
            }

            $data['stats']['revenue'] = max(0, (float) ($data['stats']['revenue'] ?? 0) - $amount);
            $this->store->save($data);

            return $order;
        }

        return null;
    }

    public function markRefundRequestFailed(string $orderNo, string $refundNo, array|string|null $remoteResponse = null): ?array
    {
        $data = $this->store->load();
        foreach ($data['orders'] as &$order) {
            if ($order['order_no'] !== $orderNo) {
                continue;
            }

            $now = date('Y-m-d H:i:s');
            $requests = array_values((array) ($order['refund_requests'] ?? []));
            foreach ($requests as &$request) {
                if (($request['refund_no'] ?? '') !== $refundNo) {
                    continue;
                }

                $request['status'] = 'failed';
                $request['query_response'] = $remoteResponse;
                $request['updated_at'] = $now;
                $request['failed_at'] = $now;
                break;
            }
            unset($request);

            $order['refund_requests'] = $requests;
            $order['refund_pending'] = $this->hasPendingRefundRequest($requests);
            $order['refund_status'] = $order['refund_pending'] ? 'processing' : 'failed';
            $order['refund_query_response'] = $remoteResponse;
            $order['refund_failed_reason'] = is_array($remoteResponse)
                ? (string) ($remoteResponse['msg'] ?? $remoteResponse['message'] ?? '通道返回退款失败。')
                : (string) ($remoteResponse ?: '通道返回退款失败。');
            $order['status_reason'] = '退款查询失败：' . $order['refund_failed_reason'];
            $order['refund_failed_at'] = $now;
            $this->store->save($data);

            return $order;
        }

        return null;
    }

    public function updateRefundRequestQuery(string $orderNo, string $refundNo, array|string|null $remoteResponse = null): ?array
    {
        $data = $this->store->load();
        foreach ($data['orders'] as &$order) {
            if ($order['order_no'] !== $orderNo) {
                continue;
            }

            $now = date('Y-m-d H:i:s');
            $requests = array_values((array) ($order['refund_requests'] ?? []));
            foreach ($requests as &$request) {
                if (($request['refund_no'] ?? '') !== $refundNo) {
                    continue;
                }

                $request['status'] = (string) ($request['status'] ?? 'processing') === 'pending' ? 'processing' : (string) ($request['status'] ?? 'processing');
                $request['query_response'] = $remoteResponse;
                $request['updated_at'] = $now;
                $request['last_queried_at'] = $now;
                break;
            }
            unset($request);

            $order['refund_requests'] = $requests;
            $order['refund_pending'] = $this->hasPendingRefundRequest($requests);
            $order['refund_status'] = $order['refund_pending'] ? 'processing' : (string) ($order['refund_status'] ?? 'processing');
            $order['refund_query_response'] = $remoteResponse;
            $order['refund_last_queried_at'] = $now;
            if ($order['refund_pending']) {
                $order['status'] = 'refund_pending';
                $order['status_reason'] = '退款仍在处理中。';
            }
            $this->store->save($data);

            return $order;
        }

        return null;
    }

    public function userEntitlements(int $userId): array
    {
        return array_values(array_filter($this->store->load()['entitlements'], static fn ($item) => (int) $item['user_id'] === $userId));
    }

    public function hasAccess(int $userId, int $dramaId, ?int $episodeId = null): bool
    {
        $data = $this->store->load();
        $user = null;
        foreach ($data['users'] as $item) {
            if ((int) $item['id'] === $userId) {
                $user = $item;
                break;
            }
        }

        if ($user && !empty($user['membership'])) {
            if (!empty($user['membership_expires_at']) && strtotime((string) $user['membership_expires_at']) < time()) {
                return false;
            }
            return true;
        }

        if ($episodeId === null) {
            foreach ($data['entitlements'] as $item) {
                $itemContentType = in_array((string) ($item['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $item['content_type'] : 'drama';
                if ($itemContentType === 'drama' && (int) $item['user_id'] === $userId && (int) $item['drama_id'] === $dramaId && in_array((string) ($item['type'] ?? ''), ['drama_unlock', 'membership', 'vip_week', 'vip_month'], true)) {
                    return true;
                }
            }

            return false;
        }

        foreach ($data['entitlements'] as $item) {
            $itemContentType = in_array((string) ($item['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $item['content_type'] : 'drama';
            if ($itemContentType !== 'drama' || (int) $item['user_id'] !== $userId || (int) $item['drama_id'] !== $dramaId) {
                continue;
            }
            if (in_array((string) ($item['type'] ?? ''), ['drama_unlock', 'membership', 'vip_week', 'vip_month'], true) && empty($item['episode_id'])) {
                return true;
            }
            if ((int) ($item['episode_id'] ?? 0) === $episodeId) {
                return true;
            }
        }

        return false;
    }

    public function hasNovelAccess(int $userId, int $novelId, ?int $chapterId = null): bool
    {
        $data = $this->store->load();
        $user = null;
        foreach ($data['users'] as $item) {
            if ((int) ($item['id'] ?? 0) === $userId) {
                $user = $item;
                break;
            }
        }

        if ($user && !empty($user['membership'])) {
            if (!empty($user['membership_expires_at']) && strtotime((string) $user['membership_expires_at']) < time()) {
                return false;
            }
            return true;
        }

        foreach ((array) ($data['entitlements'] ?? []) as $item) {
            if ((int) ($item['user_id'] ?? 0) !== $userId || (int) ($item['novel_id'] ?? 0) !== $novelId) {
                continue;
            }
            if (in_array((string) ($item['type'] ?? ''), ['novel_unlock', 'membership', 'vip_week', 'vip_month'], true) && empty($item['chapter_id'])) {
                return true;
            }
            if ($chapterId !== null && (int) ($item['chapter_id'] ?? 0) === $chapterId) {
                return true;
            }
        }

        return false;
    }

    private function grantEntitlement(array &$data, array $order): void
    {
        if (($order['type'] ?? '') === 'coin_recharge') {
            $this->grantCoinsForOrder($data, $order);
            return;
        }

        $entitlementType = match ((string) ($order['type'] ?? '')) {
            'vip_week', 'vip_month' => 'membership',
            'episode' => 'episode_unlock',
            default => (string) ($order['type'] ?? 'episode_unlock'),
        };
        $contentType = in_array((string) ($order['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $order['content_type'] : 'drama';
        $episodeId = $entitlementType === 'drama_unlock' || $entitlementType === 'membership' || $contentType === 'novel' ? null : ($order['episode_id'] ?? null);
        $chapterId = in_array($entitlementType, ['novel_unlock', 'membership'], true) ? null : ($order['chapter_id'] ?? null);
        $isMembershipOrder = in_array((string) ($order['type'] ?? ''), ['membership', 'vip_week', 'vip_month'], true);
        $hasExistingEntitlement = false;

        foreach ($data['entitlements'] as $item) {
            $itemContentType = in_array((string) ($item['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $item['content_type'] : 'drama';
            $sameBase = (int) $item['user_id'] === (int) $order['user_id']
                && $itemContentType === $contentType
                && (int) ($item['drama_id'] ?? 0) === (int) ($order['drama_id'] ?? 0)
                && (int) ($item['episode_id'] ?? 0) === (int) ($episodeId ?? 0)
                && (int) ($item['novel_id'] ?? 0) === (int) ($order['novel_id'] ?? 0)
                && (int) ($item['chapter_id'] ?? 0) === (int) ($chapterId ?? 0)
                && (string) ($item['type'] ?? '') === $entitlementType;
            if ($sameBase && !$isMembershipOrder) {
                return;
            }
            if ($sameBase && $isMembershipOrder && (string) ($item['source_order_no'] ?? '') === (string) ($order['order_no'] ?? '')) {
                if (!$isMembershipOrder) {
                    return;
                }
                $hasExistingEntitlement = true;
                break;
            }
        }

        if (!$hasExistingEntitlement) {
            $data['entitlements'][] = [
                'user_id' => $order['user_id'],
                'content_type' => $contentType,
                'drama_id' => $order['drama_id'],
                'episode_id' => $episodeId,
                'novel_id' => (int) ($order['novel_id'] ?? 0),
                'chapter_id' => $chapterId,
                'type' => $entitlementType,
                'source_order_no' => $order['order_no'] ?? '',
                'granted_at' => date('Y-m-d H:i:s'),
            ];
        }

        if ($isMembershipOrder) {
            $days = (int) ($order['vip_days'] ?? ((string) ($order['type'] ?? '') === 'vip_week' ? 7 : 30));
            foreach ($data['users'] as &$user) {
                if ((int) $user['id'] === (int) $order['user_id']) {
                    $currentExpiresAt = strtotime((string) ($user['membership_expires_at'] ?? '')) ?: time();
                    $base = max(time(), $currentExpiresAt);
                    $user['membership'] = true;
                    $user['membership_expires_at'] = date('Y-m-d H:i:s', $base + max(1, $days) * 86400);
                }
            }
            unset($user);
        }
    }

    private function grantCoinsForOrder(array &$data, array $order): void
    {
        $userId = (int) ($order['user_id'] ?? 0);
        $coins = max(0, (int) ($order['coin_amount'] ?? 0));
        $bonusCoins = max(0, (int) ($order['bonus_coin_amount'] ?? 0));
        if ($userId <= 0 || ($coins + $bonusCoins) <= 0) {
            return;
        }

        foreach ($data['coin_transactions'] ?? [] as $item) {
            if ((string) ($item['source_order_no'] ?? '') === (string) ($order['order_no'] ?? '')) {
                return;
            }
        }

        foreach ($data['users'] as &$user) {
            if ((int) ($user['id'] ?? 0) !== $userId) {
                continue;
            }
            $user['coin_balance'] = max(0, (int) ($user['coin_balance'] ?? 0)) + $coins;
            $user['bonus_coin_balance'] = max(0, (int) ($user['bonus_coin_balance'] ?? 0)) + $bonusCoins;
            $data['coin_transactions'][] = [
                'id' => count($data['coin_transactions'] ?? []) + 1,
                'user_id' => $userId,
                'type' => 'recharge',
                'scene' => 'coin_recharge',
                'coins' => $coins + $bonusCoins,
                'balance_after' => (int) $user['coin_balance'] + (int) $user['bonus_coin_balance'],
                'source_order_no' => (string) ($order['order_no'] ?? ''),
                'remark' => 'K币充值到账',
                'created_at' => date('Y-m-d H:i:s'),
            ];
            break;
        }
        unset($user);
    }

