            'position' => (string) ($slot['position'] ?? ''),
            'app_key' => (string) ($slot['app_key'] ?? 'default'),
            'provider' => (string) ($slot['provider'] ?? ''),
            'unit_id' => (string) ($slot['unit_id'] ?? ''),
            'estimate_ecpm' => round(max(0, (float) ($slot['estimate_ecpm'] ?? 0)), 2),
            'revenue_share_rate' => min(100, max(0, round((float) ($slot['revenue_share_rate'] ?? 100), 2))),
            'title' => (string) ($slot['title'] ?? ''),
            'image' => (string) ($slot['image'] ?? ''),
            'link' => (string) ($slot['link'] ?? ''),
            'reward_coins' => max(0, (int) ($slot['reward_coins'] ?? 0)),
            'daily_limit' => max(0, (int) ($slot['daily_limit'] ?? 0)),
            'frequency_seconds' => max(0, (int) ($slot['frequency_seconds'] ?? 0)),
            'sort' => (int) ($slot['sort'] ?? 100),
            'delivery_priority' => (int) ($slot['delivery_priority'] ?? $slot['sort'] ?? 100),
            'delivery_rule' => is_array($slot['delivery_rule'] ?? null) ? (array) $slot['delivery_rule'] : [],
            'waterfall' => is_array($slot['waterfall'] ?? null) ? (array) $slot['waterfall'] : [],
            'platform_config' => $platformConfig,
        ];
    }

    private function publicAdDeliveryRule(array $rule): array
    {
        return [
            'id' => (int) ($rule['id'] ?? 0),
            'code' => (string) ($rule['code'] ?? ''),
            'name' => (string) ($rule['name'] ?? ''),
            'status' => (string) ($rule['status'] ?? 'active'),
            'app_keys' => array_values(array_map('strval', (array) ($rule['app_keys'] ?? []))),
            'slot_codes' => array_values(array_map('strval', (array) ($rule['slot_codes'] ?? []))),
            'positions' => array_values(array_map('strval', (array) ($rule['positions'] ?? []))),
            'ad_types' => array_values(array_map('strval', (array) ($rule['ad_types'] ?? []))),
            'providers' => array_values(array_map('strval', (array) ($rule['providers'] ?? []))),
            'user_tags' => array_values(array_map('strval', (array) ($rule['user_tags'] ?? []))),
            'membership' => (string) ($rule['membership'] ?? 'all'),
            'pay_stage' => (string) ($rule['pay_stage'] ?? 'all'),
            'priority' => (int) ($rule['priority'] ?? 100),
            'daily_limit_override' => max(0, (int) ($rule['daily_limit_override'] ?? 0)),
            'frequency_seconds_override' => max(0, (int) ($rule['frequency_seconds_override'] ?? 0)),
            'reward_coins_override' => max(0, (int) ($rule['reward_coins_override'] ?? 0)),
            'max_impressions_per_day' => max(0, (int) ($rule['max_impressions_per_day'] ?? 0)),
            'remark' => (string) ($rule['remark'] ?? ''),
        ];
    }

    private function matchingAdDeliveryRule(array $slot, array $data, array $filters = [], string $appKey = ''): ?array
    {
        $appKey = $this->normalizeAppKey($appKey !== '' ? $appKey : (string) ($slot['app_key'] ?? 'default'));
        $appKey = $appKey !== '' ? $appKey : 'default';
        $rules = $this->activeSlotScopedDeliveryRules($slot, $data, $appKey);
        if (empty($rules)) {
            return null;
        }

        $userId = max(0, (int) ($filters['user_id'] ?? $this->currentUserId()));
        $context = $this->adDeliveryUserContext($data, $filters, $userId);
        foreach ($rules as $rule) {
            if (!$this->adDeliveryRuleMatchesUser($rule, $context)) {
                continue;
            }
            if (!$this->adDeliveryRuleWithinDailyImpressions($rule, $slot, $data, $userId)) {
                continue;
            }

            return $rule;
        }

        return null;
    }

    private function activeSlotScopedDeliveryRules(array $slot, array $data, string $appKey): array
    {
        $rules = array_values(array_filter((array) ($data['ad_delivery_rules'] ?? []), function (array $rule) use ($slot, $appKey): bool {
            if ((string) ($rule['status'] ?? 'active') !== 'active') {
                return false;
            }
            if (!$this->listMatchesValue((array) ($rule['app_keys'] ?? []), $appKey, true)) {
                return false;
            }
            $scoped = false;
            foreach (['slot_codes', 'positions', 'ad_types', 'providers'] as $key) {
                if (!empty($rule[$key])) {
                    $scoped = true;
                    break;
                }
            }
            if (!$scoped) {
                return true;
            }
            if (!$this->listMatchesValue((array) ($rule['slot_codes'] ?? []), (string) ($slot['code'] ?? ''))) {
                return false;
            }
            if (!$this->listMatchesValue((array) ($rule['positions'] ?? []), (string) ($slot['position'] ?? ''))) {
                return false;
            }
            if (!$this->listMatchesValue((array) ($rule['ad_types'] ?? []), (string) ($slot['ad_type'] ?? ''))) {
                return false;
            }
            if (!$this->listMatchesValue((array) ($rule['providers'] ?? []), (string) ($slot['provider'] ?? ''))) {
                return false;
            }

            return true;
        }));
        usort($rules, static fn (array $a, array $b): int => [(int) ($a['priority'] ?? 100), (int) ($a['id'] ?? 0)] <=> [(int) ($b['priority'] ?? 100), (int) ($b['id'] ?? 0)]);

        return $rules;
    }

    private function adDeliveryUserContext(array $data, array $filters, int $userId): array
    {
        $user = [];
        foreach ((array) ($data['users'] ?? []) as $item) {
            if ((int) ($item['id'] ?? 0) === $userId) {
                $user = $item;
                break;
            }
        }
        $isMember = !empty($user['membership']);
        $expiresAt = strtotime((string) ($user['membership_expires_at'] ?? '')) ?: 0;
        if ($isMember && $expiresAt > 0 && $expiresAt < time()) {
            $isMember = false;
        }
        $createdAt = strtotime((string) ($user['created_at'] ?? '')) ?: 0;
        $registeredDays = $createdAt > 0 ? max(0, (int) floor((time() - $createdAt) / 86400)) : 0;
        $paidOrderCount = 0;
        foreach ((array) ($data['orders'] ?? []) as $order) {
            if ((int) ($order['user_id'] ?? 0) !== $userId || !empty($order['is_test'])) {
                continue;
            }
            if (in_array((string) ($order['status'] ?? 'pending'), ['paid', 'partial_refunded', 'refunded'], true)) {
                $paidOrderCount++;
            }
        }
        $tags = array_merge(
            $this->listFromPayload($filters['user_tags'] ?? $filters['user_tag'] ?? '', 20, 24),
            $this->listFromPayload($user['tags'] ?? [], 20, 24)
        );
        $tags = array_values(array_unique(array_filter($tags, static fn (string $tag): bool => $tag !== '')));

        return [
            'user_id' => $userId,
            'is_member' => $isMember,
            'paid_order_count' => $paidOrderCount,
            'registered_days' => $registeredDays,
            'pay_stage' => $paidOrderCount > 0 ? 'paid' : ($userId > 0 ? 'unpaid' : 'new'),
            'tags' => $tags,
        ];
    }

    private function adDeliveryRuleMatchesUser(array $rule, array $context): bool
    {
        $membership = (string) ($rule['membership'] ?? 'all');
        if ($membership === 'member' && empty($context['is_member'])) {
            return false;
        }
        if ($membership === 'guest' && !empty($context['is_member'])) {
            return false;
        }
        $payStage = (string) ($rule['pay_stage'] ?? 'all');
        if ($payStage !== 'all' && (string) ($context['pay_stage'] ?? 'new') !== $payStage) {
            return false;
        }
        $ruleTags = array_values(array_map('strval', (array) ($rule['user_tags'] ?? [])));
        if (!empty($ruleTags) && empty(array_intersect($ruleTags, (array) ($context['tags'] ?? [])))) {
            return false;
        }

        return true;
    }

    private function adDeliveryRuleWithinDailyImpressions(array $rule, array $slot, array $data, int $userId): bool
    {
        $limit = max(0, (int) ($rule['max_impressions_per_day'] ?? 0));
        if ($limit <= 0 || $userId <= 0) {
            return true;
        }
        $slotId = (int) ($slot['id'] ?? 0);
        $ruleCode = (string) ($rule['code'] ?? '');
        $today = date('Y-m-d');
        $count = 0;
        foreach ((array) ($data['ad_events'] ?? []) as $event) {
            if ((int) ($event['ad_slot_id'] ?? 0) !== $slotId || (int) ($event['user_id'] ?? 0) !== $userId || (string) ($event['event'] ?? '') !== 'impression') {
                continue;
            }
            if ($ruleCode !== '' && (string) ($event['delivery_rule_code'] ?? '') !== $ruleCode) {
                continue;
            }
            if (substr((string) ($event['created_at'] ?? ''), 0, 10) === $today) {
                $count++;
            }
        }

        return $count < $limit;
    }

    private function applyAdDeliveryRuleToSlot(array $slot, array $rule): array
    {
        foreach (['daily_limit', 'frequency_seconds', 'reward_coins'] as $slotKey) {
            $ruleKey = $slotKey . '_override';
            if (array_key_exists($ruleKey, $rule) && (int) ($rule[$ruleKey] ?? 0) > 0) {
                $slot[$slotKey] = (int) $rule[$ruleKey];
            }
        }
        $slot['delivery_priority'] = (int) ($rule['priority'] ?? ($slot['sort'] ?? 100));
        $slot['delivery_rule'] = [
            'id' => (int) ($rule['id'] ?? 0),
            'code' => (string) ($rule['code'] ?? ''),
            'name' => (string) ($rule['name'] ?? ''),
            'priority' => (int) ($rule['priority'] ?? 100),
        ];

        return $slot;
    }

    private function applyAdWaterfallOrdering(array $slots, array $data): array
    {
        $config = (array) ($data['ad_waterfall_config'] ?? []);
        $enabled = !array_key_exists('enabled', $config) || !empty($config['enabled']);
        $mode = (string) ($config['mode'] ?? 'auto');
        if (!$enabled || $mode === 'manual') {
            usort($slots, static fn (array $a, array $b): int => [(int) ($a['delivery_priority'] ?? $a['sort'] ?? 0), (int) ($a['sort'] ?? 0), (int) ($a['id'] ?? 0)] <=> [(int) ($b['delivery_priority'] ?? $b['sort'] ?? 0), (int) ($b['sort'] ?? 0), (int) ($b['id'] ?? 0)]);
            return $slots;
        }

        $metricsBySlotId = $this->adWaterfallMetricsBySlot($data, $config);
        foreach ($slots as &$slot) {
            $slotId = (int) ($slot['id'] ?? 0);
            $metrics = $metricsBySlotId[$slotId] ?? $this->blankAdWaterfallMetrics();
            $score = $this->adWaterfallScore($slot, $metrics, $config);
            $slot['waterfall'] = [
                'mode' => 'auto',
                'score' => $score,
                'metrics' => $metrics,
                'config' => [
                    'score_window_days' => max(1, (int) ($config['score_window_days'] ?? 7)),
                    'min_requests' => max(0, (int) ($config['min_requests'] ?? 20)),
                ],
            ];
        }
        unset($slot);
        usort($slots, static fn (array $a, array $b): int => [(float) ($b['waterfall']['score'] ?? 0), (int) ($a['delivery_priority'] ?? $a['sort'] ?? 0), (int) ($a['sort'] ?? 0), (int) ($a['id'] ?? 0)] <=> [(float) ($a['waterfall']['score'] ?? 0), (int) ($b['delivery_priority'] ?? $b['sort'] ?? 0), (int) ($b['sort'] ?? 0), (int) ($b['id'] ?? 0)]);
        $maxSlots = max(0, (int) ($config['max_slots'] ?? 0));
        if ($maxSlots > 0) {
            $slots = array_slice($slots, 0, $maxSlots);
        }

        return $slots;
    }

    private function adWaterfallMetricsBySlot(array $data, array $config): array
    {
        $windowDays = max(1, min(90, (int) ($config['score_window_days'] ?? 7)));
        $cutoff = strtotime('-' . $windowDays . ' days') ?: 0;
        $metrics = [];
        foreach ((array) ($data['ad_events'] ?? []) as $event) {
            $createdAt = strtotime((string) ($event['created_at'] ?? '')) ?: 0;
            if ($createdAt > 0 && $createdAt < $cutoff) {
                continue;
            }
            $slotId = (int) ($event['ad_slot_id'] ?? 0);
            if ($slotId <= 0) {
                continue;
            }
            $metrics[$slotId] ??= $this->blankAdWaterfallMetrics();
            $type = (string) ($event['event'] ?? 'impression');
            if ($type === 'request') {
                $metrics[$slotId]['requests']++;
            } elseif ($type === 'fill') {
                $metrics[$slotId]['fills']++;
            } elseif ($type === 'impression') {
                $metrics[$slotId]['impressions']++;
            } elseif ($type === 'click') {
                $metrics[$slotId]['clicks']++;
            } elseif ($type === 'reward') {
                $metrics[$slotId]['rewards']++;
            } elseif ($type === 'fail') {
                $metrics[$slotId]['fails']++;
            }
            $metrics[$slotId]['revenue'] += max(0.0, (float) ($event['revenue'] ?? 0));
        }

        foreach ($metrics as &$row) {
            $requests = max(0, (int) ($row['requests'] ?? 0));
            $fills = max(0, (int) ($row['fills'] ?? 0));
            $impressions = max(0, (int) ($row['impressions'] ?? 0));
            $clicks = max(0, (int) ($row['clicks'] ?? 0));
            $rewards = max(0, (int) ($row['rewards'] ?? 0));
            $fails = max(0, (int) ($row['fails'] ?? 0));
            $row['revenue'] = round((float) ($row['revenue'] ?? 0), 4);
            $row['fill_rate'] = $requests > 0 ? round(($fills / $requests) * 100, 2) : 0.0;
            $row['show_rate'] = $fills > 0 ? round(($impressions / $fills) * 100, 2) : 0.0;
            $row['ctr'] = $impressions > 0 ? round(($clicks / $impressions) * 100, 2) : 0.0;
            $row['reward_rate'] = $impressions > 0 ? round(($rewards / $impressions) * 100, 2) : 0.0;
            $row['failure_rate'] = ($requests + $fails) > 0 ? round(($fails / ($requests + $fails)) * 100, 2) : 0.0;
            $row['ecpm'] = $impressions > 0 ? round(((float) $row['revenue'] / $impressions) * 1000, 2) : 0.0;
            $row['sample_size'] = $requests + $impressions + $fails;
        }
        unset($row);

        return $metrics;
    }

    private function blankAdWaterfallMetrics(): array
    {
        return [
            'requests' => 0,
            'fills' => 0,
            'impressions' => 0,
            'clicks' => 0,
            'rewards' => 0,
            'fails' => 0,
            'revenue' => 0.0,
            'fill_rate' => 0.0,
            'show_rate' => 0.0,
            'ctr' => 0.0,
            'reward_rate' => 0.0,
            'failure_rate' => 0.0,
            'ecpm' => 0.0,
            'sample_size' => 0,
        ];
    }

    private function adWaterfallScore(array $slot, array $metrics, array $config): float
    {
        $minRequests = max(0, (int) ($config['min_requests'] ?? 20));
        $sampleSize = max(0, (int) ($metrics['sample_size'] ?? 0));
        $confidence = $minRequests > 0 ? min(1.0, $sampleSize / $minRequests) : 1.0;
        $reportedEcpm = max(0.0, (float) ($metrics['ecpm'] ?? 0));
        $estimateEcpm = max(0.0, (float) ($slot['estimate_ecpm'] ?? 0));
        $effectiveEcpm = $reportedEcpm > 0 ? ($reportedEcpm * $confidence + $estimateEcpm * (1 - $confidence)) : $estimateEcpm * max(0.35, 1 - $confidence * 0.35);
        $manualRank = max(0.0, 100.0 - min(100.0, max(0.0, (float) ($slot['sort'] ?? 100))));
        $score = 0.0;
        $score += $effectiveEcpm * ((float) ($config['ecpm_weight'] ?? 45) / 10);
        $score += min(100.0, max(0.0, (float) ($metrics['fill_rate'] ?? 0))) * ((float) ($config['fill_rate_weight'] ?? 25) / 100);
        $score += min(100.0, max(0.0, (float) ($metrics['ctr'] ?? 0))) * ((float) ($config['ctr_weight'] ?? 10) / 100);
        $score += min(100.0, max(0.0, (float) ($metrics['reward_rate'] ?? 0))) * ((float) ($config['reward_rate_weight'] ?? 10) / 100);
        $score += $manualRank * ((float) ($config['manual_sort_weight'] ?? 10) / 100);
        $score -= min(100.0, max(0.0, (float) ($metrics['failure_rate'] ?? 0))) * ((float) ($config['failure_penalty_weight'] ?? 25) / 100);
        $score *= (0.6 + $confidence * 0.4);

        return round($score, 4);
    }

    private function listMatchesValue(array $list, string $value, bool $defaultMatches = false): bool
    {
        $items = array_values(array_map('strval', $list));
        if (empty($items)) {
            return true;
        }
        if ($defaultMatches && in_array('default', $items, true)) {
            return true;
        }

        return in_array($value, $items, true);
    }

    private function publicAdPlatformConfigForSlot(array $slot): array
    {
        $provider = (string) ($slot['provider'] ?? '');
        if ($provider === '') {
            return [];
        }
        $appKey = (string) ($slot['app_key'] ?? 'default');
        foreach ($this->activeAdPlatformConfigs(['app_key' => $appKey, 'provider' => $provider]) as $config) {
            if ((string) ($config['app_key'] ?? 'default') === $appKey || (string) ($config['app_key'] ?? 'default') === 'default') {
                return $config;
            }
        }

        return [];
    }

    private function publicAdPlatformConfig(array $config): array
    {
        return [
            'id' => (int) ($config['id'] ?? 0),
            'app_key' => (string) ($config['app_key'] ?? 'default'),
            'provider' => (string) ($config['provider'] ?? ''),
            'provider_name' => (string) ($config['provider_name'] ?? ''),
            'status' => (string) ($config['status'] ?? 'active'),
            'platform_app_id' => (string) ($config['platform_app_id'] ?? ''),
            'account_id' => (string) ($config['account_id'] ?? ''),
            'media_id' => (string) ($config['media_id'] ?? ''),
            'currency' => (string) ($config['currency'] ?? 'CNY'),
            'default_ecpm' => round(max(0, (float) ($config['default_ecpm'] ?? 0)), 2),
            'revenue_share_rate' => min(100, max(0, round((float) ($config['revenue_share_rate'] ?? 100), 2))),
            'test_mode' => !empty($config['test_mode']) || (string) ($config['status'] ?? '') === 'test',
            'init_params' => is_array($config['init_params'] ?? null) ? $config['init_params'] : [],
            'privacy_note' => (string) ($config['privacy_note'] ?? ''),
        ];
    }

    private function miniProgramConfigJsonFromPayload(array $payload, array $current = []): array
    {
        $raw = trim((string) ($payload['config_json_text'] ?? ''));
        if ($raw !== '') {
            $decoded = json_decode($raw, true);
            if (is_array($decoded)) {
                return $decoded;
            }
        }

        $base = is_array($current['config_json'] ?? null) ? (array) $current['config_json'] : [];

        return array_filter([
            'appid' => trim((string) ($payload['mp_app_id'] ?? $payload['appid'] ?? ($base['appid'] ?? ''))),
            'project_name' => $this->limitText(trim((string) ($payload['project_name'] ?? ($base['project_name'] ?? '精秀短剧小程序'))), 80),
            'compile_type' => $this->limitText(trim((string) ($payload['compile_type'] ?? ($base['compile_type'] ?? 'miniprogram'))), 40),
            'miniprogram_root' => $this->limitText(trim((string) ($payload['miniprogram_root'] ?? ($base['miniprogram_root'] ?? 'miniprogram/'))), 120),
            'setting' => [
                'urlCheck' => !empty($payload['setting_url_check']),
                'es6' => array_key_exists('setting_es6', $payload) ? !empty($payload['setting_es6']) : (bool) ($base['setting']['es6'] ?? true),
                'postcss' => array_key_exists('setting_postcss', $payload) ? !empty($payload['setting_postcss']) : (bool) ($base['setting']['postcss'] ?? true),
                'minified' => array_key_exists('setting_minified', $payload) ? !empty($payload['setting_minified']) : (bool) ($base['setting']['minified'] ?? true),
            ],
            'pages' => array_values(array_filter(array_map('trim', preg_split('/[\r\n,，]+/u', (string) ($payload['pages_text'] ?? implode("\n", (array) ($base['pages'] ?? ['pages/index/index']))))))),
        ], static fn ($value): bool => $value !== '' && $value !== []);
    }

    private function idsFromPayload(mixed $value): array
    {
        $items = is_array($value) ? $value : preg_split('/[\s,，|]+/u', (string) $value);
        $ids = [];
        foreach ((array) $items as $item) {
            $id = (int) $item;
            if ($id > 0 && !in_array($id, $ids, true)) {
                $ids[] = $id;
            }
        }

        return array_slice($ids, 0, 200);
    }

    private function miniProgramConfigById(array $data, int $configId): ?array
    {
        foreach ((array) ($data['mini_program_configs'] ?? []) as $config) {
            if ((int) ($config['id'] ?? 0) === $configId) {
                return $config;
            }
        }

        return null;
    }

    private function nextMiniProgramActionForRetry(string $status): string
    {
        return match ($status) {
            'uploaded' => 'submit_review',
            'review_submitted' => 'query_review',
            'review_passed' => 'release',
            default => 'upload',
        };
    }

    private function miniProgramRetryBlockMessage(array $task): string
    {
        $nextRetryAt = trim((string) ($task['next_retry_at'] ?? ''));
        if ($nextRetryAt !== '' && strtotime($nextRetryAt) !== false && strtotime($nextRetryAt) > time()) {
            return '未到下次重试时间：' . $nextRetryAt . '。';
        }

        return '';
    }

    private function miniProgramAccessTokenState(array $config): array
    {
        $uploadToken = trim((string) ($config['upload_token'] ?? ''));
        if ($uploadToken !== '') {
            return ['ok' => true, 'status' => 'static', 'token' => $uploadToken, 'message' => '使用上传令牌作为接口 token。'];
        }

        $token = trim((string) ($config['access_token'] ?? ''));
        $expiresAt = trim((string) ($config['access_token_expires_at'] ?? ''));
        if ($token !== '' && $expiresAt !== '' && strtotime($expiresAt) !== false && (int) strtotime($expiresAt) > time() + 300) {
            return ['ok' => true, 'status' => 'valid', 'token' => $token, 'message' => 'access_token 有效。'];
        }

        return ['ok' => false, 'status' => 'expired', 'token' => '', 'message' => 'access_token 需要刷新。'];
    }

    private function refreshMiniProgramAccessTokenForUse(array &$data, array $config, bool $force = false): array
    {
        $state = $this->miniProgramAccessTokenState($config);
        if (!$force && !empty($state['ok'])) {
            return ['ok' => true, 'status' => (string) ($state['status'] ?? 'valid'), 'token' => (string) ($state['token'] ?? ''), 'config' => $config, 'message' => (string) ($state['message'] ?? 'access_token 有效。')];
        }

        $now = date('Y-m-d H:i:s');
        $appId = trim((string) ($config['mp_app_id'] ?? ''));
        $secret = trim((string) ($config['mp_app_secret'] ?? ''));
        if ($appId === '' || $secret === '') {
            $config['access_token_status'] = 'failed';
            $config['access_token_message'] = '缺少小程序 AppID 或 AppSecret。';
            $config['access_token_last_refresh_at'] = $now;
            $this->replaceMiniProgramConfigInData($data, $config);

            return ['ok' => false, 'status' => 'failed', 'config' => $config, 'message' => $config['access_token_message'], 'response' => ['errcode' => 40002, 'errmsg' => 'missing appid or secret']];
        }

        $url = $this->miniProgramApiUrl($config, '/cgi-bin/token', [
            'grant_type' => 'client_credential',
            'appid' => $appId,
            'secret' => $secret,
        ]);
        $result = $this->performMiniProgramHttpRequest('GET', $url);
        $body = is_array($result['body'] ?? null) ? (array) $result['body'] : [];
        $errCode = (int) ($body['errcode'] ?? 0);
        $token = trim((string) ($body['access_token'] ?? ''));
        if (!empty($result['ok']) && $errCode === 0 && $token !== '') {
            $expiresIn = max(300, (int) ($body['expires_in'] ?? 7200));
            $config['access_token'] = $token;
            $config['access_token_expires_at'] = date('Y-m-d H:i:s', time() + max(60, $expiresIn - 300));
            $config['access_token_last_refresh_at'] = $now;
            $config['access_token_status'] = 'success';
            $config['access_token_message'] = 'access_token 刷新成功。';
            $config['access_token_response'] = $this->miniProgramSafeResponseSnapshot($result);
            $this->replaceMiniProgramConfigInData($data, $config);

            return ['ok' => true, 'status' => 'success', 'token' => $token, 'config' => $config, 'message' => $config['access_token_message'], 'response' => $result];
        }

        $message = (string) ($body['errmsg'] ?? ($result['message'] ?? 'access_token 刷新失败。'));
        $config['access_token_status'] = 'failed';
        $config['access_token_message'] = $this->limitText($message, 240);
        $config['access_token_last_refresh_at'] = $now;
        $config['access_token_response'] = $this->miniProgramSafeResponseSnapshot($result);
        $this->replaceMiniProgramConfigInData($data, $config);

        return ['ok' => false, 'status' => 'failed', 'config' => $config, 'message' => $config['access_token_message'], 'response' => $result];
    }

    private function replaceMiniProgramConfigInData(array &$data, array $config): void
    {
        $configId = (int) ($config['id'] ?? 0);
        foreach ($data['mini_program_configs'] as $index => $item) {
            if ((int) ($item['id'] ?? 0) !== $configId) {
                continue;
            }
            $data['mini_program_configs'][$index] = $config;
            return;
        }
    }

    private function miniProgramActionResult(string $action, array $task, array $config, array $payload, array &$data): array
    {
        $status = (string) ($task['status'] ?? 'generated');
        $mode = (string) (($payload['upload_mode'] ?? '') ?: ($task['upload_mode'] ?? ($config['upload_mode'] ?? 'manual')));
        $mode = in_array($mode, ['manual', 'api', 'ci'], true) ? $mode : 'manual';
        $version = $this->limitText(trim((string) ($payload['version'] ?? ($task['version'] ?? ''))), 40);
        if ($version === '') {
            $version = date('Y.m.d.Hi');
        }
        $description = $this->limitText(trim((string) ($payload['description'] ?? $payload['remark'] ?? '短剧/小说内容更新')), 120);
        $request = $this->miniProgramActionRequest($action, $task, $config, $mode, $version, $description);
        $response = [
            'mode' => $mode,
            'mock' => true,
            'errcode' => 0,
            'errmsg' => 'ok',
            'generated_at' => date('Y-m-d H:i:s'),
        ];

        if ($action === 'upload') {
            if (!in_array($status, ['generated', 'failed'], true)) {
                return ['ok' => false, 'message' => '只有已生成或失败的任务可以上传代码。', 'request' => $request, 'response' => ['errcode' => 40001, 'errmsg' => 'invalid_status']];
            }
            if ((string) ($config['mp_app_id'] ?? '') === '') {
                return ['ok' => false, 'message' => '请先配置小程序 AppID。', 'request' => $request, 'response' => ['errcode' => 40002, 'errmsg' => 'missing_appid']];
            }
            if ($mode !== 'manual' && (string) ($config['upload_token'] ?? '') === '' && (string) ($config['mp_app_secret'] ?? '') === '') {
                return ['ok' => false, 'message' => '接口/CI 上传需要上传令牌或 AppSecret。', 'request' => $request, 'response' => ['errcode' => 40003, 'errmsg' => 'missing_credential']];
            }
            if ($mode === 'api') {
                return $this->miniProgramWechatApiActionResult($action, $task, $config, $payload, $data, $version, $description, $request);
            }
            $jobId = 'MPU' . date('YmdHis') . substr(md5((string) ($task['id'] ?? 0) . $version . microtime(true)), 0, 6);
            $response['upload_job_id'] = $jobId;

            return [
                'ok' => true,
                'next_status' => 'uploaded',
                'message' => $mode === 'manual' ? '已标记小程序代码上传完成。' : '小程序代码上传请求已记录。',
                'request' => $request,
                'response' => $response,
                'patch' => [
                    'version' => $version,
                    'upload_mode' => $mode,
                    'upload_job_id' => $jobId,
                    'uploaded_at' => date('Y-m-d H:i:s'),
                ],
            ];
        }

        if ($action === 'submit_review') {
            if (!in_array($status, ['uploaded', 'failed'], true)) {
                return ['ok' => false, 'message' => '请先完成代码上传后再提交审核。', 'request' => $request, 'response' => ['errcode' => 40004, 'errmsg' => 'not_uploaded']];
            }
            if ($mode === 'api') {
                return $this->miniProgramWechatApiActionResult($action, $task, $config, $payload, $data, $version, $description, $request);
            }
            $reviewId = 'MPR' . date('YmdHis') . substr(md5((string) ($task['id'] ?? 0) . $version), 0, 6);
            $response['review_id'] = $reviewId;

            return [
                'ok' => true,
                'next_status' => 'review_submitted',
                'message' => '小程序审核提交请求已记录。',
                'request' => $request,
                'response' => $response,
                'patch' => [
                    'review_id' => $reviewId,
                    'review_submitted_at' => date('Y-m-d H:i:s'),
                ],
            ];
        }

        if ($action === 'query_review') {
            if (!in_array($status, ['review_submitted', 'failed'], true)) {
                return ['ok' => false, 'message' => '只有已提审任务可以查询审核状态。', 'request' => $request, 'response' => ['errcode' => 40005, 'errmsg' => 'not_reviewing']];
            }
            if ($mode === 'api') {
                return $this->miniProgramWechatApiActionResult($action, $task, $config, $payload, $data, $version, $description, $request);
            }
            $reviewStatus = (string) ($payload['review_status'] ?? 'pass');
            $reviewStatus = in_array($reviewStatus, ['pass', 'reject', 'pending'], true) ? $reviewStatus : 'pass';
            $response['review_status'] = $reviewStatus;
            $response['review_id'] = (string) ($task['review_id'] ?? '');
            if ($reviewStatus === 'pending') {
                return [
                    'ok' => true,
                    'next_status' => 'review_submitted',
                    'message' => '小程序审核仍在处理中。',
                    'request' => $request,
                    'response' => $response,
                    'patch' => ['review_checked_at' => date('Y-m-d H:i:s')],
                ];
            }

            return [
                'ok' => true,
                'next_status' => $reviewStatus === 'pass' ? 'review_passed' : 'review_rejected',
                'message' => $reviewStatus === 'pass' ? '小程序审核已通过。' : '小程序审核未通过，请按原因修改后重试。',
                'request' => $request,
                'response' => $response,
                'patch' => [
                    'review_checked_at' => date('Y-m-d H:i:s'),
                    'last_error' => $reviewStatus === 'reject' ? '审核未通过：' . $description : '',
                ],
            ];
        }

        if ($action === 'release') {
            if (!in_array($status, ['review_passed', 'failed'], true)) {
                return ['ok' => false, 'message' => '只有审核通过的小程序任务可以发布。', 'request' => $request, 'response' => ['errcode' => 40006, 'errmsg' => 'not_review_passed']];
            }
            if ($mode === 'api') {
                return $this->miniProgramWechatApiActionResult($action, $task, $config, $payload, $data, $version, $description, $request);
            }
            $response['release_version'] = $version;

            return [
                'ok' => true,
                'next_status' => 'released',
                'message' => '小程序发布请求已记录。',
                'request' => $request,
                'response' => $response,
                'patch' => [
                    'release_version' => $version,
                    'released_at' => date('Y-m-d H:i:s'),
                ],
            ];
        }

        return ['ok' => false, 'message' => '小程序任务动作不支持。', 'request' => $request, 'response' => ['errcode' => 40000, 'errmsg' => 'unsupported_action']];
    }

    private function miniProgramWechatApiActionResult(string $action, array $task, array $config, array $payload, array &$data, string $version, string $description, array $request): array
    {
        $tokenResult = $this->refreshMiniProgramAccessTokenForUse($data, $config);
        $config = (array) ($tokenResult['config'] ?? $config);
        if (empty($tokenResult['ok']) || trim((string) ($tokenResult['token'] ?? '')) === '') {
            return [
                'ok' => false,
                'message' => '微信 access_token 不可用：' . (string) ($tokenResult['message'] ?? '刷新失败。'),
                'request' => $request,
                'response' => (array) ($tokenResult['response'] ?? ['errcode' => 40001, 'errmsg' => 'access token unavailable']),
            ];
        }

        $body = $this->miniProgramWechatApiPayload($action, $task, $config, $payload, $version, $description);
        if (empty($body['ok'])) {
            return [
                'ok' => false,
                'message' => (string) ($body['message'] ?? '微信接口请求参数缺失。'),
                'request' => $request + ['body' => (array) ($body['payload'] ?? [])],
                'response' => ['errcode' => 40007, 'errmsg' => 'missing request payload'],
            ];
        }

        $path = match ($action) {
            'upload' => '/wxa/commit',
            'submit_review' => '/wxa/submit_audit',
            'query_review' => '/wxa/get_auditstatus',
            'release' => '/wxa/release',
            default => '/wxa/unknown',
        };
        $url = $this->miniProgramApiUrl($config, $path, ['access_token' => (string) $tokenResult['token']]);
        $apiRequest = $request + [
            'endpoint' => $path,
            'api_url' => $this->miniProgramApiUrl($config, $path, ['access_token' => '***']),
            'body' => (array) ($body['payload'] ?? []),
        ];
        $result = $this->performMiniProgramHttpRequest('POST', $url, (array) ($body['payload'] ?? []));
        $response = $this->miniProgramSafeResponseSnapshot($result);
        $responseBody = is_array($result['body'] ?? null) ? (array) $result['body'] : [];
        $errCode = (int) ($responseBody['errcode'] ?? 0);
        $errMsg = (string) ($responseBody['errmsg'] ?? ($result['message'] ?? ''));
        if (empty($result['ok']) || $errCode !== 0) {
            return [
                'ok' => false,
                'message' => $this->limitText('微信接口调用失败：' . ($errMsg !== '' ? $errMsg : ('errcode ' . $errCode)), 240),
                'request' => $apiRequest,
                'response' => $response,
            ];
        }

        if ($action === 'upload') {
            $jobId = (string) (($responseBody['request_id'] ?? '') ?: ('MPU' . date('YmdHis') . substr(md5((string) ($task['id'] ?? 0) . $version . microtime(true)), 0, 6)));

            return [
                'ok' => true,
                'next_status' => 'uploaded',
                'message' => '微信代码上传接口调用成功。',
                'request' => $apiRequest,
                'response' => $response,
                'patch' => [
                    'version' => $version,
                    'upload_mode' => 'api',
                    'upload_job_id' => $jobId,
                    'uploaded_at' => date('Y-m-d H:i:s'),
                    'platform_code' => (string) $errCode,
                    'platform_message' => $errMsg !== '' ? $errMsg : 'ok',
                ],
            ];
        }

        if ($action === 'submit_review') {
            $reviewId = (string) (($responseBody['auditid'] ?? $responseBody['audit_id'] ?? '') ?: ('MPR' . date('YmdHis') . substr(md5((string) ($task['id'] ?? 0) . $version), 0, 6)));

            return [
                'ok' => true,
                'next_status' => 'review_submitted',
                'message' => '微信审核提交接口调用成功。',
                'request' => $apiRequest,
                'response' => $response,
                'patch' => [
                    'review_id' => $reviewId,
                    'review_submitted_at' => date('Y-m-d H:i:s'),
                    'platform_code' => (string) $errCode,
                    'platform_message' => $errMsg !== '' ? $errMsg : 'ok',
                ],
            ];
        }

        if ($action === 'query_review') {
            $reviewStatus = (int) ($responseBody['status'] ?? 2);
            if ($reviewStatus === 0) {
                return [
                    'ok' => true,
                    'next_status' => 'review_passed',
                    'message' => '微信审核已通过。',
                    'request' => $apiRequest,
                    'response' => $response,
                    'patch' => [
                        'review_checked_at' => date('Y-m-d H:i:s'),
                        'platform_code' => (string) $errCode,
                        'platform_message' => $errMsg !== '' ? $errMsg : 'ok',
                    ],
                ];
            }
            if ($reviewStatus === 1) {
                $reason = (string) ($responseBody['reason'] ?? $responseBody['errmsg'] ?? '审核未通过。');

                return [
                    'ok' => true,
                    'next_status' => 'review_rejected',
                    'message' => '微信审核未通过，请按原因修改后重试。',
                    'request' => $apiRequest,
                    'response' => $response,
                    'patch' => [
                        'review_checked_at' => date('Y-m-d H:i:s'),
                        'last_error' => '审核未通过：' . $this->limitText($reason, 180),
                        'platform_code' => (string) $errCode,
                        'platform_message' => $this->limitText($reason, 240),
                    ],
                ];
            }

            return [
                'ok' => true,
                'next_status' => 'review_submitted',
                'message' => '微信审核仍在处理中。',
                'request' => $apiRequest,
                'response' => $response,
                'patch' => [
                    'review_checked_at' => date('Y-m-d H:i:s'),
                    'platform_code' => (string) $errCode,
                    'platform_message' => $errMsg !== '' ? $errMsg : 'review pending',
                ],
            ];
        }

        if ($action === 'release') {
            return [
                'ok' => true,
                'next_status' => 'released',
                'message' => '微信发布接口调用成功。',
                'request' => $apiRequest,
                'response' => $response,
                'patch' => [
                    'release_version' => $version,
                    'released_at' => date('Y-m-d H:i:s'),
                    'platform_code' => (string) $errCode,
                    'platform_message' => $errMsg !== '' ? $errMsg : 'ok',
                ],
            ];
        }

        return ['ok' => false, 'message' => '小程序任务动作不支持。', 'request' => $apiRequest, 'response' => $response];
    }

    private function miniProgramWechatApiPayload(string $action, array $task, array $config, array $payload, string $version, string $description): array
    {
        $configJson = (array) ($config['config_json'] ?? []);
        $manifest = (array) ($task['manifest'] ?? []);
        if ($action === 'upload') {
            $templateId = max(0, (int) ($payload['template_id'] ?? $configJson['template_id'] ?? 0));
            $extJson = $payload['ext_json'] ?? ($configJson['ext_json'] ?? []);
            if (!is_array($extJson)) {
                $decoded = json_decode((string) $extJson, true);
                $extJson = is_array($decoded) ? $decoded : [];
            }
            $extJson = array_merge([
                'extAppid' => (string) ($config['mp_app_id'] ?? ''),
                'ext' => [
                    'app_key' => (string) ($task['app_key'] ?? $config['app_key'] ?? 'default'),
                    'content_type' => (string) ($manifest['content_type'] ?? $task['content_type'] ?? 'mixed'),
                    'item_count' => (int) ($task['item_count'] ?? 0),
                ],
            ], $extJson);
            $body = [
                'template_id' => $templateId,
                'user_version' => $version,
                'user_desc' => $description,
                'ext_json' => json_encode($extJson, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES) ?: '{}',
            ];
            if ($templateId <= 0) {
                return ['ok' => false, 'message' => 'API 上传需要在项目配置 JSON 中配置 template_id。', 'payload' => $body];
            }

            return ['ok' => true, 'payload' => $body];
        }

        if ($action === 'submit_review') {
            $itemList = $configJson['audit_item_list'] ?? $configJson['item_list'] ?? [];
            if (!is_array($itemList) || empty($itemList)) {
                $pages = array_values((array) ($configJson['pages'] ?? []));
                $items = array_values((array) ($manifest['items'] ?? []));
                $firstItem = (array) ($items[0] ?? []);
                $itemList = [[
                    'address' => (string) ($pages[0] ?? 'pages/index/index'),
                    'tag' => (string) (($firstItem['category'] ?? '') ?: '短剧 小说'),
                    'title' => $this->limitText((string) (($firstItem['title'] ?? '') ?: ($config['name'] ?? '短剧小说')), 32),
                    'first_class' => '工具',
                    'second_class' => '效率',
                ]];
            }

            return ['ok' => true, 'payload' => ['item_list' => array_values($itemList)]];
        }

        if ($action === 'query_review') {
            $reviewId = trim((string) ($task['review_id'] ?? ''));
            if ($reviewId === '') {
                return ['ok' => false, 'message' => '缺少微信审核单号，无法查询审核状态。', 'payload' => []];
            }

            return ['ok' => true, 'payload' => ['auditid' => is_numeric($reviewId) ? (int) $reviewId : $reviewId]];
        }

        if ($action === 'release') {
            return ['ok' => true, 'payload' => new \stdClass()];
        }

        return ['ok' => false, 'message' => '小程序任务动作不支持。', 'payload' => []];
    }

    private function miniProgramApiUrl(array $config, string $path, array $query = []): string
    {
        $base = trim((string) ($config['api_base_url'] ?? '')) ?: 'https://api.weixin.qq.com';
        $url = rtrim($base, '/') . $path;
        if (!empty($query)) {
            $url .= (str_contains($url, '?') ? '&' : '?') . http_build_query($query);
        }

        return $url;
    }

    private function performMiniProgramHttpRequest(string $method, string $url, mixed $payload = []): array
    {
        if (str_starts_with($url, 'mock://')) {
            return $this->mockMiniProgramHttpResponse($method, $url, $payload);
        }

        if (preg_match('#^https?://#i', $url) !== 1) {
            return ['ok' => false, 'http_status' => 0, 'message' => '微信接口地址仅支持 HTTP/HTTPS。', 'body' => ['errcode' => 40008, 'errmsg' => 'invalid api url']];
        }

        $method = strtoupper($method);
        $body = '';
        if ($method !== 'GET') {
            $body = json_encode($payload, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
            if ($body === false) {
                return ['ok' => false, 'http_status' => 0, 'message' => '微信接口请求内容编码失败。', 'body' => ['errcode' => 40009, 'errmsg' => 'json encode failed']];
            }
        }

        if (function_exists('curl_init')) {
            $ch = curl_init($url);
            $options = [
                CURLOPT_RETURNTRANSFER => true,
                CURLOPT_CONNECTTIMEOUT => 5,
                CURLOPT_TIMEOUT => 10,
                CURLOPT_FOLLOWLOCATION => false,
            ];
            if ($method !== 'GET') {
                $options[CURLOPT_POST] = true;
                $options[CURLOPT_POSTFIELDS] = $body;
                $options[CURLOPT_HTTPHEADER] = ['Content-Type: application/json'];
            }
            curl_setopt_array($ch, $options);
            $raw = curl_exec($ch);
            $error = curl_error($ch);
            $httpStatus = (int) curl_getinfo($ch, CURLINFO_RESPONSE_CODE);
            curl_close($ch);

            return $this->formatMiniProgramHttpResponse($raw === false ? '' : (string) $raw, $httpStatus, $error);
        }

        $context = stream_context_create([
            'http' => [
                'method' => $method,
                'header' => $method === 'GET' ? '' : "Content-Type: application/json\r\n",
                'content' => $method === 'GET' ? '' : $body,
                'timeout' => 10,
                'ignore_errors' => true,
            ],
        ]);
        $raw = @file_get_contents($url, false, $context);
        $httpStatus = 0;
        foreach (($http_response_header ?? []) as $header) {
            if (preg_match('#^HTTP/\S+\s+(\d+)#', (string) $header, $matches) === 1) {
                $httpStatus = (int) $matches[1];
                break;
            }
        }

        return $this->formatMiniProgramHttpResponse($raw === false ? '' : (string) $raw, $httpStatus, $raw === false ? '请求失败或超时。' : '');
    }

    private function mockMiniProgramHttpResponse(string $method, string $url, mixed $payload): array
    {
        $path = parse_url($url, PHP_URL_PATH) ?: '';
        $body = ['errcode' => 0, 'errmsg' => 'ok'];
        if (str_contains($url, 'token-fail')) {
            $body = ['errcode' => 40125, 'errmsg' => 'invalid appsecret'];
        } elseif (str_contains($url, 'auth-fail')) {
            $body = ['errcode' => 40001, 'errmsg' => 'invalid credential access_token is invalid'];
        } elseif (str_contains($url, 'rate-limit')) {
            $body = ['errcode' => 45009, 'errmsg' => 'reach max api daily quota limit'];
        } elseif (str_contains($path, '/cgi-bin/token')) {
            $body = ['access_token' => 'mock-wechat-access-token', 'expires_in' => 7200];
        } elseif (str_contains($path, '/wxa/submit_audit')) {
            $body = ['errcode' => 0, 'errmsg' => 'ok', 'auditid' => 10086];
        } elseif (str_contains($path, '/wxa/get_auditstatus')) {
            if (str_contains($url, 'review-reject')) {
                $body = ['errcode' => 0, 'errmsg' => 'ok', 'status' => 1, 'reason' => 'mock review rejected'];
            } elseif (str_contains($url, 'review-pending')) {
                $body = ['errcode' => 0, 'errmsg' => 'ok', 'status' => 2];
            } else {
                $body = ['errcode' => 0, 'errmsg' => 'ok', 'status' => 0];
            }
        } elseif (str_contains($path, '/wxa/commit')) {
            $body = ['errcode' => 0, 'errmsg' => 'ok', 'request_id' => 'mock-commit-request'];
        }

        return [
            'ok' => (int) ($body['errcode'] ?? 0) === 0,
            'http_status' => 200,
            'message' => (int) ($body['errcode'] ?? 0) === 0 ? '微信接口模拟成功。' : '微信接口模拟失败。',
            'body' => $body,
            'method' => strtoupper($method),
            'request_payload' => is_object($payload) ? [] : (array) $payload,
        ];
    }

    private function formatMiniProgramHttpResponse(string $raw, int $httpStatus, string $error = ''): array
    {
        $decoded = null;
        if ($raw !== '') {
            $json = json_decode($raw, true);
            $decoded = json_last_error() === JSON_ERROR_NONE ? $json : $this->limitText($raw, 500);
        }
        $body = is_array($decoded) ? $decoded : [];
        $errCode = (int) ($body['errcode'] ?? 0);
        $ok = $httpStatus >= 200 && $httpStatus < 300 && $error === '' && $errCode === 0;

        return [
            'ok' => $ok,
            'http_status' => $httpStatus,
            'message' => $ok ? '微信接口调用成功，HTTP ' . $httpStatus . '。' : '微信接口调用失败，HTTP ' . ($httpStatus ?: '无响应') . ($error !== '' ? '，' . $error : '') . '。',
            'body' => $decoded,
        ];
    }

    private function miniProgramSafeResponseSnapshot(array $response): array
    {
        $copy = $response;
        if (is_array($copy['body'] ?? null) && array_key_exists('access_token', $copy['body'])) {
            $copy['body']['access_token_saved'] = true;
            $copy['body']['access_token'] = '';
        }

        return $copy;
    }

    private function miniProgramFailureMeta(array $result, string $action, array $task, string $now): array
    {
        $response = is_array($result['response'] ?? null) ? (array) $result['response'] : [];
        $body = is_array($response['body'] ?? null) ? (array) $response['body'] : $response;
        $errCode = (int) ($body['errcode'] ?? $response['errcode'] ?? 0);
        $httpStatus = max(0, (int) ($response['http_status'] ?? 0));
        $message = (string) ($result['message'] ?? $body['errmsg'] ?? $response['message'] ?? '小程序任务执行失败。');
        $category = 'platform_failed';
        if (in_array($errCode, [45001, 45009, 45011, 45029], true) || preg_match('/quota|rate|limit|too many|频控|限流|请求过多/u', strtolower($message)) === 1) {
            $category = 'rate_limited';
        } elseif (in_array($errCode, [40001, 40014, 42001, 40125, 40164], true) || preg_match('/access_token|credential|appsecret|unauthori[sz]ed|invalid token|授权|凭证|密钥/u', strtolower($message)) === 1) {
            $category = 'auth_failed';
        } elseif ($httpStatus === 0 || $httpStatus >= 500) {
            $category = 'retryable_failed';
        } elseif (in_array($errCode, [40002, 40003, 40007, 40008, 40009], true)) {
            $category = 'config_missing';
        } elseif (in_array($errCode, [40001, 40004, 40005, 40006], true) && str_starts_with((string) ($body['errmsg'] ?? ''), 'not_')) {
            $category = 'invalid_status';
        }

        return $this->miniProgramBuildFailureMeta($category, $message, $task, $action, $now, $errCode);
    }

    private function miniProgramBuildFailureMeta(string $category, string $message, array $task, string $action, string $now, int $platformCode = 0): array
    {
        $category = in_array($category, ['auth_failed', 'rate_limited', 'platform_failed', 'retryable_failed', 'config_missing', 'invalid_status', 'review_rejected', 'unknown'], true) ? $category : 'unknown';
        $retryCount = max(0, (int) ($task['retry_count'] ?? 0));
        $baseTime = strtotime($now) ?: time();
        $nextRetryAt = '';
        $blockedReason = '';
        if ($category === 'auth_failed') {
            $blockedReason = '微信授权失败，请刷新 access_token 或检查 AppSecret。';
        } elseif ($category === 'rate_limited') {
            $minutes = min(180, 30 * max(1, 2 ** $retryCount));
            $nextRetryAt = date('Y-m-d H:i:s', $baseTime + ($minutes * 60));
            $blockedReason = '微信接口频控，已进入退避等待。';
        } elseif ($category === 'retryable_failed') {
            $minutes = min(120, 10 * max(1, 2 ** $retryCount));
            $nextRetryAt = date('Y-m-d H:i:s', $baseTime + ($minutes * 60));
        } elseif ($category === 'config_missing') {
            $blockedReason = '小程序接口配置缺失，请补齐后重试。';
        } elseif ($category === 'invalid_status') {
            $blockedReason = '任务状态不满足该动作要求。';
        } elseif ($category === 'review_rejected') {
            $blockedReason = '微信审核驳回，请修改内容后重新上传。';
        }

        return [
            'category' => $category,
            'action' => $action,
            'platform_code' => (string) $platformCode,
            'platform_message' => $this->limitText($message, 240),
            'next_retry_at' => $nextRetryAt,
            'retry_blocked_reason' => $this->limitText($blockedReason, 240),
        ];
    }

    private function miniProgramApplyFailureMeta(array &$task, array $meta, string $now): void
    {
        $task['error_category'] = (string) ($meta['category'] ?? 'unknown');
        $task['next_retry_at'] = (string) ($meta['next_retry_at'] ?? '');
        $task['retry_blocked_reason'] = (string) ($meta['retry_blocked_reason'] ?? '');
        $task['platform_code'] = (string) ($meta['platform_code'] ?? '');
        $task['platform_message'] = (string) ($meta['platform_message'] ?? '');
        $task['last_error_at'] = $now;
    }

    private function miniProgramClearFailureMeta(array &$task): void
    {
        $task['error_category'] = '';
        $task['next_retry_at'] = '';
        $task['retry_blocked_reason'] = '';
        $task['platform_code'] = (string) ($task['platform_code'] ?? '');
        $task['platform_message'] = (string) ($task['platform_message'] ?? '');
        $task['last_error_at'] = '';
        $task['last_failed_action'] = '';
    }

    private function miniProgramActionRequest(string $action, array $task, array $config, string $mode, string $version, string $description): array
    {
        $manifest = (array) ($task['manifest'] ?? []);
        $configJson = (array) ($config['config_json'] ?? []);

        return [
            'action' => $action,
            'mode' => $mode,
            'endpoint' => match ($action) {
                'upload' => '/wxa/commit',
                'submit_review' => '/wxa/submit_audit',
                'query_review' => '/wxa/get_auditstatus',
                'release' => '/wxa/release',
                default => '/wxa/unknown',
            },
            'app_key' => (string) ($task['app_key'] ?? 'default'),
            'mp_app_id' => (string) ($config['mp_app_id'] ?? ''),
            'version' => $version,
            'description' => $description,
            'project' => [
                'project_name' => (string) ($configJson['project_name'] ?? '精秀短剧小程序'),
                'compile_type' => (string) ($configJson['compile_type'] ?? 'miniprogram'),
                'miniprogram_root' => (string) ($configJson['miniprogram_root'] ?? 'miniprogram/'),
                'pages' => array_values((array) ($configJson['pages'] ?? [])),
            ],
            'manifest' => [
                'content_type' => (string) ($manifest['content_type'] ?? ($task['content_type'] ?? 'mixed')),
                'item_count' => (int) ($task['item_count'] ?? 0),
                'items' => array_slice((array) ($manifest['items'] ?? []), 0, 20),
            ],
            'review_id' => (string) ($task['review_id'] ?? ''),
            'has_secret' => trim((string) ($config['mp_app_secret'] ?? '')) !== '',
            'has_upload_token' => trim((string) ($config['upload_token'] ?? '')) !== '',
        ];
    }

    private function miniProgramManifest(array $data, array $config, string $contentType, array $contentIds): array
    {
        $appKey = (string) ($config['app_key'] ?? 'default');
        $contentIdMap = array_fill_keys(array_map('intval', $contentIds), true);
        $items = [];
        if (in_array($contentType, ['drama', 'mixed'], true)) {
            foreach ((array) ($data['dramas'] ?? []) as $drama) {
                $dramaId = (int) ($drama['id'] ?? 0);
                if (!empty($contentIdMap) && !isset($contentIdMap[$dramaId])) {
                    continue;
                }
                if (!in_array((string) ($drama['status'] ?? 'online'), ['online', 'draft'], true)) {
                    continue;
                }
                $episodes = array_values((array) ($drama['episodes'] ?? []));
                $items[] = [
                    'type' => 'drama',
                    'id' => $dramaId,
                    'title' => (string) ($drama['title'] ?? '未命名短剧'),
                    'category' => (string) (($drama['category'] ?? '') ?: ($config['default_drama_category'] ?? '短剧')),
                    'cover' => (string) ($drama['cover'] ?? ''),
                    'episode_count' => count($episodes),
                    'free_count' => count(array_filter($episodes, static fn (array $episode): bool => !empty($episode['is_free']))),
                    'path' => '/?route=drama&id=' . $dramaId . '&app_key=' . rawurlencode($appKey),
                    'updated_at' => (string) ($drama['updated_at'] ?? ''),
                ];
            }
        }
        if (in_array($contentType, ['novel', 'mixed'], true)) {
            foreach ((array) ($data['novels'] ?? []) as $novel) {
                $novelId = (int) ($novel['id'] ?? 0);
                if (!empty($contentIdMap) && !isset($contentIdMap[$novelId])) {
                    continue;
                }
                if (!in_array((string) ($novel['status'] ?? 'online'), ['online', 'draft'], true)) {
                    continue;
                }
                $chapters = array_values((array) ($novel['chapters'] ?? []));
                $items[] = [
                    'type' => 'novel',
                    'id' => $novelId,
                    'title' => (string) ($novel['title'] ?? '未命名小说'),
                    'category' => (string) (($novel['category'] ?? '') ?: ($config['default_novel_category'] ?? '小说')),
                    'cover' => (string) ($novel['cover'] ?? ''),
                    'chapter_count' => count($chapters),
                    'free_count' => count(array_filter($chapters, static fn (array $chapter): bool => !empty($chapter['is_free']))),
                    'path' => '/?route=novel&id=' . $novelId . '&app_key=' . rawurlencode($appKey),
                    'updated_at' => (string) ($novel['updated_at'] ?? ''),
                ];
            }
        }

        return [
            'app_key' => $appKey,
            'mp_app_id' => (string) ($config['mp_app_id'] ?? ''),
            'generated_at' => date('Y-m-d H:i:s'),
            'content_type' => $contentType,
            'items' => array_slice($items, 0, 500),
            'config' => [
                'server_domain' => (string) ($config['server_domain'] ?? ''),
                'privacy_url' => (string) ($config['privacy_url'] ?? ''),
                'agreement_url' => (string) ($config['agreement_url'] ?? ''),
                'upload_mode' => (string) ($config['upload_mode'] ?? 'manual'),
                'config_json' => (array) ($config['config_json'] ?? []),
            ],
        ];
    }

    private function resolveAdSlot(array $payload, array $data): ?array
    {
        $slotId = max(0, (int) ($payload['ad_slot_id'] ?? $payload['slot_id'] ?? $payload['id'] ?? 0));
        $code = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($payload['code'] ?? $payload['ad_code'] ?? '')));
        $hasExplicitAppKey = trim((string) ($payload['app_key'] ?? $payload['media_app_id'] ?? $payload['app_id'] ?? '')) !== '';
        $appKey = $this->normalizeAppKey((string) ($payload['app_key'] ?? $payload['media_app_id'] ?? $payload['app_id'] ?? ''));
        if ($appKey === '') {
            $appKey = $this->currentAppKey($payload);
        }
        $position = (string) ($payload['position'] ?? '');
        $adType = (string) ($payload['ad_type'] ?? $payload['type'] ?? '');

        $matchesApp = static function (array $slot) use ($appKey): bool {
            $slotAppKey = (string) ($slot['app_key'] ?? 'default');
            return $appKey === '' || $slotAppKey === $appKey || $slotAppKey === 'default';
        };

        foreach ((array) ($data['ad_slots'] ?? []) as $slot) {
            if (!is_array($slot) || (string) ($slot['status'] ?? 'active') !== 'active') {
                continue;
            }
            if ($slotId > 0 && (int) ($slot['id'] ?? 0) === $slotId) {
                if ($hasExplicitAppKey && !$matchesApp($slot)) {
                    continue;
                }
                return $slot;
            }
            if ($code !== '' && (string) ($slot['code'] ?? '') === $code) {
                if ($hasExplicitAppKey && !$matchesApp($slot)) {
                    continue;
                }
                return $slot;
            }
        }

        if ($slotId <= 0 && $code === '' && $position !== '') {
            foreach ((array) ($data['ad_slots'] ?? []) as $slot) {
                if (!is_array($slot) || (string) ($slot['status'] ?? 'active') !== 'active' || !$matchesApp($slot)) {
                    continue;
                }
                if ((string) ($slot['position'] ?? '') !== $position) {
                    continue;
                }
                if ($adType !== '' && (string) ($slot['ad_type'] ?? '') !== $adType) {
                    continue;
                }

                return $slot;
            }
        }

        return null;
    }

    private function grantAdRewardIfAllowed(array &$data, array $slot, int $userId, string $now, int $eventId): array
    {
        $rewardCoins = max(0, (int) ($slot['reward_coins'] ?? 0));
        if ($userId <= 0) {
            return ['granted' => false, 'coins' => 0, 'message' => '用户未登录，未发放广告奖励。', 'limit_reached' => false, 'frequency_limited' => false];
        }
        if ($rewardCoins <= 0) {
            return ['granted' => false, 'coins' => 0, 'message' => '广告位未配置奖励。', 'limit_reached' => false, 'frequency_limited' => false];
        }

        $userIndex = null;
        foreach ((array) ($data['users'] ?? []) as $index => $user) {
            if ((int) ($user['id'] ?? 0) === $userId) {
                $userIndex = $index;
                break;
            }
        }
        if ($userIndex === null) {
            return ['granted' => false, 'coins' => 0, 'message' => '用户不存在，未发放广告奖励。', 'limit_reached' => false, 'frequency_limited' => false];
        }

        $slotId = (int) ($slot['id'] ?? 0);
        $today = substr($now, 0, 10);
        $nowTimestamp = strtotime($now) ?: time();
        $dailyRewards = 0;
        $lastRewardAt = 0;
        foreach ((array) ($data['ad_events'] ?? []) as $event) {
            if (
                (int) ($event['ad_slot_id'] ?? 0) !== $slotId
                || (int) ($event['user_id'] ?? 0) !== $userId
                || (string) ($event['event'] ?? '') !== 'reward'
                || (int) ($event['reward_coins'] ?? 0) <= 0
            ) {
                continue;
            }
            $createdAt = (string) ($event['created_at'] ?? '');
            if (substr($createdAt, 0, 10) === $today) {
                $dailyRewards++;
            }
            $timestamp = strtotime($createdAt) ?: 0;
            if ($timestamp > $lastRewardAt) {
                $lastRewardAt = $timestamp;
            }
        }

        $dailyLimit = max(0, (int) ($slot['daily_limit'] ?? 0));
        if ($dailyLimit > 0 && $dailyRewards >= $dailyLimit) {
            return ['granted' => false, 'coins' => 0, 'message' => '今日广告奖励次数已达上限。', 'limit_reached' => true, 'frequency_limited' => false];
        }

        $frequencySeconds = max(0, (int) ($slot['frequency_seconds'] ?? 0));
        if ($frequencySeconds > 0 && $lastRewardAt > 0 && ($nowTimestamp - $lastRewardAt) < $frequencySeconds) {
            return ['granted' => false, 'coins' => 0, 'message' => '广告奖励领取过于频繁，请稍后再试。', 'limit_reached' => false, 'frequency_limited' => true];
        }

        $data['users'][$userIndex]['bonus_coin_balance'] = max(0, (int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0)) + $rewardCoins;
        $data['coin_transactions'][] = [
            'id' => count((array) ($data['coin_transactions'] ?? [])) + 1,
            'user_id' => $userId,
            'type' => 'reward',
            'scene' => 'ad_reward',
            'coins' => $rewardCoins,
            'balance_after' => (int) ($data['users'][$userIndex]['coin_balance'] ?? 0) + (int) ($data['users'][$userIndex]['bonus_coin_balance'] ?? 0),
            'source_ad_event_id' => $eventId,
            'source_ad_slot_id' => $slotId,
            'source_ad_slot_code' => (string) ($slot['code'] ?? ''),
            'remark' => '广告激励奖励',
            'created_at' => $now,
        ];

        return ['granted' => true, 'coins' => $rewardCoins, 'message' => '广告奖励已发放。', 'limit_reached' => false, 'frequency_limited' => false];
    }

    private function redeemCodeFailureReason(array $codeItem, array $logs, int $userId, string $appKey, string $now, array $context = []): string
    {
        if ((string) ($codeItem['status'] ?? 'active') !== 'active') {
            return '兑换码已停用。';
        }
        $startedAt = trim((string) ($codeItem['started_at'] ?? ''));
        if ($startedAt !== '' && strtotime($startedAt) > strtotime($now)) {
            return '兑换码尚未开始。';
        }
        $endedAt = trim((string) ($codeItem['ended_at'] ?? ''));
        if ($endedAt !== '' && strtotime($endedAt) < strtotime($now)) {
            return '兑换码已过期。';
        }
        $codeAppKey = $this->normalizeAppKey((string) ($codeItem['app_key'] ?? 'all'));
        if ($codeAppKey !== '' && $codeAppKey !== 'all' && $codeAppKey !== $appKey) {
            return '兑换码不适用于当前应用。';
        }
        $scopeMessage = $this->redeemCodeScopeFailureReason($codeItem, $userId, $context);
        if ($scopeMessage !== '') {
            return $scopeMessage;
        }

        $codeId = (int) ($codeItem['id'] ?? 0);
        $code = strtoupper((string) ($codeItem['code'] ?? ''));
        $successCount = 0;
        $userSuccessCount = 0;
        foreach ($logs as $log) {
            if ((string) ($log['status'] ?? '') !== 'success') {
                continue;
            }
            $sameCode = $codeId > 0
                ? (int) ($log['code_id'] ?? 0) === $codeId
                : strtoupper((string) ($log['code'] ?? '')) === $code;
            if (!$sameCode) {
                continue;
            }
            $successCount++;
            if ((int) ($log['user_id'] ?? 0) === $userId) {
                $userSuccessCount++;
            }
        }

        $totalLimit = max(0, (int) ($codeItem['total_limit'] ?? 0));
        if ($totalLimit > 0 && $successCount >= $totalLimit) {
            return '兑换码已被领完。';
        }
        $perUserLimit = max(1, (int) ($codeItem['per_user_limit'] ?? 1));
        if ($userSuccessCount >= $perUserLimit) {
            return '你已达到该兑换码的领取次数上限。';
        }

        return '';
    }

    private function redeemCodeScopeFailureReason(array $codeItem, int $userId, array $context = []): string
    {
        $allowedUserIds = array_values(array_unique(array_filter(array_map(static fn (mixed $value): int => max(0, (int) $value), (array) ($codeItem['allowed_user_ids'] ?? [])))));
        if (!empty($allowedUserIds) && !in_array($userId, $allowedUserIds, true)) {
            return '兑换码仅限指定用户使用。';
        }

        $attribution = $this->currentPromotionAttribution();
        $contextPromotionCode = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($context['promotion_code'] ?? $context['code'] ?? ''))) ?: '';
        $currentPromotionCode = $contextPromotionCode !== '' ? $contextPromotionCode : (preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($attribution['code'] ?? ''))) ?: '');
        $requiredPromotionCode = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($codeItem['promotion_code'] ?? ''))) ?: '';
        if ($requiredPromotionCode !== '' && strcasecmp($requiredPromotionCode, $currentPromotionCode) !== 0) {
            return '兑换码仅限指定推广入口使用。';
        }

        $contextAgentId = max(0, (int) ($context['agent_id'] ?? 0));
        $currentAgentId = $contextAgentId > 0 ? $contextAgentId : max(0, (int) ($attribution['agent_id'] ?? 0));
        $requiredAgentId = max(0, (int) ($codeItem['agent_id'] ?? 0));
        if ($requiredAgentId > 0 && $requiredAgentId !== $currentAgentId) {
            return '兑换码仅限指定代理使用。';
        }

        $contextChannelId = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($context['channel_id'] ?? ''))) ?: '';
        $currentChannelId = $contextChannelId !== '' ? $contextChannelId : (preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($attribution['channel_id'] ?? ''))) ?: '');
        $requiredChannelId = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($codeItem['channel_id'] ?? ''))) ?: '';
        if ($requiredChannelId !== '' && strcasecmp($requiredChannelId, $currentChannelId) !== 0) {
            return '兑换码仅限指定渠道使用。';
        }

        return '';
    }

    private function appendRedeemCodeLog(array &$data, array $codeItem, string $code, int $userId, string $appKey, string $status, string $message, string $now): void
    {
        $data['redeem_code_logs'] ??= [];
        $data['redeem_code_logs'][] = [
            'id' => count((array) ($data['redeem_code_logs'] ?? [])) + 1,
            'code_id' => max(0, (int) ($codeItem['id'] ?? 0)),
            'code' => $code !== '' ? $code : strtoupper((string) ($codeItem['code'] ?? '')),
            'user_id' => $userId,
            'app_key' => $appKey !== '' ? $appKey : 'default',
            'promotion_code' => (string) ($codeItem['promotion_code'] ?? ''),
            'agent_id' => max(0, (int) ($codeItem['agent_id'] ?? 0)),
            'channel_id' => (string) ($codeItem['channel_id'] ?? ''),
            'reward_type' => (string) ($codeItem['reward_type'] ?? 'coin'),
            'coin_amount' => max(0, (int) ($codeItem['coin_amount'] ?? 0)),
            'bonus_coin_amount' => max(0, (int) ($codeItem['bonus_coin_amount'] ?? 0)),
            'vip_days' => max(0, (int) ($codeItem['vip_days'] ?? 0)),
            'status' => in_array($status, ['success', 'failed'], true) ? $status : 'failed',
            'message' => $this->limitText($message, 160),
            'created_at' => $now,
        ];
    }

    private function operationItemActiveForApp(array $item, string $appKey, string $now): bool
    {
        if ((string) ($item['status'] ?? 'active') !== 'active') {
            return false;
        }
        $itemAppKey = $this->normalizeAppKey((string) ($item['app_key'] ?? 'all'));
        if ($itemAppKey !== '' && $itemAppKey !== 'all' && $itemAppKey !== $appKey) {
            return false;
        }
        $startedAt = trim((string) ($item['started_at'] ?? ''));
        if ($startedAt !== '' && strtotime($startedAt) > strtotime($now)) {
            return false;
        }
        $endedAt = trim((string) ($item['ended_at'] ?? ''));
        if ($endedAt !== '' && strtotime($endedAt) < strtotime($now)) {
            return false;
        }

        return true;
    }

    private function activityTargetTiersFromPayload(array $payload, array $fallback = ['all']): array
    {
        $raw = array_key_exists('target_tiers', $payload) ? $payload['target_tiers'] : $fallback;
        if (is_string($raw)) {
            $raw = preg_split('/[\s,，|]+/u', $raw) ?: [];
        }
        $tiers = array_values(array_unique(array_filter(array_map(static fn (mixed $item): string => preg_replace('/[^a-zA-Z0-9_-]+/', '', (string) $item) ?: '', (array) $raw), static fn (string $tier): bool => in_array($tier, ['all', 'new', 'unpaid', 'paid', 'member'], true))));
        if (empty($tiers) || in_array('all', $tiers, true)) {
            return ['all'];
        }

        return $tiers;
    }

    private function activityMatchesUserTier(array $activity, array $userTier): bool
    {
        $targetTiers = $this->activityTargetTiersFromPayload(['target_tiers' => (array) ($activity['target_tiers'] ?? ['all'])]);
        if (in_array('all', $targetTiers, true)) {
            return true;
        }

        return in_array((string) ($userTier['key'] ?? ''), $targetTiers, true);
    }

    private function normalizeActivityExperimentKey(string $value): string
    {
        return $this->limitText(preg_replace('/[^a-zA-Z0-9_-]+/', '', trim($value)) ?: '', 60);
    }

    private function normalizeActivityVariantKey(string $value): string
    {
        return $this->limitText(preg_replace('/[^a-zA-Z0-9_-]+/', '', trim($value)) ?: '', 40);
    }

    private function filterActivitiesForExperiment(array $activities, string $appKey, int $userId): array
    {
        $visible = [];
        $experimentGroups = [];
        foreach ($activities as $activity) {
            if (!is_array($activity)) {
                continue;
            }
            $experimentKey = $this->normalizeActivityExperimentKey((string) ($activity['experiment_key'] ?? ''));
            if ($experimentKey === '') {
                $visible[] = $activity;
                continue;
            }
            $experimentGroups[$experimentKey][] = $activity;
        }

        foreach ($experimentGroups as $experimentKey => $items) {
            $selected = $this->selectedActivityExperimentVariant($items, $appKey, $userId, (string) $experimentKey);
            if ($selected !== null) {
                $visible[] = $selected;
            }
        }

        return $visible;
    }

    private function activityVisibleInExperiment(array $activity, array $eligibleActivities, string $appKey, int $userId): bool
    {
        $experimentKey = $this->normalizeActivityExperimentKey((string) ($activity['experiment_key'] ?? ''));
        if ($experimentKey === '') {
            return true;
        }
        $sameExperiment = array_values(array_filter($eligibleActivities, fn (array $item): bool => $this->normalizeActivityExperimentKey((string) ($item['experiment_key'] ?? '')) === $experimentKey));
        $selected = $this->selectedActivityExperimentVariant($sameExperiment, $appKey, $userId, $experimentKey);

        return is_array($selected) && (int) ($selected['id'] ?? 0) === (int) ($activity['id'] ?? 0);
    }

    private function selectedActivityExperimentVariant(array $items, string $appKey, int $userId, string $experimentKey): ?array
    {
        $items = array_values(array_filter($items, static fn (array $item): bool => max(0, min(100, (int) ($item['traffic_percent'] ?? 100))) > 0));
        if (empty($items)) {
            return null;
        }
        usort($items, static fn (array $a, array $b): int => [(int) ($a['sort'] ?? 0), (int) ($a['id'] ?? 0)] <=> [(int) ($b['sort'] ?? 0), (int) ($b['id'] ?? 0)]);
        $bucket = $this->activityExperimentBucket($appKey, $experimentKey, $userId);
        $cursor = 0;
        foreach ($items as $item) {
            $cursor += max(0, min(100, (int) ($item['traffic_percent'] ?? 100)));
            if ($bucket <= $cursor) {
                return $item;
            }
        }

        return null;
    }

    private function activityExperimentBucket(string $appKey, string $experimentKey, int $userId): int
    {
        $seed = ($appKey !== '' ? $appKey : 'default') . ':' . $experimentKey . ':' . max(0, $userId);
        $hash = crc32($seed);
        if ($hash < 0) {
            $hash += 4294967296;
        }

        return (int) (($hash % 100) + 1);
    }

