    private function publicHotRank(array $config, array $data): array
    {
        $limit = max(1, min(50, (int) ($config['limit'] ?? 10)));
        $rows = array_slice($this->hotRankRowsForConfig($data, $config), 0, $limit);

        return [
            'id' => (int) ($config['id'] ?? 0),
            'rank_key' => (string) ($config['rank_key'] ?? ''),
            'name' => (string) ($config['name'] ?? '热播榜单'),
            'app_key' => (string) ($config['app_key'] ?? 'all'),
            'content_type' => (string) ($config['content_type'] ?? 'mixed'),
            'algorithm' => (string) ($config['algorithm'] ?? 'hot_score'),
            'time_window' => (string) ($config['time_window'] ?? 'last_7_days'),
            'limit' => $limit,
            'rows' => array_map(static fn (array $row): array => [
                'rank' => (int) ($row['rank'] ?? 0),
                'content_type' => (string) ($row['content_type'] ?? 'drama'),
                'content_label' => (string) ($row['content_label'] ?? '短剧'),
                'content_id' => (int) ($row['content_id'] ?? 0),
                'title' => (string) ($row['title'] ?? ''),
                'cover' => (string) ($row['cover'] ?? ''),
                'url' => (string) ($row['url'] ?? ''),
                'score' => (int) ($row['score'] ?? 0),
                'views' => (int) ($row['views'] ?? 0),
                'legacy_views' => (int) ($row['legacy_views'] ?? 0),
                'watch_records' => (int) ($row['watch_records'] ?? 0),
                'watch_user_count' => (int) ($row['watch_user_count'] ?? 0),
                'unlock_success' => (int) ($row['unlock_success'] ?? 0),
                'unlocks' => (int) ($row['unlocks'] ?? 0),
                'revenue' => round((float) ($row['revenue'] ?? 0), 2),
                'pinned' => !empty($row['pinned']),
            ], $rows),
            'generated_at' => date('Y-m-d H:i:s'),
        ];
    }

    private function operationAppKeyFromPayload(array $payload): string
    {
        $appKey = $this->normalizeAppKey((string) ($payload['app_key'] ?? ''));

        return $appKey !== '' ? $appKey : 'all';
    }

    private function operationTimeWindowFromPayload(array $payload): array
    {
        $startedAt = $this->normalizeDateTime((string) ($payload['started_at'] ?? ''), '');
        $endedAt = $this->normalizeDateTime((string) ($payload['ended_at'] ?? ''), '');
        if ($startedAt !== '' && $endedAt !== '' && strtotime($endedAt) < strtotime($startedAt)) {
            return ['ok' => false, 'message' => '结束时间不能早于开始时间。', 'started_at' => '', 'ended_at' => ''];
        }

        return ['ok' => true, 'message' => '', 'started_at' => $startedAt, 'ended_at' => $endedAt];
    }

    private function hotRankPinnedItemsFromPayload(mixed $value): array
    {
        if (is_array($value)) {
            $items = [];
            foreach ($value as $index => $item) {
                if (!is_array($item)) {
                    continue;
                }
                $contentType = (string) ($item['content_type'] ?? 'drama') === 'novel' ? 'novel' : 'drama';
                $contentId = max(0, (int) ($item['content_id'] ?? $item['id'] ?? 0));
                if ($contentId <= 0) {
                    continue;
                }
                $items[] = [
                    'content_type' => $contentType,
                    'content_id' => $contentId,
                    'sort' => (int) ($item['sort'] ?? (($index + 1) * 10)),
                    'remark' => $this->limitText(trim((string) ($item['remark'] ?? '')), 120),
                ];
            }

            return $this->dedupeHotRankPinnedItems($items);
        }

        $lines = preg_split('/[\r\n,，]+/u', (string) $value) ?: [];
        $items = [];
        foreach ($lines as $index => $line) {
            $line = trim((string) $line);
            if ($line === '') {
                continue;
            }
            $contentType = 'drama';
            $contentIdText = $line;
            if (preg_match('/^(drama|novel)[:#-](\d+)$/i', $line, $matches) === 1) {
                $contentType = strtolower((string) $matches[1]) === 'novel' ? 'novel' : 'drama';
                $contentIdText = (string) $matches[2];
            } elseif (preg_match('/^小说[:#-]?(\d+)$/u', $line, $matches) === 1) {
                $contentType = 'novel';
                $contentIdText = (string) $matches[1];
            } elseif (preg_match('/^短剧[:#-]?(\d+)$/u', $line, $matches) === 1) {
                $contentType = 'drama';
                $contentIdText = (string) $matches[1];
            }
            $contentId = max(0, (int) $contentIdText);
            if ($contentId <= 0) {
                continue;
            }
            $items[] = [
                'content_type' => $contentType,
                'content_id' => $contentId,
                'sort' => ($index + 1) * 10,
                'remark' => '',
            ];
        }

        return $this->dedupeHotRankPinnedItems($items);
    }

    private function dedupeHotRankPinnedItems(array $items): array
    {
        $deduped = [];
        $seen = [];
        foreach ($items as $item) {
            $contentType = (string) ($item['content_type'] ?? 'drama') === 'novel' ? 'novel' : 'drama';
            $contentId = max(0, (int) ($item['content_id'] ?? 0));
            if ($contentId <= 0) {
                continue;
            }
            $key = $contentType . ':' . $contentId;
            if (isset($seen[$key])) {
                continue;
            }
            $seen[$key] = true;
            $deduped[] = [
                'content_type' => $contentType,
                'content_id' => $contentId,
                'sort' => (int) ($item['sort'] ?? ((count($deduped) + 1) * 10)),
                'remark' => $this->limitText(trim((string) ($item['remark'] ?? '')), 120),
            ];
        }
        usort($deduped, static fn (array $a, array $b): int => [(int) ($a['sort'] ?? 0), (int) ($a['content_id'] ?? 0)] <=> [(int) ($b['sort'] ?? 0), (int) ($b['content_id'] ?? 0)]);

        return array_slice($deduped, 0, 50);
    }

    private function findItemById(array $items, int $id): array
    {
        foreach ($items as $item) {
            if (is_array($item) && (int) ($item['id'] ?? 0) === $id) {
                return $item;
            }
        }

        return [];
    }

    private function replaceListItem(array $items, array $item): array
    {
        $replaced = false;
        foreach ($items as &$current) {
            if ((int) ($current['id'] ?? 0) !== (int) ($item['id'] ?? 0)) {
                continue;
            }
            $current = $item;
            $replaced = true;
            break;
        }
        unset($current);
        if (!$replaced) {
            $items[] = $item;
        }

        return array_values($items);
    }

    private function currentPromotionAttribution(): array
    {
        if (session_status() !== PHP_SESSION_ACTIVE) {
            return [];
        }

        $attribution = $_SESSION['promotion_attribution'] ?? [];
        if (!is_array($attribution)) {
            return [];
        }

        $startedAt = strtotime((string) ($attribution['started_at'] ?? ''));
        if ($startedAt !== false && (time() - $startedAt) > 86400 * 14) {
            unset($_SESSION['promotion_attribution']);
            return [];
        }

        return $attribution;
    }

    private function setPromotionAttributionFromLandingPage(array $page, ?array $link = null): void
    {
        if (session_status() !== PHP_SESSION_ACTIVE) {
            return;
        }

        $source = is_array($link) ? array_merge($page, $link) : $page;
        $appKey = $this->normalizeAppKey((string) (($page['app_key'] ?? '') ?: ($source['media_app_id'] ?? '')));
        $app = $appKey !== '' ? $this->appConfig($appKey) : null;
        $_SESSION['promotion_attribution'] = [
            'promotion_link_id' => (int) ($page['promotion_link_id'] ?? ($source['id'] ?? 0)),
            'code' => (string) (($page['promotion_code'] ?? '') ?: ($source['code'] ?? '')),
            'agent_id' => (int) ($page['agent_id'] ?? ($source['agent_id'] ?? 0)),
            'source' => (string) ($source['source'] ?? 'landing_page'),
            'campaign' => (string) ($source['campaign'] ?? ($page['name'] ?? '')),
            'app_key' => (string) ($app['app_key'] ?? $appKey),
            'app_name' => (string) ($app['name'] ?? ($source['app_name'] ?? '')),
            'traffic_platform' => (string) ($page['traffic_platform'] ?? ($source['traffic_platform'] ?? '')),
            'channel_id' => (string) ($page['channel_id'] ?? ($source['channel_id'] ?? '')),
            'media_app_id' => (string) (($page['media_app_id'] ?? '') ?: ($source['media_app_id'] ?? '')),
            'ad_id' => (string) ($page['ad_id'] ?? ($source['ad_id'] ?? '')),
            'creative_id' => (string) ($page['creative_id'] ?? ($source['creative_id'] ?? '')),
            'material_id' => (string) ($page['material_id'] ?? ($source['material_id'] ?? '')),
            'landing_page_id' => (int) ($page['id'] ?? 0),
            'landing_page_slug' => (string) ($page['slug'] ?? ''),
            'started_at' => date('Y-m-d H:i:s'),
        ];
    }

    private function landingPageViewModel(array $page, ?array $link = null): array
    {
        $contentType = (string) ($page['content_type'] ?? 'drama');
        $content = $contentType === 'novel'
            ? ($this->findNovel((int) ($page['novel_id'] ?? 0)) ?? [])
            : ($this->findDrama((int) ($page['drama_id'] ?? 0)) ?? []);
        $cover = trim((string) ($page['cover'] ?? ''));
        if ($cover === '') {
            $cover = (string) ($content['cover'] ?? '/assets/cover-1.svg');
        }
        $title = trim((string) ($page['title'] ?? ''));
        if ($title === '') {
            $title = (string) ($content['title'] ?? ($page['name'] ?? '推广落地页'));
        }
        $subtitle = trim((string) ($page['subtitle'] ?? ''));
        if ($subtitle === '') {
            $subtitle = (string) ($content['description'] ?? '精彩内容正在热播，立即进入继续观看。');
        }
        $points = array_values((array) ($page['selling_points'] ?? []));
        if (empty($points)) {
            $points = $contentType === 'novel'
                ? ['正版章节', '沉浸阅读', '充值后自动解锁']
                : ['高清短剧', '极速播放', '充值后自动解锁'];
        }

        return [
            'page' => $page,
            'promotion_link' => $link,
            'content' => $content,
            'content_type' => $contentType,
            'cover' => $cover,
            'title' => $title,
            'subtitle' => $subtitle,
            'selling_points' => $points,
            'target_url' => $this->landingPageTargetUrl($page, $link),
            'click_url' => '/?route=landing-click&slug=' . rawurlencode((string) ($page['slug'] ?? '')),
        ];
    }

    private function landingPageTargetUrl(array $page, ?array $link = null): string
    {
        $mode = (string) ($page['cta_mode'] ?? 'content');
        if ($mode === 'custom' && trim((string) ($page['cta_url'] ?? '')) !== '') {
            return (string) $page['cta_url'];
        }
        if ($mode === 'promotion' && is_array($link)) {
            return $this->promotionLandingTarget($link);
        }

        $contentType = in_array((string) ($page['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $page['content_type'] : 'drama';
        $target = $this->promotionContentTargetUrl(
            $contentType,
            max(0, (int) ($page['drama_id'] ?? 0)),
            max(0, (int) ($page['episode_id'] ?? 0)),
            max(0, (int) ($page['novel_id'] ?? 0)),
            max(0, (int) ($page['chapter_id'] ?? 0))
        );
        $appKey = $this->normalizeAppKey((string) ($page['app_key'] ?? ''));
        if ($appKey !== '') {
            $target = $this->urlWithQueryParam($target, 'app_key', $appKey);
        }

        return $target;
    }

    private function appendLandingPageEvent(array &$data, array $page, string $eventType, string $targetUrl = ''): void
    {
        $eventType = in_array($eventType, ['view', 'click'], true) ? $eventType : 'view';
        $trafficMeta = $this->trafficMetaFromPayload($page);
        $data['landing_page_events'] ??= [];
        $data['landing_page_events'][] = [
            'id' => count((array) ($data['landing_page_events'] ?? [])) + 1,
            'landing_page_id' => (int) ($page['id'] ?? 0),
            'slug' => (string) ($page['slug'] ?? ''),
            'event' => $eventType,
            'user_id' => $this->currentUserId(),
            'promotion_link_id' => (int) ($page['promotion_link_id'] ?? 0),
            'promotion_code' => (string) ($page['promotion_code'] ?? ''),
            'agent_id' => (int) ($page['agent_id'] ?? 0),
            'path' => (string) ($_SERVER['REQUEST_URI'] ?? ''),
            'target_url' => $targetUrl,
            'user_agent' => substr((string) ($_SERVER['HTTP_USER_AGENT'] ?? ''), 0, 220),
            'ip' => (string) ($_SERVER['REMOTE_ADDR'] ?? ''),
            'created_at' => date('Y-m-d H:i:s'),
        ] + $trafficMeta;
        $data['landing_page_events'] = array_slice(array_values((array) ($data['landing_page_events'] ?? [])), -10000);
    }

    private function promotionContentTargetUrl(string $contentType, int $dramaId, int $episodeId, int $novelId, int $chapterId): string
    {
        if ($contentType === 'novel') {
            if ($novelId > 0 && $chapterId > 0) {
                return '/?route=novel-read&novel_id=' . $novelId . '&chapter_id=' . $chapterId;
            }
            if ($novelId > 0) {
                return '/?route=novel&id=' . $novelId;
            }

            return '/?route=novels';
        }

        if ($dramaId > 0) {
            return '/?route=yulan&id=' . $dramaId . ($episodeId > 0 ? '&episode_id=' . $episodeId : '');
        }

        return '/duanju';
    }

    private function effectivePromotionReplacementRule(array $link, ?int $timestamp = null): ?array
    {
        $timestamp ??= time();
        $rules = $this->normalizePromotionReplacementRules((array) ($link['replacement_rules'] ?? []));
        foreach ($rules as $rule) {
            if ((string) ($rule['status'] ?? 'active') !== 'active') {
                continue;
            }
            $startedAt = trim((string) ($rule['started_at'] ?? ''));
            $endedAt = trim((string) ($rule['ended_at'] ?? ''));
            if ($startedAt !== '' && strtotime($startedAt) > $timestamp) {
                continue;
            }
            if ($endedAt !== '' && strtotime($endedAt) < $timestamp) {
                continue;
            }

            return $rule;
        }

        return null;
    }

    private function normalizePromotionReplacementRules(array $rules): array
    {
        $normalized = [];
        foreach (array_values($rules) as $index => $rule) {
            if (!is_array($rule)) {
                continue;
            }
            $contentType = in_array((string) ($rule['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $rule['content_type'] : 'drama';
            $dramaId = $contentType === 'drama' ? max(0, (int) ($rule['drama_id'] ?? 0)) : 0;
            $episodeId = $contentType === 'drama' ? max(0, (int) ($rule['episode_id'] ?? 0)) : 0;
            $novelId = $contentType === 'novel' ? max(0, (int) ($rule['novel_id'] ?? 0)) : 0;
            $chapterId = $contentType === 'novel' ? max(0, (int) ($rule['chapter_id'] ?? 0)) : 0;
            $targetUrl = trim((string) ($rule['target_url'] ?? ''));
            if ($targetUrl === '') {
                $targetUrl = $this->promotionContentTargetUrl($contentType, $dramaId, $episodeId, $novelId, $chapterId);
            }

            $normalized[] = [
                'id' => max(1, (int) ($rule['id'] ?? ($index + 1))),
                'name' => $this->limitText(trim((string) ($rule['name'] ?? '')) ?: '替换规则' . ($index + 1), 60),
                'content_type' => $contentType,
                'drama_id' => $dramaId,
                'episode_id' => $episodeId,
                'novel_id' => $novelId,
                'chapter_id' => $chapterId,
                'target_url' => $targetUrl,
                'review_url' => trim((string) ($rule['review_url'] ?? '')),
                'started_at' => $this->normalizeDateTime((string) ($rule['started_at'] ?? ''), ''),
                'ended_at' => $this->normalizeDateTime((string) ($rule['ended_at'] ?? ''), ''),
                'status' => in_array((string) ($rule['status'] ?? ''), ['active', 'paused'], true) ? (string) $rule['status'] : 'active',
                'priority' => max(0, (int) ($rule['priority'] ?? 0)),
                'remark' => $this->limitText(trim((string) ($rule['remark'] ?? '')), 120),
                'created_at' => trim((string) ($rule['created_at'] ?? '')) ?: date('Y-m-d H:i:s'),
                'updated_at' => trim((string) ($rule['updated_at'] ?? '')) ?: date('Y-m-d H:i:s'),
            ];
        }

        usort($normalized, static function (array $a, array $b): int {
            return [
                (int) ($b['priority'] ?? 0),
                strtotime((string) ($b['started_at'] ?? '')) ?: 0,
                (int) ($b['id'] ?? 0),
            ] <=> [
                (int) ($a['priority'] ?? 0),
                strtotime((string) ($a['started_at'] ?? '')) ?: 0,
                (int) ($a['id'] ?? 0),
            ];
        });

        return $normalized;
    }

    private function normalizeDateTime(string $value, string $fallback = ''): string
    {
        $value = trim($value);
        if ($value === '') {
            return $fallback;
        }

        $timestamp = strtotime(str_replace('T', ' ', $value));
        if ($timestamp === false) {
            return $fallback;
        }

        return date('Y-m-d H:i:s', $timestamp);
    }

    private function trafficMetaFromLink(array $link): array
    {
        return $this->trafficMetaFromPayload($link);
    }

    private function promotionLinkAgentId(int $promotionLinkId, array $data): int
    {
        if ($promotionLinkId <= 0) {
            return 0;
        }

        foreach ((array) ($data['promotion_links'] ?? []) as $link) {
            if ((int) ($link['id'] ?? 0) === $promotionLinkId) {
                return max(0, (int) ($link['agent_id'] ?? 0));
            }
        }

        return 0;
    }

    private function trafficMetaFromPayload(array $payload, array $fallback = []): array
    {
        $base = $this->mergeTrafficMeta([
            'traffic_platform' => '',
            'channel_id' => '',
            'media_app_id' => '',
            'ad_id' => '',
            'creative_id' => '',
            'material_id' => '',
        ], $fallback, true);

        return $this->mergeTrafficMeta($base, $payload, true);
    }

    private function mergeTrafficMeta(array $base, array $source, bool $overwrite = false): array
    {
        $aliases = [
            'traffic_platform' => ['traffic_platform', 'platform', 'ad_platform'],
            'channel_id' => ['channel_id', 'channel', 'channel_code'],
            'media_app_id' => ['media_app_id', 'app_id', 'app_code'],
            'ad_id' => ['ad_id', 'advert_id', 'advertiser_id'],
            'creative_id' => ['creative_id', 'creativity_id', 'creative'],
            'material_id' => ['material_id', 'material', 'material_code'],
        ];
        $limits = [
            'traffic_platform' => 40,
            'channel_id' => 60,
            'media_app_id' => 60,
            'ad_id' => 80,
            'creative_id' => 80,
            'material_id' => 80,
        ];

        foreach ($aliases as $target => $keys) {
            $current = trim((string) ($base[$target] ?? ''));
            if (!$overwrite && $current !== '') {
                continue;
            }

            foreach ($keys as $key) {
                if (!array_key_exists($key, $source)) {
                    continue;
                }
                $value = $this->limitText(trim((string) ($source[$key] ?? '')), $limits[$target] ?? 80);
                if ($value === '') {
                    continue;
                }
                $base[$target] = $value;
                break;
            }
        }

        return $base;
    }

    private function recordPromotionPaidEvent(array &$data, array $order): void
    {
        $promotionLinkId = (int) ($order['promotion_link_id'] ?? 0);
        $promotionCode = (string) ($order['promotion_code'] ?? '');
        $orderNo = (string) ($order['order_no'] ?? '');
        if ($promotionLinkId <= 0 || $orderNo === '') {
            return;
        }

        foreach ($data['promotion_events'] ?? [] as $event) {
            if ((string) ($event['event'] ?? '') === 'paid' && (string) ($event['order_no'] ?? '') === $orderNo) {
                return;
            }
        }

        $data['promotion_events'][] = [
            'id' => count($data['promotion_events'] ?? []) + 1,
            'promotion_link_id' => $promotionLinkId,
            'code' => $promotionCode,
            'event' => 'paid',
            'user_id' => (int) ($order['user_id'] ?? 0),
            'order_no' => $orderNo,
            'amount' => round((float) ($order['amount'] ?? 0), 2),
            'path' => '',
            'created_at' => date('Y-m-d H:i:s'),
        ] + $this->trafficMetaFromPayload($order);
        $this->queueCallbackLog($data, [
            'promotion_link_id' => $promotionLinkId,
            'code' => $promotionCode,
            'event' => 'paid',
            'user_id' => (int) ($order['user_id'] ?? 0),
            'order_no' => $orderNo,
            'amount' => round((float) ($order['amount'] ?? 0), 2),
            'created_at' => date('Y-m-d H:i:s'),
        ] + $this->trafficMetaFromPayload($order));
        $data['promotion_events'] = array_slice(array_values($data['promotion_events']), -2000);
    }

    private function appendPromotionEventFromAttribution(array &$data, string $eventType, int $userId): void
    {
        $attribution = $this->currentPromotionAttribution();
        if (empty($attribution)) {
            return;
        }

        $this->appendPromotionEvent($data, [
            'promotion_link_id' => (int) ($attribution['promotion_link_id'] ?? 0),
            'code' => (string) ($attribution['code'] ?? ''),
            'event' => $eventType,
            'user_id' => $userId,
            'order_no' => '',
            'amount' => 0,
            'path' => (string) ($_SERVER['REQUEST_URI'] ?? ''),
        ] + $this->trafficMetaFromPayload($attribution), true);
    }

    private function appendPromotionEventFromOrder(array &$data, array $order, string $eventType): void
    {
        $this->appendPromotionEvent($data, [
            'promotion_link_id' => (int) ($order['promotion_link_id'] ?? 0),
            'code' => (string) ($order['promotion_code'] ?? ''),
            'event' => $eventType,
            'user_id' => (int) ($order['user_id'] ?? 0),
            'order_no' => (string) ($order['order_no'] ?? ''),
            'amount' => round((float) ($order['amount'] ?? 0), 2),
            'path' => '',
        ] + $this->trafficMetaFromPayload($order), true);
    }

    private function appendPromotionEvent(array &$data, array $event, bool $dedupeUserEvent = false): void
    {
        $promotionLinkId = (int) ($event['promotion_link_id'] ?? 0);
        $eventType = (string) ($event['event'] ?? '');
        $userId = (int) ($event['user_id'] ?? 0);
        if ($promotionLinkId <= 0 || !in_array($eventType, ['visit', 'paid', 'register', 'add_desktop', 'activate'], true)) {
            return;
        }

        if ($dedupeUserEvent && $userId > 0) {
            foreach ($data['promotion_events'] ?? [] as $item) {
                if (
                    (int) ($item['promotion_link_id'] ?? 0) === $promotionLinkId
                    && (string) ($item['event'] ?? '') === $eventType
                    && (int) ($item['user_id'] ?? 0) === $userId
                ) {
                    return;
                }
            }
        }

        $data['promotion_events'][] = [
            'id' => count($data['promotion_events'] ?? []) + 1,
            'promotion_link_id' => $promotionLinkId,
            'code' => (string) ($event['code'] ?? ''),
            'event' => $eventType,
            'user_id' => $userId,
            'order_no' => trim((string) ($event['order_no'] ?? '')),
            'amount' => round(max(0, (float) ($event['amount'] ?? 0)), 2),
            'path' => trim((string) ($event['path'] ?? '')),
            'created_at' => date('Y-m-d H:i:s'),
        ] + $this->trafficMetaFromPayload($event);
        $this->queueCallbackLog($data, $event);
        $data['promotion_events'] = array_slice(array_values($data['promotion_events']), -5000);
    }

    private function appendContentEvent(array &$data, string $eventType, array $payload = []): void
    {
        $eventType = in_array($eventType, ['view', 'lock_exposure', 'unlock_success', 'order_created'], true) ? $eventType : 'view';
        $contentType = in_array((string) ($payload['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $payload['content_type'] : 'drama';
        $attribution = $this->currentPromotionAttribution();
        $trafficMeta = $this->trafficMetaFromPayload($payload, $attribution);
        $data['content_events'] ??= [];
        $data['content_events'][] = [
            'id' => count((array) ($data['content_events'] ?? [])) + 1,
            'content_type' => $contentType,
            'event' => $eventType,
            'drama_id' => $contentType === 'drama' ? max(0, (int) ($payload['drama_id'] ?? 0)) : 0,
            'episode_id' => $contentType === 'drama' ? max(0, (int) ($payload['episode_id'] ?? 0)) : 0,
            'novel_id' => $contentType === 'novel' ? max(0, (int) ($payload['novel_id'] ?? 0)) : 0,
            'chapter_id' => $contentType === 'novel' ? max(0, (int) ($payload['chapter_id'] ?? 0)) : 0,
            'user_id' => max(0, (int) ($payload['user_id'] ?? $this->currentUserId())),
            'order_no' => trim((string) ($payload['order_no'] ?? '')),
            'amount' => round(max(0, (float) ($payload['amount'] ?? 0)), 2),
            'promotion_link_id' => max(0, (int) ($payload['promotion_link_id'] ?? ($attribution['promotion_link_id'] ?? 0))),
            'code' => (string) ($payload['code'] ?? ($attribution['code'] ?? '')),
            'path' => trim((string) ($payload['path'] ?? ($_SERVER['REQUEST_URI'] ?? ''))),
            'created_at' => date('Y-m-d H:i:s'),
        ] + $trafficMeta;
        $data['content_events'] = array_slice(array_values((array) ($data['content_events'] ?? [])), -10000);
    }

    private function queueCallbackLog(array &$data, array $event): void
    {
        $eventType = (string) ($event['event'] ?? '');
        if (!in_array($eventType, ['add_desktop', 'paid'], true)) {
            return;
        }

        $config = (array) ($data['callback_config'] ?? []);
        $callbackPolicy = $this->callbackPolicyForEvent($event, $config);
        $enabled = !empty($callbackPolicy['enabled']);
        $endpoint = trim((string) ($callbackPolicy['endpoint'] ?? ''));
        $platformEvents = $eventType === 'add_desktop'
            ? array_values((array) ($callbackPolicy['add_desktop_events'] ?? ['active']))
            : array_values((array) ($callbackPolicy['paid_events'] ?? ['pay']));
        if (empty($platformEvents)) {
            $platformEvents = [$eventType === 'add_desktop' ? 'active' : 'pay'];
        }

        $orderNo = trim((string) ($event['order_no'] ?? ''));
        $userId = (int) ($event['user_id'] ?? 0);
        foreach ((array) ($data['callback_logs'] ?? []) as $log) {
            $sameOrderEvent = $orderNo !== ''
                && (string) ($log['event'] ?? '') === $eventType
                && (string) ($log['order_no'] ?? '') === $orderNo;
            $sameUserAddDesktop = $eventType === 'add_desktop'
                && $userId > 0
                && (string) ($log['event'] ?? '') === $eventType
                && (int) ($log['user_id'] ?? 0) === $userId
                && (int) ($log['promotion_link_id'] ?? 0) === (int) ($event['promotion_link_id'] ?? 0);
            if ($sameOrderEvent || $sameUserAddDesktop) {
                return;
            }
        }

        $now = date('Y-m-d H:i:s');
        foreach ($platformEvents as $platformEvent) {
            $platformEvent = trim((string) $platformEvent);
            if ($platformEvent === '') {
                continue;
            }
            $trafficMeta = $this->trafficMetaFromPayload($event);
            $payload = [
                'platform' => (string) ($callbackPolicy['platform'] ?? '巨量引擎'),
                'event' => $platformEvent,
                'event_type' => $eventType,
                'promotion_code' => (string) ($event['code'] ?? ''),
                'promotion_link_id' => (int) ($event['promotion_link_id'] ?? 0),
                'app_key' => (string) ($callbackPolicy['app_key'] ?? ($trafficMeta['media_app_id'] ?? '')),
                'app_name' => (string) ($callbackPolicy['app_name'] ?? ''),
                'user_id' => $userId,
                'order_no' => $orderNo,
                'amount' => round(max(0, (float) ($event['amount'] ?? 0)), 2),
                'timestamp' => (string) (($event['created_at'] ?? '') ?: $now),
            ] + $trafficMeta;
            $fieldMapping = (array) ($callbackPolicy['field_mapping'] ?? []);
            $payload = $this->callbackPayloadForTemplate($payload, $fieldMapping);

            $data['callback_logs'][] = [
                'id' => count($data['callback_logs'] ?? []) + 1,
                'event' => $eventType,
                'platform_event' => $platformEvent,
                'promotion_link_id' => (int) ($event['promotion_link_id'] ?? 0),
                'code' => (string) ($event['code'] ?? ''),
                'user_id' => $userId,
                'order_no' => $orderNo,
                'amount' => round(max(0, (float) ($event['amount'] ?? 0)), 2),
                'app_key' => (string) ($callbackPolicy['app_key'] ?? ($trafficMeta['media_app_id'] ?? '')),
                'app_name' => (string) ($callbackPolicy['app_name'] ?? ''),
                'callback_policy_source' => (string) ($callbackPolicy['source'] ?? 'global'),
                'callback_enabled' => $enabled,
                'callback_retry_failed' => !empty($callbackPolicy['retry_failed']),
                'callback_fallback_time_match' => !empty($callbackPolicy['fallback_time_match']),
                'callback_secret' => (string) ($callbackPolicy['secret'] ?? ''),
                'callback_template_key' => (string) ($callbackPolicy['template_key'] ?? 'custom'),
                'callback_template_name' => (string) ($callbackPolicy['template_name'] ?? '自定义模板'),
                'callback_field_mapping' => $fieldMapping,
                'callback_auth_config' => (array) ($callbackPolicy['auth_config'] ?? []),
                'status' => ($enabled && $endpoint !== '') ? 'pending' : 'skipped',
                'message' => ($enabled && $endpoint !== '') ? '已进入回传队列，等待发送。' : '回传未启用或未配置地址，已跳过外部发送。',
                'endpoint' => $endpoint,
                'request_payload' => $payload,
                'response_payload' => [],
                'next_retry_at' => '',
                'retry_blocked_reason' => '',
                'created_at' => $now,
                'updated_at' => $now,
            ] + $trafficMeta;
        }

        $data['callback_logs'] = array_slice(array_values((array) ($data['callback_logs'] ?? [])), -5000);
    }

    private function operationAlertReceiversFromPayload(array $payload, array $existing): array
    {
        $existingById = [];
        foreach ($existing as $item) {
            if (is_array($item) && (int) ($item['id'] ?? 0) > 0) {
                $existingById[(int) $item['id']] = $item;
            }
        }

        $rawReceivers = (array) ($payload['receivers'] ?? []);
        $receivers = [];
        $now = date('Y-m-d H:i:s');
        $nextId = empty($existingById) ? 1 : (max(array_keys($existingById)) + 1);
        foreach ($rawReceivers as $raw) {
            if (!is_array($raw)) {
                continue;
            }
            $delete = !empty($raw['delete']);
            $id = max(0, (int) ($raw['id'] ?? 0));
            if ($delete && $id > 0) {
                continue;
            }
            if ($delete) {
                continue;
            }

            $name = $this->limitText(trim((string) ($raw['name'] ?? '')), 80);
            $webhook = trim((string) ($raw['webhook_url'] ?? ''));
            $wechatWorkUrl = trim((string) ($raw['wechat_work_url'] ?? ''));
            $email = $this->limitText(trim((string) ($raw['email'] ?? '')), 120);
            $phone = $this->limitText(trim((string) ($raw['phone'] ?? '')), 30);
            if ($name === '' && $webhook === '' && $wechatWorkUrl === '' && $email === '' && $phone === '' && $id <= 0) {
                continue;
            }
            if ($id <= 0) {
                $id = $nextId++;
            }
            $previous = (array) ($existingById[$id] ?? []);
            $fallbackChannels = $this->operationAlertChannelsFromValue($previous['channels'] ?? ($previous['channel'] ?? []), ['webhook']);
            $channels = $this->operationAlertChannelsFromValue($raw['channels'] ?? [], $fallbackChannels);
            $statuses = array_values(array_filter(array_map('strval', (array) ($raw['send_statuses'] ?? [])), static fn (string $status): bool => in_array($status, ['pending', 'processing', 'resolved', 'ignored'], true)));
            if (empty($statuses)) {
                $statuses = (array) ($previous['send_statuses'] ?? ['pending', 'processing']);
            }
            $operationAlertTypes = ['callback_failed', 'low_conversion_material', 'high_refund_material', 'low_recovery_link', 'auto_paused_link', 'promotion_stop_failed', 'promotion_stop_auth_failed', 'promotion_stop_rate_limited'];
            $types = array_values(array_filter(array_map('strval', (array) ($raw['alert_types'] ?? [])), static fn (string $type): bool => $type === 'all' || in_array($type, $operationAlertTypes, true)));
            if (empty($types)) {
                $types = (array) ($previous['alert_types'] ?? ['all']);
            }
            if (in_array('all', $types, true)) {
                $types = ['all'];
            }
            $scopeType = (string) ($raw['scope_type'] ?? ($previous['scope_type'] ?? 'global'));
            $scopeType = in_array($scopeType, ['global', 'role', 'agent'], true) ? $scopeType : 'global';
            $scopeRole = (string) ($raw['scope_role'] ?? ($previous['scope_role'] ?? ''));
            $scopeRole = in_array($scopeRole, ['business', 'leader', 'agent'], true) ? $scopeRole : '';
            $priority = (string) ($raw['min_priority'] ?? ($previous['min_priority'] ?? 'normal'));
            $priority = in_array($priority, ['low', 'normal', 'high', 'urgent'], true) ? $priority : 'normal';

            $receivers[] = [
                'id' => $id,
                'name' => $name !== '' ? $name : ('预警接收人' . $id),
                'status' => (string) ($raw['status'] ?? ($previous['status'] ?? 'active')) === 'paused' ? 'paused' : 'active',
                'scope_type' => $scopeType,
                'scope_role' => $scopeRole,
                'agent_id' => max(0, (int) ($raw['agent_id'] ?? ($previous['agent_id'] ?? 0))),
                'channel' => $channels[0] ?? 'webhook',
                'channels' => $channels,
                'webhook_url' => $webhook,
                'secret' => trim((string) ($raw['secret'] ?? ($previous['secret'] ?? ''))),
                'wechat_work_url' => $wechatWorkUrl,
                'wechat_work_secret' => trim((string) ($raw['wechat_work_secret'] ?? ($previous['wechat_work_secret'] ?? ''))),
                'wechat_work_signing_enabled' => !empty($raw['wechat_work_signing_enabled']),
                'email' => $email,
                'phone' => $phone,
                'send_statuses' => $statuses,
                'alert_types' => $types,
                'min_priority' => $priority,
                'retry_failed' => !empty($raw['retry_failed']),
                'remark' => $this->limitText(trim((string) ($raw['remark'] ?? ($previous['remark'] ?? ''))), 160),
                'created_at' => (string) ($previous['created_at'] ?? $now),
                'updated_at' => $now,
            ];
        }

        return $receivers;
    }

    private function operationAlertChannelsFromValue($value, array $fallback = ['webhook']): array
    {
        $allowed = ['webhook', 'wechat_work', 'email', 'sms', 'in_app'];
        if (is_string($value)) {
            $items = preg_split('/[\s,，|]+/u', $value) ?: [];
        } else {
            $items = (array) $value;
        }

        $channels = [];
        foreach ($items as $item) {
            $channel = (string) $item;
            if (!in_array($channel, $allowed, true) || in_array($channel, $channels, true)) {
                continue;
            }
            $channels[] = $channel;
        }
        if (empty($channels)) {
            foreach ($fallback as $item) {
                $channel = (string) $item;
                if (!in_array($channel, $allowed, true) || in_array($channel, $channels, true)) {
                    continue;
                }
                $channels[] = $channel;
            }
        }

        if (empty($channels) && !empty($fallback)) {
            return ['webhook'];
        }

        return $channels;
    }

    private function operationAlertNotificationChannelLabel(string $channel): string
    {
        return [
            'webhook' => 'Webhook',
            'wechat_work' => '企业微信',
            'email' => '邮件',
            'sms' => '短信',
            'in_app' => '站内',
        ][$channel] ?? $channel;
    }

    private function operationAlertNotificationTargetEndpoint(array $target): string
    {
        return match ((string) ($target['channel'] ?? 'webhook')) {
            'wechat_work' => trim((string) ($target['wechat_work_url'] ?? '')),
            'email' => trim((string) ($target['email'] ?? '')),
            'sms' => preg_replace('/\D+/', '', (string) ($target['phone'] ?? '')) ?? '',
            'in_app' => '站内预警',
            default => trim((string) ($target['webhook_url'] ?? $target['endpoint'] ?? '')),
        };
    }

    private function operationAlertNotificationTargetKey(array $target): string
    {
        return implode('|', [
            (int) ($target['receiver_id'] ?? $target['id'] ?? 0),
            (string) ($target['channel'] ?? 'webhook'),
            $this->operationAlertNotificationTargetEndpoint($target),
            !empty($target['is_escalation']) || !empty($target['_escalation']) ? 'escalation' : 'normal',
        ]);
    }

    private function operationAlertWechatWorkRequestEndpoint(array $target): array
    {
        $endpoint = $this->operationAlertNotificationTargetEndpoint($target);
        $secret = trim((string) ($target['wechat_work_secret'] ?? ''));
        $signingEnabled = !empty($target['wechat_work_signing_enabled']) && $secret !== '' && $endpoint !== '';
        if (!$signingEnabled) {
            return ['endpoint' => $endpoint, 'signed' => false, 'timestamp' => ''];
        }

        $timestamp = (string) (int) floor(microtime(true) * 1000);
        $signature = base64_encode(hash_hmac('sha256', $timestamp . "\n" . $secret, $secret, true));
        $separator = str_contains($endpoint, '?') ? '&' : '?';

        return [
            'endpoint' => $endpoint . $separator . 'timestamp=' . rawurlencode($timestamp) . '&sign=' . rawurlencode($signature),
            'signed' => true,
            'timestamp' => $timestamp,
        ];
    }

    private function operationAlertMissingEndpointMessage(string $channel): string
    {
        return match ($channel) {
            'wechat_work' => '接收人未配置企业微信机器人地址，已跳过。',
            'email' => '接收人未配置邮箱，已跳过。',
            'sms' => '接收人未配置手机号，已跳过。',
            'in_app' => '站内预警无需外部地址。',
            default => '接收人未配置 Webhook 地址，已跳过。',
        };
    }

    private function sendOperationAlertNotificationTarget(array &$data, array $target, array $payload, string $now): array
    {
        $channel = (string) ($target['channel'] ?? 'webhook');
        if ($channel === 'wechat_work') {
            $wechatEndpoint = $this->operationAlertWechatWorkRequestEndpoint($target);
            $result = $this->performCallbackRequest((string) ($wechatEndpoint['endpoint'] ?? ''), $payload, '');
            $result['wechat_work_signed'] = !empty($wechatEndpoint['signed']);
            $result['wechat_work_signed_timestamp'] = (string) ($wechatEndpoint['timestamp'] ?? '');

            return $result;
        }
        if ($channel === 'email') {
            return $this->sendOperationAlertEmailNotification($data, $target, $payload, $now);
        }
        if ($channel === 'sms') {
            return $this->sendOperationAlertSmsNotification($data, $target, $payload, $now);
        }
        if ($channel === 'in_app') {
            $created = $this->createOperationAlertInAppMessages($data, $target, $payload, $now);

            return [
                'ok' => true,
                'status' => 'success',
                'message' => '站内预警已投递 ' . $created . ' 条。',
                'request_payload' => $payload,
                'in_app_created' => $created,
                'attempted_at' => $now,
            ];
        }

        return $this->performCallbackRequest($this->operationAlertNotificationTargetEndpoint($target), $payload, (string) ($target['secret'] ?? ''));
    }

    private function createOperationAlertInAppMessages(array &$data, array $target, array $payload, string $now): int
    {
        $admins = [];
        $scopeType = (string) ($target['scope_type'] ?? 'global');
        $scopeRole = (string) ($target['scope_role'] ?? '');
        $agentId = (int) ($target['agent_id'] ?? 0);
        foreach ((array) ($data['admins'] ?? []) as $admin) {
            if ((string) ($admin['status'] ?? 'active') !== 'active') {
                continue;
            }
            if ($scopeType === 'role' && $scopeRole !== '' && (string) ($admin['role'] ?? '') !== $scopeRole) {
                continue;
            }
            if ($scopeType === 'agent' && $agentId > 0 && (int) ($admin['agent_id'] ?? 0) !== $agentId) {
                continue;
            }
            if ($scopeType === 'global' && !in_array((string) ($admin['role'] ?? 'super_admin'), ['super_admin', 'business', 'leader', 'agent'], true)) {
                continue;
            }
            $admins[] = $admin;
        }
        if (empty($admins)) {
            return 0;
        }

        $title = (string) ($payload['title'] ?? $payload['alert']['title'] ?? '投放预警');
        $body = (string) ($payload['body'] ?? $payload['alert']['body'] ?? $payload['alert']['message'] ?? '');
        $created = 0;
        foreach (array_slice($admins, 0, 100) as $admin) {
            $recipient = $this->adminInAppRecipient($admin);
            $this->appendInAppMessage($data, [
                'recipient_type' => 'admin',
                'admin_id' => (int) ($recipient['admin_id'] ?? 0),
                'agent_id' => (int) ($recipient['agent_id'] ?? 0),
                'recipient_name' => (string) ($recipient['recipient_name'] ?? ''),
                'recipient_contact' => (string) ($recipient['recipient_contact'] ?? ''),
                'scenario' => 'operation_alert',
                'template_key' => 'operation_alert_in_app',
                'source' => 'operation_alert',
                'reference_type' => 'operation_alert',
                'reference_id' => (int) ($payload['alert']['id'] ?? 0),
                'title' => $title,
                'body' => $body,
                'priority' => (string) ($payload['alert']['priority'] ?? 'normal'),
                'created_at' => $now,
                'updated_at' => $now,
            ]);
            $created++;
        }

        return $created;
    }

    private function sendOperationAlertEmailNotification(array &$data, array $target, array $payload, string $now): array
    {
        $toEmail = trim((string) ($payload['to_email'] ?? $target['email'] ?? ''));
        if (!filter_var($toEmail, FILTER_VALIDATE_EMAIL)) {
            return ['ok' => false, 'status' => 'failed', 'message' => '收件邮箱格式不正确。', 'to_email' => $toEmail];
        }

        $emailConfig = $this->emailConfig($data);
        if ((string) ($emailConfig['status'] ?? 'paused') !== 'active') {
            return ['ok' => false, 'status' => 'skipped', 'message' => '邮件通道已停用，仅保留预警日志。', 'to_email' => $toEmail];
        }

        $subject = (string) ($payload['subject'] ?? '投放预警');
        $body = (string) ($payload['body'] ?? '');
        $delivery = $this->deliverEmailMessage($emailConfig, $toEmail, $subject, $body);
        $this->appendEmailDeliveryLog($data, $toEmail, $subject, $body, $delivery, $now);

        return [
            'ok' => !empty($delivery['ok']),
            'status' => (string) ($delivery['status'] ?? (!empty($delivery['ok']) ? 'success' : 'failed')),
            'message' => (string) ($delivery['message'] ?? (!empty($delivery['ok']) ? '预警邮件发送成功。' : '预警邮件发送失败。')),
            'provider' => (string) ($delivery['provider'] ?? $emailConfig['provider'] ?? 'mock'),
            'to_email' => $toEmail,
            'response_payload' => (array) ($delivery['response_payload'] ?? []),
        ];
    }

    private function sendOperationAlertSmsNotification(array &$data, array $target, array $payload, string $now): array
    {
        $phone = preg_replace('/\D+/', '', (string) ($payload['phone'] ?? $target['phone'] ?? '')) ?? '';
        if (!preg_match('/^1\d{10}$/', $phone)) {
            return ['ok' => false, 'status' => 'failed', 'message' => '手机号格式不正确。', 'phone' => $phone];
        }

        $smsConfig = $this->smsConfig($data);
        if ((string) ($smsConfig['status'] ?? 'active') !== 'active') {
            return ['ok' => false, 'status' => 'skipped', 'message' => '短信通道已停用，仅保留预警日志。', 'phone' => $phone];
        }

        $delivery = $this->deliverSmsMessage($smsConfig, $phone, (string) ($payload['message'] ?? ''), 'operation_alert');
        $providerRequestId = (string) ($delivery['provider_request_id'] ?? '');

        return [
            'ok' => !empty($delivery['ok']),
            'status' => (string) ($delivery['status'] ?? (!empty($delivery['ok']) ? 'success' : 'failed')),
            'message' => (string) ($delivery['message'] ?? (!empty($delivery['ok']) ? '预警短信发送成功。' : '预警短信发送失败。')),
            'provider' => (string) ($delivery['provider'] ?? $smsConfig['provider'] ?? 'mock'),
            'phone' => $phone,
            'template_id' => (string) ($smsConfig['template_id'] ?? ''),
            'sms_body' => $this->limitText((string) ($payload['message'] ?? ''), 240),
            'attempted_at' => $now,
            'provider_request_id' => $providerRequestId,
            'response_payload' => (array) ($delivery['response_payload'] ?? []),
        ];
    }

    private function deliverSmsMessage(array $smsConfig, string $phone, string $message, string $scene = 'operation_alert'): array
    {
        $provider = (string) ($smsConfig['provider'] ?? 'mock');
        if ($provider === 'mock') {
            return [
                'ok' => true,
                'status' => 'success',
                'provider' => $provider,
                'message' => '模拟短信已记录。',
                'response_payload' => ['mode' => 'mock'],
            ];
        }

        $endpoint = trim((string) ($smsConfig['endpoint'] ?? ''));
        if ($endpoint === '') {
            return [
                'ok' => false,
                'status' => 'failed',
                'provider' => $provider,
                'message' => '短信供应商接口地址未配置。',
                'response_payload' => ['provider' => $provider],
            ];
        }

        $requestPayload = [
            'scene' => $scene,
            'provider' => $provider,
            'phone' => $phone,
            'message' => $message,
            'sign_name' => (string) ($smsConfig['sign_name'] ?? ''),
            'template_id' => (string) ($smsConfig['template_id'] ?? ''),
            'access_key' => (string) ($smsConfig['access_key'] ?? ''),
        ];
        $secret = trim((string) ($smsConfig['access_secret'] ?? ''));
        $authConfig = $secret !== '' ? [
            'mode' => 'hmac_header',
            'secret' => $secret,
            'algorithm' => 'sha256',
            'header_name' => 'X-JX-Signature',
            'include_timestamp' => true,
            'timestamp_key' => 'timestamp',
            'sign_source' => 'body_with_timestamp',
        ] : ['mode' => 'none'];
        $result = $this->performCallbackRequest($endpoint, $requestPayload, $secret, $authConfig);
        $ok = !empty($result['ok']);

        return [
            'ok' => $ok,
            'status' => $ok ? 'success' : 'failed',
            'provider' => $provider,
            'message' => $ok ? '短信供应商发送成功。' : (string) ($result['message'] ?? '短信供应商发送失败。'),
            'provider_request_id' => $this->notificationProviderRequestId($result),
            'response_payload' => $result,
        ];
    }

    private function notificationProviderRequestId(array $payload): string
    {
        $keys = ['provider_request_id', 'request_id', 'sms_id', 'message_id', 'msg_id', 'task_id', 'biz_id', 'sid'];
        $stack = [$payload];
        while (!empty($stack)) {
            $current = array_shift($stack);
            if (!is_array($current)) {
                continue;
            }
            foreach ($keys as $key) {
                if (isset($current[$key]) && trim((string) $current[$key]) !== '') {
                    return $this->limitText(trim((string) $current[$key]), 120);
                }
            }
            foreach ($current as $value) {
                if (is_array($value)) {
                    $stack[] = $value;
                }
            }
        }

        return '';
    }

    public function handleSmsDeliveryReceipt(array $payload, array $headers = [], string $rawBody = ''): array
    {
        $data = $this->store->load();
        $smsConfig = $this->smsConfig($data);
        $receipt = $this->normalizeSmsDeliveryReceiptPayload($payload);
        if (!$this->verifySmsDeliveryReceiptSignature($payload, $headers, $rawBody, $smsConfig)) {
            return ['ok' => false, 'message' => '短信回执签名校验失败。'];
        }
        if ((string) ($receipt['provider_request_id'] ?? '') === '' && (string) ($receipt['phone'] ?? '') === '') {
            return ['ok' => false, 'message' => '短信回执缺少请求号或手机号。'];
        }

        $now = date('Y-m-d H:i:s');
        $smsUpdated = $this->applySmsDeliveryReceiptToSmsCodes($data, $receipt, $now);
        $alertUpdated = $this->applySmsDeliveryReceiptToOperationAlertLogs($data, $receipt, $now);
        if ($smsUpdated + $alertUpdated > 0) {
            $this->store->save($data);
        }

        return [
            'ok' => true,
            'message' => '短信回执已处理。',
            'receipt' => $receipt,
            'sms_updated' => $smsUpdated,
            'alert_logs_updated' => $alertUpdated,
        ];
    }

    private function normalizeSmsDeliveryReceiptPayload(array $payload): array
    {
        $flat = $payload;
        foreach (['data', 'body', 'receipt', 'result'] as $key) {
            if (isset($flat[$key]) && is_array($flat[$key])) {
                $flat = array_replace($flat, (array) $flat[$key]);
            }
        }
        $scalar = static function (mixed $value): string {
            return is_scalar($value) ? (string) $value : '';
        };
        $requestId = $this->notificationProviderRequestId($flat);
        $phone = preg_replace('/\D+/', '', $scalar($flat['phone'] ?? $flat['mobile'] ?? $flat['receiver'] ?? '')) ?? '';
        $rawStatus = strtolower(trim($scalar($flat['status'] ?? $flat['send_status'] ?? $flat['state'] ?? $flat['result'] ?? $flat['code'] ?? '')));
        $status = match (true) {
            in_array($rawStatus, ['success', 'succeed', 'delivered', 'deliver_success', 'sent', 'ok', '0', '200', 'delivrd'], true) => 'success',
            in_array($rawStatus, ['failed', 'fail', 'failure', 'rejected', 'undelivered', 'error', 'timeout', 'expired'], true) => 'failed',
            in_array($rawStatus, ['pending', 'queued', 'sending', 'processing'], true) => 'queued',
            default => $rawStatus === '' ? 'queued' : (str_contains($rawStatus, 'success') || str_contains($rawStatus, 'deliver') ? 'success' : (str_contains($rawStatus, 'fail') || str_contains($rawStatus, 'error') ? 'failed' : 'queued')),
        };
        $message = $this->limitText(trim($scalar($flat['message'] ?? $flat['msg'] ?? $flat['reason'] ?? $flat['error'] ?? $flat['desc'] ?? '')), 200);

        return [
            'provider_request_id' => $requestId,
            'phone' => $this->limitText($phone, 20),
            'raw_status' => $this->limitText($rawStatus, 80),
            'status' => $status,
            'message' => $message,
            'provider' => $this->limitText(trim($scalar($flat['provider'] ?? '')), 40),
            'received_at' => date('Y-m-d H:i:s'),
            'payload' => $payload,
        ];
    }

    private function verifySmsDeliveryReceiptSignature(array $payload, array $headers, string $rawBody, array $smsConfig): bool
    {
        $secret = trim((string) ($smsConfig['access_secret'] ?? ''));
        if ($secret === '') {
            return true;
        }
        $signature = trim((string) ($payload['sign'] ?? $payload['signature'] ?? ''));
        foreach ($headers as $key => $value) {
            $headerKey = strtolower((string) $key);
            if (in_array($headerKey, ['x-jx-signature', 'x-signature', 'signature'], true) && trim((string) $value) !== '') {
                $signature = trim((string) $value);
                break;
            }
        }
        if ($signature === '') {
            return false;
        }

        $signingPayload = $payload;
        unset($signingPayload['sign'], $signingPayload['signature']);
        $encodedPayload = json_encode($signingPayload, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
        $timestamp = trim((string) ($payload['timestamp'] ?? $payload['ts'] ?? ''));
        $requestId = $this->notificationProviderRequestId($payload);
        $phone = preg_replace('/\D+/', '', (string) ($payload['phone'] ?? $payload['mobile'] ?? '')) ?? '';
        $status = (string) ($payload['status'] ?? $payload['send_status'] ?? $payload['state'] ?? $payload['code'] ?? '');
        $candidates = array_filter([
            $encodedPayload === false ? '' : hash_hmac('sha256', $encodedPayload, $secret),
            $rawBody !== '' ? hash_hmac('sha256', $rawBody, $secret) : '',
            hash_hmac('sha256', implode('|', [$requestId, $phone, $status, $timestamp]), $secret),
            hash_hmac('sha256', implode('|', [$phone, $status, $timestamp]), $secret),
        ], static fn (string $item): bool => $item !== '');
        foreach ($candidates as $candidate) {
            if (hash_equals($candidate, $signature)) {
                return true;
            }
        }

        return false;
    }

    private function applySmsDeliveryReceiptToSmsCodes(array &$data, array $receipt, string $now): int
    {
        $updated = 0;
        $requestId = (string) ($receipt['provider_request_id'] ?? '');
        $phone = (string) ($receipt['phone'] ?? '');
        foreach (array_reverse(array_keys((array) ($data['sms_codes'] ?? []))) as $index) {
            $item = (array) ($data['sms_codes'][$index] ?? []);
            if (!$this->smsDeliveryReceiptMatches((string) ($item['provider_request_id'] ?? ''), (string) ($item['phone'] ?? ''), $requestId, $phone)) {
                continue;
            }
            $data['sms_codes'][$index]['send_status'] = (string) ($receipt['status'] ?? 'queued');
            $data['sms_codes'][$index]['provider_request_id'] = (string) (($item['provider_request_id'] ?? '') ?: $requestId);
            $data['sms_codes'][$index]['receipt_status'] = (string) ($receipt['raw_status'] ?? $receipt['status'] ?? '');
            $data['sms_codes'][$index]['receipt_message'] = (string) ($receipt['message'] ?? '');
            $data['sms_codes'][$index]['receipt_received_at'] = $now;
            $data['sms_codes'][$index]['response_payload']['delivery_receipt'] = (array) ($receipt['payload'] ?? []);
            $updated++;
            break;
        }

        return $updated;
    }

    private function applySmsDeliveryReceiptToOperationAlertLogs(array &$data, array $receipt, string $now): int
    {
        $updated = 0;
        $requestId = (string) ($receipt['provider_request_id'] ?? '');
        $phone = (string) ($receipt['phone'] ?? '');
        foreach (array_reverse(array_keys((array) ($data['operation_alert_notification_logs'] ?? []))) as $index) {
            $log = (array) ($data['operation_alert_notification_logs'][$index] ?? []);
            if ((string) ($log['channel'] ?? '') !== 'sms') {
                continue;
            }
            $logRequestId = (string) (($log['provider_request_id'] ?? '') ?: $this->notificationProviderRequestId((array) ($log['response_payload'] ?? [])));
            if (!$this->smsDeliveryReceiptMatches($logRequestId, (string) ($log['receiver_contact'] ?? $log['endpoint'] ?? ''), $requestId, $phone)) {
                continue;
            }
            $status = (string) ($receipt['status'] ?? 'queued');
            $data['operation_alert_notification_logs'][$index]['status'] = $status === 'success' ? 'success' : ($status === 'failed' ? 'failed' : (string) ($log['status'] ?? 'pending'));
            $data['operation_alert_notification_logs'][$index]['message'] = $status === 'failed'
                ? '短信回执失败：' . ((string) ($receipt['message'] ?? '') ?: '供应商返回失败。')
                : ($status === 'success' ? '短信供应商回执成功。' : ((string) ($log['message'] ?? '') ?: '短信供应商回执处理中。'));
            $data['operation_alert_notification_logs'][$index]['provider_request_id'] = $logRequestId !== '' ? $logRequestId : $requestId;
            $data['operation_alert_notification_logs'][$index]['receipt_status'] = (string) ($receipt['raw_status'] ?? $receipt['status'] ?? '');
            $data['operation_alert_notification_logs'][$index]['receipt_message'] = (string) ($receipt['message'] ?? '');
            $data['operation_alert_notification_logs'][$index]['receipt_received_at'] = $now;
            $data['operation_alert_notification_logs'][$index]['response_payload']['delivery_receipt'] = (array) ($receipt['payload'] ?? []);
            $data['operation_alert_notification_logs'][$index]['updated_at'] = $now;
            $updated++;
            break;
        }

        return $updated;
    }

    private function smsDeliveryReceiptMatches(string $recordRequestId, string $recordPhone, string $receiptRequestId, string $receiptPhone): bool
    {
        $recordPhone = preg_replace('/\D+/', '', $recordPhone) ?? '';
        if ($receiptRequestId !== '' && $recordRequestId !== '' && $recordRequestId === $receiptRequestId) {
            return $receiptPhone === '' || $recordPhone === '' || $recordPhone === $receiptPhone;
        }

        return $receiptPhone !== '' && $recordPhone === $receiptPhone;
    }

    private function operationAlertFailureEscalationTargets(array $alert, array $failedTarget, array $config, array $data): array
    {
        if (empty($config['failure_escalation_enabled']) || !empty($failedTarget['_escalation'])) {
            return [];
        }
        $attemptCount = max(1, (int) ($alert['external_notify_attempt_count'] ?? 1));
        $threshold = max(1, min(10, (int) ($config['failure_escalation_after_attempts'] ?? 1)));
        if ($attemptCount < $threshold) {
            return [];
        }

        $channels = $this->operationAlertChannelsFromValue($config['failure_escalation_channels'] ?? [], []);
        if (empty($channels)) {
            $channels = $this->operationAlertChannelsFromValue($config['urgent_channels'] ?? [], []);
        }
        $channels = array_values(array_filter($channels, static fn (string $channel): bool => $channel !== (string) ($failedTarget['channel'] ?? 'webhook')));
        if (empty($channels)) {
            return [];
        }

        $targets = [];
        foreach ($channels as $channel) {
            $target = $failedTarget;
            $target['channel'] = $channel;
            $target['channels'] = [$channel];
            $target['_escalation'] = true;
            $target['is_escalation'] = true;
            $target['escalation_reason'] = $this->operationAlertNotificationChannelLabel((string) ($failedTarget['channel'] ?? 'webhook')) . '发送失败，触发升级通知。';
            $target['name'] = trim((string) ($target['name'] ?? '接收人')) . '（失败升级）';
            $target['retry_failed'] = true;
            foreach (['webhook_url', 'secret', 'wechat_work_url', 'wechat_work_secret', 'email', 'phone', 'wechat_work_signing_enabled'] as $field) {
                if (($target[$field] ?? '') === '' && array_key_exists($field, $config)) {
                    $target[$field] = $config[$field];
                }
            }
            if (!$this->operationAlertNotificationAlreadySucceeded($alert, $target, $data)) {
                $targets[] = $target;
            }
        }

        return $targets;
    }

    private function shouldSendOperationAlertNotification(array $alert, array $config, ?array $data = null): bool
    {
        $data ??= $this->store->load();
        foreach ($this->operationAlertNotificationTargets($alert, $config, $data, false) as $target) {
            if ($this->operationAlertNotificationTargetAllowed($alert, $target)) {
                return true;
            }
        }

        return false;
    }

    private function sendOperationAlertNotificationRecord(array &$alert, array $config, array &$data, bool $force = false): array
    {
        $now = date('Y-m-d H:i:s');
        $targets = $this->operationAlertNotificationTargets($alert, $config, $data, $force);
        if (empty($targets)) {
            return ['ok' => false, 'status' => 'skipped', 'message' => '没有匹配的预警外部通知接收人。'];
        }

        $alert['external_notify_attempt_count'] = max(0, (int) ($alert['external_notify_attempt_count'] ?? 0)) + 1;
        $alert['external_notify_last_attempt_at'] = $now;
        $alert['updated_at'] = $now;

        $sent = 0;
        $success = 0;
        $failed = 0;
        $skipped = 0;
        $messages = [];
        $endpoints = [];
        $queue = $targets;
        $sentTargetKeys = [];
        $failureEscalatedKeys = [];

        while (!empty($queue)) {
            $target = array_shift($queue);
            if (!is_array($target)) {
                continue;
            }
            $targetKey = $this->operationAlertNotificationTargetKey($target);
            if (isset($sentTargetKeys[$targetKey])) {
                continue;
            }
            $sentTargetKeys[$targetKey] = true;
            $endpoint = $this->operationAlertNotificationTargetEndpoint($target);
            $payload = $this->operationAlertNotificationPayload($alert, $target, $now);
            $log = $this->operationAlertNotificationLogFromAlert($alert, $target, $payload, $now);
            if ($endpoint !== '' && $endpoint !== '站内预警') {
                $endpoints[] = $endpoint;
            }
            if ($endpoint === '') {
                $status = 'skipped';
                $message = $this->operationAlertMissingEndpointMessage((string) ($target['channel'] ?? 'webhook'));
                $result = ['ok' => false, 'status' => 'skipped', 'message' => $message, 'attempted_at' => $now];
                $skipped++;
            } elseif (!$force && !$this->operationAlertNotificationTargetAllowed($alert, $target)) {
                $status = 'skipped';
                $message = '该预警不满足接收人发送范围。';
                $result = ['ok' => false, 'status' => 'skipped', 'message' => $message, 'attempted_at' => $now];
                $skipped++;
            } else {
                $result = $this->sendOperationAlertNotificationTarget($data, $target, $payload, $now);
                $resultStatus = (string) ($result['status'] ?? '');
                $status = in_array($resultStatus, ['success', 'failed', 'skipped'], true) ? $resultStatus : (!empty($result['ok']) ? 'success' : 'failed');
                $message = (string) ($result['message'] ?? (!empty($result['ok']) ? '预警通知发送成功。' : '预警通知发送失败。'));
                if ($status === 'success') {
                    $success++;
                } elseif ($status === 'skipped') {
                    $skipped++;
                } else {
                    $failed++;
                }
            }
            $sent++;
            if (count($messages) < 3) {
                $messages[] = (string) ($target['name'] ?? '接收人') . '/' . $this->operationAlertNotificationChannelLabel((string) ($target['channel'] ?? 'webhook')) . '：' . $message;
            }
            $log['status'] = $status;
            $log['message'] = $message;
            if (isset($result['provider_request_id']) && trim((string) $result['provider_request_id']) !== '') {
                $log['provider_request_id'] = $this->limitText(trim((string) $result['provider_request_id']), 120);
            }
            $log['response_payload'] = $result;
            $this->appendOperationAlertNotificationLog($data, $log);
            if ($status === 'failed') {
                $failureKey = (int) ($alert['id'] ?? 0) . '|' . (int) ($target['receiver_id'] ?? $target['id'] ?? 0) . '|' . (string) ($target['channel'] ?? 'webhook');
                if (!isset($failureEscalatedKeys[$failureKey])) {
                    $failureEscalatedKeys[$failureKey] = true;
                    foreach ($this->operationAlertFailureEscalationTargets($alert, $target, $config, $data) as $escalationTarget) {
                        $escalationKey = $this->operationAlertNotificationTargetKey($escalationTarget);
                        if (!isset($sentTargetKeys[$escalationKey])) {
                            $queue[] = $escalationTarget;
                        }
                    }
                }
            }
        }

        $status = $success > 0 ? 'success' : ($failed > 0 ? 'failed' : 'skipped');
        $message = '预警通知发送完成：接收人 ' . $sent . ' 个，成功 ' . $success . ' 个，失败 ' . $failed . ' 个，跳过 ' . $skipped . ' 个。' . (!empty($messages) ? ' ' . implode('；', $messages) : '');
        $alert['external_notify_status'] = $status;
        $alert['external_notify_message'] = $message;
        $alert['external_notify_endpoint'] = implode(',', array_values(array_unique(array_filter($endpoints, static fn (string $item): bool => $item !== ''))));
        $alert['external_notify_last_success_at'] = $success > 0 ? $now : (string) ($alert['external_notify_last_success_at'] ?? '');

        return [
            'ok' => $success > 0,
            'status' => $status,
            'message' => $message,
            'sent' => $sent,
            'success' => $success,
            'failed' => $failed,
            'skipped' => $skipped,
        ];
    }

    private function operationAlertNotificationPayload(array $alert, array $config, string $now): array
    {
        $title = $this->renderOperationAlertTemplate((string) ($config['title_template'] ?? '短剧投放预警：{{title}}'), $alert);
        $body = $this->renderOperationAlertTemplate((string) ($config['body_template'] ?? '{{message}}'), $alert);
        $channel = (string) ($config['channel'] ?? 'webhook');

        $base = [
            'event' => 'operation_alert',
            'channel' => $channel,
            'receiver' => [
                'id' => (int) ($config['receiver_id'] ?? 0),
                'name' => (string) ($config['name'] ?? $config['receiver_name'] ?? ''),
                'scope_type' => (string) ($config['scope_type'] ?? 'global'),
                'scope_role' => (string) ($config['scope_role'] ?? ''),
                'agent_id' => (int) ($config['agent_id'] ?? 0),
                'contact' => $this->operationAlertNotificationTargetEndpoint($config),
            ],
            'alert' => [
                'id' => (int) ($alert['id'] ?? 0),
                'fingerprint' => (string) ($alert['fingerprint'] ?? ''),
                'type' => (string) ($alert['type'] ?? 'operation_alert'),
                'status' => (string) ($alert['status'] ?? 'pending'),
                'priority' => (string) ($alert['priority'] ?? 'normal'),
                'title' => $title,
                'body' => $body,
                'message' => (string) ($alert['message'] ?? ''),
                'suggestion' => (string) ($alert['suggestion'] ?? ''),
                'first_seen_at' => (string) ($alert['first_seen_at'] ?? ''),
                'last_seen_at' => (string) ($alert['last_seen_at'] ?? ''),
                'occurrence_count' => max(1, (int) ($alert['occurrence_count'] ?? 1)),
            ],
            'attribution' => [
                'promotion_link_id' => (int) ($alert['promotion_link_id'] ?? 0),
                'promotion_code' => (string) ($alert['promotion_code'] ?? ''),
                'order_no' => (string) ($alert['order_no'] ?? ''),
                'agent_id' => (int) ($alert['agent_id'] ?? 0),
                'traffic_platform' => (string) ($alert['traffic_platform'] ?? ''),
                'channel_id' => (string) ($alert['channel_id'] ?? ''),
                'media_app_id' => (string) ($alert['media_app_id'] ?? ''),
                'ad_id' => (string) ($alert['ad_id'] ?? ''),
                'creative_id' => (string) ($alert['creative_id'] ?? ''),
                'material_id' => (string) ($alert['material_id'] ?? ''),
            ],
            'metrics' => (array) ($alert['metric_snapshot'] ?? []),
            'sent_at' => $now,
        ];

        if ($channel === 'wechat_work') {
            $content = '### ' . $title . "\n"
                . '> 优先级：' . (string) ($alert['priority'] ?? 'normal') . "\n"
                . '> 状态：' . (string) ($alert['status'] ?? 'pending') . "\n"
                . '> 推广码：' . ((string) ($alert['promotion_code'] ?? '') ?: '-') . "\n\n"
                . $body . "\n\n"
                . ((string) ($alert['suggestion'] ?? '') !== '' ? '建议：' . (string) ($alert['suggestion'] ?? '') : '');

            return [
                'msgtype' => 'markdown',
                'markdown' => ['content' => $this->limitText($content, 1800)],
                'jx_alert' => $base,
            ];
        }

        if ($channel === 'email') {
            return [
                'event' => 'operation_alert',
                'channel' => 'email',
                'to_email' => (string) ($config['email'] ?? ''),
                'subject' => $this->renderOperationAlertTemplate((string) ($config['email_subject_template'] ?? $config['title_template'] ?? '短剧投放预警：{{title}}'), $alert),
                'body' => $body . ((string) ($alert['suggestion'] ?? '') !== '' ? "\n\n处理建议：" . (string) ($alert['suggestion'] ?? '') : ''),
                'alert' => $base['alert'],
                'attribution' => $base['attribution'],
                'sent_at' => $now,
            ];
        }

        if ($channel === 'sms') {
            return [
                'event' => 'operation_alert',
                'channel' => 'sms',
                'phone' => (string) ($config['phone'] ?? ''),
                'message' => $this->renderOperationAlertTemplate((string) ($config['sms_template'] ?? '【{{priority}}】{{title}} {{message}}'), $alert),
                'alert' => $base['alert'],
                'attribution' => $base['attribution'],
                'sent_at' => $now,
            ];
        }

        if ($channel === 'in_app') {
            return [
                'event' => 'operation_alert',
                'channel' => 'in_app',
                'title' => $title,
                'body' => $body,
                'alert' => $base['alert'],
                'attribution' => $base['attribution'],
                'sent_at' => $now,
            ];
        }

        return $base;
    }

    private function operationAlertNotificationTargets(array $alert, array $config, array $data, bool $force = false): array
    {
        if (empty($config['enabled'])) {
            return [];
        }

        $configChannels = $this->operationAlertChannelsFromValue($config['channels'] ?? ($config['channel'] ?? []), ['webhook']);
        $receivers = array_values(array_filter((array) ($data['operation_alert_notification_receivers'] ?? []), static fn (array $receiver): bool => (string) ($receiver['status'] ?? 'active') === 'active'));
        if (empty($receivers)) {
            $receivers[] = [
                'id' => 0,
                'name' => '全局预警',
                'status' => 'active',
                'scope_type' => 'global',
                'scope_role' => '',
                'agent_id' => 0,
                'channels' => $configChannels,
                'webhook_url' => trim((string) ($config['webhook_url'] ?? $config['endpoint'] ?? '')),
                'secret' => (string) ($config['secret'] ?? ''),
                'wechat_work_url' => trim((string) ($config['wechat_work_url'] ?? '')),
                'wechat_work_secret' => (string) ($config['wechat_work_secret'] ?? ''),
                'wechat_work_signing_enabled' => !empty($config['wechat_work_signing_enabled']),
                'email' => (string) ($config['email'] ?? ''),
                'phone' => (string) ($config['phone'] ?? ''),
                'send_statuses' => (array) ($config['send_statuses'] ?? ['pending', 'processing']),
                'alert_types' => ['all'],
                'min_priority' => (string) ($config['min_priority'] ?? 'normal'),
                'retry_failed' => array_key_exists('retry_failed', $config) ? !empty($config['retry_failed']) : true,
                'title_template' => (string) ($config['title_template'] ?? '短剧投放预警：{{title}}'),
                'body_template' => (string) ($config['body_template'] ?? '{{message}}'),
                'email_subject_template' => (string) ($config['email_subject_template'] ?? $config['title_template'] ?? '短剧投放预警：{{title}}'),
                'sms_template' => (string) ($config['sms_template'] ?? '【{{priority}}】{{title}} {{message}}'),
            ];
        }

        $targets = [];
        $seenTargets = [];
        foreach ($receivers as $receiver) {
            $baseTarget = array_merge([
                'title_template' => (string) ($config['title_template'] ?? '短剧投放预警：{{title}}'),
                'body_template' => (string) ($config['body_template'] ?? '{{message}}'),
                'email_subject_template' => (string) ($config['email_subject_template'] ?? $config['title_template'] ?? '短剧投放预警：{{title}}'),
                'sms_template' => (string) ($config['sms_template'] ?? '【{{priority}}】{{title}} {{message}}'),
            ], $receiver);
            $baseTarget['receiver_id'] = (int) ($receiver['id'] ?? 0);
            if (!$this->operationAlertReceiverMatches($alert, $baseTarget, $data)) {
                continue;
            }
            $channels = $this->operationAlertChannelsFromValue($receiver['channels'] ?? ($receiver['channel'] ?? []), $configChannels);
            if (!empty($config['escalation_enabled']) && (string) ($alert['priority'] ?? 'normal') === 'urgent') {
                $channels = array_values(array_unique(array_merge($channels, $this->operationAlertChannelsFromValue($config['urgent_channels'] ?? [], []))));
            }
            foreach ($channels as $channel) {
                $target = $baseTarget;
                $target['channel'] = $channel;
                $target['channels'] = [$channel];
                if (!$force && !$this->operationAlertNotificationTargetAllowed($alert, $target)) {
                    continue;
                }
                if (!$force && $this->operationAlertNotificationAlreadySucceeded($alert, $target, $data)) {
                    continue;
                }
                $endpoint = $this->operationAlertNotificationTargetEndpoint($target);
                $targetKey = (int) ($target['receiver_id'] ?? 0) . '|' . $channel . '|' . $endpoint;
                if (isset($seenTargets[$targetKey])) {
                    continue;
                }
                $seenTargets[$targetKey] = true;
                $targets[] = $target;
            }
        }

        return $targets;
    }

    private function operationAlertNotificationTargetAllowed(array $alert, array $target): bool
    {
        if (empty($target['retry_failed']) && (string) ($alert['external_notify_status'] ?? '') === 'failed') {
            return false;
        }
        $statuses = array_values((array) ($target['send_statuses'] ?? ['pending', 'processing']));
        if (!in_array((string) ($alert['status'] ?? 'pending'), $statuses, true)) {
            return false;
        }
        $types = array_values((array) ($target['alert_types'] ?? ['all']));
        if (!in_array('all', $types, true) && !in_array((string) ($alert['type'] ?? 'operation_alert'), $types, true)) {
            return false;
        }

        $rank = ['low' => 0, 'normal' => 1, 'high' => 2, 'urgent' => 3];
        $priority = (string) ($alert['priority'] ?? 'normal');
        $minPriority = (string) ($target['min_priority'] ?? 'normal');

        return ($rank[$priority] ?? 1) >= ($rank[$minPriority] ?? 1);
    }

    private function operationAlertReceiverMatches(array $alert, array $receiver, array $data): bool
    {
        $scopeType = (string) ($receiver['scope_type'] ?? 'global');
        if ($scopeType === 'global') {
            return true;
        }

        $lineage = $this->operationAlertAgentLineage($alert, $data);
        if ($scopeType === 'role') {
            return match ((string) ($receiver['scope_role'] ?? '')) {
                'business' => (int) ($lineage['business_id'] ?? 0) > 0,
                'leader' => (int) ($lineage['leader_id'] ?? 0) > 0,
                'agent' => (int) ($lineage['agent_id'] ?? 0) > 0,
                default => false,
            };
        }
        if ($scopeType === 'agent') {
            $agentId = (int) ($receiver['agent_id'] ?? 0);
            return $agentId > 0 && in_array($agentId, [(int) ($lineage['agent_id'] ?? 0), (int) ($lineage['leader_id'] ?? 0), (int) ($lineage['business_id'] ?? 0)], true);
        }

        return false;
    }

    private function operationAlertAgentLineage(array $alert, array $data): array
    {
        $agentId = (int) ($alert['agent_id'] ?? 0);
        if ($agentId <= 0 && (int) ($alert['promotion_link_id'] ?? 0) > 0) {
            $agentId = $this->promotionLinkAgentId((int) ($alert['promotion_link_id'] ?? 0), $data);
        }
        if ($agentId <= 0 && trim((string) ($alert['order_no'] ?? '')) !== '') {
            foreach ((array) ($data['orders'] ?? []) as $order) {
                if ((string) ($order['order_no'] ?? '') !== (string) ($alert['order_no'] ?? '')) {
                    continue;
                }
                $agentId = (int) ($order['agent_id'] ?? 0);
                if ($agentId <= 0) {
                    $agentId = $this->promotionLinkAgentId((int) ($order['promotion_link_id'] ?? 0), $data);
                }
                break;
            }
        }
        if ($agentId <= 0) {
            return ['agent_id' => 0, 'leader_id' => 0, 'business_id' => 0];
        }

        return $this->agentTree((array) ($data['agents'] ?? []))[$agentId] ?? ['agent_id' => $agentId, 'leader_id' => 0, 'business_id' => 0];
    }

    private function operationAlertNotificationAlreadySucceeded(array $alert, array $target, array $data): bool
    {
        $receiverId = (int) ($target['receiver_id'] ?? $target['id'] ?? 0);
        $channel = (string) ($target['channel'] ?? 'webhook');
        foreach (array_reverse((array) ($data['operation_alert_notification_logs'] ?? [])) as $log) {
            if ((int) ($log['alert_id'] ?? 0) !== (int) ($alert['id'] ?? 0)) {
                continue;
            }
            if ((int) ($log['receiver_id'] ?? 0) !== $receiverId) {
                continue;
            }
            if ((string) ($log['channel'] ?? 'webhook') !== $channel) {
                continue;
            }

            return (string) ($log['status'] ?? '') === 'success';
        }

        return false;
    }

