    private function appendOperationAlertNotificationLog(array &$data, array $log): void
    {
        $data['operation_alert_notification_logs'] = array_values((array) ($data['operation_alert_notification_logs'] ?? []));
        $nextId = empty($data['operation_alert_notification_logs']) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $data['operation_alert_notification_logs'])) + 1);
        $log['id'] = $nextId;
        $data['operation_alert_notification_logs'][] = $log;
        $data['operation_alert_notification_logs'] = array_slice(array_values($data['operation_alert_notification_logs']), -5000);
    }

    private function sendCallbackLogRecord(array &$log, array $config, bool $force = false): array
    {
        if ((string) ($log['status'] ?? '') === 'success') {
            return ['ok' => true, 'status' => 'success', 'message' => '该记录已回传成功，无需重复发送。'];
        }

        $now = date('Y-m-d H:i:s');
        $retryPolicy = $this->normalizeCallbackRetryPolicy((array) ($config['retry_policy'] ?? []));
        $currentAttempts = max(0, (int) ($log['attempt_count'] ?? 0));
        if (!$force && (string) ($log['status'] ?? '') === 'failed') {
            if ($currentAttempts >= (int) $retryPolicy['max_attempts']) {
                $log['retry_blocked_reason'] = '已达到最大重试次数。';
                $log['updated_at'] = $now;

                return ['ok' => false, 'status' => 'skipped', 'message' => $log['retry_blocked_reason']];
            }
            $nextRetryAt = trim((string) ($log['next_retry_at'] ?? ''));
            if ($nextRetryAt !== '' && strtotime($nextRetryAt) !== false && strtotime($nextRetryAt) > time()) {
                $log['retry_blocked_reason'] = '未到下次重试时间。';
                $log['updated_at'] = $now;

                return ['ok' => false, 'status' => 'skipped', 'message' => $log['retry_blocked_reason']];
            }
        }
        $endpoint = trim((string) (($log['endpoint'] ?? '') ?: ($config['endpoint'] ?? '')));
        $enabled = array_key_exists('callback_enabled', $log)
            ? !empty($log['callback_enabled'])
            : (!empty($log['endpoint']) && (string) ($log['callback_policy_source'] ?? '') === 'app' ? true : !empty($config['enabled']));
        $log['attempt_count'] = $currentAttempts + 1;
        $log['last_attempt_at'] = $now;
        $log['updated_at'] = $now;
        $log['retry_blocked_reason'] = '';

        if (!$enabled || $endpoint === '') {
            $log['status'] = 'skipped';
            $log['message'] = '回传未启用或未配置地址，已跳过本次发送。';
            $log['endpoint'] = $endpoint;
            $log['next_retry_at'] = '';
            $log['response_payload'] = [
                'ok' => false,
                'message' => $log['message'],
                'attempted_at' => $now,
            ];

            return ['ok' => false, 'status' => 'skipped', 'message' => $log['message']];
        }

        $payload = is_array($log['request_payload'] ?? null) ? $log['request_payload'] : [];
        if (empty($payload)) {
            $payload = [
                'platform' => (string) ($config['platform'] ?? '巨量引擎'),
                'event' => (string) ($log['platform_event'] ?? ''),
                'event_type' => (string) ($log['event'] ?? ''),
                'promotion_code' => (string) ($log['code'] ?? ''),
                'promotion_link_id' => (int) ($log['promotion_link_id'] ?? 0),
                'user_id' => (int) ($log['user_id'] ?? 0),
                'order_no' => (string) ($log['order_no'] ?? ''),
                'amount' => round(max(0, (float) ($log['amount'] ?? 0)), 2),
                'timestamp' => (string) (($log['created_at'] ?? '') ?: $now),
            ] + $this->trafficMetaFromPayload($log);
            $payload = $this->callbackPayloadForTemplate($payload, (array) ($log['callback_field_mapping'] ?? $config['field_mapping'] ?? []));
            $log['request_payload'] = $payload;
        }

        $secret = (string) (($log['callback_secret'] ?? '') ?: ($config['secret'] ?? ''));
        $authConfig = $this->normalizeCallbackAuthConfig((array) ($log['callback_auth_config'] ?? $config['auth_config'] ?? []), $secret);
        $log['callback_auth_config'] = $this->callbackAuthConfigForLog($authConfig);
        $result = $this->performCallbackRequest($endpoint, $payload, $secret, $authConfig);
        if (is_array($result['request_payload'] ?? null)) {
            $log['request_payload'] = (array) $result['request_payload'];
        }
        $log['endpoint'] = $endpoint;
        $log['status'] = !empty($result['ok']) ? 'success' : 'failed';
        $log['message'] = (string) ($result['message'] ?? (!empty($result['ok']) ? '回传成功。' : '回传失败。'));
        $log['response_payload'] = $result;
        $log['next_retry_at'] = !empty($result['ok']) ? '' : $this->callbackNextRetryAt((int) $log['attempt_count'], $retryPolicy, time());
        if (!empty($result['ok'])) {
            $log['retry_blocked_reason'] = '';
        } elseif ((int) $log['attempt_count'] >= (int) $retryPolicy['max_attempts']) {
            $log['retry_blocked_reason'] = '已达到最大重试次数。';
            $log['next_retry_at'] = '';
        }
        $log['updated_at'] = date('Y-m-d H:i:s');

        return [
            'ok' => !empty($result['ok']),
            'status' => $log['status'],
            'message' => $log['message'],
            'response' => $result,
        ];
    }

    private function callbackPolicyForEvent(array $event, array $globalConfig): array
    {
        $trafficMeta = $this->trafficMetaFromPayload($event);
        $appKey = $this->normalizeAppKey((string) ($event['app_key'] ?? $trafficMeta['media_app_id'] ?? ''));
        $app = $appKey !== '' ? $this->appConfig($appKey) : null;
        $globalPolicy = [
            'enabled' => !empty($globalConfig['enabled']),
            'platform' => (string) ($globalConfig['platform'] ?? '巨量引擎'),
            'endpoint' => trim((string) ($globalConfig['endpoint'] ?? '')),
            'secret' => trim((string) ($globalConfig['secret'] ?? '')),
            'template_key' => (string) ($globalConfig['template_key'] ?? 'custom'),
            'template_name' => (string) ($globalConfig['template_name'] ?? '自定义模板'),
            'field_mapping' => (array) ($globalConfig['field_mapping'] ?? []),
            'auth_config' => $this->normalizeCallbackAuthConfig((array) ($globalConfig['auth_config'] ?? []), (string) ($globalConfig['secret'] ?? '')),
            'add_desktop_events' => array_values((array) ($globalConfig['add_desktop_events'] ?? ['active'])),
            'paid_events' => array_values((array) ($globalConfig['paid_events'] ?? ['pay'])),
            'fallback_time_match' => !empty($globalConfig['fallback_time_match']),
            'retry_failed' => true,
            'source' => 'global',
            'app_key' => $appKey,
            'app_name' => (string) ($app['name'] ?? ''),
        ];
        if (!is_array($app)) {
            return $globalPolicy;
        }

        $policy = (array) ($app['callback_policy'] ?? []);
        if (empty($policy['enabled']) && !empty($policy['use_global_fallback'])) {
            return array_merge($globalPolicy, [
                'app_key' => (string) ($app['app_key'] ?? $appKey),
                'app_name' => (string) ($app['name'] ?? ''),
            ]);
        }
        if (empty($policy['enabled'])) {
            return [
                'enabled' => false,
                'platform' => (string) (($policy['platform'] ?? '') ?: ($globalConfig['platform'] ?? '巨量引擎')),
                'endpoint' => trim((string) ($policy['endpoint'] ?? '')),
                'secret' => trim((string) ($policy['secret'] ?? '')),
                'template_key' => (string) ($policy['template_key'] ?? ($globalConfig['template_key'] ?? 'custom')),
                'template_name' => (string) ($policy['template_name'] ?? ($globalConfig['template_name'] ?? '自定义模板')),
                'field_mapping' => (array) ($policy['field_mapping'] ?? ($globalConfig['field_mapping'] ?? [])),
                'auth_config' => $this->normalizeCallbackAuthConfig((array) ($policy['auth_config'] ?? ($globalConfig['auth_config'] ?? [])), (string) (($policy['secret'] ?? '') ?: ($globalConfig['secret'] ?? ''))),
                'add_desktop_events' => array_values((array) ($policy['add_desktop_events'] ?? ['active'])),
                'paid_events' => array_values((array) ($policy['paid_events'] ?? ['pay'])),
                'fallback_time_match' => !empty($policy['fallback_time_match']),
                'retry_failed' => !empty($policy['retry_failed']),
                'source' => 'app',
                'app_key' => (string) ($app['app_key'] ?? $appKey),
                'app_name' => (string) ($app['name'] ?? ''),
            ];
        }

        return [
            'enabled' => true,
            'platform' => (string) (($policy['platform'] ?? '') ?: ($globalConfig['platform'] ?? '巨量引擎')),
            'endpoint' => trim((string) (($policy['endpoint'] ?? '') ?: ($globalConfig['endpoint'] ?? ''))),
            'secret' => trim((string) (($policy['secret'] ?? '') ?: ($globalConfig['secret'] ?? ''))),
            'template_key' => (string) ($policy['template_key'] ?? ($globalConfig['template_key'] ?? 'custom')),
            'template_name' => (string) ($policy['template_name'] ?? ($globalConfig['template_name'] ?? '自定义模板')),
            'field_mapping' => (array) ($policy['field_mapping'] ?? ($globalConfig['field_mapping'] ?? [])),
            'auth_config' => $this->normalizeCallbackAuthConfig((array) ($policy['auth_config'] ?? ($globalConfig['auth_config'] ?? [])), (string) (($policy['secret'] ?? '') ?: ($globalConfig['secret'] ?? ''))),
            'add_desktop_events' => array_values((array) ($policy['add_desktop_events'] ?? ($globalConfig['add_desktop_events'] ?? ['active']))),
            'paid_events' => array_values((array) ($policy['paid_events'] ?? ($globalConfig['paid_events'] ?? ['pay']))),
            'fallback_time_match' => array_key_exists('fallback_time_match', $policy) ? !empty($policy['fallback_time_match']) : !empty($globalConfig['fallback_time_match']),
            'retry_failed' => array_key_exists('retry_failed', $policy) ? !empty($policy['retry_failed']) : true,
            'source' => 'app',
            'app_key' => (string) ($app['app_key'] ?? $appKey),
            'app_name' => (string) ($app['name'] ?? ''),
        ];
    }

