    private function callbackFieldMappingFromPayload(array $payload, array $fallback = []): array
    {
        $raw = trim((string) ($payload['field_mapping_text'] ?? ''));
        if ($raw !== '') {
            $decoded = json_decode($raw, true);
            if (is_array($decoded)) {
                return $this->normalizeCallbackFieldMapping($decoded);
            }
        }

        return $this->normalizeCallbackFieldMapping($fallback);
    }

    private function callbackAuthConfigFromPayload(array $payload, array $fallback = [], string $secret = ''): array
    {
        $mode = (string) ($payload['auth_mode'] ?? ($fallback['mode'] ?? 'hmac_header'));
        $config = [
            'mode' => $mode,
            'secret' => array_key_exists('auth_secret', $payload) ? trim((string) $payload['auth_secret']) : (string) ($fallback['secret'] ?? $secret),
            'token' => array_key_exists('auth_token', $payload) ? trim((string) $payload['auth_token']) : (string) ($fallback['token'] ?? ''),
            'algorithm' => (string) ($payload['auth_algorithm'] ?? ($fallback['algorithm'] ?? 'sha256')),
            'header_name' => (string) ($payload['auth_header_name'] ?? ($fallback['header_name'] ?? 'X-JX-Signature')),
            'token_header_name' => (string) ($payload['auth_token_header_name'] ?? ($fallback['token_header_name'] ?? 'Authorization')),
            'query_key' => (string) ($payload['auth_query_key'] ?? ($fallback['query_key'] ?? 'sign')),
            'body_key' => (string) ($payload['auth_body_key'] ?? ($fallback['body_key'] ?? 'sign')),
            'timestamp_key' => (string) ($payload['auth_timestamp_key'] ?? ($fallback['timestamp_key'] ?? 'timestamp')),
            'include_timestamp' => array_key_exists('auth_include_timestamp', $payload) ? !empty($payload['auth_include_timestamp']) : !empty($fallback['include_timestamp']),
            'sign_source' => (string) ($payload['auth_sign_source'] ?? ($fallback['sign_source'] ?? 'body')),
        ];

        return $this->normalizeCallbackAuthConfig($config, $secret);
    }

    private function normalizeCallbackAuthConfig(array $config, string $secret = ''): array
    {
        $mode = (string) ($config['mode'] ?? 'none');
        $mode = in_array($mode, ['none', 'hmac_header', 'bearer', 'query_sign', 'body_sign'], true) ? $mode : 'none';
        $algorithm = strtolower((string) ($config['algorithm'] ?? 'sha256'));
        $algorithm = in_array($algorithm, hash_hmac_algos(), true) ? $algorithm : 'sha256';
        $headerName = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($config['header_name'] ?? 'X-JX-Signature'))) ?: 'X-JX-Signature';
        $tokenHeaderName = preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($config['token_header_name'] ?? 'Authorization'))) ?: 'Authorization';
        $queryKey = preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim((string) ($config['query_key'] ?? 'sign'))) ?: 'sign';
        $bodyKey = preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim((string) ($config['body_key'] ?? 'sign'))) ?: 'sign';
        $timestampKey = preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim((string) ($config['timestamp_key'] ?? 'timestamp'))) ?: 'timestamp';
        $signSource = (string) ($config['sign_source'] ?? 'body');
        $signSource = in_array($signSource, ['body', 'query', 'body_with_timestamp'], true) ? $signSource : 'body';
        $authSecret = trim((string) ($config['secret'] ?? ''));
        if ($authSecret === '') {
            $authSecret = trim($secret);
        }

        return [
            'mode' => $mode,
            'secret' => $authSecret,
            'token' => trim((string) ($config['token'] ?? '')),
            'algorithm' => $algorithm,
            'header_name' => $headerName,
            'token_header_name' => $tokenHeaderName,
            'query_key' => $queryKey,
            'body_key' => $bodyKey,
            'timestamp_key' => $timestampKey,
            'include_timestamp' => !empty($config['include_timestamp']),
            'sign_source' => $signSource,
        ];
    }

    private function callbackRetryPolicyFromPayload(array $payload, array $fallback = []): array
    {
        return $this->normalizeCallbackRetryPolicy([
            'max_attempts' => $payload['retry_max_attempts'] ?? ($fallback['max_attempts'] ?? 5),
            'base_interval_minutes' => $payload['retry_base_interval_minutes'] ?? ($fallback['base_interval_minutes'] ?? 5),
            'max_interval_minutes' => $payload['retry_max_interval_minutes'] ?? ($fallback['max_interval_minutes'] ?? 120),
            'backoff' => array_key_exists('retry_backoff', $payload) ? !empty($payload['retry_backoff']) : (!array_key_exists('backoff', $fallback) || !empty($fallback['backoff'])),
        ]);
    }

    private function normalizeCallbackRetryPolicy(array $policy): array
    {
        $maxAttempts = max(1, min(20, (int) ($policy['max_attempts'] ?? 5)));
        $baseInterval = max(1, min(1440, (int) ($policy['base_interval_minutes'] ?? 5)));
        $maxInterval = max($baseInterval, min(1440, (int) ($policy['max_interval_minutes'] ?? 120)));

        return [
            'max_attempts' => $maxAttempts,
            'base_interval_minutes' => $baseInterval,
            'max_interval_minutes' => $maxInterval,
            'backoff' => array_key_exists('backoff', $policy) ? !empty($policy['backoff']) : true,
        ];
    }

    private function callbackNextRetryAt(int $attemptCount, array $policy, ?int $baseTime = null): string
    {
        $policy = $this->normalizeCallbackRetryPolicy($policy);
        $interval = (int) $policy['base_interval_minutes'];
        if (!empty($policy['backoff'])) {
            $interval *= max(1, 2 ** max(0, $attemptCount - 1));
        }
        $interval = min((int) $policy['max_interval_minutes'], $interval);
        $baseTime ??= time();

        return date('Y-m-d H:i:s', $baseTime + ($interval * 60));
    }

    private function callbackAuthConfigForLog(array $config): array
    {
        $copy = $config;
        if ((string) ($copy['secret'] ?? '') !== '') {
            $copy['secret_saved'] = true;
            $copy['secret'] = '';
        }
        if ((string) ($copy['token'] ?? '') !== '') {
            $copy['token_saved'] = true;
            $copy['token'] = '';
        }

        return $copy;
    }

    private function callbackRequestWithAuth(string $endpoint, array $payload, string $secret = '', array $authConfig = []): array
    {
        $headers = [
            'Content-Type: application/json; charset=utf-8',
            'Accept: application/json',
            'User-Agent: JXDrama-Callback/1.0',
        ];
        $auth = $this->normalizeCallbackAuthConfig($authConfig, $secret);
        $mode = (string) ($auth['mode'] ?? 'none');
        if ($mode === 'none') {
            return ['ok' => true, 'endpoint' => $endpoint, 'payload' => $payload, 'headers' => $headers, 'auth_mode' => $mode];
        }

        $timestamp = (string) time();
        if (!empty($auth['include_timestamp'])) {
            $payload[(string) $auth['timestamp_key']] = $timestamp;
        }

        $signingPayload = $payload;
        if ((string) ($auth['sign_source'] ?? 'body') === 'body_with_timestamp') {
            $signingPayload[(string) $auth['timestamp_key']] = $timestamp;
        }
        $body = json_encode($signingPayload, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
        if ($body === false) {
            return ['ok' => false, 'message' => '回传签名内容编码失败。'];
        }
        $secretValue = (string) ($auth['secret'] ?? '');
        $signature = $secretValue !== '' ? hash_hmac((string) $auth['algorithm'], $body, $secretValue) : '';

        if ($mode === 'hmac_header') {
            if ($signature !== '') {
                $headers[] = (string) $auth['header_name'] . ': ' . $signature;
            }
            return ['ok' => true, 'endpoint' => $endpoint, 'payload' => $payload, 'headers' => $headers, 'auth_mode' => $mode];
        }

        if ($mode === 'bearer') {
            $token = (string) ($auth['token'] ?? '');
            if ($token === '') {
                return ['ok' => false, 'message' => 'Bearer Token 未配置。'];
            }
            $headers[] = (string) $auth['token_header_name'] . ': Bearer ' . $token;
            return ['ok' => true, 'endpoint' => $endpoint, 'payload' => $payload, 'headers' => $headers, 'auth_mode' => $mode];
        }

        if ($mode === 'query_sign') {
            if ($signature === '') {
                return ['ok' => false, 'message' => 'Query 签名密钥未配置。'];
            }
            $separator = str_contains($endpoint, '?') ? '&' : '?';
            $endpoint .= $separator . rawurlencode((string) $auth['query_key']) . '=' . rawurlencode($signature);
            if (!empty($auth['include_timestamp'])) {
                $endpoint .= '&' . rawurlencode((string) $auth['timestamp_key']) . '=' . rawurlencode($timestamp);
            }
            return ['ok' => true, 'endpoint' => $endpoint, 'payload' => $payload, 'headers' => $headers, 'auth_mode' => $mode];
        }

        if ($mode === 'body_sign') {
            if ($signature === '') {
                return ['ok' => false, 'message' => 'Body 签名密钥未配置。'];
            }
            $payload[(string) $auth['body_key']] = $signature;
            return ['ok' => true, 'endpoint' => $endpoint, 'payload' => $payload, 'headers' => $headers, 'auth_mode' => $mode];
        }

        return ['ok' => true, 'endpoint' => $endpoint, 'payload' => $payload, 'headers' => $headers, 'auth_mode' => $mode];
    }

    private function normalizeCallbackFieldMapping(array $mapping): array
    {
        $normalized = [];
        foreach ($mapping as $target => $source) {
            $targetKey = preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim((string) $target)) ?: '';
            $sourceKey = preg_replace('/[^a-zA-Z0-9_.-]+/', '', trim((string) $source)) ?: '';
            if ($targetKey === '' || $sourceKey === '') {
                continue;
            }
            $normalized[$targetKey] = $sourceKey;
        }

        return array_slice($normalized, 0, 40, true);
    }

    private function callbackPayloadForTemplate(array $payload, array $mapping): array
    {
        $mapping = $this->normalizeCallbackFieldMapping($mapping);
        if (empty($mapping)) {
            return $payload;
        }

        $mapped = [
            'platform' => (string) ($payload['platform'] ?? ''),
            'event' => (string) ($payload['event'] ?? ''),
        ];
        foreach ($mapping as $targetKey => $sourceKey) {
            $mapped[$targetKey] = $payload[$sourceKey] ?? '';
        }
        $mapped['_raw'] = $payload;

        return $mapped;
    }

    private function performCallbackRequest(string $endpoint, array $payload, string $secret = '', array $authConfig = []): array
    {
        $request = $this->callbackRequestWithAuth($endpoint, $payload, $secret, $authConfig);
        if (empty($request['ok'])) {
            return ['ok' => false, 'message' => (string) ($request['message'] ?? '回传鉴权配置无效。')];
        }

        $endpoint = (string) $request['endpoint'];
        $payload = (array) $request['payload'];
        $headers = (array) $request['headers'];
        $body = json_encode($payload, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
        if ($body === false) {
            return ['ok' => false, 'message' => '请求内容编码失败。'];
        }

        if (str_starts_with($endpoint, 'mock://processing') || str_starts_with($endpoint, 'mock://success-processing')) {
            return [
                'ok' => true,
                'http_status' => 200,
                'message' => '模拟平台受理中。',
                'body' => ['success' => true, 'code' => 0, 'message' => 'mock processing', 'request_id' => 'mock-request', 'status' => 'processing'],
                'request_payload' => $payload,
                'auth_mode' => (string) ($request['auth_mode'] ?? 'none'),
            ];
        }

        if (str_starts_with($endpoint, 'mock://refresh-success')) {
            return [
                'ok' => true,
                'http_status' => 200,
                'message' => '模拟 token 刷新成功。',
                'body' => ['success' => true, 'code' => 0, 'message' => 'refresh ok', 'access_token' => 'mock-refreshed-token', 'refresh_token' => 'mock-refresh-token-new', 'expires_in' => 7200],
                'request_payload' => $payload,
                'auth_mode' => (string) ($request['auth_mode'] ?? 'none'),
            ];
        }

        if (str_starts_with($endpoint, 'mock://refresh-fail')) {
            return [
                'ok' => false,
                'http_status' => 401,
                'message' => '模拟 token 刷新失败。',
                'body' => ['success' => false, 'code' => 401, 'message' => 'refresh fail'],
                'request_payload' => $payload,
                'auth_mode' => (string) ($request['auth_mode'] ?? 'none'),
            ];
        }

        if (str_starts_with($endpoint, 'mock://auth-fail') || str_starts_with($endpoint, 'mock://query-auth-fail')) {
            return [
                'ok' => false,
                'http_status' => 401,
                'message' => '模拟平台授权失败。',
                'body' => ['success' => false, 'code' => 401, 'message' => 'invalid access_token', 'request_id' => 'mock-request', 'status' => 'failed'],
                'request_payload' => $payload,
                'auth_mode' => (string) ($request['auth_mode'] ?? 'none'),
            ];
        }

        if (str_starts_with($endpoint, 'mock://rate-limit') || str_starts_with($endpoint, 'mock://query-rate-limit')) {
            return [
                'ok' => false,
                'http_status' => 429,
                'message' => '模拟平台限流。',
                'body' => ['success' => false, 'code' => 429, 'message' => 'too many requests rate limited', 'request_id' => 'mock-request', 'status' => 'failed'],
                'request_payload' => $payload,
                'auth_mode' => (string) ($request['auth_mode'] ?? 'none'),
            ];
        }

        if (str_starts_with($endpoint, 'mock://query-processing')) {
            return [
                'ok' => true,
                'http_status' => 200,
                'message' => '模拟平台回查处理中。',
                'body' => ['success' => true, 'code' => 0, 'message' => 'mock still processing', 'request_id' => (string) ($payload['request_id'] ?? $payload['platform_request_id'] ?? 'mock-request'), 'status' => 'processing'],
                'request_payload' => $payload,
                'auth_mode' => (string) ($request['auth_mode'] ?? 'none'),
            ];
        }

        if (str_starts_with($endpoint, 'mock://query-fail')) {
            return [
                'ok' => true,
                'http_status' => 200,
                'message' => '模拟平台回查失败。',
                'body' => ['success' => true, 'code' => 0, 'message' => 'mock platform failed', 'request_id' => (string) ($payload['request_id'] ?? $payload['platform_request_id'] ?? 'mock-request'), 'status' => 'failed'],
                'request_payload' => $payload,
                'auth_mode' => (string) ($request['auth_mode'] ?? 'none'),
            ];
        }

        if (str_starts_with($endpoint, 'mock://query-success')) {
            return [
                'ok' => true,
                'http_status' => 200,
                'message' => '模拟平台回查成功。',
                'body' => ['success' => true, 'code' => 0, 'message' => 'mock query ok', 'request_id' => (string) ($payload['request_id'] ?? $payload['platform_request_id'] ?? 'mock-request'), 'status' => 'paused'],
                'request_payload' => $payload,
                'auth_mode' => (string) ($request['auth_mode'] ?? 'none'),
            ];
        }

        if (str_starts_with($endpoint, 'mock://success')) {
            return [
                'ok' => true,
                'http_status' => 200,
                'message' => '模拟回传成功。',
                'body' => ['success' => true, 'code' => 0, 'message' => 'mock ok', 'request_id' => 'mock-request', 'status' => 'paused'],
                'request_payload' => $payload,
                'auth_mode' => (string) ($request['auth_mode'] ?? 'none'),
            ];
        }

        if (str_starts_with($endpoint, 'mock://fail')) {
            return [
                'ok' => false,
                'http_status' => 500,
                'message' => '模拟回传失败。',
                'body' => ['success' => false, 'code' => 500, 'message' => 'mock fail', 'request_id' => 'mock-request', 'status' => 'failed'],
                'request_payload' => $payload,
                'auth_mode' => (string) ($request['auth_mode'] ?? 'none'),
            ];
        }

        if (preg_match('#^https?://#i', $endpoint) !== 1) {
            return ['ok' => false, 'message' => '回传地址仅支持 HTTP/HTTPS。'];
        }

        if (function_exists('curl_init')) {
            $ch = curl_init($endpoint);
            curl_setopt_array($ch, [
                CURLOPT_POST => true,
                CURLOPT_POSTFIELDS => $body,
                CURLOPT_HTTPHEADER => $headers,
                CURLOPT_RETURNTRANSFER => true,
                CURLOPT_CONNECTTIMEOUT => 5,
                CURLOPT_TIMEOUT => 8,
                CURLOPT_FOLLOWLOCATION => false,
            ]);
            $raw = curl_exec($ch);
            $error = curl_error($ch);
            $httpStatus = (int) curl_getinfo($ch, CURLINFO_RESPONSE_CODE);
            curl_close($ch);

            return $this->formatCallbackResponse($raw === false ? '' : (string) $raw, $httpStatus, $error) + [
                'request_payload' => $payload,
                'auth_mode' => (string) ($request['auth_mode'] ?? 'none'),
            ];
        }

        $context = stream_context_create([
            'http' => [
                'method' => 'POST',
                'header' => implode("\r\n", $headers),
                'content' => $body,
                'timeout' => 8,
                'ignore_errors' => true,
            ],
        ]);
        $raw = @file_get_contents($endpoint, false, $context);
        $httpStatus = 0;
        foreach (($http_response_header ?? []) as $header) {
            if (preg_match('#^HTTP/\S+\s+(\d+)#', (string) $header, $matches) === 1) {
                $httpStatus = (int) $matches[1];
                break;
            }
        }

        return $this->formatCallbackResponse($raw === false ? '' : (string) $raw, $httpStatus, $raw === false ? '请求失败或超时。' : '') + [
            'request_payload' => $payload,
            'auth_mode' => (string) ($request['auth_mode'] ?? 'none'),
        ];
    }

    private function formatCallbackResponse(string $raw, int $httpStatus, string $error = ''): array
    {
        $decoded = null;
        if ($raw !== '') {
            $json = json_decode($raw, true);
            $decoded = json_last_error() === JSON_ERROR_NONE ? $json : $this->limitText($raw, 500);
        }

        $ok = $httpStatus >= 200 && $httpStatus < 300 && $error === '';
        $message = $ok ? '回传成功，HTTP ' . $httpStatus . '。' : '回传失败，HTTP ' . ($httpStatus ?: '无响应') . ($error !== '' ? '，' . $error : '') . '。';

        return [
            'ok' => $ok,
            'http_status' => $httpStatus,
            'message' => $message,
            'body' => $decoded,
        ];
    }

    private function syncRechargeLegacyPackages(array &$data): void
    {
        $products = array_values((array) ($data['recharge_products'] ?? []));
        $coinPackages = [];
        $vipPlans = [];
        foreach ($products as $product) {
            if (empty($product['enabled'])) {
                continue;
            }
            if ((string) ($product['type'] ?? '') === 'coin') {
                $coinPackages[] = [
                    'code' => (string) ($product['code'] ?? ''),
                    'name' => (string) ($product['name'] ?? 'K币套餐'),
                    'coins' => max(0, (int) ($product['coins'] ?? 0)),
                    'bonus_coins' => max(0, (int) ($product['bonus_coins'] ?? 0)),
                    'price' => round(max(0, (float) ($product['price'] ?? 0)), 2),
                    'badge' => (string) ($product['badge'] ?? ''),
                    'enabled' => true,
                ];
            }
            if ((string) ($product['type'] ?? '') === 'vip') {
                $vipPlans[] = [
                    'code' => (string) ($product['code'] ?? ''),
                    'name' => (string) ($product['name'] ?? 'VIP 套餐'),
                    'days' => max(1, (int) ($product['vip_days'] ?? 30)),
                    'price' => round(max(0, (float) ($product['price'] ?? 0)), 2),
                    'badge' => (string) (($product['badge'] ?? '') ?: ($product['description'] ?? '畅看权益')),
                    'enabled' => true,
                ];
            }
        }
        if (!empty($coinPackages)) {
            $data['coin_packages'] = $coinPackages;
        }
        if (!empty($vipPlans)) {
            $data['vip_plans'] = $vipPlans;
        }
    }

    private function agentScopeIds(array $agents, string $role, int $agentId): array
    {
        if (in_array($role, ['super_admin', 'editor'], true) || $agentId <= 0) {
            return [];
        }

        $children = [];
        foreach ($agents as $agent) {
            $parentId = (int) ($agent['parent_id'] ?? 0);
            if ($parentId > 0) {
                $children[$parentId][] = (int) ($agent['id'] ?? 0);
            }
        }

        $ids = [];
        $queue = [$agentId];
        while (!empty($queue)) {
            $id = (int) array_shift($queue);
            if ($id <= 0 || isset($ids[$id])) {
                continue;
            }
            $ids[$id] = true;
            foreach ((array) ($children[$id] ?? []) as $childId) {
                $queue[] = (int) $childId;
            }
        }

        return array_keys($ids);
    }

    private function scopeDashboardData(array $data, array $scope): array
    {
        if (empty($scope['restricted'])) {
            return $data;
        }

        $agentIds = array_fill_keys(array_map('intval', (array) ($scope['agent_ids'] ?? [])), true);
        if (empty($agentIds)) {
                foreach (['promotion_links', 'promotion_events', 'promotion_costs', 'agent_settlements', 'agent_settlement_notification_logs', 'agent_payout_batches', 'callback_logs', 'content_events', 'content_comments', 'feedback_items', 'operation_alert_notifications', 'operation_alert_notification_logs', 'promotion_stop_tasks', 'analytics_review_tasks', 'landing_pages', 'landing_page_events', 'ad_slots', 'ad_events', 'orders', 'order_action_logs', 'entitlements', 'coin_transactions', 'redeem_code_logs', 'activity_participation_logs', 'watch_history', 'followed_dramas', 'users'] as $key) {
                $data[$key] = [];
            }
            $data['agents'] = [];

            return $data;
        }

        $visibleLinks = [];
        $visibleLinkIds = [];
        foreach ((array) ($data['promotion_links'] ?? []) as $link) {
            if (!isset($agentIds[(int) ($link['agent_id'] ?? 0)])) {
                continue;
            }
            $visibleLinks[] = $link;
            $visibleLinkIds[(int) ($link['id'] ?? 0)] = true;
        }
        $data['promotion_links'] = $visibleLinks;

        $data['promotion_events'] = array_values(array_filter((array) ($data['promotion_events'] ?? []), static fn (array $event): bool => isset($visibleLinkIds[(int) ($event['promotion_link_id'] ?? 0)])));
        $data['promotion_costs'] = array_values(array_filter((array) ($data['promotion_costs'] ?? []), static fn (array $cost): bool => isset($agentIds[(int) ($cost['agent_id'] ?? 0)]) || isset($visibleLinkIds[(int) ($cost['promotion_link_id'] ?? 0)])));
        $data['callback_logs'] = array_values(array_filter((array) ($data['callback_logs'] ?? []), static fn (array $log): bool => isset($visibleLinkIds[(int) ($log['promotion_link_id'] ?? 0)])));
        $data['content_events'] = array_values(array_filter((array) ($data['content_events'] ?? []), static fn (array $event): bool => isset($visibleLinkIds[(int) ($event['promotion_link_id'] ?? 0)])));
        $visibleLandingPageIds = [];
        $data['landing_pages'] = array_values(array_filter((array) ($data['landing_pages'] ?? []), static function (array $page) use ($agentIds, $visibleLinkIds, &$visibleLandingPageIds): bool {
            $visible = isset($agentIds[(int) ($page['agent_id'] ?? 0)])
                || isset($visibleLinkIds[(int) ($page['promotion_link_id'] ?? 0)]);
            if ($visible) {
                $visibleLandingPageIds[(int) ($page['id'] ?? 0)] = true;
            }

            return $visible;
        }));
        $data['landing_page_events'] = array_values(array_filter((array) ($data['landing_page_events'] ?? []), static fn (array $event): bool => isset($visibleLandingPageIds[(int) ($event['landing_page_id'] ?? 0)])));

        $visibleOrderNos = [];
        $visibleUserIds = [];
        $orders = [];
        foreach ((array) ($data['orders'] ?? []) as $order) {
            $orderAgentId = (int) ($order['agent_id'] ?? 0);
            if (!isset($agentIds[$orderAgentId]) && !isset($visibleLinkIds[(int) ($order['promotion_link_id'] ?? 0)])) {
                continue;
            }
            $orders[] = $order;
            $visibleOrderNos[(string) ($order['order_no'] ?? '')] = true;
            $visibleUserIds[(int) ($order['user_id'] ?? 0)] = true;
        }
        foreach ($data['promotion_events'] as $event) {
            $visibleUserIds[(int) ($event['user_id'] ?? 0)] = true;
            $orderNo = trim((string) ($event['order_no'] ?? ''));
            if ($orderNo !== '') {
                $visibleOrderNos[$orderNo] = true;
            }
        }

        $data['orders'] = $orders;
        $data['feedback_items'] = array_values(array_filter((array) ($data['feedback_items'] ?? []), static function (array $item) use ($visibleLinkIds, $visibleOrderNos, &$visibleUserIds): bool {
            $visible = isset($visibleLinkIds[(int) ($item['promotion_link_id'] ?? 0)])
                || isset($visibleOrderNos[(string) ($item['order_no'] ?? '')]);
            if ($visible) {
                $visibleUserIds[(int) ($item['user_id'] ?? 0)] = true;
            }

            return $visible;
        }));
        $data['content_comments'] = array_values(array_filter((array) ($data['content_comments'] ?? []), static function (array $item) use ($visibleLinkIds, &$visibleUserIds): bool {
            $visible = isset($visibleLinkIds[(int) ($item['promotion_link_id'] ?? 0)]);
            $userId = (int) ($item['user_id'] ?? 0);
            if ($visible || ($userId > 0 && isset($visibleUserIds[$userId]))) {
                if ($userId > 0) {
                    $visibleUserIds[$userId] = true;
                }
                return true;
            }

            return false;
        }));
        $data['operation_alert_notifications'] = array_values(array_filter((array) ($data['operation_alert_notifications'] ?? []), static fn (array $item): bool => isset($visibleLinkIds[(int) ($item['promotion_link_id'] ?? 0)]) || isset($visibleOrderNos[(string) ($item['order_no'] ?? '')])));
        $data['operation_alert_notification_logs'] = array_values(array_filter((array) ($data['operation_alert_notification_logs'] ?? []), static fn (array $item): bool => isset($visibleLinkIds[(int) ($item['promotion_link_id'] ?? 0)]) || isset($visibleOrderNos[(string) ($item['order_no'] ?? '')])));
        $data['promotion_stop_tasks'] = array_values(array_filter((array) ($data['promotion_stop_tasks'] ?? []), static fn (array $item): bool => isset($visibleLinkIds[(int) ($item['promotion_link_id'] ?? 0)])));
        $currentAdminId = (int) ($_SESSION['admin_id'] ?? 0);
        $data['analytics_review_tasks'] = array_values(array_filter((array) ($data['analytics_review_tasks'] ?? []), static fn (array $item): bool => isset($visibleLinkIds[(int) ($item['promotion_link_id'] ?? 0)]) || ((int) ($item['promotion_link_id'] ?? 0) === 0 && (int) ($item['created_by_admin_id'] ?? 0) === $currentAdminId)));
        $data['order_action_logs'] = array_values(array_filter((array) ($data['order_action_logs'] ?? []), static fn (array $log): bool => isset($visibleOrderNos[(string) ($log['order_no'] ?? '')])));
        $data['users'] = array_values(array_filter((array) ($data['users'] ?? []), static fn (array $user): bool => isset($visibleUserIds[(int) ($user['id'] ?? 0)])));
        $data['entitlements'] = array_values(array_filter((array) ($data['entitlements'] ?? []), static fn (array $item): bool => isset($visibleUserIds[(int) ($item['user_id'] ?? 0)])));
        $data['coin_transactions'] = array_values(array_filter((array) ($data['coin_transactions'] ?? []), static fn (array $item): bool => isset($visibleUserIds[(int) ($item['user_id'] ?? 0)])));
        $data['redeem_code_logs'] = array_values(array_filter((array) ($data['redeem_code_logs'] ?? []), static fn (array $item): bool => isset($visibleUserIds[(int) ($item['user_id'] ?? 0)])));
        $data['activity_participation_logs'] = array_values(array_filter((array) ($data['activity_participation_logs'] ?? []), static fn (array $item): bool => isset($visibleUserIds[(int) ($item['user_id'] ?? 0)])));
        $data['watch_history'] = array_values(array_filter((array) ($data['watch_history'] ?? []), static fn (array $item): bool => isset($visibleUserIds[(int) ($item['user_id'] ?? 0)])));
        $data['followed_dramas'] = array_values(array_filter((array) ($data['followed_dramas'] ?? []), static fn (array $item): bool => isset($visibleUserIds[(int) ($item['user_id'] ?? 0)])));
        $data['agent_settlements'] = array_values(array_filter((array) ($data['agent_settlements'] ?? []), static fn (array $item): bool => isset($agentIds[(int) ($item['agent_id'] ?? 0)]) || isset($agentIds[(int) ($item['leader_id'] ?? 0)]) || isset($agentIds[(int) ($item['business_id'] ?? 0)])));
        $visibleSettlementIds = array_fill_keys(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $data['agent_settlements']), true);
        $data['agent_payout_batches'] = array_values(array_filter((array) ($data['agent_payout_batches'] ?? []), static function (array $batch) use ($agentIds, $visibleSettlementIds): bool {
            foreach ((array) ($batch['agent_ids'] ?? []) as $agentId) {
                if (isset($agentIds[(int) $agentId])) {
                    return true;
                }
            }
            foreach ((array) ($batch['settlement_ids'] ?? []) as $settlementId) {
                if (isset($visibleSettlementIds[(int) $settlementId])) {
                    return true;
                }
            }

            return false;
        }));
        $data['agent_settlement_notification_logs'] = array_values(array_filter((array) ($data['agent_settlement_notification_logs'] ?? []), static fn (array $item): bool => isset($agentIds[(int) ($item['agent_id'] ?? 0)]) || isset($agentIds[(int) ($item['leader_id'] ?? 0)]) || isset($agentIds[(int) ($item['business_id'] ?? 0)])));
        $data['agents'] = array_values(array_filter((array) ($data['agents'] ?? []), static fn (array $agent): bool => isset($agentIds[(int) ($agent['id'] ?? 0)])));
        $data['ad_slots'] = [];
        $data['ad_events'] = [];

        return $data;
    }

    private function analyticsFiltersFromRequest(array $query): array
    {
        $range = $this->analyticsDateRangeFromRequest($query);
        $filters = [
            'date_preset' => (string) ($range['preset'] ?? 'all'),
            'date_start' => (string) ($range['start'] ?? ''),
            'date_end' => (string) ($range['end'] ?? ''),
            'date_label' => (string) ($range['label'] ?? '全部时间'),
            'app_key' => $this->normalizeAppKey((string) ($query['analytics_app_key'] ?? '')),
            'business_id' => max(0, (int) ($query['analytics_business_id'] ?? 0)),
            'leader_id' => max(0, (int) ($query['analytics_leader_id'] ?? 0)),
            'agent_id' => max(0, (int) ($query['analytics_agent_id'] ?? 0)),
            'promotion_link_id' => max(0, (int) ($query['analytics_promotion_link_id'] ?? 0)),
            'promotion_code' => preg_replace('/[^a-zA-Z0-9_-]+/', '', trim((string) ($query['analytics_promotion_code'] ?? ''))) ?: '',
            'traffic_platform' => $this->limitText(trim((string) ($query['analytics_traffic_platform'] ?? '')), 40),
            'channel_id' => $this->limitText(trim((string) ($query['analytics_channel_id'] ?? '')), 60),
            'ad_id' => $this->limitText(trim((string) ($query['analytics_ad_id'] ?? '')), 80),
            'material_id' => $this->limitText(trim((string) ($query['analytics_material_id'] ?? '')), 80),
        ];
        $filters['active'] = false;
        foreach ($filters as $key => $value) {
            if (in_array($key, ['active', 'date_preset', 'date_label'], true)) {
                continue;
            }
            if (in_array($key, ['date_start', 'date_end'], true) && (string) ($filters['date_preset'] ?? 'all') === 'all') {
                continue;
            }
            if ((string) $value !== '' && (string) $value !== '0') {
                $filters['active'] = true;
                break;
            }
        }

        return $filters;
    }

    private function analyticsDateRangeFromRequest(array $query): array
    {
        $timezone = new \DateTimeZone('Asia/Shanghai');
        $today = new \DateTimeImmutable('today', $timezone);
        $preset = preg_replace('/[^a-z0-9_-]+/', '', strtolower(trim((string) ($query['analytics_date_preset'] ?? 'all')))) ?: 'all';
        $allowedPresets = ['all', 'today', 'yesterday', 'last_7_days', 'last_30_days', 'last_90_days', 'this_month', 'last_month', 'custom'];
        if (!in_array($preset, $allowedPresets, true)) {
            $preset = 'all';
        }

        $format = static fn (\DateTimeImmutable $date): string => $date->format('Y-m-d');
        $range = match ($preset) {
            'today' => ['start' => $today, 'end' => $today, 'label' => '今日'],
            'yesterday' => ['start' => $today->modify('-1 day'), 'end' => $today->modify('-1 day'), 'label' => '昨日'],
            'last_7_days' => ['start' => $today->modify('-6 days'), 'end' => $today, 'label' => '近7天'],
            'last_30_days' => ['start' => $today->modify('-29 days'), 'end' => $today, 'label' => '近30天'],
            'last_90_days' => ['start' => $today->modify('-89 days'), 'end' => $today, 'label' => '近90天'],
            'this_month' => ['start' => $today->modify('first day of this month'), 'end' => $today, 'label' => '本月'],
            'last_month' => [
                'start' => $today->modify('first day of last month'),
                'end' => $today->modify('last day of last month'),
                'label' => '上月',
            ],
            default => ['start' => null, 'end' => null, 'label' => '全部时间'],
        };

        if ($preset === 'custom') {
            $start = $this->parseAnalyticsDate((string) ($query['analytics_date_start'] ?? ''), $timezone);
            $end = $this->parseAnalyticsDate((string) ($query['analytics_date_end'] ?? ''), $timezone);
            if ($start === null && $end === null) {
                return ['preset' => 'all', 'start' => '', 'end' => '', 'label' => '全部时间'];
            }
            $start ??= $end;
            $end ??= $start;
            if ($start > $end) {
                [$start, $end] = [$end, $start];
            }
            $range = [
                'start' => $start,
                'end' => $end,
                'label' => $format($start) . ' 至 ' . $format($end),
            ];
        }

        if (!$range['start'] instanceof \DateTimeImmutable || !$range['end'] instanceof \DateTimeImmutable) {
            return ['preset' => 'all', 'start' => '', 'end' => '', 'label' => '全部时间'];
        }

        return [
            'preset' => $preset,
            'start' => $format($range['start']),
            'end' => $format($range['end']),
            'label' => (string) $range['label'],
        ];
    }

    private function parseAnalyticsDate(string $value, \DateTimeZone $timezone): ?\DateTimeImmutable
    {
        $value = trim($value);
        if (!preg_match('/^\d{4}-\d{2}-\d{2}$/', $value)) {
            return null;
        }
        $date = \DateTimeImmutable::createFromFormat('!Y-m-d', $value, $timezone);

        return $date instanceof \DateTimeImmutable && $date->format('Y-m-d') === $value ? $date : null;
    }

    private function parseAnalyticsDateTime(string $value, \DateTimeZone $timezone): ?\DateTimeImmutable
    {
        $value = trim($value);
        if ($value === '') {
            return null;
        }
        $normalized = str_replace('T', ' ', $value);
        if (preg_match('/^\d{4}-\d{2}-\d{2}$/', $normalized) === 1) {
            return $this->parseAnalyticsDate($normalized, $timezone);
        }
        if (preg_match('/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}(:\d{2})?(\.\d+)?$/', $normalized) === 1) {
            $withoutFraction = preg_replace('/\.\d+$/', '', $normalized) ?: $normalized;
            $format = substr_count($withoutFraction, ':') === 1 ? '!Y-m-d H:i' : '!Y-m-d H:i:s';
            $date = \DateTimeImmutable::createFromFormat($format, $withoutFraction, $timezone);

            return $date instanceof \DateTimeImmutable ? $date : null;
        }

        try {
            return (new \DateTimeImmutable($value))->setTimezone($timezone);
        } catch (\Throwable) {
            $timestamp = strtotime($value);
            if ($timestamp === false) {
                return null;
            }

            return (new \DateTimeImmutable('@' . $timestamp))->setTimezone($timezone);
        }
    }

    private function previousAnalyticsFilters(array $filters): ?array
    {
        $timezone = new \DateTimeZone('Asia/Shanghai');
        $start = $this->parseAnalyticsDate((string) ($filters['date_start'] ?? ''), $timezone);
        $end = $this->parseAnalyticsDate((string) ($filters['date_end'] ?? ''), $timezone);
        if ($start === null || $end === null) {
            return null;
        }
        if ($start > $end) {
            [$start, $end] = [$end, $start];
        }
        $days = ((int) $start->diff($end)->format('%a')) + 1;
        $previousEnd = $start->modify('-1 day');
        $previousStart = $previousEnd->modify('-' . ($days - 1) . ' days');
        $previous = $filters;
        $previous['date_preset'] = 'previous';
        $previous['date_start'] = $previousStart->format('Y-m-d');
        $previous['date_end'] = $previousEnd->format('Y-m-d');
        $previous['date_label'] = '上一周期 ' . $previous['date_start'] . ' 至 ' . $previous['date_end'];
        $previous['active'] = true;

        return $previous;
    }

    private function analyticsComparisonSummary(array $currentData, array $previousData, array $filters, ?array $previousFilters): array
    {
        $current = $this->analyticsPeriodMetrics($currentData);
        $previous = $this->analyticsPeriodMetrics($previousData);
        $changes = [];
        foreach (['new_users', 'add_desktop', 'paid_orders', 'revenue', 'cost'] as $metric) {
            $changes[$metric] = $this->analyticsMetricChange((float) ($current[$metric] ?? 0), (float) ($previous[$metric] ?? 0));
        }
        foreach (['pay_rate', 'recovery_rate'] as $metric) {
            $changes[$metric] = [
                'current' => $current[$metric],
                'previous' => $previous[$metric],
                'diff' => $current[$metric] === null || $previous[$metric] === null ? null : round((float) $current[$metric] - (float) $previous[$metric], 2),
            ];
        }

        return [
            'enabled' => $previousFilters !== null,
            'current_label' => (string) ($filters['date_label'] ?? ''),
            'previous_label' => (string) ($previousFilters['date_label'] ?? ''),
            'current' => $current,
            'previous' => $previous,
            'changes' => $changes,
        ];
    }

    private function analyticsPeriodMetrics(array $data): array
    {
        $users = array_values((array) ($data['users'] ?? []));
        $events = array_values((array) ($data['promotion_events'] ?? []));
        $orders = array_values((array) ($data['orders'] ?? []));
        $costs = array_values((array) ($data['promotion_costs'] ?? []));
        $paidUserIds = [];
        $paidOrders = 0;
        $revenue = 0.0;
        foreach ($orders as $order) {
            if (!empty($order['is_test']) || !in_array((string) ($order['status'] ?? 'pending'), ['paid', 'partial_refunded', 'refunded'], true)) {
                continue;
            }
            $amount = max(0.0, (float) ($order['amount'] ?? 0));
            $refund = min($amount, max(0.0, (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0)));
            $revenue += max(0.0, $amount - $refund);
            $paidOrders++;
            if ((int) ($order['user_id'] ?? 0) > 0) {
                $paidUserIds[(int) $order['user_id']] = true;
            }
        }
        $cost = 0.0;
        foreach ($costs as $costRow) {
            $cost += max(0.0, (float) ($costRow['amount'] ?? 0));
        }
        $addDesktop = count(array_filter($events, static fn (array $event): bool => (string) ($event['event'] ?? '') === 'add_desktop'));
        $newUsers = count($users);

        return [
            'new_users' => $newUsers,
            'add_desktop' => $addDesktop,
            'paid_users' => count($paidUserIds),
            'paid_orders' => $paidOrders,
            'revenue' => round($revenue, 2),
            'cost' => round($cost, 2),
            'pay_rate' => $newUsers > 0 ? round((count($paidUserIds) / $newUsers) * 100, 2) : 0.0,
            'recovery_rate' => $cost > 0 ? round(($revenue / $cost) * 100, 2) : null,
        ];
    }

    private function analyticsMetricChange(float $current, float $previous): array
    {
        return [
            'current' => round($current, 2),
            'previous' => round($previous, 2),
            'diff' => round($current - $previous, 2),
            'percent' => $previous > 0 ? round((($current - $previous) / $previous) * 100, 2) : null,
        ];
    }

    private function filterDashboardDataForAnalytics(array $data, array $filters): array
    {
        if (empty($filters['active'])) {
            return $data;
        }

        $agentTree = $this->agentTree((array) ($data['agents'] ?? []));
        $timezone = new \DateTimeZone('Asia/Shanghai');
        $dateStart = $this->parseAnalyticsDate((string) ($filters['date_start'] ?? ''), $timezone);
        $dateEnd = $this->parseAnalyticsDate((string) ($filters['date_end'] ?? ''), $timezone);
        if ($dateStart !== null && $dateEnd !== null && $dateStart > $dateEnd) {
            [$dateStart, $dateEnd] = [$dateEnd, $dateStart];
        }
        $hasDateRange = $dateStart !== null && $dateEnd !== null;
        $matchesDate = function (array $source, array $keys = ['created_at']) use ($dateStart, $dateEnd, $timezone): bool {
            if ($dateStart === null || $dateEnd === null) {
                return true;
            }
            $value = '';
            foreach ($keys as $key) {
                $candidate = trim((string) ($source[$key] ?? ''));
                if ($candidate !== '') {
                    $value = $candidate;
                    break;
                }
            }
            if ($value === '') {
                return false;
            }
            $dateTime = $this->parseAnalyticsDateTime($value, $timezone);
            if ($dateTime === null) {
                return false;
            }
            $date = $dateTime->format('Y-m-d');

            return $date >= $dateStart->format('Y-m-d') && $date <= $dateEnd->format('Y-m-d');
        };
        $matchesTraffic = function (array $source) use ($filters): bool {
            $meta = $this->trafficMetaFromPayload($source);
            $appKey = $this->normalizeAppKey((string) (($source['app_key'] ?? '') ?: ($meta['media_app_id'] ?? '')));
            if ((string) ($filters['app_key'] ?? '') !== '' && $appKey !== (string) $filters['app_key'] && (string) ($meta['media_app_id'] ?? '') !== (string) $filters['app_key']) {
                return false;
            }
            foreach (['traffic_platform', 'channel_id', 'ad_id', 'material_id'] as $key) {
                $needle = (string) ($filters[$key] ?? '');
                if ($needle !== '' && !str_contains((string) ($meta[$key] ?? ''), $needle)) {
                    return false;
                }
            }

            return true;
        };

        $visibleLinkIds = [];
        $visibleCodes = [];
        $visibleAgentIds = [];
        $links = [];
        foreach ((array) ($data['promotion_links'] ?? []) as $link) {
            $linkId = (int) ($link['id'] ?? 0);
            $agentId = (int) ($link['agent_id'] ?? 0);
            $org = $agentTree[$agentId] ?? [];
            if ((int) ($filters['promotion_link_id'] ?? 0) > 0 && $linkId !== (int) $filters['promotion_link_id']) {
                continue;
            }
            if ((string) ($filters['promotion_code'] ?? '') !== '' && (string) ($link['code'] ?? '') !== (string) $filters['promotion_code']) {
                continue;
            }
            if ((int) ($filters['business_id'] ?? 0) > 0 && (int) ($org['business_id'] ?? 0) !== (int) $filters['business_id']) {
                continue;
            }
            if ((int) ($filters['leader_id'] ?? 0) > 0 && (int) ($org['leader_id'] ?? 0) !== (int) $filters['leader_id']) {
                continue;
            }
            if ((int) ($filters['agent_id'] ?? 0) > 0 && $agentId !== (int) $filters['agent_id']) {
                continue;
            }
            if (!$matchesTraffic($link)) {
                continue;
            }
            $links[] = $link;
            $visibleLinkIds[$linkId] = true;
            if ((string) ($link['code'] ?? '') !== '') {
                $visibleCodes[(string) $link['code']] = true;
            }
            if ($agentId > 0) {
                $visibleAgentIds[$agentId] = true;
            }
        }
        $data['promotion_links'] = $links;

        $requiresLinkMatch = (int) ($filters['business_id'] ?? 0) > 0
            || (int) ($filters['leader_id'] ?? 0) > 0
            || (int) ($filters['agent_id'] ?? 0) > 0
            || (int) ($filters['promotion_link_id'] ?? 0) > 0
            || (string) ($filters['promotion_code'] ?? '') !== '';
        $hasNonDateFilters = $requiresLinkMatch
            || (string) ($filters['app_key'] ?? '') !== ''
            || (string) ($filters['traffic_platform'] ?? '') !== ''
            || (string) ($filters['channel_id'] ?? '') !== ''
            || (string) ($filters['ad_id'] ?? '') !== ''
            || (string) ($filters['material_id'] ?? '') !== '';
        $matchesLinkedRecord = function (array $item) use ($filters, $visibleLinkIds, $visibleCodes, $matchesTraffic, $requiresLinkMatch): bool {
            $linkId = (int) ($item['promotion_link_id'] ?? 0);
            $code = (string) (($item['code'] ?? '') ?: ($item['promotion_code'] ?? ''));
            if ((int) ($filters['promotion_link_id'] ?? 0) > 0 && $linkId !== (int) $filters['promotion_link_id']) {
                return false;
            }
            if ((string) ($filters['promotion_code'] ?? '') !== '' && $code !== (string) $filters['promotion_code']) {
                return false;
            }
            if ($linkId > 0 && isset($visibleLinkIds[$linkId])) {
                return $matchesTraffic($item);
            }
            if ($code !== '' && isset($visibleCodes[$code])) {
                return $matchesTraffic($item);
            }
            if ($requiresLinkMatch) {
                return false;
            }

            return $matchesTraffic($item);
        };

        $visibleOrderNos = [];
        $visibleUserIds = [];
        $data['promotion_events'] = array_values(array_filter((array) ($data['promotion_events'] ?? []), static function (array $event) use ($matchesLinkedRecord, $matchesDate, &$visibleOrderNos, &$visibleUserIds): bool {
            if (!$matchesLinkedRecord($event) || !$matchesDate($event, ['created_at'])) {
                return false;
            }
            if ((string) ($event['order_no'] ?? '') !== '') {
                $visibleOrderNos[(string) $event['order_no']] = true;
            }
            if ((int) ($event['user_id'] ?? 0) > 0) {
                $visibleUserIds[(int) $event['user_id']] = true;
            }

            return true;
        }));
        $data['promotion_costs'] = array_values(array_filter((array) ($data['promotion_costs'] ?? []), static fn (array $cost): bool => $matchesLinkedRecord($cost) && $matchesDate($cost, ['date', 'created_at'])));
        $data['callback_logs'] = array_values(array_filter((array) ($data['callback_logs'] ?? []), static function (array $log) use ($matchesLinkedRecord, $matchesDate, &$visibleOrderNos, &$visibleUserIds): bool {
            if (!$matchesLinkedRecord($log) || !$matchesDate($log, ['last_attempt_at', 'updated_at', 'created_at'])) {
                return false;
            }
            if ((string) ($log['order_no'] ?? '') !== '') {
                $visibleOrderNos[(string) $log['order_no']] = true;
            }
            if ((int) ($log['user_id'] ?? 0) > 0) {
                $visibleUserIds[(int) $log['user_id']] = true;
            }

            return true;
        }));

        $data['orders'] = array_values(array_filter((array) ($data['orders'] ?? []), static function (array $order) use ($matchesLinkedRecord, $matchesDate, &$visibleOrderNos, &$visibleUserIds): bool {
            if (!$matchesLinkedRecord($order) || !$matchesDate($order, ['paid_at', 'created_at'])) {
                return false;
            }
            if ((string) ($order['order_no'] ?? '') !== '') {
                $visibleOrderNos[(string) $order['order_no']] = true;
            }
            if ((int) ($order['user_id'] ?? 0) > 0) {
                $visibleUserIds[(int) $order['user_id']] = true;
            }

            return true;
        }));

        $data['content_events'] = array_values(array_filter((array) ($data['content_events'] ?? []), static function (array $event) use ($matchesLinkedRecord, $matchesDate, $visibleOrderNos, $visibleUserIds): bool {
            if (!$matchesDate($event, ['created_at'])) {
                return false;
            }
            if ($matchesLinkedRecord($event)) {
                return true;
            }
            $orderNo = (string) ($event['order_no'] ?? '');
            if ($orderNo !== '' && isset($visibleOrderNos[$orderNo])) {
                return true;
            }
            $userId = (int) ($event['user_id'] ?? 0);

            return $userId > 0 && isset($visibleUserIds[$userId]);
        }));
        $contentEventUserIds = [];
        foreach ((array) ($data['content_events'] ?? []) as $event) {
            if ((int) ($event['user_id'] ?? 0) > 0) {
                $contentEventUserIds[(int) $event['user_id']] = true;
            }
        }
        $data['watch_history'] = array_values(array_filter((array) ($data['watch_history'] ?? []), static function (array $item) use ($matchesDate, $hasDateRange, $hasNonDateFilters, $visibleUserIds, $contentEventUserIds): bool {
            if ($hasDateRange && !$matchesDate($item, ['updated_at', 'created_at'])) {
                return false;
            }
            if (!$hasNonDateFilters) {
                return true;
            }
            $userId = (int) ($item['user_id'] ?? 0);

            return $userId > 0 && (isset($visibleUserIds[$userId]) || isset($contentEventUserIds[$userId]));
        }));
        $visibleLandingPageIds = [];
        $data['landing_pages'] = array_values(array_filter((array) ($data['landing_pages'] ?? []), static function (array $page) use ($matchesLinkedRecord, &$visibleLandingPageIds): bool {
            if (!$matchesLinkedRecord($page)) {
                return false;
            }
            $visibleLandingPageIds[(int) ($page['id'] ?? 0)] = true;

            return true;
        }));
        $data['landing_page_events'] = array_values(array_filter((array) ($data['landing_page_events'] ?? []), static fn (array $event): bool => isset($visibleLandingPageIds[(int) ($event['landing_page_id'] ?? 0)]) && $matchesDate($event, ['created_at'])));
        $data['feedback_items'] = array_values(array_filter((array) ($data['feedback_items'] ?? []), static fn (array $item): bool => ($matchesLinkedRecord($item) || isset($visibleOrderNos[(string) ($item['order_no'] ?? '')])) && $matchesDate($item, ['created_at', 'updated_at'])));
        $data['operation_alert_notifications'] = array_values(array_filter((array) ($data['operation_alert_notifications'] ?? []), static fn (array $item): bool => ($matchesLinkedRecord($item) || isset($visibleOrderNos[(string) ($item['order_no'] ?? '')])) && $matchesDate($item, ['last_seen_at', 'created_at'])));
        $data['operation_alert_notification_logs'] = array_values(array_filter((array) ($data['operation_alert_notification_logs'] ?? []), static fn (array $item): bool => ($matchesLinkedRecord($item) || isset($visibleOrderNos[(string) ($item['order_no'] ?? '')])) && $matchesDate($item, ['created_at'])));
        $data['promotion_stop_tasks'] = array_values(array_filter((array) ($data['promotion_stop_tasks'] ?? []), static fn (array $item): bool => $matchesLinkedRecord($item) && $matchesDate($item, ['created_at', 'updated_at', 'last_attempt_at', 'completed_at'])));
        $data['analytics_review_tasks'] = array_values(array_filter((array) ($data['analytics_review_tasks'] ?? []), static fn (array $item): bool => $matchesLinkedRecord($item) && $matchesDate($item, ['created_at', 'updated_at', 'completed_at'])));
        $data['order_action_logs'] = array_values(array_filter((array) ($data['order_action_logs'] ?? []), static fn (array $log): bool => isset($visibleOrderNos[(string) ($log['order_no'] ?? '')])));
        $data['users'] = array_values(array_filter((array) ($data['users'] ?? []), static function (array $user) use ($visibleUserIds, $matchesDate, $hasDateRange, $hasNonDateFilters): bool {
            if (isset($visibleUserIds[(int) ($user['id'] ?? 0)])) {
                return !$hasDateRange || $matchesDate($user, ['created_at']);
            }

            return $hasDateRange && !$hasNonDateFilters && $matchesDate($user, ['created_at']);
        }));
        $data['agents'] = array_values(array_filter((array) ($data['agents'] ?? []), static fn (array $agent): bool => isset($visibleAgentIds[(int) ($agent['id'] ?? 0)]) || (int) ($filters['business_id'] ?? 0) === (int) ($agent['id'] ?? 0) || (int) ($filters['leader_id'] ?? 0) === (int) ($agent['id'] ?? 0) || (int) ($filters['agent_id'] ?? 0) === (int) ($agent['id'] ?? 0)));

        return $data;
    }

    private function statsForDashboardData(array $data): array
    {
        $paidOrders = array_values(array_filter((array) ($data['orders'] ?? []), static fn (array $order): bool => empty($order['is_test']) && in_array((string) ($order['status'] ?? 'pending'), ['paid', 'partial_refunded', 'refunded'], true)));
        $revenue = 0.0;
        foreach ($paidOrders as $order) {
            $amount = (float) ($order['amount'] ?? 0);
            $refund = min($amount, max(0.0, (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0)));
            $revenue += max(0.0, $amount - $refund);
        }

        return [
            'users' => count((array) ($data['users'] ?? [])),
            'orders' => count($paidOrders),
            'revenue' => round($revenue, 2),
            'dramas' => count((array) ($data['dramas'] ?? [])),
        ];
    }

    private function promotionStopTaskDashboard(array $tasks): array
    {
        $rows = array_values(array_filter($tasks, static fn (mixed $item): bool => is_array($item)));
        $summary = [
            'total' => count($rows),
            'pending' => 0,
            'processing' => 0,
            'success' => 0,
            'failed' => 0,
            'skipped' => 0,
            'manual_done' => 0,
            'cancelled' => 0,
        ];
        $providerRows = [];
        foreach ($rows as $row) {
            $status = (string) ($row['status'] ?? 'pending');
            if (isset($summary[$status])) {
                $summary[$status]++;
            }
            $provider = trim((string) (($row['provider'] ?? '') ?: ($row['traffic_platform'] ?? '')));
            $provider = $provider !== '' ? $provider : '未标记平台';
            $providerRows[$provider] ??= ['provider' => $provider, 'total' => 0, 'pending' => 0, 'processing' => 0, 'success' => 0, 'failed' => 0, 'manual_done' => 0];
            $providerRows[$provider]['total']++;
            if (isset($providerRows[$provider][$status])) {
                $providerRows[$provider][$status]++;
            }
        }
        usort($rows, static fn (array $a, array $b): int => [
            ['pending' => 0, 'failed' => 1, 'processing' => 2, 'success' => 3, 'manual_done' => 4, 'skipped' => 5, 'cancelled' => 6][(string) ($a['status'] ?? 'pending')] ?? 9,
            (string) ($b['created_at'] ?? ''),
            (int) ($b['id'] ?? 0),
        ] <=> [
            ['pending' => 0, 'failed' => 1, 'processing' => 2, 'success' => 3, 'manual_done' => 4, 'skipped' => 5, 'cancelled' => 6][(string) ($b['status'] ?? 'pending')] ?? 9,
            (string) ($a['created_at'] ?? ''),
            (int) ($a['id'] ?? 0),
        ]);
        usort($providerRows, static fn (array $a, array $b): int => [(int) ($b['pending'] ?? 0), (int) ($b['failed'] ?? 0), (int) ($b['total'] ?? 0)] <=> [(int) ($a['pending'] ?? 0), (int) ($a['failed'] ?? 0), (int) ($a['total'] ?? 0)]);

        return [
            'summary' => $summary,
            'rows' => array_slice($rows, 0, 100),
            'provider_rows' => array_values($providerRows),
        ];
    }

    private function promotionLinkPerformance(array $link, array $data): array
    {
        $linkId = (int) ($link['id'] ?? 0);
        $today = date('Y-m-d');
        $row = [
            'visits' => 0,
            'registers' => 0,
            'add_desktop' => 0,
            'activations' => 0,
            'orders' => 0,
            'paid_orders' => 0,
            'revenue' => 0.0,
            'cost' => 0.0,
            'today_visits' => 0,
            'today_add_desktop' => 0,
            'today_revenue' => 0.0,
            'conversion_rate' => 0.0,
            'recovery_rate' => null,
            'add_desktop_cost' => null,
            'order_cost' => null,
        ];

        foreach ((array) ($data['promotion_events'] ?? []) as $event) {
            if ((int) ($event['promotion_link_id'] ?? 0) !== $linkId) {
                continue;
            }
            $eventType = (string) ($event['event'] ?? '');
            if ($eventType === 'visit') {
                $row['visits']++;
                if (str_starts_with((string) ($event['created_at'] ?? ''), $today)) {
                    $row['today_visits']++;
                }
            } elseif ($eventType === 'register') {
                $row['registers']++;
            } elseif ($eventType === 'add_desktop') {
                $row['add_desktop']++;
                if (str_starts_with((string) ($event['created_at'] ?? ''), $today)) {
                    $row['today_add_desktop']++;
                }
            } elseif ($eventType === 'activate') {
                $row['activations']++;
            }
        }

        foreach ((array) ($data['promotion_costs'] ?? []) as $cost) {
            if ((int) ($cost['promotion_link_id'] ?? 0) === $linkId) {
                $row['cost'] += (float) ($cost['amount'] ?? 0);
            }
        }

        $settledStatuses = ['paid', 'partial_refunded', 'refunded'];
        foreach ((array) ($data['orders'] ?? []) as $order) {
            if (!empty($order['is_test']) || (int) ($order['promotion_link_id'] ?? 0) !== $linkId) {
                continue;
            }
            $row['orders']++;
            if (!in_array((string) ($order['status'] ?? 'pending'), $settledStatuses, true)) {
                continue;
            }
            $amount = (float) ($order['amount'] ?? 0);
            $refund = min($amount, max(0.0, (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0)));
            $net = max(0.0, $amount - $refund);
            $row['paid_orders']++;
            $row['revenue'] += $net;
            $paidAt = (string) ($order['paid_at'] ?? $order['created_at'] ?? '');
            if (str_starts_with($paidAt, $today)) {
                $row['today_revenue'] += $net;
            }
        }

        $row['revenue'] = round((float) $row['revenue'], 2);
        $row['today_revenue'] = round((float) $row['today_revenue'], 2);
        $row['cost'] = round((float) $row['cost'], 2);
        $row['conversion_rate'] = (int) $row['visits'] > 0 ? round(((int) $row['paid_orders'] / (int) $row['visits']) * 100, 2) : 0.0;
        $row['recovery_rate'] = (float) $row['cost'] > 0 ? round(((float) $row['revenue'] / (float) $row['cost']) * 100, 2) : null;
        $row['add_desktop_cost'] = (int) $row['add_desktop'] > 0 ? round(((float) $row['cost'] / (int) $row['add_desktop']), 2) : null;
        $row['order_cost'] = (int) $row['paid_orders'] > 0 ? round(((float) $row['cost'] / (int) $row['paid_orders']), 2) : null;

        return $row;
    }

    private function applyPromotionLinkAutoPause(array &$data, int $linkId, string $now): array
    {
        $linkIndex = null;
        foreach ((array) ($data['promotion_links'] ?? []) as $index => $link) {
            if ((int) ($link['id'] ?? 0) === $linkId) {
                $linkIndex = $index;
                break;
            }
        }
        if ($linkIndex === null) {
            return ['checked' => false, 'paused' => false, 'reason' => '推广入口不存在'];
        }

        $link =& $data['promotion_links'][$linkIndex];
        if (empty($link['auto_pause_on_cost'])) {
            return ['checked' => false, 'paused' => false, 'reason' => '未开启自动停投'];
        }
        if ((string) ($link['status'] ?? 'active') === 'paused') {
            return ['checked' => true, 'paused' => false, 'reason' => '入口已暂停'];
        }

        $performance = $this->promotionLinkPerformance((array) $link, $data);
        $cost = round(max(0.0, (float) ($performance['cost'] ?? 0)), 2);
        $budgetLimit = round(max(0.0, (float) ($link['cost_budget_limit'] ?? 0)), 2);
        $minRecoveryRate = round(max(0.0, (float) ($link['min_recovery_rate'] ?? 0)), 2);
        $minCost = round(max(0.0, (float) ($link['auto_pause_min_cost'] ?? 0)), 2);
        $recoveryRate = $performance['recovery_rate'] ?? null;
        $reason = '';

        if ($budgetLimit > 0 && $cost >= $budgetLimit) {
            $reason = '投放消耗 ' . number_format($cost, 2) . ' 已达到预算 ' . number_format($budgetLimit, 2) . '，系统自动暂停入口。';
        } elseif ($minRecoveryRate > 0 && $cost >= $minCost && $recoveryRate !== null && (float) $recoveryRate < $minRecoveryRate) {
            $reason = '回本率 ' . number_format((float) $recoveryRate, 2) . '% 低于保护线 ' . number_format($minRecoveryRate, 2) . '%，系统自动暂停入口。';
        }

        if ($reason === '') {
            return ['checked' => true, 'paused' => false, 'reason' => '', 'performance' => $performance];
        }

        $link['status'] = 'paused';
        $link['auto_paused_at'] = $now;
        $link['auto_paused_reason'] = $this->limitText($reason, 160);
        $link['updated_at'] = $now;
        $alert = $this->operationAlertFromAutoPausedPromotionLink((array) $link, $performance, $reason, $now);
        $notificationResult = $this->upsertOperationAlertNotification($data, $alert, $now, '系统自动停投');
        $externalNotify = null;
        $noticeIndex = $notificationResult['index'] ?? null;
        if ($noticeIndex !== null && isset($data['operation_alert_notifications'][$noticeIndex])) {
            $config = (array) ($data['operation_alert_notification_config'] ?? []);
            if ($this->shouldSendOperationAlertNotification($data['operation_alert_notifications'][$noticeIndex], $config, $data)) {
                $externalNotify = $this->sendOperationAlertNotificationRecord($data['operation_alert_notifications'][$noticeIndex], $config, $data, false);
            }
        }
        $stopTask = $this->upsertPromotionStopTask(
            $data,
            (array) $link,
            $alert,
            $now,
            is_int($noticeIndex) ? (int) ($data['operation_alert_notifications'][$noticeIndex]['id'] ?? 0) : 0
        );

        return [
            'checked' => true,
            'paused' => true,
            'reason' => $reason,
            'performance' => $performance,
            'alert' => $alert,
            'notification' => $notificationResult,
            'external_notify' => $externalNotify,
            'stop_task' => $stopTask,
        ];
    }

    private function operationAlertFromAutoPausedPromotionLink(array $link, array $performance, string $reason, string $now): array
    {
        $cost = round(max(0.0, (float) ($performance['cost'] ?? 0)), 2);
        $revenue = round(max(0.0, (float) ($performance['revenue'] ?? 0)), 2);
        $budgetLimit = round(max(0.0, (float) ($link['cost_budget_limit'] ?? 0)), 2);
        $recoveryRate = $performance['recovery_rate'] ?? null;
        $minRecoveryRate = round(max(0.0, (float) ($link['min_recovery_rate'] ?? 0)), 2);
        $budgetUsedRate = $budgetLimit > 0 ? round(($cost / $budgetLimit) * 100, 2) : null;
        $code = (string) ($link['code'] ?? '');
        $identity = $code !== '' ? $code : ('链接 #' . (int) ($link['id'] ?? 0));

        return [
            'type' => 'auto_paused_link',
            'level' => 'high',
            'title' => '自动停投推广：' . $identity,
            'message' => trim($reason . ' 当前消耗 ' . number_format($cost, 2) . '，净回收 ' . number_format($revenue, 2) . '，回本 ' . ($recoveryRate === null ? '-' : number_format((float) $recoveryRate, 2) . '%') . '。'),
            'code' => $code,
            'promotion_link_id' => (int) ($link['id'] ?? 0),
            'agent_id' => (int) ($link['agent_id'] ?? 0),
            'traffic_platform' => (string) ($link['traffic_platform'] ?? ''),
            'channel_id' => (string) ($link['channel_id'] ?? ''),
            'media_app_id' => (string) ($link['media_app_id'] ?? ''),
            'ad_id' => (string) ($link['ad_id'] ?? ''),
            'creative_id' => (string) ($link['creative_id'] ?? ''),
            'material_id' => (string) ($link['material_id'] ?? ''),
            'cost' => $cost,
            'net_amount' => $revenue,
            'paid_orders' => (int) ($performance['paid_orders'] ?? 0),
            'recovery_rate' => $recoveryRate,
            'cost_budget_limit' => $budgetLimit,
            'budget_used_rate' => $budgetUsedRate,
            'min_recovery_rate' => $minRecoveryRate,
            'auto_pause_min_cost' => round(max(0.0, (float) ($link['auto_pause_min_cost'] ?? 0)), 2),
            'auto_paused_at' => $now,
            'auto_paused_reason' => $reason,
        ];
    }

    private function upsertPromotionStopTask(array &$data, array $link, array $alert, string $now, int $alertId = 0): array
    {
        $data['promotion_stop_tasks'] = array_values((array) ($data['promotion_stop_tasks'] ?? []));
        $linkId = (int) ($link['id'] ?? 0);
        $pausedAt = (string) (($link['auto_paused_at'] ?? '') ?: $now);
        $fingerprint = 'stop:' . md5(implode('|', [
            (string) $linkId,
            $pausedAt,
            (string) ($link['ad_id'] ?? ''),
            (string) ($link['material_id'] ?? ''),
        ]));
        $provider = trim((string) (($link['traffic_platform'] ?? '') ?: '未标记平台'));
        $stopAction = trim((string) ($link['ad_id'] ?? '')) !== ''
            ? 'pause_ad'
            : (trim((string) ($link['material_id'] ?? '')) !== '' ? 'pause_material' : 'manual');

        foreach ($data['promotion_stop_tasks'] as $index => $task) {
            if ((string) ($task['fingerprint'] ?? '') !== $fingerprint) {
                continue;
            }
            $task = (array) $task;
            foreach (['promotion_link_id', 'promotion_code', 'agent_id', 'traffic_platform', 'channel_id', 'media_app_id', 'ad_id', 'creative_id', 'material_id'] as $key) {
                $task[$key] = match ($key) {
                    'promotion_link_id' => $linkId,
                    'promotion_code' => (string) ($link['code'] ?? ''),
                    default => $link[$key] ?? ($task[$key] ?? ''),
                };
            }
            $task['alert_id'] = $alertId > 0 ? $alertId : (int) ($task['alert_id'] ?? 0);
            $task['provider'] = $provider;
            $task['stop_action'] = $stopAction;
            $task['reason'] = (string) ($alert['message'] ?? $link['auto_paused_reason'] ?? $task['reason'] ?? '');
            $task['updated_at'] = $now;
            $data['promotion_stop_tasks'][$index] = $task;

            return ['created' => 0, 'updated' => 1, 'task' => $task];
        }

        $nextId = empty($data['promotion_stop_tasks']) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $data['promotion_stop_tasks'])) + 1);
        $task = [
            'id' => $nextId,
            'task_no' => 'STOP' . date('Ymd') . str_pad((string) $nextId, 4, '0', STR_PAD_LEFT),
            'fingerprint' => $fingerprint,
            'source_type' => 'auto_pause',
            'alert_id' => $alertId,
            'promotion_link_id' => $linkId,
            'promotion_code' => (string) ($link['code'] ?? ''),
            'agent_id' => (int) ($link['agent_id'] ?? 0),
            'traffic_platform' => (string) ($link['traffic_platform'] ?? ''),
            'channel_id' => (string) ($link['channel_id'] ?? ''),
            'media_app_id' => (string) ($link['media_app_id'] ?? ''),
            'ad_id' => (string) ($link['ad_id'] ?? ''),
            'creative_id' => (string) ($link['creative_id'] ?? ''),
            'material_id' => (string) ($link['material_id'] ?? ''),
            'provider' => $provider,
            'stop_action' => $stopAction,
            'reason' => (string) ($alert['message'] ?? $link['auto_paused_reason'] ?? ''),
            'status' => 'pending',
            'endpoint' => '',
            'query_endpoint' => '',
            'request_payload' => [],
            'response_payload' => [],
            'query_request_payload' => [],
            'query_response_payload' => [],
            'attempt_count' => 0,
            'query_count' => 0,
            'last_attempt_at' => '',
            'last_query_at' => '',
            'error_category' => '',
            'next_retry_at' => '',
            'rate_limited_until' => '',
            'retry_blocked_reason' => '',
            'last_error_at' => '',
            'completed_at' => '',
            'handled_by_admin_id' => 0,
            'handled_by_admin_name' => '',
            'message' => '已生成平台停投任务，等待执行。',
            'remark' => '',
            'created_at' => $now,
            'updated_at' => $now,
        ];
        $data['promotion_stop_tasks'][] = $task;

        return ['created' => 1, 'updated' => 0, 'task' => $task];
    }

    private function promotionDashboard(array $data): array
    {
        $links = array_values((array) ($data['promotion_links'] ?? []));
        $events = array_values((array) ($data['promotion_events'] ?? []));
        $costs = array_values((array) ($data['promotion_costs'] ?? []));
        $orders = array_values((array) ($data['orders'] ?? []));
        $dramaIndex = [];
        foreach ((array) ($data['dramas'] ?? []) as $drama) {
            $dramaIndex[(int) ($drama['id'] ?? 0)] = (string) ($drama['title'] ?? '未命名短剧');
        }
        $novelIndex = [];
        foreach ((array) ($data['novels'] ?? []) as $novel) {
            $novelIndex[(int) ($novel['id'] ?? 0)] = (string) ($novel['title'] ?? '未命名小说');
        }
        $agentIndex = [];
        foreach ((array) ($data['agents'] ?? []) as $agent) {
            $agentIndex[(int) ($agent['id'] ?? 0)] = $agent;
        }
        $agentTree = $this->agentTree((array) ($data['agents'] ?? []));

        $rows = [];
        foreach ($links as $link) {
            $id = (int) ($link['id'] ?? 0);
            $agentId = (int) ($link['agent_id'] ?? 0);
            $org = $agentTree[$agentId] ?? ['agent_id' => $agentId, 'agent_name' => '未分配代理', 'leader_id' => 0, 'leader_name' => '未分配组长', 'business_id' => 0, 'business_name' => '未分配商务'];
            $rows[$id] = [
                'link' => $link,
                'entry_url' => '/?route=promo&code=' . rawurlencode((string) ($link['code'] ?? '')),
                'drama_title' => $dramaIndex[(int) ($link['drama_id'] ?? 0)] ?? '未绑定短剧',
                'novel_title' => $novelIndex[(int) ($link['novel_id'] ?? 0)] ?? '未绑定小说',
                'content_title' => (string) (($link['content_type'] ?? 'drama') === 'novel'
                    ? ($novelIndex[(int) ($link['novel_id'] ?? 0)] ?? '未绑定小说')
                    : ($dramaIndex[(int) ($link['drama_id'] ?? 0)] ?? '未绑定短剧')),
                'agent_id' => $agentId,
                'agent_name' => (string) ($org['agent_name'] ?? ($agentIndex[$agentId]['name'] ?? '未分配代理')),
                'leader_id' => (int) ($org['leader_id'] ?? 0),
                'leader_name' => (string) ($org['leader_name'] ?? '未分配组长'),
                'business_id' => (int) ($org['business_id'] ?? 0),
                'business_name' => (string) ($org['business_name'] ?? '未分配商务'),
                'visits' => 0,
                'registers' => 0,
                'add_desktop' => 0,
                'activations' => 0,
                'orders' => 0,
                'paid_orders' => 0,
                'revenue' => 0.0,
                'cost' => 0.0,
                'today_visits' => 0,
                'today_add_desktop' => 0,
                'today_revenue' => 0.0,
                'conversion_rate' => 0.0,
                'recovery_rate' => null,
                'add_desktop_cost' => null,
                'order_cost' => null,
                'cost_budget_limit' => round(max(0, (float) ($link['cost_budget_limit'] ?? 0)), 2),
                'budget_remaining' => null,
                'budget_used_rate' => null,
                'budget_exhausted' => false,
                'min_recovery_rate' => round(max(0, (float) ($link['min_recovery_rate'] ?? 0)), 2),
                'auto_pause_on_cost' => !empty($link['auto_pause_on_cost']),
                'auto_pause_min_cost' => round(max(0, (float) ($link['auto_pause_min_cost'] ?? 0)), 2),
                'auto_pause_triggered' => (string) ($link['auto_paused_at'] ?? '') !== '',
                'recovery_below_min' => false,
            ];
        }

        $today = date('Y-m-d');
        foreach ($events as $event) {
            $linkId = (int) ($event['promotion_link_id'] ?? 0);
            $eventType = (string) ($event['event'] ?? '');
            if (!isset($rows[$linkId]) || !in_array($eventType, ['visit', 'register', 'add_desktop', 'activate'], true)) {
                continue;
            }
            if ($eventType === 'visit') {
                $rows[$linkId]['visits']++;
                if (str_starts_with((string) ($event['created_at'] ?? ''), $today)) {
                    $rows[$linkId]['today_visits']++;
                }
            } elseif ($eventType === 'register') {
                $rows[$linkId]['registers']++;
            } elseif ($eventType === 'add_desktop') {
                $rows[$linkId]['add_desktop']++;
                if (str_starts_with((string) ($event['created_at'] ?? ''), $today)) {
                    $rows[$linkId]['today_add_desktop']++;
                }
            } elseif ($eventType === 'activate') {
                $rows[$linkId]['activations']++;
            }
        }

        foreach ($costs as $cost) {
            $linkId = (int) ($cost['promotion_link_id'] ?? 0);
            if (!isset($rows[$linkId])) {
                continue;
            }
            $rows[$linkId]['cost'] += (float) ($cost['amount'] ?? 0);
        }

        $settledStatuses = ['paid', 'partial_refunded', 'refunded'];
        foreach ($orders as $order) {
            if (!empty($order['is_test'])) {
                continue;
            }
            $linkId = (int) ($order['promotion_link_id'] ?? 0);
            if (!isset($rows[$linkId])) {
                continue;
            }
            $rows[$linkId]['orders']++;
            $status = (string) ($order['status'] ?? 'pending');
            if (!in_array($status, $settledStatuses, true)) {
                continue;
            }
            $amount = (float) ($order['amount'] ?? 0);
            $refund = min($amount, max(0.0, (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0)));
            $net = max(0.0, $amount - $refund);
            $rows[$linkId]['paid_orders']++;
            $rows[$linkId]['revenue'] += $net;
            $paidAt = (string) ($order['paid_at'] ?? $order['created_at'] ?? '');
            if (str_starts_with($paidAt, $today)) {
                $rows[$linkId]['today_revenue'] += $net;
            }
        }

        foreach ($rows as &$row) {
            $row['revenue'] = round((float) $row['revenue'], 2);
            $row['today_revenue'] = round((float) $row['today_revenue'], 2);
            $row['cost'] = round((float) $row['cost'], 2);
            $row['conversion_rate'] = $row['visits'] > 0 ? round(((int) $row['paid_orders'] / (int) $row['visits']) * 100, 2) : 0.0;
            $row['recovery_rate'] = $row['cost'] > 0 ? round(((float) $row['revenue'] / (float) $row['cost']) * 100, 2) : null;
            $row['add_desktop_cost'] = (int) $row['add_desktop'] > 0 ? round(((float) $row['cost'] / (int) $row['add_desktop']), 2) : null;
            $row['order_cost'] = (int) $row['paid_orders'] > 0 ? round(((float) $row['cost'] / (int) $row['paid_orders']), 2) : null;
            $budgetLimit = (float) ($row['cost_budget_limit'] ?? 0);
            $row['budget_remaining'] = $budgetLimit > 0 ? round(max(0.0, $budgetLimit - (float) $row['cost']), 2) : null;
            $row['budget_used_rate'] = $budgetLimit > 0 ? round(((float) $row['cost'] / $budgetLimit) * 100, 2) : null;
            $row['budget_exhausted'] = $budgetLimit > 0 && (float) $row['cost'] >= $budgetLimit;
            $row['recovery_below_min'] = (float) ($row['min_recovery_rate'] ?? 0) > 0
                && (float) $row['cost'] >= (float) ($row['auto_pause_min_cost'] ?? 0)
                && $row['recovery_rate'] !== null
                && (float) $row['recovery_rate'] < (float) $row['min_recovery_rate'];
        }
        unset($row);

        usort($rows, static fn (array $a, array $b): int => [$b['revenue'], $b['paid_orders'], $b['visits']] <=> [$a['revenue'], $a['paid_orders'], $a['visits']]);

        $totalVisits = array_sum(array_column($rows, 'visits'));
        $totalRegisters = array_sum(array_column($rows, 'registers'));
        $totalAddDesktop = array_sum(array_column($rows, 'add_desktop'));
        $totalActivations = array_sum(array_column($rows, 'activations'));
        $totalPaidOrders = array_sum(array_column($rows, 'paid_orders'));
        $totalRevenue = array_sum(array_column($rows, 'revenue'));
        $totalCost = array_sum(array_column($rows, 'cost'));
        $autoPauseLinkCount = count(array_filter($rows, static fn (array $row): bool => !empty($row['auto_pause_on_cost'])));
        $autoPausedCount = count(array_filter($rows, static fn (array $row): bool => !empty($row['auto_pause_triggered'])));
        $budgetExhaustedCount = count(array_filter($rows, static fn (array $row): bool => !empty($row['budget_exhausted'])));
        $lowRecoveryProtectedCount = count(array_filter($rows, static fn (array $row): bool => !empty($row['recovery_below_min'])));

        return [
            'rows' => $rows,
            'summary' => [
                'link_count' => count($links),
                'active_link_count' => count(array_filter($links, static fn (array $link): bool => (string) ($link['status'] ?? 'active') === 'active')),
                'visits' => (int) $totalVisits,
                'registers' => (int) $totalRegisters,
                'add_desktop' => (int) $totalAddDesktop,
                'activations' => (int) $totalActivations,
                'paid_orders' => (int) $totalPaidOrders,
                'revenue' => round((float) $totalRevenue, 2),
                'cost' => round((float) $totalCost, 2),
                'conversion_rate' => $totalVisits > 0 ? round(($totalPaidOrders / $totalVisits) * 100, 2) : 0.0,
                'recovery_rate' => $totalCost > 0 ? round(($totalRevenue / $totalCost) * 100, 2) : null,
                'add_desktop_cost' => $totalAddDesktop > 0 ? round($totalCost / $totalAddDesktop, 2) : null,
                'order_cost' => $totalPaidOrders > 0 ? round($totalCost / $totalPaidOrders, 2) : null,
                'auto_pause_link_count' => $autoPauseLinkCount,
                'auto_paused_count' => $autoPausedCount,
                'budget_exhausted_count' => $budgetExhaustedCount,
                'low_recovery_protected_count' => $lowRecoveryProtectedCount,
            ],
        ];
    }

    private function agentSettlementDashboard(array $data, array $settlements): array
    {
        $rows = array_values(array_filter($settlements, static fn (mixed $item): bool => is_array($item)));
        $summary = [
            'total' => count($rows),
            'pending' => 0,
            'confirmed' => 0,
            'paid' => 0,
            'rejected' => 0,
            'pending_amount' => 0.0,
            'confirmed_amount' => 0.0,
            'paid_amount' => 0.0,
            'commission_amount' => 0.0,
            'net_revenue' => 0.0,
            'cost_amount' => 0.0,
            'agent_confirm_pending' => 0,
            'agent_confirmed' => 0,
            'agent_disputed' => 0,
            'agent_dispute_open' => 0,
            'agent_dispute_processing' => 0,
            'agent_dispute_closed' => 0,
        ];
        foreach ($rows as &$row) {
            $status = (string) ($row['status'] ?? 'pending');
            if (isset($summary[$status])) {
                $summary[$status]++;
            }
            $commission = round(max(0.0, (float) ($row['commission_amount'] ?? 0)), 2);
            if ($status === 'pending') {
                $summary['pending_amount'] += $commission;
            } elseif ($status === 'confirmed') {
                $summary['confirmed_amount'] += $commission;
            } elseif ($status === 'paid') {
                $summary['paid_amount'] += $commission;
            }
            $summary['commission_amount'] += $commission;
            $summary['net_revenue'] += max(0.0, (float) ($row['net_revenue'] ?? 0));
            $summary['cost_amount'] += max(0.0, (float) ($row['cost_amount'] ?? 0));
            $confirmStatus = (string) ($row['agent_confirm_status'] ?? 'none');
            if ($status === 'paid' && $confirmStatus === 'none') {
                $summary['agent_confirm_pending']++;
            } elseif ($confirmStatus === 'confirmed') {
                $summary['agent_confirmed']++;
            } elseif ($confirmStatus === 'disputed') {
                $summary['agent_disputed']++;
            }
            $disputeStatus = (string) ($row['dispute_status'] ?? 'none');
            if ($disputeStatus === 'open') {
                $summary['agent_dispute_open']++;
            } elseif ($disputeStatus === 'processing') {
                $summary['agent_dispute_processing']++;
            } elseif (in_array($disputeStatus, ['resolved', 'rejected'], true)) {
                $summary['agent_dispute_closed']++;
            }
        }
        unset($row);
        foreach (['pending_amount', 'confirmed_amount', 'paid_amount', 'commission_amount', 'net_revenue', 'cost_amount'] as $key) {
            $summary[$key] = round((float) $summary[$key], 2);
        }

        usort($rows, static fn (array $a, array $b): int => [
            ['pending' => 0, 'confirmed' => 1, 'paid' => 2, 'rejected' => 3][(string) ($a['status'] ?? 'pending')] ?? 9,
            (string) ($b['period_end'] ?? ''),
            (int) ($b['id'] ?? 0),
        ] <=> [
            ['pending' => 0, 'confirmed' => 1, 'paid' => 2, 'rejected' => 3][(string) ($b['status'] ?? 'pending')] ?? 9,
            (string) ($a['period_end'] ?? ''),
            (int) ($a['id'] ?? 0),
        ]);

        return [
            'summary' => $summary,
            'rows' => array_slice($rows, 0, 300),
            'preview_rows' => $this->buildAgentSettlementRows($data, date('Y-m-01'), date('Y-m-d'), 0, 'revenue_share', 10, ''),
        ];
    }

    private function buildAgentSettlementRows(array $data, string $periodStart, string $periodEnd, int $targetAgentId, string $settlementMode, float $commissionRate, string $remark): array
    {
        $agents = array_values((array) ($data['agents'] ?? []));
        $agentById = [];
        foreach ($agents as $agent) {
            $agentById[(int) ($agent['id'] ?? 0)] = $agent;
        }
        $tree = $this->agentTree($agents);
        $linkAgentById = [];
        foreach ((array) ($data['promotion_links'] ?? []) as $link) {
            $linkAgentById[(int) ($link['id'] ?? 0)] = (int) ($link['agent_id'] ?? 0);
        }
        $rows = [];
        $settledStatuses = ['paid', 'partial_refunded', 'refunded'];
        foreach ((array) ($data['orders'] ?? []) as $order) {
            if (!empty($order['is_test']) || !in_array((string) ($order['status'] ?? 'pending'), $settledStatuses, true)) {
                continue;
            }
            $dateText = (string) (($order['paid_at'] ?? '') ?: ($order['created_at'] ?? ''));
            $date = $this->settlementDateString($dateText);
            if ($date === '' || $date < $periodStart || $date > $periodEnd) {
                continue;
            }
            $agentId = max(0, (int) ($order['agent_id'] ?? 0));
            if ($agentId <= 0) {
                $agentId = $linkAgentById[(int) ($order['promotion_link_id'] ?? 0)] ?? 0;
            }
            if ($agentId <= 0) {
                continue;
            }
            $lineage = $tree[$agentId] ?? ['agent_id' => $agentId, 'leader_id' => 0, 'business_id' => 0];
            if ($targetAgentId > 0 && !in_array($targetAgentId, [(int) ($lineage['agent_id'] ?? 0), (int) ($lineage['leader_id'] ?? 0), (int) ($lineage['business_id'] ?? 0), $agentId], true)) {
                continue;
            }
            $rowAgentId = (int) ($lineage['agent_id'] ?? $agentId);
            if ($rowAgentId <= 0) {
                $rowAgentId = $agentId;
            }
            $agent = $agentById[$rowAgentId] ?? [];
            $rows[$rowAgentId] ??= $this->blankAgentSettlementRow($rowAgentId, $agent, $lineage, $periodStart, $periodEnd, $settlementMode, $commissionRate, $remark);
            $amount = max(0.0, (float) ($order['amount'] ?? 0));
            $refund = min($amount, max(0.0, (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0)));
            $rows[$rowAgentId]['order_count']++;
            $rows[$rowAgentId]['gross_revenue'] += $amount;
            $rows[$rowAgentId]['refund_amount'] += $refund;
            $rows[$rowAgentId]['net_revenue'] += max(0.0, $amount - $refund);
            $userId = (int) ($order['user_id'] ?? 0);
            if ($userId > 0) {
                $rows[$rowAgentId]['paid_users'][$userId] = true;
            }
        }

        foreach ((array) ($data['promotion_costs'] ?? []) as $cost) {
            $date = $this->settlementDateString((string) ($cost['date'] ?? $cost['created_at'] ?? ''));
            if ($date === '' || $date < $periodStart || $date > $periodEnd) {
                continue;
            }
            $agentId = max(0, (int) ($cost['agent_id'] ?? 0));
            if ($agentId <= 0) {
                $agentId = $linkAgentById[(int) ($cost['promotion_link_id'] ?? 0)] ?? 0;
            }
            if ($agentId <= 0) {
                continue;
            }
            $lineage = $tree[$agentId] ?? ['agent_id' => $agentId, 'leader_id' => 0, 'business_id' => 0];
            if ($targetAgentId > 0 && !in_array($targetAgentId, [(int) ($lineage['agent_id'] ?? 0), (int) ($lineage['leader_id'] ?? 0), (int) ($lineage['business_id'] ?? 0), $agentId], true)) {
                continue;
            }
            $rowAgentId = (int) ($lineage['agent_id'] ?? $agentId);
            if ($rowAgentId <= 0) {
                $rowAgentId = $agentId;
            }
            $agent = $agentById[$rowAgentId] ?? [];
            $rows[$rowAgentId] ??= $this->blankAgentSettlementRow($rowAgentId, $agent, $lineage, $periodStart, $periodEnd, $settlementMode, $commissionRate, $remark);
            $rows[$rowAgentId]['cost_amount'] += max(0.0, (float) ($cost['amount'] ?? 0));
        }

        foreach ($rows as &$row) {
            $row['paid_user_count'] = count((array) ($row['paid_users'] ?? []));
            unset($row['paid_users']);
            foreach (['gross_revenue', 'refund_amount', 'net_revenue', 'cost_amount'] as $key) {
                $row[$key] = round(max(0.0, (float) ($row[$key] ?? 0)), 2);
            }
            $row['commission_base'] = $settlementMode === 'profit_share'
                ? round(max(0.0, (float) $row['net_revenue'] - (float) $row['cost_amount']), 2)
                : round(max(0.0, (float) $row['net_revenue']), 2);
            $row['commission_amount'] = round((float) $row['commission_base'] * (float) $row['commission_rate'] / 100, 2);
        }
        unset($row);

        $rows = array_values(array_filter($rows, static fn (array $row): bool => (float) ($row['commission_base'] ?? 0) > 0 || (int) ($row['order_count'] ?? 0) > 0));
        usort($rows, static fn (array $a, array $b): int => [(float) $b['commission_amount'], (float) $b['net_revenue'], (int) $b['order_count']] <=> [(float) $a['commission_amount'], (float) $a['net_revenue'], (int) $a['order_count']]);

        return $rows;
    }

    private function blankAgentSettlementRow(int $agentId, array $agent, array $lineage, string $periodStart, string $periodEnd, string $settlementMode, float $commissionRate, string $remark): array
    {
        return [
            'fingerprint' => 'agent:' . $agentId . ':' . $periodStart . ':' . $periodEnd . ':' . $settlementMode,
            'agent_id' => $agentId,
            'agent_name' => (string) (($agent['name'] ?? '') ?: ($lineage['agent_name'] ?? '投放账号')),
            'agent_role' => (string) (($agent['role'] ?? '') ?: 'agent'),
            'leader_id' => max(0, (int) ($lineage['leader_id'] ?? 0)),
            'leader_name' => (string) ($lineage['leader_name'] ?? ''),
            'business_id' => max(0, (int) ($lineage['business_id'] ?? 0)),
            'business_name' => (string) ($lineage['business_name'] ?? ''),
            'period_start' => $periodStart,
            'period_end' => $periodEnd,
            'settlement_mode' => $settlementMode,
            'order_count' => 0,
            'paid_user_count' => 0,
            'paid_users' => [],
            'gross_revenue' => 0.0,
            'refund_amount' => 0.0,
            'net_revenue' => 0.0,
            'cost_amount' => 0.0,
            'commission_base' => 0.0,
            'commission_rate' => $commissionRate,
            'commission_amount' => 0.0,
            'remark' => $remark,
        ];
    }

    private function settlementDateFromPayload(array $payload, array $keys, string $fallback): string
    {
        foreach ($keys as $key) {
            $date = $this->settlementDateString((string) ($payload[$key] ?? ''));
            if ($date !== '') {
                return $date;
            }
        }

        return $fallback;
    }

    private function settlementDateString(string $value): string
    {
        $value = trim($value);
        if ($value === '') {
            return '';
        }
        $timestamp = strtotime(str_replace('T', ' ', $value));
        if ($timestamp === false) {
            return '';
        }

        return date('Y-m-d', $timestamp);
    }

    private function agentDashboard(array $data, array $promotionDashboard): array
    {
        $agents = array_values((array) ($data['agents'] ?? []));
        $tree = $this->agentTree($agents);
        $rows = [];
        foreach ($agents as $agent) {
            $id = (int) ($agent['id'] ?? 0);
            $rows[$id] = [
                'agent' => $agent,
                'id' => $id,
                'name' => (string) ($agent['name'] ?? '投放账号'),
                'role' => (string) ($agent['role'] ?? 'agent'),
                'parent_id' => (int) ($agent['parent_id'] ?? 0),
                'status' => (string) ($agent['status'] ?? 'active'),
                'link_count' => 0,
                'visits' => 0,
                'registers' => 0,
                'add_desktop' => 0,
                'paid_orders' => 0,
                'revenue' => 0.0,
                'cost' => 0.0,
                'recovery_rate' => null,
                'add_desktop_cost' => null,
                'order_cost' => null,
            ];
        }

        foreach ((array) ($promotionDashboard['rows'] ?? []) as $linkRow) {
            $ids = array_values(array_unique(array_filter([
                (int) ($linkRow['agent_id'] ?? 0),
                (int) ($linkRow['leader_id'] ?? 0),
                (int) ($linkRow['business_id'] ?? 0),
            ], static fn (int $id): bool => $id > 0)));
            foreach ($ids as $id) {
                if (!isset($rows[$id])) {
                    continue;
                }
                $rows[$id]['link_count']++;
                foreach (['visits', 'registers', 'add_desktop', 'paid_orders'] as $metric) {
                    $rows[$id][$metric] += (int) ($linkRow[$metric] ?? 0);
                }
                $rows[$id]['revenue'] += (float) ($linkRow['revenue'] ?? 0);
                $rows[$id]['cost'] += (float) ($linkRow['cost'] ?? 0);
            }
        }

        foreach ($rows as &$row) {
            $row['revenue'] = round((float) $row['revenue'], 2);
            $row['cost'] = round((float) $row['cost'], 2);
            $row['recovery_rate'] = $row['cost'] > 0 ? round(((float) $row['revenue'] / (float) $row['cost']) * 100, 2) : null;
            $row['add_desktop_cost'] = (int) $row['add_desktop'] > 0 ? round(((float) $row['cost'] / (int) $row['add_desktop']), 2) : null;
            $row['order_cost'] = (int) $row['paid_orders'] > 0 ? round(((float) $row['cost'] / (int) $row['paid_orders']), 2) : null;
            $row['path'] = $tree[(int) $row['id']]['path'] ?? (string) $row['name'];
        }
        unset($row);

        usort($rows, static fn (array $a, array $b): int => [
            ['business' => 0, 'leader' => 1, 'agent' => 2][(string) ($a['role'] ?? 'agent')] ?? 9,
            (int) ($a['parent_id'] ?? 0),
            (int) ($a['id'] ?? 0),
        ] <=> [
            ['business' => 0, 'leader' => 1, 'agent' => 2][(string) ($b['role'] ?? 'agent')] ?? 9,
            (int) ($b['parent_id'] ?? 0),
            (int) ($b['id'] ?? 0),
        ]);

        return [
            'rows' => $rows,
            'summary' => [
                'business_count' => count(array_filter($agents, static fn (array $agent): bool => (string) ($agent['role'] ?? '') === 'business')),
                'leader_count' => count(array_filter($agents, static fn (array $agent): bool => (string) ($agent['role'] ?? '') === 'leader')),
                'agent_count' => count(array_filter($agents, static fn (array $agent): bool => (string) ($agent['role'] ?? '') === 'agent')),
            ],
        ];
    }

    private function hotRankDashboard(array $data, array $configs): array
    {
        $configs = array_values(array_filter($configs, static fn (mixed $item): bool => is_array($item)));
        usort($configs, static fn (array $a, array $b): int => [(int) ($a['sort'] ?? 0), (int) ($a['id'] ?? 0)] <=> [(int) ($b['sort'] ?? 0), (int) ($b['id'] ?? 0)]);

        $summary = [
            'config_count' => count($configs),
            'active_count' => 0,
            'paused_count' => 0,
            'mixed_config_count' => 0,
            'drama_config_count' => 0,
            'novel_config_count' => 0,
            'drama_count' => count((array) ($data['dramas'] ?? [])),
            'novel_count' => count((array) ($data['novels'] ?? [])),
        ];
        $configRows = [];
        $rowsByConfig = [];
        foreach ($configs as $config) {
            $status = (string) ($config['status'] ?? 'active');
            if ($status === 'active') {
                $summary['active_count']++;
            } else {
                $summary['paused_count']++;
            }
            $contentType = (string) ($config['content_type'] ?? 'mixed');
            if ($contentType === 'drama') {
                $summary['drama_config_count']++;
            } elseif ($contentType === 'novel') {
                $summary['novel_config_count']++;
            } else {
                $summary['mixed_config_count']++;
            }

            $rows = $this->hotRankRowsForConfig($data, $config);
            $configKey = (string) ($config['id'] ?? $config['rank_key'] ?? count($configRows) + 1);
            $rowsByConfig[$configKey] = $rows;
            $configRows[] = [
                'config' => $config,
                'rows' => array_slice($rows, 0, max(1, min(50, (int) ($config['limit'] ?? 10)))),
                'row_count' => count($rows),
                'top_row' => $rows[0] ?? [],
            ];
        }

        return [
            'summary' => $summary,
            'configs' => $configRows,
            'rows_by_config' => $rowsByConfig,
            'generated_at' => date('Y-m-d H:i:s'),
        ];
    }

    private function hotRankRowsForConfig(array $data, array $config): array
    {
        $contentType = (string) ($config['content_type'] ?? 'mixed');
        $contentType = in_array($contentType, ['mixed', 'drama', 'novel'], true) ? $contentType : 'mixed';
        $algorithm = (string) ($config['algorithm'] ?? 'hot_score');
        $algorithm = in_array($algorithm, ['hot_score', 'views', 'unlock', 'revenue', 'manual'], true) ? $algorithm : 'hot_score';
        $limit = max(1, min(50, (int) ($config['limit'] ?? 10)));
        $minScore = max(0, (int) ($config['min_score'] ?? 0));
        $matchesContentType = static fn (string $type): bool => $contentType === 'mixed' || $contentType === $type;

        $contentIndex = $this->hotRankContentIndex($data);
        $rows = [];
        foreach ($contentIndex as $key => $content) {
            if (!$matchesContentType((string) ($content['content_type'] ?? 'drama'))) {
                continue;
            }
            $rows[$key] = $this->hotRankBaseRow((string) ($content['content_type'] ?? 'drama'), (int) ($content['content_id'] ?? 0), $content);
        }

        $analyticsData = $this->filterDashboardDataForAnalytics($data, $this->hotRankAnalyticsFilters($config));
        $playStats = $this->playStatsDashboard($analyticsData);
        foreach ((array) ($playStats['rows'] ?? []) as $playRow) {
            $type = (string) ($playRow['content_type'] ?? 'drama') === 'novel' ? 'novel' : 'drama';
            if (!$matchesContentType($type)) {
                continue;
            }
            $contentId = max(0, (int) ($playRow['content_id'] ?? 0));
            $key = $type . ':' . $contentId;
            $rows[$key] ??= $this->hotRankBaseRow($type, $contentId, $contentIndex[$key] ?? []);
            foreach (['views', 'legacy_views', 'watch_records', 'watch_user_count', 'completion_records', 'lock_exposures', 'order_created', 'unlock_success', 'hot_score'] as $metric) {
                $rows[$key][$metric] = max((int) ($rows[$key][$metric] ?? 0), (int) ($playRow[$metric] ?? 0));
            }
            $rows[$key]['unlock_rate'] = max((float) ($rows[$key]['unlock_rate'] ?? 0), (float) ($playRow['unlock_rate'] ?? 0));
            $rows[$key]['avg_progress'] = max((float) ($rows[$key]['avg_progress'] ?? 0), (float) ($playRow['avg_progress'] ?? 0));
        }

        $conversion = $this->contentConversionDashboard($analyticsData);
        foreach ((array) ($conversion['rows'] ?? []) as $conversionRow) {
            $type = (string) ($conversionRow['content_type'] ?? 'drama') === 'novel' ? 'novel' : 'drama';
            if (!$matchesContentType($type)) {
                continue;
            }
            $contentId = max(0, (int) ($conversionRow['content_id'] ?? 0));
            $key = $type . ':' . $contentId;
            $rows[$key] ??= $this->hotRankBaseRow($type, $contentId, $contentIndex[$key] ?? []);
            foreach (['lock_exposures', 'orders', 'unlocks', 'paid_user_count'] as $metric) {
                $rows[$key][$metric] = max((int) ($rows[$key][$metric] ?? 0), (int) ($conversionRow[$metric] ?? 0));
            }
            foreach (['revenue', 'promotion_revenue', 'lock_rate', 'order_rate', 'unlock_rate', 'arppu'] as $metric) {
                $rows[$key][$metric] = max((float) ($rows[$key][$metric] ?? 0), (float) ($conversionRow[$metric] ?? 0));
            }
        }

        foreach ((array) ($config['pinned_items'] ?? []) as $pinned) {
            $type = (string) ($pinned['content_type'] ?? 'drama') === 'novel' ? 'novel' : 'drama';
            if (!$matchesContentType($type)) {
                continue;
            }
            $contentId = max(0, (int) ($pinned['content_id'] ?? 0));
            if ($contentId <= 0) {
                continue;
            }
            $key = $type . ':' . $contentId;
            $rows[$key] ??= $this->hotRankBaseRow($type, $contentId, $contentIndex[$key] ?? []);
            $rows[$key]['pinned'] = true;
            $rows[$key]['pinned_sort'] = (int) ($pinned['sort'] ?? 100);
            $rows[$key]['pinned_remark'] = (string) ($pinned['remark'] ?? '');
        }

        $ranked = [];
        foreach ($rows as $row) {
            $row['score'] = $this->hotRankScore($row, $algorithm);
            if ($algorithm === 'manual' && empty($row['pinned'])) {
                continue;
            }
            if (empty($row['pinned']) && (int) ($row['score'] ?? 0) < $minScore) {
                continue;
            }
            $ranked[] = $row;
        }

        usort($ranked, static function (array $a, array $b): int {
            $aPinned = !empty($a['pinned']);
            $bPinned = !empty($b['pinned']);
            if ($aPinned !== $bPinned) {
                return $aPinned ? -1 : 1;
            }
            if ($aPinned && $bPinned) {
                $pinnedCompare = [(int) ($a['pinned_sort'] ?? 100), (int) ($a['content_id'] ?? 0)] <=> [(int) ($b['pinned_sort'] ?? 100), (int) ($b['content_id'] ?? 0)];
                if ($pinnedCompare !== 0) {
                    return $pinnedCompare;
                }
            }

            $aViews = (int) ($a['views'] ?? 0) + (int) ($a['legacy_views'] ?? 0) + (int) ($a['watch_records'] ?? 0);
            $bViews = (int) ($b['views'] ?? 0) + (int) ($b['legacy_views'] ?? 0) + (int) ($b['watch_records'] ?? 0);
            $aUnlocks = max((int) ($a['unlock_success'] ?? 0), (int) ($a['unlocks'] ?? 0));
            $bUnlocks = max((int) ($b['unlock_success'] ?? 0), (int) ($b['unlocks'] ?? 0));

            return [
                (int) ($b['score'] ?? 0),
                (float) ($b['revenue'] ?? 0),
                $bUnlocks,
                $bViews,
                (int) ($a['content_id'] ?? 0) * -1,
            ] <=> [
                (int) ($a['score'] ?? 0),
                (float) ($a['revenue'] ?? 0),
                $aUnlocks,
                $aViews,
                (int) ($b['content_id'] ?? 0) * -1,
            ];
        });

        $ranked = array_slice($ranked, 0, $limit);
        foreach ($ranked as $index => &$row) {
            $row['rank'] = $index + 1;
            $row['revenue'] = round((float) ($row['revenue'] ?? 0), 2);
            $row['promotion_revenue'] = round((float) ($row['promotion_revenue'] ?? 0), 2);
        }
        unset($row);

        return $ranked;
    }

    private function hotRankBaseRow(string $contentType, int $contentId, array $content = []): array
    {
        $contentType = $contentType === 'novel' ? 'novel' : 'drama';

        return [
            'key' => $contentType . ':' . $contentId,
            'content_type' => $contentType,
            'content_label' => $contentType === 'novel' ? '小说' : '短剧',
            'content_id' => $contentId,
            'title' => (string) (($content['title'] ?? '') ?: (($contentType === 'novel' ? '小说' : '短剧') . ' #' . $contentId)),
            'cover' => (string) ($content['cover'] ?? ''),
            'url' => (string) (($content['url'] ?? '') ?: ('/?route=' . ($contentType === 'novel' ? 'novel' : 'drama') . '&id=' . $contentId)),
            'status' => (string) ($content['status'] ?? ''),
            'category' => (string) ($content['category'] ?? ''),
            'tags' => array_values((array) ($content['tags'] ?? [])),
            'unit_count' => max(0, (int) ($content['unit_count'] ?? 0)),
            'unit_label' => $contentType === 'novel' ? '章' : '集',
            'views' => 0,
            'legacy_views' => 0,
            'watch_records' => 0,
            'watch_user_count' => 0,
            'completion_records' => 0,
            'lock_exposures' => 0,
            'order_created' => 0,
            'unlock_success' => 0,
            'unlock_rate' => 0.0,
            'avg_progress' => 0.0,
            'hot_score' => 0,
            'orders' => 0,
            'unlocks' => 0,
            'paid_user_count' => 0,
            'revenue' => 0.0,
            'promotion_revenue' => 0.0,
            'lock_rate' => 0.0,
            'order_rate' => 0.0,
            'arppu' => 0.0,
            'score' => 0,
            'pinned' => false,
            'pinned_sort' => 100,
            'pinned_remark' => '',
        ];
    }

    private function hotRankAnalyticsFilters(array $config): array
    {
        $timezone = new \DateTimeZone('Asia/Shanghai');
        $today = new \DateTimeImmutable('today', $timezone);
        $timeWindow = (string) ($config['time_window'] ?? 'last_7_days');
        $filters = ['active' => true, 'date_label' => '全部时间'];
        $start = null;
        $end = null;
        if ($timeWindow === 'today') {
            $start = $today;
            $end = $today;
            $filters['date_label'] = '今天';
        } elseif ($timeWindow === 'yesterday') {
            $start = $today->modify('-1 day');
            $end = $start;
            $filters['date_label'] = '昨天';
        } elseif ($timeWindow === 'last_7_days') {
            $start = $today->modify('-6 days');
            $end = $today;
            $filters['date_label'] = '近7天';
        } elseif ($timeWindow === 'last_30_days') {
            $start = $today->modify('-29 days');
            $end = $today;
            $filters['date_label'] = '近30天';
        } elseif ($timeWindow === 'this_month') {
            $start = $today->modify('first day of this month');
            $end = $today;
            $filters['date_label'] = '本月';
        }
        if ($start instanceof \DateTimeImmutable && $end instanceof \DateTimeImmutable) {
            $filters['date_start'] = $start->format('Y-m-d');
            $filters['date_end'] = $end->format('Y-m-d');
        }

        $appKey = $this->normalizeAppKey((string) ($config['app_key'] ?? 'all'));
        if ($appKey !== '' && $appKey !== 'all') {
            $filters['app_key'] = $appKey;
        }

        return $filters;
    }

    private function hotRankContentIndex(array $data): array
    {
        $items = [];
        foreach ((array) ($data['dramas'] ?? []) as $drama) {
            $id = (int) ($drama['id'] ?? 0);
            if ($id <= 0 || in_array((string) ($drama['status'] ?? 'online'), ['offline', 'disabled', 'deleted'], true)) {
                continue;
            }
            $items['drama:' . $id] = [
                'content_type' => 'drama',
                'content_id' => $id,
                'title' => (string) ($drama['title'] ?? '未命名短剧'),
                'cover' => (string) ($drama['cover'] ?? ''),
                'url' => '/?route=drama&id=' . $id,
                'status' => (string) ($drama['status'] ?? 'online'),
                'category' => (string) ($drama['category'] ?? ''),
                'tags' => array_values((array) ($drama['tags'] ?? [])),
                'unit_count' => count((array) ($drama['episodes'] ?? [])),
            ];
        }
        foreach ((array) ($data['novels'] ?? []) as $novel) {
            $id = (int) ($novel['id'] ?? 0);
            if ($id <= 0 || in_array((string) ($novel['status'] ?? 'online'), ['offline', 'disabled', 'deleted'], true)) {
                continue;
            }
            $items['novel:' . $id] = [
                'content_type' => 'novel',
                'content_id' => $id,
                'title' => (string) ($novel['title'] ?? '未命名小说'),
                'cover' => (string) ($novel['cover'] ?? ''),
                'url' => '/?route=novel&id=' . $id,
                'status' => (string) ($novel['status'] ?? 'online'),
                'category' => (string) ($novel['category'] ?? ''),
                'tags' => array_values((array) ($novel['tags'] ?? [])),
                'unit_count' => count((array) ($novel['chapters'] ?? [])),
            ];
        }

        return $items;
    }

    private function hotRankScore(array $row, string $algorithm): int
    {
        $views = (int) ($row['views'] ?? 0) + (int) ($row['legacy_views'] ?? 0) + (int) ($row['watch_records'] ?? 0);
        $unlocks = max((int) ($row['unlock_success'] ?? 0), (int) ($row['unlocks'] ?? 0));
        $revenue = max(0.0, (float) ($row['revenue'] ?? 0));

        return match ($algorithm) {
            'views' => $views,
            'unlock' => $unlocks,
            'revenue' => (int) round($revenue * 100),
            'manual' => !empty($row['pinned']) ? max(1, 1000000 - (int) ($row['pinned_sort'] ?? 100)) : 0,
            default => max(0, (int) ($row['hot_score'] ?? 0))
                + $views
                + (int) ($row['completion_records'] ?? 0) * 2
                + $unlocks * 8
                + (int) ($row['paid_user_count'] ?? 0) * 5
                + (int) round($revenue * 10),
        };
    }

    private function userGrowthDashboard(array $data): array
    {
        $timezone = new \DateTimeZone('Asia/Shanghai');
        $users = array_values((array) ($data['users'] ?? []));
        $events = array_values((array) ($data['promotion_events'] ?? []));
        $orders = array_values(array_filter((array) ($data['orders'] ?? []), static fn (array $order): bool => empty($order['is_test'])));
        $costs = array_values((array) ($data['promotion_costs'] ?? []));
        $paidStatuses = ['paid', 'partial_refunded', 'refunded'];

        $linkById = [];
        $linkByCode = [];
        foreach ((array) ($data['promotion_links'] ?? []) as $link) {
            $linkId = (int) ($link['id'] ?? 0);
            if ($linkId > 0) {
                $linkById[$linkId] = $link;
            }
            $code = (string) ($link['code'] ?? '');
            if ($code !== '') {
                $linkByCode[$code] = $link;
            }
        }

        $dateKey = function (array $source, array $keys = ['created_at']) use ($timezone): string {
            foreach ($keys as $key) {
                $value = trim((string) ($source[$key] ?? ''));
                if ($value === '') {
                    continue;
                }
                $date = $this->parseAnalyticsDateTime($value, $timezone);
                if ($date instanceof \DateTimeImmutable) {
                    return $date->format('Y-m-d');
                }
            }

            return '';
        };

        $sourceFrom = function (array $source) use ($linkById, $linkByCode): array {
            $linkId = max(0, (int) ($source['promotion_link_id'] ?? 0));
            $code = preg_replace('/[^a-zA-Z0-9_-]+/', '', (string) (($source['code'] ?? '') ?: ($source['promotion_code'] ?? '')));
            $link = [];
            if ($linkId > 0 && isset($linkById[$linkId])) {
                $link = $linkById[$linkId];
            } elseif ($code !== '' && isset($linkByCode[$code])) {
                $link = $linkByCode[$code];
                $linkId = (int) ($link['id'] ?? $linkId);
            }
            if (!empty($link)) {
                $code = $code !== '' ? $code : (string) ($link['code'] ?? '');
            }

            $meta = $this->trafficMetaFromPayload($link);
            $meta = $this->trafficMetaFromPayload($source, $meta);
            $appKey = $this->normalizeAppKey((string) (($source['app_key'] ?? '') ?: ($meta['media_app_id'] ?? '')));
            $nameParts = array_values(array_filter([
                (string) ($link['name'] ?? ''),
                $code !== '' ? '码 ' . $code : '',
                (string) (($meta['traffic_platform'] ?? '') ?: ''),
                (string) (($meta['channel_id'] ?? '') ?: ''),
            ], static fn (string $part): bool => trim($part) !== ''));
            $keyParts = [
                $appKey,
                (string) ($meta['traffic_platform'] ?? ''),
                (string) ($meta['channel_id'] ?? ''),
                (string) ($meta['ad_id'] ?? ''),
                (string) ($meta['material_id'] ?? ''),
                (string) $linkId,
                $code,
            ];
            $key = implode('|', $keyParts);
            if (trim(str_replace('|', '', $key)) === '') {
                $key = 'organic';
            }

            return [
                'key' => $key,
                'name' => $nameParts === [] ? '自然/未归因' : implode(' / ', array_slice($nameParts, 0, 3)),
                'app_key' => $appKey,
                'promotion_link_id' => $linkId,
                'code' => $code,
                'traffic_platform' => (string) ($meta['traffic_platform'] ?? ''),
                'channel_id' => (string) ($meta['channel_id'] ?? ''),
                'ad_id' => (string) ($meta['ad_id'] ?? ''),
                'material_id' => (string) ($meta['material_id'] ?? ''),
            ];
        };

        $blankDaily = static fn (string $date): array => [
            'date' => $date,
            'new_users' => 0,
            'visits' => 0,
            'registers' => 0,
            'add_desktop' => 0,
            'activations' => 0,
            'paid_users' => [],
            'paid_user_count' => 0,
            'paid_orders' => 0,
            'revenue' => 0.0,
            'cost' => 0.0,
            'pay_rate' => 0.0,
            'register_rate' => 0.0,
            'add_desktop_rate' => 0.0,
            'activation_rate' => 0.0,
            'recovery_rate' => null,
        ];
        $blankSource = static fn (array $source): array => [
            'key' => (string) ($source['key'] ?? 'organic'),
            'name' => (string) ($source['name'] ?? '自然/未归因'),
            'app_key' => (string) ($source['app_key'] ?? ''),
            'promotion_link_id' => (int) ($source['promotion_link_id'] ?? 0),
            'code' => (string) ($source['code'] ?? ''),
            'traffic_platform' => (string) ($source['traffic_platform'] ?? ''),
            'channel_id' => (string) ($source['channel_id'] ?? ''),
            'ad_id' => (string) ($source['ad_id'] ?? ''),
            'material_id' => (string) ($source['material_id'] ?? ''),
            'new_users' => 0,
            'visits' => 0,
            'registers' => 0,
            'add_desktop' => 0,
            'activations' => 0,
            'paid_users' => [],
            'paid_user_count' => 0,
            'paid_orders' => 0,
            'revenue' => 0.0,
            'cost' => 0.0,
            'clicks' => 0,
            'impressions' => 0,
            'pay_rate' => 0.0,
            'register_rate' => 0.0,
            'add_desktop_rate' => 0.0,
            'activation_rate' => 0.0,
            'recovery_rate' => null,
            'new_user_cost' => null,
            'add_desktop_cost' => null,
            'order_cost' => null,
        ];

        $userSources = [];
        $rememberUserSource = function (array $source, string $timeText) use (&$userSources, $sourceFrom, $timezone): void {
            $userId = (int) ($source['user_id'] ?? 0);
            if ($userId <= 0) {
                return;
            }
            $date = $this->parseAnalyticsDateTime($timeText, $timezone);
            $timestamp = $date instanceof \DateTimeImmutable ? $date->getTimestamp() : PHP_INT_MAX;
            if (!isset($userSources[$userId]) || $timestamp < (int) ($userSources[$userId]['timestamp'] ?? PHP_INT_MAX)) {
                $userSources[$userId] = [
                    'timestamp' => $timestamp,
                    'source' => $sourceFrom($source),
                ];
            }
        };
        foreach ($events as $event) {
            $rememberUserSource($event, (string) ($event['created_at'] ?? ''));
        }
        foreach ($orders as $order) {
            $rememberUserSource($order, (string) (($order['created_at'] ?? '') ?: ($order['paid_at'] ?? '')));
        }

        $dailyRows = [];
        $sourceRows = [];
        $summaryPaidUsers = [];
        $summary = [
            'new_users' => 0,
            'visits' => 0,
            'registers' => 0,
            'add_desktop' => 0,
            'activations' => 0,
            'paid_users' => 0,
            'paid_orders' => 0,
            'revenue' => 0.0,
            'cost' => 0.0,
            'pay_rate' => 0.0,
            'register_rate' => 0.0,
            'add_desktop_rate' => 0.0,
            'activation_rate' => 0.0,
            'recovery_rate' => null,
            'new_user_cost' => null,
            'add_desktop_cost' => null,
            'order_cost' => null,
        ];

        $ensureDaily = static function (string $date) use (&$dailyRows, $blankDaily): void {
            if ($date !== '' && !isset($dailyRows[$date])) {
                $dailyRows[$date] = $blankDaily($date);
            }
        };
        $ensureSource = static function (array $source) use (&$sourceRows, $blankSource): void {
            $key = (string) ($source['key'] ?? 'organic');
            if (!isset($sourceRows[$key])) {
                $sourceRows[$key] = $blankSource($source);
            }
        };

        $organicSource = $sourceFrom([]);
        foreach ($users as $user) {
            $userId = (int) ($user['id'] ?? 0);
            $date = $dateKey($user, ['created_at']);
            if ($date !== '') {
                $ensureDaily($date);
                $dailyRows[$date]['new_users']++;
                $summary['new_users']++;
            }
            $source = $userSources[$userId]['source'] ?? $organicSource;
            $ensureSource($source);
            $sourceRows[$source['key']]['new_users']++;
        }

        $eventMap = [
            'visit' => 'visits',
            'register' => 'registers',
            'add_desktop' => 'add_desktop',
            'activate' => 'activations',
        ];
        foreach ($events as $event) {
            $eventType = (string) ($event['event'] ?? '');
            if (!isset($eventMap[$eventType])) {
                continue;
            }
            $metric = $eventMap[$eventType];
            $date = $dateKey($event, ['created_at']);
            if ($date !== '') {
                $ensureDaily($date);
                $dailyRows[$date][$metric]++;
            }
            $summary[$metric]++;
            $source = $sourceFrom($event);
            $ensureSource($source);
            $sourceRows[$source['key']][$metric]++;
        }

        foreach ($orders as $order) {
            if (!in_array((string) ($order['status'] ?? 'pending'), $paidStatuses, true)) {
                continue;
            }
            $date = $dateKey($order, ['paid_at', 'created_at']);
            $amount = max(0.0, (float) ($order['amount'] ?? 0));
            $refund = min($amount, max(0.0, (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0)));
            $net = max(0.0, $amount - $refund);
            $userId = (int) ($order['user_id'] ?? 0);
            if ($date !== '') {
                $ensureDaily($date);
                $dailyRows[$date]['paid_orders']++;
                $dailyRows[$date]['revenue'] += $net;
                if ($userId > 0) {
                    $dailyRows[$date]['paid_users'][$userId] = true;
                }
            }
            $summary['paid_orders']++;
            $summary['revenue'] += $net;
            if ($userId > 0) {
                $summaryPaidUsers[$userId] = true;
            }
            $source = $sourceFrom($order);
            $ensureSource($source);
            $sourceRows[$source['key']]['paid_orders']++;
            $sourceRows[$source['key']]['revenue'] += $net;
            if ($userId > 0) {
                $sourceRows[$source['key']]['paid_users'][$userId] = true;
            }
        }

        foreach ($costs as $cost) {
            $date = $dateKey($cost, ['date', 'created_at']);
            $amount = max(0.0, (float) ($cost['amount'] ?? 0));
            if ($date !== '') {
                $ensureDaily($date);
                $dailyRows[$date]['cost'] += $amount;
            }
            $summary['cost'] += $amount;
            $source = $sourceFrom($cost);
            $ensureSource($source);
            $sourceRows[$source['key']]['cost'] += $amount;
            $sourceRows[$source['key']]['clicks'] += max(0, (int) ($cost['clicks'] ?? 0));
            $sourceRows[$source['key']]['impressions'] += max(0, (int) ($cost['impressions'] ?? 0));
        }

        $finalizeRow = static function (array $row): array {
            $row['paid_user_count'] = count((array) ($row['paid_users'] ?? []));
            unset($row['paid_users']);
            $row['revenue'] = round((float) ($row['revenue'] ?? 0), 2);
            $row['cost'] = round((float) ($row['cost'] ?? 0), 2);
            $row['pay_rate'] = (int) ($row['new_users'] ?? 0) > 0 ? round(((int) ($row['paid_user_count'] ?? 0) / (int) $row['new_users']) * 100, 2) : 0.0;
            $row['register_rate'] = (int) ($row['visits'] ?? 0) > 0 ? round(((int) ($row['registers'] ?? 0) / (int) $row['visits']) * 100, 2) : 0.0;
            $row['add_desktop_rate'] = (int) ($row['visits'] ?? 0) > 0 ? round(((int) ($row['add_desktop'] ?? 0) / (int) $row['visits']) * 100, 2) : 0.0;
            $row['activation_rate'] = (int) ($row['add_desktop'] ?? 0) > 0 ? round(((int) ($row['activations'] ?? 0) / (int) $row['add_desktop']) * 100, 2) : 0.0;
            $row['recovery_rate'] = (float) ($row['cost'] ?? 0) > 0 ? round(((float) ($row['revenue'] ?? 0) / (float) $row['cost']) * 100, 2) : null;
            $row['new_user_cost'] = (int) ($row['new_users'] ?? 0) > 0 ? round((float) ($row['cost'] ?? 0) / (int) $row['new_users'], 2) : null;
            $row['add_desktop_cost'] = (int) ($row['add_desktop'] ?? 0) > 0 ? round((float) ($row['cost'] ?? 0) / (int) $row['add_desktop'], 2) : null;
            $row['order_cost'] = (int) ($row['paid_orders'] ?? 0) > 0 ? round((float) ($row['cost'] ?? 0) / (int) $row['paid_orders'], 2) : null;

            return $row;
        };

        $dailyRows = array_map($finalizeRow, array_values($dailyRows));
        usort($dailyRows, static fn (array $a, array $b): int => strcmp((string) ($b['date'] ?? ''), (string) ($a['date'] ?? '')));
        $sourceRows = array_map($finalizeRow, array_values($sourceRows));
        usort($sourceRows, static fn (array $a, array $b): int => [
            (int) ($b['new_users'] ?? 0),
            (float) ($b['revenue'] ?? 0),
            (int) ($b['registers'] ?? 0),
        ] <=> [
            (int) ($a['new_users'] ?? 0),
            (float) ($a['revenue'] ?? 0),
            (int) ($a['registers'] ?? 0),
        ]);

        $summary['paid_users'] = count($summaryPaidUsers);
        $summary['revenue'] = round((float) $summary['revenue'], 2);
        $summary['cost'] = round((float) $summary['cost'], 2);
        $summary['pay_rate'] = (int) $summary['new_users'] > 0 ? round(((int) $summary['paid_users'] / (int) $summary['new_users']) * 100, 2) : 0.0;
        $summary['register_rate'] = (int) $summary['visits'] > 0 ? round(((int) $summary['registers'] / (int) $summary['visits']) * 100, 2) : 0.0;
        $summary['add_desktop_rate'] = (int) $summary['visits'] > 0 ? round(((int) $summary['add_desktop'] / (int) $summary['visits']) * 100, 2) : 0.0;
        $summary['activation_rate'] = (int) $summary['add_desktop'] > 0 ? round(((int) $summary['activations'] / (int) $summary['add_desktop']) * 100, 2) : 0.0;
        $summary['recovery_rate'] = (float) $summary['cost'] > 0 ? round(((float) $summary['revenue'] / (float) $summary['cost']) * 100, 2) : null;
        $summary['new_user_cost'] = (int) $summary['new_users'] > 0 ? round((float) $summary['cost'] / (int) $summary['new_users'], 2) : null;
        $summary['add_desktop_cost'] = (int) $summary['add_desktop'] > 0 ? round((float) $summary['cost'] / (int) $summary['add_desktop'], 2) : null;
        $summary['order_cost'] = (int) $summary['paid_orders'] > 0 ? round((float) $summary['cost'] / (int) $summary['paid_orders'], 2) : null;

        return [
            'rows' => array_slice($dailyRows, 0, 62),
            'source_rows' => array_slice($sourceRows, 0, 50),
            'summary' => $summary,
        ];
    }

    private function playStatsDashboard(array $data): array
    {
        $timezone = new \DateTimeZone('Asia/Shanghai');
        $dateKey = function (array $source, array $keys = ['created_at']) use ($timezone): string {
            foreach ($keys as $key) {
                $value = trim((string) ($source[$key] ?? ''));
                if ($value === '') {
                    continue;
                }
                $date = $this->parseAnalyticsDateTime($value, $timezone);
                if ($date instanceof \DateTimeImmutable) {
                    return $date->format('Y-m-d');
                }
            }

            return '';
        };
        $contentRows = [];
        $unitRows = [];
        $dailyRows = [];
        $summary = [
            'content_count' => 0,
            'views' => 0,
            'legacy_views' => 0,
            'watch_records' => 0,
            'watch_users' => 0,
            'avg_progress' => 0.0,
            'completion_records' => 0,
            'lock_exposures' => 0,
            'order_created' => 0,
            'unlock_success' => 0,
            'unlock_rate' => 0.0,
            'drama_views' => 0,
            'novel_views' => 0,
            'active_days' => 0,
        ];
        $blankContent = static fn (string $key, string $contentType, int $contentId, string $title, int $unitCount, string $unitLabel, int $legacyViews = 0): array => [
            'key' => $key,
            'content_type' => $contentType,
            'content_label' => $contentType === 'novel' ? '小说' : '短剧',
            'content_id' => $contentId,
            'title' => $title,
            'unit_count' => $unitCount,
            'unit_label' => $unitLabel,
            'views' => 0,
            'legacy_views' => max(0, $legacyViews),
            'watch_records' => 0,
            'watch_users' => [],
            'progress_sum' => 0,
            'completion_records' => 0,
            'lock_exposures' => 0,
            'order_created' => 0,
            'unlock_success' => 0,
            'unlock_rate' => 0.0,
            'avg_progress' => 0.0,
            'hot_score' => 0,
        ];
        $blankUnit = static fn (string $key, string $contentKey, string $contentType, int $contentId, int $unitId, string $title, string $unitLabel): array => [
            'key' => $key,
            'content_key' => $contentKey,
            'content_type' => $contentType,
            'content_label' => $contentType === 'novel' ? '小说' : '短剧',
            'content_id' => $contentId,
            'unit_id' => $unitId,
            'title' => $title,
            'unit_label' => $unitLabel,
            'views' => 0,
            'watch_records' => 0,
            'watch_users' => [],
            'progress_sum' => 0,
            'completion_records' => 0,
            'lock_exposures' => 0,
            'order_created' => 0,
            'unlock_success' => 0,
            'unlock_rate' => 0.0,
            'avg_progress' => 0.0,
        ];
        $blankDaily = static fn (string $date): array => [
            'date' => $date,
            'views' => 0,
            'watch_records' => 0,
            'watch_users' => [],
            'lock_exposures' => 0,
            'order_created' => 0,
            'unlock_success' => 0,
        ];

        foreach ((array) ($data['dramas'] ?? []) as $drama) {
            $id = (int) ($drama['id'] ?? 0);
            if ($id <= 0) {
                continue;
            }
            $contentKey = 'drama:' . $id;
            $episodes = array_values((array) ($drama['episodes'] ?? []));
            $contentRows[$contentKey] = $blankContent($contentKey, 'drama', $id, (string) ($drama['title'] ?? '未命名短剧'), count($episodes), '集', (int) ($drama['views'] ?? 0));
            foreach ($episodes as $index => $episode) {
                $episodeId = (int) ($episode['id'] ?? 0);
                if ($episodeId <= 0) {
                    continue;
                }
                $unitKey = 'drama:' . $id . ':' . $episodeId;
                $unitRows[$unitKey] = $blankUnit($unitKey, $contentKey, 'drama', $id, $episodeId, (string) (($episode['title'] ?? '') ?: ('第' . ($index + 1) . '集')), '集');
            }
        }
        foreach ((array) ($data['novels'] ?? []) as $novel) {
            $id = (int) ($novel['id'] ?? 0);
            if ($id <= 0) {
                continue;
            }
            $contentKey = 'novel:' . $id;
            $chapters = array_values((array) ($novel['chapters'] ?? []));
            $contentRows[$contentKey] = $blankContent($contentKey, 'novel', $id, (string) ($novel['title'] ?? '未命名小说'), count($chapters), '章', 0);
            foreach ($chapters as $index => $chapter) {
                $chapterId = (int) ($chapter['id'] ?? 0);
                if ($chapterId <= 0) {
                    continue;
                }
                $unitKey = 'novel:' . $id . ':' . $chapterId;
                $unitRows[$unitKey] = $blankUnit($unitKey, $contentKey, 'novel', $id, $chapterId, (string) (($chapter['title'] ?? '') ?: ('第' . ($index + 1) . '章')), '章');
            }
        }

        $ensureContent = function (string $contentType, int $contentId) use (&$contentRows, $blankContent): string {
            $contentType = $contentType === 'novel' ? 'novel' : 'drama';
            $key = $contentType . ':' . $contentId;
            if (!isset($contentRows[$key])) {
                $contentRows[$key] = $blankContent($key, $contentType, $contentId, ($contentType === 'novel' ? '小说' : '短剧') . ' #' . $contentId, 0, $contentType === 'novel' ? '章' : '集');
            }

            return $key;
        };
        $ensureUnit = function (string $contentType, int $contentId, int $unitId) use (&$unitRows, $blankUnit, $ensureContent): string {
            $contentType = $contentType === 'novel' ? 'novel' : 'drama';
            $contentKey = $ensureContent($contentType, $contentId);
            $key = $contentType . ':' . $contentId . ':' . $unitId;
            if ($unitId > 0 && !isset($unitRows[$key])) {
                $unitRows[$key] = $blankUnit($key, $contentKey, $contentType, $contentId, $unitId, ($contentType === 'novel' ? '章节' : '分集') . ' #' . $unitId, $contentType === 'novel' ? '章' : '集');
            }

            return $key;
        };
        $ensureDaily = static function (string $date) use (&$dailyRows, $blankDaily): void {
            if ($date !== '' && !isset($dailyRows[$date])) {
                $dailyRows[$date] = $blankDaily($date);
            }
        };

        foreach ((array) ($data['content_events'] ?? []) as $event) {
            $contentType = (string) ($event['content_type'] ?? 'drama') === 'novel' ? 'novel' : 'drama';
            $contentId = $contentType === 'novel' ? (int) ($event['novel_id'] ?? 0) : (int) ($event['drama_id'] ?? 0);
            if ($contentId <= 0) {
                continue;
            }
            $unitId = $contentType === 'novel' ? (int) ($event['chapter_id'] ?? 0) : (int) ($event['episode_id'] ?? 0);
            $contentKey = $ensureContent($contentType, $contentId);
            $unitKey = $unitId > 0 ? $ensureUnit($contentType, $contentId, $unitId) : '';
            $eventType = (string) ($event['event'] ?? 'view');
            $metric = match ($eventType) {
                'lock_exposure' => 'lock_exposures',
                'order_created' => 'order_created',
                'unlock_success' => 'unlock_success',
                default => 'views',
            };
            $contentRows[$contentKey][$metric]++;
            if ($unitKey !== '') {
                $unitRows[$unitKey][$metric]++;
            }
            $date = $dateKey($event, ['created_at']);
            if ($date !== '') {
                $ensureDaily($date);
                $dailyRows[$date][$metric]++;
                if ((int) ($event['user_id'] ?? 0) > 0) {
                    $dailyRows[$date]['watch_users'][(int) $event['user_id']] = true;
                }
            }
        }

        foreach ((array) ($data['watch_history'] ?? []) as $history) {
            $dramaId = (int) ($history['drama_id'] ?? 0);
            $episodeId = (int) ($history['episode_id'] ?? 0);
            if ($dramaId <= 0) {
                continue;
            }
            $contentKey = $ensureContent('drama', $dramaId);
            $unitKey = $episodeId > 0 ? $ensureUnit('drama', $dramaId, $episodeId) : '';
            $progress = max(0, min(100, (int) ($history['progress'] ?? 0)));
            $userId = (int) ($history['user_id'] ?? 0);
            $contentRows[$contentKey]['watch_records']++;
            $contentRows[$contentKey]['progress_sum'] += $progress;
            if ($progress >= 90) {
                $contentRows[$contentKey]['completion_records']++;
            }
            if ($userId > 0) {
                $contentRows[$contentKey]['watch_users'][$userId] = true;
            }
            if ($unitKey !== '') {
                $unitRows[$unitKey]['watch_records']++;
                $unitRows[$unitKey]['progress_sum'] += $progress;
                if ($progress >= 90) {
                    $unitRows[$unitKey]['completion_records']++;
                }
                if ($userId > 0) {
                    $unitRows[$unitKey]['watch_users'][$userId] = true;
                }
            }
            $date = $dateKey($history, ['updated_at', 'created_at']);
            if ($date !== '') {
                $ensureDaily($date);
                $dailyRows[$date]['watch_records']++;
                if ($userId > 0) {
                    $dailyRows[$date]['watch_users'][$userId] = true;
                }
            }
        }

        $summaryWatchUsers = [];
        $progressSum = 0;
        $finalize = static function (array $row): array {
            $watchUsers = (array) ($row['watch_users'] ?? []);
            $watchRecords = (int) ($row['watch_records'] ?? 0);
            $row['watch_user_count'] = count($watchUsers);
            unset($row['watch_users']);
            $row['avg_progress'] = $watchRecords > 0 ? round((float) ($row['progress_sum'] ?? 0) / $watchRecords, 2) : 0.0;
            unset($row['progress_sum']);
            $row['unlock_rate'] = (int) ($row['lock_exposures'] ?? 0) > 0 ? round(((int) ($row['unlock_success'] ?? 0) / (int) $row['lock_exposures']) * 100, 2) : 0.0;
            $row['hot_score'] = (int) ($row['views'] ?? 0) + (int) ($row['watch_records'] ?? 0) + (int) ($row['unlock_success'] ?? 0) * 3 + (int) ($row['legacy_views'] ?? 0);

            return $row;
        };

        foreach ($contentRows as &$row) {
            $summary['views'] += (int) ($row['views'] ?? 0);
            $summary['legacy_views'] += (int) ($row['legacy_views'] ?? 0);
            $summary['watch_records'] += (int) ($row['watch_records'] ?? 0);
            $summary['completion_records'] += (int) ($row['completion_records'] ?? 0);
            $summary['lock_exposures'] += (int) ($row['lock_exposures'] ?? 0);
            $summary['order_created'] += (int) ($row['order_created'] ?? 0);
            $summary['unlock_success'] += (int) ($row['unlock_success'] ?? 0);
            $progressSum += (int) ($row['progress_sum'] ?? 0);
            foreach ((array) ($row['watch_users'] ?? []) as $userId => $_) {
                $summaryWatchUsers[(int) $userId] = true;
            }
            if ((string) ($row['content_type'] ?? 'drama') === 'novel') {
                $summary['novel_views'] += (int) ($row['views'] ?? 0);
            } else {
                $summary['drama_views'] += (int) ($row['views'] ?? 0) + (int) ($row['watch_records'] ?? 0);
            }
            $row = $finalize($row);
        }
        unset($row);
        foreach ($unitRows as &$row) {
            $row = $finalize($row);
        }
        unset($row);
        foreach ($dailyRows as &$row) {
            $row['watch_user_count'] = count((array) ($row['watch_users'] ?? []));
            unset($row['watch_users']);
        }
        unset($row);

        $summary['content_count'] = count($contentRows);
        $summary['watch_users'] = count($summaryWatchUsers);
        $summary['avg_progress'] = (int) $summary['watch_records'] > 0 ? round($progressSum / (int) $summary['watch_records'], 2) : 0.0;
        $summary['unlock_rate'] = (int) $summary['lock_exposures'] > 0 ? round(((int) $summary['unlock_success'] / (int) $summary['lock_exposures']) * 100, 2) : 0.0;
        $summary['active_days'] = count($dailyRows);

        $contentRows = array_values($contentRows);
        usort($contentRows, static fn (array $a, array $b): int => [(int) ($b['hot_score'] ?? 0), (int) ($b['views'] ?? 0), (int) ($b['watch_records'] ?? 0)] <=> [(int) ($a['hot_score'] ?? 0), (int) ($a['views'] ?? 0), (int) ($a['watch_records'] ?? 0)]);
        $unitRows = array_values($unitRows);
        usort($unitRows, static fn (array $a, array $b): int => [(int) ($b['views'] ?? 0) + (int) ($b['watch_records'] ?? 0), (int) ($b['unlock_success'] ?? 0)] <=> [(int) ($a['views'] ?? 0) + (int) ($a['watch_records'] ?? 0), (int) ($a['unlock_success'] ?? 0)]);
        $dailyRows = array_values($dailyRows);
        usort($dailyRows, static fn (array $a, array $b): int => strcmp((string) ($b['date'] ?? ''), (string) ($a['date'] ?? '')));

        return [
            'summary' => $summary,
            'rows' => array_slice($contentRows, 0, 50),
            'unit_rows' => array_slice($unitRows, 0, 80),
            'daily_rows' => array_slice($dailyRows, 0, 62),
        ];
    }

    private function contentConversionDashboard(array $data): array
    {
        $rows = [];
        foreach ((array) ($data['dramas'] ?? []) as $drama) {
            $id = (int) ($drama['id'] ?? 0);
            $key = 'drama:' . $id;
            $rows[$key] = [
                'key' => $key,
                'content_type' => 'drama',
                'content_label' => '短剧',
                'content_id' => $id,
                'title' => (string) ($drama['title'] ?? '未命名短剧'),
                'status' => (string) ($drama['status'] ?? 'draft'),
                'unit_count' => count((array) ($drama['episodes'] ?? [])),
                'unit_label' => '集',
                'views' => 0,
                'lock_exposures' => 0,
                'orders' => 0,
                'unlocks' => 0,
                'revenue' => 0.0,
                'paid_users' => [],
                'promotion_revenue' => 0.0,
            ];
        }
        foreach ((array) ($data['novels'] ?? []) as $novel) {
            $id = (int) ($novel['id'] ?? 0);
            $key = 'novel:' . $id;
            $rows[$key] = [
                'key' => $key,
                'content_type' => 'novel',
                'content_label' => '小说',
                'content_id' => $id,
                'title' => (string) ($novel['title'] ?? '未命名小说'),
                'status' => (string) ($novel['status'] ?? 'draft'),
                'unit_count' => count((array) ($novel['chapters'] ?? [])),
                'unit_label' => '章',
                'views' => 0,
                'lock_exposures' => 0,
                'orders' => 0,
                'unlocks' => 0,
                'revenue' => 0.0,
                'paid_users' => [],
                'promotion_revenue' => 0.0,
            ];
        }

        foreach ((array) ($data['content_events'] ?? []) as $event) {
            $contentType = (string) ($event['content_type'] ?? 'drama');
            $contentId = $contentType === 'novel' ? (int) ($event['novel_id'] ?? 0) : (int) ($event['drama_id'] ?? 0);
            $key = $contentType . ':' . $contentId;
            if (!isset($rows[$key])) {
                continue;
            }
            match ((string) ($event['event'] ?? '')) {
                'view' => $rows[$key]['views']++,
                'lock_exposure' => $rows[$key]['lock_exposures']++,
                'order_created' => $rows[$key]['orders']++,
                'unlock_success' => $rows[$key]['unlocks']++,
                default => null,
            };
        }

        $settledStatuses = ['paid', 'partial_refunded', 'refunded'];
        foreach ((array) ($data['orders'] ?? []) as $order) {
            if (!empty($order['is_test']) || !in_array((string) ($order['status'] ?? 'pending'), $settledStatuses, true)) {
                continue;
            }
            $contentType = (string) ($order['content_type'] ?? 'drama');
            $contentId = $contentType === 'novel' ? (int) ($order['novel_id'] ?? 0) : (int) ($order['drama_id'] ?? 0);
            $key = $contentType . ':' . $contentId;
            if (!isset($rows[$key])) {
                continue;
            }
            $amount = (float) ($order['amount'] ?? 0);
            $refund = min($amount, max(0.0, (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0)));
            $net = max(0.0, $amount - $refund);
            $rows[$key]['revenue'] += $net;
            if ((int) ($order['user_id'] ?? 0) > 0) {
                $rows[$key]['paid_users'][(int) $order['user_id']] = true;
            }
            if ((int) ($order['promotion_link_id'] ?? 0) > 0) {
                $rows[$key]['promotion_revenue'] += $net;
            }
        }

        foreach ($rows as &$row) {
            $row['paid_user_count'] = count($row['paid_users']);
            unset($row['paid_users']);
            $row['revenue'] = round((float) $row['revenue'], 2);
            $row['promotion_revenue'] = round((float) $row['promotion_revenue'], 2);
            $row['lock_rate'] = (int) $row['views'] > 0 ? round(((int) $row['lock_exposures'] / (int) $row['views']) * 100, 2) : 0.0;
            $row['order_rate'] = (int) $row['lock_exposures'] > 0 ? round(((int) $row['orders'] / (int) $row['lock_exposures']) * 100, 2) : 0.0;
            $row['unlock_rate'] = (int) $row['lock_exposures'] > 0 ? round(((int) $row['unlocks'] / (int) $row['lock_exposures']) * 100, 2) : 0.0;
            $row['arppu'] = (int) $row['paid_user_count'] > 0 ? round(((float) $row['revenue'] / (int) $row['paid_user_count']), 2) : 0.0;
        }
        unset($row);

        usort($rows, static fn (array $a, array $b): int => [$b['revenue'], $b['unlocks'], $b['views']] <=> [$a['revenue'], $a['unlocks'], $a['views']]);

        return [
            'rows' => array_values($rows),
            'summary' => [
                'content_count' => count($rows),
                'views' => array_sum(array_column($rows, 'views')),
                'lock_exposures' => array_sum(array_column($rows, 'lock_exposures')),
                'orders' => array_sum(array_column($rows, 'orders')),
                'unlocks' => array_sum(array_column($rows, 'unlocks')),
                'revenue' => round(array_sum(array_column($rows, 'revenue')), 2),
                'promotion_revenue' => round(array_sum(array_column($rows, 'promotion_revenue')), 2),
            ],
        ];
    }

    private function rechargeHourlyDashboard(array $data): array
    {
        $timezone = new \DateTimeZone('Asia/Shanghai');
        $settledStatuses = ['paid', 'partial_refunded', 'refunded'];
        $rows = [];
        for ($hour = 0; $hour < 24; $hour++) {
            $rows[$hour] = [
                'hour' => $hour,
                'label' => sprintf('%02d:00-%02d:59', $hour, $hour),
                'orders' => 0,
                'paid_users' => [],
                'gross_amount' => 0.0,
                'refund_amount' => 0.0,
                'net_amount' => 0.0,
                'avg_order_amount' => 0.0,
                'refund_rate' => 0.0,
            ];
        }
        $methodRows = [];
        $totalOrders = 0;
        $totalPaidUsers = [];
        $grossAmount = 0.0;
        $refundAmount = 0.0;
        $netAmount = 0.0;

        foreach ((array) ($data['orders'] ?? []) as $order) {
            if (!empty($order['is_test']) || !in_array((string) ($order['status'] ?? 'pending'), $settledStatuses, true)) {
                continue;
            }
            $paidTimeText = (string) (($order['paid_at'] ?? '') ?: ($order['created_at'] ?? ''));
            $paidDate = $this->parseAnalyticsDateTime($paidTimeText, $timezone);
            if ($paidDate === null) {
                continue;
            }
            $hour = (int) $paidDate->format('G');
            $amount = max(0.0, (float) ($order['amount'] ?? 0));
            $refund = min($amount, max(0.0, (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0)));
            $net = max(0.0, $amount - $refund);
            $userId = (int) ($order['user_id'] ?? 0);
            $display = $this->paymentDisplayForOrder($order);
            $methodKey = (string) (($display['method'] ?? '') ?: ($order['payment_method'] ?? 'unknown'));
            $methodName = (string) (($display['method_name'] ?? '') ?: $methodKey);

            $rows[$hour]['orders']++;
            $rows[$hour]['gross_amount'] += $amount;
            $rows[$hour]['refund_amount'] += $refund;
            $rows[$hour]['net_amount'] += $net;
            if ($userId > 0) {
                $rows[$hour]['paid_users'][$userId] = true;
                $totalPaidUsers[$userId] = true;
            }

            if (!isset($methodRows[$methodKey])) {
                $methodRows[$methodKey] = [
                    'method' => $methodKey,
                    'method_name' => $methodName,
                    'orders' => 0,
                    'paid_users' => [],
                    'gross_amount' => 0.0,
                    'refund_amount' => 0.0,
                    'net_amount' => 0.0,
                    'avg_order_amount' => 0.0,
                    'refund_rate' => 0.0,
                ];
            }
            $methodRows[$methodKey]['orders']++;
            $methodRows[$methodKey]['gross_amount'] += $amount;
            $methodRows[$methodKey]['refund_amount'] += $refund;
            $methodRows[$methodKey]['net_amount'] += $net;
            if ($userId > 0) {
                $methodRows[$methodKey]['paid_users'][$userId] = true;
            }

            $totalOrders++;
            $grossAmount += $amount;
            $refundAmount += $refund;
            $netAmount += $net;
        }

        foreach ($rows as &$row) {
            $row['paid_user_count'] = count($row['paid_users']);
            unset($row['paid_users']);
            $row['gross_amount'] = round((float) $row['gross_amount'], 2);
            $row['refund_amount'] = round((float) $row['refund_amount'], 2);
            $row['net_amount'] = round((float) $row['net_amount'], 2);
            $row['avg_order_amount'] = (int) $row['orders'] > 0 ? round((float) $row['gross_amount'] / (int) $row['orders'], 2) : 0.0;
            $row['refund_rate'] = (float) $row['gross_amount'] > 0 ? round(((float) $row['refund_amount'] / (float) $row['gross_amount']) * 100, 2) : 0.0;
        }
        unset($row);

        foreach ($methodRows as &$row) {
            $row['paid_user_count'] = count($row['paid_users']);
            unset($row['paid_users']);
            $row['gross_amount'] = round((float) $row['gross_amount'], 2);
            $row['refund_amount'] = round((float) $row['refund_amount'], 2);
            $row['net_amount'] = round((float) $row['net_amount'], 2);
            $row['avg_order_amount'] = (int) $row['orders'] > 0 ? round((float) $row['gross_amount'] / (int) $row['orders'], 2) : 0.0;
            $row['refund_rate'] = (float) $row['gross_amount'] > 0 ? round(((float) $row['refund_amount'] / (float) $row['gross_amount']) * 100, 2) : 0.0;
        }
        unset($row);
        usort($methodRows, static fn (array $a, array $b): int => [(float) $b['net_amount'], (int) $b['orders']] <=> [(float) $a['net_amount'], (int) $a['orders']]);

        $peakRevenueHour = null;
        $peakOrderHour = null;
        foreach ($rows as $row) {
            if ($peakRevenueHour === null || (float) $row['net_amount'] > (float) ($peakRevenueHour['net_amount'] ?? 0)) {
                $peakRevenueHour = $row;
            }
            if ($peakOrderHour === null || (int) $row['orders'] > (int) ($peakOrderHour['orders'] ?? 0)) {
                $peakOrderHour = $row;
            }
        }

        return [
            'rows' => array_values($rows),
            'method_rows' => array_values($methodRows),
            'summary' => [
                'orders' => $totalOrders,
                'paid_users' => count($totalPaidUsers),
                'gross_amount' => round($grossAmount, 2),
                'refund_amount' => round($refundAmount, 2),
                'net_amount' => round($netAmount, 2),
                'avg_order_amount' => $totalOrders > 0 ? round($grossAmount / $totalOrders, 2) : 0.0,
                'refund_rate' => $grossAmount > 0 ? round(($refundAmount / $grossAmount) * 100, 2) : 0.0,
                'peak_revenue_hour' => $peakRevenueHour ?? [],
                'peak_order_hour' => $peakOrderHour ?? [],
            ],
        ];
    }

    private function paymentSuccessDashboard(array $data): array
    {
        $successStatuses = ['paid', 'partial_refunded', 'refunded'];
        $pendingStatuses = ['pending', 'refund_pending'];
        $failedStatuses = ['failed', 'closed', 'expired'];
        $statusLabels = [
            'pending' => '待支付',
            'paid' => '已支付',
            'refund_pending' => '退款处理中',
            'partial_refunded' => '部分退款',
            'refunded' => '已退款',
            'failed' => '支付失败',
            'closed' => '已关闭',
            'expired' => '已过期',
            'other' => '其他',
        ];
        $blank = static fn (string $key = '', string $name = ''): array => [
            'key' => $key,
            'name' => $name,
            'orders' => 0,
            'success_orders' => 0,
            'pending_orders' => 0,
            'failed_orders' => 0,
            'refund_orders' => 0,
            'gross_amount' => 0.0,
            'refund_amount' => 0.0,
            'net_amount' => 0.0,
            'success_rate' => 0.0,
            'failure_rate' => 0.0,
            'refund_rate' => 0.0,
        ];

        $summary = $blank('summary', '全部订单');
        $statusRows = [];
        $routeRows = [];
        $methodRows = [];
        foreach ((array) ($data['orders'] ?? []) as $order) {
            if (!empty($order['is_test'])) {
                continue;
            }
            $status = (string) ($order['status'] ?? 'pending');
            if (!isset($statusLabels[$status])) {
                $status = 'other';
            }
            $display = $this->paymentDisplayForOrder($order);
            $routeId = (string) (($display['route_id'] ?? '') ?: ($order['payment_route_id'] ?? 'unknown'));
            $routeName = (string) (($display['channel_name'] ?? '') ?: '未识别通道');
            $methodKey = (string) (($display['method'] ?? '') ?: ($order['payment_method'] ?? 'unknown'));
            $methodName = (string) (($display['method_name'] ?? '') ?: $methodKey);
            $amount = max(0.0, (float) ($order['amount'] ?? 0));
            $refund = min($amount, max(0.0, (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0)));
            $isSuccess = in_array($status, $successStatuses, true);
            $isPending = in_array($status, $pendingStatuses, true);
            $isFailed = in_array($status, $failedStatuses, true) || $status === 'other';
            $isRefund = in_array($status, ['refund_pending', 'partial_refunded', 'refunded'], true) || $refund > 0;
            $net = $isSuccess ? max(0.0, $amount - $refund) : 0.0;

            $statusRows[$status] ??= $blank($status, $statusLabels[$status] ?? $status);
            $routeRows[$routeId] ??= $blank($routeId, $routeName);
            $methodRows[$methodKey] ??= $blank($methodKey, $methodName);

            foreach ([&$summary, &$statusRows[$status], &$routeRows[$routeId], &$methodRows[$methodKey]] as &$row) {
                $row['orders']++;
                $row['success_orders'] += $isSuccess ? 1 : 0;
                $row['pending_orders'] += $isPending ? 1 : 0;
                $row['failed_orders'] += $isFailed ? 1 : 0;
                $row['refund_orders'] += $isRefund ? 1 : 0;
                if ($isSuccess) {
                    $row['gross_amount'] += $amount;
                    $row['refund_amount'] += $refund;
                    $row['net_amount'] += $net;
                }
            }
            unset($row);
        }

        $finalize = static function (array $row): array {
            $row['gross_amount'] = round((float) $row['gross_amount'], 2);
            $row['refund_amount'] = round((float) $row['refund_amount'], 2);
            $row['net_amount'] = round((float) $row['net_amount'], 2);
            $row['success_rate'] = (int) $row['orders'] > 0 ? round(((int) $row['success_orders'] / (int) $row['orders']) * 100, 2) : 0.0;
            $row['failure_rate'] = (int) $row['orders'] > 0 ? round(((int) $row['failed_orders'] / (int) $row['orders']) * 100, 2) : 0.0;
            $row['refund_rate'] = (int) $row['success_orders'] > 0 ? round(((int) $row['refund_orders'] / (int) $row['success_orders']) * 100, 2) : 0.0;

            return $row;
        };

        $summary = $finalize($summary);
        $statusRows = array_map($finalize, array_values($statusRows));
        usort($statusRows, static fn (array $a, array $b): int => (int) $b['orders'] <=> (int) $a['orders']);
        $routeRows = array_map($finalize, array_values($routeRows));
        usort($routeRows, static fn (array $a, array $b): int => [(int) $b['orders'], (float) $b['net_amount']] <=> [(int) $a['orders'], (float) $a['net_amount']]);
        $methodRows = array_map($finalize, array_values($methodRows));
        usort($methodRows, static fn (array $a, array $b): int => [(int) $b['orders'], (float) $b['net_amount']] <=> [(int) $a['orders'], (float) $a['net_amount']]);

        return [
            'summary' => $summary,
            'status_rows' => $statusRows,
            'route_rows' => $routeRows,
            'method_rows' => $methodRows,
        ];
    }

    private function analyticsInsightDashboard(array $data, array $contentConversionDashboard, array $operationAlertDashboard): array
    {
        $timezone = new \DateTimeZone('Asia/Shanghai');
        $settledStatuses = ['paid', 'partial_refunded', 'refunded'];
        $rows = [];
        for ($hour = 0; $hour < 24; $hour++) {
            $rows[$hour] = [
                'hour' => $hour,
                'label' => sprintf('%02d:00-%02d:59', $hour, $hour),
                'visits' => 0,
                'content_views' => 0,
                'lock_exposures' => 0,
                'orders' => 0,
                'paid_orders' => 0,
                'paid_users' => [],
                'net_amount' => 0.0,
                'cost' => 0.0,
                'conversion_rate' => 0.0,
                'recovery_rate' => null,
                'avg_order_amount' => 0.0,
            ];
        }

        $hourFrom = function (array $source, array $keys) use ($timezone): ?int {
            foreach ($keys as $key) {
                $value = trim((string) ($source[$key] ?? ''));
                if ($value === '') {
                    continue;
                }
                $date = $this->parseAnalyticsDateTime($value, $timezone);
                if ($date instanceof \DateTimeImmutable) {
                    return (int) $date->format('G');
                }
            }

            return null;
        };

        foreach ((array) ($data['promotion_events'] ?? []) as $event) {
            if ((string) ($event['event'] ?? 'visit') !== 'visit') {
                continue;
            }
            $hour = $hourFrom($event, ['created_at']);
            if ($hour !== null) {
                $rows[$hour]['visits']++;
            }
        }

        foreach ((array) ($data['content_events'] ?? []) as $event) {
            $eventType = (string) ($event['event'] ?? 'view');
            if (!in_array($eventType, ['view', 'lock_exposure'], true)) {
                continue;
            }
            $hour = $hourFrom($event, ['created_at']);
            if ($hour === null) {
                continue;
            }
            if ($eventType === 'view') {
                $rows[$hour]['content_views']++;
            } else {
                $rows[$hour]['lock_exposures']++;
            }
        }

        foreach ((array) ($data['orders'] ?? []) as $order) {
            if (!empty($order['is_test'])) {
                continue;
            }
            $createdHour = $hourFrom($order, ['created_at']);
            if ($createdHour !== null) {
                $rows[$createdHour]['orders']++;
            }
            if (!in_array((string) ($order['status'] ?? 'pending'), $settledStatuses, true)) {
                continue;
            }
            $paidHour = $hourFrom($order, ['paid_at', 'created_at']);
            if ($paidHour === null) {
                continue;
            }
            $amount = max(0.0, (float) ($order['amount'] ?? 0));
            $refund = min($amount, max(0.0, (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0)));
            $net = max(0.0, $amount - $refund);
            $rows[$paidHour]['paid_orders']++;
            $rows[$paidHour]['net_amount'] += $net;
            $userId = (int) ($order['user_id'] ?? 0);
            if ($userId > 0) {
                $rows[$paidHour]['paid_users'][$userId] = true;
            }
        }

        foreach ((array) ($data['promotion_costs'] ?? []) as $cost) {
            $hour = $hourFrom($cost, ['created_at', 'updated_at']);
            if ($hour === null) {
                $hour = 12;
            }
            $rows[$hour]['cost'] += max(0.0, (float) ($cost['amount'] ?? 0));
        }

        $summary = [
            'visits' => 0,
            'content_views' => 0,
            'lock_exposures' => 0,
            'orders' => 0,
            'paid_orders' => 0,
            'paid_users' => [],
            'net_amount' => 0.0,
            'cost' => 0.0,
            'conversion_rate' => 0.0,
            'recovery_rate' => null,
        ];
        foreach ($rows as &$row) {
            $row['paid_user_count'] = count($row['paid_users']);
            unset($row['paid_users']);
            $row['net_amount'] = round((float) $row['net_amount'], 2);
            $row['cost'] = round((float) $row['cost'], 2);
            $trafficBase = max((int) $row['visits'], (int) $row['content_views']);
            $row['conversion_rate'] = $trafficBase > 0 ? round(((int) $row['paid_orders'] / $trafficBase) * 100, 2) : 0.0;
            $row['recovery_rate'] = (float) $row['cost'] > 0 ? round(((float) $row['net_amount'] / (float) $row['cost']) * 100, 2) : null;
            $row['avg_order_amount'] = (int) $row['paid_orders'] > 0 ? round((float) $row['net_amount'] / (int) $row['paid_orders'], 2) : 0.0;
            foreach (['visits', 'content_views', 'lock_exposures', 'orders', 'paid_orders'] as $key) {
                $summary[$key] += (int) $row[$key];
            }
            $summary['net_amount'] += (float) $row['net_amount'];
            $summary['cost'] += (float) $row['cost'];
        }
        unset($row);
        foreach ((array) ($data['orders'] ?? []) as $order) {
            if (!empty($order['is_test']) || !in_array((string) ($order['status'] ?? 'pending'), $settledStatuses, true)) {
                continue;
            }
            $userId = (int) ($order['user_id'] ?? 0);
            if ($userId > 0) {
                $summary['paid_users'][$userId] = true;
            }
        }
        $summary['paid_user_count'] = count($summary['paid_users']);
        unset($summary['paid_users']);
        $summary['net_amount'] = round((float) $summary['net_amount'], 2);
        $summary['cost'] = round((float) $summary['cost'], 2);
        $trafficBase = max((int) $summary['visits'], (int) $summary['content_views']);
        $summary['conversion_rate'] = $trafficBase > 0 ? round(((int) $summary['paid_orders'] / $trafficBase) * 100, 2) : 0.0;
        $summary['recovery_rate'] = (float) $summary['cost'] > 0 ? round(((float) $summary['net_amount'] / (float) $summary['cost']) * 100, 2) : null;

        $peakRevenueHour = null;
        $peakOrderHour = null;
        $bestRecoveryHour = null;
        foreach ($rows as $row) {
            if ((float) ($row['net_amount'] ?? 0) > 0 && ($peakRevenueHour === null || (float) $row['net_amount'] > (float) ($peakRevenueHour['net_amount'] ?? 0))) {
                $peakRevenueHour = $row;
            }
            if ((int) ($row['paid_orders'] ?? 0) > 0 && ($peakOrderHour === null || (int) $row['paid_orders'] > (int) ($peakOrderHour['paid_orders'] ?? 0))) {
                $peakOrderHour = $row;
            }
            if ((float) ($row['cost'] ?? 0) > 0 && (int) ($row['paid_orders'] ?? 0) > 0 && ($bestRecoveryHour === null || (float) ($row['recovery_rate'] ?? 0) > (float) ($bestRecoveryHour['recovery_rate'] ?? 0))) {
                $bestRecoveryHour = $row;
            }
        }
        $summary['peak_revenue_hour'] = $peakRevenueHour ?? [];
        $summary['peak_order_hour'] = $peakOrderHour ?? [];
        $summary['best_recovery_hour'] = $bestRecoveryHour ?? [];

        $recommendations = [];
        $recommendationActionType = static function (string $title, array $metrics): string {
            if (str_contains($title, '低回收') || str_contains($title, '回本偏低')) {
                return (int) ($metrics['promotion_link_id'] ?? 0) > 0 ? 'pause_promotion' : 'adjust_budget';
            }
            if (str_contains($title, '低转化') || str_contains($title, '高退款')) {
                return 'replace_material';
            }
            if (str_contains($title, '内容承接')) {
                return 'review_content';
            }
            if (str_contains($title, '高回收') || str_contains($title, '高回本') || str_contains($title, '收入峰值')) {
                return 'amplify';
            }

            return 'observe';
        };
        $recommendationContext = static function (array $metrics): array {
            return [
                'promotion_link_id' => max(0, (int) ($metrics['promotion_link_id'] ?? 0)),
                'promotion_code' => (string) ($metrics['promotion_code'] ?? $metrics['code'] ?? ''),
                'agent_id' => max(0, (int) ($metrics['agent_id'] ?? 0)),
                'traffic_platform' => (string) ($metrics['traffic_platform'] ?? $metrics['platform'] ?? ''),
                'channel_id' => (string) ($metrics['channel_id'] ?? $metrics['channel'] ?? ''),
                'media_app_id' => (string) ($metrics['media_app_id'] ?? $metrics['app_id'] ?? ''),
                'ad_id' => (string) ($metrics['ad_id'] ?? ''),
                'creative_id' => (string) ($metrics['creative_id'] ?? ''),
                'material_id' => (string) ($metrics['material_id'] ?? ''),
                'content_type' => (string) ($metrics['content_type'] ?? ''),
                'content_id' => max(0, (int) ($metrics['content_id'] ?? 0)),
                'content_title' => (string) ($metrics['content_title'] ?? $metrics['title'] ?? ''),
            ];
        };
        $addRecommendation = static function (array &$items, string $level, string $title, string $message, string $action = '', array $metrics = []) use ($recommendationActionType, $recommendationContext): void {
            $context = $recommendationContext($metrics);
            $actionType = $recommendationActionType($title, $metrics);
            $fingerprint = 'insight:' . md5(implode('|', [
                $level,
                $title,
                $message,
                $actionType,
                (string) ($context['promotion_link_id'] ?? 0),
                (string) ($context['content_type'] ?? ''),
                (string) ($context['content_id'] ?? 0),
                (string) ($metrics['hour'] ?? ''),
                (string) ($metrics['ad_id'] ?? ''),
                (string) ($metrics['material_id'] ?? ''),
            ]));
            $key = md5($fingerprint);
            $items[$key] = [
                'fingerprint' => $fingerprint,
                'level' => in_array($level, ['high', 'medium', 'low', 'good'], true) ? $level : 'medium',
                'action_type' => $actionType,
                'title' => $title,
                'message' => $message,
                'action' => $action,
                'context' => $context,
                'metrics' => $metrics,
            ];
        };

        if ((int) $summary['visits'] > 0 && (int) $summary['paid_orders'] === 0) {
            $addRecommendation($recommendations, 'high', '有流量但没有支付', '当前筛选范围有访问但没有支付订单，优先检查支付入口、商品价格、审核模式和落地页跳转。', '先看支付成功率页和投放入口承接，再决定是否暂停当前素材。', $summary);
        } elseif ((float) $summary['cost'] > 0 && $summary['recovery_rate'] !== null && (float) $summary['recovery_rate'] < 80.0) {
            $addRecommendation($recommendations, 'high', '整体回本偏低', '当前筛选范围消耗 ' . number_format((float) $summary['cost'], 2) . '，净回收 ' . number_format((float) $summary['net_amount'], 2) . '，回本率 ' . number_format((float) $summary['recovery_rate'], 2) . '%。', '优先处理低回收推广入口和低转化素材，必要时先降预算。', $summary);
        }

        if (!empty($summary['peak_revenue_hour']) && (float) ($summary['peak_revenue_hour']['net_amount'] ?? 0) > 0) {
            $hour = (array) $summary['peak_revenue_hour'];
            $addRecommendation($recommendations, 'good', '收入峰值小时', (string) ($hour['label'] ?? '') . ' 净收入最高，为 ' . number_format((float) ($hour['net_amount'] ?? 0), 2) . '，支付订单 ' . (int) ($hour['paid_orders'] ?? 0) . ' 笔。', '可把预算、弹窗和活动入口优先排到该时段附近。', $hour);
        }
        if (!empty($summary['best_recovery_hour'])) {
            $hour = (array) $summary['best_recovery_hour'];
            $addRecommendation($recommendations, 'good', '高回本小时', (string) ($hour['label'] ?? '') . ' 回本率最高，为 ' . number_format((float) ($hour['recovery_rate'] ?? 0), 2) . '%。', '适合放大同类素材或复制该时段投放策略。', $hour);
        }

        $contentRows = array_values((array) ($contentConversionDashboard['rows'] ?? []));
        $lowContentRows = array_values(array_filter($contentRows, static fn (array $row): bool => (int) ($row['views'] ?? 0) >= 10 && (float) ($row['order_rate'] ?? 0) < 1.0));
        usort($lowContentRows, static fn (array $a, array $b): int => [(int) ($b['views'] ?? 0), (float) ($a['order_rate'] ?? 0)] <=> [(int) ($a['views'] ?? 0), (float) ($b['order_rate'] ?? 0)]);
        if (!empty($lowContentRows)) {
            $row = $lowContentRows[0];
            $addRecommendation($recommendations, 'medium', '内容承接转化偏低', (string) ($row['title'] ?? '内容') . ' 浏览 ' . (int) ($row['views'] ?? 0) . '，锁定曝光 ' . (int) ($row['lock_exposures'] ?? 0) . '，下单率 ' . number_format((float) ($row['order_rate'] ?? 0), 2) . '%。', '检查试看节点、价格、封面标题和投放素材承诺是否一致。', $row);
        }
        $bestContentRows = array_values(array_filter($contentRows, static fn (array $row): bool => (float) ($row['revenue'] ?? 0) > 0));
        usort($bestContentRows, static fn (array $a, array $b): int => (float) ($b['revenue'] ?? 0) <=> (float) ($a['revenue'] ?? 0));
        if (!empty($bestContentRows)) {
            $row = $bestContentRows[0];
            $addRecommendation($recommendations, 'good', '高回收内容可放大', (string) ($row['title'] ?? '内容') . ' 当前收入 ' . number_format((float) ($row['revenue'] ?? 0), 2) . '，解锁 ' . (int) ($row['unlocks'] ?? 0) . ' 次。', '可加入热播榜、首页推荐或作为下一轮素材主推内容。', $row);
        }

        foreach ([
            ['rows' => (array) ($operationAlertDashboard['low_conversion_alerts'] ?? []), 'title' => '低转化素材需处理', 'action' => '暂停或替换该素材，检查落地页承接和目标人群。'],
            ['rows' => (array) ($operationAlertDashboard['high_refund_alerts'] ?? []), 'title' => '高退款素材需复盘', 'action' => '核对素材承诺、剧情实际内容和商品价格，必要时下架素材。'],
            ['rows' => (array) ($operationAlertDashboard['low_recovery_alerts'] ?? []), 'title' => '低回收推广需降预算', 'action' => '优先暂停低回收入口或降低预算，再替换素材测试。'],
        ] as $group) {
            $rowsForGroup = array_values((array) ($group['rows'] ?? []));
            if (empty($rowsForGroup)) {
                continue;
            }
            $alert = $rowsForGroup[0];
            $addRecommendation($recommendations, (string) ($alert['level'] ?? 'medium'), (string) $group['title'], (string) ($alert['message'] ?? $alert['title'] ?? ''), (string) $group['action'], $alert);
        }

        if (empty($recommendations)) {
            $addRecommendation($recommendations, 'low', '暂无明显异常', '当前筛选范围的小时趋势、内容转化和素材异常未触发明显预警，可继续积累样本。', '保持现有投放节奏，并关注新增素材的前 24 小时表现。');
        }

        $recommendations = array_values($recommendations);
        usort($recommendations, static function (array $a, array $b): int {
            $rank = ['high' => 4, 'medium' => 3, 'good' => 2, 'low' => 1];

            return ($rank[(string) ($b['level'] ?? 'low')] ?? 0) <=> ($rank[(string) ($a['level'] ?? 'low')] ?? 0);
        });

        return [
            'summary' => $summary,
            'hour_rows' => array_values($rows),
            'recommendations' => array_slice($recommendations, 0, 8),
        ];
    }

    private function analyticsReviewTaskDashboard(array $tasks): array
    {
        $rows = array_values(array_filter($tasks, static fn (mixed $item): bool => is_array($item)));
        $summary = [
            'total' => count($rows),
            'pending' => 0,
            'processing' => 0,
            'done' => 0,
            'ignored' => 0,
            'high' => 0,
            'overdue' => 0,
            'due_today' => 0,
            'unassigned' => 0,
            'material_pending' => 0,
            'material_applied' => 0,
            'effect_positive' => 0,
        ];
        $today = date('Y-m-d');
        $now = date('Y-m-d H:i:s');
        foreach ($rows as $row) {
            $status = (string) ($row['status'] ?? 'pending');
            if (isset($summary[$status])) {
                $summary[$status]++;
            }
            if ((string) ($row['level'] ?? '') === 'high') {
                $summary['high']++;
            }
            if ((int) ($row['assigned_to_admin_id'] ?? 0) <= 0 && !in_array($status, ['done', 'ignored'], true)) {
                $summary['unassigned']++;
            }
            if ((string) ($row['material_review_status'] ?? 'none') === 'pending') {
                $summary['material_pending']++;
            } elseif ((string) ($row['material_review_status'] ?? 'none') === 'applied') {
                $summary['material_applied']++;
            }
            $effectDelta = (array) ($row['effect_delta_metrics'] ?? []);
            if ((float) ($effectDelta['revenue'] ?? 0) > 0 || (float) ($effectDelta['recovery_rate'] ?? 0) > 0) {
                $summary['effect_positive']++;
            }
            $dueAt = (string) ($row['due_at'] ?? '');
            if ($dueAt !== '' && !in_array($status, ['done', 'ignored'], true)) {
                if ($dueAt < $now) {
                    $summary['overdue']++;
                } elseif (str_starts_with($dueAt, $today)) {
                    $summary['due_today']++;
                }
            }
        }
        foreach ($rows as &$row) {
            $status = (string) ($row['status'] ?? 'pending');
            $dueAt = (string) ($row['due_at'] ?? '');
            $row['is_overdue'] = $dueAt !== '' && !in_array($status, ['done', 'ignored'], true) && $dueAt < $now;
            $row['is_due_today'] = $dueAt !== '' && !in_array($status, ['done', 'ignored'], true) && !$row['is_overdue'] && str_starts_with($dueAt, $today);
        }
        unset($row);
        usort($rows, static fn (array $a, array $b): int => [
            ['pending' => 0, 'processing' => 1, 'done' => 2, 'ignored' => 3][(string) ($a['status'] ?? 'pending')] ?? 9,
            ['high' => 0, 'medium' => 1, 'good' => 2, 'low' => 3][(string) ($a['level'] ?? 'medium')] ?? 9,
            (string) ($b['updated_at'] ?? $b['created_at'] ?? ''),
        ] <=> [
            ['pending' => 0, 'processing' => 1, 'done' => 2, 'ignored' => 3][(string) ($b['status'] ?? 'pending')] ?? 9,
            ['high' => 0, 'medium' => 1, 'good' => 2, 'low' => 3][(string) ($b['level'] ?? 'medium')] ?? 9,
            (string) ($a['updated_at'] ?? $a['created_at'] ?? ''),
        ]);

        return ['summary' => $summary, 'rows' => array_slice($rows, 0, 80)];
    }

    public function createAnalyticsReviewTask(array $payload): array
    {
        $data = $this->store->load();
        $now = date('Y-m-d H:i:s');
        $admin = $this->adminIdentity($data);
        $metrics = $this->jsonArrayFromPayload((string) ($payload['metrics_json'] ?? ''));
        $context = $this->jsonArrayFromPayload((string) ($payload['context_json'] ?? ''));
        $fingerprint = preg_replace('/[^a-zA-Z0-9:_-]+/', '', (string) ($payload['fingerprint'] ?? ''));
        if ($fingerprint === '') {
            $fingerprint = 'insight:' . md5(implode('|', [
                (string) ($payload['title'] ?? ''),
                (string) ($payload['message'] ?? ''),
                (string) ($payload['action_type'] ?? ''),
                (string) ($context['promotion_link_id'] ?? $payload['promotion_link_id'] ?? 0),
                (string) ($context['content_type'] ?? $payload['content_type'] ?? ''),
                (string) ($context['content_id'] ?? $payload['content_id'] ?? 0),
            ]));
        }

        $linkId = max(0, (int) ($payload['promotion_link_id'] ?? $context['promotion_link_id'] ?? $metrics['promotion_link_id'] ?? 0));
        if ($linkId > 0 && !$this->canManagePromotionLink($data, $linkId)) {
            return ['ok' => false, 'message' => '当前账号无权处理该推广入口的复盘任务。'];
        }

        $data['analytics_review_tasks'] = array_values((array) ($data['analytics_review_tasks'] ?? []));
        foreach ($data['analytics_review_tasks'] as $index => $task) {
            if ((string) ($task['fingerprint'] ?? '') !== $fingerprint) {
                continue;
            }
            $this->appendAnalyticsReviewTaskLog($data['analytics_review_tasks'][$index], 'sync', '复盘建议已同步，未重复创建。', $admin, $now);
            $data['analytics_review_tasks'][$index]['updated_at'] = $now;
            $this->store->save($data);

            return ['ok' => true, 'created' => 0, 'task' => $data['analytics_review_tasks'][$index], 'message' => '复盘任务已存在，已更新同步时间。'];
        }

        $nextId = empty($data['analytics_review_tasks']) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $data['analytics_review_tasks'])) + 1);
        $level = (string) ($payload['level'] ?? 'medium');
        $level = in_array($level, ['high', 'medium', 'low', 'good'], true) ? $level : 'medium';
        $actionType = (string) ($payload['action_type'] ?? 'observe');
        $actionType = in_array($actionType, ['observe', 'review_content', 'replace_material', 'adjust_budget', 'pause_promotion', 'amplify', 'custom'], true) ? $actionType : 'observe';
        $contentType = (string) ($payload['content_type'] ?? $context['content_type'] ?? $metrics['content_type'] ?? '');
        $contentType = in_array($contentType, ['drama', 'novel'], true) ? $contentType : '';
        $dueAt = $level === 'high' ? date('Y-m-d H:i:s', strtotime('+1 day')) : date('Y-m-d H:i:s', strtotime('+3 days'));
        $assignedAdmin = $this->adminById($data, max(0, (int) ($payload['assigned_to_admin_id'] ?? $admin['id'] ?? 0)));
        $assignedAdminId = (int) ($assignedAdmin['id'] ?? 0);
        if ($assignedAdminId > 0 && !$this->canAssignAnalyticsReviewTaskToAdmin($data, $assignedAdminId)) {
            return ['ok' => false, 'message' => '当前账号无权指派给该负责人。'];
        }
        $assignedAdminName = $assignedAdminId > 0 ? $this->adminDisplayName($assignedAdmin) : '';
        $task = [
            'id' => $nextId,
            'task_no' => 'REV' . date('Ymd') . str_pad((string) $nextId, 4, '0', STR_PAD_LEFT),
            'fingerprint' => $fingerprint,
            'source_type' => 'analytics_insight',
            'level' => $level,
            'action_type' => $actionType,
            'title' => $this->limitText(trim((string) ($payload['title'] ?? '复盘任务')), 120),
            'message' => $this->limitText(trim((string) ($payload['message'] ?? '')), 300),
            'suggested_action' => $this->limitText(trim((string) ($payload['suggested_action'] ?? $payload['action'] ?? '')), 240),
            'status' => 'pending',
            'promotion_link_id' => $linkId,
            'promotion_code' => preg_replace('/[^a-zA-Z0-9_-]+/', '', (string) ($payload['promotion_code'] ?? $context['promotion_code'] ?? $metrics['promotion_code'] ?? $metrics['code'] ?? '')),
            'agent_id' => max(0, (int) ($payload['agent_id'] ?? $context['agent_id'] ?? $metrics['agent_id'] ?? 0)),
            'traffic_platform' => $this->limitText(trim((string) ($payload['traffic_platform'] ?? $context['traffic_platform'] ?? $metrics['traffic_platform'] ?? '')), 40),
            'channel_id' => $this->limitText(trim((string) ($payload['channel_id'] ?? $context['channel_id'] ?? $metrics['channel_id'] ?? '')), 60),
            'media_app_id' => $this->limitText(trim((string) ($payload['media_app_id'] ?? $context['media_app_id'] ?? $metrics['media_app_id'] ?? '')), 60),
            'ad_id' => $this->limitText(trim((string) ($payload['ad_id'] ?? $context['ad_id'] ?? $metrics['ad_id'] ?? '')), 80),
            'creative_id' => $this->limitText(trim((string) ($payload['creative_id'] ?? $context['creative_id'] ?? $metrics['creative_id'] ?? '')), 80),
            'material_id' => $this->limitText(trim((string) ($payload['material_id'] ?? $context['material_id'] ?? $metrics['material_id'] ?? '')), 80),
            'content_type' => $contentType,
            'content_id' => max(0, (int) ($payload['content_id'] ?? $context['content_id'] ?? $metrics['content_id'] ?? 0)),
            'content_title' => $this->limitText(trim((string) ($payload['content_title'] ?? $context['content_title'] ?? $metrics['content_title'] ?? $metrics['title'] ?? '')), 120),
            'metrics' => $metrics,
            'created_by_admin_id' => (int) ($admin['id'] ?? 0),
            'created_by_admin_name' => (string) ($admin['name'] ?? ''),
            'assigned_to_admin_id' => $assignedAdminId,
            'assigned_to_admin_name' => $assignedAdminName,
            'assigned_at' => $assignedAdminId > 0 ? $now : '',
            'handled_by_admin_id' => 0,
            'handled_by_admin_name' => '',
            'due_at' => $dueAt,
            'last_reminded_at' => '',
            'last_reminded_by_admin_id' => 0,
            'last_reminded_by_admin_name' => '',
            'reminder_count' => 0,
            'material_review_status' => 'none',
            'original_ad_id' => '',
            'original_creative_id' => '',
            'original_material_id' => '',
            'proposed_ad_id' => '',
            'proposed_creative_id' => '',
            'proposed_material_id' => '',
            'proposed_note' => '',
            'material_submitted_by_admin_id' => 0,
            'material_submitted_by_admin_name' => '',
            'material_submitted_at' => '',
            'material_reviewed_by_admin_id' => 0,
            'material_reviewed_by_admin_name' => '',
            'material_reviewed_at' => '',
            'material_review_note' => '',
            'material_applied_at' => '',
            'effect_baseline_metrics' => $linkId > 0 ? $this->analyticsReviewTaskPerformanceSnapshot(['promotion_link_id' => $linkId], $data) : $metrics,
            'effect_latest_metrics' => [],
            'effect_delta_metrics' => [],
            'effect_updated_at' => '',
            'completed_at' => '',
            'remark' => '',
            'action_logs' => [],
            'created_at' => $now,
            'updated_at' => $now,
        ];
        $this->appendAnalyticsReviewTaskLog($task, 'create', '由小时洞察建议生成复盘任务。', $admin, $now);
        $data['analytics_review_tasks'][] = $task;
        $this->store->save($data);

        return ['ok' => true, 'created' => 1, 'task' => $task, 'message' => '复盘任务已创建。'];
    }

    public function updateAnalyticsReviewTask(array $payload): array
    {
        $data = $this->store->load();
        $taskId = max(0, (int) ($payload['task_id'] ?? 0));
        if ($taskId <= 0) {
            return ['ok' => false, 'message' => '请选择要处理的复盘任务。'];
        }

        $taskIndex = null;
        foreach ((array) ($data['analytics_review_tasks'] ?? []) as $index => $task) {
            if ((int) ($task['id'] ?? 0) === $taskId) {
                $taskIndex = $index;
                break;
            }
        }
        if ($taskIndex === null) {
            return ['ok' => false, 'message' => '复盘任务不存在。'];
        }

        $now = date('Y-m-d H:i:s');
        $admin = $this->adminIdentity($data);
        $task =& $data['analytics_review_tasks'][$taskIndex];
        $linkId = max(0, (int) ($task['promotion_link_id'] ?? 0));
        if ($linkId > 0 && !$this->canManagePromotionLink($data, $linkId)) {
            return ['ok' => false, 'message' => '当前账号无权处理该推广入口的复盘任务。'];
        }

        $status = (string) ($payload['task_status'] ?? $task['status'] ?? 'processing');
        $status = in_array($status, ['pending', 'processing', 'done', 'ignored'], true) ? $status : 'processing';
        $remark = $this->limitText(trim((string) ($payload['task_remark'] ?? '')), 300);
        $promotionAction = (string) ($payload['promotion_action'] ?? 'none');
        $actionMessages = [];

        if (array_key_exists('assigned_to_admin_id', $payload)) {
            $assignedId = max(0, (int) ($payload['assigned_to_admin_id'] ?? 0));
            $assignedAdmin = $assignedId > 0 ? $this->adminById($data, $assignedId) : [];
            if ($assignedId > 0 && empty($assignedAdmin)) {
                return ['ok' => false, 'message' => '指派负责人不存在。'];
            }
            if ($assignedId > 0 && !$this->canAssignAnalyticsReviewTaskToAdmin($data, $assignedId)) {
                return ['ok' => false, 'message' => '当前账号无权指派给该负责人。'];
            }
            $oldAssignedId = (int) ($task['assigned_to_admin_id'] ?? 0);
            $task['assigned_to_admin_id'] = $assignedId;
            $task['assigned_to_admin_name'] = $assignedId > 0 ? $this->adminDisplayName($assignedAdmin) : '';
            if ($oldAssignedId !== $assignedId) {
                $task['assigned_at'] = $assignedId > 0 ? $now : '';
                $actionMessages[] = $assignedId > 0 ? ('已指派给 ' . (string) $task['assigned_to_admin_name'] . '。') : '已取消负责人。';
            }
        }

        if (array_key_exists('due_at', $payload)) {
            $dueAt = $this->dateTimeFromInput((string) ($payload['due_at'] ?? ''));
            if ($dueAt !== (string) ($task['due_at'] ?? '')) {
                $task['due_at'] = $dueAt;
                $actionMessages[] = $dueAt !== '' ? ('截止时间已调整为 ' . $dueAt . '。') : '已清空截止时间。';
            }
        }

        if ($promotionAction === 'update_budget' && $linkId > 0) {
            $linkIndex = $this->promotionLinkIndexById($data, $linkId);
            if ($linkIndex === null) {
                return ['ok' => false, 'message' => '关联推广入口不存在，无法更新预算。'];
            }
            $link =& $data['promotion_links'][$linkIndex];
            $link['cost_budget_limit'] = round(max(0.0, (float) ($payload['cost_budget_limit'] ?? $link['cost_budget_limit'] ?? 0)), 2);
            $link['min_recovery_rate'] = round(max(0.0, (float) ($payload['min_recovery_rate'] ?? $link['min_recovery_rate'] ?? 0)), 2);
            $link['auto_pause_min_cost'] = round(max(0.0, (float) ($payload['auto_pause_min_cost'] ?? $link['auto_pause_min_cost'] ?? 0)), 2);
            $link['auto_pause_on_cost'] = !empty($payload['auto_pause_on_cost']) || (float) $link['cost_budget_limit'] > 0 || (float) $link['min_recovery_rate'] > 0;
            $link['updated_at'] = $now;
            unset($link);
            $actionMessages[] = '推广入口预算保护线已更新。';
        } elseif ($promotionAction === 'pause_link' && $linkId > 0) {
            $linkIndex = $this->promotionLinkIndexById($data, $linkId);
            if ($linkIndex === null) {
                return ['ok' => false, 'message' => '关联推广入口不存在，无法暂停。'];
            }
            $reason = $remark !== '' ? $remark : ((string) ($task['suggested_action'] ?? '') ?: (string) ($task['message'] ?? '复盘任务触发暂停推广入口。'));
            $link =& $data['promotion_links'][$linkIndex];
            $link['status'] = 'paused';
            $link['auto_paused_at'] = $now;
            $link['auto_paused_reason'] = $this->limitText($reason, 160);
            $link['updated_at'] = $now;
            $performance = $this->promotionLinkPerformance((array) $link, $data);
            $alert = $this->operationAlertFromAutoPausedPromotionLink((array) $link, $performance, $reason, $now);
            $notificationResult = $this->upsertOperationAlertNotification($data, $alert, $now, '复盘任务触发暂停');
            $noticeIndex = $notificationResult['index'] ?? null;
            $this->upsertPromotionStopTask(
                $data,
                (array) $link,
                $alert,
                $now,
                is_int($noticeIndex) ? (int) ($data['operation_alert_notifications'][$noticeIndex]['id'] ?? 0) : 0
            );
            unset($link);
            $actionMessages[] = '推广入口已暂停，并生成/更新平台停投任务。';
        }

        $task['status'] = $status;
        $task['remark'] = $remark !== '' ? $remark : (string) ($task['remark'] ?? '');
        $task['handled_by_admin_id'] = (int) ($admin['id'] ?? 0);
        $task['handled_by_admin_name'] = (string) ($admin['name'] ?? '');
        $task['updated_at'] = $now;
        if (in_array($status, ['done', 'ignored'], true)) {
            $task['completed_at'] = $now;
        } elseif ((string) ($task['completed_at'] ?? '') !== '') {
            $task['completed_at'] = '';
        }
        $logMessage = trim(($remark !== '' ? $remark : '复盘任务状态已更新。') . ' ' . implode(' ', $actionMessages));
        $this->appendAnalyticsReviewTaskLog($task, 'update', $logMessage, $admin, $now);
        unset($task);
        $this->store->save($data);

        return ['ok' => true, 'message' => trim('复盘任务已保存。' . (empty($actionMessages) ? '' : ' ' . implode(' ', $actionMessages)))];
    }

    public function sendAnalyticsReviewTaskReminder(array $payload): array
    {
        $data = $this->store->load();
        $taskId = max(0, (int) ($payload['task_id'] ?? 0));
        if ($taskId <= 0) {
            return ['ok' => false, 'message' => '请选择要提醒的复盘任务。'];
        }

        $taskIndex = null;
        foreach ((array) ($data['analytics_review_tasks'] ?? []) as $index => $task) {
            if ((int) ($task['id'] ?? 0) === $taskId) {
                $taskIndex = $index;
                break;
            }
        }
        if ($taskIndex === null) {
            return ['ok' => false, 'message' => '复盘任务不存在。'];
        }

        $now = date('Y-m-d H:i:s');
        $admin = $this->adminIdentity($data);
        $task =& $data['analytics_review_tasks'][$taskIndex];
        $linkId = max(0, (int) ($task['promotion_link_id'] ?? 0));
        if ($linkId > 0 && !$this->canManagePromotionLink($data, $linkId)) {
            return ['ok' => false, 'message' => '当前账号无权提醒该推广入口的复盘任务。'];
        }
        if (in_array((string) ($task['status'] ?? 'pending'), ['done', 'ignored'], true)) {
            return ['ok' => false, 'message' => '已结束的复盘任务无需提醒。'];
        }

        $receiverId = max(0, (int) ($task['assigned_to_admin_id'] ?? 0));
        if ($receiverId <= 0) {
            $receiverId = max(0, (int) ($task['created_by_admin_id'] ?? 0));
        }
        if ($receiverId <= 0) {
            $receiverId = (int) ($admin['id'] ?? 0);
        }
        $receiver = $this->adminById($data, $receiverId);
        if (empty($receiver)) {
            return ['ok' => false, 'message' => '未找到可提醒的负责人。'];
        }
        if (!$this->canAssignAnalyticsReviewTaskToAdmin($data, $receiverId)) {
            return ['ok' => false, 'message' => '当前账号无权提醒该负责人。'];
        }

        $recipient = $this->adminInAppRecipient($receiver);
        $dueAt = (string) ($task['due_at'] ?? '');
        $bodyParts = [
            '任务：' . (string) ($task['title'] ?? '复盘任务'),
            (string) ($task['message'] ?? ''),
        ];
        if ($dueAt !== '') {
            $bodyParts[] = '截止时间：' . $dueAt;
        }
        if ((string) ($task['suggested_action'] ?? '') !== '') {
            $bodyParts[] = '建议动作：' . (string) ($task['suggested_action'] ?? '');
        }
        if ((int) ($task['promotion_link_id'] ?? 0) > 0) {
            $bodyParts[] = '推广入口：#' . (int) ($task['promotion_link_id'] ?? 0) . ' ' . (string) ($task['promotion_code'] ?? '');
        }
        $this->appendInAppMessage($data, [
            'recipient_type' => 'admin',
            'admin_id' => (int) ($recipient['admin_id'] ?? 0),
            'agent_id' => (int) ($recipient['agent_id'] ?? 0),
            'recipient_name' => (string) ($recipient['recipient_name'] ?? ''),
            'recipient_contact' => (string) ($recipient['recipient_contact'] ?? ''),
            'scenario' => 'operation_alert',
            'template_key' => 'analytics_review_task_reminder',
            'source' => 'analytics_review_task',
            'reference_type' => 'analytics_review_task',
            'reference_id' => $taskId,
            'title' => '复盘任务提醒：' . (string) ($task['title'] ?? '待处理'),
            'body' => implode("\n", array_filter($bodyParts, static fn (string $item): bool => trim($item) !== '')),
            'priority' => (string) ($task['level'] ?? '') === 'high' ? 'high' : 'normal',
            'sender_admin_id' => (int) ($admin['id'] ?? 0),
            'sender_admin_name' => (string) ($admin['name'] ?? ''),
            'created_at' => $now,
            'updated_at' => $now,
        ]);
        $task['assigned_to_admin_id'] = (int) ($recipient['admin_id'] ?? 0);
        $task['assigned_to_admin_name'] = (string) ($recipient['recipient_name'] ?? '');
        if ((string) ($task['assigned_at'] ?? '') === '') {
            $task['assigned_at'] = $now;
        }
        $task['last_reminded_at'] = $now;
        $task['last_reminded_by_admin_id'] = (int) ($admin['id'] ?? 0);
        $task['last_reminded_by_admin_name'] = (string) ($admin['name'] ?? '');
        $task['reminder_count'] = max(0, (int) ($task['reminder_count'] ?? 0)) + 1;
        $task['updated_at'] = $now;
        $this->appendAnalyticsReviewTaskLog($task, 'remind', '已发送站内提醒给 ' . (string) ($recipient['recipient_name'] ?? '负责人') . '。', $admin, $now);
        unset($task);
        $this->store->save($data);

        return ['ok' => true, 'message' => '复盘任务提醒已发送给 ' . (string) ($recipient['recipient_name'] ?? '负责人') . '。'];
    }

    public function submitAnalyticsReviewMaterialProposal(array $payload): array
    {
        $data = $this->store->load();
        $taskRef = $this->analyticsReviewTaskRef($data, max(0, (int) ($payload['task_id'] ?? 0)));
        if ($taskRef['index'] === null) {
            return ['ok' => false, 'message' => '复盘任务不存在。'];
        }
        $now = date('Y-m-d H:i:s');
        $admin = $this->adminIdentity($data);
        $task =& $data['analytics_review_tasks'][$taskRef['index']];
        $linkId = max(0, (int) ($task['promotion_link_id'] ?? 0));
        if ($linkId > 0 && !$this->canManagePromotionLink($data, $linkId)) {
            return ['ok' => false, 'message' => '当前账号无权提交该推广入口的素材替换。'];
        }

        $proposal = [
            'proposed_ad_id' => $this->limitText(trim((string) ($payload['proposed_ad_id'] ?? '')), 80),
            'proposed_creative_id' => $this->limitText(trim((string) ($payload['proposed_creative_id'] ?? '')), 80),
            'proposed_material_id' => $this->limitText(trim((string) ($payload['proposed_material_id'] ?? '')), 80),
        ];
        if (implode('', $proposal) === '') {
            return ['ok' => false, 'message' => '请填写至少一个新广告、创意或素材 ID。'];
        }

        $link = $linkId > 0 ? $this->promotionLinkById($data, $linkId) : [];
        $task['original_ad_id'] = (string) (($link['ad_id'] ?? '') ?: ($task['ad_id'] ?? ''));
        $task['original_creative_id'] = (string) (($link['creative_id'] ?? '') ?: ($task['creative_id'] ?? ''));
        $task['original_material_id'] = (string) (($link['material_id'] ?? '') ?: ($task['material_id'] ?? ''));
        foreach ($proposal as $key => $value) {
            $task[$key] = $value;
        }
        $task['proposed_note'] = $this->limitText(trim((string) ($payload['proposed_note'] ?? '')), 300);
        $task['material_review_status'] = 'pending';
        $task['material_submitted_by_admin_id'] = (int) ($admin['id'] ?? 0);
        $task['material_submitted_by_admin_name'] = (string) ($admin['name'] ?? '');
        $task['material_submitted_at'] = $now;
        $task['material_reviewed_by_admin_id'] = 0;
        $task['material_reviewed_by_admin_name'] = '';
        $task['material_reviewed_at'] = '';
        $task['material_review_note'] = '';
        $task['material_applied_at'] = '';
        $task['effect_baseline_metrics'] = !empty($task['effect_baseline_metrics']) ? (array) $task['effect_baseline_metrics'] : $this->analyticsReviewTaskPerformanceSnapshot((array) $task, $data);
        $task['updated_at'] = $now;
        $this->appendAnalyticsReviewTaskLog($task, 'material_submit', '已提交素材替换审批。', $admin, $now);
        unset($task);
        $this->store->save($data);

        return ['ok' => true, 'message' => '素材替换审批已提交。'];
    }

    public function reviewAnalyticsReviewMaterialProposal(array $payload): array
    {
        $data = $this->store->load();
        $taskRef = $this->analyticsReviewTaskRef($data, max(0, (int) ($payload['task_id'] ?? 0)));
        if ($taskRef['index'] === null) {
            return ['ok' => false, 'message' => '复盘任务不存在。'];
        }
        $now = date('Y-m-d H:i:s');
        $admin = $this->adminIdentity($data);
        $task =& $data['analytics_review_tasks'][$taskRef['index']];
        $linkId = max(0, (int) ($task['promotion_link_id'] ?? 0));
        if ($linkId > 0 && !$this->canManagePromotionLink($data, $linkId)) {
            return ['ok' => false, 'message' => '当前账号无权审批该推广入口的素材替换。'];
        }
        if ((string) ($task['material_review_status'] ?? 'none') === 'none') {
            return ['ok' => false, 'message' => '该任务还没有提交素材替换方案。'];
        }

        $decision = (string) ($payload['material_decision'] ?? 'approve');
        $decision = in_array($decision, ['approve', 'reject', 'apply'], true) ? $decision : 'approve';
        $note = $this->limitText(trim((string) ($payload['material_review_note'] ?? '')), 300);
        $task['material_reviewed_by_admin_id'] = (int) ($admin['id'] ?? 0);
        $task['material_reviewed_by_admin_name'] = (string) ($admin['name'] ?? '');
        $task['material_reviewed_at'] = $now;
        $task['material_review_note'] = $note;
        $message = '';

        if ($decision === 'reject') {
            $task['material_review_status'] = 'rejected';
            $message = '素材替换方案已驳回。';
        } elseif ($decision === 'approve') {
            $task['material_review_status'] = 'approved';
            $message = '素材替换方案已通过。';
        } else {
            if ($linkId <= 0) {
                return ['ok' => false, 'message' => '该复盘任务未关联推广入口，无法直接应用素材。'];
            }
            $linkIndex = $this->promotionLinkIndexById($data, $linkId);
            if ($linkIndex === null) {
                return ['ok' => false, 'message' => '关联推广入口不存在，无法应用素材。'];
            }
            $task['effect_baseline_metrics'] = !empty($task['effect_baseline_metrics']) ? (array) $task['effect_baseline_metrics'] : $this->analyticsReviewTaskPerformanceSnapshot((array) $task, $data);
            $link =& $data['promotion_links'][$linkIndex];
            foreach (['ad_id' => 'proposed_ad_id', 'creative_id' => 'proposed_creative_id', 'material_id' => 'proposed_material_id'] as $linkKey => $taskKey) {
                $value = trim((string) ($task[$taskKey] ?? ''));
                if ($value !== '') {
                    $link[$linkKey] = $value;
                    $task[$linkKey] = $value;
                }
            }
            $link['updated_at'] = $now;
            unset($link);
            $task['material_review_status'] = 'applied';
            $task['material_applied_at'] = $now;
            $message = '素材替换方案已通过并应用到推广入口。';
        }

        $task['updated_at'] = $now;
        $this->appendAnalyticsReviewTaskLog($task, 'material_review', trim($message . ($note !== '' ? ' 备注：' . $note : '')), $admin, $now);
        unset($task);
        $this->store->save($data);

        return ['ok' => true, 'message' => $message];
    }

    public function refreshAnalyticsReviewTaskEffect(array $payload): array
    {
        $data = $this->store->load();
        $taskRef = $this->analyticsReviewTaskRef($data, max(0, (int) ($payload['task_id'] ?? 0)));
        if ($taskRef['index'] === null) {
            return ['ok' => false, 'message' => '复盘任务不存在。'];
        }
        $now = date('Y-m-d H:i:s');
        $admin = $this->adminIdentity($data);
        $task =& $data['analytics_review_tasks'][$taskRef['index']];
        $linkId = max(0, (int) ($task['promotion_link_id'] ?? 0));
        if ($linkId > 0 && !$this->canManagePromotionLink($data, $linkId)) {
            return ['ok' => false, 'message' => '当前账号无权刷新该推广入口的效果。'];
        }

        $baseline = !empty($task['effect_baseline_metrics']) ? (array) $task['effect_baseline_metrics'] : $this->analyticsReviewTaskPerformanceSnapshot((array) $task, $data);
        $latest = $this->analyticsReviewTaskPerformanceSnapshot((array) $task, $data);
        $task['effect_baseline_metrics'] = $baseline;
        $task['effect_latest_metrics'] = $latest;
        $task['effect_delta_metrics'] = $this->analyticsReviewEffectDelta($baseline, $latest);
        $task['effect_updated_at'] = $now;
        $task['updated_at'] = $now;
        $this->appendAnalyticsReviewTaskLog($task, 'effect_refresh', '已刷新复盘效果追踪。', $admin, $now);
        unset($task);
        $this->store->save($data);

        return ['ok' => true, 'message' => '复盘效果已刷新。'];
    }

    private function jsonArrayFromPayload(string $json): array
    {
        $json = trim($json);
        if ($json === '') {
            return [];
        }
        $decoded = json_decode($json, true);

        return is_array($decoded) ? $decoded : [];
    }

    private function analyticsReviewTaskRef(array $data, int $taskId): array
    {
        if ($taskId <= 0) {
            return ['index' => null, 'task' => []];
        }
        foreach ((array) ($data['analytics_review_tasks'] ?? []) as $index => $task) {
            if ((int) ($task['id'] ?? 0) === $taskId) {
                return ['index' => $index, 'task' => (array) $task];
            }
        }

        return ['index' => null, 'task' => []];
    }

    private function promotionLinkById(array $data, int $linkId): array
    {
        foreach ((array) ($data['promotion_links'] ?? []) as $link) {
            if ((int) ($link['id'] ?? 0) === $linkId) {
                return (array) $link;
            }
        }

        return [];
    }

    private function analyticsReviewTaskPerformanceSnapshot(array $task, array $data): array
    {
        $linkId = max(0, (int) ($task['promotion_link_id'] ?? 0));
        $link = $linkId > 0 ? $this->promotionLinkById($data, $linkId) : [];
        if (!empty($link)) {
            $performance = $this->promotionLinkPerformance($link, $data);
            return [
                'promotion_link_id' => $linkId,
                'promotion_code' => (string) ($link['code'] ?? ''),
                'ad_id' => (string) ($link['ad_id'] ?? ''),
                'creative_id' => (string) ($link['creative_id'] ?? ''),
                'material_id' => (string) ($link['material_id'] ?? ''),
                'visits' => (int) ($performance['visits'] ?? 0),
                'paid_orders' => (int) ($performance['paid_orders'] ?? 0),
                'revenue' => round((float) ($performance['revenue'] ?? 0), 2),
                'cost' => round((float) ($performance['cost'] ?? 0), 2),
                'conversion_rate' => round((float) ($performance['conversion_rate'] ?? 0), 2),
                'recovery_rate' => $performance['recovery_rate'] ?? null,
                'captured_at' => date('Y-m-d H:i:s'),
            ];
        }

        $metrics = (array) ($task['metrics'] ?? []);
        return [
            'promotion_link_id' => $linkId,
            'promotion_code' => (string) ($task['promotion_code'] ?? ''),
            'ad_id' => (string) ($task['ad_id'] ?? ''),
            'creative_id' => (string) ($task['creative_id'] ?? ''),
            'material_id' => (string) ($task['material_id'] ?? ''),
            'visits' => max(0, (int) ($metrics['visits'] ?? $metrics['views'] ?? 0)),
            'paid_orders' => max(0, (int) ($metrics['paid_orders'] ?? $metrics['orders'] ?? 0)),
            'revenue' => round(max(0.0, (float) ($metrics['revenue'] ?? $metrics['net_amount'] ?? 0)), 2),
            'cost' => round(max(0.0, (float) ($metrics['cost'] ?? 0)), 2),
            'conversion_rate' => round(max(0.0, (float) ($metrics['conversion_rate'] ?? $metrics['order_rate'] ?? 0)), 2),
            'recovery_rate' => array_key_exists('recovery_rate', $metrics) ? $metrics['recovery_rate'] : null,
            'captured_at' => date('Y-m-d H:i:s'),
        ];
    }

    private function analyticsReviewEffectDelta(array $baseline, array $latest): array
    {
        $delta = [];
        foreach (['visits', 'paid_orders', 'revenue', 'cost', 'conversion_rate'] as $key) {
            $delta[$key] = round((float) ($latest[$key] ?? 0) - (float) ($baseline[$key] ?? 0), 2);
        }
        $baselineRecovery = $baseline['recovery_rate'] ?? null;
        $latestRecovery = $latest['recovery_rate'] ?? null;
        $delta['recovery_rate'] = $baselineRecovery !== null && $latestRecovery !== null
            ? round((float) $latestRecovery - (float) $baselineRecovery, 2)
            : null;
        $delta['captured_at'] = date('Y-m-d H:i:s');

        return $delta;
    }

    private function adminIdentity(array $data): array
    {
        $admin = $this->currentAdmin();

        return [
            'id' => (int) ($admin['id'] ?? ($_SESSION['admin_id'] ?? 0)),
            'name' => $this->limitText((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? ($_SESSION['admin_name'] ?? '管理员'))), 60),
        ];
    }

    private function adminById(array $data, int $adminId): array
    {
        if ($adminId <= 0) {
            return [];
        }
        foreach ((array) ($data['admins'] ?? []) as $admin) {
            if ((int) ($admin['id'] ?? 0) === $adminId && (string) ($admin['status'] ?? 'active') === 'active') {
                return $admin;
            }
        }

        return [];
    }

    private function adminDisplayName(array $admin): string
    {
        return $this->limitText((string) (($admin['nickname'] ?? '') ?: ($admin['username'] ?? ('管理员' . (int) ($admin['id'] ?? 0)))), 60);
    }

    private function canAssignAnalyticsReviewTaskToAdmin(array $data, int $adminId): bool
    {
        if ($adminId <= 0) {
            return true;
        }
        $scope = $this->currentAdminScope($data);
        if (empty($scope['restricted'])) {
            return true;
        }

        return $adminId === (int) ($_SESSION['admin_id'] ?? 0);
    }

    private function dateTimeFromInput(string $value): string
    {
        $value = trim(str_replace('T', ' ', $value));
        if ($value === '') {
            return '';
        }
        $timestamp = strtotime($value);
        if ($timestamp === false) {
            return '';
        }

        return date('Y-m-d H:i:s', $timestamp);
    }

    private function canManagePromotionLink(array $data, int $linkId): bool
    {
        if ($linkId <= 0) {
            return true;
        }
        $scope = $this->currentAdminScope($data);
        if (empty($scope['restricted'])) {
            return true;
        }
        $agentIds = array_fill_keys(array_map('intval', (array) ($scope['agent_ids'] ?? [])), true);
        foreach ((array) ($data['promotion_links'] ?? []) as $link) {
            if ((int) ($link['id'] ?? 0) === $linkId) {
                return isset($agentIds[(int) ($link['agent_id'] ?? 0)]);
            }
        }

        return false;
    }

    private function promotionLinkIndexById(array $data, int $linkId): ?int
    {
        foreach ((array) ($data['promotion_links'] ?? []) as $index => $link) {
            if ((int) ($link['id'] ?? 0) === $linkId) {
                return (int) $index;
            }
        }

        return null;
    }

    private function appendAnalyticsReviewTaskLog(array &$task, string $action, string $message, array $admin, string $now): void
    {
        $logs = array_values((array) ($task['action_logs'] ?? []));
        $logs[] = [
            'id' => empty($logs) ? 1 : ((int) max(array_map(static fn (array $item): int => (int) ($item['id'] ?? 0), $logs)) + 1),
            'action' => $this->limitText($action, 40),
            'message' => $this->limitText($message, 220),
            'admin_id' => (int) ($admin['id'] ?? 0),
            'admin_name' => $this->limitText((string) ($admin['name'] ?? ''), 60),
            'created_at' => $now,
        ];
        $task['action_logs'] = array_slice($logs, -20);
    }

    private function adMonetizationDashboard(array $data): array
    {
        $slots = array_values((array) ($data['ad_slots'] ?? []));
        $events = array_values((array) ($data['ad_events'] ?? []));
        $waterfallPreview = $this->applyAdWaterfallOrdering(array_values(array_filter($slots, static fn (array $slot): bool => (string) ($slot['status'] ?? 'active') === 'active')), $data);
        $slotById = [];
        $slotByCode = [];
        foreach ($slots as $slot) {
            $slotById[(int) ($slot['id'] ?? 0)] = $slot;
            $slotByCode[(string) ($slot['code'] ?? '')] = $slot;
        }

        $blank = static fn (): array => [
            'requests' => 0,
            'fills' => 0,
            'impressions' => 0,
            'clicks' => 0,
            'rewards' => 0,
            'fails' => 0,
            'reward_coins' => 0,
            'revenue' => 0.0,
            'ecpm_sum' => 0.0,
            'ecpm_count' => 0,
        ];
        $summary = $blank();
        $rows = [];
        $appRows = [];
        $positionRows = [];
        $providerRows = [];

        foreach ($slots as $slot) {
            $slotId = (int) ($slot['id'] ?? 0);
            $rows[$slotId] = $blank() + [
                'slot_id' => $slotId,
                'code' => (string) ($slot['code'] ?? ''),
                'name' => (string) ($slot['name'] ?? '广告位'),
                'app_key' => (string) ($slot['app_key'] ?? 'default'),
                'position' => (string) ($slot['position'] ?? ''),
                'ad_type' => (string) ($slot['ad_type'] ?? ''),
                'provider' => (string) ($slot['provider'] ?? ''),
                'unit_id' => (string) ($slot['unit_id'] ?? ''),
                'status' => (string) ($slot['status'] ?? 'active'),
                'slot' => $slot,
            ];
        }

        $addMetrics = static function (array &$row, array $event): void {
            $type = (string) ($event['event'] ?? 'impression');
            if ($type === 'request') {
                $row['requests']++;
            } elseif ($type === 'fill') {
                $row['fills']++;
            } elseif ($type === 'impression') {
                $row['impressions']++;
            } elseif ($type === 'click') {
                $row['clicks']++;
            } elseif ($type === 'reward') {
                $row['rewards']++;
            } elseif ($type === 'fail') {
                $row['fails']++;
            }
            $row['reward_coins'] += max(0, (int) ($event['reward_coins'] ?? 0));
            $row['revenue'] += max(0.0, (float) ($event['revenue'] ?? 0));
            $ecpm = max(0.0, (float) ($event['ecpm'] ?? 0));
            if ($ecpm > 0) {
                $row['ecpm_sum'] += $ecpm;
                $row['ecpm_count']++;
            }
        };

        foreach ($events as $event) {
            $slotId = (int) ($event['ad_slot_id'] ?? 0);
            $slot = $slotById[$slotId] ?? ($slotByCode[(string) ($event['code'] ?? '')] ?? []);
            if ($slotId <= 0) {
                $slotId = (int) ($slot['id'] ?? 0);
            }
            if (!isset($rows[$slotId])) {
                $rows[$slotId] = $blank() + [
                    'slot_id' => $slotId,
                    'code' => (string) ($event['code'] ?? ''),
                    'name' => (string) (($slot['name'] ?? '') ?: '未配置广告位'),
                    'app_key' => (string) (($event['app_key'] ?? '') ?: ($slot['app_key'] ?? 'default')),
                    'position' => (string) (($event['position'] ?? '') ?: ($slot['position'] ?? '')),
                    'ad_type' => (string) (($event['ad_type'] ?? '') ?: ($slot['ad_type'] ?? '')),
                    'provider' => (string) (($event['provider'] ?? '') ?: ($slot['provider'] ?? '')),
                    'unit_id' => (string) (($event['unit_id'] ?? '') ?: ($slot['unit_id'] ?? '')),
                    'status' => (string) ($slot['status'] ?? 'unknown'),
                    'slot' => $slot,
                ];
            }
            $addMetrics($summary, $event);
            $addMetrics($rows[$slotId], $event);

            $appKey = (string) (($event['app_key'] ?? '') ?: ($rows[$slotId]['app_key'] ?? 'default'));
            $position = (string) (($event['position'] ?? '') ?: ($rows[$slotId]['position'] ?? ''));
            $provider = (string) (($event['provider'] ?? '') ?: ($rows[$slotId]['provider'] ?? ''));
            $appRows[$appKey] ??= $blank() + ['label' => $appKey, 'app_key' => $appKey];
            $positionRows[$position] ??= $blank() + ['label' => $position !== '' ? $position : '未标记位置', 'position' => $position];
            $providerRows[$provider] ??= $blank() + ['label' => $provider !== '' ? $provider : '未标记平台', 'provider' => $provider];
            $addMetrics($appRows[$appKey], $event);
            $addMetrics($positionRows[$position], $event);
            $addMetrics($providerRows[$provider], $event);
        }

        $finalize = static function (array $row): array {
            $requests = max(0, (int) ($row['requests'] ?? 0));
            $fills = max(0, (int) ($row['fills'] ?? 0));
            $impressions = max(0, (int) ($row['impressions'] ?? 0));
            $clicks = max(0, (int) ($row['clicks'] ?? 0));
            $rewards = max(0, (int) ($row['rewards'] ?? 0));
            $row['revenue'] = round((float) ($row['revenue'] ?? 0), 4);
            $row['fill_rate'] = $requests > 0 ? round(($fills / $requests) * 100, 2) : null;
            $row['show_rate'] = $fills > 0 ? round(($impressions / $fills) * 100, 2) : null;
            $row['ctr'] = $impressions > 0 ? round(($clicks / $impressions) * 100, 2) : null;
            $row['reward_rate'] = $impressions > 0 ? round(($rewards / $impressions) * 100, 2) : null;
            $row['ecpm'] = $impressions > 0 ? round(((float) $row['revenue'] / $impressions) * 1000, 2) : 0.0;
            $row['avg_reported_ecpm'] = (int) ($row['ecpm_count'] ?? 0) > 0 ? round((float) ($row['ecpm_sum'] ?? 0) / (int) $row['ecpm_count'], 2) : 0.0;
            unset($row['ecpm_sum'], $row['ecpm_count']);

            return $row;
        };

        $summary = $finalize($summary);
        $rows = array_values(array_map($finalize, $rows));
        $appRows = array_values(array_map($finalize, $appRows));
        $positionRows = array_values(array_map($finalize, $positionRows));
        $providerRows = array_values(array_map($finalize, $providerRows));
        usort($rows, static fn (array $a, array $b): int => [(float) ($b['revenue'] ?? 0), (int) ($b['impressions'] ?? 0)] <=> [(float) ($a['revenue'] ?? 0), (int) ($a['impressions'] ?? 0)]);
        usort($appRows, static fn (array $a, array $b): int => (float) ($b['revenue'] ?? 0) <=> (float) ($a['revenue'] ?? 0));
        usort($positionRows, static fn (array $a, array $b): int => (float) ($b['revenue'] ?? 0) <=> (float) ($a['revenue'] ?? 0));
        usort($providerRows, static fn (array $a, array $b): int => (float) ($b['revenue'] ?? 0) <=> (float) ($a['revenue'] ?? 0));

        return [
            'summary' => $summary,
            'rows' => $rows,
            'app_rows' => $appRows,
            'position_rows' => $positionRows,
            'provider_rows' => $providerRows,
            'waterfall_rows' => array_map([$this, 'publicAdSlot'], array_slice($waterfallPreview, 0, 20)),
        ];
    }

    private function operationAlertDashboard(array $data, array $promotionDashboard): array
    {
        $callbackAlerts = [];
        foreach ((array) ($data['callback_logs'] ?? []) as $log) {
            $status = (string) ($log['status'] ?? 'pending');
            $retryDisabled = array_key_exists('callback_retry_failed', $log) && empty($log['callback_retry_failed']);
            if ($status !== 'failed' && !($status === 'pending' && $retryDisabled)) {
                continue;
            }
            $callbackAlerts[] = [
                'type' => 'callback_failed',
                'level' => $status === 'failed' ? 'high' : 'medium',
                'title' => '回传异常：' . ((string) ($log['order_no'] ?? '') ?: ((string) ($log['code'] ?? '') ?: '未关联订单')),
                'message' => (string) (($log['message'] ?? '') ?: ($retryDisabled ? '失败重试已关闭。' : '回传失败。')),
                'status' => $status,
                'event' => (string) ($log['event'] ?? ''),
                'platform_event' => (string) ($log['platform_event'] ?? ''),
                'order_no' => (string) ($log['order_no'] ?? ''),
                'code' => (string) ($log['code'] ?? ''),
                'promotion_link_id' => (int) ($log['promotion_link_id'] ?? 0),
                'ad_id' => (string) ($log['ad_id'] ?? ($log['request_payload']['ad_id'] ?? '')),
                'material_id' => (string) ($log['material_id'] ?? ($log['request_payload']['material_id'] ?? '')),
                'endpoint' => (string) ($log['endpoint'] ?? ''),
                'attempt_count' => (int) ($log['attempt_count'] ?? 0),
                'created_at' => (string) ($log['created_at'] ?? ''),
                'last_attempt_at' => (string) (($log['last_attempt_at'] ?? '') ?: ($log['updated_at'] ?? '')),
            ] + $this->trafficMetaFromPayload($log);
        }
        usort($callbackAlerts, static fn (array $a, array $b): int => strcmp((string) ($b['last_attempt_at'] ?? $b['created_at'] ?? ''), (string) ($a['last_attempt_at'] ?? $a['created_at'] ?? '')));

        $callbackGroupRows = [];
        foreach ((array) ($data['callback_logs'] ?? []) as $log) {
            $trafficMeta = $this->trafficMetaFromPayload($log);
            $payload = is_array($log['request_payload'] ?? null) ? (array) $log['request_payload'] : [];
            $groupSource = [
                'traffic_platform' => (string) (($trafficMeta['traffic_platform'] ?? '') ?: ($payload['platform'] ?? '')),
                'channel_id' => (string) (($trafficMeta['channel_id'] ?? '') ?: ($payload['channel_id'] ?? '')),
                'media_app_id' => (string) (($trafficMeta['media_app_id'] ?? '') ?: ($payload['app_key'] ?? '')),
                'ad_id' => (string) (($trafficMeta['ad_id'] ?? '') ?: ($payload['ad_id'] ?? $payload['cid'] ?? $payload['unit_id'] ?? '')),
                'creative_id' => (string) (($trafficMeta['creative_id'] ?? '') ?: ($payload['creative_id'] ?? '')),
                'material_id' => (string) (($trafficMeta['material_id'] ?? '') ?: ($payload['material_id'] ?? '')),
                'promotion_link_id' => (int) ($log['promotion_link_id'] ?? 0),
                'code' => (string) ($log['code'] ?? ''),
            ];
            $groupKey = implode('|', [
                $groupSource['traffic_platform'],
                $groupSource['channel_id'],
                $groupSource['media_app_id'],
                $groupSource['ad_id'],
                $groupSource['material_id'],
                (string) $groupSource['promotion_link_id'],
                $groupSource['code'],
            ]);
            if (trim(str_replace('|', '', $groupKey)) === '') {
                $groupKey = 'unknown|' . (string) ($log['endpoint'] ?? '');
            }
            if (!isset($callbackGroupRows[$groupKey])) {
                $callbackGroupRows[$groupKey] = [
                    'type' => 'callback_failed',
                    'group_type' => 'callback_group',
                    'key' => $groupKey,
                    'traffic_platform' => $groupSource['traffic_platform'],
                    'channel_id' => $groupSource['channel_id'],
                    'media_app_id' => $groupSource['media_app_id'],
                    'ad_id' => $groupSource['ad_id'],
                    'creative_id' => $groupSource['creative_id'],
                    'material_id' => $groupSource['material_id'],
                    'promotion_link_id' => $groupSource['promotion_link_id'],
                    'code' => $groupSource['code'],
                    'endpoint' => (string) ($log['endpoint'] ?? ''),
                    'total_logs' => 0,
                    'failed_logs' => 0,
                    'pending_logs' => 0,
                    'success_logs' => 0,
                    'skipped_logs' => 0,
                    'retry_disabled_logs' => 0,
                    'attempt_count' => 0,
                    'amount' => 0.0,
                    'failed_amount' => 0.0,
                    'last_message' => '',
                    'last_attempt_at' => '',
                    'last_failed_at' => '',
                    'sample_order_no' => '',
                ];
            }
            $status = (string) ($log['status'] ?? 'pending');
            $row =& $callbackGroupRows[$groupKey];
            $row['total_logs']++;
            $row['attempt_count'] += max(0, (int) ($log['attempt_count'] ?? 0));
            $amount = max(0.0, (float) ($log['amount'] ?? 0));
            $row['amount'] += $amount;
            if (isset($row[$status . '_logs'])) {
                $row[$status . '_logs']++;
            }
            $retryDisabled = array_key_exists('callback_retry_failed', $log) && empty($log['callback_retry_failed']);
            if ($retryDisabled) {
                $row['retry_disabled_logs']++;
            }
            $seenAt = (string) (($log['last_attempt_at'] ?? '') ?: ($log['updated_at'] ?? $log['created_at'] ?? ''));
            if ($seenAt !== '' && strcmp($seenAt, (string) ($row['last_attempt_at'] ?? '')) > 0) {
                $row['last_attempt_at'] = $seenAt;
            }
            if ($status === 'failed' || ($status === 'pending' && $retryDisabled)) {
                $row['failed_amount'] += $amount;
                $row['last_message'] = (string) (($log['message'] ?? '') ?: ($retryDisabled ? '失败重试已关闭。' : '回传异常。'));
                $row['sample_order_no'] = (string) (($log['order_no'] ?? '') ?: ($row['sample_order_no'] ?? ''));
                if ($seenAt !== '' && strcmp($seenAt, (string) ($row['last_failed_at'] ?? '')) > 0) {
                    $row['last_failed_at'] = $seenAt;
                }
            }
            unset($row);
        }
        $callbackGroupAlerts = [];
        foreach ($callbackGroupRows as $row) {
            $row['amount'] = round((float) $row['amount'], 2);
            $row['failed_amount'] = round((float) $row['failed_amount'], 2);
            $row['failure_rate'] = (int) $row['total_logs'] > 0 ? round((((int) $row['failed_logs'] + (int) $row['retry_disabled_logs']) / (int) $row['total_logs']) * 100, 2) : 0.0;
            $badCount = (int) $row['failed_logs'] + (int) $row['retry_disabled_logs'];
            if ($badCount < 2 && (float) $row['failure_rate'] < 50.0) {
                continue;
            }
            $identity = (string) (($row['material_id'] ?? '') ?: (($row['ad_id'] ?? '') ?: (($row['code'] ?? '') ?: (($row['traffic_platform'] ?? '') ?: '未标记渠道'))));
            $callbackGroupAlerts[] = [
                'type' => 'callback_failed',
                'group_type' => 'callback_group',
                'level' => $badCount >= 5 || (float) $row['failure_rate'] >= 80.0 ? 'high' : 'medium',
                'title' => '回传失败聚合：' . $identity,
                'message' => '共 ' . (int) $row['total_logs'] . ' 条，失败/不可重试 ' . $badCount . ' 条，失败率 ' . number_format((float) $row['failure_rate'], 2) . '%，影响金额 ' . number_format((float) $row['failed_amount'], 2) . '。',
                'order_no' => (string) ($row['sample_order_no'] ?? ''),
                'last_failed_at' => (string) ($row['last_failed_at'] ?: $row['last_attempt_at']),
            ] + $row;
        }
        usort($callbackGroupAlerts, static fn (array $a, array $b): int => [
            (int) (($b['failed_logs'] ?? 0) + ($b['retry_disabled_logs'] ?? 0)),
            (float) ($b['failed_amount'] ?? 0),
            (string) ($b['last_failed_at'] ?? ''),
        ] <=> [
            (int) (($a['failed_logs'] ?? 0) + ($a['retry_disabled_logs'] ?? 0)),
            (float) ($a['failed_amount'] ?? 0),
            (string) ($a['last_failed_at'] ?? ''),
        ]);

        $materialRows = [];
        $blankMaterial = static fn (string $key, array $source = []): array => [
            'key' => $key,
            'traffic_platform' => (string) ($source['traffic_platform'] ?? ''),
            'channel_id' => (string) ($source['channel_id'] ?? ''),
            'media_app_id' => (string) ($source['media_app_id'] ?? ''),
            'ad_id' => (string) ($source['ad_id'] ?? ''),
            'creative_id' => (string) ($source['creative_id'] ?? ''),
            'material_id' => (string) ($source['material_id'] ?? ''),
            'code' => (string) ($source['code'] ?? $source['promotion_code'] ?? ''),
            'promotion_link_id' => (int) ($source['promotion_link_id'] ?? 0),
            'visits' => 0,
            'orders' => 0,
            'paid_orders' => 0,
            'refund_orders' => 0,
            'amount' => 0.0,
            'refund_amount' => 0.0,
            'net_amount' => 0.0,
            'cost' => 0.0,
        ];
        $materialKey = static function (array $source): string {
            $parts = [
                (string) ($source['traffic_platform'] ?? ''),
                (string) ($source['channel_id'] ?? ''),
                (string) ($source['media_app_id'] ?? ''),
                (string) ($source['ad_id'] ?? ''),
                (string) ($source['material_id'] ?? ''),
                (string) ($source['promotion_link_id'] ?? ''),
            ];
            $key = implode('|', $parts);

            return trim(str_replace('|', '', $key)) !== '' ? $key : 'unknown|' . (string) ($source['code'] ?? $source['promotion_code'] ?? 'unknown');
        };

        foreach ((array) ($data['promotion_events'] ?? []) as $event) {
            $key = $materialKey($event);
            $materialRows[$key] ??= $blankMaterial($key, $event);
            if ((string) ($event['event'] ?? '') === 'visit') {
                $materialRows[$key]['visits']++;
            }
        }

        foreach ((array) ($data['promotion_costs'] ?? []) as $cost) {
            $key = $materialKey($cost);
            $materialRows[$key] ??= $blankMaterial($key, $cost);
            $materialRows[$key]['cost'] += max(0.0, (float) ($cost['amount'] ?? 0));
        }

        $settledStatuses = ['paid', 'partial_refunded', 'refunded'];
        foreach ((array) ($data['orders'] ?? []) as $order) {
            if (!empty($order['is_test'])) {
                continue;
            }
            $key = $materialKey($order);
            $materialRows[$key] ??= $blankMaterial($key, $order);
            $materialRows[$key]['orders']++;
            if (!in_array((string) ($order['status'] ?? 'pending'), $settledStatuses, true)) {
                continue;
            }
            $amount = max(0.0, (float) ($order['amount'] ?? 0));
            $refund = min($amount, max(0.0, (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0)));
            $materialRows[$key]['paid_orders']++;
            $materialRows[$key]['amount'] += $amount;
            $materialRows[$key]['refund_amount'] += $refund;
            $materialRows[$key]['net_amount'] += max(0.0, $amount - $refund);
            if ($refund > 0) {
                $materialRows[$key]['refund_orders']++;
            }
        }

        $lowConversionAlerts = [];
        $highRefundAlerts = [];
        foreach ($materialRows as $row) {
            $row['amount'] = round((float) $row['amount'], 2);
            $row['refund_amount'] = round((float) $row['refund_amount'], 2);
            $row['net_amount'] = round((float) $row['net_amount'], 2);
            $row['cost'] = round((float) $row['cost'], 2);
            $row['conversion_rate'] = (int) $row['visits'] > 0 ? round(((int) $row['paid_orders'] / (int) $row['visits']) * 100, 2) : 0.0;
            $row['refund_rate'] = (int) $row['paid_orders'] > 0 ? round(((int) $row['refund_orders'] / (int) $row['paid_orders']) * 100, 2) : 0.0;
            $row['recovery_rate'] = (float) $row['cost'] > 0 ? round(((float) $row['net_amount'] / (float) $row['cost']) * 100, 2) : null;
            $identity = (string) (($row['material_id'] ?? '') ?: (($row['ad_id'] ?? '') ?: (($row['code'] ?? '') ?: '未标记素材')));

            if ((int) $row['visits'] >= 10 && (float) $row['conversion_rate'] < 1.0) {
                $lowConversionAlerts[] = [
                    'type' => 'low_conversion_material',
                    'level' => (int) $row['visits'] >= 50 ? 'high' : 'medium',
                    'title' => '低转化素材：' . $identity,
                    'message' => '访问 ' . (int) $row['visits'] . '，付费 ' . (int) $row['paid_orders'] . '，转化率 ' . number_format((float) $row['conversion_rate'], 2) . '%。',
                ] + $row;
            }

            if ((int) $row['paid_orders'] >= 3 && (float) $row['refund_rate'] >= 20.0) {
                $highRefundAlerts[] = [
                    'type' => 'high_refund_material',
                    'level' => (float) $row['refund_rate'] >= 50.0 ? 'high' : 'medium',
                    'title' => '高退款素材：' . $identity,
                    'message' => '付费 ' . (int) $row['paid_orders'] . '，退款订单 ' . (int) $row['refund_orders'] . '，退款率 ' . number_format((float) $row['refund_rate'], 2) . '%。',
                ] + $row;
            }
        }

        usort($lowConversionAlerts, static fn (array $a, array $b): int => [(int) $b['visits'], (float) $a['conversion_rate']] <=> [(int) $a['visits'], (float) $b['conversion_rate']]);
        usort($highRefundAlerts, static fn (array $a, array $b): int => [(float) $b['refund_rate'], (int) $b['paid_orders']] <=> [(float) $a['refund_rate'], (int) $a['paid_orders']]);

        $lowRecoveryLinks = [];
        $autoPausedLinks = [];
        foreach ((array) ($promotionDashboard['rows'] ?? []) as $row) {
            $link = (array) ($row['link'] ?? []);
            if ((string) ($link['auto_paused_at'] ?? '') !== '') {
                $reason = trim((string) ($link['auto_paused_reason'] ?? ''));
                $autoPausedLinks[] = [
                    'type' => 'auto_paused_link',
                    'level' => 'high',
                    'title' => '自动停投推广：' . ((string) ($link['code'] ?? '') ?: ('链接 #' . (int) ($link['id'] ?? 0))),
                    'message' => $reason !== '' ? $reason : '推广入口已由系统自动暂停。',
                    'code' => (string) ($link['code'] ?? ''),
                    'promotion_link_id' => (int) ($link['id'] ?? 0),
                    'cost' => round((float) ($row['cost'] ?? 0), 2),
                    'net_amount' => round((float) ($row['revenue'] ?? 0), 2),
                    'paid_orders' => (int) ($row['paid_orders'] ?? 0),
                    'recovery_rate' => $row['recovery_rate'] ?? null,
                    'cost_budget_limit' => round((float) ($row['cost_budget_limit'] ?? 0), 2),
                    'budget_used_rate' => $row['budget_used_rate'] ?? null,
                    'min_recovery_rate' => round((float) ($row['min_recovery_rate'] ?? 0), 2),
                    'auto_pause_min_cost' => round((float) ($row['auto_pause_min_cost'] ?? 0), 2),
                    'auto_paused_at' => (string) ($link['auto_paused_at'] ?? ''),
                    'auto_paused_reason' => $reason,
                    'agent_id' => (int) ($link['agent_id'] ?? 0),
                    'agent_name' => (string) ($row['agent_name'] ?? ''),
                    'business_name' => (string) ($row['business_name'] ?? ''),
                    'traffic_platform' => (string) ($link['traffic_platform'] ?? ''),
                    'channel_id' => (string) ($link['channel_id'] ?? ''),
                    'media_app_id' => (string) ($link['media_app_id'] ?? ''),
                    'ad_id' => (string) ($link['ad_id'] ?? ''),
                    'creative_id' => (string) ($link['creative_id'] ?? ''),
                    'material_id' => (string) ($link['material_id'] ?? ''),
                ];
            }
            if ((float) ($row['cost'] ?? 0) <= 0) {
                continue;
            }
            $recoveryRate = $row['recovery_rate'] ?? null;
            if ($recoveryRate !== null && (float) $recoveryRate < 50.0) {
                $lowRecoveryLinks[] = [
                    'type' => 'low_recovery_link',
                    'level' => (float) $recoveryRate < 25.0 ? 'high' : 'medium',
                    'title' => '低回收推广：' . ((string) ($link['code'] ?? '') ?: ('链接 #' . (int) ($link['id'] ?? 0))),
                    'message' => '消耗 ' . number_format((float) ($row['cost'] ?? 0), 2) . '，净回收 ' . number_format((float) ($row['revenue'] ?? 0), 2) . '，回本 ' . number_format((float) $recoveryRate, 2) . '%。',
                    'code' => (string) ($link['code'] ?? ''),
                    'promotion_link_id' => (int) ($link['id'] ?? 0),
                    'cost' => round((float) ($row['cost'] ?? 0), 2),
                    'net_amount' => round((float) ($row['revenue'] ?? 0), 2),
                    'paid_orders' => (int) ($row['paid_orders'] ?? 0),
                    'recovery_rate' => (float) $recoveryRate,
                    'agent_name' => (string) ($row['agent_name'] ?? ''),
                    'business_name' => (string) ($row['business_name'] ?? ''),
                    'traffic_platform' => (string) ($link['traffic_platform'] ?? ''),
                    'ad_id' => (string) ($link['ad_id'] ?? ''),
                    'material_id' => (string) ($link['material_id'] ?? ''),
                ];
            }
        }
        usort($lowRecoveryLinks, static fn (array $a, array $b): int => [(float) $a['recovery_rate'], (float) $b['cost']] <=> [(float) $b['recovery_rate'], (float) $a['cost']]);
        usort($autoPausedLinks, static fn (array $a, array $b): int => strcmp((string) ($b['auto_paused_at'] ?? ''), (string) ($a['auto_paused_at'] ?? '')));

        return [
            'summary' => [
                'total' => count($callbackAlerts) + count($callbackGroupAlerts) + count($lowConversionAlerts) + count($highRefundAlerts) + count($lowRecoveryLinks) + count($autoPausedLinks),
                'callback_failed' => count($callbackAlerts),
                'callback_group_failed' => count($callbackGroupAlerts),
                'low_conversion' => count($lowConversionAlerts),
                'high_refund' => count($highRefundAlerts),
                'low_recovery' => count($lowRecoveryLinks),
                'auto_paused' => count($autoPausedLinks),
            ],
            'callback_alerts' => array_slice($callbackAlerts, 0, 20),
            'callback_group_alerts' => array_slice($callbackGroupAlerts, 0, 20),
            'low_conversion_alerts' => array_slice($lowConversionAlerts, 0, 20),
            'high_refund_alerts' => array_slice($highRefundAlerts, 0, 20),
            'low_recovery_alerts' => array_slice($lowRecoveryLinks, 0, 20),
            'auto_paused_alerts' => array_slice($autoPausedLinks, 0, 20),
            'thresholds' => [
                'low_conversion_min_visits' => 10,
                'low_conversion_rate' => 1.0,
                'callback_group_min_bad_logs' => 2,
                'callback_group_failure_rate' => 50.0,
                'high_refund_min_paid_orders' => 3,
                'high_refund_rate' => 20.0,
                'low_recovery_rate' => 50.0,
                'auto_paused_link' => 1,
            ],
        ];
    }

    private function notificationFromOperationAlert(array $alert, int $id, string $now): array
    {
        $type = (string) ($alert['type'] ?? 'operation_alert');
        $priority = match ((string) ($alert['level'] ?? 'medium')) {
            'high' => 'urgent',
            'medium' => 'high',
            default => 'normal',
        };
        $fingerprintParts = [
            $type,
            (string) ($alert['group_type'] ?? ''),
            (string) ($alert['key'] ?? ''),
            (string) ($alert['promotion_link_id'] ?? 0),
            (string) (($alert['group_type'] ?? '') === 'callback_group' ? '' : ($alert['order_no'] ?? '')),
            (string) ($alert['ad_id'] ?? ''),
            (string) ($alert['material_id'] ?? ''),
            (string) ($alert['code'] ?? ''),
        ];
        $fingerprint = 'op:' . md5(implode('|', $fingerprintParts));
        $suggestion = match ($type) {
            'callback_failed' => '检查回传地址、签名密钥和平台事件名；必要时在回传配置页重试或批量回传订单。',
            'low_conversion_material' => '检查素材标题、落地页承接、审核跳转和目标人群；低成本小流量可继续观察，高流量低转化建议暂停或替换素材。',
            'high_refund_material' => '复盘素材承诺与实际内容/价格是否一致，关注支付投诉和退款订单，必要时下架素材或调整承接内容。',
            'low_recovery_link' => '检查投放消耗、回收周期和充值商品配置，优先暂停低回收链接并替换素材或落地页。',
            'auto_paused_link' => '系统已暂停该推广入口；请复核预算、回本率、素材和承接内容，确认后再决定是否重新投放。',
            'promotion_stop_auth_failed' => '刷新或重新授权平台账号 token，再单条重试停投任务；同账号任务会保留在异常台账中。',
            'promotion_stop_rate_limited' => '等待平台限流窗口结束后批量重试；高频失败时请降低批量上限或检查平台 QPS 配额。',
            'promotion_stop_failed' => '核对平台适配器接口、字段映射、账号权限和平台返回错误码，必要时人工停投后补记结果。',
            default => '请结合订单、回传和投放消耗记录排查。',
        };
        $metricKeys = [
            'visits', 'paid_orders', 'refund_orders', 'conversion_rate', 'refund_rate', 'recovery_rate',
            'cost', 'amount', 'refund_amount', 'net_amount', 'attempt_count',
            'total_logs', 'failed_logs', 'pending_logs', 'success_logs', 'skipped_logs', 'retry_disabled_logs',
            'failure_rate', 'failed_amount', 'cost_budget_limit', 'budget_used_rate', 'min_recovery_rate',
            'auto_pause_min_cost',
        ];
        $metrics = [];
        foreach ($metricKeys as $key) {
            if (array_key_exists($key, $alert)) {
                $metrics[$key] = $alert[$key];
            }
        }

        return [
            'id' => $id,
            'fingerprint' => $fingerprint,
            'type' => in_array($type, ['callback_failed', 'low_conversion_material', 'high_refund_material', 'low_recovery_link', 'auto_paused_link', 'promotion_stop_failed', 'promotion_stop_auth_failed', 'promotion_stop_rate_limited', 'operation_alert'], true) ? $type : 'operation_alert',
            'status' => 'pending',
            'priority' => $priority,
            'title' => $this->limitText(trim((string) ($alert['title'] ?? '投放异常预警')), 120),
            'message' => $this->limitText(trim((string) ($alert['message'] ?? '')), 600),
            'suggestion' => $suggestion,
            'promotion_link_id' => max(0, (int) ($alert['promotion_link_id'] ?? 0)),
            'promotion_code' => preg_replace('/[^a-zA-Z0-9_-]+/', '', (string) ($alert['code'] ?? $alert['promotion_code'] ?? '')),
            'order_no' => $this->limitText(trim((string) ($alert['order_no'] ?? '')), 80),
            'agent_id' => max(0, (int) ($alert['agent_id'] ?? 0)),
            'traffic_platform' => $this->limitText(trim((string) ($alert['traffic_platform'] ?? '')), 40),
            'channel_id' => $this->limitText(trim((string) ($alert['channel_id'] ?? '')), 60),
            'media_app_id' => $this->limitText(trim((string) ($alert['media_app_id'] ?? '')), 60),
            'ad_id' => $this->limitText(trim((string) ($alert['ad_id'] ?? '')), 80),
            'creative_id' => $this->limitText(trim((string) ($alert['creative_id'] ?? '')), 80),
            'material_id' => $this->limitText(trim((string) ($alert['material_id'] ?? '')), 80),
            'metric_snapshot' => $metrics,
            'source_payload' => $alert,
            'first_seen_at' => $now,
            'last_seen_at' => $now,
            'occurrence_count' => 1,
            'handled_by_admin_id' => 0,
            'handled_by_admin_name' => '',
            'handled_at' => '',
            'reply' => '',
            'created_at' => $now,
            'updated_at' => $now,
        ];
    }

    private function agentTree(array $agents): array
    {
        $index = [];
        foreach ($agents as $agent) {
            $index[(int) ($agent['id'] ?? 0)] = $agent;
        }

        $tree = [];
        foreach ($index as $id => $agent) {
            $role = (string) ($agent['role'] ?? 'agent');
            $parent = $index[(int) ($agent['parent_id'] ?? 0)] ?? null;
            $grandParent = is_array($parent) ? ($index[(int) ($parent['parent_id'] ?? 0)] ?? null) : null;
            if ($role === 'business') {
                $business = $agent;
                $leader = null;
                $proxy = null;
            } elseif ($role === 'leader') {
                $business = $parent;
                $leader = $agent;
                $proxy = null;
            } else {
                $business = $grandParent;
                $leader = $parent;
                $proxy = $agent;
            }

            $parts = array_values(array_filter([
                is_array($business) ? (string) ($business['name'] ?? '') : '',
                is_array($leader) ? (string) ($leader['name'] ?? '') : '',
                is_array($proxy) ? (string) ($proxy['name'] ?? '') : '',
            ], static fn (string $part): bool => $part !== ''));

            $tree[$id] = [
                'agent_id' => is_array($proxy) ? (int) ($proxy['id'] ?? 0) : ($role === 'agent' ? $id : 0),
                'agent_name' => is_array($proxy) ? (string) ($proxy['name'] ?? '未分配代理') : ($role === 'agent' ? (string) ($agent['name'] ?? '未分配代理') : '未分配代理'),
                'leader_id' => is_array($leader) ? (int) ($leader['id'] ?? 0) : ($role === 'leader' ? $id : 0),
                'leader_name' => is_array($leader) ? (string) ($leader['name'] ?? '未分配组长') : ($role === 'leader' ? (string) ($agent['name'] ?? '未分配组长') : '未分配组长'),
                'business_id' => is_array($business) ? (int) ($business['id'] ?? 0) : ($role === 'business' ? $id : 0),
                'business_name' => is_array($business) ? (string) ($business['name'] ?? '未分配商务') : ($role === 'business' ? (string) ($agent['name'] ?? '未分配商务') : '未分配商务'),
                'path' => implode(' / ', $parts),
            ];
        }

        return $tree;
    }

    private function recoveryDashboard(array $data): array
    {
        $timezone = new \DateTimeZone('Asia/Shanghai');
        $today = new \DateTimeImmutable('today', $timezone);
        $days = [0, 1, 3, 7, 15, 30, 60, 90];
        $users = array_values((array) ($data['users'] ?? []));
        $orders = array_values(array_filter((array) ($data['orders'] ?? []), static fn (array $order): bool => empty($order['is_test'])));
        $events = array_values((array) ($data['promotion_events'] ?? []));
        $costs = array_values((array) ($data['promotion_costs'] ?? []));

        $paidOrders = array_values(array_filter($orders, static fn (array $order): bool => in_array((string) ($order['status'] ?? 'pending'), ['paid', 'partial_refunded', 'refunded'], true)));
        $firstOrderTimeByUser = [];
        foreach ($orders as $order) {
            $userId = (int) ($order['user_id'] ?? 0);
            $time = strtotime((string) ($order['created_at'] ?? ''));
            if ($userId > 0 && $time !== false) {
                $firstOrderTimeByUser[$userId] = min($firstOrderTimeByUser[$userId] ?? $time, $time);
            }
        }

        $firstEventTimeByUser = [];
        foreach ($events as $event) {
            $userId = (int) ($event['user_id'] ?? 0);
            $time = strtotime((string) ($event['created_at'] ?? ''));
            if ($userId > 0 && $time !== false) {
                $firstEventTimeByUser[$userId] = min($firstEventTimeByUser[$userId] ?? $time, $time);
            }
        }

        $userCohorts = [];
        foreach ($users as $user) {
            $userId = (int) ($user['id'] ?? 0);
            if ($userId <= 0) {
                continue;
            }
            $createdAt = strtotime((string) ($user['created_at'] ?? ''));
            if ($createdAt === false) {
                $createdAt = $firstOrderTimeByUser[$userId] ?? $firstEventTimeByUser[$userId] ?? time();
            }
            $userCohorts[$userId] = (new \DateTimeImmutable('@' . $createdAt))->setTimezone($timezone)->format('Y-m-d');
        }

        $rows = [];
        $blankRow = static fn (string $date): array => [
            'date' => $date,
            'new_users' => 0,
            'paid_users' => [],
            'orders' => 0,
            'revenue' => 0.0,
            'cost' => 0.0,
            'add_desktop' => 0,
            'day_amounts' => array_fill_keys($days, 0.0),
            'recovery_rates' => array_fill_keys($days, null),
        ];

        foreach ($userCohorts as $dateKey) {
            $rows[$dateKey] ??= $blankRow($dateKey);
            $rows[$dateKey]['new_users']++;
        }

        foreach ($events as $event) {
            if ((string) ($event['event'] ?? '') !== 'add_desktop') {
                continue;
            }
            $userId = (int) ($event['user_id'] ?? 0);
            $eventTime = strtotime((string) ($event['created_at'] ?? '')) ?: time();
            $cohortDate = $userCohorts[$userId] ?? (new \DateTimeImmutable('@' . $eventTime))->setTimezone($timezone)->format('Y-m-d');
            $rows[$cohortDate] ??= $blankRow($cohortDate);
            $rows[$cohortDate]['add_desktop']++;
        }

        foreach ($costs as $cost) {
            $date = trim((string) ($cost['date'] ?? ''));
            $timestamp = strtotime($date);
            if ($timestamp === false) {
                continue;
            }
            $dateKey = (new \DateTimeImmutable('@' . $timestamp))->setTimezone($timezone)->format('Y-m-d');
            $rows[$dateKey] ??= $blankRow($dateKey);
            $rows[$dateKey]['cost'] += (float) ($cost['amount'] ?? 0);
        }

        foreach ($paidOrders as $order) {
            $userId = (int) ($order['user_id'] ?? 0);
            $cohortDate = $userCohorts[$userId] ?? null;
            if ($cohortDate === null) {
                $fallbackTime = strtotime((string) ($order['created_at'] ?? '')) ?: time();
                $cohortDate = (new \DateTimeImmutable('@' . $fallbackTime))->setTimezone($timezone)->format('Y-m-d');
                $rows[$cohortDate] ??= $blankRow($cohortDate);
            }

            $paidTime = strtotime((string) (($order['paid_at'] ?? '') ?: ($order['created_at'] ?? '')));
            if ($paidTime === false) {
                continue;
            }
            $paidDate = (new \DateTimeImmutable('@' . $paidTime))->setTimezone($timezone);
            $cohort = new \DateTimeImmutable($cohortDate, $timezone);
            $diffDays = max(0, (int) $cohort->diff($paidDate)->format('%a'));
            $amount = (float) ($order['amount'] ?? 0);
            $refund = min($amount, max(0.0, (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0)));
            $net = max(0.0, $amount - $refund);

            $rows[$cohortDate]['orders']++;
            $rows[$cohortDate]['revenue'] += $net;
            if ($userId > 0) {
                $rows[$cohortDate]['paid_users'][$userId] = true;
            }
            foreach ($days as $day) {
                if ($diffDays <= $day) {
                    $rows[$cohortDate]['day_amounts'][$day] += $net;
                }
            }
        }

        foreach ($rows as &$row) {
            $row['paid_user_count'] = count($row['paid_users']);
            unset($row['paid_users']);
            $row['revenue'] = round((float) $row['revenue'], 2);
            $row['cost'] = round((float) $row['cost'], 2);
            foreach ($days as $day) {
                $row['day_amounts'][$day] = round((float) ($row['day_amounts'][$day] ?? 0), 2);
                $row['recovery_rates'][$day] = $row['cost'] > 0 ? round(((float) ($row['day_amounts'][$day] ?? 0) / (float) $row['cost']) * 100, 2) : null;
            }
            $row['pay_rate'] = (int) $row['new_users'] > 0 ? round(((int) $row['paid_user_count'] / (int) $row['new_users']) * 100, 2) : 0.0;
            $row['recovery_rate'] = $row['cost'] > 0 ? round(((float) $row['revenue'] / (float) $row['cost']) * 100, 2) : null;
            $row['add_desktop_cost'] = (int) $row['add_desktop'] > 0 ? round(((float) $row['cost'] / (int) $row['add_desktop']), 2) : null;
            $row['order_cost'] = (int) $row['orders'] > 0 ? round(((float) $row['cost'] / (int) $row['orders']), 2) : null;
            $row['age_days'] = (int) (new \DateTimeImmutable($row['date'], $timezone))->diff($today)->format('%a');
        }
        unset($row);

        usort($rows, static fn (array $a, array $b): int => strcmp((string) $b['date'], (string) $a['date']));

        $summaryUsers = array_sum(array_column($rows, 'new_users'));
        $summaryPaidUsers = array_sum(array_column($rows, 'paid_user_count'));
        $summaryRevenue = array_sum(array_column($rows, 'revenue'));
        $summaryCost = array_sum(array_column($rows, 'cost'));
        $summaryAddDesktop = array_sum(array_column($rows, 'add_desktop'));
        $summaryOrders = array_sum(array_column($rows, 'orders'));

        return [
            'days' => $days,
            'rows' => array_slice($rows, 0, 31),
            'summary' => [
                'new_users' => (int) $summaryUsers,
                'add_desktop' => (int) $summaryAddDesktop,
                'paid_users' => (int) $summaryPaidUsers,
                'revenue' => round((float) $summaryRevenue, 2),
                'pay_rate' => $summaryUsers > 0 ? round(($summaryPaidUsers / $summaryUsers) * 100, 2) : 0.0,
                'cost' => round((float) $summaryCost, 2),
                'recovery_rate' => $summaryCost > 0 ? round(($summaryRevenue / $summaryCost) * 100, 2) : null,
                'add_desktop_cost' => $summaryAddDesktop > 0 ? round($summaryCost / $summaryAddDesktop, 2) : null,
                'order_cost' => $summaryOrders > 0 ? round($summaryCost / $summaryOrders, 2) : null,
            ],
        ];
    }

    private function revokeEntitlement(array &$data, array $order): void
    {
        $entitlementType = match ((string) ($order['type'] ?? '')) {
            'vip_week', 'vip_month' => 'membership',
            'episode' => 'episode_unlock',
            default => (string) ($order['type'] ?? ''),
        };
        $contentType = in_array((string) ($order['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $order['content_type'] : 'drama';
        $episodeId = in_array($entitlementType, ['drama_unlock', 'membership'], true) || $contentType === 'novel' ? null : ($order['episode_id'] ?? null);
        $chapterId = in_array($entitlementType, ['novel_unlock', 'membership'], true) ? null : ($order['chapter_id'] ?? null);
        $sourceOrderNo = (string) ($order['order_no'] ?? '');
        $data['entitlements'] = array_values(array_filter(
            $data['entitlements'],
            static function (array $item) use ($order, $contentType, $episodeId, $chapterId, $entitlementType, $sourceOrderNo): bool {
                $itemContentType = in_array((string) ($item['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $item['content_type'] : 'drama';

                return !(
                (int) ($item['user_id'] ?? 0) === (int) ($order['user_id'] ?? 0)
                && $itemContentType === $contentType
                && (int) ($item['drama_id'] ?? 0) === (int) ($order['drama_id'] ?? 0)
                && (int) ($item['episode_id'] ?? 0) === (int) ($episodeId ?? 0)
                && (int) ($item['novel_id'] ?? 0) === (int) ($order['novel_id'] ?? 0)
                && (int) ($item['chapter_id'] ?? 0) === (int) ($chapterId ?? 0)
                && (string) ($item['type'] ?? '') === $entitlementType
                && ($sourceOrderNo === '' || (string) ($item['source_order_no'] ?? '') === '' || (string) ($item['source_order_no'] ?? '') === $sourceOrderNo)
            );
            }
        ));

        if (!in_array((string) ($order['type'] ?? ''), ['membership', 'vip_week', 'vip_month'], true)) {
            return;
        }

        $hasOtherMembership = false;
        foreach ($data['entitlements'] as $item) {
            if ((int) $item['user_id'] === (int) $order['user_id'] && $item['type'] === 'membership') {
                $hasOtherMembership = true;
                break;
            }
        }

        if ($hasOtherMembership) {
            return;
        }

        foreach ($data['users'] as &$user) {
            if ((int) $user['id'] === (int) $order['user_id']) {
                $user['membership'] = false;
                $user['membership_expires_at'] = null;
                break;
            }
        }
    }

    private function transferUserAssets(array &$data, int $fromUserId, int $toUserId): void
    {
        if ($fromUserId <= 0 || $toUserId <= 0 || $fromUserId === $toUserId) {
            return;
        }

        foreach (['orders', 'entitlements', 'coin_transactions', 'watch_history', 'followed_dramas'] as $collection) {
            foreach ($data[$collection] ?? [] as &$item) {
                if ((int) ($item['user_id'] ?? 0) === $fromUserId) {
                    $item['user_id'] = $toUserId;
                }
            }
            unset($item);
        }

        $fromIndex = null;
        $toIndex = null;
        foreach ($data['users'] ?? [] as $index => $user) {
            if ((int) ($user['id'] ?? 0) === $fromUserId) {
                $fromIndex = $index;
            }
            if ((int) ($user['id'] ?? 0) === $toUserId) {
                $toIndex = $index;
            }
        }

        if ($fromIndex !== null && $toIndex !== null) {
            $data['users'][$toIndex]['coin_balance'] = max(0, (int) ($data['users'][$toIndex]['coin_balance'] ?? 0)) + max(0, (int) ($data['users'][$fromIndex]['coin_balance'] ?? 0));
            $data['users'][$toIndex]['bonus_coin_balance'] = max(0, (int) ($data['users'][$toIndex]['bonus_coin_balance'] ?? 0)) + max(0, (int) ($data['users'][$fromIndex]['bonus_coin_balance'] ?? 0));
            if (!empty($data['users'][$fromIndex]['membership']) && empty($data['users'][$toIndex]['membership'])) {
                $data['users'][$toIndex]['membership'] = true;
                $data['users'][$toIndex]['membership_expires_at'] = $data['users'][$fromIndex]['membership_expires_at'] ?? null;
            }
            $data['users'][$fromIndex]['coin_balance'] = 0;
            $data['users'][$fromIndex]['bonus_coin_balance'] = 0;
        }

        $seen = [];
        foreach (['entitlements', 'watch_history', 'followed_dramas'] as $collection) {
            $data[$collection] = array_values(array_filter($data[$collection] ?? [], static function (array $item) use (&$seen, $collection): bool {
                $key = $collection . ':' . (int) ($item['user_id'] ?? 0) . ':' . (int) ($item['drama_id'] ?? 0) . ':' . (int) ($item['episode_id'] ?? 0) . ':' . (string) ($item['type'] ?? '');
                if (isset($seen[$key])) {
                    return false;
                }
                $seen[$key] = true;

                return true;
            }));
        }
    }

    private function findRelatedFeedbackOrder(array $data, int $userId, string $contentType, int $dramaId, int $episodeId, int $novelId, int $chapterId): ?array
    {
        if ($userId <= 0) {
            return null;
        }

        $candidates = [];
        foreach ((array) ($data['orders'] ?? []) as $order) {
            if ((int) ($order['user_id'] ?? 0) !== $userId) {
                continue;
            }
            $order = $this->normalizeOrderState($order);
            $score = 0;
            $orderContentType = in_array((string) ($order['content_type'] ?? ''), ['drama', 'novel'], true) ? (string) $order['content_type'] : '';
            if ($contentType !== '' && $orderContentType === $contentType) {
                $score += 20;
            }
            if ($contentType === 'drama') {
                if ($dramaId > 0 && (int) ($order['drama_id'] ?? 0) === $dramaId) {
                    $score += 30;
                }
                if ($episodeId > 0 && (int) ($order['episode_id'] ?? 0) === $episodeId) {
                    $score += 20;
                }
            } elseif ($contentType === 'novel') {
                if ($novelId > 0 && (int) ($order['novel_id'] ?? 0) === $novelId) {
                    $score += 30;
                }
                if ($chapterId > 0 && (int) ($order['chapter_id'] ?? 0) === $chapterId) {
                    $score += 20;
                }
            }
            if (in_array((string) ($order['status'] ?? 'pending'), ['paid', 'refund_pending', 'partial_refunded', 'refunded'], true)) {
                $score += 10;
            }
            if ($contentType === '' && trim((string) ($order['order_no'] ?? '')) !== '') {
                $score += 5;
            }
            if ($score <= 0) {
                continue;
            }
            $time = strtotime((string) ($order['created_at'] ?? '')) ?: 0;
            $candidates[] = ['score' => $score, 'time' => $time, 'order' => $order];
        }

        if (empty($candidates)) {
            return null;
        }

        usort($candidates, static fn (array $a, array $b): int => [(int) $b['score'], (int) $b['time']] <=> [(int) $a['score'], (int) $a['time']]);

        return (array) ($candidates[0]['order'] ?? []);
    }

    private function feedbackAppKey(array $payload, ?array $order, ?array $link, array $attribution, array $data): string
    {
        foreach ([
            $payload['app_key'] ?? '',
            $payload['media_app_id'] ?? '',
            $payload['app_id'] ?? '',
            $order['app_key'] ?? '',
            $link['app_key'] ?? '',
            $link['media_app_id'] ?? '',
            $attribution['app_key'] ?? '',
            $attribution['media_app_id'] ?? '',
        ] as $candidate) {
            $appKey = $this->normalizeAppKey((string) $candidate);
            if ($appKey === '') {
                continue;
            }
            $app = $this->appConfigFromData($appKey, $data);
            return (string) ($app['app_key'] ?? $appKey);
        }

        return 'default';
    }

    private function feedbackSlaHours(string $type, string $priority): int
    {
        $base = match ($type) {
            'payment', 'complaint' => 4,
            'account' => 8,
            'promotion' => 12,
            'content' => 24,
            default => 24,
        };

        return match ($priority) {
            'urgent' => max(1, (int) floor($base / 2)),
            'high' => max(2, (int) floor($base * 0.75)),
            'low' => max($base, 48),
            default => $base,
        };
    }

    private function refreshFeedbackSlaState(array $item, ?string $now = null): array
    {
        $now ??= date('Y-m-d H:i:s');
        $type = (string) ($item['type'] ?? 'feedback');
        $priority = (string) ($item['priority'] ?? 'normal');
        $item['sla_hours'] = max(1, (int) ($item['sla_hours'] ?? $this->feedbackSlaHours($type, $priority)));
        if (trim((string) ($item['due_at'] ?? '')) === '') {
            $createdAt = strtotime((string) ($item['created_at'] ?? '')) ?: strtotime($now);
            $item['due_at'] = date('Y-m-d H:i:s', $createdAt + ($item['sla_hours'] * 3600));
        }

        $status = (string) ($item['status'] ?? 'pending');
        $dueAt = strtotime((string) ($item['due_at'] ?? '')) ?: 0;
        $nowAt = strtotime($now) ?: time();
        if (in_array($status, ['resolved', 'rejected'], true)) {
            $handledAt = strtotime((string) ($item['handled_at'] ?? '')) ?: $nowAt;
            $item['sla_status'] = ($dueAt > 0 && $handledAt > $dueAt) ? 'handled_overdue' : 'handled_on_time';
            $createdAt = strtotime((string) ($item['created_at'] ?? '')) ?: $handledAt;
            $item['handled_minutes'] = max(0, (int) floor(($handledAt - $createdAt) / 60));

            return $item;
        }

        $remainingSeconds = $dueAt > 0 ? $dueAt - $nowAt : PHP_INT_MAX;
        if ($remainingSeconds < 0) {
            $item['sla_status'] = 'overdue';
        } elseif ($remainingSeconds <= 3600) {
            $item['sla_status'] = 'due_soon';
        } else {
            $item['sla_status'] = 'normal';
        }

        return $item;
    }

    private function feedbackSuggestedAction(string $type, string $priority, string $content, ?array $order, string $contentType): array
    {
        $text = function_exists('mb_strtolower') ? mb_strtolower($content, 'UTF-8') : strtolower($content);
        $hasOrder = is_array($order) && trim((string) ($order['order_no'] ?? '')) !== '';
        $status = $hasOrder ? (string) ($order['status'] ?? 'pending') : '';
        $refundTotal = $hasOrder ? (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0) : 0.0;

        if (!$hasOrder && in_array($type, ['payment', 'complaint'], true)) {
            return ['action' => 'check_order', 'reason' => '支付/投诉反馈未明确关联订单，先核对用户最近订单和支付状态。'];
        }
        if ($type === 'payment' && in_array($status, ['pending', 'failed', 'closed', 'expired'], true)) {
            return ['action' => 'query_payment', 'reason' => '关联订单尚未确认支付成功，建议先发起支付状态查询。'];
        }
        if ($hasOrder && in_array($status, ['paid', 'partial_refunded'], true) && (str_contains($text, '没解锁') || str_contains($text, '打不开') || str_contains($text, '未到账') || str_contains($text, '没到账'))) {
            return ['action' => 'rights_repair', 'reason' => '订单已支付但用户反馈权益未到账，建议核实后走权益补发。'];
        }
        if ($hasOrder && in_array($status, ['paid', 'partial_refunded'], true) && $refundTotal <= 0 && (str_contains($text, '退款') || str_contains($text, '退钱') || str_contains($text, '扣款'))) {
            return ['action' => 'refund', 'reason' => '用户反馈含退款/扣款诉求且订单仍有可退金额，建议核实后走订单退款。'];
        }
        if ($contentType !== '' && (str_contains($text, '错集') || str_contains($text, '少集') || str_contains($text, '不能看') || str_contains($text, '内容'))) {
            return ['action' => 'content_review', 'reason' => '反馈指向内容质量或章节/分集问题，建议编辑侧复核内容。'];
        }
        if ($type === 'promotion') {
            return ['action' => 'promotion_review', 'reason' => '投放问题建议结合推广链接、素材和回传数据排查。'];
        }
        if (in_array($priority, ['high', 'urgent'], true)) {
            return ['action' => 'contact_user', 'reason' => '高优先级反馈建议客服优先联系用户确认诉求。'];
        }

        return ['action' => 'contact_user', 'reason' => '先联系用户确认问题细节并记录处理结果。'];
    }

    private function feedbackOrderSnapshot(?array $order): array
    {
        if (!is_array($order) || trim((string) ($order['order_no'] ?? '')) === '') {
            return [];
        }

        return [
            'order_no' => (string) ($order['order_no'] ?? ''),
            'status' => (string) ($order['status'] ?? 'pending'),
            'amount' => round((float) ($order['amount'] ?? 0), 2),
            'refund_total' => round((float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0), 2),
            'payment_channel_name' => (string) ($order['payment_channel_name'] ?? ''),
            'payment_method_name' => (string) ($order['payment_method_name'] ?? ''),
            'created_at' => (string) ($order['created_at'] ?? ''),
            'paid_at' => (string) ($order['paid_at'] ?? ''),
        ];
    }

    private function feedbackUserSnapshot(array $user): array
    {
        return [
            'id' => max(0, (int) ($user['id'] ?? 0)),
            'nickname' => $this->limitText(trim((string) ($user['nickname'] ?? '')), 60),
            'phone' => $this->limitText(trim((string) ($user['phone'] ?? '')), 32),
            'coin_balance' => max(0, (int) ($user['coin_balance'] ?? 0)),
            'bonus_coin_balance' => max(0, (int) ($user['bonus_coin_balance'] ?? 0)),
            'membership' => !empty($user['membership']),
        ];
    }

    private function findRouteInList(array $routes, string $routeId): ?array
    {
        if ($routeId === '') {
            return null;
        }

        foreach ($routes as $route) {
            if (is_array($route) && (string) ($route['id'] ?? '') === $routeId) {
                return $route;
            }
        }

        return null;
    }

    private function buildPaymentRouteFromPayload(array $payload, array $fallback): array
    {
        $text = static function (string $key, string $default = '') use ($payload, $fallback): string {
            if (array_key_exists($key, $payload)) {
                return trim((string) $payload[$key]);
            }

            return trim((string) ($fallback[$key] ?? $default));
        };
        $secret = static function (string $key) use ($payload, $fallback): string {
            $value = trim((string) ($payload[$key] ?? ''));

            return $value !== '' ? $value : (string) ($fallback[$key] ?? '');
        };
        $decimal = static function (string $key, float $default = 0.0) use ($payload, $fallback): string {
            $value = trim((string) ($payload[$key] ?? ($fallback[$key] ?? $default)));
            if ($value === '') {
                return (string) $default;
            }

            return (string) max(0, (float) $value);
        };
        $intText = static function (string $key, int $default = 0) use ($payload, $fallback): string {
            $value = trim((string) ($payload[$key] ?? ($fallback[$key] ?? $default)));
            if ($value === '') {
                return (string) $default;
            }

            return (string) max(0, (int) $value);
        };

        $provider = strtolower($text('provider', 'jingxiu') ?: 'jingxiu');
        if ($provider === 'payjf') {
            $provider = 'superpay';
        }
        $method = $text('payment_method', 'alipay') ?: 'alipay';
        $routeId = preg_replace('/\D+/', '', $text('payment_route_id', (string) ($fallback['id'] ?? ''))) ?: (string) ($fallback['id'] ?? '1');
        if (!ctype_digit((string) $routeId) || (int) $routeId < 1) {
            $routeId = '1';
        }

        $defaultTradeType = $provider === 'superpay' ? $method : 'alipayWap';
        $tradeType = $text('trade_type', $text('pay_type', $defaultTradeType)) ?: $defaultTradeType;
        $providerName = $text('provider_name', match ($provider) {
            'jingxiu' => '精秀聚合支付',
            'superpay' => '超级支付',
            default => strtoupper($provider),
        });
        $methodName = $text('payment_method_name', match ($method) {
            'wechat', 'wxpay' => '微信支付',
            'qqpay' => 'QQ 钱包',
            'bank' => '网银支付',
            'jdpay' => '京东钱包',
            'unionpay' => '云闪付',
            'paypal' => 'PayPal',
            'douyinpay' => '抖音支付',
            default => '支付宝',
        });
        $apiUrl = $text('api_url');
        if ($apiUrl === '' && $provider === 'superpay') {
            $apiUrl = 'http://payjf.cn';
        }
        $channelName = $this->limitText($text('channel_name', $providerName ?: strtoupper($provider)) ?: ($providerName ?: strtoupper($provider)), 20);
        $notes = $this->limitText($text('notes'), 20);
        $payChannelId = preg_replace('/\D+/', '', $text('pay_channel_id'));
        $signType = strtoupper($text('sign_type', $provider === 'superpay' ? 'MD5' : 'RSA2') ?: ($provider === 'superpay' ? 'MD5' : 'RSA2'));
        if ($provider === 'superpay' && $signType === 'RSA2') {
            $signType = 'RSA';
        }

        return [
            'id' => $routeId,
            'provider' => $provider,
            'provider_name' => $providerName ?: strtoupper($provider),
            'channel_name' => $channelName,
            'payment_method' => $method,
            'payment_method_name' => $methodName ?: $method,
            'trade_type' => $tradeType,
            'pay_type' => $tradeType,
            'channel_mode' => 'short_drama',
            'share_rate' => '0',
            'cost_rate' => '0',
            'daily_amount_limit' => $decimal('daily_amount_limit', 0),
            'daily_order_limit' => $intText('daily_order_limit', 0),
            'frequency_window' => $intText('frequency_window', 0),
            'frequency_count' => $intText('frequency_count', 0),
            'min_amount' => $decimal('min_amount', 0),
            'max_amount' => $decimal('max_amount', 0),
            'open_start_hour' => (string) min(23, (int) $intText('open_start_hour', 0)),
            'open_end_hour' => (string) min(23, (int) $intText('open_end_hour', 23)),
            'enabled' => !empty($payload['enabled']),
            'is_default' => !empty($payload['is_default']),
            'api_url' => $apiUrl,
            'merchant_id' => $text('merchant_id'),
            'app_id' => $text('app_id'),
            'secret_key' => $secret('secret_key'),
            'merchant_private_key' => $secret('merchant_private_key'),
            'platform_public_key' => $secret('platform_public_key'),
            'pay_channel_id' => $payChannelId,
            'channel_code' => $text('channel_code'),
            'request_method' => strtoupper($text('request_method', 'POST') ?: 'POST'),
            'amount_unit' => $text('amount_unit', 'yuan') ?: 'yuan',
            'sign_type' => $signType,
            'charset' => $text('charset', 'utf-8') ?: 'utf-8',
            'version' => $text('version', '1.0') ?: '1.0',
            'request_timeout' => max(1, (int) ($payload['request_timeout'] ?? $fallback['request_timeout'] ?? 12)),
            'notify_url' => $text('notify_url'),
            'return_url' => $text('return_url'),
            'notify_success_text' => $text('notify_success_text', 'success') ?: 'success',
            'notes' => $notes,
        ];
    }

    private function nextPaymentRouteId(array $routes): string
    {
        $maxId = 0;
        foreach ($routes as $route) {
            $routeId = (string) ($route['id'] ?? '');
            if (ctype_digit($routeId)) {
                $maxId = max($maxId, (int) $routeId);
            }
        }

        return (string) ($maxId + 1);
    }

    private function limitText(string $value, int $maxLength): string
    {
        if ($maxLength < 1) {
            return '';
        }

        if (function_exists('mb_substr')) {
            return mb_substr($value, 0, $maxLength, 'UTF-8');
        }

        preg_match_all('/./us', $value, $matches);
        if (!empty($matches[0])) {
            return implode('', array_slice($matches[0], 0, $maxLength));
        }

        return substr($value, 0, $maxLength);
    }

    private function contentTagsFromPayload(mixed $value): array
    {
        $items = is_array($value) ? $value : preg_split('/[\s,，|]+/u', (string) $value);
        $tags = [];
        foreach ((array) $items as $item) {
            $tag = $this->limitText(trim((string) $item), 24);
            if ($tag === '' || in_array($tag, $tags, true)) {
                continue;
            }
            $tags[] = $tag;
        }

        return array_slice($tags, 0, 12);
    }

    private function contentImportItemsFromText(string $raw): array
    {
        $decoded = json_decode($raw, true);
        if (json_last_error() === JSON_ERROR_NONE && is_array($decoded)) {
            $items = array_is_list($decoded) ? $decoded : [$decoded];
            return ['ok' => true, 'format' => 'json', 'items' => $items];
        }

        $items = [];
        $errors = [];
        foreach (preg_split('/\r\n|\r|\n/', $raw) ?: [] as $lineNumber => $line) {
            $line = trim((string) $line);
            if ($line === '') {
                continue;
            }
            $item = json_decode($line, true);
            if (json_last_error() !== JSON_ERROR_NONE || !is_array($item)) {
                $errors[] = '第 ' . ($lineNumber + 1) . ' 行不是有效 JSON。';
                continue;
            }
            $items[] = $item;
        }

        if (!empty($items)) {
            return ['ok' => true, 'format' => 'jsonl', 'items' => $items, 'parse_errors' => $errors];
        }

        return ['ok' => false, 'message' => '导入内容必须是 JSON 数组、单个 JSON 对象，或一行一个 JSON 对象。'];
    }

    private function contentImportDramaFromItem(array $item, int $dramaId, string $defaultCategory, array $defaultTags, int $defaultGroupId, string $defaultStatus, string $defaultAuditStatus, string $now): array
    {
        $title = $this->limitText(trim((string) ($item['title'] ?? $item['name'] ?? '新短剧')), 100) ?: '新短剧';
        $episodes = [];
        foreach (array_values((array) ($item['episodes'] ?? $item['items'] ?? [])) as $index => $episode) {
            if (!is_array($episode)) {
                $episode = ['title' => (string) $episode];
            }
            $episodeId = $dramaId * 100 + $index + 1;
            $episodes[] = [
                'id' => $episodeId,
                'title' => $this->limitText(trim((string) ($episode['title'] ?? $episode['name'] ?? ('第' . ($index + 1) . '集'))), 80) ?: ('第' . ($index + 1) . '集'),
                'duration' => $this->limitText(trim((string) ($episode['duration'] ?? '03:00')), 20) ?: '03:00',
                'is_free' => array_key_exists('is_free', $episode) ? !empty($episode['is_free']) : $index === 0,
                'video_url' => trim((string) ($episode['video_url'] ?? $episode['url'] ?? 'https://example.com/demo.mp4')) ?: 'https://example.com/demo.mp4',
            ];
        }

        return [
            'id' => $dramaId,
            'title' => $title,
            'cover' => trim((string) ($item['cover'] ?? '/assets/cover-1.svg')) ?: '/assets/cover-1.svg',
            'description' => trim((string) ($item['description'] ?? $item['summary'] ?? '待补充简介')),
            'price_per_episode' => round(max(0, (float) ($item['price_per_episode'] ?? 1.99)), 2),
            'membership_price' => round(max(0, (float) ($item['membership_price'] ?? 19.9)), 2),
            'category' => $this->limitText(trim((string) ($item['category'] ?? $defaultCategory)), 40) ?: $defaultCategory,
            'tags' => $this->contentImportTags($item, $defaultTags, $defaultCategory),
            'group_id' => max(0, (int) ($item['group_id'] ?? $defaultGroupId)),
            'audit_status' => in_array((string) ($item['audit_status'] ?? $defaultAuditStatus), ['draft', 'pending', 'approved', 'rejected', 'online', 'offline'], true) ? (string) ($item['audit_status'] ?? $defaultAuditStatus) : $defaultAuditStatus,
            'audit_note' => $this->limitText(trim((string) ($item['audit_note'] ?? '批量导入')), 160),
            'free_episode_count' => max(0, (int) ($item['free_episode_count'] ?? max(1, count(array_filter($episodes, static fn (array $episode): bool => !empty($episode['is_free'])))))),
            'episode_coin_price' => max(1, (int) ($item['episode_coin_price'] ?? 199)),
            'full_unlock_price' => round(max(0, (float) ($item['full_unlock_price'] ?? 19.9)), 2),
            'is_hot' => !empty($item['is_hot']),
            'is_new' => array_key_exists('is_new', $item) ? !empty($item['is_new']) : true,
            'sort' => (int) ($item['sort'] ?? $dramaId),
            'status' => in_array((string) ($item['status'] ?? $defaultStatus), ['draft', 'online', 'offline'], true) ? (string) ($item['status'] ?? $defaultStatus) : $defaultStatus,
            'episodes' => $episodes,
            'created_at' => $now,
            'updated_at' => $now,
        ];
    }

    private function contentImportNovelFromItem(array $item, int $novelId, string $defaultCategory, array $defaultTags, int $defaultGroupId, string $defaultStatus, string $defaultAuditStatus, string $now): array
    {
        $title = $this->limitText(trim((string) ($item['title'] ?? $item['name'] ?? '新小说')), 100) ?: '新小说';
        $chapters = [];
        foreach (array_values((array) ($item['chapters'] ?? $item['items'] ?? [])) as $index => $chapter) {
            if (!is_array($chapter)) {
                $chapter = ['content' => (string) $chapter];
            }
            $content = trim((string) ($chapter['content'] ?? $chapter['body'] ?? ''));
            $chapters[] = [
                'id' => $novelId * 1000 + $index + 1,
                'title' => $this->limitText(trim((string) ($chapter['title'] ?? $chapter['name'] ?? ('第' . ($index + 1) . '章'))), 80) ?: ('第' . ($index + 1) . '章'),
                'content' => $content,
                'word_count' => max(0, (int) ($chapter['word_count'] ?? $this->textLength($content))),
                'is_free' => array_key_exists('is_free', $chapter) ? !empty($chapter['is_free']) : $index < 3,
                'sort' => (int) ($chapter['sort'] ?? ($index + 1)),
                'status' => in_array((string) ($chapter['status'] ?? $defaultStatus), ['draft', 'online', 'offline'], true) ? (string) ($chapter['status'] ?? $defaultStatus) : $defaultStatus,
                'created_at' => $now,
                'updated_at' => $now,
            ];
        }

        return [
            'id' => $novelId,
            'title' => $title,
            'cover' => trim((string) ($item['cover'] ?? '/assets/cover-1.svg')) ?: '/assets/cover-1.svg',
            'description' => trim((string) ($item['description'] ?? $item['summary'] ?? '待补充简介')),
            'author' => $this->limitText(trim((string) ($item['author'] ?? '')), 40),
            'category' => $this->limitText(trim((string) ($item['category'] ?? $defaultCategory)), 40) ?: $defaultCategory,
            'tags' => $this->contentImportTags($item, $defaultTags, $defaultCategory),
            'group_id' => max(0, (int) ($item['group_id'] ?? $defaultGroupId)),
            'audit_status' => in_array((string) ($item['audit_status'] ?? $defaultAuditStatus), ['draft', 'pending', 'approved', 'rejected', 'online', 'offline'], true) ? (string) ($item['audit_status'] ?? $defaultAuditStatus) : $defaultAuditStatus,
            'audit_note' => $this->limitText(trim((string) ($item['audit_note'] ?? '批量导入')), 160),
            'free_chapter_count' => max(0, (int) ($item['free_chapter_count'] ?? max(1, count(array_filter($chapters, static fn (array $chapter): bool => !empty($chapter['is_free'])))))),
            'chapter_coin_price' => max(1, (int) ($item['chapter_coin_price'] ?? 99)),
            'full_unlock_price' => round(max(0, (float) ($item['full_unlock_price'] ?? 19.9)), 2),
            'is_hot' => !empty($item['is_hot']),
            'is_new' => array_key_exists('is_new', $item) ? !empty($item['is_new']) : true,
            'sort' => (int) ($item['sort'] ?? $novelId),
            'status' => in_array((string) ($item['status'] ?? $defaultStatus), ['draft', 'online', 'offline'], true) ? (string) ($item['status'] ?? $defaultStatus) : $defaultStatus,
            'chapters' => $chapters,
            'created_at' => $now,
            'updated_at' => $now,
        ];
    }

    private function contentImportTags(array $item, array $defaultTags, string $defaultCategory): array
    {
        $tags = $this->contentTagsFromPayload($item['tags'] ?? $item['tag_names'] ?? []);
        if (empty($tags)) {
            $tags = $defaultTags;
        }
        if (empty($tags)) {
            $tags = [$this->limitText(trim((string) ($item['category'] ?? $defaultCategory)), 24) ?: $defaultCategory];
        }

        return array_slice($tags, 0, 12);
    }

    private function listFromPayload(mixed $value, int $limit = 20, int $maxLength = 40, bool $identifierOnly = false): array
    {
        $items = is_array($value) ? $value : preg_split('/[\s,，|]+/u', (string) $value);
        $list = [];
        foreach ((array) $items as $item) {
            $text = trim((string) $item);
            if ($identifierOnly) {
                $text = preg_replace('/[^a-zA-Z0-9_-]+/', '', $text) ?: '';
            }
            $text = $this->limitText($text, $maxLength);
            if ($text === '' || in_array($text, $list, true)) {
                continue;
            }
            $list[] = $text;
        }

        return array_slice($list, 0, max(1, $limit));
    }

    private function landingPagePointsFromPayload(mixed $value): array
    {
        $items = is_array($value) ? $value : preg_split('/[\r\n,，|]+/u', (string) $value);
        $points = [];
        foreach ((array) $items as $item) {
            $point = $this->limitText(trim((string) $item), 40);
            if ($point === '' || in_array($point, $points, true)) {
                continue;
            }
            $points[] = $point;
        }

        return array_slice($points, 0, 6);
    }

    private function normalizeAppKey(string $value): string
    {
