    private function resolveAppUserTier(array $app, int $userId, ?array $data = null): array
    {
        $data ??= $this->store->load();
        $user = [];
        foreach ((array) ($data['users'] ?? []) as $item) {
            if ((int) ($item['id'] ?? 0) === $userId) {
                $user = $item;
                break;
            }
        }
        $isMember = !empty($user['membership']);
        $expiresAt = strtotime((string) ($user['membership_expires_at'] ?? '')) ?: 0;
        if ($isMember && $expiresAt > 0 && $expiresAt < time()) {
            $isMember = false;
        }
        $createdAt = strtotime((string) ($user['created_at'] ?? '')) ?: 0;
        $registeredDays = $createdAt > 0 ? max(0, (int) floor((time() - $createdAt) / 86400)) : 0;
        $paidOrderCount = 0;
        foreach ((array) ($data['orders'] ?? []) as $order) {
            if ((int) ($order['user_id'] ?? 0) !== $userId || !empty($order['is_test'])) {
                continue;
            }
            if (in_array((string) ($order['status'] ?? 'pending'), ['paid', 'partial_refunded', 'refunded'], true)) {
                $paidOrderCount++;
            }
        }
        $fallback = [
            'key' => $paidOrderCount > 0 ? 'paid' : 'unpaid',
            'name' => $paidOrderCount > 0 ? '已付费' : '未付费',
            'tag' => $paidOrderCount > 0 ? '已付费' : '未付费',
            'paid_order_count' => $paidOrderCount,
            'membership' => $isMember,
            'registered_days' => $registeredDays,
        ];
        $memberTierEnabled = false;
        foreach (array_values((array) ($app['user_tiers'] ?? [])) as $tier) {
            if ((string) ($tier['key'] ?? '') === 'member' && !empty($tier['enabled']) && !empty($tier['membership_required'])) {
                $memberTierEnabled = true;
                break;
            }
        }
        foreach (array_values((array) ($app['user_tiers'] ?? [])) as $tier) {
            if (empty($tier['enabled'])) {
                continue;
            }
            $tierKey = (string) ($tier['key'] ?? '');
            if ($isMember && $memberTierEnabled && $tierKey !== 'member') {
                continue;
            }
            $membershipRequired = !empty($tier['membership_required']);
            if ($membershipRequired && !$isMember) {
                continue;
            }
            if (!$membershipRequired && $tierKey === 'member' && !$isMember) {
                continue;
            }
            $minPaid = max(0, (int) ($tier['min_paid_orders'] ?? 0));
            $maxPaid = max(0, (int) ($tier['max_paid_orders'] ?? 0));
            if ($paidOrderCount < $minPaid) {
                continue;
            }
            if (in_array($tierKey, ['new', 'unpaid'], true) && $minPaid === 0 && $maxPaid === 0 && $paidOrderCount > 0) {
                continue;
            }
            if ($maxPaid > 0 && $paidOrderCount > $maxPaid) {
                continue;
            }
            $registeredWithinDays = max(0, (int) ($tier['registered_within_days'] ?? 0));
            if ($registeredWithinDays > 0 && $registeredDays > $registeredWithinDays) {
                continue;
            }

            return $tier + [
                'paid_order_count' => $paidOrderCount,
                'membership' => $isMember,
                'registered_days' => $registeredDays,
            ];
        }

        return $fallback;
    }

