                'min_paid_orders' => max(0, (int) ($payload['tier_' . $tierKey . '_min_paid_orders'] ?? ($currentTier['min_paid_orders'] ?? $default['min_paid_orders']))),
                'max_paid_orders' => max(0, (int) ($payload['tier_' . $tierKey . '_max_paid_orders'] ?? ($currentTier['max_paid_orders'] ?? $default['max_paid_orders']))),
                'registered_within_days' => max(0, (int) ($payload['tier_' . $tierKey . '_registered_within_days'] ?? ($currentTier['registered_within_days'] ?? $default['registered_within_days']))),
                'membership_required' => array_key_exists('tier_' . $tierKey . '_membership_required', $payload) ? !empty($payload['tier_' . $tierKey . '_membership_required']) : (bool) ($currentTier['membership_required'] ?? $default['membership_required']),
                'tag' => $this->limitText(trim((string) ($payload['tier_' . $tierKey . '_tag'] ?? ($currentTier['tag'] ?? $default['tag']))), 24),
                'benefit_text' => $this->limitText(trim((string) ($payload['tier_' . $tierKey . '_benefit_text'] ?? ($currentTier['benefit_text'] ?? $default['benefit_text']))), 80),
                'sort' => (int) ($payload['tier_' . $tierKey . '_sort'] ?? ($currentTier['sort'] ?? $default['sort'])),
            ];
