        uasort($tiers, static fn (array $a, array $b): int => [(int) ($a['sort'] ?? 0), (string) ($a['key'] ?? '')] <=> [(int) ($b['sort'] ?? 0), (string) ($b['key'] ?? '')]);

        return $tiers;
