    private function urlWithQueryParam(string $url, string $key, string $value): string
    {
        $url = trim($url);
        if ($url === '' || $value === '') {
            return $url;
        }
        if (preg_match('/(?:^|[?&])' . preg_quote($key, '/') . '=/', $url) === 1) {
            return $url;
        }

        $fragment = '';
        $fragmentPos = strpos($url, '#');
        if ($fragmentPos !== false) {
            $fragment = substr($url, $fragmentPos);
            $url = substr($url, 0, $fragmentPos);
        }
        $separator = str_contains($url, '?') ? '&' : '?';

        return $url . $separator . rawurlencode($key) . '=' . rawurlencode($value) . $fragment;
    }

    private function textLength(string $value): int
    {
        if ($value === '') {
            return 0;
        }

        if (function_exists('mb_strlen')) {
            return mb_strlen($value, 'UTF-8');
        }

        preg_match_all('/./us', $value, $matches);

        return !empty($matches[0]) ? count($matches[0]) : strlen($value);
    }

