    private function hasPendingRefundRequest(array $requests): bool
    {
        foreach ($requests as $request) {
            if (in_array((string) ($request['status'] ?? 'processing'), ['pending', 'processing'], true)) {
                return true;
            }
        }

        return false;
    }

    private function normalizeOrderState(array $order): array
    {
        $status = (string) ($order['status'] ?? 'pending');
        $allowedStatuses = ['pending', 'paid', 'refund_pending', 'partial_refunded', 'refunded', 'failed', 'closed', 'expired'];
        if (!in_array($status, $allowedStatuses, true)) {
            $status = in_array($status, ['success', 'paid_success'], true) ? 'paid' : 'pending';
        }

        $requests = array_values((array) ($order['refund_requests'] ?? []));
        $hasPendingRefund = $this->hasPendingRefundRequest($requests) || !empty($order['refund_pending']);
        $refundTotal = round(max(0, (float) ($order['refund_total'] ?? $order['refund_amount'] ?? 0)), 2);
        $amount = round(max(0, (float) ($order['amount'] ?? 0)), 2);

        if ($hasPendingRefund && in_array($status, ['paid', 'partial_refunded'], true)) {
            $status = 'refund_pending';
        } elseif ($refundTotal > 0 && $amount > 0 && $refundTotal < $amount && in_array($status, ['paid', 'refunded'], true)) {
            $status = 'partial_refunded';
        } elseif ($refundTotal > 0 && $amount > 0 && $refundTotal >= $amount && in_array($status, ['paid', 'partial_refunded', 'refund_pending'], true)) {
            $status = 'refunded';
        }

        $order['status'] = $status;
        $order['status_reason'] = (string) ($order['status_reason'] ?? match ($status) {
            'paid' => '支付成功已确认。',
            'refund_pending' => '退款处理中。',
            'partial_refunded' => '订单已部分退款。',
            'refunded' => '订单已退款。',
            'failed' => '订单支付失败。',
            'closed' => '订单已关闭。',
            'expired' => '订单已过期。',
            default => '订单待支付。',
        });
        $order['refund_status'] = (string) ($order['refund_status'] ?? ($hasPendingRefund ? 'processing' : ($refundTotal > 0 ? 'success' : 'none')));
        $order['refund_pending'] = $hasPendingRefund;
        $order['refund_failed_reason'] = (string) ($order['refund_failed_reason'] ?? '');
        $order['last_status_checked_at'] = $order['last_status_checked_at'] ?? null;
        $order['paid_confirmed_by'] = (string) ($order['paid_confirmed_by'] ?? '');

        return $order;
    }
}
